# ---------------------------------------------------------------------------
# Mixed-precision profiles
# ---------------------------------------------------------------------------
# Each profile maps to (propagation_dtype, pattern_dtype, power_dtype).
#
# Propagation: SGP4 orbit mechanics + ECI→topocentric geometry.
#   - fp64 recommended (orbital radii ~6.9e6 m, angular precision matters)
#   - fp32 acceptable (current default), fp16 impossible (overflow)
#
# Pattern: S.1528 transmit + RAS receive antenna gain evaluation.
#   - fp32 standard (gain range -80 to +34 dB fits well)
#   - fp16 viable for angles only; linear gain 1e-8..2500 has poor fp16 precision
#     at the low end but is acceptable when the final accumulation is in fp32+
#   - fp64 for reference/validation
#
# Power: EIRP × FSPL × atm × pattern → EPFD/PFD accumulation.
#   - fp32 minimum (FSPL ~1e-16 underflows fp16 to zero)
#   - fp64 for maximum tail precision
#   - fp16 NOT viable (FSPL underflow)
#
PRECISION_PROFILES: dict[str, dict[str, np.dtype]] = {
    "float64": {
        "propagation": np.dtype(np.float64),
        "pattern": np.dtype(np.float64),
        "power": np.dtype(np.float64),
    },
    "float64/float32": {
        "propagation": np.dtype(np.float64),
        "pattern": np.dtype(np.float32),
        "power": np.dtype(np.float32),
    },
    "float32": {
        "propagation": np.dtype(np.float32),
        "pattern": np.dtype(np.float32),
        "power": np.dtype(np.float32),
    },
    "float32/float16": {
        "propagation": np.dtype(np.float32),
        "pattern": np.dtype(np.float16),
        "power": np.dtype(np.float32),
    },
    "float64/float32/float16": {
        "propagation": np.dtype(np.float64),
        "pattern": np.dtype(np.float16),
        "power": np.dtype(np.float32),
    },
}
PRECISION_PROFILE_NAMES = tuple(PRECISION_PROFILES.keys())


def resolve_precision_profile(
    name: str | None,
) -> dict[str, np.dtype]:
    """
    Resolve a named precision profile to per-stage dtypes.

    Parameters
    ----------
    name : str or None
        Profile name from :data:`PRECISION_PROFILES`.  ``None`` returns the
        ``"float32"`` default.

    Returns
    -------
    dict[str, numpy.dtype]
        Mapping with keys ``"propagation"``, ``"pattern"``, ``"power"``.
    """
    key = "float32" if name is None else str(name).strip().lower()
    # Backward compatibility: bare dtype names map to pure-precision profiles
    if key in ("float16", "fp16"):
        key = "float32/float16"
    elif key in ("fp32",):
        key = "float32"
    elif key in ("fp64",):
        key = "float64"
    if key not in PRECISION_PROFILES:
        raise ValueError(
            f"precision_profile must be one of {sorted(PRECISION_PROFILES)!r}; got {name!r}."
        )
    return dict(PRECISION_PROFILES[key])


