def _normalise_cell_active_mask_cupy(
    value: Any | None,
    *,
    time_count: int,
    cell_count: int,
) -> Any | None:
    if value is None:
        return None
    arr = cp.asarray(value, dtype=cp.bool_)
    time_count_i = int(time_count)
    cell_count_i = int(cell_count)
    if arr.ndim == 1:
        if int(arr.shape[0]) != cell_count_i:
            raise ValueError(
                f"cell_active_mask with shape {tuple(arr.shape)!r} must have length {cell_count_i}."
            )
        arr = cp.broadcast_to(arr.reshape(1, cell_count_i), (time_count_i, cell_count_i)).copy()
    elif arr.ndim == 2:
        if tuple(arr.shape) != (time_count_i, cell_count_i):
            raise ValueError(
                f"cell_active_mask must have shape ({time_count_i}, {cell_count_i}) or ({cell_count_i},); "
                f"got {tuple(arr.shape)!r}."
            )
        arr = cp.ascontiguousarray(arr.astype(cp.bool_, copy=False))
    else:
        raise ValueError(
            f"cell_active_mask must have shape ({time_count_i}, {cell_count_i}) or ({cell_count_i},); "
            f"got {tuple(arr.shape)!r}."
        )
    return arr


def _normalise_cell_spectral_weight_cupy(
    value: Any | None,
    *,
    time_count: int,
    cell_count: int | None = None,
) -> Any | None:
    if value is None:
        return None
    arr = cp.asarray(value, dtype=cp.float32)
    time_count_i = int(time_count)
    cell_count_i = None if cell_count is None else int(cell_count)
    if arr.ndim == 1:
        if cell_count_i is None:
            cell_count_i = int(arr.shape[0])
        if int(arr.shape[0]) != cell_count_i:
            raise ValueError(
                f"cell_spectral_weight with shape {tuple(arr.shape)!r} must have length {cell_count_i}."
            )
        if time_count_i == 1:
            arr = arr.reshape(1, cell_count_i)
        else:
            arr = cp.broadcast_to(arr.reshape(1, cell_count_i), (time_count_i, cell_count_i))
    elif arr.ndim == 2:
        if cell_count_i is None:
            cell_count_i = int(arr.shape[1])
        if tuple(arr.shape) != (time_count_i, cell_count_i):
            raise ValueError(
                f"cell_spectral_weight must have shape ({time_count_i}, {cell_count_i}) or ({cell_count_i},); "
                f"got {tuple(arr.shape)!r}."
            )
        flags = getattr(arr, "flags", None)
        if arr.dtype == cp.float32 and flags is not None and bool(getattr(flags, "c_contiguous", False)):
            return arr
        arr = cp.ascontiguousarray(arr.astype(cp.float32, copy=False))
    else:
        raise ValueError(
            f"cell_spectral_weight must have shape ({time_count_i}, {cell_count_i}) or ({cell_count_i},); "
            f"got {tuple(arr.shape)!r}."
        )
    return arr


