def _iter_numba_low_occupancy_warning_categories() -> Iterator[type[Warning]]:
    seen: set[int] = set()
    for category in (_NumbaCudaPerformanceWarning, _NumbaCorePerformanceWarning):
        if category is None:
            continue
        marker = id(category)
        if marker in seen:
            continue
        seen.add(marker)
        yield category


def _managed_numba_low_occupancy_filter_specs() -> list[tuple[str, str, type[Warning], str, int]]:
    specs: list[tuple[str, str, type[Warning], str, int]] = []
    for category in _iter_numba_low_occupancy_warning_categories():
        for module_re in _NUMBA_LOW_OCCUPANCY_WARNING_MODULE_RES:
            specs.append(
                (
                    "ignore",
                    _NUMBA_LOW_OCCUPANCY_WARNING_MESSAGE_RE,
                    category,
                    module_re,
                    0,
                )
            )
    return specs


def _warning_filter_pattern_text(value: Any) -> Any:
    return getattr(value, "pattern", value)


def _warning_filter_matches_spec(
    entry: tuple[Any, Any, Any, Any, Any],
    spec: tuple[str, str, type[Warning], str, int],
) -> bool:
    if len(entry) != 5:
        return False
    action, message, category, module, lineno = entry
    expected_action, expected_message, expected_category, expected_module, expected_lineno = spec
    return (
        action == expected_action
        and _warning_filter_pattern_text(message) == expected_message
        and category is expected_category
        and _warning_filter_pattern_text(module) == expected_module
        and lineno == expected_lineno
    )


def _count_managed_numba_low_occupancy_filters() -> int:
    specs = _managed_numba_low_occupancy_filter_specs()
    if not specs:
        return 0
    return sum(
        1
        for entry in warnings.filters
        if any(_warning_filter_matches_spec(entry, spec) for spec in specs)
    )


def _clear_managed_numba_low_occupancy_filters() -> None:
    specs = _managed_numba_low_occupancy_filter_specs()
    if not specs:
        return
    warnings.filters[:] = [
        entry
        for entry in warnings.filters
        if not any(_warning_filter_matches_spec(entry, spec) for spec in specs)
    ]
    filters_mutated = getattr(warnings, "_filters_mutated", None)
    if callable(filters_mutated):
        filters_mutated()


def _show_numba_low_occupancy_warnings_from_env() -> bool:
    return os.environ.get(_NUMBA_LOW_OCCUPANCY_WARNING_ENVVAR, "").strip() == "1"


def configure_numba_low_occupancy_warnings(show: bool = False) -> None:
    """
    Control suppression of repetitive CUDA low-occupancy warnings.

    Parameters
    ----------
    show : bool, optional
        If ``False`` (default), suppress only the common CUDA dispatcher
        warning whose message starts with ``"Grid size ... low occupancy"``.
        If ``True``, remove the SCEPTer-managed suppression filters so those
        warnings are visible again.

    Returns
    -------
    None
        This helper updates Python's warning filters in place.

    Notes
    -----
    The suppression is intentionally narrow: it only targets low-occupancy
    launch warnings emitted from ``numba_cuda.numba.cuda.dispatcher`` and the
    legacy ``numba.cuda.dispatcher`` module. Other
    ``NumbaPerformanceWarning`` messages remain visible.

    To keep the warnings visible from import time onward, set
    ``SCEPTER_SHOW_NUMBA_LOW_OCCUPANCY_WARNINGS=1`` before importing
    :mod:`scepter.gpu_accel`.
    """
    _clear_managed_numba_low_occupancy_filters()
    if show:
        return
    for action, message, category, module, lineno in _managed_numba_low_occupancy_filter_specs():
        warnings.filterwarnings(
            action,
            message=message,
            category=category,
            module=module,
            lineno=lineno,
        )


configure_numba_low_occupancy_warnings(show=_show_numba_low_occupancy_warnings_from_env())

