class GpuAccelWarning(UserWarning):
    """Base warning category for non-fatal GPU backend surprises."""


class GpuEarthModelOverrideWarning(GpuAccelWarning):
    """Raised when explicit model kwargs are ignored in favour of contexts."""


class GpuMixedEarthModelWarning(GpuAccelWarning):
    """Raised when propagation and observer geometry use different models."""


class GpuTerminalCloseWarning(GpuAccelWarning):
    """Raised when terminal session shutdown must degrade to a soft close."""


def _default_cache_dir() -> Path:
    local_appdata = os.environ.get("LOCALAPPDATA")
    if local_appdata:
        return Path(local_appdata) / "scepter"
    xdg_cache = os.environ.get("XDG_CACHE_HOME")
    if xdg_cache:
        return Path(xdg_cache) / "scepter"
    return Path.home() / ".cache" / "scepter"


_AUTO_THRESHOLD_CACHE_PATH = _default_cache_dir() / "gpu_auto_thresholds.json"
_SCHEDULER_CALIBRATION_CACHE_PATH = _default_cache_dir() / "gpu_scheduler_calibration.json"
_SCHEDULER_CALIBRATION_CACHE_VERSION = 1
_SCHEDULER_TARGET_FRACTIONS = {
    "conservative": 0.75,
    "high_throughput": 0.90,
    "max_throughput": 0.97,
}


def _resolve_scheduler_target_fraction(
    target: str | float | None,
    *,
    default: float = 0.90,
) -> tuple[str, float]:
    if target is None:
        return "high_throughput", float(default)
    if isinstance(target, str):
        key = str(target).strip().lower()
        if key not in _SCHEDULER_TARGET_FRACTIONS:
            raise ValueError(
                "scheduler_target_profile must be one of "
                f"{sorted(_SCHEDULER_TARGET_FRACTIONS)!r}; got {target!r}."
            )
        return key, float(_SCHEDULER_TARGET_FRACTIONS[key])
    numeric = float(target)
    if not np.isfinite(numeric) or numeric <= 0.0 or numeric > 1.0:
        raise ValueError("scheduler_target_fraction must lie in (0, 1].")
    return "custom", float(numeric)


def _candidate_chunk_sizes(total: int) -> list[int]:
    total_i = max(1, int(total))
    fractions = (1.0, 0.875, 0.75, 0.625, 0.5, 0.375, 0.25, 0.125)
    values = {1, total_i}
    for fraction in fractions:
        values.add(max(1, min(total_i, int(np.ceil(total_i * float(fraction))))))
    current = total_i
    while current > 1:
        current = max(1, (current + 1) // 2)
        values.add(int(current))
        if current <= 4:
            break
    return sorted(values, reverse=True)


def _bucket_scheduler_dimension(value: int) -> int:
    value_i = max(1, int(value))
    bucket = 1
    while bucket < value_i:
        bucket *= 2
    return int(bucket)


def _load_scheduler_calibration_cache() -> dict[str, Any]:
    path = _SCHEDULER_CALIBRATION_CACHE_PATH
    try:
        if not path.exists():
            return {"version": _SCHEDULER_CALIBRATION_CACHE_VERSION, "entries": {}}
        with path.open("r", encoding="utf-8") as fh:
            payload = json.load(fh)
    except Exception:
        return {"version": _SCHEDULER_CALIBRATION_CACHE_VERSION, "entries": {}}
    if not isinstance(payload, dict):
        return {"version": _SCHEDULER_CALIBRATION_CACHE_VERSION, "entries": {}}
    if int(payload.get("version", -1)) != _SCHEDULER_CALIBRATION_CACHE_VERSION:
        return {"version": _SCHEDULER_CALIBRATION_CACHE_VERSION, "entries": {}}
    entries = payload.get("entries", {})
    if not isinstance(entries, dict):
        entries = {}
    return {"version": _SCHEDULER_CALIBRATION_CACHE_VERSION, "entries": entries}


def _save_scheduler_calibration_cache(payload: Mapping[str, Any]) -> None:
    path = _SCHEDULER_CALIBRATION_CACHE_PATH
    try:
        path.parent.mkdir(parents=True, exist_ok=True)
        with path.open("w", encoding="utf-8") as fh:
            json.dump(dict(payload), fh, indent=2, sort_keys=True)
    except Exception:
        return


def _has_cuda() -> bool:
    return cuda is not None and bool(cuda.is_available())


def _require_cuda() -> None:
    if not _has_cuda():
        raise RuntimeError(
            "CUDA is not available. Install numba with CUDA support and run "
            "inside an environment where numba.cuda.is_available() is True."
        )


def _has_cupy() -> bool:
    return cp is not None and cupy_special is not None


def _require_cupy() -> None:
    if not _has_cupy():
        raise RuntimeError(
            "CuPy is required for the exact EPFDflow GPU helpers. "
            "Install it in the full environment (scepter-dev-full)."
        )
    os.environ.setdefault("CONDA_PREFIX", sys.prefix)


def copy_device_to_host(value: Any) -> np.ndarray:
    """
    Copy a CUDA-array-compatible value back to host memory.

    Parameters
    ----------
    value : Any
        Host NumPy array, Numba device array, CuPy array, or any object
        exposing the CUDA array interface.

    Returns
    -------
    np.ndarray
        Host NumPy array copy.

    Raises
    ------
    TypeError
        If `value` cannot be interpreted as a host or CUDA array.
    """
    if isinstance(value, np.ndarray):
        return value.copy()
    if hasattr(value, "copy_to_host"):
        return np.asarray(value.copy_to_host())
    if _has_cupy() and isinstance(value, cp.ndarray):
        return cp.asnumpy(value)
    if _is_cuda_array(value):
        return np.asarray(cuda.as_cuda_array(value).copy_to_host())
    raise TypeError(f"Unsupported device/host array type: {type(value)!r}.")


def _array_nbytes_any(value: Any) -> int:
    if value is None:
        return 0
    nbytes = getattr(value, "nbytes", None)
    if nbytes is not None:
        try:
            return int(nbytes)
        except Exception:
            pass
    shape = getattr(value, "shape", None)
    dtype = getattr(value, "dtype", None)
    if shape is not None and dtype is not None:
        total = int(np.dtype(dtype).itemsize)
        for dim in shape:
            total *= int(dim)
        return int(total)
    try:
        return int(np.asarray(value).nbytes)
    except Exception:
        return 0


def _shape_nbytes_gpu(shape: tuple[int, ...], dtype: Any) -> int:
    dtype_obj = np.dtype(dtype)
    total = int(dtype_obj.itemsize)
    for dim in shape:
        total *= int(dim)
    return total


def _normalise_device_headroom_profile(profile: str) -> tuple[str, dict[str, float | int]]:
    name = str(profile).strip().lower()
    if name not in _DEVICE_MEMORY_HEADROOM_PROFILES:
        raise ValueError(
            "headroom_profile must be one of "
            f"{sorted(_DEVICE_MEMORY_HEADROOM_PROFILES)!r}; got {profile!r}."
        )
    return name, _DEVICE_MEMORY_HEADROOM_PROFILES[name]


def _copy_cp_to_device_view(value: Any) -> Any:
    if _has_cupy() and isinstance(value, cp.ndarray):
        return cuda.as_cuda_array(value)
    return value


def _to_cupy_array(value: Any, *, dtype: Any | None = None, copy: bool = False) -> Any:
    _require_cupy()
    if isinstance(value, cp.ndarray):
        out = value
    elif _is_cuda_array(value):
        out = cp.asarray(value)
    else:
        out = cp.asarray(value)
    if dtype is not None and out.dtype != cp.dtype(dtype):
        out = out.astype(dtype, copy=False)
    elif copy:
        out = out.copy()
    return out


def _cupy_rng(seed: int) -> Any:
    _require_cupy()
    return cp.random.RandomState(int(seed))


def _normalise_compute_dtype(compute_dtype: Any) -> np.dtype:
    dtype = np.dtype(compute_dtype)
    if dtype.type not in SUPPORTED_COMPUTE_DTYPES:
        if dtype == np.dtype(np.float16):
            raise NotImplementedError(
                "compute_dtype=float16 is not supported. Use float32 or "
                "float64 compute and optionally request output_dtype=float16."
            )
        raise TypeError(
            "compute_dtype must be one of float64 or float32; "
            f"got {dtype!r}."
        )
    return dtype


def _normalise_output_dtype(output_dtype: Any | None, *, default: np.dtype) -> np.dtype:
    if output_dtype is None:
        return default
    dtype = np.dtype(output_dtype)
    if dtype.type not in SUPPORTED_OUTPUT_DTYPES:
        raise TypeError(
            "output_dtype must be one of float64, float32, or float16; "
            f"got {dtype!r}."
        )
    return dtype


def _normalise_method(method: str | None, *, default: str) -> str:
    canonical = _METHOD_ALIASES.get(default if method is None else str(method))
    if canonical is None:
        raise NotImplementedError(
            "method must be one of {'vallado', 'dwarner'}; "
            f"got {method!r}."
        )
    return canonical


def _normalise_selection_strategy(strategy: str | None) -> str:
    resolved = "random" if strategy is None else str(strategy).lower()
    if resolved in {"random", "rng", "rand"}:
        return "random"
    if resolved in {"max_elevation", "elevation", "highest_elevation"}:
        return "max_elevation"
    raise ValueError(
        "selection strategy must be one of "
        "{'random', 'max_elevation'}; "
        f"got {strategy!r}."
    )


def _normalise_earth_model(model: str | None, *, default: str) -> str:
    resolved = default if model is None else str(model).lower()
    if resolved not in EARTH_SHAPE_MODELS:
        raise ValueError(
            "earth models must be one of {'wgs72', 'wgs84'}; "
            f"got {model!r}."
        )
    return resolved


def _normalise_per_satellite_float(
    value: Any,
    n_sats: int,
    *,
    name: str,
    dtype: np.dtype,
    fill_value: float | None = None,
) -> np.ndarray:
    if value is None:
        if fill_value is None:
            raise ValueError(f"{name} must not be None.")
        return np.full(n_sats, fill_value, dtype=dtype)

    if hasattr(value, "to_value"):
        arr = np.asarray(u.Quantity(value).to_value(u.deg), dtype=np.float64)
    else:
        arr = _to_host_plain_array(value, dtype=np.float64)

    if arr.ndim == 0:
        return np.full(n_sats, float(arr), dtype=dtype)

    flat = arr.reshape(-1)
    if flat.size == 1:
        return np.full(n_sats, float(flat[0]), dtype=dtype)
    if flat.size != n_sats:
        raise ValueError(f"{name} must be scalar or have length {n_sats}, got {flat.size}.")
    return flat.astype(dtype, copy=False)


def _normalise_per_satellite_int(
    value: Any,
    n_sats: int,
    *,
    name: str,
    dtype: np.dtype,
    fill_value: int,
) -> np.ndarray:
    if value is None:
        return np.full(n_sats, fill_value, dtype=dtype)

    if _is_cuda_array(value):
        arr = cuda.as_cuda_array(value).copy_to_host()
    else:
        arr = np.asarray(value)
    if arr.ndim == 0:
        return np.full(n_sats, int(arr), dtype=dtype)

    flat = arr.reshape(-1)
    if flat.size == 1:
        return np.full(n_sats, int(flat[0]), dtype=dtype)
    if flat.size != n_sats:
        raise ValueError(f"{name} must be scalar or have length {n_sats}, got {flat.size}.")
    return flat.astype(dtype, copy=False)


def _earth_shape_constants(model: str) -> tuple[float, float]:
    spec = EARTH_SHAPE_MODELS[_normalise_earth_model(model, default=EARTH_MODEL_WGS72)]
    return float(spec["a_km"]), float(spec["e2"])


def _sgp4_gravity_spec(model: str) -> Any:
    from sgp4.earth_gravity import wgs72, wgs84

    resolved = _normalise_earth_model(model, default=EARTH_MODEL_WGS72)
    return wgs72 if resolved == EARTH_MODEL_WGS72 else wgs84


def _warn_context_model_override(
    *,
    kind: str,
    supplied_model: str,
    context_model: str,
) -> None:
    warnings.warn(
        f"Ignoring {kind}={supplied_model!r} because the explicit prepared context "
        f"is already bound to {context_model!r}.",
        GpuEarthModelOverrideWarning,
        stacklevel=3,
    )


def _warn_if_mixed_earth_models(*, gravity_model: str, ellipsoid_model: str) -> None:
    if gravity_model == ellipsoid_model:
        return
    warnings.warn(
        "Mixed earth-model configuration detected: "
        f"gravity_model={gravity_model!r}, ellipsoid_model={ellipsoid_model!r}. "
        "This is allowed, but it is non-standard and may produce surprising "
        "geometry-relative results.",
        GpuMixedEarthModelWarning,
        stacklevel=3,
    )


def _require_supported_geometry_flags(
    *,
    do_geo: bool = False,
    do_obs_pos: bool = False,
    do_sat_rotmat: bool = False,
    sat_frame: str = "xyz",
    on_error: str = "raise",
) -> None:
    del do_geo, do_obs_pos, do_sat_rotmat
    if sat_frame not in {"xyz", "zxy"}:
        raise NotImplementedError("Only sat_frame='xyz' or sat_frame='zxy' is supported by the GPU backend.")
    if on_error not in {"raise", "coerce_to_nan"}:
        raise ValueError("on_error must be either 'raise' or 'coerce_to_nan'.")


def _as_ordered_tuple(
    value: Any,
    *,
    default_factory: Callable[[], Any] | None = None,
) -> tuple[Any, ...]:
    if value is None:
        if default_factory is None:
            return tuple()
        return (default_factory(),)

    arr = np.asarray(value, dtype=object)
    if arr.ndim == 0:
        return (arr.item(),)

    squeezed = np.squeeze(arr)
    if squeezed.ndim == 0:
        return (squeezed.item(),)
    if squeezed.ndim != 1:
        raise NotImplementedError(
            "This GPU backend currently expects scalar or 1-D tles/observers, "
            "or broadcast-style arrays that squeeze to 1-D."
        )
    return tuple(squeezed.tolist())


def _as_time_vector(mjds: Any) -> np.ndarray:
    arr = np.asarray(mjds, dtype=np.float64)
    if arr.ndim == 0:
        return arr.reshape(1)
    squeezed = np.squeeze(arr)
    if squeezed.ndim == 0:
        return squeezed.reshape(1)
    if squeezed.ndim != 1:
        raise NotImplementedError(
            "This GPU backend currently expects scalar or 1-D mjds, or "
            "broadcast-style arrays that squeeze to 1-D."
        )
    return squeezed.astype(np.float64, copy=False)


def _observer_key(observer: Any) -> tuple[float, float, float]:
    return (
        float(observer.loc.lon),
        float(observer.loc.lat),
        float(observer.loc.alt),
    )


def _tle_key(tle: Any) -> tuple[str, str, str]:
    name, line1, line2 = tle.tle_strings()
    return str(name), str(line1), str(line2)


def _ordered_unique(items: Iterable[Any], *, key_func: Callable[[Any], Any]) -> tuple[Any, ...]:
    seen: dict[Any, None] = {}
    ordered: list[Any] = []
    for item in items:
        key = key_func(item)
        if key in seen:
            continue
        seen[key] = None
        ordered.append(item)
    return tuple(ordered)


def _observer_geodetic_arrays(observers: tuple[Any, ...]) -> tuple[np.ndarray, np.ndarray, np.ndarray]:
    lon_deg = np.asarray([float(obs.loc.lon) for obs in observers], dtype=np.float64)
    lat_deg = np.asarray([float(obs.loc.lat) for obs in observers], dtype=np.float64)
    alt_km = np.asarray([float(obs.loc.alt) for obs in observers], dtype=np.float64)
    return lon_deg, lat_deg, alt_km


def _observer_ecef_from_geodetic(
    lon_deg: np.ndarray,
    lat_deg: np.ndarray,
    alt_km: np.ndarray,
    *,
    ellipsoid_model: str,
) -> tuple[np.ndarray, np.ndarray, np.ndarray, np.ndarray, np.ndarray, np.ndarray, np.ndarray]:
    a_km, e2 = _earth_shape_constants(ellipsoid_model)
    lon_rad = np.deg2rad(lon_deg.astype(np.float64, copy=False))
    lat_rad = np.deg2rad(lat_deg.astype(np.float64, copy=False))

    sin_lat = np.sin(lat_rad)
    cos_lat = np.cos(lat_rad)
    sin_lon = np.sin(lon_rad)
    cos_lon = np.cos(lon_rad)

    N = a_km / np.sqrt(1.0 - e2 * sin_lat * sin_lat)
    x = (N + alt_km) * cos_lat * cos_lon
    y = (N + alt_km) * cos_lat * sin_lon
    z = (N * (1.0 - e2) + alt_km) * sin_lat
    return x, y, z, sin_lat, cos_lat, sin_lon, cos_lon


def _gmst_from_mjd(mjds: np.ndarray) -> np.ndarray:
    from sgp4.propagation import gstime

    jd = mjds.astype(np.float64, copy=False) + MJD_TO_JD_OFFSET
    return np.asarray([gstime(float(jd_i)) for jd_i in jd], dtype=np.float64)


def _normalise_observer_slice(
    observer_slice: slice | None,
    total: int,
) -> tuple[int, int]:
    if observer_slice is None:
        return 0, total
    if not isinstance(observer_slice, slice):
        raise TypeError("observer_slice must be None or a built-in slice object.")
    step = 1 if observer_slice.step is None else int(observer_slice.step)
    if step != 1:
        raise ValueError("observer_slice must be contiguous with step=1.")
    start = 0 if observer_slice.start is None else int(observer_slice.start)
    stop = total if observer_slice.stop is None else int(observer_slice.stop)
    if start < 0:
        start += total
    if stop < 0:
        stop += total
    start = max(0, min(total, start))
    stop = max(start, min(total, stop))
    return start, stop - start


def _is_cuda_array(value: Any) -> bool:
    return hasattr(value, "__cuda_array_interface__")


def _shape_of_input(value: Any) -> tuple[int, ...]:
    if hasattr(value, "shape"):
        return tuple(getattr(value, "shape"))
    if hasattr(value, "to_value"):
        return tuple(np.shape(u.Quantity(value).to_value(u.deg)))
    return tuple(np.shape(value))


def _broadcast_shape_from_inputs(*values: Any) -> tuple[int, ...]:
    shapes = [_shape_of_input(value) for value in values]
    return tuple(np.broadcast_shapes(*shapes))


def _to_host_degree_array(value: Any, *, dtype: np.dtype | type[np.floating] = np.float64) -> np.ndarray:
    if _is_cuda_array(value):
        value = cuda.as_cuda_array(value).copy_to_host()
    if hasattr(value, "to_value"):
        arr = np.asarray(u.Quantity(value).to_value(u.deg))
    else:
        arr = np.asarray(value)
    return np.ascontiguousarray(arr, dtype=np.dtype(dtype))


def _to_host_plain_array(value: Any, *, dtype: np.dtype | type[Any]) -> np.ndarray:
    if _is_cuda_array(value):
        value = cuda.as_cuda_array(value).copy_to_host()
    return np.ascontiguousarray(np.asarray(value), dtype=np.dtype(dtype))


def _to_scalar_decibel_value(value: Any, *, name: str) -> float:
    """
    Convert a scalar decibel-like value to a plain float in dB.

    Parameters
    ----------
    value : Any
        Scalar float/int or an Astropy logarithmic quantity such as
        ``u.dB``, ``cnv.dB``, or ``cnv.dBi``.
    name : str
        Human-readable parameter name used in validation errors.

    Returns
    -------
    float
        Scalar value expressed in dB.

    Raises
    ------
    ValueError
        Raised when ``value`` is not scalar after host conversion.

    Notes
    -----
    Astropy distinguishes plain ``dB`` from logarithmic units such as
    ``dB(1)``. Normalising through ``u.dB`` preserves the numeric decibel value
    for both forms and for ``dBi``-style gains.
    """
    if _is_cuda_array(value):
        value = cuda.as_cuda_array(value).copy_to_host()

    if hasattr(value, "to_value"):
        arr = np.asarray(u.Quantity(value).to_value(u.dB), dtype=np.float64)
    else:
        arr = np.asarray(value, dtype=np.float64)

    flat = arr.reshape(-1)
    if flat.size != 1:
        raise ValueError(f"{name} must be scalar, got shape {arr.shape}.")
    return float(flat[0])


def _normalise_conditioned_template_mode(mode: str | None) -> str:
    resolved = CONDITIONED_TEMPLATE_MODE_HYBRID if mode is None else str(mode).lower()
    if resolved not in {
        CONDITIONED_TEMPLATE_MODE_PER_SOURCE,
        CONDITIONED_TEMPLATE_MODE_PER_ROW,
        CONDITIONED_TEMPLATE_MODE_HYBRID,
    }:
        raise ValueError(
            "template mode must be one of "
            "{'per_source', 'per_row', 'hybrid'}."
        )
    return resolved


def _conditioned_template_scratch_bytes(active_rows: int, pool_size: int) -> int:
    rows = int(max(0, active_rows))
    pool = int(max(0, pool_size))
    float_bytes = rows * pool * _CONDITIONED_TEMPLATE_FLOAT_SCRATCH_ARRAYS * np.dtype(np.float32).itemsize
    int_bytes = rows * pool * _CONDITIONED_TEMPLATE_INT_SCRATCH_ARRAYS * np.dtype(np.int32).itemsize
    return int(float_bytes + int_bytes)


def _encode_sampler_source(kind: np.ndarray, source_id: np.ndarray) -> np.ndarray:
    kind_i64 = np.asarray(kind, dtype=np.int64)
    source_i64 = np.asarray(source_id, dtype=np.int64)
    return (kind_i64 + 1) * np.int64(1_000_000_000_000) + source_i64


def _s1586_skycell_id_host(
    azimuth_deg: np.ndarray,
    elevation_deg: np.ndarray,
) -> np.ndarray:
    az = np.asarray(azimuth_deg, dtype=np.float32)
    el = np.asarray(elevation_deg, dtype=np.float32)
    sky = np.full(az.shape, -1, dtype=np.int32)
    valid = np.isfinite(az) & np.isfinite(el) & (el >= 0.0) & (el <= 90.0)
    if not np.any(valid):
        return sky

    az_valid = np.remainder(az[valid], np.float32(360.0)).astype(np.float32, copy=False)
    el_valid = el[valid]
    ring = np.floor(el_valid / np.float32(3.0)).astype(np.int32, copy=False)
    np.minimum(ring, np.int32(_S1586_AZ_STEPS_DEG.size - 1), out=ring)
    step = _S1586_AZ_STEPS_DEG[ring].astype(np.float32, copy=False)
    ring_counts = _S1586_RING_COUNTS[ring]
    az_bin = np.floor(az_valid / step).astype(np.int32, copy=False)
    np.minimum(az_bin, ring_counts - 1, out=az_bin)
    sky[valid] = _S1586_RING_OFFSETS[ring] + az_bin
    return sky


def _s1586_skycell_id_device(
    azimuth_deg: Any,
    elevation_deg: Any,
) -> Any:
    az = _to_cupy_array(azimuth_deg, dtype=cp.float32)
    el = _to_cupy_array(elevation_deg, dtype=cp.float32)
    sky = cp.full(az.shape, -1, dtype=cp.int32)
    valid = cp.isfinite(az) & cp.isfinite(el) & (el >= cp.float32(0.0)) & (el <= cp.float32(90.0))
    if int(cp.nonzero(valid)[0].size) <= 0:
        return sky

    az_valid = cp.remainder(az[valid], cp.float32(360.0))
    el_valid = el[valid]
    ring = cp.floor(el_valid / cp.float32(3.0)).astype(cp.int32, copy=False)
    ring = cp.minimum(ring, cp.int32(_S1586_AZ_STEPS_DEG.size - 1))
    step = cp.asarray(_S1586_AZ_STEPS_DEG, dtype=cp.int32)[ring].astype(cp.float32, copy=False)
    ring_counts = cp.asarray(_S1586_RING_COUNTS, dtype=cp.int32)[ring]
    az_bin = cp.floor(az_valid / step).astype(cp.int32, copy=False)
    az_bin = cp.minimum(az_bin, ring_counts - 1)
    offsets = cp.asarray(_S1586_RING_OFFSETS, dtype=cp.int32)[ring]
    sky[valid] = offsets + az_bin
    return sky


def _coerce_link_pairwise_tensor(
    value: Any,
    *,
    name: str,
    min_last_dim: int,
    compute_dtype: np.dtype,
) -> tuple[Any, bool, tuple[int, int, int, int]]:
    if _is_cuda_array(value):
        arr = cuda.as_cuda_array(value)
        shape = tuple(int(v) for v in arr.shape)
        if len(shape) == 3:
            host = arr.copy_to_host()
            host = np.ascontiguousarray(host[np.newaxis, ...], dtype=compute_dtype)
            d_arr = cuda.to_device(host)
            return d_arr, True, tuple(int(v) for v in d_arr.shape)
        if len(shape) != 4:
            raise ValueError(f"{name} must be a 3-D or 4-D array, got shape {shape!r}.")
        if shape[-1] < min_last_dim:
            raise ValueError(
                f"{name} last axis must contain at least {min_last_dim} fields; "
                f"got {shape[-1]}."
            )
        return arr, False, shape

    host = np.asarray(value)
    single_time_input = host.ndim == 3
    if single_time_input:
        host = host[np.newaxis, ...]
    elif host.ndim != 4:
        raise ValueError(f"{name} must be a 3-D or 4-D array, got shape {host.shape!r}.")
    host = np.ascontiguousarray(host, dtype=compute_dtype)
    if host.shape[-1] < min_last_dim:
        raise ValueError(
            f"{name} last axis must contain at least {min_last_dim} fields; "
            f"got {host.shape[-1]}."
        )
    return cuda.to_device(host), single_time_input, tuple(int(v) for v in host.shape)


def _coerce_ras_topo_tensor(
    value: Any,
    *,
    time_count: int,
    sat_count: int,
    compute_dtype: np.dtype,
) -> Any:
    if _is_cuda_array(value):
        arr = cuda.as_cuda_array(value)
        shape = tuple(int(v) for v in arr.shape)
        if len(shape) == 4:
            if shape[1] < 1:
                raise ValueError("ras_topo observer axis must not be empty.")
            arr = arr[:, 0, :, :]
            shape = tuple(int(v) for v in arr.shape)
        elif len(shape) == 2:
            host = arr.copy_to_host()
            host = np.ascontiguousarray(host[np.newaxis, ...], dtype=compute_dtype)
            arr = cuda.to_device(host)
            shape = tuple(int(v) for v in arr.shape)
        elif len(shape) != 3:
            raise ValueError("ras_topo must be a 2-D, 3-D, or 4-D array.")
        if shape[0] != time_count or shape[1] != sat_count:
            raise ValueError(
                f"ras_topo must have shape ({time_count}, {sat_count}, K) after normalization; "
                f"got {shape!r}."
            )
        if shape[-1] < 2:
            raise ValueError("ras_topo last axis must contain at least azimuth and elevation.")
        return arr

    arr = np.asarray(value)
    if arr.ndim == 2:
        arr = arr[np.newaxis, ...]
    elif arr.ndim == 4:
        if arr.shape[1] < 1:
            raise ValueError("ras_topo observer axis must not be empty.")
        arr = arr[:, 0, :, :]
    elif arr.ndim != 3:
        raise ValueError("ras_topo must be a 2-D, 3-D, or 4-D array.")
    arr = np.ascontiguousarray(arr, dtype=compute_dtype)
    if arr.shape[0] != time_count or arr.shape[1] != sat_count:
        raise ValueError(
            f"ras_topo must have shape ({time_count}, {sat_count}, K) after normalization; "
            f"got {arr.shape!r}."
        )
    if arr.shape[-1] < 2:
        raise ValueError("ras_topo last axis must contain at least azimuth and elevation.")
    return cuda.to_device(arr)


def _normalise_ras_topo_host(
    value: Any,
    *,
    time_count: int,
    sat_count: int,
    compute_dtype: np.dtype,
) -> np.ndarray:
    if _is_cuda_array(value):
        arr = cuda.as_cuda_array(value).copy_to_host()
    else:
        arr = np.asarray(value)
    if arr.ndim == 2:
        arr = arr[np.newaxis, ...]
    elif arr.ndim == 4:
        if arr.shape[1] < 1:
            raise ValueError("ras_topo observer axis must not be empty.")
        arr = arr[:, 0, :, :]
    elif arr.ndim != 3:
        raise ValueError("ras_topo must be a 2-D, 3-D, or 4-D array.")
    arr = np.ascontiguousarray(arr, dtype=compute_dtype)
    if arr.shape[0] != time_count or arr.shape[1] != sat_count:
        raise ValueError(
            f"ras_topo must have shape ({time_count}, {sat_count}, K) after normalization; "
            f"got {arr.shape!r}."
        )
    if arr.shape[-1] < 2:
        raise ValueError("ras_topo last axis must contain at least azimuth and elevation.")
    return arr


def _normalise_ras_topo_cupy(
    value: Any,
    *,
    time_count: int,
    sat_count: int,
    compute_dtype: np.dtype,
) -> Any:
    _require_cupy()
    if _is_cuda_array(value) or (_has_cupy() and isinstance(value, cp.ndarray)):
        arr = _to_cupy_array(value, dtype=compute_dtype)
    else:
        arr = cp.asarray(np.asarray(value), dtype=compute_dtype)
    if arr.ndim == 2:
        arr = arr[None, ...]
    elif arr.ndim == 4:
        if int(arr.shape[1]) < 1:
            raise ValueError("ras_topo observer axis must not be empty.")
        arr = arr[:, 0, :, :]
    elif arr.ndim != 3:
        raise ValueError("ras_topo must be a 2-D, 3-D, or 4-D array.")
    if int(arr.shape[0]) != time_count or int(arr.shape[1]) != sat_count:
        raise ValueError(
            f"ras_topo must have shape ({time_count}, {sat_count}, K) after normalization; "
            f"got {tuple(int(v) for v in arr.shape)!r}."
        )
    if int(arr.shape[-1]) < 2:
        raise ValueError("ras_topo last axis must contain at least azimuth and elevation.")
    return cp.ascontiguousarray(arr)


def _seed_from_rng(rng: np.random.Generator | int | np.integer | None) -> np.uint64:
    if rng is None:
        local_rng = np.random.default_rng()
        return np.uint64(local_rng.integers(0, np.iinfo(np.uint64).max, dtype=np.uint64))
    if isinstance(rng, np.random.Generator):
        return np.uint64(rng.integers(0, np.iinfo(np.uint64).max, dtype=np.uint64))
    return np.uint64(int(rng))


def _splitmix64_cupy(x: Any) -> Any:
    _require_cupy()
    z = _to_cupy_array(x, dtype=cp.uint64)
    z = z * cp.uint64(6364136223846793005) + cp.uint64(1442695040888963407)
    z = z ^ (z >> cp.uint64(33))
    z = z * cp.uint64(3202034522624059733)
    z = z ^ (z >> cp.uint64(29))
    z = z * cp.uint64(3935559000370003845)
    return z ^ (z >> cp.uint64(32))


_pair_priority_fused_kernel = None


def _get_pair_priority_fused_kernel():
    """Fused kernel: combine pair-priority key derivation + splitmix64
    hash in one launch.  Replaces ~12 sequential CuPy operations
    (uint64 arithmetic + bit mixing) with a single ElementwiseKernel."""
    global _pair_priority_fused_kernel
    if _pair_priority_fused_kernel is not None:
        return _pair_priority_fused_kernel
    _pair_priority_fused_kernel = cp.ElementwiseKernel(
        "uint64 row_idx, uint64 sat_idx, uint64 seed, uint64 c1, uint64 c2",
        "uint64 priority",
        r"""
        unsigned long long key = seed
            + (row_idx + 1ULL) * c1
            + (sat_idx + 1ULL) * c2;
        /* splitmix64 */
        key = key * 6364136223846793005ULL + 1442695040888963407ULL;
        key ^= (key >> 33);
        key *= 3202034522624059733ULL;
        key ^= (key >> 29);
        key *= 3935559000370003845ULL;
        priority = key ^ (key >> 32);
        """,
        "pair_priority_splitmix64_fused",
    )
    return _pair_priority_fused_kernel


def _pair_priority_random_cupy(
    seed_u64: np.uint64,
    row_index: Any,
    sat_index: Any,
) -> Any:
    _require_cupy()
    # Use fused kernel: 12 CuPy dispatches → 1 ElementwiseKernel.
    _kernel = _get_pair_priority_fused_kernel()
    return _kernel(
        _to_cupy_array(row_index, dtype=cp.uint64),
        _to_cupy_array(sat_index, dtype=cp.uint64),
        np.uint64(int(seed_u64)),
        np.uint64(int(_GPU_LINK_RANDOM_PAIR_C1)),
        np.uint64(int(_GPU_LINK_RANDOM_PAIR_C2)),
    )


def _stable_lexsort_cupy(*keys: Any) -> Any:
    """
    GPU-side stable lexsort for one-dimensional CuPy keys.

    CuPy's :func:`lexsort` requires a stacked array with a common dtype, which
    is not suitable here because the finite-cap selector mixes integer and
    floating / uint64 priority keys. This helper reproduces NumPy's lexsort
    semantics with repeated stable argsorts on-device.
    """

    if not keys:
        raise ValueError("At least one key is required.")
    order = None
    for key in keys:
        key_array = _to_cupy_array(key)
        if key_array.ndim != 1:
            raise ValueError("All lexsort keys must be one-dimensional.")
        if order is None:
            order = cp.arange(key_array.size, dtype=cp.int64)
        elif key_array.size != order.size:
            raise ValueError("All lexsort keys must share the same length.")

    assert order is not None
    for key in keys:
        key_array = _to_cupy_array(key)
        ranked = key_array[order]
        order = order[cp.argsort(ranked, kind="stable")]
    return order


def _gpu_used_bytes_observation_cp() -> int | None:
    _require_cupy()
    candidates: list[int] = []
    try:
        free_bytes, total_bytes = cp.cuda.runtime.memGetInfo()
        candidates.append(int(total_bytes) - int(free_bytes))
    except Exception:
        pass
    try:
        pool = cp.get_default_memory_pool()
        if hasattr(pool, "used_bytes"):
            candidates.append(int(pool.used_bytes()))
    except Exception:
        pass
    if not candidates:
        return None
    return int(max(candidates))


def _start_gpu_memory_observation_cp() -> dict[str, Any]:
    used_bytes = _gpu_used_bytes_observation_cp()
    return {
        "start_used_bytes": None if used_bytes is None else int(used_bytes),
        "end_used_bytes": None if used_bytes is None else int(used_bytes),
        "peak_used_bytes": None if used_bytes is None else int(used_bytes),
    }


def _update_gpu_memory_observation_cp(observation: Mapping[str, Any] | None) -> dict[str, Any]:
    updated = dict(observation or {})
    used_bytes = _gpu_used_bytes_observation_cp()
    if used_bytes is None:
        return updated
    if updated.get("start_used_bytes") is None:
        updated["start_used_bytes"] = int(used_bytes)
    updated["end_used_bytes"] = int(used_bytes)
    updated["peak_used_bytes"] = int(
        max(int(updated.get("peak_used_bytes", used_bytes) or used_bytes), int(used_bytes))
    )
    return updated


def _finalize_gpu_memory_observation_cp(observation: Mapping[str, Any] | None) -> dict[str, Any]:
    finalized = dict(observation or {})
    start_used_bytes = finalized.get("start_used_bytes")
    end_used_bytes = finalized.get("end_used_bytes")
    peak_used_bytes = finalized.get("peak_used_bytes")
    try:
        start_i = None if start_used_bytes is None else int(start_used_bytes)
        end_i = None if end_used_bytes is None else int(end_used_bytes)
        peak_i = None if peak_used_bytes is None else int(peak_used_bytes)
    except Exception:
        return finalized
    if start_i is not None and end_i is not None:
        finalized["resident_bytes"] = int(max(0, end_i - start_i))
    else:
        finalized.setdefault("resident_bytes", None)
    if peak_i is not None:
        baseline_i = max(
            int(start_i) if start_i is not None else 0,
            int(end_i) if end_i is not None else 0,
        )
        finalized["transient_peak_bytes"] = int(max(0, peak_i - baseline_i))
    else:
        finalized.setdefault("transient_peak_bytes", None)
    return finalized


def _concatenate_or_single_cp(
    parts: list[Any],
    *,
    dtype: Any | None = None,
    empty_dtype: Any,
) -> Any:
    """Pack CuPy array parts while avoiding redundant single-part concatenation."""
    if not parts:
        return cp.empty(0, dtype=empty_dtype)
    if len(parts) == 1:
        array_cp = parts[0]
    else:
        array_cp = cp.concatenate(parts)
    if dtype is not None:
        return array_cp.astype(dtype, copy=False)
    return array_cp


def _build_link_library_candidate_base_cp(
    library: "GpuSatelliteLinkSelectionLibrary",
) -> dict[str, Any]:
    if library._packed_candidate_base_cp is not None:
        return library._packed_candidate_base_cp

    if library._candidate_time_parts:
        candidate_time_cp = _concatenate_or_single_cp(
            library._candidate_time_parts,
            dtype=cp.int32,
            empty_dtype=cp.int32,
        )
        candidate_cell_cp = _concatenate_or_single_cp(
            library._candidate_cell_parts,
            dtype=cp.int32,
            empty_dtype=cp.int32,
        )
        candidate_sat_cp = _concatenate_or_single_cp(
            library._candidate_sat_parts,
            dtype=cp.int32,
            empty_dtype=cp.int32,
        )
        candidate_key_cp = _concatenate_or_single_cp(
            library._candidate_key_parts,
            empty_dtype=cp.float64,
        )
        candidate_alpha_deg_cp = None
        candidate_beta_deg_cp = None
        candidate_alpha_rad_cp = None
        candidate_beta_rad_cp = None
        if library._candidate_alpha_parts is not None and library._candidate_beta_parts is not None:
            candidate_alpha_deg_cp = _concatenate_or_single_cp(
                library._candidate_alpha_parts,
                dtype=cp.float32,
                empty_dtype=cp.float32,
            )
            candidate_beta_deg_cp = _concatenate_or_single_cp(
                library._candidate_beta_parts,
                dtype=cp.float32,
                empty_dtype=cp.float32,
            )
            candidate_alpha_rad_cp = cp.remainder(
                candidate_alpha_deg_cp * cp.float32(np.pi / 180.0),
                cp.float32(2.0 * np.pi),
            ).astype(cp.float32, copy=False)
            candidate_beta_rad_cp = (
                candidate_beta_deg_cp * cp.float32(np.pi / 180.0)
            ).astype(cp.float32, copy=False)
    else:
        candidate_time_cp = cp.empty(0, dtype=cp.int32)
        candidate_cell_cp = cp.empty(0, dtype=cp.int32)
        candidate_sat_cp = cp.empty(0, dtype=cp.int32)
        candidate_key_cp = cp.empty(0, dtype=cp.float64)
        candidate_alpha_deg_cp = (
            cp.empty(0, dtype=cp.float32)
            if library._candidate_alpha_parts is not None and library._candidate_beta_parts is not None
            else None
        )
        candidate_beta_deg_cp = (
            cp.empty(0, dtype=cp.float32)
            if library._candidate_alpha_parts is not None and library._candidate_beta_parts is not None
            else None
        )
        candidate_alpha_rad_cp = (
            cp.empty(0, dtype=cp.float32)
            if library._candidate_alpha_parts is not None and library._candidate_beta_parts is not None
            else None
        )
        candidate_beta_rad_cp = (
            cp.empty(0, dtype=cp.float32)
            if library._candidate_alpha_parts is not None and library._candidate_beta_parts is not None
            else None
        )

    library._packed_candidate_base_cp = {
        "time": candidate_time_cp,
        "cell": candidate_cell_cp,
        "sat": candidate_sat_cp,
        "key": candidate_key_cp,
        "alpha_deg": candidate_alpha_deg_cp,
        "beta_deg": candidate_beta_deg_cp,
        "alpha_rad": candidate_alpha_rad_cp,
        "beta_rad": candidate_beta_rad_cp,
    }
    library._candidate_time_parts.clear()
    library._candidate_cell_parts.clear()
    library._candidate_sat_parts.clear()
    library._candidate_key_parts.clear()
    if library._candidate_alpha_parts is not None:
        library._candidate_alpha_parts.clear()
    if library._candidate_beta_parts is not None:
        library._candidate_beta_parts.clear()
    return library._packed_candidate_base_cp


def _get_link_library_selector_candidate_view_cp(
    library: "GpuSatelliteLinkSelectionLibrary",
) -> dict[str, Any]:
    if library._selector_candidate_view_cp is not None:
        return library._selector_candidate_view_cp

    base = _build_link_library_candidate_base_cp(library)
    candidate_count = int(base["time"].size)
    if candidate_count <= 0:
        order_cp = cp.empty(0, dtype=cp.int32)
        segment_start_cp = cp.zeros(library.time_count, dtype=cp.int64)
        segment_end_cp = cp.zeros(library.time_count, dtype=cp.int64)
    else:
        order_cp = _stable_lexsort_cupy(
            base["sat"],
            base["cell"],
            base["key"],
            base["time"],
        ).astype(cp.int32, copy=False)
        time_sorted_cp = base["time"][order_cp]
        time_counts_cp = cp.bincount(
            time_sorted_cp.astype(cp.int32, copy=False),
            minlength=library.time_count,
        ).astype(cp.int64, copy=False)
        segment_end_cp = cp.cumsum(time_counts_cp, dtype=cp.int64)
        segment_start_cp = cp.empty_like(segment_end_cp)
        if library.time_count > 0:
            segment_start_cp[0] = cp.int64(0)
        if library.time_count > 1:
            segment_start_cp[1:] = segment_end_cp[:-1]

    library._selector_candidate_view_cp = {
        "order": order_cp,
        "segment_start": segment_start_cp,
        "segment_end": segment_end_cp,
        "segment_start_host": np.asarray(
            copy_device_to_host(segment_start_cp),
            dtype=np.int64,
        ),
        "segment_end_host": np.asarray(
            copy_device_to_host(segment_end_cp),
            dtype=np.int64,
        ),
    }
    return library._selector_candidate_view_cp


def _get_link_library_direct_candidate_view_cp(
    library: "GpuSatelliteLinkSelectionLibrary",
) -> dict[str, Any]:
    if library._direct_candidate_view_cp is not None:
        return library._direct_candidate_view_cp

    base = _build_link_library_candidate_base_cp(library)
    candidate_count = int(base["time"].size)
    if candidate_count <= 0:
        order_cp = cp.empty(0, dtype=cp.int32)
        row_ptr_cp = cp.zeros(library.time_count * library.cell_count + 1, dtype=cp.int64)
    else:
        order_cp = _stable_lexsort_cupy(
            base["sat"],
            base["key"],
            base["cell"],
            base["time"],
        ).astype(cp.int32, copy=False)
        time_sorted_cp = base["time"][order_cp]
        cell_sorted_cp = base["cell"][order_cp]
        row_id_cp = (
            time_sorted_cp.astype(cp.int64, copy=False) * cp.int64(library.cell_count)
            + cell_sorted_cp.astype(cp.int64, copy=False)
        )
        row_counts_cp = cp.bincount(
            row_id_cp.astype(cp.int32, copy=False),
            minlength=library.time_count * library.cell_count,
        ).astype(cp.int64, copy=False)
        row_ptr_cp = cp.empty(library.time_count * library.cell_count + 1, dtype=cp.int64)
        row_ptr_cp[0] = cp.int64(0)
        row_ptr_cp[1:] = cp.cumsum(row_counts_cp, dtype=cp.int64)

    library._direct_candidate_view_cp = {
        "order": order_cp,
        "row_ptr": row_ptr_cp,
        "row_ptr_host": np.asarray(
            copy_device_to_host(row_ptr_cp),
            dtype=np.int64,
        ),
    }
    return library._direct_candidate_view_cp


def _selector_candidate_slab_cp(
    library: "GpuSatelliteLinkSelectionLibrary",
    *,
    time_start: int,
    time_stop: int,
) -> dict[str, Any]:
    base = _build_link_library_candidate_base_cp(library)
    view = _get_link_library_selector_candidate_view_cp(library)
    if time_start >= time_stop:
        return {
            "candidate_cell": cp.empty(0, dtype=cp.int32),
            "candidate_sat": cp.empty(0, dtype=cp.int32),
            "candidate_alpha_deg": cp.empty(0, dtype=cp.float32),
            "candidate_beta_deg": cp.empty(0, dtype=cp.float32),
            "segment_start": cp.zeros(0, dtype=cp.int64),
            "segment_end": cp.zeros(0, dtype=cp.int64),
        }

    segment_start_host = np.asarray(view["segment_start_host"], dtype=np.int64)
    segment_end_host = np.asarray(view["segment_end_host"], dtype=np.int64)
    start_idx = int(segment_start_host[int(time_start)])
    stop_idx = int(segment_end_host[int(time_stop) - 1])
    order_slice_cp = view["order"][start_idx:stop_idx]
    alpha_base = base["alpha_deg"]
    beta_base = base["beta_deg"]
    return {
        "candidate_cell": base["cell"][order_slice_cp],
        "candidate_sat": base["sat"][order_slice_cp],
        "candidate_alpha_deg": (
            alpha_base[order_slice_cp]
            if alpha_base is not None
            else cp.empty(0, dtype=cp.float32)
        ),
        "candidate_beta_deg": (
            beta_base[order_slice_cp]
            if beta_base is not None
            else cp.empty(0, dtype=cp.float32)
        ),
        "segment_start": view["segment_start"][time_start:time_stop] - cp.int64(start_idx),
        "segment_end": view["segment_end"][time_start:time_stop] - cp.int64(start_idx),
    }


def _direct_candidate_slab_cp(
    library: "GpuSatelliteLinkSelectionLibrary",
    *,
    time_start: int,
    time_stop: int,
) -> dict[str, Any]:
    base = _build_link_library_candidate_base_cp(library)
    view = _get_link_library_direct_candidate_view_cp(library)
    row_start = int(time_start) * int(library.cell_count)
    row_stop = int(time_stop) * int(library.cell_count)
    row_ptr_host = np.asarray(view["row_ptr_host"], dtype=np.int64)
    start_idx = int(row_ptr_host[row_start])
    stop_idx = int(row_ptr_host[row_stop])
    order_slice_cp = view["order"][start_idx:stop_idx]
    alpha_base = base["alpha_rad"]
    beta_base = base["beta_rad"]
    if alpha_base is None or beta_base is None:
        raise RuntimeError("Direct EPFD finalization requires stored candidate alpha/beta geometry.")
    return {
        "candidate_sat": base["sat"][order_slice_cp],
        "candidate_alpha_rad": alpha_base[order_slice_cp],
        "candidate_beta_rad": beta_base[order_slice_cp],
        "row_ptr": view["row_ptr"][row_start : row_stop + 1] - cp.int64(start_idx),
    }


def _frontier_select_link_candidates_reference_cp(
    library: "GpuSatelliteLinkSelectionLibrary",
    *,
    time_start: int,
    time_stop: int,
) -> dict[str, Any]:
    slab = _direct_candidate_slab_cp(
        library,
        time_start=int(time_start),
        time_stop=int(time_stop),
    )
    time_count = int(time_stop) - int(time_start)
    if time_count <= 0:
        raise ValueError("time_stop must be greater than time_start.")

    assignments_cp = cp.full((time_count, library.cell_count, library.n_links), -1, dtype=cp.int32)
    cone_ok_cp = cp.zeros(assignments_cp.shape, dtype=cp.bool_)
    selected_alpha_rad_cp = cp.full(assignments_cp.shape, cp.nan, dtype=cp.float32)
    selected_beta_rad_cp = cp.full(assignments_cp.shape, cp.nan, dtype=cp.float32)
    if int(slab["candidate_sat"].size) <= 0:
        return {
            "assignments": assignments_cp,
            "cone_ok": cone_ok_cp,
            "selected_alpha_rad": selected_alpha_rad_cp,
            "selected_beta_rad": selected_beta_rad_cp,
        }

    row_ptr_cp = slab["row_ptr"].astype(cp.int64, copy=False)
    row_cursor_cp = row_ptr_cp[:-1].copy()
    row_stop_cp = row_ptr_cp[1:].astype(cp.int64, copy=False)
    row_fill_cp = cp.zeros((time_count * int(library.cell_count),), dtype=cp.int32)
    sat_used_cp = cp.zeros((time_count, library.sat_count), dtype=cp.int32)
    n_beam_i32 = np.int32(int(library.n_beam))
    n_links_i32 = np.int32(int(library.n_links))
    cell_count_i32 = np.int32(int(library.cell_count))
    sat_count_i32 = np.int32(int(library.sat_count))
    beta_tol_rad = np.float32(float(library.beta_tol_deg) * np.pi / 180.0)
    sat_beta_max_rad_cp = library.sat_beta_max_rad_cp
    has_link_geom = int(slab["candidate_alpha_rad"].size) > 0 and int(slab["candidate_beta_rad"].size) > 0

    active_rows_cp = cp.nonzero(row_cursor_cp < row_stop_cp)[0].astype(cp.int32, copy=False)
    while int(active_rows_cp.size) > 0:
        proposal_pos_cp = row_cursor_cp[active_rows_cp].astype(cp.int64, copy=False)
        proposal_sat_cp = slab["candidate_sat"][proposal_pos_cp].astype(cp.int32, copy=False)
        proposal_t_cp = (active_rows_cp // cell_count_i32).astype(cp.int32, copy=False)
        proposal_c_cp = (active_rows_cp - proposal_t_cp * cell_count_i32).astype(cp.int32, copy=False)
        row_slot_cp = row_fill_cp[active_rows_cp].astype(cp.int32, copy=False)
        remaining_cap_cp = cp.maximum(
            np.int32(0),
            n_beam_i32 - sat_used_cp.reshape(-1).astype(cp.int32, copy=False),
        ).astype(cp.int32, copy=False)
        group_key_cp = (
            proposal_t_cp * sat_count_i32 + proposal_sat_cp
        ).astype(cp.int32, copy=False)
        keep_local_cp, _keep_rank_cp = _select_group_limited_edges_cp(
            group_key_cp=group_key_cp,
            order_key_cp=proposal_pos_cp,
            group_limit_flat_cp=remaining_cap_cp,
        )

        row_cursor_cp[active_rows_cp] = proposal_pos_cp + cp.int64(1)
        if int(keep_local_cp.size) > 0:
            kept_rows_cp = active_rows_cp[keep_local_cp].astype(cp.int32, copy=False)
            kept_t_cp = proposal_t_cp[keep_local_cp].astype(cp.int32, copy=False)
            kept_c_cp = proposal_c_cp[keep_local_cp].astype(cp.int32, copy=False)
            kept_slot_cp = row_slot_cp[keep_local_cp].astype(cp.int32, copy=False)
            kept_sat_cp = proposal_sat_cp[keep_local_cp].astype(cp.int32, copy=False)
            kept_pos_cp = proposal_pos_cp[keep_local_cp].astype(cp.int64, copy=False)

            assignments_cp[kept_t_cp, kept_c_cp, kept_slot_cp] = kept_sat_cp
            row_fill_cp[kept_rows_cp] = kept_slot_cp + np.int32(1)
            cp.add.at(sat_used_cp, (kept_t_cp, kept_sat_cp), np.int32(1))

            if library.use_cone_check and has_link_geom:
                kept_beta_cp = slab["candidate_beta_rad"][kept_pos_cp].astype(cp.float32, copy=False)
                ok_cp = kept_beta_cp <= (
                    sat_beta_max_rad_cp[kept_sat_cp] + np.float32(beta_tol_rad)
                )
            else:
                ok_cp = cp.ones((int(kept_pos_cp.size),), dtype=cp.bool_)
            cone_ok_cp[kept_t_cp, kept_c_cp, kept_slot_cp] = ok_cp
            if has_link_geom:
                kept_alpha_cp = slab["candidate_alpha_rad"][kept_pos_cp].astype(cp.float32, copy=False)
                kept_beta_cp = slab["candidate_beta_rad"][kept_pos_cp].astype(cp.float32, copy=False)
                valid_geom_cp = cp.nonzero(ok_cp)[0].astype(cp.int64, copy=False)
                if int(valid_geom_cp.size) > 0:
                    selected_alpha_rad_cp[
                        kept_t_cp[valid_geom_cp],
                        kept_c_cp[valid_geom_cp],
                        kept_slot_cp[valid_geom_cp],
                    ] = kept_alpha_cp[valid_geom_cp]
                    selected_beta_rad_cp[
                        kept_t_cp[valid_geom_cp],
                        kept_c_cp[valid_geom_cp],
                        kept_slot_cp[valid_geom_cp],
                    ] = kept_beta_cp[valid_geom_cp]

        active_mask_cp = (row_fill_cp < n_links_i32) & (row_cursor_cp < row_stop_cp)
        active_rows_cp = cp.nonzero(active_mask_cp)[0].astype(cp.int32, copy=False)

    return {
        "assignments": assignments_cp,
        "cone_ok": cone_ok_cp,
        "selected_alpha_rad": selected_alpha_rad_cp,
        "selected_beta_rad": selected_beta_rad_cp,
    }


def _estimate_selector_row_chunk_size(
    *,
    working_memory_budget_bytes: int | None,
) -> int:
    # The production fast selector now resolves contention over a slab-global
    # proposal frontier, so row chunking is no longer part of the hot path.
    # Keep a large deterministic fallback here for any future debug-only use.
    _ = working_memory_budget_bytes
    return 65536


_active_rows_mask_kernel = None


def _get_active_rows_mask_kernel():
    """Fused active-rows mask for the `_fast_select_link_candidates_cp` hot loop.

    Replaces ``(row_fill == slot) & (row_cursor < row_stop)`` — a 2-launch
    + 2-intermediate pattern — with a single elementwise kernel that
    writes the final ``bool`` mask directly.  Called twice per
    while-iteration (prime + restart), so cumulative savings scale with
    the total window-iteration count (≈10 per fast-select call).
    """
    global _active_rows_mask_kernel
    if _active_rows_mask_kernel is not None:
        return _active_rows_mask_kernel
    _active_rows_mask_kernel = cp.ElementwiseKernel(
        "int32 row_fill, int64 row_cursor, int64 row_stop, int32 slot",
        "bool active",
        """
        active = (row_fill == slot) && (row_cursor < row_stop);
        """,
        "active_rows_mask",
    )
    return _active_rows_mask_kernel


# Lever #3: fused proposal-row compute kernel for the first-pass
# selector inner loop.  Replaces 6 separate CuPy launches (gather
# row_cursor, div/mod for t/c, gather candidate_sat, compute
# group_key) with 1 launch.  The selector's while-loop iterates
# 3-10× per link_slot × 30 slots, so this saves 180-1800 launches
# per first-pass call (5-20 ms/batch on analytical at bulk=6).
_first_pass_proposal_kernel = None
_first_pass_chosen_gather_kernel = None


def _get_first_pass_chosen_gather_kernel():
    """Lever #5b: fused gather kernel for the post-proposal "chosen_*"
    arrays in the first-pass selector inner loop.

    Replaces 5 separate ``proposal_*[keep_local_cp]`` gathers + 5
    ``.astype(cp.int32, copy=False)`` no-op casts with one
    ElementwiseKernel launch.  The while-loop runs 3-10× per
    link_slot × 30 slots, so this saves 150-500 CuPy launches per
    first-pass call (3-10 ms/batch on analytical at bulk=6).

    Inputs per output element:
      keep_local — index into the proposal_* arrays
      proposal_{row, t, c, sat, pos} — raw int32/int64 arrays
    Outputs:
      chosen_{rows, t, c, sat, pos}

    ``chosen_slot`` is NOT produced here — it depends on
    ``chosen_rows`` (a gather into row_fill) so it stays a
    separate launch downstream.
    """
    global _first_pass_chosen_gather_kernel
    if _first_pass_chosen_gather_kernel is not None:
        return _first_pass_chosen_gather_kernel
    _first_pass_chosen_gather_kernel = cp.ElementwiseKernel(
        "int64 keep_local, raw int32 proposal_row, raw int32 proposal_t, "
        "raw int32 proposal_c, raw int32 proposal_sat, raw int64 proposal_pos",
        "int32 chosen_row, int32 chosen_t, int32 chosen_c, "
        "int32 chosen_sat, int64 chosen_pos",
        r"""
        chosen_row = proposal_row[keep_local];
        chosen_t   = proposal_t[keep_local];
        chosen_c   = proposal_c[keep_local];
        chosen_sat = proposal_sat[keep_local];
        chosen_pos = proposal_pos[keep_local];
        """,
        "first_pass_chosen_gather_fused",
    )
    return _first_pass_chosen_gather_kernel


def _get_first_pass_proposal_kernel():
    global _first_pass_proposal_kernel
    if _first_pass_proposal_kernel is not None:
        return _first_pass_proposal_kernel
    _first_pass_proposal_kernel = cp.ElementwiseKernel(
        "int32 active_row, raw int64 row_cursor, raw int32 candidate_sat, "
        "int32 cell_count, int32 sat_count",
        "int32 proposal_row, int64 proposal_pos, "
        "int32 proposal_t, int32 proposal_c, "
        "int32 proposal_sat, int32 group_key",
        r"""
        proposal_row = active_row;
        long long pos = row_cursor[active_row];
        proposal_pos = pos;
        int t = active_row / cell_count;
        proposal_t = t;
        proposal_c = active_row - t * cell_count;
        int sat = candidate_sat[pos];
        proposal_sat = sat;
        group_key = t * sat_count + sat;
        """,
        "first_pass_proposal_fused",
    )
    return _first_pass_proposal_kernel


def _fast_select_link_candidates_cp(
    library: "GpuSatelliteLinkSelectionLibrary",
    *,
    time_start: int,
    time_stop: int,
    working_memory_budget_bytes: int | None,
    debug_direct_epfd: bool = False,
) -> dict[str, Any]:
    _ = working_memory_budget_bytes
    slab = _direct_candidate_slab_cp(
        library,
        time_start=int(time_start),
        time_stop=int(time_stop),
    )
    time_count = int(time_stop) - int(time_start)
    if time_count <= 0:
        raise ValueError("time_stop must be greater than time_start.")

    assignments_cp = cp.full((time_count, library.cell_count, library.n_links), -1, dtype=cp.int32)
    cone_ok_cp = cp.zeros(assignments_cp.shape, dtype=cp.bool_)
    selected_alpha_rad_cp = cp.full(assignments_cp.shape, cp.nan, dtype=cp.float32)
    selected_beta_rad_cp = cp.full(assignments_cp.shape, cp.nan, dtype=cp.float32)
    if int(slab["candidate_sat"].size) <= 0:
        result_cp = {
            "assignments": assignments_cp,
            "cone_ok": cone_ok_cp,
            "selected_alpha_rad": selected_alpha_rad_cp,
            "selected_beta_rad": selected_beta_rad_cp,
        }
        if debug_direct_epfd:
            result_cp["debug_direct_epfd_stats"] = {
                "window_iterations": 0,
                "active_rows_peak": 0,
                "rows_exhausted_without_assignment": int(time_count * int(library.cell_count)),
                "fast_backend_used": True,
            }
        return result_cp

    row_ptr_cp = slab["row_ptr"].astype(cp.int64, copy=False)
    row_cursor_cp = row_ptr_cp[:-1].copy()
    row_stop_cp = row_ptr_cp[1:].astype(cp.int64, copy=False)
    row_fill_cp = cp.zeros((time_count * int(library.cell_count),), dtype=cp.int32)
    sat_used_cp = cp.zeros((time_count, library.sat_count), dtype=cp.int32)
    n_beam_i32 = np.int32(int(library.n_beam))
    n_links_i32 = np.int32(int(library.n_links))
    cell_count_i32 = np.int32(int(library.cell_count))
    sat_count_i32 = np.int32(int(library.sat_count))
    beta_tol_rad = np.float32(float(library.beta_tol_deg) * np.pi / 180.0)
    sat_beta_max_rad_cp = library.sat_beta_max_rad_cp
    has_link_geom = int(slab["candidate_alpha_rad"].size) > 0 and int(slab["candidate_beta_rad"].size) > 0
    debug_stats = {
        "window_iterations": 0,
        "active_rows_peak": 0,
        "rows_exhausted_without_assignment": 0,
        "fast_backend_used": True,
    }

    active_rows_mask_kernel = _get_active_rows_mask_kernel()
    for link_slot in range(int(library.n_links)):
        slot_i32 = np.int32(link_slot)
        active_mask_cp = active_rows_mask_kernel(
            row_fill_cp, row_cursor_cp, row_stop_cp, slot_i32,
        )
        active_rows_cp = cp.nonzero(active_mask_cp)[0].astype(cp.int32, copy=False)
        _proposal_kernel = _get_first_pass_proposal_kernel()
        while int(active_rows_cp.size) > 0:
            debug_stats["window_iterations"] += 1
            debug_stats["active_rows_peak"] = max(
                int(debug_stats["active_rows_peak"]),
                int(active_rows_cp.size),
            )
            # Fused: compute (proposal_row, pos, t, c, sat, group_key)
            # from active_rows_cp in one launch instead of 6.
            (
                proposal_row_cp, proposal_pos_cp, proposal_t_cp,
                proposal_c_cp, proposal_sat_cp, group_key_cp,
            ) = _proposal_kernel(
                active_rows_cp,
                row_cursor_cp,
                slab["candidate_sat"].astype(cp.int32, copy=False),
                cell_count_i32, sat_count_i32,
            )
            remaining_cap_cp = cp.maximum(
                np.int32(0),
                n_beam_i32 - sat_used_cp.reshape(-1).astype(cp.int32, copy=False),
            ).astype(cp.int32, copy=False)
            keep_local_cp, _keep_rank_cp = _select_group_limited_edges_cp(
                group_key_cp=group_key_cp,
                order_key_cp=proposal_pos_cp,
                group_limit_flat_cp=remaining_cap_cp,
            )
            row_cursor_cp[proposal_row_cp] = proposal_pos_cp + cp.int64(1)
            if int(keep_local_cp.size) > 0:
                # Lever #5b: fused "chosen_*" gather.  Replaces 5
                # separate proposal_*[keep_local_cp] gathers with one
                # ElementwiseKernel launch.
                _chosen_kernel = _get_first_pass_chosen_gather_kernel()
                (
                    chosen_rows_cp, chosen_t_cp, chosen_c_cp,
                    chosen_sat_cp, chosen_pos_cp,
                ) = _chosen_kernel(
                    keep_local_cp.astype(cp.int64, copy=False),
                    proposal_row_cp, proposal_t_cp, proposal_c_cp,
                    proposal_sat_cp, proposal_pos_cp,
                )
                # chosen_slot depends on chosen_rows (gather into
                # row_fill) — can't fuse into the above kernel.
                chosen_slot_cp = row_fill_cp[chosen_rows_cp].astype(cp.int32, copy=False)

                assignments_cp[chosen_t_cp, chosen_c_cp, chosen_slot_cp] = chosen_sat_cp
                row_fill_cp[chosen_rows_cp] = chosen_slot_cp + np.int32(1)
                cp.add.at(sat_used_cp, (chosen_t_cp, chosen_sat_cp), np.int32(1))

                # Cone-check mask.  Two wins vs the old version:
                #  - when ``use_cone_check`` is off, skip building a bool array
                #    and the subsequent ``cp.nonzero(ok_cp)`` gather — scatter
                #    the scalar True directly, and use the full ``chosen_*``
                #    indices as the ``valid_geom_cp`` alias below;
                #  - share the ``chosen_beta_cp`` gather between the cone
                #    check and the ``selected_beta_rad`` scatter instead of
                #    fetching it twice.
                chosen_beta_cp = None
                if has_link_geom:
                    chosen_beta_cp = slab["candidate_beta_rad"][chosen_pos_cp].astype(cp.float32, copy=False)
                if library.use_cone_check and has_link_geom:
                    ok_cp = chosen_beta_cp <= (
                        sat_beta_max_rad_cp[chosen_sat_cp] + np.float32(beta_tol_rad)
                    )
                    cone_ok_cp[chosen_t_cp, chosen_c_cp, chosen_slot_cp] = ok_cp
                else:
                    # All entries pass: scatter-assign a scalar True and
                    # treat every chosen index as geom-valid below.
                    cone_ok_cp[chosen_t_cp, chosen_c_cp, chosen_slot_cp] = True
                    ok_cp = None
                if has_link_geom:
                    chosen_alpha_cp = slab["candidate_alpha_rad"][chosen_pos_cp].astype(cp.float32, copy=False)
                    if ok_cp is None:
                        # Fast path: no cone filter, all chosen entries valid.
                        selected_alpha_rad_cp[chosen_t_cp, chosen_c_cp, chosen_slot_cp] = chosen_alpha_cp
                        selected_beta_rad_cp[chosen_t_cp, chosen_c_cp, chosen_slot_cp] = chosen_beta_cp
                    else:
                        valid_geom_cp = cp.nonzero(ok_cp)[0].astype(cp.int64, copy=False)
                        if int(valid_geom_cp.size) > 0:
                            selected_alpha_rad_cp[
                                chosen_t_cp[valid_geom_cp],
                                chosen_c_cp[valid_geom_cp],
                                chosen_slot_cp[valid_geom_cp],
                            ] = chosen_alpha_cp[valid_geom_cp]
                            selected_beta_rad_cp[
                                chosen_t_cp[valid_geom_cp],
                                chosen_c_cp[valid_geom_cp],
                                chosen_slot_cp[valid_geom_cp],
                            ] = chosen_beta_cp[valid_geom_cp]
            active_mask_cp = active_rows_mask_kernel(
                row_fill_cp, row_cursor_cp, row_stop_cp, slot_i32,
            )
            active_rows_cp = cp.nonzero(active_mask_cp)[0].astype(cp.int32, copy=False)

    result_cp = {
        "assignments": assignments_cp,
        "cone_ok": cone_ok_cp,
        "selected_alpha_rad": selected_alpha_rad_cp,
        "selected_beta_rad": selected_beta_rad_cp,
    }
    if debug_direct_epfd:
        exhausted_mask_cp = (row_fill_cp == 0) & (row_cursor_cp >= row_stop_cp)
        debug_stats["rows_exhausted_without_assignment"] = int(cp.count_nonzero(exhausted_mask_cp).item())
        result_cp["debug_direct_epfd_stats"] = debug_stats
    return result_cp


def _frontier_select_link_candidates_cp(
    library: "GpuSatelliteLinkSelectionLibrary",
    *,
    time_start: int,
    time_stop: int,
    selector_backend: str = GPU_DIRECT_SELECTOR_BACKEND_FAST,
    working_memory_budget_bytes: int | None = None,
    debug_direct_epfd: bool = False,
) -> dict[str, Any]:
    backend = str(selector_backend).strip().lower()
    if backend == GPU_DIRECT_SELECTOR_BACKEND_REFERENCE:
        result_cp = _frontier_select_link_candidates_reference_cp(
            library,
            time_start=int(time_start),
            time_stop=int(time_stop),
        )
        if debug_direct_epfd:
            result_cp["debug_direct_epfd_stats"] = {
                "window_iterations": 0,
                "active_rows_peak": 0,
                "rows_exhausted_without_assignment": 0,
                "fast_backend_used": False,
            }
        return result_cp
    if backend != GPU_DIRECT_SELECTOR_BACKEND_FAST:
        raise ValueError(
            f"Unsupported selector backend {selector_backend!r}; "
            f"expected {GPU_DIRECT_SELECTOR_BACKEND_FAST!r} or {GPU_DIRECT_SELECTOR_BACKEND_REFERENCE!r}."
        )
    return _fast_select_link_candidates_cp(
        library,
        time_start=int(time_start),
        time_stop=int(time_stop),
        working_memory_budget_bytes=working_memory_budget_bytes,
        debug_direct_epfd=bool(debug_direct_epfd),
    )


def _normalise_direct_output_sat_indices(
    output_sat_indices: Any | None,
    *,
    sat_count: int,
) -> tuple[Any, Any, int]:
    if output_sat_indices is None:
        sat_indices_cp = cp.arange(int(sat_count), dtype=cp.int32)
    else:
        sat_indices_cp = _to_cupy_array(
            output_sat_indices,
            dtype=cp.int32,
            copy=False,
        ).reshape(-1)
        if int(sat_indices_cp.size) > 0:
            invalid_mask_cp = (sat_indices_cp < 0) | (sat_indices_cp >= int(sat_count))
            if bool(copy_device_to_host(cp.any(invalid_mask_cp)).reshape(())):
                raise ValueError(
                    f"output_sat_indices must lie within [0, {int(sat_count) - 1}]."
                )
            if int(cp.unique(sat_indices_cp).size) != int(sat_indices_cp.size):
                raise ValueError("output_sat_indices must be unique and one-dimensional.")
    sat_output_index_cp = cp.full(int(sat_count), -1, dtype=cp.int32)
    if int(sat_indices_cp.size) > 0:
        sat_output_index_cp[sat_indices_cp] = cp.arange(int(sat_indices_cp.size), dtype=cp.int32)
    return sat_indices_cp, sat_output_index_cp, int(sat_indices_cp.size)


def _device_result_dict_from_cupy(result: dict[str, Any]) -> dict[str, Any]:
    out: dict[str, Any] = {}
    for key, value in result.items():
        if _has_cupy() and isinstance(value, cp.ndarray):
            out[key] = cuda.as_cuda_array(value)
        else:
            out[key] = value
    return out


def _normalise_pure_reroute_beam_caps(beam_caps: Any) -> np.ndarray:
    caps = np.asarray(beam_caps, dtype=np.int32).reshape(-1)
    if caps.size == 0:
        raise ValueError("beam_caps must be a non-empty one-dimensional array.")
    if int(caps[0]) != 0:
        raise ValueError("beam_caps must start at 0.")
    expected = np.arange(int(caps[0]), int(caps[0]) + caps.size, dtype=np.int32)
    if not np.array_equal(caps, expected):
        raise ValueError("beam_caps must be contiguous integer values.")
    return caps


def _normalise_pure_reroute_mask_input(eligible_mask: Any) -> tuple[Any, bool, bool]:
    on_device = _is_cuda_array(eligible_mask) or (_has_cupy() and isinstance(eligible_mask, cp.ndarray))
    if on_device:
        mask = _to_cupy_array(eligible_mask, dtype=cp.bool_, copy=False)
    else:
        mask = np.asarray(eligible_mask, dtype=np.bool_)
    if mask.ndim == 2:
        return mask[np.newaxis, ...], True, on_device
    if mask.ndim == 3:
        return mask, False, on_device
    raise ValueError(
        "eligible_mask must have shape (C, S) or (T, C, S); "
        f"got {tuple(mask.shape)!r}."
    )


def _estimate_pure_reroute_batch_slots(
    time_count: int,
    cell_count: int,
    sat_count: int,
    active_slot_count: int | None = None,
    edge_count_total: int | None = None,
) -> int:
    if time_count <= 0:
        return 0
    if not _has_cupy():
        return max(1, int(time_count))
    try:
        free_bytes, _total_bytes = cp.cuda.runtime.memGetInfo()
    except Exception:
        return max(1, min(int(time_count), 8))
    dense_mask_bytes_per_slot = max(int(cell_count) * int(sat_count), 1)
    if active_slot_count is not None and int(active_slot_count) > 0 and edge_count_total is not None:
        mean_edges_per_slot = max(float(edge_count_total) / float(active_slot_count), 1.0)
    else:
        mean_edges_per_slot = float(dense_mask_bytes_per_slot)
    active_sat_estimate = max(1.0, min(float(sat_count), mean_edges_per_slot))
    # The exact solver keeps the dense boolean mask plus sparse graph state and
    # alternating-path work buffers alive per slot. Use the sparse edge count
    # when it is known, but keep the dense mask term because the batch is still
    # materialized as a compact boolean tensor on device.
    estimated_bytes_per_slot = int(
        dense_mask_bytes_per_slot
        + mean_edges_per_slot * 28.0
        + float(cell_count) * 24.0
        + active_sat_estimate * 28.0
    )
    target_bytes = max(int(float(free_bytes) * 0.10), 64 * 1024 * 1024)
    batch_slots = target_bytes // max(estimated_bytes_per_slot, 1)
    return max(1, min(int(time_count), int(batch_slots)))


def _is_cupy_out_of_memory(exc: BaseException) -> bool:
    if _has_cupy() and isinstance(exc, cp.cuda.memory.OutOfMemoryError):
        return True
    text = str(exc).lower()
    return "out of memory" in text and ("cuda" in text or "cupy" in text)


def _has_exact_pure_reroute_gpu_support() -> bool:
    return _has_cuda() and _has_cupy()


def _attach_gpu_eligible_mask_outputs(
    result: dict[str, Any],
    *,
    dense_mask_cp: Any | None,
    eligible_time_parts: list[Any] | None,
    eligible_cell_parts: list[Any] | None,
    eligible_sat_parts: list[Any] | None,
    time_count: int,
    cell_count: int,
    sat_count: int,
    encoding: str,
    return_device: bool,
) -> dict[str, Any]:
    from scepter import satsim

    encoding_name = satsim._normalise_eligible_mask_encoding(encoding)
    dense_host = None
    if dense_mask_cp is not None and (not return_device or encoding_name in {"csr", "both"}):
        dense_host = copy_device_to_host(dense_mask_cp)

    if encoding_name in {"dense", "both"}:
        if dense_mask_cp is None:
            raise RuntimeError("Dense eligible-mask output requested but no dense GPU mask is available.")
        if return_device:
            result["sat_eligible_mask"] = dense_mask_cp
        else:
            if dense_host is None:
                dense_host = copy_device_to_host(dense_mask_cp)
            result["sat_eligible_mask"] = np.asarray(dense_host, dtype=np.bool_, copy=False)

    if encoding_name in {"csr", "both"}:
        if dense_host is not None:
            payload = satsim._pure_reroute_dense_mask_to_csr_payload(
                np.asarray(dense_host, dtype=np.bool_, copy=False)
            )
        else:
            if eligible_time_parts is None or eligible_cell_parts is None or eligible_sat_parts is None:
                raise RuntimeError("CSR eligible-mask output requested but no sparse GPU eligibility indices are available.")
            time_host = (
                copy_device_to_host(cp.concatenate(eligible_time_parts)).astype(np.int32, copy=False)
                if eligible_time_parts
                else np.empty(0, dtype=np.int32)
            )
            cell_host = (
                copy_device_to_host(cp.concatenate(eligible_cell_parts)).astype(np.int32, copy=False)
                if eligible_cell_parts
                else np.empty(0, dtype=np.int32)
            )
            sat_host = (
                copy_device_to_host(cp.concatenate(eligible_sat_parts)).astype(np.int32, copy=False)
                if eligible_sat_parts
                else np.empty(0, dtype=np.int32)
            )
            payload = satsim._pure_reroute_pairs_to_csr_payload(
                time_host,
                cell_host,
                sat_host,
                time_count=int(time_count),
                cell_count=int(cell_count),
                sat_count=int(sat_count),
            )
        if return_device:
            for key, value in payload.items():
                if isinstance(value, np.ndarray):
                    result[key] = cp.asarray(value)
                else:
                    result[key] = value
        else:
            result.update(payload)
    return result


# Exact pure-reroute service-curve solving is kept in one block because the
# device-side alternating-path implementation needs its helpers close by.
def _pure_reroute_service_curve_gpu_batch(
    eligible_mask_cp: Any,
    *,
    nco: int,
    beam_caps_cp: Any,
) -> dict[str, Any]:
    _require_cupy()
    mask_cp = cp.ascontiguousarray(_to_cupy_array(eligible_mask_cp, dtype=cp.bool_, copy=False))
    if mask_cp.ndim != 3:
        raise ValueError(
            "eligible_mask must be normalized to shape (T, C, S) before GPU solving; "
            f"got {tuple(mask_cp.shape)!r}."
        )
    time_count, cell_count, sat_count = (int(v) for v in mask_cp.shape)
    beam_caps_cp = cp.ascontiguousarray(_to_cupy_array(beam_caps_cp, dtype=cp.int32, copy=False))
    beam_cap_count = int(beam_caps_cp.size)
    if int(nco) <= 0:
        raise ValueError("nco must be positive.")

    degree_cp = cp.sum(mask_cp, axis=2, dtype=cp.int32)
    cell_cap_cp = cp.minimum(degree_cp, cp.int32(int(nco))).astype(cp.int32, copy=False)
    eligible_demand_cp = cp.sum(cell_cap_cp, axis=1, dtype=cp.int32)
    matched_links_cp = cp.zeros((time_count, beam_cap_count), dtype=cp.int32)
    required_beam_cap_cp = cp.where(
        eligible_demand_cp > 0,
        cp.int32(int(beam_caps_cp[-1].item()) + 1),
        cp.int32(0),
    ).astype(cp.int32, copy=False)

    flat_idx_cp = cp.nonzero(mask_cp.reshape(-1))[0].astype(cp.int64, copy=False)
    edge_count = int(flat_idx_cp.size)
    if edge_count == 0:
        return {
            "eligible_demand": eligible_demand_cp,
            "matched_links": matched_links_cp,
            "required_beam_cap": required_beam_cap_cp,
        }
    if edge_count > np.iinfo(np.int32).max:
        raise RuntimeError(
            "pure_reroute GPU batch is too dense for the current int32 graph workspace. "
            "Reduce READ_SLOT_CHUNK or let the solver split into smaller internal batches."
        )

    row_id_cp = (flat_idx_cp // np.int64(sat_count)).astype(cp.int32, copy=False)
    edge_cell_cp = (row_id_cp % np.int32(cell_count)).astype(cp.int32, copy=False)
    slot_idx_cp = (row_id_cp // np.int32(cell_count)).astype(cp.int32, copy=False)
    sat_global_cp = (flat_idx_cp % np.int64(sat_count)).astype(cp.int32, copy=False)

    row_counts_cp = cp.bincount(row_id_cp, minlength=time_count * cell_count).astype(cp.int32, copy=False)
    row_ptr_cp = cp.empty(time_count * cell_count + 1, dtype=cp.int32)
    row_ptr_cp[0] = cp.int32(0)
    row_ptr_cp[1:] = cp.cumsum(row_counts_cp, dtype=cp.int32)

    slot_sat_code_cp = slot_idx_cp.astype(cp.int64, copy=False) * np.int64(sat_count)
    slot_sat_code_cp = slot_sat_code_cp + sat_global_cp.astype(cp.int64, copy=False)
    unique_sat_code_cp, edge_sat_cp = cp.unique(slot_sat_code_cp, return_inverse=True)
    edge_sat_cp = edge_sat_cp.astype(cp.int32, copy=False)
    sat_slot_cp = (unique_sat_code_cp // np.int64(sat_count)).astype(cp.int32, copy=False)
    sat_counts_cp = cp.bincount(sat_slot_cp, minlength=time_count).astype(cp.int32, copy=False)
    sat_ptr_cp = cp.empty(time_count + 1, dtype=cp.int32)
    sat_ptr_cp[0] = cp.int32(0)
    sat_ptr_cp[1:] = cp.cumsum(sat_counts_cp, dtype=cp.int32)
    total_active_sats = int(unique_sat_code_cp.size)

    cell_cap_flat_cp = cp.ascontiguousarray(cell_cap_cp.reshape(-1), dtype=cp.int32)
    cell_load_cp = cp.zeros(time_count * cell_count, dtype=cp.int32)
    parent_edge_cell_cp = cp.empty(time_count * cell_count, dtype=cp.int32)
    queue_cp = cp.empty(time_count * cell_count, dtype=cp.int32)
    sat_load_cp = cp.zeros(total_active_sats, dtype=cp.int32)
    sat_head_cp = cp.full(total_active_sats, -1, dtype=cp.int32)
    parent_edge_sat_cp = cp.empty(total_active_sats, dtype=cp.int32)
    edge_matched_cp = cp.zeros(edge_count, dtype=cp.int8)
    edge_next_cp = cp.full(edge_count, -1, dtype=cp.int32)
    edge_prev_cp = cp.full(edge_count, -1, dtype=cp.int32)

    grid = (time_count, 1, 1)
    block = (1, 1, 1)
    _pure_reroute_service_curve_kernel[grid, block](
        cuda.as_cuda_array(row_ptr_cp),
        cuda.as_cuda_array(edge_cell_cp),
        cuda.as_cuda_array(edge_sat_cp),
        cuda.as_cuda_array(cell_cap_flat_cp),
        cuda.as_cuda_array(sat_ptr_cp),
        cuda.as_cuda_array(beam_caps_cp),
        cuda.as_cuda_array(cell_load_cp),
        cuda.as_cuda_array(parent_edge_cell_cp),
        cuda.as_cuda_array(queue_cp),
        cuda.as_cuda_array(sat_load_cp),
        cuda.as_cuda_array(sat_head_cp),
        cuda.as_cuda_array(parent_edge_sat_cp),
        cuda.as_cuda_array(edge_matched_cp),
        cuda.as_cuda_array(edge_next_cp),
        cuda.as_cuda_array(edge_prev_cp),
        cuda.as_cuda_array(eligible_demand_cp),
        cuda.as_cuda_array(matched_links_cp),
        cuda.as_cuda_array(required_beam_cap_cp),
        int(cell_count),
    )
    cuda.synchronize()
    return {
        "eligible_demand": eligible_demand_cp,
        "matched_links": matched_links_cp,
        "required_beam_cap": required_beam_cap_cp,
    }


def _estimate_pure_reroute_component_batch_size(
    components: list[dict[str, Any]],
    *,
    start_idx: int,
) -> int:
    if start_idx >= len(components):
        return 0
    if not _has_cupy():
        return max(1, len(components) - start_idx)
    try:
        free_bytes, _total_bytes = cp.cuda.runtime.memGetInfo()
    except Exception:
        return max(1, min(len(components) - start_idx, 32))

    target_bytes = max(int(float(free_bytes) * 0.10), 64 * 1024 * 1024)
    batch_count = 0
    max_rows = 0
    total_edges = 0
    total_sats = 0
    while start_idx + batch_count < len(components):
        component = components[start_idx + batch_count]
        row_count = int(np.asarray(component["cell_cap"]).size)
        edge_count = int(np.asarray(component["edge_sat"]).size)
        sat_count = int(component["sat_count"])
        next_batch_count = batch_count + 1
        next_max_rows = max(max_rows, row_count)
        next_total_edges = total_edges + edge_count
        next_total_sats = total_sats + sat_count
        estimated_bytes = int(
            next_batch_count * next_max_rows * 20
            + next_total_edges * 20
            + next_total_sats * 16
        )
        if batch_count > 0 and estimated_bytes > target_bytes:
            break
        batch_count = next_batch_count
        max_rows = next_max_rows
        total_edges = next_total_edges
        total_sats = next_total_sats
    return max(1, batch_count)


def _pack_pure_reroute_component_batch(
    components: list[dict[str, Any]],
) -> dict[str, np.ndarray]:
    batch_count = len(components)
    if batch_count <= 0:
        raise ValueError("components must contain at least one component graph.")
    max_rows = max(int(np.asarray(component["cell_cap"]).size) for component in components)
    total_edges = sum(int(np.asarray(component["edge_sat"]).size) for component in components)
    total_sats = sum(int(component["sat_count"]) for component in components)

    row_ptr = np.empty(batch_count * max_rows + 1, dtype=np.int32)
    cell_cap_flat = np.zeros(batch_count * max_rows, dtype=np.int32)
    edge_cell = np.empty(total_edges, dtype=np.int32)
    edge_sat = np.empty(total_edges, dtype=np.int32)
    sat_ptr = np.zeros(batch_count + 1, dtype=np.int32)
    eligible_demand = np.zeros(batch_count, dtype=np.int32)

    edge_offset = 0
    sat_offset = 0
    row_ptr[0] = np.int32(0)
    for batch_idx, component in enumerate(components):
        row_ptr_local = np.asarray(component["row_ptr"], dtype=np.int32, copy=False)
        edge_cell_local = np.asarray(component["edge_cell"], dtype=np.int32, copy=False)
        edge_sat_local = np.asarray(component["edge_sat"], dtype=np.int32, copy=False)
        cell_cap_local = np.asarray(component["cell_cap"], dtype=np.int32, copy=False)
        row_count = int(cell_cap_local.size)
        base = batch_idx * max_rows
        for local_row in range(row_count + 1):
            row_ptr[base + local_row] = np.int32(edge_offset + int(row_ptr_local[local_row]))
        fill_value = np.int32(edge_offset + int(row_ptr_local[-1]))
        for local_row in range(row_count + 1, max_rows + 1):
            row_ptr[base + local_row] = fill_value
        cell_cap_flat[base : base + row_count] = cell_cap_local
        edge_count = int(edge_sat_local.size)
        edge_cell[edge_offset : edge_offset + edge_count] = edge_cell_local
        edge_sat[edge_offset : edge_offset + edge_count] = edge_sat_local + np.int32(sat_offset)
        sat_ptr[batch_idx] = np.int32(sat_offset)
        sat_offset += int(component["sat_count"])
        eligible_demand[batch_idx] = np.int32(int(component["eligible_demand"]))
        edge_offset += edge_count
    sat_ptr[batch_count] = np.int32(sat_offset)
    row_ptr[batch_count * max_rows] = np.int32(edge_offset)
    return {
        "row_ptr": row_ptr,
        "edge_cell": edge_cell,
        "edge_sat": edge_sat,
        "cell_cap_flat": cell_cap_flat,
        "sat_ptr": sat_ptr,
        "eligible_demand": eligible_demand,
        "row_count_padded": np.asarray(max_rows, dtype=np.int32),
    }


def _pure_reroute_service_curve_gpu_component_batch(
    components: list[dict[str, Any]],
    *,
    beam_caps_cp: Any,
) -> dict[str, Any]:
    _require_cupy()
    packed = _pack_pure_reroute_component_batch(components)
    batch_count = len(components)
    beam_caps_use = cp.ascontiguousarray(_to_cupy_array(beam_caps_cp, dtype=cp.int32, copy=False))
    beam_cap_count = int(beam_caps_use.size)
    row_count_padded = int(np.asarray(packed["row_count_padded"]).item())
    eligible_demand_cp = cp.asarray(packed["eligible_demand"], dtype=cp.int32)
    matched_links_cp = cp.zeros((batch_count, beam_cap_count), dtype=cp.int32)
    required_beam_cap_cp = cp.where(
        eligible_demand_cp > 0,
        cp.int32(int(beam_caps_use[-1].item()) + 1),
        cp.int32(0),
    ).astype(cp.int32, copy=False)
    if int(np.asarray(packed["edge_sat"]).size) == 0:
        return {
            "eligible_demand": eligible_demand_cp,
            "matched_links": matched_links_cp,
            "required_beam_cap": required_beam_cap_cp,
        }

    row_ptr_cp = cp.asarray(packed["row_ptr"], dtype=cp.int32)
    edge_cell_cp = cp.asarray(packed["edge_cell"], dtype=cp.int32)
    edge_sat_cp = cp.asarray(packed["edge_sat"], dtype=cp.int32)
    cell_cap_flat_cp = cp.asarray(packed["cell_cap_flat"], dtype=cp.int32)
    sat_ptr_cp = cp.asarray(packed["sat_ptr"], dtype=cp.int32)

    total_rows = batch_count * row_count_padded
    total_sats = int(np.asarray(packed["sat_ptr"][-1]).item())
    total_edges = int(np.asarray(packed["edge_sat"]).size)
    cell_load_cp = cp.zeros(total_rows, dtype=cp.int32)
    parent_edge_cell_cp = cp.empty(total_rows, dtype=cp.int32)
    queue_cp = cp.empty(total_rows, dtype=cp.int32)
    sat_load_cp = cp.zeros(total_sats, dtype=cp.int32)
    sat_head_cp = cp.full(total_sats, -1, dtype=cp.int32)
    parent_edge_sat_cp = cp.empty(total_sats, dtype=cp.int32)
    edge_matched_cp = cp.zeros(total_edges, dtype=cp.int8)
    edge_next_cp = cp.full(total_edges, -1, dtype=cp.int32)
    edge_prev_cp = cp.full(total_edges, -1, dtype=cp.int32)

    grid = (batch_count, 1, 1)
    block = (1, 1, 1)
    _pure_reroute_service_curve_kernel[grid, block](
        cuda.as_cuda_array(row_ptr_cp),
        cuda.as_cuda_array(edge_cell_cp),
        cuda.as_cuda_array(edge_sat_cp),
        cuda.as_cuda_array(cell_cap_flat_cp),
        cuda.as_cuda_array(sat_ptr_cp),
        cuda.as_cuda_array(beam_caps_use),
        cuda.as_cuda_array(cell_load_cp),
        cuda.as_cuda_array(parent_edge_cell_cp),
        cuda.as_cuda_array(queue_cp),
        cuda.as_cuda_array(sat_load_cp),
        cuda.as_cuda_array(sat_head_cp),
        cuda.as_cuda_array(parent_edge_sat_cp),
        cuda.as_cuda_array(edge_matched_cp),
        cuda.as_cuda_array(edge_next_cp),
        cuda.as_cuda_array(edge_prev_cp),
        cuda.as_cuda_array(eligible_demand_cp),
        cuda.as_cuda_array(matched_links_cp),
        cuda.as_cuda_array(required_beam_cap_cp),
        int(row_count_padded),
    )
    cuda.synchronize()
    return {
        "eligible_demand": eligible_demand_cp,
        "matched_links": matched_links_cp,
        "required_beam_cap": required_beam_cap_cp,
    }


def _infer_angular_compute_dtype(
    values: tuple[Any, ...],
    *,
    session: "GpuScepterSession | None",
    output_dtype: Any | None,
) -> np.dtype:
    if session is not None:
        return session.compute_dtype
    if output_dtype is not None:
        out_dtype = np.dtype(output_dtype)
        if out_dtype.type in SUPPORTED_COMPUTE_DTYPES:
            return out_dtype
    dtypes: list[np.dtype] = []
    for value in values:
        if _is_cuda_array(value):
            dtypes.append(np.dtype(cuda.as_cuda_array(value).dtype))
        elif hasattr(value, "to_value"):
            dtypes.append(np.asarray(u.Quantity(value).to_value(u.deg)).dtype)
        else:
            dtypes.append(np.asarray(value).dtype)
    if dtypes and all(np.dtype(dtype).itemsize <= np.dtype(np.float32).itemsize for dtype in dtypes):
        return np.dtype(np.float32)
    return np.dtype(np.float64)


def _normalise_force_backend(force_backend: str | None) -> str | None:
    if force_backend is None:
        return None
    if force_backend not in {_AUTO_BACKEND_CPU, _AUTO_BACKEND_GPU}:
        raise ValueError("force_backend must be one of {'cpu', 'gpu'} or None.")
    return force_backend


def _default_cuda_device_id() -> int:
    if not _has_cuda():
        raise RuntimeError("CUDA is not available.")
    try:
        return int(cuda.get_current_device().id)
    except Exception:
        return 0


def _current_device_fingerprint(device_id: int) -> dict[str, Any]:
    if not _has_cuda():
        return {"backend": "cpu-only"}
    context = cuda.gpus[int(device_id)].get_primary_context()
    context.push()
    try:
        device = cuda.get_current_device()
        name = getattr(device, "name", "unknown")
        if isinstance(name, bytes):
            name = name.decode("utf-8", "replace")
        return {
            "device_id": int(device_id),
            "name": str(name),
            "compute_capability": tuple(int(x) for x in device.compute_capability),
        }
    finally:
        context.pop()


def _library_version(name: str) -> str:
    try:
        return importlib_metadata.version(name)
    except importlib_metadata.PackageNotFoundError:
        return "unknown"


def _load_auto_threshold_cache() -> dict[str, Any]:
    path = _AUTO_THRESHOLD_CACHE_PATH
    try:
        payload = json.loads(path.read_text(encoding="utf-8"))
    except FileNotFoundError:
        return {"version": _ANGULAR_DISTANCE_CACHE_VERSION, "entries": {}}
    except Exception:
        return {"version": _ANGULAR_DISTANCE_CACHE_VERSION, "entries": {}}
    if not isinstance(payload, dict):
        return {"version": _ANGULAR_DISTANCE_CACHE_VERSION, "entries": {}}
    if int(payload.get("version", -1)) != _ANGULAR_DISTANCE_CACHE_VERSION:
        return {"version": _ANGULAR_DISTANCE_CACHE_VERSION, "entries": {}}
    entries = payload.get("entries", {})
    if not isinstance(entries, dict):
        entries = {}
    return {"version": _ANGULAR_DISTANCE_CACHE_VERSION, "entries": entries}


def _save_auto_threshold_cache(payload: dict[str, Any]) -> None:
    path = _AUTO_THRESHOLD_CACHE_PATH
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(json.dumps(payload, indent=2, sort_keys=True), encoding="utf-8")


def _angular_threshold_cache_key(*, device_id: int, compute_dtype: np.dtype) -> str:
    fingerprint = _current_device_fingerprint(device_id)
    key = {
        "cache_version": _ANGULAR_DISTANCE_CACHE_VERSION,
        "device": fingerprint,
        "dtype": np.dtype(compute_dtype).name,
        "platform": {
            "machine": platform.machine(),
            "platform": platform.platform(),
            "python": sys.version.split()[0],
        },
        "versions": {
            "numba": _library_version("numba"),
            "numpy": _library_version("numpy"),
            "pycraf": _library_version("pycraf"),
        },
    }
    return json.dumps(key, sort_keys=True)


def _scheduler_calibration_cache_key(
    *,
    device_id: int,
    compute_dtype: np.dtype,
    output_dtype: np.dtype,
    boresight_active: bool,
    observer_count: int,
    time_count: int,
    visible_satellite_count: int,
) -> str:
    fingerprint = _current_device_fingerprint(device_id)
    key = {
        "cache_version": _SCHEDULER_CALIBRATION_CACHE_VERSION,
        "device": fingerprint,
        "compute_dtype": np.dtype(compute_dtype).name,
        "output_dtype": np.dtype(output_dtype).name,
        "boresight_active": bool(boresight_active),
        "observer_bucket": _bucket_scheduler_dimension(observer_count),
        "time_bucket": _bucket_scheduler_dimension(time_count),
        "visible_sat_bucket": _bucket_scheduler_dimension(visible_satellite_count),
    }
    return json.dumps(key, sort_keys=True)


def _normalise_eci_input(
    value: Any,
    *,
    name: str,
    time_count: int,
    sat_count: int,
) -> np.ndarray:
    arr = np.asarray(value)
    if arr.shape != (time_count, sat_count, 3):
        raise ValueError(
            f"{name} must have shape ({time_count}, {sat_count}, 3); "
            f"got {arr.shape!r}."
        )
    return np.ascontiguousarray(arr)


def _copy_param_dict_to_device(params: dict[str, np.ndarray]) -> dict[str, Any]:
    return {
        name: cuda.to_device(np.ascontiguousarray(values))
        for name, values in params.items()
    }


def _extract_vallado_satellites(
    tles: tuple[Any, ...],
    *,
    gravity_model: str,
) -> tuple[Any, ...]:
    from sgp4.io import twoline2rv

    gravity_spec = _sgp4_gravity_spec(gravity_model)
    satellites: list[Any] = []
    for tle in tles:
        _, line1, line2 = tle.tle_strings()
        satellites.append(twoline2rv(str(line1), str(line2), gravity_spec))
    return tuple(satellites)


def _extract_vallado_params(
    satellites: tuple[Any, ...],
    *,
    compute_dtype: np.dtype,
) -> tuple[dict[str, np.ndarray], np.ndarray, np.ndarray, np.ndarray]:
    params: dict[str, np.ndarray] = {}
    for name in VALLADO_FLOAT_FIELDS:
        params[name] = np.asarray(
            [float(getattr(sat, name, 0.0)) for sat in satellites],
            dtype=compute_dtype,
        )
    for name in VALLADO_INT_FIELDS:
        if name == "opsmode_afspc":
            values = [
                1 if str(getattr(sat, "operationmode", "i")).lower() == "a" else 0
                for sat in satellites
            ]
        else:
            values = [int(getattr(sat, name, 0)) for sat in satellites]
        params[name] = np.asarray(values, dtype=np.int32)
    epoch_mjd = np.asarray(
        [float(getattr(sat, "jdsatepoch")) - MJD_TO_JD_OFFSET for sat in satellites],
        dtype=np.float64,
    )
    near_indices = np.asarray(
        [idx for idx, sat in enumerate(satellites) if getattr(sat, "method", "n") != "d"],
        dtype=np.int32,
    )
    deep_indices = np.asarray(
        [idx for idx, sat in enumerate(satellites) if getattr(sat, "method", "n") == "d"],
        dtype=np.int32,
    )
    return params, epoch_mjd, near_indices, deep_indices


