@dataclass(slots=True)
class GpuPeakPfdLutContext:
    """
    Lookup table K(β) used by the Service & Demand surface-PFD cap.

    For each orbit shell registered at build time the context stores a 1-D
    CuPy array of

        K(β) = max over ψ of [ p(|ψ − β|) / (4π · d(ψ)² · atm(ψ)) ]

    in units of 1/m², where ψ sweeps the satellite→ground symmetry plane
    containing nadir and the beam boresight, ``d(ψ)`` is the sat→point slant
    range, ``p`` is the transmit pattern normalised so that the peak gain
    equals unity, and ``atm(ψ)`` is the one-way atmospheric attenuation from
    the satellite to the ground candidate point (unity when the host run is
    executed with atmosphere disabled).

    The cap is then applied as

        PFD_peak_on_earth = EIRP_peak · K(β, shell)

    where ``EIRP_peak = Ptx · g_max`` is the beam's absolute peak EIRP.

    Parameters
    ----------
    apply_atmosphere : bool
        Whether the K table was built with the atmospheric absorption term.
        Must match the ``atmosphere_lut_context`` supplied to the hot power
        kernel at runtime so the cap and the emitted PFD cannot disagree.
    pattern_eval_mode : str
        Either ``"lut"`` or ``"analytical"``.  The builder dispatches on
        ``gpu_accel._pattern_eval_mode`` at call time so the runtime
        Review & Run "Pattern evaluation" setting is honoured without a
        per-batch rebuild.
    beta_step_deg, beta_max_deg, n_beta : float, float, int
        Uniform β grid parameters.  ``beta_step_deg × n_beta ≈ beta_max_deg``.
    shell_keys : tuple[tuple[int, int], ...]
        Deduplicated ``(pattern_id, rounded_orbit_radius_m_cm)`` identifiers
        describing the shells tabulated in ``d_k_lut``.
    orbit_radius_m_per_shell : numpy.ndarray
        Shell orbit radii in metres, shape ``(n_shells,)``, aligned with
        ``shell_keys``.
    psi_horizon_deg_per_shell : numpy.ndarray
        Visible-disc half-angle per shell, shape ``(n_shells,)``, kept for
        introspection and boundary clamping.
    observer_alt_km, target_alt_km : float
        Altitudes used for atmosphere slant-path queries at build time;
        mirrored from the host run configuration.
    d_k_lut : Any
        Device array of shape ``(n_shells, n_beta)`` and dtype ``float32``,
        storing K in units of 1/m².
    d_shell_id_per_sat : Any or None
        Device array of shape ``(sat_count,)`` and dtype ``int32`` mapping
        each satellite to a row in ``d_k_lut``.  Populated by the session
        builder once the satellite context is known.

    Notes
    -----
    Axisymmetric transmit patterns (S.1528 and S.1528 Rec 1.2) use a 1-D
    ``K(β)`` table per shell.  ITU-R M.2101 phased-array patterns are
    non-axisymmetric, so they use a 2-D ``K(α, β)`` table indexed by both
    the beam steering azimuth and the off-nadir angle.  The ``is_2d`` flag
    selects between the two layouts:

    - ``is_2d == False`` (default) — ``d_k_lut`` has shape
      ``(n_shells, n_beta)`` and the ``alpha_*`` fields are zero/unused.
    - ``is_2d == True`` — ``d_k_lut`` has shape ``(n_shells, n_alpha,
      n_beta)`` and the ``alpha_step_deg``/``n_alpha``/``alpha_min_deg``
      fields describe the α grid.  α is the beam's azimuth in degrees,
      interpreted exactly as the hot-path M.2101 kernel uses it
      (``beam_alpha_rad * 180/π`` fed as the array "az_i" argument).
    """

    session: "GpuScepterSession" = field(repr=False, compare=False)
    compute_dtype: np.dtype
    device_id: int
    apply_atmosphere: bool
    pattern_eval_mode: str
    beta_step_deg: float
    beta_max_deg: float
    n_beta: int
    shell_keys: tuple[tuple[int, int], ...]
    orbit_radius_m_per_shell: np.ndarray = field(repr=False)
    psi_horizon_deg_per_shell: np.ndarray = field(repr=False)
    observer_alt_km: float
    target_alt_km: float
    d_k_lut: Any = field(repr=False)
    d_shell_id_per_sat: Any = field(default=None, repr=False)
    is_2d: bool = False
    alpha_step_deg: float = 0.0
    alpha_min_deg: float = 0.0
    n_alpha: int = 0


