@dataclass(slots=True)
class GpuSatelliteLinkSelectionLibrary:
    """
    GPU-resident chunk-stable finite-cap link allocator.

    Parameters
    ----------
    session : GpuScepterSession
        Owning GPU session. The library shares its device and activation
        semantics with this session.
    time_count : int
        Number of timesteps represented by the full batch.
    cell_count : int
        Total number of cell observers in the full batch.
    sat_count : int
        Total number of satellites in the full batch.
    min_elevation_deg : float, Quantity, array-like, or CUDA array, optional
        Per-satellite minimum elevation threshold in degrees.
    n_links : int, optional
        Number of concurrent serving links retained per cell.
    n_beam : int
        Per-satellite serving-capacity limit applied independently at each
        timestep.
    strategy : {"random", "max_elevation"}, optional
        Candidate ranking strategy used by the exact capped allocator.
    sat_belt_id_per_sat : array-like or CUDA array, optional
        Integer belt identifier for each satellite.
    beta_max_deg_per_sat : float, Quantity, array-like, or CUDA array, optional
        Per-satellite maximum cone angle ``beta`` in degrees.
    ras_topo : array-like or CUDA array, optional
        RAS-frame satellite geometry aligned to ``(T, S, K)`` after
        normalization. Required when ``include_payload=True``.
    cell_active_mask : array-like or CUDA array, optional
        Boolean demand mask aligned with the compact cell axis. Accepted shapes
        are ``(T, C)`` and ``(C,)``. Inactive cells contribute no selected
        links, counts, or eligibility.
    rng : np.random.Generator, int, numpy integer, or None, optional
        Random source used only for ``strategy="random"``. The source is
        consumed once during initialization so chunk order does not affect the
        capped result.
    include_counts : bool, optional
        If ``True``, return per-satellite demand and cone-valid counts.
    include_payload : bool, optional
        If ``True``, gather the selected-link payload tensors.
    include_eligible_mask : bool, optional
        If ``True``, store uncapped candidate eligibility for the batch.
    eligible_mask_encoding : {"dense", "csr", "both"}, optional
        Eligibility output encoding used when ``include_eligible_mask=True``.
        ``"dense"`` returns ``sat_eligible_mask`` with shape ``(T, C, S)``.
        ``"csr"`` returns sparse exact-reroute inputs via
        ``sat_eligible_csr_row_ptr``, ``sat_eligible_csr_sat_idx``, and scalar
        ``*_time_count`` / ``*_cell_count`` / ``*_sat_count`` metadata.
        ``"both"`` returns both representations.
    boresight_pointing_azimuth_deg, boresight_pointing_elevation_deg : array-like or CUDA array, optional
        Sampled RAS telescope pointings with shape ``(T, N_sky)``. Required
        only when ``boresight_theta1_deg`` or ``boresight_theta2_deg`` is
        active.
    boresight_theta1_deg, boresight_theta2_deg : float or Quantity, optional
        Optional hard-shutdown and local-exclusion boresight angles in
        degrees. ``None`` disables the corresponding rule.
    boresight_theta2_cell_ids : array-like of int, optional
        Cell-axis indices affected by ``Theta_2``. Required only when
        ``boresight_theta2_deg`` is active.
    beta_tol_deg : float, optional
        Absolute cone-validation tolerance in degrees.
    """

    session: "GpuScepterSession" = field(repr=False, compare=False)
    time_count: int
    cell_count: int
    sat_count: int
    min_elevation_deg: Any = 30 * u.deg
    n_links: int = 1
    n_beam: int = 1
    strategy: str = "random"
    sat_belt_id_per_sat: Any | None = None
    beta_max_deg_per_sat: Any | None = None
    ras_topo: Any | None = None
    cell_active_mask: Any | None = None
    rng: np.random.Generator | int | np.integer | None = None
    include_counts: bool = True
    include_payload: bool = True
    include_eligible_mask: bool = False
    eligible_mask_encoding: str = "dense"
    boresight_pointing_azimuth_deg: Any | None = None
    boresight_pointing_elevation_deg: Any | None = None
    boresight_theta1_deg: float | u.Quantity | None = None
    boresight_theta2_deg: float | u.Quantity | None = None
    boresight_theta2_cell_ids: Any | None = None
    beta_tol_deg: float = 1e-3
    strategy_name: str = field(init=False)
    use_cone_check: bool = field(init=False)
    seed_u64: np.uint64 = field(init=False, repr=False)
    sat_min_elev_host: np.ndarray = field(init=False, repr=False)
    sat_beta_max_host: np.ndarray = field(init=False, repr=False)
    sat_belt_id_host: np.ndarray = field(init=False, repr=False)
    sat_min_elev_cp: Any = field(init=False, repr=False)
    sat_beta_max_cp: Any = field(init=False, repr=False)
    sat_beta_max_rad_cp: Any = field(init=False, repr=False)
    sat_belt_id_cp: Any = field(init=False, repr=False)
    ras_topo_cp: Any | None = field(init=False, repr=False)
    cell_active_mask_cp: Any | None = field(init=False, repr=False)
    eligible_mask_cp: Any | None = field(init=False, repr=False)
    eligible_mask_encoding_name: str = field(init=False)
    boresight_theta1_deg_value: float | None = field(init=False, repr=False)
    boresight_theta2_deg_value: float | None = field(init=False, repr=False)
    boresight_sky_count: int = field(init=False)
    boresight_active: bool = field(init=False)
    boresight_pointing_az_cp: Any | None = field(init=False, repr=False)
    boresight_pointing_el_cp: Any | None = field(init=False, repr=False)
    boresight_theta2_cell_mask_cp: Any | None = field(init=False, repr=False)
    boresight_full_mask_cp: Any | None = field(init=False, repr=False)
    boresight_partial_mask_cp: Any | None = field(init=False, repr=False)
    _cells_seen: np.ndarray = field(init=False, repr=False)
    _candidate_time_parts: list[Any] = field(init=False, repr=False)
    _candidate_cell_parts: list[Any] = field(init=False, repr=False)
    _candidate_sat_parts: list[Any] = field(init=False, repr=False)
    _candidate_key_parts: list[Any] = field(init=False, repr=False)
    _candidate_alpha_parts: list[Any] | None = field(init=False, repr=False)
    _candidate_beta_parts: list[Any] | None = field(init=False, repr=False)
    _eligible_time_parts: list[Any] | None = field(init=False, repr=False)
    _eligible_cell_parts: list[Any] | None = field(init=False, repr=False)
    _eligible_sat_parts: list[Any] | None = field(init=False, repr=False)
    _packed_candidate_base_cp: dict[str, Any] | None = field(init=False, repr=False)
    _selector_candidate_view_cp: dict[str, Any] | None = field(init=False, repr=False)
    _direct_candidate_view_cp: dict[str, Any] | None = field(init=False, repr=False)
    last_add_chunk_telemetry: dict[str, Any] = field(init=False, repr=False, default_factory=dict)
    max_add_chunk_telemetry: dict[str, Any] = field(init=False, repr=False, default_factory=dict)
    _finalize_workspace: dict[str, Any] = field(init=False, repr=False, default_factory=dict)
    _use_parallel_finalize: bool = field(init=False, repr=False, default=False)
    _load_balanced_beams: bool = field(init=False, repr=False, default=False)

    def __post_init__(self) -> None:
        _require_cupy()
        self.session._ensure_owner_thread()
        self.session._ensure_open()
        if int(self.time_count) <= 0:
            raise ValueError("time_count must be positive.")
        if int(self.cell_count) <= 0:
            raise ValueError("cell_count must be positive.")
        if int(self.sat_count) <= 0:
            raise ValueError("sat_count must be positive.")
        if int(self.n_links) <= 0:
            raise ValueError("n_links must be positive.")
        if int(self.n_beam) <= 0:
            raise ValueError("n_beam must be positive.")

        self.time_count = int(self.time_count)
        self.cell_count = int(self.cell_count)
        self.sat_count = int(self.sat_count)
        self.n_links = int(self.n_links)
        self.n_beam = int(self.n_beam)
        self.strategy_name = _normalise_selection_strategy(self.strategy)
        from scepter import satsim

        self.eligible_mask_encoding_name = satsim._normalise_eligible_mask_encoding(
            self.eligible_mask_encoding
        )
        self.use_cone_check = self.beta_max_deg_per_sat is not None
        self.seed_u64 = _seed_from_rng(self.rng) if self.strategy_name == "random" else np.uint64(0)
        self.boresight_theta1_deg_value = (
            float(u.Quantity(self.boresight_theta1_deg).to_value(u.deg))
            if self.boresight_theta1_deg is not None and hasattr(self.boresight_theta1_deg, "to")
            else (float(self.boresight_theta1_deg) if self.boresight_theta1_deg is not None else None)
        )
        self.boresight_theta2_deg_value = (
            float(u.Quantity(self.boresight_theta2_deg).to_value(u.deg))
            if self.boresight_theta2_deg is not None and hasattr(self.boresight_theta2_deg, "to")
            else (float(self.boresight_theta2_deg) if self.boresight_theta2_deg is not None else None)
        )
        if self.boresight_theta1_deg_value is not None and self.boresight_theta1_deg_value < 0.0:
            raise ValueError("boresight_theta1_deg must be non-negative or None.")
        if self.boresight_theta2_deg_value is not None and self.boresight_theta2_deg_value < 0.0:
            raise ValueError("boresight_theta2_deg must be non-negative or None.")
        if (
            self.boresight_theta1_deg_value is not None
            and self.boresight_theta2_deg_value is not None
            and self.boresight_theta1_deg_value > self.boresight_theta2_deg_value
        ):
            raise ValueError("boresight_theta1_deg must be less than or equal to boresight_theta2_deg.")
        self.boresight_active = (
            self.boresight_theta1_deg_value is not None or self.boresight_theta2_deg_value is not None
        )
        self.boresight_sky_count = 1
        self.boresight_pointing_az_cp = None
        self.boresight_pointing_el_cp = None
        self.boresight_theta2_cell_mask_cp = None
        self.boresight_full_mask_cp = None
        self.boresight_partial_mask_cp = None

        self.sat_min_elev_host = _normalise_per_satellite_float(
            self.min_elevation_deg,
            self.sat_count,
            name="min_elevation_deg",
            dtype=self.session.compute_dtype,
        )
        self.sat_beta_max_host = _normalise_per_satellite_float(
            self.beta_max_deg_per_sat,
            self.sat_count,
            name="beta_max_deg_per_sat",
            dtype=np.float32,
            fill_value=np.inf,
        )
        self.sat_belt_id_host = _normalise_per_satellite_int(
            self.sat_belt_id_per_sat,
            self.sat_count,
            name="sat_belt_id_per_sat",
            dtype=np.int16,
            fill_value=-1,
        )

        with self.session._temporary_activation():
            self.sat_min_elev_cp = cp.asarray(np.ascontiguousarray(self.sat_min_elev_host, dtype=self.session.compute_dtype))
            self.sat_beta_max_cp = cp.asarray(np.ascontiguousarray(self.sat_beta_max_host, dtype=np.float32))
            self.sat_beta_max_rad_cp = (self.sat_beta_max_cp * cp.float32(np.pi / 180.0)).astype(cp.float32, copy=False)
            self.sat_belt_id_cp = cp.asarray(np.ascontiguousarray(self.sat_belt_id_host, dtype=np.int16))
            if self.include_payload:
                if self.ras_topo is None:
                    raise ValueError("ras_topo is required when include_payload=True.")
                self.ras_topo_cp = _normalise_ras_topo_cupy(
                    self.ras_topo,
                    time_count=self.time_count,
                    sat_count=self.sat_count,
                    compute_dtype=self.session.compute_dtype,
                )
            elif self.ras_topo is not None:
                self.ras_topo_cp = _normalise_ras_topo_cupy(
                    self.ras_topo,
                    time_count=self.time_count,
                    sat_count=self.sat_count,
                    compute_dtype=self.session.compute_dtype,
                )
            else:
                self.ras_topo_cp = None
            self.cell_active_mask_cp = _normalise_cell_active_mask_cupy(
                self.cell_active_mask,
                time_count=self.time_count,
                cell_count=self.cell_count,
            )
            self.eligible_mask_cp = None
            if self.include_eligible_mask and (
                self.eligible_mask_encoding_name in {"dense", "both"} or self.boresight_active
            ):
                self.eligible_mask_cp = cp.zeros((self.time_count, self.cell_count, self.sat_count), dtype=cp.bool_)
            if self.boresight_active:
                if self.ras_topo_cp is None:
                    raise ValueError("ras_topo is required when boresight avoidance is active.")
                if self.boresight_pointing_azimuth_deg is None or self.boresight_pointing_elevation_deg is None:
                    raise ValueError(
                        "boresight_pointing_azimuth_deg and boresight_pointing_elevation_deg are required "
                        "when boresight avoidance is active."
                    )
                self.boresight_pointing_az_cp = cp.asarray(self.boresight_pointing_azimuth_deg, dtype=cp.float32)
                self.boresight_pointing_el_cp = cp.asarray(self.boresight_pointing_elevation_deg, dtype=cp.float32)
                if self.boresight_pointing_az_cp.shape != self.boresight_pointing_el_cp.shape:
                    raise ValueError(
                        "boresight_pointing_azimuth_deg and boresight_pointing_elevation_deg must share the same shape."
                    )
                if self.boresight_pointing_az_cp.ndim != 2:
                    raise ValueError(
                        "boresight_pointing_azimuth_deg and boresight_pointing_elevation_deg must have shape (T, N_sky)."
                    )
                if int(self.boresight_pointing_az_cp.shape[0]) != self.time_count:
                    raise ValueError(
                        "Boresight pointing time axis must match the selection time axis; "
                        f"expected {self.time_count}, got {int(self.boresight_pointing_az_cp.shape[0])}."
                    )
                self.boresight_sky_count = int(self.boresight_pointing_az_cp.shape[1])
                if self.boresight_theta2_deg_value is not None:
                    if self.boresight_theta2_cell_ids is None:
                        raise ValueError(
                            "boresight_theta2_cell_ids is required when boresight_theta2_deg is active."
                        )
                    theta2_ids = np.asarray(self.boresight_theta2_cell_ids, dtype=np.int32).reshape(-1)

                    # Empty is valid here: adjacency/radius resolution can legitimately
                    # collapse to an empty ACTIVE-axis set after geography masking and/or
                    # RAS exclusion. That simply means Theta_2 affects no active cells.
                    if theta2_ids.size == 0:
                        self.boresight_theta2_cell_mask_cp = cp.zeros(
                            self.cell_count,
                            dtype=cp.bool_,
                        )
                    else:
                        if np.any(theta2_ids < 0) or np.any(theta2_ids >= int(self.cell_count)):
                            raise ValueError(
                                f"boresight_theta2_cell_ids must lie within [0, {self.cell_count - 1}]."
                            )
                        theta2_ids = np.unique(theta2_ids.astype(np.int32, copy=False))
                        theta2_mask = np.zeros(self.cell_count, dtype=np.bool_)
                        theta2_mask[theta2_ids] = True
                        self.boresight_theta2_cell_mask_cp = cp.asarray(theta2_mask, dtype=cp.bool_)

        self._cells_seen = np.zeros(self.cell_count, dtype=np.bool_)
        self._candidate_time_parts = []
        self._candidate_cell_parts = []
        self._candidate_sat_parts = []
        self._candidate_key_parts = []
        if self.include_payload or self.use_cone_check or self.boresight_active:
            self._candidate_alpha_parts = []
            self._candidate_beta_parts = []
        else:
            self._candidate_alpha_parts = None
            self._candidate_beta_parts = None
        if self.include_eligible_mask and self.eligible_mask_encoding_name in {"csr", "both"} and not self.boresight_active:
            self._eligible_time_parts = []
            self._eligible_cell_parts = []
            self._eligible_sat_parts = []
        else:
            self._eligible_time_parts = None
            self._eligible_cell_parts = None
            self._eligible_sat_parts = None
        self._packed_candidate_base_cp = None
        self._selector_candidate_view_cp = None
        self._direct_candidate_view_cp = None
        self.last_add_chunk_telemetry = {}
        self.max_add_chunk_telemetry = {}

    def add_chunk(
        self,
        cell_offset: int,
        sat_topo_chunk: Any,
        *,
        sat_azel: Any | None = None,
        sat_index_remap: Any | None = None,
    ) -> None:
        cell_offset_i = int(cell_offset)
        if cell_offset_i < 0 or cell_offset_i > self.cell_count:
            raise ValueError(f"cell_offset must be in [0, {self.cell_count}], got {cell_offset_i}.")

        self.session._ensure_owner_thread()
        self.session._ensure_open()
        with self.session._temporary_activation():
            chunk_memory_observation = _start_gpu_memory_observation_cp()
            sat_topo_dev, _, sat_shape = _coerce_link_pairwise_tensor(
                sat_topo_chunk,
                name="sat_topo_chunk",
                min_last_dim=2,
                compute_dtype=self.session.compute_dtype,
            )
            if sat_shape[0] != self.time_count:
                raise ValueError(
                    f"sat_topo_chunk time dimension {sat_shape[0]} does not match time_count={self.time_count}."
                )
            # When sat_index_remap is provided the chunk carries only the
            # pre-filtered satellite subset.  The remap array maps filtered
            # indices back to the full satellite axis so candidate sat ids
            # remain globally consistent.
            sat_remap_cp: Any | None = None
            chunk_sat_count = int(sat_shape[2])
            if sat_index_remap is not None:
                sat_remap_cp = cp.asarray(sat_index_remap, dtype=cp.int32).reshape(-1)
                if int(sat_remap_cp.size) != chunk_sat_count:
                    raise ValueError(
                        f"sat_index_remap length {int(sat_remap_cp.size)} does not match "
                        f"satellite dimension {chunk_sat_count}."
                    )
            elif sat_shape[2] != self.sat_count:
                raise ValueError(
                    f"sat_topo_chunk satellite dimension {sat_shape[2]} does not match sat_count={self.sat_count}."
                )

            chunk_cell_count = int(sat_shape[1])
            cell_stop = cell_offset_i + chunk_cell_count
            if cell_stop > self.cell_count:
                raise ValueError(
                    f"Chunk cell range [{cell_offset_i}, {cell_stop}) exceeds cell_count={self.cell_count}."
                )
            if np.any(self._cells_seen[cell_offset_i:cell_stop]):
                raise ValueError(f"Chunk cell range [{cell_offset_i}, {cell_stop}) overlaps an existing chunk.")
            self._cells_seen[cell_offset_i:cell_stop] = True

            sat_azel_dev = None
            if sat_azel is not None:
                sat_azel_dev, _, sat_azel_shape = _coerce_link_pairwise_tensor(
                    sat_azel,
                    name="sat_azel",
                    min_last_dim=2,
                    compute_dtype=self.session.compute_dtype,
                )
                if sat_azel_shape[:3] != sat_shape[:3]:
                    raise ValueError("sat_azel must align with sat_topo_chunk over (T, C, S).")
            if (
                self.include_payload
                or self.use_cone_check
                or self.include_eligible_mask
                or self.boresight_active
            ) and sat_azel_dev is None:
                raise ValueError(
                    "sat_azel is required when include_payload=True, include_eligible_mask=True, "
                    "boresight avoidance is active, or beta_max_deg_per_sat is provided."
                )

            sat_topo_cp = _to_cupy_array(sat_topo_dev, dtype=cp.float32 if self.session.compute_dtype == np.float32 else cp.float64)
            elev_deg = sat_topo_cp[..., 1]
            # When sat_index_remap is provided the chunk carries a filtered
            # satellite subset.  Index per-sat thresholds accordingly.
            if sat_remap_cp is not None:
                min_elev_for_chunk = self.sat_min_elev_cp[sat_remap_cp]
            else:
                min_elev_for_chunk = self.sat_min_elev_cp
            sat_azel_cp = None
            theta_abs = None
            if sat_azel_dev is not None:
                sat_azel_cp = _to_cupy_array(sat_azel_dev, dtype=cp.float32 if self.session.compute_dtype == np.float32 else cp.float64)
                theta_abs = cp.abs(sat_azel_cp[..., 1]).astype(cp.float32, copy=False)

            if sat_remap_cp is not None and self.use_cone_check:
                beta_max_for_chunk = self.sat_beta_max_cp[sat_remap_cp]
            elif self.use_cone_check:
                beta_max_for_chunk = self.sat_beta_max_cp
            else:
                beta_max_for_chunk = None

            # Fused visibility + eligible computation: elevation check +
            # cell activity mask + cone check in a single kernel launch.
            _cell_mask = (
                self.cell_active_mask_cp[:, cell_offset_i:cell_stop, None]
                if self.cell_active_mask_cp is not None
                else cp.bool_(True)
            )
            _theta_for_vis = theta_abs if theta_abs is not None else cp.float32(0.0)
            _beta_for_vis = (
                beta_max_for_chunk[None, None, :] if beta_max_for_chunk is not None
                else cp.float32(999.0)
            )
            _vis_kernel = _get_visibility_fused_kernel()
            # The fused visibility kernel is declared with float32 inputs.
            # Under ``compute_dtype=float64`` the propagation tensors
            # (``sat_topo_cp``, ``sat_min_elev_cp``, ``sat_beta_max_cp``)
            # arrive as float64, so we down-cast explicitly at the kernel
            # boundary — these are degrees in the ±90 / ±180 range where
            # fp32 is plenty, and the kernel's comparisons are semantically
            # unchanged by the cast.  Without these casts CuPy raises
            # ``TypeError: Type is mismatched`` on the first batch.
            _elev_f32 = elev_deg.astype(cp.float32, copy=False)
            _min_elev_f32 = min_elev_for_chunk.astype(cp.float32, copy=False)
            if beta_max_for_chunk is not None:
                _beta_for_vis = beta_max_for_chunk.astype(cp.float32, copy=False)[None, None, :]
            visible, eligible_computed = _vis_kernel(
                _elev_f32,
                _min_elev_f32[None, None, :],
                _cell_mask,
                _theta_for_vis,
                _beta_for_vis,
                cp.int32(1 if self.cell_active_mask_cp is not None else 0),
                cp.int32(1 if self.use_cone_check else 0),
                cp.float32(float(self.beta_tol_deg)),
            )
            chunk_memory_observation = _update_gpu_memory_observation_cp(chunk_memory_observation)

            eligible_matches_visible = not self.use_cone_check
            if self.include_eligible_mask and self.eligible_mask_cp is not None:
                eligible = eligible_computed
                if sat_remap_cp is not None:
                    self.eligible_mask_cp[:, cell_offset_i:cell_stop, :] = False
                    self.eligible_mask_cp[:, cell_offset_i:cell_stop, :][:, :, sat_remap_cp] = eligible.astype(cp.bool_, copy=False)
                else:
                    self.eligible_mask_cp[:, cell_offset_i:cell_stop, :] = eligible.astype(cp.bool_, copy=False)
            elif self.include_eligible_mask:
                eligible = eligible_computed
                if not self.use_cone_check:
                    eligible_matches_visible = True
            else:
                eligible = None
            chunk_memory_observation = _update_gpu_memory_observation_cp(chunk_memory_observation)

            visible_flat = visible.reshape(-1)
            flat_idx = cp.nonzero(visible_flat)[0].astype(cp.int64, copy=False)
            if int(flat_idx.size) == 0:
                finalized_chunk_memory = _finalize_gpu_memory_observation_cp(
                    _update_gpu_memory_observation_cp(chunk_memory_observation)
                )
                finalized_chunk_memory["chunk_cell_count"] = int(chunk_cell_count)
                finalized_chunk_memory["visible_candidate_count"] = 0
                self.last_add_chunk_telemetry = dict(finalized_chunk_memory)
                self.max_add_chunk_telemetry = {
                    **dict(self.max_add_chunk_telemetry),
                    **{
                        str(key): (
                            max(
                                int(self.max_add_chunk_telemetry.get(str(key), 0) or 0),
                                int(value),
                            )
                            if isinstance(value, (int, np.integer))
                            else value
                        )
                        for key, value in finalized_chunk_memory.items()
                    },
                }
                return
            # Fused candidate field gathering: decompose flat_idx AND
            # gather all 7 candidate fields in ONE kernel launch.
            # Replaces ~12 separate CuPy operations.
            _has_azel = sat_azel_cp is not None and theta_abs is not None
            _has_remap = sat_remap_cp is not None
            _gather_k = _get_add_chunk_gather_kernel()
            # Fused gather kernel declares float32 inputs; under fp64
            # compute_dtype the propagation tensors land as float64, so
            # cast at the kernel boundary (same rationale as the
            # visibility-kernel cast above).  Elevation and azimuth are
            # in degrees, well inside fp32's meaningful range.
            _elev_flat_f32 = elev_deg.reshape(-1).astype(cp.float32, copy=False)
            if _has_azel:
                _az_flat_f32 = sat_azel_cp[..., 0].reshape(-1).astype(
                    cp.float32, copy=False,
                )
                _theta_flat_f32 = theta_abs.reshape(-1).astype(cp.float32, copy=False)
            else:
                _az_flat_f32 = cp.zeros(1, dtype=cp.float32)
                _theta_flat_f32 = cp.zeros(1, dtype=cp.float32)
            (
                time_idx, global_cell_idx, sat_idx,
                _key_out, global_row_idx, _alpha_out, _beta_out,
            ) = _gather_k(
                flat_idx,
                _elev_flat_f32,
                _az_flat_f32,
                _theta_flat_f32,
                sat_remap_cp if _has_remap else cp.zeros(1, dtype=cp.int32),
                np.int32(chunk_sat_count),
                np.int32(chunk_cell_count),
                np.int32(cell_offset_i),
                np.int32(self.cell_count),
                np.int32(1 if _has_remap else 0),
                np.int32(1 if _has_azel else 0),
            )
            local_cell_idx = global_cell_idx - cp.int32(cell_offset_i)
            chunk_memory_observation = _update_gpu_memory_observation_cp(chunk_memory_observation)

            if (
                eligible is not None
                and self._eligible_time_parts is not None
                and self._eligible_cell_parts is not None
                and self._eligible_sat_parts is not None
            ):
                if eligible_matches_visible:
                    eligible_time = time_idx
                    eligible_local_cell = local_cell_idx
                    eligible_sat = sat_idx
                else:
                    eligible_flat = eligible.reshape(-1)
                    eligible_idx = cp.nonzero(eligible_flat)[0].astype(cp.int64, copy=False)
                    _init_decode_edge_kernels()
                    eligible_time, eligible_local_cell, eligible_local_sat = _decode_edge_kernel_3d(
                        eligible_idx,
                        np.int32(int(chunk_cell_count) * int(chunk_sat_count)),
                        np.int32(int(chunk_sat_count)),
                    )
                    eligible_sat = sat_remap_cp[eligible_local_sat] if _has_remap else eligible_local_sat
                self._eligible_time_parts.append(eligible_time.astype(cp.int32, copy=False))
                self._eligible_cell_parts.append(eligible_local_cell + cp.int32(cell_offset_i))
                self._eligible_sat_parts.append(eligible_sat.astype(cp.int32, copy=False))
                chunk_memory_observation = _update_gpu_memory_observation_cp(chunk_memory_observation)

            self._candidate_time_parts.append(time_idx)
            self._candidate_cell_parts.append(global_cell_idx)
            self._candidate_sat_parts.append(sat_idx)
            if self.strategy_name == "max_elevation":
                self._candidate_key_parts.append(_key_out)
            else:
                self._candidate_key_parts.append(_pair_priority_random_cupy(self.seed_u64, global_row_idx, sat_idx))

            if self._candidate_alpha_parts is not None and self._candidate_beta_parts is not None:
                self._candidate_alpha_parts.append(_alpha_out)
                self._candidate_beta_parts.append(_beta_out)
            finalized_chunk_memory = _finalize_gpu_memory_observation_cp(
                _update_gpu_memory_observation_cp(chunk_memory_observation)
            )
            finalized_chunk_memory["chunk_cell_count"] = int(chunk_cell_count)
            finalized_chunk_memory["visible_candidate_count"] = int(flat_idx.size)
            self.last_add_chunk_telemetry = dict(finalized_chunk_memory)
            aggregated = dict(self.max_add_chunk_telemetry)
            for key, value in finalized_chunk_memory.items():
                if isinstance(value, (int, np.integer)):
                    aggregated[str(key)] = int(
                        max(int(aggregated.get(str(key), 0) or 0), int(value))
                    )
                else:
                    aggregated[str(key)] = value
            self.max_add_chunk_telemetry = aggregated

    def finalize(self, *, return_device: bool = False) -> dict[str, Any]:
        self.session._ensure_owner_thread()
        self.session._ensure_open()
        if not np.all(self._cells_seen):
            missing = np.flatnonzero(~self._cells_seen)
            raise RuntimeError(
                f"Missing cell chunks for {missing.size} cells; first missing index is {int(missing[0])}."
            )

        with self.session._temporary_activation():
            if self.boresight_active:
                result = _finalize_staged_boresight_link_selection_library_cupy(
                    self,
                    return_device=return_device,
                )
            else:
                result = _package_link_selection_result_cp(
                    self,
                    selection_cp=_finalize_link_selection_library_minimal_slab_cp(
                        self,
                        time_start=0,
                        time_stop=self.time_count,
                        force_ordinary=True,
                        selector_backend=GPU_DIRECT_SELECTOR_BACKEND_REFERENCE,
                        debug_direct_epfd=False,
                    ),
                    eligible_mask_cp=None,
                    return_device=return_device,
                )
        self.session._touch()
        return result

    # Direct EPFD beam finalization consumes the ranked link library and
    # rewrites only the affected links so the first-pass capped allocation
    # stays stable for all unaffected cells.
    def finalize_direct_epfd_beams(
        self,
        *,
        ras_cell_index: int | None = None,
        ras_sat_azel: Any | None = None,
        ras_guard_angle_rad: float = 0.0,
        ras_pointing_mode: str = "ras_station",
        include_diagnostics: bool = True,
        include_full_sat_beam_counts_used: bool = False,
        output_sat_indices: Any | None = None,
        working_memory_budget_bytes: int | None = None,
        scheduler_target_profile: str | float | None = "high_throughput",
        debug_direct_epfd: bool = False,
        return_device: bool = False,
    ) -> dict[str, Any]:
        """
        Finalize a direct-link EPFD beam table from the stored finite-cap library.

        This method reuses the exact finite-cap selector as the first pass,
        then materializes one direct beam per realized ``(time, cell, link)``
        assignment. In ``ras_pointing_mode="ras_station"`` it retargets the
        selected links of the RAS service cell as exact RAS-pointed beams and
        performs a GPU-side local repair of only the displaced ordinary
        direct-cell links. In ``ras_pointing_mode="cell_center"`` it keeps the
        ordinary cell-center beams from the first pass without any RAS-specific
        retarget or repair step.

        Parameters
        ----------
        ras_cell_index : int or None, optional
            Zero-based index of the active hexgrid cell representing the RAS
            service cell within the full batch cell axis. Required when
            ``ras_pointing_mode="ras_station"`` and ignored otherwise.
        ras_sat_azel : Any or None, optional
            Exact RAS-observer satellite body-frame geometry with shape
            ``(T, S, K)``, ``(T, 1, S, K)``, or ``(S, K)``. The first two
            fields must be azimuth and theta in degrees. When
            ``output_sat_indices`` is provided, the satellite axis may align
            either with the full link-library satellite count ``S`` or with the
            compact ``output_sat_indices`` axis. The compact form is the
            preferred production path for direct-EPFD batches because it avoids
            carrying unused RAS-side satellites through finalize. Required when
            ``ras_pointing_mode="ras_station"`` and ignored otherwise.
        ras_guard_angle_rad : float, optional
            Minimum angular separation in radians enforced only between a
            RAS-pointed beam and a direct-cell beam on the same
            satellite. Set to zero to disable the guard. Ignored when
            ``ras_pointing_mode="cell_center"``.
        ras_pointing_mode : {"ras_station", "cell_center"}, optional
            Direct-link pointing policy for the RAS service cell.
        include_diagnostics : bool, optional
            If ``True``, return per-timestep diagnostics describing how many
            links were reserved, kept, repaired, and dropped.
        include_full_sat_beam_counts_used : bool, optional
            If ``True``, also return ``sat_beam_counts_used_full`` on the full
            library satellite axis. The existing ``sat_beam_counts_used``
            result remains aligned to ``output_sat_indices`` so reduced-output
            beam-table workflows can stay memory-efficient.
        output_sat_indices : Any or None, optional
            Optional one-dimensional integer satellite subset on the original
            library satellite axis. NumPy arrays, Python sequences, CuPy
            arrays, and CUDA-array-interface inputs are accepted. When
            provided, the returned beam-table and ``sat_beam_counts_used``
            tensors are restricted to that output axis order, while the
            internal exact retarget/repair logic still evaluates the full
            satellite set.
        working_memory_budget_bytes : int or None, optional
            Optional transient-device-memory budget used to split the direct
            finalization into exact time and, when boresight is active, sky
            slabs. ``None`` uses an automatic working budget derived from
            current free GPU memory and ``scheduler_target_profile``.
        scheduler_target_profile : {"conservative", "high_throughput", "max_throughput"} or float or None, optional
            Packing target applied when ``working_memory_budget_bytes`` is not
            provided. String presets resolve to the standard scheduler
            fractions; raw floats in ``(0, 1]`` are also accepted.
        return_device : bool, optional
            If ``True``, keep the result arrays on the GPU. Otherwise return
            NumPy host copies.

        Returns
        -------
        dict[str, Any]
            Dictionary containing ``beam_idx``, ``beam_alpha_rad``,
            ``beam_beta_rad``, and ``sat_beam_counts_used``. The
            ``sat_beam_counts_used`` tensor follows the requested
            ``output_sat_indices`` axis order, while
            ``sat_beam_counts_used_full`` is included only when
            ``include_full_sat_beam_counts_used=True`` and stays on the full
            library satellite axis. In the non-boresight path the beam-table
            tensors have shape
            ``(T, S_out, Nbeam)``; when the underlying link library was
            prepared with boresight pointings and active boresight the
            beam-table tensors gain a sky-cell axis with shape
            ``(T, N_sky, S_out, Nbeam)``. ``S_out`` equals the full library
            satellite axis when ``output_sat_indices=None`` and otherwise
            follows the provided output subset order. When
            ``include_diagnostics=True``, the result also includes
            ``ras_retargeted_count``, ``direct_kept_count``,
            ``repaired_link_count``, and ``dropped_link_count`` with matching
            leading axes. In ``ras_pointing_mode="cell_center"``,
            ``ras_retargeted_count`` and ``repaired_link_count`` are always
            zero.

        Raises
        ------
        RuntimeError
            Raised if the library is incomplete or if payload gathering was not
            enabled when the library was created.
        ValueError
            Raised when the requested pointing mode is unsupported or when the
            RAS-specific inputs are invalid for ``ras_pointing_mode="ras_station"``.

        Notes
        -----
        Ordinary direct-cell beams are not subjected to a generic pairwise
        ``theta_sep`` rule here. In ``ras_pointing_mode="ras_station"`` the
        only extra angular exclusion is the RAS-pointed guard angle against
        beams on the same satellite. The RAS service cell does not create extra
        beams beyond the realized ``(time, cell, link)`` assignments of the
        finite-cap selector; its selected links are simply retargeted to the
        exact RAS boresight when that pointing mode is active. The default call
        signature preserves the historical exact behavior and full-satellite
        output shape. ``output_sat_indices`` and
        ``working_memory_budget_bytes`` are opt-in execution controls: they may
        reduce the returned satellite axis or split the work into exact slabs,
        but they do not change which links are retargeted, kept, repaired, or
        dropped.
        """
        return _finalize_direct_epfd_beams_cp(
            self,
            ras_cell_index=None if ras_cell_index is None else int(ras_cell_index),
            ras_sat_azel=ras_sat_azel,
            ras_guard_angle_rad=float(ras_guard_angle_rad),
            ras_pointing_mode=_normalise_direct_epfd_ras_pointing_mode(ras_pointing_mode),
            include_diagnostics=bool(include_diagnostics),
            include_full_sat_beam_counts_used=bool(include_full_sat_beam_counts_used),
            output_sat_indices=output_sat_indices,
            working_memory_budget_bytes=(
                None if working_memory_budget_bytes is None else int(working_memory_budget_bytes)
            ),
            scheduler_target_profile=scheduler_target_profile,
            debug_direct_epfd=bool(debug_direct_epfd),
            return_device=bool(return_device),
        )

    def iter_direct_epfd_beam_slabs(
        self,
        *,
        ras_cell_index: int | None = None,
        ras_sat_azel: Any | None = None,
        ras_guard_angle_rad: float = 0.0,
        ras_pointing_mode: str = "ras_station",
        include_diagnostics: bool = True,
        include_full_sat_beam_counts_used: bool = False,
        output_sat_indices: Any | None = None,
        working_memory_budget_bytes: int | None = None,
        scheduler_target_profile: str | float | None = "high_throughput",
        debug_direct_epfd: bool = False,
    ) -> Iterator[dict[str, Any]]:
        """
        Yield exact direct-EPFD beam-table slabs on the GPU.

        This internal iterator mirrors :meth:`finalize_direct_epfd_beams` but
        keeps the work split into exact time / sky slabs so downstream GPU
        stages can stream them without materializing the full beam table.
        """
        yield from _iter_direct_finalize_slab_results_cp(
            self,
            ras_cell_index=None if ras_cell_index is None else int(ras_cell_index),
            ras_sat_azel=ras_sat_azel,
            ras_guard_angle_rad=float(ras_guard_angle_rad),
            ras_pointing_mode=_normalise_direct_epfd_ras_pointing_mode(ras_pointing_mode),
            include_diagnostics=bool(include_diagnostics),
            include_full_sat_beam_counts_used=bool(include_full_sat_beam_counts_used),
            output_sat_indices=output_sat_indices,
            working_memory_budget_bytes=(
                None if working_memory_budget_bytes is None else int(working_memory_budget_bytes)
            ),
            scheduler_target_profile=scheduler_target_profile,
            debug_direct_epfd=bool(debug_direct_epfd),
        )


def _normalise_ras_sat_azel_cupy(
    value: Any,
    *,
    time_count: int,
    sat_count: int,
) -> Any:
    arr = _coerce_step2_topo_tensor_cp(value, name="ras_sat_azel")
    if int(arr.shape[0]) != int(time_count) or int(arr.shape[1]) != int(sat_count):
        raise ValueError(
            "ras_sat_azel must align with the link library over (T, S); "
            f"expected ({int(time_count)}, {int(sat_count)}, K), got {tuple(arr.shape)!r}."
        )
    if int(arr.shape[2]) < 2:
        raise ValueError("ras_sat_azel last axis must contain at least azimuth and theta.")
    return arr


def _prepare_finalize_ras_station_lookup_cupy(
    value: Any,
    *,
    time_count: int,
    library_sat_count: int,
    output_sat_indices_cp: Any,
    ras_topo_cp: Any,
) -> dict[str, Any]:
    arr = _coerce_step2_topo_tensor_cp(value, name="ras_sat_azel")
    if int(arr.shape[0]) != int(time_count):
        raise ValueError(
            "ras_sat_azel must align with finalize time axis; "
            f"expected time dimension {int(time_count)}, got {tuple(arr.shape)!r}."
        )
    if int(arr.shape[2]) < 2:
        raise ValueError("ras_sat_azel last axis must contain at least azimuth and theta.")

    sat_axis_count = int(arr.shape[1])
    output_sat_count = int(output_sat_indices_cp.size)
    ras_axis_is_compact = False
    ras_topo_lookup_cp = ras_topo_cp
    if sat_axis_count == int(library_sat_count):
        pass
    elif sat_axis_count == int(output_sat_count):
        ras_axis_is_compact = True
        ras_topo_lookup_cp = cp.take(
            ras_topo_cp,
            output_sat_indices_cp.astype(cp.int32, copy=False),
            axis=1,
        )
    else:
        raise ValueError(
            "ras_sat_azel must align with either the full link-library satellite axis or the "
            "compact output_sat_indices axis; expected "
            f"({int(time_count)}, {int(library_sat_count)}, K) or "
            f"({int(time_count)}, {int(output_sat_count)}, K), got {tuple(arr.shape)!r}."
        )

    ras_elevation_deg_cp = ras_topo_lookup_cp[..., 1].astype(cp.float32, copy=False)
    ras_alpha_rad_cp = cp.remainder(
        arr[..., 0].astype(cp.float32, copy=False) * cp.float32(np.pi / 180.0),
        cp.float32(2.0 * np.pi),
    ).astype(cp.float32, copy=False)
    ras_beta_deg_cp = cp.abs(arr[..., 1].astype(cp.float32, copy=False))
    ras_beta_rad_cp = (ras_beta_deg_cp * cp.float32(np.pi / 180.0)).astype(cp.float32, copy=False)
    return {
        "ras_sat_azel_cp": arr,
        "ras_elevation_deg_cp": ras_elevation_deg_cp,
        "ras_alpha_rad_cp": ras_alpha_rad_cp,
        "ras_beta_rad_cp": ras_beta_rad_cp,
        "ras_sat_axis_is_compact": bool(ras_axis_is_compact),
    }


def _compute_boresight_masks_slab_cp(
    library: GpuSatelliteLinkSelectionLibrary,
    *,
    time_start: int,
    time_stop: int,
    sky_start: int = 0,
    sky_stop: int | None = None,
) -> tuple[Any, Any]:
    if not library.boresight_active:
        raise RuntimeError("_compute_boresight_masks_slab_cp requires boresight_active=True.")
    assert library.ras_topo_cp is not None
    assert library.boresight_pointing_az_cp is not None
    assert library.boresight_pointing_el_cp is not None

    time_start_i = int(time_start)
    time_stop_i = int(time_stop)
    sky_start_i = int(sky_start)
    sky_stop_i = int(library.boresight_sky_count if sky_stop is None else sky_stop)
    if time_stop_i <= time_start_i:
        raise ValueError("time_stop must be greater than time_start.")
    if sky_stop_i <= sky_start_i:
        raise ValueError("sky_stop must be greater than sky_start.")

    ras_topo_cp = library.ras_topo_cp[time_start_i:time_stop_i]
    pointing_az_cp = library.boresight_pointing_az_cp[time_start_i:time_stop_i, sky_start_i:sky_stop_i]
    pointing_el_cp = library.boresight_pointing_el_cp[time_start_i:time_stop_i, sky_start_i:sky_stop_i]

    sat_az_rad = cp.deg2rad(
        cp.remainder(
            ras_topo_cp[..., 0].astype(cp.float32, copy=False),
            cp.float32(360.0),
        )
    )
    sat_el_rad = cp.deg2rad(ras_topo_cp[..., 1].astype(cp.float32, copy=False))
    tel_az_rad = cp.deg2rad(cp.remainder(pointing_az_cp, cp.float32(360.0)))
    tel_el_rad = cp.deg2rad(pointing_el_cp)
    cos_daz = cp.cos(tel_az_rad[:, :, None] - sat_az_rad[:, None, :]).astype(
        cp.float32, copy=False
    )
    cos_gamma = (
        cp.sin(tel_el_rad[:, :, None]).astype(cp.float32, copy=False)
        * cp.sin(sat_el_rad[:, None, :]).astype(cp.float32, copy=False)
        + cp.cos(tel_el_rad[:, :, None]).astype(cp.float32, copy=False)
        * cp.cos(sat_el_rad[:, None, :]).astype(cp.float32, copy=False)
        * cos_daz
    ).astype(cp.float32, copy=False)
    cos_gamma = cp.clip(cos_gamma, cp.float32(-1.0), cp.float32(1.0))
    separation_deg = cp.rad2deg(cp.arccos(cos_gamma)).astype(cp.float32, copy=False)
    above_horizon = ras_topo_cp[:, None, :, 1].astype(cp.float32, copy=False) > cp.float32(0.0)

    if library.boresight_theta1_deg_value is not None:
        full_mask_cp = above_horizon & (
            separation_deg <= cp.float32(library.boresight_theta1_deg_value)
        )
    else:
        full_mask_cp = cp.zeros_like(separation_deg, dtype=cp.bool_)
    if library.boresight_theta2_deg_value is not None:
        partial_mask_cp = above_horizon & (
            separation_deg <= cp.float32(library.boresight_theta2_deg_value)
        )
        if library.boresight_theta1_deg_value is not None:
            partial_mask_cp &= ~full_mask_cp
    else:
        partial_mask_cp = cp.zeros_like(separation_deg, dtype=cp.bool_)
    return (
        cp.ascontiguousarray(full_mask_cp.astype(cp.bool_, copy=False)),
        cp.ascontiguousarray(partial_mask_cp.astype(cp.bool_, copy=False)),
    )


def _ensure_boresight_masks_cp(library: GpuSatelliteLinkSelectionLibrary) -> None:
    if not library.boresight_active:
        return
    if library.boresight_full_mask_cp is not None and library.boresight_partial_mask_cp is not None:
        return
    (
        library.boresight_full_mask_cp,
        library.boresight_partial_mask_cp,
    ) = _compute_boresight_masks_slab_cp(
        library,
        time_start=0,
        time_stop=library.time_count,
        sky_start=0,
        sky_stop=library.boresight_sky_count,
    )


def _compact_boresight_sat_mask_rows_cp(mask_cp: Any) -> tuple[Any, Any]:
    row_count = int(mask_cp.shape[0]) * int(mask_cp.shape[1])
    sat_count = int(mask_cp.shape[2])
    flat_mask_cp = mask_cp.reshape(-1)
    true_idx_cp = cp.nonzero(flat_mask_cp)[0].astype(cp.int64, copy=False)
    if int(true_idx_cp.size) <= 0:
        return cp.zeros(row_count + 1, dtype=cp.int64), cp.empty(0, dtype=cp.int32)

    sat_idx_cp = (true_idx_cp % cp.int64(sat_count)).astype(cp.int32, copy=False)
    row_idx_cp = (true_idx_cp // cp.int64(sat_count)).astype(cp.int32, copy=False)
    row_counts_cp = cp.bincount(row_idx_cp, minlength=row_count).astype(cp.int64, copy=False)
    row_ptr_cp = cp.empty(row_count + 1, dtype=cp.int64)
    row_ptr_cp[0] = cp.int64(0)
    row_ptr_cp[1:] = cp.cumsum(row_counts_cp, dtype=cp.int64)
    return row_ptr_cp, sat_idx_cp


def _scatter_sparse_row_sat_chunk_cp(
    *,
    row_idx_cp: Any,
    sat_idx_cp: Any,
    row_count: int,
    row_write_offsets_cp: Any,
    sat_out_cp: Any,
) -> None:
    if int(row_idx_cp.size) <= 0:
        return
    order_cp, rank_cp = _stable_group_rank_cp(
        row_idx_cp.astype(cp.int32, copy=False),
        sat_idx_cp.astype(cp.int64, copy=False),
    )
    row_sorted_cp = row_idx_cp[order_cp].astype(cp.int32, copy=False)
    sat_sorted_cp = sat_idx_cp[order_cp].astype(cp.int32, copy=False)
    dest_cp = (
        row_write_offsets_cp[row_sorted_cp].astype(cp.int64, copy=False)
        + rank_cp.astype(cp.int64, copy=False)
    )
    sat_out_cp[dest_cp] = sat_sorted_cp
    row_write_offsets_cp += cp.bincount(
        row_idx_cp.astype(cp.int32, copy=False),
        minlength=int(row_count),
    ).astype(cp.int64, copy=False)


def _slice_csr_rows_cp(
    row_ptr_cp: Any,
    value_cp: Any,
    selected_rows_cp: Any,
) -> tuple[Any, Any]:
    selected_rows_cp = _to_cupy_array(selected_rows_cp, dtype=cp.int32, copy=False).reshape(-1)
    row_count = int(selected_rows_cp.size)
    out_row_ptr_cp = cp.zeros(row_count + 1, dtype=cp.int64)
    if row_count <= 0:
        return out_row_ptr_cp, cp.empty(0, dtype=value_cp.dtype)

    starts_cp = row_ptr_cp[selected_rows_cp].astype(cp.int64, copy=False)
    stops_cp = row_ptr_cp[selected_rows_cp + np.int32(1)].astype(cp.int64, copy=False)
    lengths_cp = (stops_cp - starts_cp).astype(cp.int64, copy=False)
    out_row_ptr_cp[1:] = cp.cumsum(lengths_cp, dtype=cp.int64)
    total = int(out_row_ptr_cp[-1].item())
    if total <= 0:
        return out_row_ptr_cp, cp.empty(0, dtype=value_cp.dtype)

    dest_idx_cp = cp.arange(total, dtype=cp.int64)
    row_ids_cp = cp.searchsorted(
        out_row_ptr_cp[1:],
        dest_idx_cp,
        side="right",
    ).astype(cp.int32, copy=False)
    src_idx_cp = starts_cp[row_ids_cp].astype(cp.int64, copy=False) + (
        dest_idx_cp - out_row_ptr_cp[row_ids_cp].astype(cp.int64, copy=False)
    )
    return out_row_ptr_cp, value_cp[src_idx_cp]


def _build_boresight_sparse_restrictions_slab_cp(
    library: GpuSatelliteLinkSelectionLibrary,
    *,
    time_start: int,
    time_stop: int,
    sky_start: int = 0,
    sky_stop: int | None = None,
    working_memory_budget_bytes: int | None = None,
) -> dict[str, Any]:
    time_start_i = int(time_start)
    time_stop_i = int(time_stop)
    sky_start_i = int(sky_start)
    sky_stop_i = int(library.boresight_sky_count if sky_stop is None else sky_stop)
    slab_time_count = time_stop_i - time_start_i
    slab_sky_count = sky_stop_i - sky_start_i
    row_count = max(slab_time_count * slab_sky_count, 0)
    if row_count <= 0:
        raise ValueError("time/sky slab must be non-empty when building boresight restrictions.")

    if not library.boresight_active:
        empty_row_ptr = cp.zeros(row_count + 1, dtype=cp.int64)
        empty_sat_idx = cp.empty(0, dtype=cp.int32)
        return {
            "theta1_row_ptr": empty_row_ptr,
            "theta1_sat_idx": empty_sat_idx,
            "theta2_row_ptr": empty_row_ptr.copy(),
            "theta2_sat_idx": empty_sat_idx.copy(),
        }

    ras_topo_cp = library.ras_topo_cp[time_start_i:time_stop_i]
    pointing_az_cp = library.boresight_pointing_az_cp[time_start_i:time_stop_i, sky_start_i:sky_stop_i]
    pointing_el_cp = library.boresight_pointing_el_cp[time_start_i:time_stop_i, sky_start_i:sky_stop_i]
    sat_az_rad_cp = cp.deg2rad(
        cp.remainder(
            ras_topo_cp[..., 0].astype(cp.float32, copy=False),
            cp.float32(360.0),
        )
    ).astype(cp.float32, copy=False)
    sat_el_deg_cp = ras_topo_cp[..., 1].astype(cp.float32, copy=False)
    sat_el_rad_cp = cp.deg2rad(sat_el_deg_cp).astype(cp.float32, copy=False)
    tel_az_rad_cp = cp.deg2rad(
        cp.remainder(pointing_az_cp.astype(cp.float32, copy=False), cp.float32(360.0))
    ).astype(cp.float32, copy=False)
    tel_el_rad_cp = cp.deg2rad(pointing_el_cp.astype(cp.float32, copy=False)).astype(cp.float32, copy=False)
    tel_sin_cp = cp.sin(tel_el_rad_cp).astype(cp.float32, copy=False)
    tel_cos_cp = cp.cos(tel_el_rad_cp).astype(cp.float32, copy=False)
    theta1_cos_threshold = (
        None
        if library.boresight_theta1_deg_value is None
        else np.float32(np.cos(np.deg2rad(float(library.boresight_theta1_deg_value))))
    )
    theta2_cos_threshold = (
        None
        if library.boresight_theta2_deg_value is None
        else np.float32(np.cos(np.deg2rad(float(library.boresight_theta2_deg_value))))
    )
    row_counts_theta1_cp = cp.zeros((row_count,), dtype=cp.int64)
    row_counts_theta2_cp = cp.zeros((row_count,), dtype=cp.int64)
    sat_chunk = max(1, min(int(GPU_DIRECT_BORESIGHT_SAT_CHUNK), int(library.sat_count)))
    theta1_row_parts: list[Any] = []
    theta1_sat_parts: list[Any] = []
    theta2_row_parts: list[Any] = []
    theta2_sat_parts: list[Any] = []
    theta1_total = 0
    theta2_total = 0
    sat_chunk = max(1, min(int(GPU_DIRECT_BORESIGHT_SAT_CHUNK), int(library.sat_count)))
    if working_memory_budget_bytes is not None and sat_chunk > 1:
        bytes_per_sat_est = max(int(slab_time_count) * int(slab_sky_count) * 24, 1)
        budget_limited_chunk = max(
            1,
            int(int(working_memory_budget_bytes) // max(bytes_per_sat_est, 1)),
        )
        sat_chunk = max(1, min(sat_chunk, budget_limited_chunk))
    for sat_start in range(0, int(library.sat_count), sat_chunk):
        sat_stop = min(sat_start + sat_chunk, int(library.sat_count))
        sat_az_chunk_cp = sat_az_rad_cp[:, sat_start:sat_stop]
        sat_el_chunk_cp = sat_el_rad_cp[:, sat_start:sat_stop]
        sat_sin_chunk_cp = cp.sin(sat_el_chunk_cp[:, None, :]).astype(cp.float32, copy=False)
        sat_cos_chunk_cp = cp.cos(sat_el_chunk_cp[:, None, :]).astype(cp.float32, copy=False)
        cos_daz_cp = cp.cos(
            tel_az_rad_cp[:, :, None] - sat_az_chunk_cp[:, None, :]
        ).astype(cp.float32, copy=False)
        cos_gamma_cp = (
            tel_sin_cp[:, :, None] * sat_sin_chunk_cp
            + tel_cos_cp[:, :, None] * sat_cos_chunk_cp * cos_daz_cp
        ).astype(cp.float32, copy=False)
        cos_gamma_cp = cp.clip(cos_gamma_cp, cp.float32(-1.0), cp.float32(1.0))
        above_horizon_cp = (
            sat_el_deg_cp[:, None, sat_start:sat_stop] > cp.float32(0.0)
        )
        theta1_mask_cp = cp.zeros_like(cos_gamma_cp, dtype=cp.bool_)
        theta2_mask_cp = cp.zeros_like(cos_gamma_cp, dtype=cp.bool_)
        if theta1_cos_threshold is not None:
            theta1_mask_cp = above_horizon_cp & (
                cos_gamma_cp > cp.float32(theta1_cos_threshold)
            )
        if theta2_cos_threshold is not None:
            theta2_mask_cp = above_horizon_cp & (
                cos_gamma_cp > cp.float32(theta2_cos_threshold)
            )
            if theta1_cos_threshold is not None:
                theta2_mask_cp &= ~theta1_mask_cp
        true_idx_cp = cp.nonzero(theta1_mask_cp.reshape(-1))[0].astype(cp.int64, copy=False)
        if int(true_idx_cp.size) > 0:
            theta1_row_idx_cp = (true_idx_cp // np.int64(sat_stop - sat_start)).astype(cp.int32, copy=False)
            theta1_sat_chunk_cp = (
                (true_idx_cp % np.int64(sat_stop - sat_start)).astype(cp.int32, copy=False)
                + np.int32(sat_start)
            ).astype(cp.int32, copy=False)
            theta1_total += int(theta1_sat_chunk_cp.size)
            row_counts_theta1_cp += cp.bincount(
                theta1_row_idx_cp,
                minlength=row_count,
            ).astype(cp.int64, copy=False)
            theta1_row_parts.append(theta1_row_idx_cp)
            theta1_sat_parts.append(theta1_sat_chunk_cp)
        true_idx_cp = cp.nonzero(theta2_mask_cp.reshape(-1))[0].astype(cp.int64, copy=False)
        if int(true_idx_cp.size) > 0:
            theta2_row_idx_cp = (true_idx_cp // np.int64(sat_stop - sat_start)).astype(cp.int32, copy=False)
            theta2_sat_chunk_cp = (
                (true_idx_cp % np.int64(sat_stop - sat_start)).astype(cp.int32, copy=False)
                + np.int32(sat_start)
            ).astype(cp.int32, copy=False)
            theta2_total += int(theta2_sat_chunk_cp.size)
            row_counts_theta2_cp += cp.bincount(
                theta2_row_idx_cp,
                minlength=row_count,
            ).astype(cp.int64, copy=False)
            theta2_row_parts.append(theta2_row_idx_cp)
            theta2_sat_parts.append(theta2_sat_chunk_cp)

    theta1_row_ptr_cp = cp.empty(row_count + 1, dtype=cp.int64)
    theta1_row_ptr_cp[0] = cp.int64(0)
    theta1_row_ptr_cp[1:] = cp.cumsum(row_counts_theta1_cp, dtype=cp.int64)
    theta2_row_ptr_cp = cp.empty(row_count + 1, dtype=cp.int64)
    theta2_row_ptr_cp[0] = cp.int64(0)
    theta2_row_ptr_cp[1:] = cp.cumsum(row_counts_theta2_cp, dtype=cp.int64)
    theta1_sat_idx_cp = cp.empty(int(theta1_total), dtype=cp.int32)
    theta2_sat_idx_cp = cp.empty(int(theta2_total), dtype=cp.int32)
    theta1_write_offsets_cp = theta1_row_ptr_cp[:-1].copy()
    theta2_write_offsets_cp = theta2_row_ptr_cp[:-1].copy()

    for row_idx_cp, sat_idx_cp in zip(theta1_row_parts, theta1_sat_parts, strict=False):
        if int(theta1_sat_idx_cp.size) > 0 and int(sat_idx_cp.size) > 0:
            _scatter_sparse_row_sat_chunk_cp(
                row_idx_cp=row_idx_cp,
                sat_idx_cp=sat_idx_cp,
                row_count=row_count,
                row_write_offsets_cp=theta1_write_offsets_cp,
                sat_out_cp=theta1_sat_idx_cp,
            )
    for row_idx_cp, sat_idx_cp in zip(theta2_row_parts, theta2_sat_parts, strict=False):
        if int(theta2_sat_idx_cp.size) > 0 and int(sat_idx_cp.size) > 0:
            _scatter_sparse_row_sat_chunk_cp(
                row_idx_cp=row_idx_cp,
                sat_idx_cp=sat_idx_cp,
                row_count=row_count,
                row_write_offsets_cp=theta2_write_offsets_cp,
                sat_out_cp=theta2_sat_idx_cp,
            )

    return {
        "theta1_row_ptr": theta1_row_ptr_cp,
        "theta1_sat_idx": theta1_sat_idx_cp,
        "theta2_row_ptr": theta2_row_ptr_cp,
        "theta2_sat_idx": theta2_sat_idx_cp,
    }


def _finalize_boresight_link_selection_library_cupy(
    library: GpuSatelliteLinkSelectionLibrary,
    *,
    candidate_cell_cp: Any,
    candidate_sat_cp: Any,
    candidate_alpha_cp: Any,
    candidate_beta_cp: Any,
    segment_start_cp: Any,
    segment_end_cp: Any,
    return_device: bool,
) -> dict[str, Any]:
    _ensure_boresight_masks_cp(library)
    sky_count = int(library.boresight_sky_count)
    assignments_cp = cp.full((library.time_count, sky_count, library.cell_count, library.n_links), -1, dtype=cp.int32)
    sat_count_cp = cp.zeros((library.time_count, sky_count, library.sat_count), dtype=cp.int32)
    eligible_count_cp = cp.zeros((library.time_count, sky_count, library.sat_count), dtype=cp.int32)
    cell_count_cp = cp.zeros((library.time_count, sky_count, library.cell_count), dtype=cp.int32)

    sat_azimuth_cp = cp.empty((1, 1, 1, 1), dtype=cp.float32)
    sat_elevation_cp = cp.empty((1, 1, 1, 1), dtype=cp.float32)
    sat_alpha_cp = cp.empty((1, 1, 1, 1), dtype=cp.float32)
    sat_beta_cp = cp.empty((1, 1, 1, 1), dtype=cp.float32)
    sat_belt_cp = cp.empty((1, 1, 1, 1), dtype=cp.int16)
    cone_ok_cp = cp.empty((1, 1, 1, 1), dtype=cp.bool_)
    if library.include_payload:
        sat_azimuth_cp = cp.full(assignments_cp.shape, cp.nan, dtype=cp.float32)
        sat_elevation_cp = cp.full(assignments_cp.shape, cp.nan, dtype=cp.float32)
        sat_alpha_cp = cp.full(assignments_cp.shape, cp.nan, dtype=cp.float32)
        sat_beta_cp = cp.full(assignments_cp.shape, cp.nan, dtype=cp.float32)
        sat_belt_cp = cp.full(assignments_cp.shape, np.int16(-1), dtype=cp.int16)
        cone_ok_cp = cp.zeros(assignments_cp.shape, dtype=cp.bool_)
    elif library.include_counts and library.use_cone_check:
        cone_ok_cp = cp.zeros(assignments_cp.shape, dtype=cp.bool_)

    ras_azimuth_cp = cp.empty((1, 1), dtype=cp.float32)
    ras_elevation_cp = cp.empty((1, 1), dtype=cp.float32)
    if library.ras_topo_cp is not None:
        ras_azimuth_cp = cp.remainder(library.ras_topo_cp[..., 0], cp.float32(360.0)).astype(cp.float32, copy=False)
        ras_elevation_cp = library.ras_topo_cp[..., 1].astype(cp.float32, copy=False)

    theta2_cell_mask_cp = library.boresight_theta2_cell_mask_cp
    if theta2_cell_mask_cp is None:
        theta2_cell_mask_cp = cp.zeros((library.cell_count,), dtype=cp.bool_)

    grid = (library.time_count, sky_count, 1)
    block = (1, 1, 1)
    _greedy_assign_sorted_candidates_boresight_kernel[grid, block](
        cuda.as_cuda_array(segment_start_cp),
        cuda.as_cuda_array(segment_end_cp),
        cuda.as_cuda_array(candidate_cell_cp),
        cuda.as_cuda_array(candidate_sat_cp),
        cuda.as_cuda_array(candidate_alpha_cp),
        cuda.as_cuda_array(candidate_beta_cp),
        cuda.as_cuda_array(ras_azimuth_cp),
        cuda.as_cuda_array(ras_elevation_cp),
        cuda.as_cuda_array(library.sat_belt_id_cp),
        cuda.as_cuda_array(library.sat_beta_max_cp),
        cuda.as_cuda_array(library.boresight_full_mask_cp),
        cuda.as_cuda_array(library.boresight_partial_mask_cp),
        cuda.as_cuda_array(theta2_cell_mask_cp),
        int(library.cell_count),
        int(library.n_links),
        int(library.n_beam),
        bool(library.use_cone_check),
        bool(library.include_payload),
        bool(library.include_counts),
        bool(library._candidate_alpha_parts is not None and library._candidate_beta_parts is not None),
        np.float32(library.beta_tol_deg),
        cuda.as_cuda_array(cell_count_cp),
        cuda.as_cuda_array(sat_count_cp),
        cuda.as_cuda_array(eligible_count_cp),
        cuda.as_cuda_array(assignments_cp),
        cuda.as_cuda_array(cone_ok_cp),
        cuda.as_cuda_array(sat_azimuth_cp),
        cuda.as_cuda_array(sat_elevation_cp),
        cuda.as_cuda_array(sat_alpha_cp),
        cuda.as_cuda_array(sat_beta_cp),
        cuda.as_cuda_array(sat_belt_cp),
    )
    result_cp: dict[str, Any] = {"assignments": assignments_cp}
    if library.include_payload:
        result_cp["sat_azimuth"] = sat_azimuth_cp
        result_cp["sat_elevation"] = sat_elevation_cp
        result_cp["sat_alpha"] = sat_alpha_cp
        result_cp["sat_beta"] = sat_beta_cp
        result_cp["sat_belt_id"] = sat_belt_cp
        result_cp["cone_ok"] = cone_ok_cp
    elif library.include_counts and library.use_cone_check:
        result_cp["cone_ok"] = cone_ok_cp
    if library.include_counts:
        result_cp["sat_beam_counts_demand"] = sat_count_cp
        result_cp["sat_beam_counts_eligible"] = eligible_count_cp
    if library.include_eligible_mask and library.eligible_mask_cp is not None:
        eligible_cp = cp.broadcast_to(
            library.eligible_mask_cp[:, None, :, :],
            (library.time_count, sky_count, library.cell_count, library.sat_count),
        ).copy()
        eligible_cp &= ~library.boresight_full_mask_cp[:, :, None, :]
        if library.boresight_theta2_cell_mask_cp is not None:
            eligible_cp &= ~(
                library.boresight_partial_mask_cp[:, :, None, :]
                & library.boresight_theta2_cell_mask_cp[None, None, :, None]
            )
        result_cp["sat_eligible_mask"] = eligible_cp

    if return_device:
        return _device_result_dict_from_cupy(result_cp)
    return {key: copy_device_to_host(value) for key, value in result_cp.items()}


def _count_selected_assignments_cp(
    assignments_cp: Any,
    *,
    sat_count: int,
    mask_cp: Any | None = None,
) -> Any:
    boresight_active = assignments_cp.ndim == 4
    time_count = int(assignments_cp.shape[0])
    sky_count = int(assignments_cp.shape[1]) if boresight_active else 1
    base_mask_cp = assignments_cp >= np.int32(0)
    if mask_cp is not None:
        base_mask_cp &= cp.asarray(mask_cp, dtype=cp.bool_)
    pos = cp.nonzero(base_mask_cp)
    if int(pos[0].size) <= 0:
        return (
            cp.zeros((time_count, sky_count, sat_count), dtype=cp.int32)
            if boresight_active
            else cp.zeros((time_count, sat_count), dtype=cp.int32)
        )
    sat_sel_cp = assignments_cp[pos].astype(cp.int32, copy=False)
    t_sel_cp = pos[0].astype(cp.int32, copy=False)
    if boresight_active:
        sky_sel_cp = pos[1].astype(cp.int32, copy=False)
        key_cp = (
            (
                t_sel_cp * np.int32(int(sky_count))
                + sky_sel_cp
            ) * np.int32(int(sat_count))
            + sat_sel_cp
        ).astype(cp.int32, copy=False)
        counts_cp = cp.bincount(
            key_cp,
            minlength=int(time_count) * int(sky_count) * int(sat_count),
        ).astype(cp.int32, copy=False)
        return counts_cp.reshape((time_count, sky_count, int(sat_count)))
    key_cp = (
        t_sel_cp * np.int32(int(sat_count)) + sat_sel_cp
    ).astype(cp.int32, copy=False)
    counts_cp = cp.bincount(
        key_cp,
        minlength=int(time_count) * int(sat_count),
    ).astype(cp.int32, copy=False)
    return counts_cp.reshape((time_count, int(sat_count)))


def _apply_sparse_rows_to_eligible_mask_cp(
    eligible_cp: Any,
    *,
    row_ptr_cp: Any,
    sat_idx_cp: Any,
    theta2_cell_mask_cp: Any | None = None,
) -> None:
    row_idx_cp, sat_sel_cp = _csr_row_sat_pairs_cp(row_ptr_cp, sat_idx_cp)
    if int(sat_sel_cp.size) <= 0:
        return
    sky_count = int(eligible_cp.shape[1])
    t_sel_cp = (
        row_idx_cp.astype(cp.int32, copy=False) // np.int32(int(sky_count))
    ).astype(cp.int32, copy=False)
    sky_sel_cp = (
        row_idx_cp.astype(cp.int32, copy=False) - t_sel_cp * np.int32(int(sky_count))
    ).astype(cp.int32, copy=False)
    if theta2_cell_mask_cp is None:
        eligible_cp[t_sel_cp, sky_sel_cp, :, sat_sel_cp.astype(cp.int32, copy=False)] = False
        return
    cell_ids_cp = cp.nonzero(
        cp.asarray(theta2_cell_mask_cp, dtype=cp.bool_)
    )[0].astype(cp.int32, copy=False)
    if int(cell_ids_cp.size) <= 0:
        return
    eligible_cp[
        t_sel_cp[:, None],
        sky_sel_cp[:, None],
        cell_ids_cp[None, :],
        sat_sel_cp.astype(cp.int32, copy=False)[:, None],
    ] = False


def _build_boresight_eligible_mask_slab_cp(
    library: GpuSatelliteLinkSelectionLibrary,
    *,
    time_start: int,
    time_stop: int,
    boresight_sparse_slab: dict[str, Any],
) -> Any | None:
    if not library.include_eligible_mask or library.eligible_mask_cp is None:
        return None
    time_start_i = int(time_start)
    time_stop_i = int(time_stop)
    slab_time_count = max(time_stop_i - time_start_i, 0)
    sky_count = int(boresight_sparse_slab["theta1_row_ptr"].shape[0] - 1) // max(slab_time_count, 1)
    eligible_cp = cp.broadcast_to(
        library.eligible_mask_cp[time_start_i:time_stop_i, None, :, :],
        (
            slab_time_count,
            int(sky_count),
            int(library.cell_count),
            int(library.sat_count),
        ),
    ).copy()
    _apply_sparse_rows_to_eligible_mask_cp(
        eligible_cp,
        row_ptr_cp=boresight_sparse_slab["theta1_row_ptr"],
        sat_idx_cp=boresight_sparse_slab["theta1_sat_idx"],
        theta2_cell_mask_cp=None,
    )
    if library.boresight_theta2_cell_mask_cp is not None:
        _apply_sparse_rows_to_eligible_mask_cp(
            eligible_cp,
            row_ptr_cp=boresight_sparse_slab["theta2_row_ptr"],
            sat_idx_cp=boresight_sparse_slab["theta2_sat_idx"],
            theta2_cell_mask_cp=library.boresight_theta2_cell_mask_cp,
        )
    return eligible_cp


def _reconstruct_boresight_selection_from_beam_slab_cp(
    *,
    beam_idx_cp: Any,
    beam_alpha_rad_cp: Any,
    beam_beta_rad_cp: Any,
    output_sat_indices_cp: Any,
    cell_count: int,
    n_links: int,
) -> dict[str, Any]:
    time_count = int(beam_idx_cp.shape[0])
    sky_count = int(beam_idx_cp.shape[1])
    shape = (time_count, sky_count, int(cell_count), int(n_links))
    assignments_cp = cp.full(shape, -1, dtype=cp.int32)
    cone_ok_cp = cp.zeros(shape, dtype=cp.bool_)
    selected_alpha_rad_cp = cp.full(shape, cp.nan, dtype=cp.float32)
    selected_beta_rad_cp = cp.full(shape, cp.nan, dtype=cp.float32)

    valid_pos = cp.nonzero(beam_idx_cp >= np.int32(0))
    if int(valid_pos[0].size) > 0:
        beam_id_cp = beam_idx_cp[valid_pos].astype(cp.int32, copy=False)
        cell_sel_cp = (beam_id_cp // np.int32(int(n_links))).astype(cp.int32, copy=False)
        link_sel_cp = (
            beam_id_cp - cell_sel_cp * np.int32(int(n_links))
        ).astype(cp.int32, copy=False)
        sat_sel_cp = output_sat_indices_cp[
            valid_pos[2].astype(cp.int32, copy=False)
        ].astype(cp.int32, copy=False)
        t_sel_cp = valid_pos[0].astype(cp.int32, copy=False)
        sky_sel_cp = valid_pos[1].astype(cp.int32, copy=False)
        assignments_cp[t_sel_cp, sky_sel_cp, cell_sel_cp, link_sel_cp] = sat_sel_cp
        cone_ok_cp[t_sel_cp, sky_sel_cp, cell_sel_cp, link_sel_cp] = True
        selected_alpha_rad_cp[t_sel_cp, sky_sel_cp, cell_sel_cp, link_sel_cp] = (
            beam_alpha_rad_cp[valid_pos].astype(cp.float32, copy=False)
        )
        selected_beta_rad_cp[t_sel_cp, sky_sel_cp, cell_sel_cp, link_sel_cp] = (
            beam_beta_rad_cp[valid_pos].astype(cp.float32, copy=False)
        )

    return {
        "assignments": assignments_cp,
        "cone_ok": cone_ok_cp,
        "selected_alpha_rad": selected_alpha_rad_cp,
        "selected_beta_rad": selected_beta_rad_cp,
    }


def _package_link_selection_result_cp(
    library: GpuSatelliteLinkSelectionLibrary,
    *,
    selection_cp: dict[str, Any],
    eligible_mask_cp: Any | None,
    return_device: bool,
) -> dict[str, Any]:
    assignments_cp = selection_cp["assignments"]
    cone_ok_cp = selection_cp["cone_ok"].astype(cp.bool_, copy=False)
    selected_alpha_rad_cp = selection_cp["selected_alpha_rad"].astype(cp.float32, copy=False)
    selected_beta_rad_cp = selection_cp["selected_beta_rad"].astype(cp.float32, copy=False)
    shape = tuple(assignments_cp.shape)
    boresight_active = assignments_cp.ndim == 4

    result_cp: dict[str, Any] = {"assignments": assignments_cp}
    valid_pos = cp.nonzero(assignments_cp >= np.int32(0))
    valid_count = int(valid_pos[0].size)
    sat_sel_cp = (
        assignments_cp[valid_pos].astype(cp.int32, copy=False)
        if valid_count > 0
        else cp.empty((0,), dtype=cp.int32)
    )

    if library.include_payload:
        sat_azimuth_cp = cp.full(shape, cp.nan, dtype=cp.float32)
        sat_elevation_cp = cp.full(shape, cp.nan, dtype=cp.float32)
        sat_alpha_cp = cp.full(shape, cp.nan, dtype=cp.float32)
        sat_beta_cp = cp.full(shape, cp.nan, dtype=cp.float32)
        sat_belt_cp = cp.full(shape, np.int16(-1), dtype=cp.int16)
        if valid_count > 0:
            ras_topo_cp = _to_cupy_array(library.ras_topo_cp, dtype=cp.float32)
            t_sel_cp = valid_pos[0].astype(cp.int32, copy=False)
            sat_az_sel_cp = cp.remainder(
                ras_topo_cp[t_sel_cp, sat_sel_cp, 0].astype(cp.float32, copy=False),
                cp.float32(360.0),
            ).astype(cp.float32, copy=False)
            sat_el_sel_cp = ras_topo_cp[t_sel_cp, sat_sel_cp, 1].astype(cp.float32, copy=False)
            alpha_sel_cp = (
                selected_alpha_rad_cp[valid_pos] * cp.float32(180.0 / np.pi)
            ).astype(cp.float32, copy=False)
            beta_sel_cp = (
                selected_beta_rad_cp[valid_pos] * cp.float32(180.0 / np.pi)
            ).astype(cp.float32, copy=False)
            alpha_sel_cp = (
                cp.rint(alpha_sel_cp * cp.float32(1.0e5)) / cp.float32(1.0e5)
            ).astype(cp.float32, copy=False)
            beta_sel_cp = (
                cp.rint(beta_sel_cp * cp.float32(1.0e5)) / cp.float32(1.0e5)
            ).astype(cp.float32, copy=False)
            ok_sel_cp = cone_ok_cp[valid_pos].astype(cp.bool_, copy=False)
            ok_pos_cp = cp.nonzero(ok_sel_cp)[0].astype(cp.int64, copy=False)
            if int(ok_pos_cp.size) > 0:
                t_ok_cp = t_sel_cp[ok_pos_cp].astype(cp.int32, copy=False)
                sat_ok_cp = sat_sel_cp[ok_pos_cp].astype(cp.int32, copy=False)
                if assignments_cp.ndim == 4:
                    sky_ok_cp = valid_pos[1][ok_pos_cp].astype(cp.int32, copy=False)
                    cell_ok_cp = valid_pos[2][ok_pos_cp].astype(cp.int32, copy=False)
                    link_ok_cp = valid_pos[3][ok_pos_cp].astype(cp.int32, copy=False)
                    sat_azimuth_cp[t_ok_cp, sky_ok_cp, cell_ok_cp, link_ok_cp] = sat_az_sel_cp[ok_pos_cp]
                    sat_elevation_cp[t_ok_cp, sky_ok_cp, cell_ok_cp, link_ok_cp] = sat_el_sel_cp[ok_pos_cp]
                    sat_alpha_cp[t_ok_cp, sky_ok_cp, cell_ok_cp, link_ok_cp] = alpha_sel_cp[ok_pos_cp]
                    sat_beta_cp[t_ok_cp, sky_ok_cp, cell_ok_cp, link_ok_cp] = beta_sel_cp[ok_pos_cp]
                    sat_belt_cp[t_ok_cp, sky_ok_cp, cell_ok_cp, link_ok_cp] = library.sat_belt_id_cp[
                        sat_ok_cp
                    ].astype(cp.int16, copy=False)
                else:
                    cell_ok_cp = valid_pos[1][ok_pos_cp].astype(cp.int32, copy=False)
                    link_ok_cp = valid_pos[2][ok_pos_cp].astype(cp.int32, copy=False)
                    sat_azimuth_cp[t_ok_cp, cell_ok_cp, link_ok_cp] = sat_az_sel_cp[ok_pos_cp]
                    sat_elevation_cp[t_ok_cp, cell_ok_cp, link_ok_cp] = sat_el_sel_cp[ok_pos_cp]
                    sat_alpha_cp[t_ok_cp, cell_ok_cp, link_ok_cp] = alpha_sel_cp[ok_pos_cp]
                    sat_beta_cp[t_ok_cp, cell_ok_cp, link_ok_cp] = beta_sel_cp[ok_pos_cp]
                    sat_belt_cp[t_ok_cp, cell_ok_cp, link_ok_cp] = library.sat_belt_id_cp[
                        sat_ok_cp
                    ].astype(cp.int16, copy=False)
        result_cp["sat_azimuth"] = sat_azimuth_cp
        result_cp["sat_elevation"] = sat_elevation_cp
        result_cp["sat_alpha"] = sat_alpha_cp
        result_cp["sat_beta"] = sat_beta_cp
        result_cp["sat_belt_id"] = sat_belt_cp
        result_cp["cone_ok"] = cone_ok_cp
    elif library.include_counts and library.use_cone_check:
        result_cp["cone_ok"] = cone_ok_cp

    if library.include_counts:
        demand_cp = _count_selected_assignments_cp(
            assignments_cp,
            sat_count=int(library.sat_count),
            mask_cp=None,
        )
        eligible_cp = demand_cp if not library.use_cone_check else _count_selected_assignments_cp(
            assignments_cp,
            sat_count=int(library.sat_count),
            mask_cp=cone_ok_cp,
        )
        result_cp["sat_beam_counts_demand"] = demand_cp
        result_cp["sat_beam_counts_eligible"] = eligible_cp

    if library.boresight_active:
        if library.include_eligible_mask and eligible_mask_cp is not None:
            result_cp["sat_eligible_mask"] = eligible_mask_cp
        if return_device:
            return _device_result_dict_from_cupy(result_cp)
        return {key: copy_device_to_host(value) for key, value in result_cp.items()}

    if return_device:
        if library.include_eligible_mask:
            result_cp = _attach_gpu_eligible_mask_outputs(
                result_cp,
                dense_mask_cp=library.eligible_mask_cp,
                eligible_time_parts=library._eligible_time_parts,
                eligible_cell_parts=library._eligible_cell_parts,
                eligible_sat_parts=library._eligible_sat_parts,
                time_count=library.time_count,
                cell_count=library.cell_count,
                sat_count=library.sat_count,
                encoding=library.eligible_mask_encoding_name,
                return_device=True,
            )
        return _device_result_dict_from_cupy(result_cp)

    result_host = {key: copy_device_to_host(value) for key, value in result_cp.items()}
    if library.include_eligible_mask:
        result_host = _attach_gpu_eligible_mask_outputs(
            result_host,
            dense_mask_cp=library.eligible_mask_cp,
            eligible_time_parts=library._eligible_time_parts,
            eligible_cell_parts=library._eligible_cell_parts,
            eligible_sat_parts=library._eligible_sat_parts,
            time_count=library.time_count,
            cell_count=library.cell_count,
            sat_count=library.sat_count,
            encoding=library.eligible_mask_encoding_name,
            return_device=False,
        )
    return result_host


def _finalize_staged_boresight_link_selection_library_cupy(
    library: GpuSatelliteLinkSelectionLibrary,
    *,
    return_device: bool,
) -> dict[str, Any]:
    if library._candidate_alpha_parts is None or library._candidate_beta_parts is None:
        raise RuntimeError(
            "Staged boresight link-library finalization requires stored candidate "
            "alpha/beta geometry. Rebuild the library with sat_azel available."
        )

    sat_output_indices_cp = cp.arange(int(library.sat_count), dtype=cp.int32)
    sat_output_index_cp = sat_output_indices_cp.copy()
    sat_beta_max_rad_cp = library.sat_beta_max_rad_cp
    slab_plan = _plan_direct_finalize_slabs(
        library,
        sat_output_count=int(library.sat_count),
        include_diagnostics=False,
        mode="cell_center",
        working_memory_budget_bytes=None,
        return_device=return_device,
    )
    sky_total = int(library.boresight_sky_count)
    shape = (int(library.time_count), sky_total, int(library.cell_count), int(library.n_links))
    assignments_cp = cp.full(shape, -1, dtype=cp.int32)
    cone_ok_cp = cp.zeros(shape, dtype=cp.bool_)
    selected_alpha_rad_cp = cp.full(shape, cp.nan, dtype=cp.float32)
    selected_beta_rad_cp = cp.full(shape, cp.nan, dtype=cp.float32)
    eligible_mask_out_cp = (
        cp.zeros((int(library.time_count), sky_total, int(library.cell_count), int(library.sat_count)), dtype=cp.bool_)
        if library.include_eligible_mask and library.eligible_mask_cp is not None
        else None
    )

    time_chunk_size = int(slab_plan["time_chunk_size"])
    sky_chunk_size = int(slab_plan["sky_chunk_size"])
    beta_tol_rad = np.float32(float(library.beta_tol_deg) * np.pi / 180.0)
    for time_start in range(0, int(library.time_count), time_chunk_size):
        time_stop = min(time_start + time_chunk_size, int(library.time_count))
        first_pass_slab = _finalize_link_selection_library_minimal_slab_cp(
            library,
            time_start=time_start,
            time_stop=time_stop,
            force_ordinary=True,
            selector_backend=GPU_DIRECT_SELECTOR_BACKEND_FAST,
            working_memory_budget_bytes=slab_plan["working_memory_budget_bytes"],
            debug_direct_epfd=False,
        )
        direct_candidate_slab = _direct_candidate_slab_cp(
            library,
            time_start=time_start,
            time_stop=time_stop,
        )
        for sky_start in range(0, sky_total, sky_chunk_size):
            sky_stop = min(sky_start + sky_chunk_size, sky_total)
            boresight_sparse_slab = _build_boresight_sparse_restrictions_slab_cp(
                library,
                time_start=time_start,
                time_stop=time_stop,
                sky_start=sky_start,
                sky_stop=sky_stop,
                working_memory_budget_bytes=slab_plan["working_memory_budget_bytes"],
            )
            beam_result_cp = _finalize_direct_epfd_beams_staged_slab_cp(
                library,
                first_pass_slab=first_pass_slab,
                direct_candidate_slab=direct_candidate_slab,
                boresight_sparse_slab=boresight_sparse_slab,
                sat_output_index_cp=sat_output_index_cp,
                output_sat_indices_cp=sat_output_indices_cp,
                sat_output_count=int(library.sat_count),
                ras_cell_index=None,
                ras_elevation_deg_cp=None,
                ras_alpha_rad_cp=None,
                ras_beta_rad_cp=None,
                ras_sat_axis_is_compact=False,
                sat_beta_max_rad_cp=sat_beta_max_rad_cp,
                beta_tol_rad=beta_tol_rad,
                use_ras_guard=False,
                ras_guard_cos=np.float32(0.0),
                mode="cell_center",
                include_diagnostics=False,
                include_full_sat_beam_counts_used=False,
                working_memory_budget_bytes=slab_plan["working_memory_budget_bytes"],
                debug_direct_epfd=False,
            )
            slab_selection_cp = _reconstruct_boresight_selection_from_beam_slab_cp(
                beam_idx_cp=beam_result_cp["beam_idx"],
                beam_alpha_rad_cp=beam_result_cp["beam_alpha_rad"],
                beam_beta_rad_cp=beam_result_cp["beam_beta_rad"],
                output_sat_indices_cp=sat_output_indices_cp,
                cell_count=int(library.cell_count),
                n_links=int(library.n_links),
            )
            assignments_cp[time_start:time_stop, sky_start:sky_stop, :, :] = slab_selection_cp["assignments"]
            cone_ok_cp[time_start:time_stop, sky_start:sky_stop, :, :] = slab_selection_cp["cone_ok"]
            selected_alpha_rad_cp[time_start:time_stop, sky_start:sky_stop, :, :] = slab_selection_cp["selected_alpha_rad"]
            selected_beta_rad_cp[time_start:time_stop, sky_start:sky_stop, :, :] = slab_selection_cp["selected_beta_rad"]
            if eligible_mask_out_cp is not None:
                eligible_mask_out_cp[time_start:time_stop, sky_start:sky_stop, :, :] = _build_boresight_eligible_mask_slab_cp(
                    library,
                    time_start=time_start,
                    time_stop=time_stop,
                    boresight_sparse_slab=boresight_sparse_slab,
                )

    return _package_link_selection_result_cp(
        library,
        selection_cp={
            "assignments": assignments_cp,
            "cone_ok": cone_ok_cp,
            "selected_alpha_rad": selected_alpha_rad_cp,
            "selected_beta_rad": selected_beta_rad_cp,
        },
        eligible_mask_cp=eligible_mask_out_cp,
        return_device=return_device,
    )


def _finalize_link_selection_library_minimal_slab_cp(
    library: GpuSatelliteLinkSelectionLibrary,
    *,
    time_start: int,
    time_stop: int,
    sky_start: int = 0,
    sky_stop: int | None = None,
    force_ordinary: bool = False,
    selector_backend: str = GPU_DIRECT_SELECTOR_BACKEND_FAST,
    working_memory_budget_bytes: int | None = None,
    debug_direct_epfd: bool = False,
) -> dict[str, Any]:
    slab_time_count = int(time_stop) - int(time_start)
    if slab_time_count <= 0:
        raise ValueError("time_stop must be greater than time_start.")

    if library.boresight_active and not bool(force_ordinary):
        slab = _selector_candidate_slab_cp(
            library,
            time_start=int(time_start),
            time_stop=int(time_stop),
        )
        has_link_geom = int(slab["candidate_alpha_deg"].size) > 0 and int(slab["candidate_beta_deg"].size) > 0
        _ensure_boresight_masks_cp(library)
        sky_stop_i = int(library.boresight_sky_count if sky_stop is None else sky_stop)
        sky_start_i = int(sky_start)
        slab_sky_count = sky_stop_i - sky_start_i
        if slab_sky_count <= 0:
            raise ValueError("sky_stop must be greater than sky_start for boresight slabs.")

        assignments_cp = cp.full(
            (slab_time_count, slab_sky_count, library.cell_count, library.n_links),
            -1,
            dtype=cp.int32,
        )
        cone_ok_cp = cp.zeros(assignments_cp.shape, dtype=cp.bool_)
        selected_alpha_deg_cp = cp.full(assignments_cp.shape, cp.nan, dtype=cp.float32)
        selected_beta_deg_cp = cp.full(assignments_cp.shape, cp.nan, dtype=cp.float32)
        cell_count_work_cp = cp.zeros((slab_time_count, slab_sky_count, library.cell_count), dtype=cp.int32)
        sat_count_work_cp = cp.zeros((slab_time_count, slab_sky_count, library.sat_count), dtype=cp.int32)
        theta2_cell_mask_cp = library.boresight_theta2_cell_mask_cp
        if theta2_cell_mask_cp is None:
            theta2_cell_mask_cp = cp.zeros((library.cell_count,), dtype=cp.bool_)
        if int(slab["candidate_cell"].size) > 0:
            grid = (slab_time_count, slab_sky_count, 1)
            block = (1, 1, 1)
            _greedy_assign_sorted_candidates_boresight_minimal_kernel[grid, block](
                cuda.as_cuda_array(slab["segment_start"]),
                cuda.as_cuda_array(slab["segment_end"]),
                cuda.as_cuda_array(slab["candidate_cell"]),
                cuda.as_cuda_array(slab["candidate_sat"]),
                cuda.as_cuda_array(slab["candidate_alpha_deg"]),
                cuda.as_cuda_array(slab["candidate_beta_deg"]),
                cuda.as_cuda_array(library.sat_beta_max_cp),
                cuda.as_cuda_array(library.boresight_full_mask_cp[time_start:time_stop, sky_start_i:sky_stop_i, :]),
                cuda.as_cuda_array(library.boresight_partial_mask_cp[time_start:time_stop, sky_start_i:sky_stop_i, :]),
                cuda.as_cuda_array(theta2_cell_mask_cp),
                int(library.cell_count),
                int(library.n_links),
                int(library.n_beam),
                bool(library.use_cone_check),
                bool(has_link_geom),
                np.float32(library.beta_tol_deg),
                cuda.as_cuda_array(cell_count_work_cp),
                cuda.as_cuda_array(sat_count_work_cp),
                cuda.as_cuda_array(assignments_cp),
                cuda.as_cuda_array(cone_ok_cp),
                cuda.as_cuda_array(selected_alpha_deg_cp),
                cuda.as_cuda_array(selected_beta_deg_cp),
            )
        return {
            "assignments": assignments_cp,
            "cone_ok": cone_ok_cp,
            "selected_alpha_rad": cp.remainder(
                selected_alpha_deg_cp * cp.float32(np.pi / 180.0),
                cp.float32(2.0 * np.pi),
            ).astype(cp.float32, copy=False),
            "selected_beta_rad": (
                selected_beta_deg_cp * cp.float32(np.pi / 180.0)
            ).astype(cp.float32, copy=False),
        }

    result_cp = _frontier_select_link_candidates_cp(
        library,
        time_start=int(time_start),
        time_stop=int(time_stop),
        selector_backend=selector_backend,
        working_memory_budget_bytes=working_memory_budget_bytes,
        debug_direct_epfd=bool(debug_direct_epfd),
    )
    selector_backend_name = str(selector_backend).strip().lower()
    if (
        debug_direct_epfd
        and selector_backend_name == GPU_DIRECT_SELECTOR_BACKEND_FAST
        and (
            compare_slab := _direct_candidate_slab_cp(
                library,
                time_start=int(time_start),
                time_stop=int(time_stop),
            )
        ) is not None
        and _should_debug_compare_direct_finalize_cp(
            assignments_cp=result_cp["assignments"],
            direct_candidate_slab=compare_slab,
        )
    ):
        reference_cp = _frontier_select_link_candidates_cp(
            library,
            time_start=int(time_start),
            time_stop=int(time_stop),
            selector_backend=GPU_DIRECT_SELECTOR_BACKEND_REFERENCE,
            debug_direct_epfd=False,
        )
        selector_stats = dict(result_cp.get("debug_direct_epfd_stats", {}))
        assignment_drift_cp = result_cp["assignments"] != reference_cp["assignments"]
        cone_drift_cp = result_cp["cone_ok"] != reference_cp["cone_ok"]
        alpha_drift_cp = ~cp.isclose(
            result_cp["selected_alpha_rad"],
            reference_cp["selected_alpha_rad"],
            rtol=0.0,
            atol=0.0,
            equal_nan=True,
        )
        beta_drift_cp = ~cp.isclose(
            result_cp["selected_beta_rad"],
            reference_cp["selected_beta_rad"],
            rtol=0.0,
            atol=0.0,
            equal_nan=True,
        )
        selector_stats.update(
            selector_reference_compared=True,
            selector_assignment_drift_count=int(cp.count_nonzero(assignment_drift_cp).item()),
            selector_cone_ok_drift_count=int(cp.count_nonzero(cone_drift_cp).item()),
            selector_alpha_drift_count=int(cp.count_nonzero(alpha_drift_cp).item()),
            selector_beta_drift_count=int(cp.count_nonzero(beta_drift_cp).item()),
            selector_fast_assignment_count=int(cp.count_nonzero(result_cp["assignments"] >= 0).item()),
            selector_reference_assignment_count=int(cp.count_nonzero(reference_cp["assignments"] >= 0).item()),
        )
        result_cp["debug_direct_epfd_stats"] = selector_stats
    elif (
        debug_direct_epfd
        and selector_backend_name == GPU_DIRECT_SELECTOR_BACKEND_REFERENCE
        and (
            compare_slab := _direct_candidate_slab_cp(
                library,
                time_start=int(time_start),
                time_stop=int(time_stop),
            )
        ) is not None
        and _should_debug_compare_direct_finalize_cp(
            assignments_cp=result_cp["assignments"],
            direct_candidate_slab=compare_slab,
        )
    ):
        fast_cp = _frontier_select_link_candidates_cp(
            library,
            time_start=int(time_start),
            time_stop=int(time_stop),
            selector_backend=GPU_DIRECT_SELECTOR_BACKEND_FAST,
            working_memory_budget_bytes=working_memory_budget_bytes,
            debug_direct_epfd=False,
        )
        selector_stats = dict(result_cp.get("debug_direct_epfd_stats", {}))
        selector_stats.update(
            selector_reference_compared=False,
            selector_fast_compared=True,
            selector_assignment_drift_count=int(
                cp.count_nonzero(result_cp["assignments"] != fast_cp["assignments"]).item()
            ),
            selector_cone_ok_drift_count=int(
                cp.count_nonzero(result_cp["cone_ok"] != fast_cp["cone_ok"]).item()
            ),
            selector_fast_assignment_count=int(cp.count_nonzero(fast_cp["assignments"] >= 0).item()),
            selector_reference_assignment_count=int(cp.count_nonzero(result_cp["assignments"] >= 0).item()),
        )
        result_cp["debug_direct_epfd_stats"] = selector_stats
    elif debug_direct_epfd:
        selector_stats = dict(result_cp.get("debug_direct_epfd_stats", {}))
        selector_stats["selector_reference_compared"] = False
        result_cp["debug_direct_epfd_stats"] = selector_stats
    return result_cp


def _estimate_direct_finalize_output_bytes(
    *,
    time_count: int,
    sky_count: int,
    sat_output_count: int,
    n_beam: int,
    include_diagnostics: bool,
    boresight_active: bool,
) -> int:
    beam_value_count = int(time_count) * int(sat_output_count) * int(n_beam)
    if boresight_active:
        beam_value_count *= int(sky_count)
    total = beam_value_count * (4 + 4 + 4)
    count_value_count = int(time_count) * int(sat_output_count)
    if boresight_active:
        count_value_count *= int(sky_count)
    total += count_value_count * 4
    if include_diagnostics:
        diag_value_count = int(time_count) * (int(sky_count) if boresight_active else 1)
        total += diag_value_count * 5 * 4
    return int(total)


def _estimate_direct_finalize_slab_bytes(
    *,
    cell_count: int,
    sat_count: int,
    sat_output_count: int,
    n_links: int,
    n_beam: int,
    time_count: int,
    sky_count: int,
    include_diagnostics: bool,
    boresight_active: bool,
    mode: str,
) -> int:
    row_factor = int(time_count) * (int(sky_count) if boresight_active else 1)
    first_pass_row_factor = int(time_count) * (1 if boresight_active else 1)
    first_pass_bytes = first_pass_row_factor * int(cell_count) * int(n_links) * (4 + 1 + 4 + 4)
    first_pass_bytes += first_pass_row_factor * (int(cell_count) + int(sat_count)) * 4
    first_pass_bytes += (
        first_pass_row_factor
        * int(cell_count)
        * int(GPU_DIRECT_SELECTOR_BYTES_PER_ROW_EST)
    )
    output_bytes = _estimate_direct_finalize_output_bytes(
        time_count=time_count,
        sky_count=sky_count,
        sat_output_count=sat_output_count,
        n_beam=n_beam,
        include_diagnostics=include_diagnostics,
        boresight_active=boresight_active,
    )
    if mode == "cell_center":
        return int(first_pass_bytes + output_bytes + row_factor * int(sat_count) * 4)

    repair_bytes = row_factor * int(cell_count) * int(n_links) * (4 + 1)
    repair_bytes += row_factor * int(sat_count) * (4 + 4 + 1 + 4)
    return int(first_pass_bytes + output_bytes + repair_bytes)


def _estimate_direct_finalize_slab_byte_components(
    *,
    cell_count: int,
    sat_count: int,
    sat_output_count: int,
    n_links: int,
    n_beam: int,
    time_count: int,
    sky_count: int,
    include_diagnostics: bool,
    boresight_active: bool,
    mode: str,
) -> dict[str, int]:
    time_count_i = int(max(0, time_count))
    sky_count_i = int(max(1, sky_count if boresight_active else 1))
    row_factor = int(time_count_i * sky_count_i)
    first_pass_row_factor = int(time_count_i)
    first_pass_selector_bytes = (
        first_pass_row_factor * int(cell_count) * int(n_links) * (4 + 1 + 4 + 4)
    )
    first_pass_selector_bytes += first_pass_row_factor * (int(cell_count) + int(sat_count)) * 4
    first_pass_selector_bytes += (
        first_pass_row_factor
        * int(cell_count)
        * int(GPU_DIRECT_SELECTOR_BYTES_PER_ROW_EST)
    )
    direct_candidate_bytes = int(time_count_i) * (
        int(cell_count) * int(sat_count) * (4 + 4 + 4)
        + (int(cell_count) + 1) * 8
    )
    boresight_sparse_bytes = 0
    if boresight_active:
        boresight_sparse_bytes = row_factor * (
            2 * int(sat_count) * 4
            + 2 * 8
        )
    output_bytes = _estimate_direct_finalize_output_bytes(
        time_count=time_count_i,
        sky_count=sky_count_i,
        sat_output_count=sat_output_count,
        n_beam=n_beam,
        include_diagnostics=include_diagnostics,
        boresight_active=boresight_active,
    )
    if mode == "cell_center":
        retarget_repair_bytes = row_factor * int(sat_count) * 4
    else:
        retarget_repair_bytes = row_factor * int(cell_count) * int(n_links) * (4 + 1)
        retarget_repair_bytes += row_factor * int(sat_count) * (4 + 4 + 1 + 4)
    return {
        "first_pass_selector_bytes": int(first_pass_selector_bytes),
        "direct_candidate_bytes": int(direct_candidate_bytes),
        "boresight_sparse_bytes": int(boresight_sparse_bytes),
        "retarget_repair_bytes": int(retarget_repair_bytes),
        "output_bytes": int(output_bytes),
        "total_bytes": int(
            first_pass_selector_bytes
            + direct_candidate_bytes
            + boresight_sparse_bytes
            + retarget_repair_bytes
            + output_bytes
        ),
    }


def _estimate_ras_power_workspace_bytes(
    *,
    time_count: int,
    sky_count: int,
    sat_count: int,
    beam_count: int,
    include_receive_outputs: bool,
    include_total_pfd: bool,
    include_per_satellite_pfd: bool,
    boresight_active: bool,
) -> int:
    time_count_i = int(time_count)
    sky_count_i = int(sky_count if boresight_active else 1)
    sat_count_i = int(sat_count)
    beam_count_i = int(beam_count)
    if time_count_i <= 0 or sky_count_i <= 0 or sat_count_i <= 0:
        return 0

    if boresight_active:
        beam_row_count = time_count_i * sky_count_i * sat_count_i * max(beam_count_i, 1)
        sat_row_count = time_count_i * sky_count_i * sat_count_i
        time_sat_count = time_count_i * sat_count_i
        time_sky_count = time_count_i * sky_count_i
        total = 0
        total += beam_row_count * ((14 * 4) + (4 * 1))
        total += sat_row_count * ((8 * 4) + (1 * 1))
        total += time_sat_count * ((12 * 4) + (1 * 1))
        total += time_sky_count * (4 * 4)
        if include_receive_outputs:
            total += sat_row_count * (7 * 4)
        if include_total_pfd:
            total += time_sky_count * 4
        if include_per_satellite_pfd:
            total += sat_row_count * 4
        return int(total)

    beam_row_count = time_count_i * sat_count_i * max(beam_count_i, 1)
    sat_row_count = time_count_i * sat_count_i
    total = 0
    total += beam_row_count * ((14 * 4) + (4 * 1))
    total += sat_row_count * ((14 * 4) + (2 * 1))
    if include_receive_outputs:
        total += sat_row_count * (7 * 4)
    if include_total_pfd:
        total += time_count_i * 4
    if include_per_satellite_pfd:
        total += sat_row_count * 4
    return int(total)


def _plan_direct_finalize_slabs(
    library: GpuSatelliteLinkSelectionLibrary,
    *,
    sat_output_count: int,
    include_diagnostics: bool,
    mode: str,
    working_memory_budget_bytes: int | None,
    return_device: bool,
    scheduler_target_profile: str | float | None = "high_throughput",
) -> dict[str, int]:
    boresight_active = bool(library.boresight_active)
    sky_total = int(library.boresight_sky_count if boresight_active else 1)
    if working_memory_budget_bytes is not None:
        target_bytes = int(working_memory_budget_bytes)
        if target_bytes <= 0:
            raise ValueError("working_memory_budget_bytes must be positive when provided.")
    else:
        _target_profile_name, target_fraction = _resolve_scheduler_target_fraction(
            scheduler_target_profile
        )
        try:
            free_bytes, _total_bytes = cp.cuda.runtime.memGetInfo()
            target_bytes = max(
                int(float(free_bytes) * float(target_fraction)),
                64 * 1024 * 1024,
            )
        except Exception:
            target_bytes = 256 * 1024 * 1024
        if return_device:
            target_bytes = max(
                target_bytes
                - _estimate_direct_finalize_output_bytes(
                    time_count=library.time_count,
                    sky_count=sky_total,
                    sat_output_count=sat_output_count,
                    n_beam=library.n_beam,
                    include_diagnostics=include_diagnostics,
                    boresight_active=boresight_active,
                ),
                8 * 1024 * 1024,
            )

    def _estimate_components(time_chunk: int, sky_chunk: int) -> dict[str, int]:
        return _estimate_direct_finalize_slab_byte_components(
            cell_count=library.cell_count,
            sat_count=library.sat_count,
            sat_output_count=sat_output_count,
            n_links=library.n_links,
            n_beam=library.n_beam,
            time_count=int(time_chunk),
            sky_count=int(sky_chunk),
            include_diagnostics=include_diagnostics,
            boresight_active=boresight_active,
            mode=mode,
        )

    bytes_per_time_sky = _estimate_components(1, 1)["total_bytes"]
    if not boresight_active:
        time_chunk = max(1, min(library.time_count, target_bytes // max(bytes_per_time_sky, 1)))
        component_estimates = _estimate_components(int(time_chunk), 1)
        return {
            "time_chunk_size": int(time_chunk),
            "sky_chunk_size": 1,
            "working_memory_budget_bytes": int(target_bytes),
            "estimated_component_bytes": dict(component_estimates),
        }

    total_time = int(max(1, library.time_count))
    bytes_per_time_full_sky = _estimate_components(1, int(sky_total))["total_bytes"]
    if target_bytes >= bytes_per_time_full_sky:
        time_chunk = max(1, min(total_time, target_bytes // max(bytes_per_time_full_sky, 1)))
        sky_chunk = int(sky_total)
        component_estimates = _estimate_components(int(time_chunk), int(sky_chunk))
        return {
            "time_chunk_size": int(time_chunk),
            "sky_chunk_size": int(sky_chunk),
            "working_memory_budget_bytes": int(target_bytes),
            "estimated_component_bytes": dict(component_estimates),
        }

    best_time_chunk = 1
    best_sky_chunk = max(1, min(int(sky_total), target_bytes // max(bytes_per_time_sky, 1)))
    best_components = _estimate_components(int(best_time_chunk), int(best_sky_chunk))
    best_fit = int(best_components["total_bytes"]) <= int(target_bytes)
    best_score = (
        float("inf"),
        float("inf"),
        -int(best_time_chunk * best_sky_chunk),
        -int(best_time_chunk),
        -int(best_sky_chunk),
    )
    for time_chunk in range(1, total_time + 1):
        best_sky_for_time = 0
        best_components_for_time: dict[str, int] | None = None
        low = 1
        high = int(sky_total)
        while low <= high:
            mid = (low + high) // 2
            components_mid = _estimate_components(int(time_chunk), int(mid))
            if int(components_mid["total_bytes"]) <= int(target_bytes):
                best_sky_for_time = int(mid)
                best_components_for_time = components_mid
                low = mid + 1
            else:
                high = mid - 1
        if best_sky_for_time <= 0 or best_components_for_time is None:
            continue
        n_time_slabs = int(math.ceil(float(total_time) / float(max(1, time_chunk))))
        n_sky_slabs = int(math.ceil(float(sky_total) / float(max(1, best_sky_for_time))))
        score = (
            float((4 * n_time_slabs) + (n_time_slabs * n_sky_slabs)),
            float(n_time_slabs * n_sky_slabs),
            -int(time_chunk * best_sky_for_time),
            -int(time_chunk),
            -int(best_sky_for_time),
        )
        if (not best_fit) or score < best_score:
            best_fit = True
            best_score = score
            best_time_chunk = int(time_chunk)
            best_sky_chunk = int(best_sky_for_time)
            best_components = dict(best_components_for_time)

    time_chunk = int(best_time_chunk)
    sky_chunk = int(best_sky_chunk)
    component_estimates = dict(best_components)
    return {
        "time_chunk_size": int(time_chunk),
        "sky_chunk_size": int(sky_chunk),
        "working_memory_budget_bytes": int(target_bytes),
        "estimated_component_bytes": dict(component_estimates),
    }


def _allocate_direct_finalize_result(
    *,
    time_count: int,
    sky_count: int,
    sat_output_count: int,
    sat_count: int,
    n_beam: int,
    include_diagnostics: bool,
    include_full_sat_beam_counts_used: bool,
    boresight_active: bool,
    return_device: bool,
) -> dict[str, Any]:
    module = cp if return_device else np
    beam_shape = (
        (time_count, sky_count, sat_output_count, n_beam)
        if boresight_active
        else (time_count, sat_output_count, n_beam)
    )
    count_shape = (
        (time_count, sky_count, sat_output_count)
        if boresight_active
        else (time_count, sat_output_count)
    )
    diag_shape = (time_count, sky_count) if boresight_active else (time_count,)
    result: dict[str, Any] = {
        "beam_idx": module.full(beam_shape, -1, dtype=np.int32),
        "beam_alpha_rad": module.full(beam_shape, np.nan, dtype=np.float32),
        "beam_beta_rad": module.full(beam_shape, np.nan, dtype=np.float32),
        "sat_beam_counts_used": module.zeros(count_shape, dtype=np.int32),
    }
    if include_full_sat_beam_counts_used:
        full_count_shape = (
            (time_count, sky_count, sat_count) if boresight_active else (time_count, sat_count)
        )
        result["sat_beam_counts_used_full"] = module.zeros(full_count_shape, dtype=np.int32)
    if include_diagnostics:
        result["ras_retargeted_count"] = module.zeros(diag_shape, dtype=np.int32)
        result["ras_reserved_count"] = module.zeros(diag_shape, dtype=np.int32)
        result["direct_kept_count"] = module.zeros(diag_shape, dtype=np.int32)
        result["repaired_link_count"] = module.zeros(diag_shape, dtype=np.int32)
        result["dropped_link_count"] = module.zeros(diag_shape, dtype=np.int32)
    return result


def _store_direct_finalize_slab_result(
    target: dict[str, Any],
    slab: dict[str, Any],
    *,
    boresight_active: bool,
    time_start: int,
    time_stop: int,
    sky_start: int,
    sky_stop: int,
    return_device: bool,
) -> None:
    for key, value in slab.items():
        if key not in target:
            continue
        payload = value if return_device else copy_device_to_host(value)
        if boresight_active:
            if target[key].ndim == 4:
                target[key][time_start:time_stop, sky_start:sky_stop, :, :] = payload
            elif target[key].ndim == 3:
                target[key][time_start:time_stop, sky_start:sky_stop, :] = payload
            else:
                target[key][time_start:time_stop, sky_start:sky_stop] = payload
        else:
            if target[key].ndim == 3:
                target[key][time_start:time_stop, :, :] = payload
            elif target[key].ndim == 2:
                target[key][time_start:time_stop, :] = payload
            else:
                target[key][time_start:time_stop] = payload


def _stable_group_rank_cp(group_key_cp: Any, order_key_cp: Any) -> tuple[Any, Any]:
    """Return a stable sort order and 0-based rank within each group.

    Uses a composite-key argsort (group_key << 40 | order_key) instead
    of ``cp.lexsort`` — ~3x faster for 14M elements (6.9ms vs 26.4ms).
    The 40-bit shift accommodates order_key values up to ~1 trillion
    (well beyond any candidate count). Group keys fit in the upper
    24 bits (max ~16M groups).
    """
    if int(group_key_cp.size) == 0:
        empty_i64 = cp.empty((0,), dtype=cp.int64)
        empty_i32 = cp.empty((0,), dtype=cp.int32)
        return empty_i64, empty_i32
    # Composite key: group in upper bits, order in lower bits.
    # Zero collision: group_key < 2^24, order_key < 2^40.
    _composite = (
        group_key_cp.astype(cp.int64, copy=False) << np.int64(40)
    ) | (order_key_cp.astype(cp.int64, copy=False) & np.int64(0xFFFFFFFFFF))
    order_cp = cp.argsort(_composite).astype(cp.int64, copy=False)
    group_sorted = group_key_cp[order_cp]
    item_count = int(group_sorted.size)
    is_new = cp.empty((item_count,), dtype=cp.bool_)
    is_new[0] = True
    if item_count > 1:
        is_new[1:] = group_sorted[1:] != group_sorted[:-1]
    segment_ids = cp.cumsum(is_new.astype(cp.int32, copy=False), dtype=cp.int32) - np.int32(1)
    segment_starts = cp.nonzero(is_new)[0].astype(cp.int64, copy=False)
    last_start = segment_starts[segment_ids]
    rank_cp = (
        cp.arange(item_count, dtype=cp.int64) - last_start
    ).astype(cp.int32, copy=False)
    return order_cp, rank_cp


_decode_edge_kernel_3d: Any = None
_decode_edge_kernel_4d: Any = None


_eirp_fspl_raw_module: Any = None
_power_mega_raw_module: Any = None
_prx_output_raw_module: Any = None
_edge_feasibility_raw_module: Any = None
_scatter_edges_raw_module: Any = None
_gather_edges_raw_module: Any = None
_post_lexsort_raw_module: Any = None


def _get_post_lexsort_kernel():
    """Fused kernel: after lexsort, compute group boundaries + rank +
    cap-limited selection in a single pass.  Replaces ~9 CuPy dispatches
    (is_new + cumsum + nonzero + indexing + arange + subtraction).

    NOTE: This is a SERIAL kernel (one thread) because the group
    boundary detection is inherently sequential (depends on previous
    element).  For ~5000 sorted edges this is <0.1ms.  The win is
    eliminating 9 Python→CuPy dispatch round-trips (~4.5ms)."""
    global _post_lexsort_raw_module
    if _post_lexsort_raw_module is not None:
        return _post_lexsort_raw_module
    _post_lexsort_raw_module = cp.RawModule(code=r'''
extern "C" __global__
void compute_group_rank_and_select(
    const int* __restrict__ group_sorted,     // (N,) group keys after lexsort reorder
    const int* __restrict__ group_limit_flat, // (G,) per-group beam capacity
    int N,
    int* __restrict__ rank_out,               // (N,) output: within-group rank
    bool* __restrict__ keep_out,              // (N,) output: true if rank < limit
    int* __restrict__ n_kept_out              // (1,) output: total kept count
) {
    // Single-thread serial scan -- appropriate for N ~ 5000
    if (threadIdx.x != 0 || blockIdx.x != 0) return;

    int n_kept = 0;
    int prev_group = -1;
    int rank = 0;

    for (int i = 0; i < N; i++) {
        int g = group_sorted[i];
        if (g != prev_group) {
            rank = 0;
            prev_group = g;
        }
        rank_out[i] = rank;
        int limit = (g >= 0) ? group_limit_flat[g] : 0;
        bool k = (rank < limit);
        keep_out[i] = k;
        if (k) n_kept++;
        rank++;
    }
    n_kept_out[0] = n_kept;
}
    ''')
    return _post_lexsort_raw_module


def _get_gather_edges_kernel():
    """Fused kernel: from nonzero indices of assigned edges, decode
    (t, cell, link) + exclude RAS cell + gather (sat, cone_ok, alpha, beta)
    in a single CUDA launch.  Replaces ~8 CuPy dispatches."""
    global _gather_edges_raw_module
    if _gather_edges_raw_module is not None:
        return _gather_edges_raw_module
    _gather_edges_raw_module = cp.RawModule(code=r'''
extern "C" __global__
void gather_realized_edges_3d(
    const long long* __restrict__ realized_idx,  // (N,) flat indices into assignment tensor
    const int* __restrict__ assignments_flat,     // (T*C*K,) flat assignments
    const bool* __restrict__ cone_ok_flat,        // (T*C*K,) cone check results
    const float* __restrict__ alpha_flat,         // (T*C*K,) alpha angles
    const float* __restrict__ beta_flat,          // (T*C*K,) beta angles
    int cell_count, int n_links, int exclude_cell,
    int N,
    // Outputs -- write at positions [0..N), some may be filtered out
    int* __restrict__ out_t,
    int* __restrict__ out_cell,
    int* __restrict__ out_link,
    int* __restrict__ out_sat,
    bool* __restrict__ out_cone_ok,
    float* __restrict__ out_alpha,
    float* __restrict__ out_beta,
    long long* __restrict__ out_edge_linear,
    bool* __restrict__ out_keep  // true if not excluded by RAS cell
) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= N) return;

    long long flat = realized_idx[idx];
    int row_width = cell_count * n_links;
    int t = (int)(flat / row_width);
    int rem = (int)(flat - (long long)t * row_width);
    int cell = rem / n_links;
    int link = rem - cell * n_links;

    out_t[idx] = t;
    out_cell[idx] = cell;
    out_link[idx] = link;
    out_sat[idx] = assignments_flat[flat];
    out_cone_ok[idx] = cone_ok_flat[flat];
    out_alpha[idx] = alpha_flat[flat];
    out_beta[idx] = beta_flat[flat];
    out_edge_linear[idx] = flat;
    out_keep[idx] = (cell != exclude_cell);
}
    ''')
    return _gather_edges_raw_module


def _get_scatter_edges_kernel():
    """Fused kernel: gather edge fields at selected positions AND scatter
    into beam output arrays in a single CUDA launch.  Replaces ~13 CuPy
    dispatches (gathers + count_nonzero host sync + advanced-index scatters).
    Non-boresight (3-D) path only."""
    global _scatter_edges_raw_module
    if _scatter_edges_raw_module is not None:
        return _scatter_edges_raw_module
    _scatter_edges_raw_module = cp.RawModule(code=r'''
extern "C" __global__
void scatter_selected_edges_3d(
    // Edge info arrays (full realised edge set)
    const int* __restrict__ edge_sat,       // (N_realised,)
    const int* __restrict__ edge_cell,      // (N_realised,)
    const int* __restrict__ edge_link,      // (N_realised,)
    const int* __restrict__ edge_t,         // (N_realised,)
    const float* __restrict__ edge_alpha,   // (N_realised,)
    const float* __restrict__ edge_beta,    // (N_realised,)
    // Selected positions + slots
    const long long* __restrict__ sel_pos,  // (N_selected,) indices into edge arrays
    const int* __restrict__ sel_slot,       // (N_selected,) beam slot assignment
    // Mapping
    const int* __restrict__ sat_output_index, // (S_total,) sat -> output index
    int n_links,
    // Output arrays (3-D: T x S_out x K)
    int S_out, int K,
    int* __restrict__ beam_idx,
    float* __restrict__ beam_alpha,
    float* __restrict__ beam_beta,
    // Optional: cell_slot_sat (T x C x n_links), may be NULL
    int* __restrict__ cell_slot_sat,
    int has_cell_slot,
    int C,
    // Count
    int N_selected
) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= N_selected) return;

    long long pos = sel_pos[idx];
    int sat = edge_sat[pos];
    int sat_out = sat_output_index[sat];
    int cell = edge_cell[pos];
    int link = edge_link[pos];
    int t = edge_t[pos];
    int slot = sel_slot[idx];
    float alpha = edge_alpha[pos];
    float beta = edge_beta[pos];
    int beam_id = cell * n_links + link;

    // Scatter into beam output arrays (only if sat has a valid output slot)
    if (sat_out >= 0) {
        int out_idx = (t * S_out + sat_out) * K + slot;
        beam_idx[out_idx] = beam_id;
        beam_alpha[out_idx] = alpha;
        beam_beta[out_idx] = beta;
    }

    // Optional: update cell_slot_sat
    if (has_cell_slot) {
        int cs_idx = (t * C + cell) * n_links + link;
        cell_slot_sat[cs_idx] = sat;
    }
}
    ''')
    return _scatter_edges_raw_module


def _get_edge_feasibility_kernel():
    """Fused kernel: cone_ok + RAS guard angular check → feasibility mask.
    Replaces ~18 CuPy dispatches in the non-boresight edge processing."""
    global _edge_feasibility_raw_module
    if _edge_feasibility_raw_module is not None:
        return _edge_feasibility_raw_module
    _edge_feasibility_raw_module = cp.RawModule(code=r'''
extern "C" __global__
void compute_edge_feasibility(
    const bool* __restrict__ cone_ok,          // (N,) per realized edge
    const int* __restrict__ edge_t,            // (N,) time index per edge
    const int* __restrict__ edge_sat,          // (N,) satellite index per edge
    const float* __restrict__ edge_alpha,      // (N,) edge beam alpha
    const float* __restrict__ edge_beta,       // (N,) edge beam beta
    const bool* __restrict__ reserved_present, // (T, S) RAS reservation flags
    const float* __restrict__ reserved_alpha,  // (T, S) RAS reserved alpha
    const float* __restrict__ reserved_beta,   // (T, S) RAS reserved beta
    float ras_guard_cos,
    int use_ras_guard,
    int sat_count,
    int N,
    bool* __restrict__ feasible                // (N,) output
) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= N) return;

    if (!cone_ok[idx]) {
        feasible[idx] = false;
        return;
    }

    if (!use_ras_guard) {
        feasible[idx] = true;
        return;
    }

    int t = edge_t[idx];
    int s = edge_sat[idx];
    int ts = t * sat_count + s;

    if (!reserved_present[ts]) {
        feasible[idx] = true;
        return;
    }

    float a_ras = reserved_alpha[ts];
    float b_ras = reserved_beta[ts];
    float a_edge = edge_alpha[idx];
    float b_edge = edge_beta[idx];

    // Check all finite
    if (!isfinite(a_ras) || !isfinite(b_ras) ||
        !isfinite(a_edge) || !isfinite(b_edge)) {
        feasible[idx] = true;
        return;
    }

    // Angular distance between RAS reserved beam and edge beam
    float cos_da = cosf(a_ras - a_edge);
    float cos_gamma = cosf(b_ras) * cosf(b_edge)
                    + sinf(b_ras) * sinf(b_edge) * cos_da;

    // Conflict if angular distance < guard angle (cos_gamma > cos threshold)
    feasible[idx] = !(cos_gamma > ras_guard_cos);
}
    ''')
    return _edge_feasibility_raw_module


def _get_prx_output_kernel():
    """Fused kernel: grx_lin × vis × scale → sum over sats → EPFD/PFD outputs.
    Replaces ~7 CuPy dispatches in the output assembly."""
    global _prx_output_raw_module
    if _prx_output_raw_module is not None:
        return _prx_output_raw_module
    _prx_output_raw_module = cp.RawModule(code=r'''
extern "C" __global__
void compute_prx_and_reduce(
    const float* __restrict__ grx_lin,        // (T, N_tel, S)
    const float* __restrict__ scale_w_channel, // (T, S)
    const bool* __restrict__ vis_horizon,      // (T, S)
    float pfd_from_prx_scale,
    int T, int N_tel, int S,
    int want_prx_total,
    int want_epfd,
    int want_pfd_total,
    float* __restrict__ prx_total,             // (T, N_tel) output
    float* __restrict__ epfd,                  // (T, N_tel) output
    float* __restrict__ pfd_total              // (T,) output
) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;

    // Each thread handles one (t, sky) pair for prx/epfd
    // or one (t,) for pfd_total
    if (idx < T * N_tel && (want_prx_total || want_epfd)) {
        int sky = idx % N_tel;
        int t = idx / N_tel;
        float prx_sum = 0.0f;
        for (int s = 0; s < S; s++) {
            int ts = t * S + s;
            float vis = vis_horizon[ts] ? 1.0f : 0.0f;
            float grx = grx_lin[t * N_tel * S + sky * S + s];
            float scale = scale_w_channel[ts];
            prx_sum += grx * vis * scale;
        }
        if (want_prx_total) prx_total[idx] = prx_sum;
        if (want_epfd) epfd[idx] = prx_sum * pfd_from_prx_scale;
    }

    // PFD total: sum scale_w_channel over satellites (no grx)
    if (want_pfd_total && idx < T) {
        float pfd_sum = 0.0f;
        for (int s = 0; s < S; s++) {
            pfd_sum += scale_w_channel[idx * S + s];
        }
        pfd_total[idx] = pfd_sum * pfd_from_prx_scale;
    }
}
    ''')
    return _prx_output_raw_module


def _get_power_mega_kernel():
    """Mega-fused power kernel: EIRP computation + leakage scaling +
    beam-sum reduction + FSPL × atm × vis_horizon in TWO CUDA launches
    (element-wise + reduction), replacing ~17 CuPy dispatches.

    Kernel 1 (per-beam): valid_beam → EIRP → leakage → emitted_eirp
    Kernel 2 (per-sat): sum(emitted_eirp, axis=beams) × FSPL × atm × vis
    """
    global _power_mega_raw_module
    if _power_mega_raw_module is not None:
        return _power_mega_raw_module
    _power_mega_raw_module = cp.RawModule(code=r'''
extern "C" __global__
void compute_emitted_eirp_with_leakage(
    const bool* __restrict__ valid_geom,
    const bool* __restrict__ mask_bore,
    const bool* __restrict__ valid_beam,
    const float* __restrict__ d_target_m,
    const float* __restrict__ atm_target,
    const float* __restrict__ range_m,
    const float* __restrict__ atm_ras,
    const float* __restrict__ gtx_rel_lin,
    const float* __restrict__ gtx_abs_lin,
    const int* __restrict__ beam_idx,
    const float* __restrict__ leakage_factors,
    float target_pfd_lin,
    float satellite_eirp_lin,
    float satellite_ptx_lin,
    int quantity_mode,  // 0=target_pfd, 1=satellite_eirp, 2=satellite_ptx
    int use_ras_alt_co,
    int n_links,
    int ras_cell_idx,
    int n_leakage_cells,
    int has_leakage,
    int T, int S, int K,
    float* __restrict__ emitted_eirp
) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    int total = T * S * K;
    if (idx >= total) return;

    int k = idx % K;
    int ts = idx / K;
    int s = ts % S;
    int t = ts / S;
    int ts_idx = t * S + s;

    if (!valid_beam[idx]) {
        emitted_eirp[idx] = 0.0f;
        return;
    }

    float eirp;
    float four_pi = 12.5663706f;

    if (quantity_mode == 0) {
        // target_pfd mode
        if (mask_bore[idx]) {
            float r = range_m[ts_idx];
            float a = use_ras_alt_co ? atm_ras[ts_idx] : 1.0f;
            eirp = target_pfd_lin * four_pi * r * r / fmaxf(a, 1e-30f);
        } else if (valid_geom[idx]) {
            float d = d_target_m[idx];
            float a = atm_target[idx];
            eirp = target_pfd_lin * four_pi * d * d / fmaxf(a, 1e-30f);
        } else {
            eirp = 0.0f;
        }
        eirp *= gtx_rel_lin[idx];
    } else if (quantity_mode == 1) {
        // satellite_eirp mode
        eirp = satellite_eirp_lin * gtx_rel_lin[idx];
    } else {
        // satellite_ptx mode
        eirp = satellite_ptx_lin * gtx_abs_lin[idx];
    }

    // Leakage scaling
    if (has_leakage) {
        int bidx = beam_idx[idx];
        if (bidx >= 0) {
            int cell_idx = bidx / n_links;
            if (mask_bore[idx]) cell_idx = ras_cell_idx;
            if (cell_idx >= 0 && cell_idx < n_leakage_cells) {
                eirp *= leakage_factors[cell_idx];
            } else {
                eirp = 0.0f;
            }
        }
    }

    emitted_eirp[idx] = eirp;
}

extern "C" __global__
void reduce_eirp_to_scale(
    const float* __restrict__ emitted_eirp,  // (T, S, K)
    const float* __restrict__ range_m,       // (T, S)
    const float* __restrict__ atm_ras,       // (T, S)
    const bool* __restrict__ vis_horizon,    // (T, S)
    float wavelength_m,
    int T, int S, int K,
    float* __restrict__ scale_w_channel      // (T, S) output
) {
    int ts = blockIdx.x * blockDim.x + threadIdx.x;
    if (ts >= T * S) return;

    // Sum EIRP over beams
    float eirp_sum = 0.0f;
    int base = ts * K;
    for (int k = 0; k < K; k++) {
        eirp_sum += emitted_eirp[base + k];
    }

    // FSPL = (wavelength / (4*pi*range))^2
    float four_pi = 12.5663706f;
    float r = range_m[ts];
    float fspl = wavelength_m / (four_pi * r);
    fspl = fspl * fspl;

    // Atmosphere attenuation
    float atm = atm_ras[ts];

    // Visibility mask
    float vis = vis_horizon[ts] ? 1.0f : 0.0f;

    scale_w_channel[ts] = eirp_sum * fspl * atm * vis;
}
    ''')
    return _power_mega_raw_module


def _get_eirp_fspl_fused_kernel():
    """Fused CUDA kernel: computes emitted EIRP from beam geometry and
    FSPL × atmosphere in a single launch.  Replaces ~8 separate CuPy
    operations in the target_pfd power path.

    Inputs (per element [t, s, k]):
      valid_geom, mask_bore, valid_beam: bool masks
      d_target_m: slant range to beam footprint on Earth
      atm_target: atmosphere transmission for beam target (0-1)
      range_m_ts: slant range to satellite from RAS station [t,s]
      atm_ras_ts: atmosphere transmission at RAS elevation [t,s]
      gtx_rel_lin: relative TX gain (pattern / Gmax) [t,s,k]
      target_pfd_lin: target PFD in linear W/m²/channel (scalar)
      wavelength_m: wavelength in metres (scalar)
      use_ras_alt_for_co: whether CO beam uses RAS station altitude

    Outputs (per element):
      emitted_eirp: per-beam EIRP [t,s,k]
      fspl_vis: FSPL × atm × vis_horizon [t,s] (only for the [t,s] subset)
    """
    global _eirp_fspl_raw_module
    if _eirp_fspl_raw_module is not None:
        return _eirp_fspl_raw_module
    _eirp_fspl_raw_module = cp.RawModule(code=r'''
extern "C" __global__
void compute_eirp_and_scale(
    const bool* __restrict__ valid_geom,   // (T, S, K)
    const bool* __restrict__ mask_bore,    // (T, S, K)
    const bool* __restrict__ valid_beam,   // (T, S, K)
    const float* __restrict__ d_target_m,  // (T, S, K)
    const float* __restrict__ atm_target,  // (T, S, K)
    const float* __restrict__ range_m,     // (T, S)
    const float* __restrict__ atm_ras,     // (T, S)
    const float* __restrict__ gtx_rel_lin, // (T, S, K)
    const bool* __restrict__ vis_horizon,  // (T, S)
    float target_pfd_lin,
    float wavelength_m,
    int use_ras_alt_co,
    int time_count,
    int sat_count,
    int beam_count,
    float* __restrict__ emitted_eirp       // (T, S, K) output
) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    int total = time_count * sat_count * beam_count;
    if (idx >= total) return;

    int k = idx % beam_count;
    int ts = idx / beam_count;
    int s = ts % sat_count;
    int t = ts / sat_count;

    float four_pi = 12.5663706f;

    if (!valid_beam[idx]) {
        emitted_eirp[idx] = 0.0f;
        return;
    }

    float eirp;
    if (mask_bore[idx]) {
        // Boresight (CO) beam: EIRP from RAS station range
        float r = range_m[t * sat_count + s];
        float a = use_ras_alt_co ? atm_ras[t * sat_count + s] : 1.0f;
        eirp = target_pfd_lin * four_pi * r * r / fmaxf(a, 1e-30f);
    } else if (valid_geom[idx]) {
        // Off-boresight beam: EIRP from beam footprint geometry
        float d = d_target_m[idx];
        float a = atm_target[idx];
        eirp = target_pfd_lin * four_pi * d * d / fmaxf(a, 1e-30f);
    } else {
        eirp = 0.0f;
    }

    emitted_eirp[idx] = eirp * gtx_rel_lin[idx];
}
    ''')
    return _eirp_fspl_raw_module


_add_chunk_gather_kernel: Any = None
_visibility_fused_kernel: Any = None


def _get_visibility_fused_kernel():
    """Fused kernel: elevation check + cell activity mask + cone check
    in a single CUDA launch.  Replaces 3-4 CuPy operations on the
    full (T, C, S) visibility tensor."""
    global _visibility_fused_kernel
    if _visibility_fused_kernel is not None:
        return _visibility_fused_kernel
    _visibility_fused_kernel = cp.ElementwiseKernel(
        "float32 elev_deg, float32 min_elev, "
        "bool cell_active, float32 theta_abs, float32 beta_max, "
        "int32 has_cell_mask, int32 has_cone_check, float32 beta_tol",
        "bool visible, bool eligible",
        """
        visible = (elev_deg >= min_elev);
        if (has_cell_mask && !cell_active) visible = false;
        eligible = visible;
        if (has_cone_check && theta_abs > (beta_max + beta_tol)) {
            eligible = false;
        }
        """,
        "visibility_fused",
    )
    return _visibility_fused_kernel


def _get_add_chunk_gather_kernel():
    """Fused kernel: from flat visible indices, gather all candidate fields
    in one pass (time, cell, sat, key, global_row, alpha, beta).
    Replaces ~12 separate CuPy operations."""
    global _add_chunk_gather_kernel
    if _add_chunk_gather_kernel is not None:
        return _add_chunk_gather_kernel
    _add_chunk_gather_kernel = cp.ElementwiseKernel(
        "int64 flat_idx, raw float32 elev_flat, raw float32 azel_az_flat, "
        "raw float32 theta_abs_flat, raw int32 sat_remap, "
        "int32 chunk_sat_count, int32 chunk_cell_count, "
        "int32 cell_offset, int32 total_cell_count, "
        "int32 has_remap, int32 has_azel",
        "int32 time_out, int32 cell_out, int32 sat_out, "
        "float64 key_out, int64 row_out, float32 alpha_out, float32 beta_out",
        """
        int local_sat = (int)(flat_idx % chunk_sat_count);
        long long row_local = flat_idx / chunk_sat_count;
        int local_cell = (int)(row_local % chunk_cell_count);
        int t = (int)(row_local / chunk_cell_count);

        int sat = has_remap ? sat_remap[local_sat] : local_sat;
        int global_cell = local_cell + cell_offset;
        long long global_row = (long long)t * total_cell_count + global_cell;

        time_out = t;
        cell_out = global_cell;
        sat_out = sat;
        key_out = (double)(-elev_flat[flat_idx]);
        row_out = global_row;
        if (has_azel) {
            float az = azel_az_flat[flat_idx];
            // cp.remainder equivalent: fmodf then wrap negative
            az = fmodf(az, 360.0f);
            if (az < 0.0f) az += 360.0f;
            alpha_out = az;
            beta_out = theta_abs_flat[flat_idx];
        } else {
            alpha_out = 0.0f;
            beta_out = 0.0f;
        }
        """,
        "add_chunk_gather",
    )
    return _add_chunk_gather_kernel


def _init_decode_edge_kernels() -> None:
    """Lazily initialize the fused index-decomposition kernels."""
    global _decode_edge_kernel_3d, _decode_edge_kernel_4d
    if _decode_edge_kernel_3d is not None:
        return
    _decode_edge_kernel_3d = cp.ElementwiseKernel(
        "int64 flat_idx, int32 row_width, int32 n_links",
        "int32 t_out, int32 cell_out, int32 link_out",
        """
        int t = (int)(flat_idx / row_width);
        int rem = (int)(flat_idx - (long long)t * row_width);
        int c = rem / n_links;
        int l = rem - c * n_links;
        t_out = t; cell_out = c; link_out = l;
        """,
        "decode_edge_3d",
    )
    _decode_edge_kernel_4d = cp.ElementwiseKernel(
        "int64 flat_idx, int32 row_width, int32 sky_width, int32 n_links",
        "int32 t_out, int32 sky_out, int32 cell_out, int32 link_out",
        """
        int t = (int)(flat_idx / row_width);
        int rem = (int)(flat_idx - (long long)t * row_width);
        int s = rem / sky_width;
        rem = rem - s * sky_width;
        int c = rem / n_links;
        int l = rem - c * n_links;
        t_out = t; sky_out = s; cell_out = c; link_out = l;
        """,
        "decode_edge_4d",
    )


def _decode_realized_direct_edges_cp(
    edge_linear_cp: Any,
    *,
    boresight_active: bool,
    sky_count: int,
    cell_count: int,
    n_links: int,
) -> dict[str, Any]:
    _init_decode_edge_kernels()
    edge_linear_cp = cp.asarray(edge_linear_cp, dtype=cp.int64).reshape(-1)
    if not boresight_active:
        row_width = int(cell_count) * int(n_links)
        t_cp, cell_cp, link_cp = _decode_edge_kernel_3d(
            edge_linear_cp, np.int32(row_width), np.int32(n_links),
        )
        return {"t": t_cp, "cell": cell_cp, "link": link_cp}

    row_width = int(sky_count) * int(cell_count) * int(n_links)
    sky_width = int(cell_count) * int(n_links)
    t_cp, sky_cp, cell_cp, link_cp = _decode_edge_kernel_4d(
        edge_linear_cp, np.int32(row_width), np.int32(sky_width), np.int32(n_links),
    )
    return {"t": t_cp, "sky": sky_cp, "cell": cell_cp, "link": link_cp}


def _gather_realized_direct_edges_cp(
    assignments_cp: Any,
    cone_ok_cp: Any,
    alpha_cp: Any,
    beta_cp: Any,
    *,
    exclude_cell: int | None = None,
) -> dict[str, Any]:
    boresight_active = assignments_cp.ndim == 4
    sky_count = int(assignments_cp.shape[1]) if boresight_active else 1
    cell_count = int(assignments_cp.shape[-2])
    n_links = int(assignments_cp.shape[-1])
    sat_flat = assignments_cp.reshape(-1)
    realized_idx_cp = cp.nonzero(sat_flat >= 0)[0].astype(cp.int64, copy=False)
    n_realized = int(realized_idx_cp.size)

    # Non-boresight fused path: decode + exclude + gather in 1 kernel
    if not boresight_active and n_realized > 0 and exclude_cell is not None:
        _ge_mod = _get_gather_edges_kernel()
        _ge_k = _ge_mod.get_function("gather_realized_edges_3d")
        out_t = cp.empty(n_realized, dtype=cp.int32)
        out_cell = cp.empty(n_realized, dtype=cp.int32)
        out_link = cp.empty(n_realized, dtype=cp.int32)
        out_sat = cp.empty(n_realized, dtype=cp.int32)
        out_cone = cp.empty(n_realized, dtype=cp.bool_)
        out_alpha = cp.empty(n_realized, dtype=cp.float32)
        out_beta = cp.empty(n_realized, dtype=cp.float32)
        out_linear = cp.empty(n_realized, dtype=cp.int64)
        out_keep = cp.empty(n_realized, dtype=cp.bool_)
        _block = 256
        _ge_k(
            ((n_realized + _block - 1) // _block,), (_block,),
            (
                realized_idx_cp,
                sat_flat.astype(cp.int32, copy=False),
                cone_ok_cp.reshape(-1),
                alpha_cp.reshape(-1).astype(cp.float32, copy=False),
                beta_cp.reshape(-1).astype(cp.float32, copy=False),
                np.int32(cell_count), np.int32(n_links),
                np.int32(int(exclude_cell)),
                np.int32(n_realized),
                out_t, out_cell, out_link, out_sat,
                out_cone, out_alpha, out_beta, out_linear, out_keep,
            ),
        )
        # Filter by keep mask (exclude RAS cell)
        keep_pos = cp.nonzero(out_keep)[0]
        return {
            "t": out_t[keep_pos],
            "cell": out_cell[keep_pos],
            "link": out_link[keep_pos],
            "edge_linear": out_linear[keep_pos],
            "sat": out_sat[keep_pos],
            "cone_ok": out_cone[keep_pos],
            "alpha": out_alpha[keep_pos],
            "beta": out_beta[keep_pos],
        }

    # Fallback: boresight or no exclude_cell
    edge_info = _decode_realized_direct_edges_cp(
        realized_idx_cp,
        boresight_active=boresight_active,
        sky_count=sky_count,
        cell_count=cell_count,
        n_links=n_links,
    )
    if exclude_cell is not None:
        keep_mask = edge_info["cell"] != np.int32(int(exclude_cell))
        realized_idx_cp = realized_idx_cp[keep_mask]
        for key, value in tuple(edge_info.items()):
            edge_info[key] = value[keep_mask]
    edge_info["edge_linear"] = realized_idx_cp
    edge_info["sat"] = sat_flat[realized_idx_cp]
    edge_info["cone_ok"] = cone_ok_cp.reshape(-1)[realized_idx_cp]
    edge_info["alpha"] = alpha_cp.reshape(-1)[realized_idx_cp]
    edge_info["beta"] = beta_cp.reshape(-1)[realized_idx_cp]
    return edge_info


def _scatter_direct_edge_selection_cp(
    *,
    edge_info: dict[str, Any],
    selected_positions_cp: Any,
    slot_cp: Any,
    sat_output_index_cp: Any,
    n_links: int,
    beam_idx_cp: Any,
    beam_alpha_cp: Any,
    beam_beta_cp: Any,
    cell_slot_sat_cp: Any | None,
    cell_slot_beam_slot_cp: Any | None = None,
) -> None:
    if int(selected_positions_cp.size) == 0:
        return
    if beam_idx_cp.ndim == 4:
        # 4D (boresight) path: pure-CuPy gather + boolean-indexed scatter.
        # The fused RawModule below handles 3D only, so the CuPy pre-gather
        # is required here.
        edge_sel = selected_positions_cp.astype(cp.int64, copy=False)
        sat_sel = edge_info["sat"][edge_sel]
        sat_out_sel = sat_output_index_cp[sat_sel]
        cell_sel = edge_info["cell"][edge_sel]
        link_sel = edge_info["link"][edge_sel]
        beam_id_sel = cell_sel * np.int32(int(n_links)) + link_sel
        alpha_sel = edge_info["alpha"][edge_sel]
        beta_sel = edge_info["beta"][edge_sel]
        slot_sel = slot_cp.astype(cp.int32, copy=False)
        valid_out = sat_out_sel >= 0
        t_sel = edge_info["t"][edge_sel]
        sky_sel = edge_info["sky"][edge_sel]
        # Skip count_nonzero host sync — apply valid_out as a filter
        # directly via boolean indexing. If all sat_output_indices are
        # valid (common case), the filter is a no-op.
        vo = valid_out
        beam_idx_cp[t_sel[vo], sky_sel[vo], sat_out_sel[vo], slot_sel[vo]] = beam_id_sel[vo]
        beam_alpha_cp[t_sel[vo], sky_sel[vo], sat_out_sel[vo], slot_sel[vo]] = alpha_sel[vo]
        beam_beta_cp[t_sel[vo], sky_sel[vo], sat_out_sel[vo], slot_sel[vo]] = beta_sel[vo]
        if cell_slot_sat_cp is not None:
            cell_slot_sat_cp[t_sel, sky_sel, cell_sel, link_sel] = sat_sel
        if cell_slot_beam_slot_cp is not None:
            cell_slot_beam_slot_cp[t_sel, sky_sel, cell_sel, link_sel] = slot_sel
        return

    # Fused gather + scatter via RawModule: eliminates ~13 CuPy dispatches
    # including the count_nonzero host sync.  Writes beam_idx/alpha/beta
    # and cell_slot_sat in a single CUDA launch.
    _sc_mod = _get_scatter_edges_kernel()
    _sc_k = _sc_mod.get_function("scatter_selected_edges_3d")
    _n_sel = int(selected_positions_cp.size)
    _block = 256
    _S_out = int(beam_idx_cp.shape[1])
    _K = int(beam_idx_cp.shape[2])
    _C = int(cell_slot_sat_cp.shape[1]) if cell_slot_sat_cp is not None else 0
    _sc_k(
        ((_n_sel + _block - 1) // _block,), (_block,),
        (
            edge_info["sat"],
            edge_info["cell"],
            edge_info["link"],
            edge_info["t"],
            edge_info["alpha"],
            edge_info["beta"],
            selected_positions_cp.astype(cp.int64, copy=False),
            slot_cp.astype(cp.int32, copy=False),
            sat_output_index_cp,
            np.int32(n_links),
            np.int32(_S_out), np.int32(_K),
            beam_idx_cp, beam_alpha_cp, beam_beta_cp,
            cell_slot_sat_cp if cell_slot_sat_cp is not None else cp.empty(1, dtype=cp.int32),
            np.int32(1 if cell_slot_sat_cp is not None else 0),
            np.int32(_C),
            np.int32(_n_sel),
        ),
    )
    if cell_slot_beam_slot_cp is not None:
        # Rare path (boresight only); fall back to CuPy indexing.
        edge_sel = selected_positions_cp.astype(cp.int64, copy=False)
        _t_fb = edge_info["t"][edge_sel]
        _cell_fb = edge_info["cell"][edge_sel]
        _link_fb = edge_info["link"][edge_sel]
        cell_slot_beam_slot_cp[_t_fb, _cell_fb, _link_fb] = slot_cp.astype(cp.int32, copy=False)


def _count_edges_per_satellite_group_cp(
    *,
    group_key_cp: Any,
    base_shape: tuple[int, ...],
) -> Any:
    if int(group_key_cp.size) == 0:
        return cp.zeros(base_shape, dtype=cp.int32)
    flat_count = int(np.prod(base_shape, dtype=np.int64))
    counts_flat = cp.bincount(
        group_key_cp.astype(cp.int32, copy=False),
        minlength=flat_count,
    ).astype(cp.int32, copy=False)
    return counts_flat.reshape(base_shape)


def _count_edges_per_time_axis_cp(
    *,
    boresight_active: bool,
    t_cp: Any,
    sky_cp: Any | None,
    time_count: int,
    sky_count: int,
) -> Any:
    if int(t_cp.size) == 0:
        return cp.zeros((time_count, sky_count), dtype=cp.int32) if boresight_active else cp.zeros((time_count,), dtype=cp.int32)
    if boresight_active:
        flat = (t_cp.astype(cp.int32, copy=False) * np.int32(int(sky_count)) + sky_cp.astype(cp.int32, copy=False))
        counts = cp.bincount(flat, minlength=int(time_count) * int(sky_count)).astype(cp.int32, copy=False)
        return counts.reshape((int(time_count), int(sky_count)))
    return cp.bincount(t_cp.astype(cp.int32, copy=False), minlength=int(time_count)).astype(cp.int32, copy=False)


def _accumulate_flat_counts_inplace_cp(
    target_flat_cp: Any,
    *,
    key_cp: Any,
) -> None:
    _apply_flat_count_delta_cp(
        target_flat_cp,
        key_cp=key_cp,
        delta=np.int32(1),
    )


def _apply_flat_count_delta_cp(
    target_flat_cp: Any,
    *,
    key_cp: Any,
    delta: np.int32,
) -> None:
    if int(key_cp.size) <= 0:
        return
    unique_key_cp, counts_cp = cp.unique(
        key_cp.astype(cp.int64, copy=False),
        return_counts=True,
    )
    target_flat_cp[unique_key_cp] = (
        target_flat_cp[unique_key_cp].astype(cp.int32, copy=False)
        + np.int32(delta) * counts_cp.astype(cp.int32, copy=False)
    )


def _estimate_direct_pair_chunk_size(
    *,
    total_pair_count: int,
    working_memory_budget_bytes: int | None,
) -> int:
    if total_pair_count <= 0:
        return 1
    if working_memory_budget_bytes is None:
        return int(total_pair_count)
    return max(
        1,
        min(
            int(total_pair_count),
            int(working_memory_budget_bytes) // max(int(GPU_DIRECT_PAIR_CHUNK_BYTES_PER_PAIR_EST), 1),
        ),
    )


def _select_group_limited_edges_cp(
    *,
    group_key_cp: Any,
    order_key_cp: Any,
    group_limit_flat_cp: Any,
) -> tuple[Any, Any]:
    if int(group_key_cp.size) == 0:
        return cp.empty((0,), dtype=cp.int64), cp.empty((0,), dtype=cp.int32)
    order_cp, rank_cp = _stable_group_rank_cp(group_key_cp, order_key_cp)
    keep_sorted = rank_cp < group_limit_flat_cp[group_key_cp[order_cp]]
    return order_cp[keep_sorted].astype(cp.int64, copy=False), rank_cp[keep_sorted].astype(cp.int32, copy=False)


def _debug_cuda_sync_cp(
    *,
    enabled: bool,
    stage: str,
) -> None:
    if not enabled:
        return
    try:
        cuda.synchronize()
    except Exception as exc:  # pragma: no cover - only triggered on GPU failure paths
        raise RuntimeError(f"direct EPFD debug sync failed after {stage}") from exc


def _should_debug_compare_direct_finalize_cp(
    *,
    assignments_cp: Any,
    direct_candidate_slab: dict[str, Any],
) -> bool:
    assignment_count = int(np.prod(assignments_cp.shape, dtype=np.int64))
    candidate_count = int(direct_candidate_slab["candidate_sat"].size)
    return (
        assignment_count <= int(GPU_DIRECT_DEBUG_COMPARE_MAX_ASSIGNMENTS)
        and candidate_count <= int(GPU_DIRECT_DEBUG_COMPARE_MAX_CANDIDATES)
    )

def _canonicalize_direct_beam_slots_cp(
    beam_idx_cp: Any,
    beam_alpha_cp: Any,
    beam_beta_cp: Any,
) -> None:
    if int(beam_idx_cp.size) <= 0 or int(beam_idx_cp.shape[-1]) <= 1:
        return
    flat_idx = beam_idx_cp.reshape(-1, beam_idx_cp.shape[-1])
    flat_alpha = beam_alpha_cp.reshape(-1, beam_alpha_cp.shape[-1])
    flat_beta = beam_beta_cp.reshape(-1, beam_beta_cp.shape[-1])
    invalid_key = np.int64(np.iinfo(np.int32).max)
    sort_key = cp.where(
        flat_idx == np.int32(-1),
        invalid_key,
        flat_idx.astype(cp.int64, copy=False),
    )
    order_cp = cp.argsort(sort_key, axis=1)
    flat_idx[...] = cp.take_along_axis(flat_idx, order_cp, axis=1)
    flat_alpha[...] = cp.take_along_axis(flat_alpha, order_cp, axis=1)
    flat_beta[...] = cp.take_along_axis(flat_beta, order_cp, axis=1)


def _canonicalize_direct_beam_slots_np(
    beam_idx_np: np.ndarray,
    beam_alpha_np: np.ndarray,
    beam_beta_np: np.ndarray,
) -> None:
    if int(beam_idx_np.size) <= 0 or int(beam_idx_np.shape[-1]) <= 1:
        return
    flat_idx = beam_idx_np.reshape(-1, beam_idx_np.shape[-1])
    flat_alpha = beam_alpha_np.reshape(-1, beam_alpha_np.shape[-1])
    flat_beta = beam_beta_np.reshape(-1, beam_beta_np.shape[-1])
    invalid_key = np.int64(np.iinfo(np.int32).max)
    sort_key = np.where(
        flat_idx == np.int32(-1),
        invalid_key,
        flat_idx.astype(np.int64, copy=False),
    )
    order_np = np.argsort(sort_key, axis=1)
    flat_idx[...] = np.take_along_axis(flat_idx, order_np, axis=1)
    flat_alpha[...] = np.take_along_axis(flat_alpha, order_np, axis=1)
    flat_beta[...] = np.take_along_axis(flat_beta, order_np, axis=1)


def _direct_epfd_repair_launch_grid(*, row_count: int) -> tuple[tuple[int, int, int], int]:
    """
    Build a single CUDA grid for row-repair kernels.

    The direct-EPFD repair path previously sliced impacted rows into many
    Python-launched chunks once the row count exceeded the CUDA 1-D block-grid
    limit. Flattening the repair work onto a 3-D grid lets the default runtime
    keep the full impacted-row set on the device and launch the repair kernel
    once, which reduces host orchestration and makes telemetry reflect the
    actual GPU work more truthfully.

    Parameters
    ----------
    row_count : int
        Number of impacted rows that need repair.

    Returns
    -------
    tuple[tuple[int, int, int], int]
        CUDA launch grid `(grid_x, grid_y, grid_z)` plus the number of kernel
        launches required for that repair set. Non-empty repair sets now always
        return a single launch.

    Raises
    ------
    ValueError
        If `row_count` is negative or exceeds the representable 3-D CUDA grid
        range for the configured maximum blocks per dimension.
    """
    row_count_i = int(row_count)
    if row_count_i < 0:
        raise ValueError("row_count must be non-negative.")
    if row_count_i == 0:
        return (0, 1, 1), 0

    max_blocks = int(GPU_DIRECT_REPAIR_MAX_BLOCKS_PER_LAUNCH)
    grid_x = min(row_count_i, max_blocks)
    remaining = (row_count_i + grid_x - 1) // grid_x
    grid_y = min(max(1, remaining), max_blocks)
    remaining = (remaining + grid_y - 1) // grid_y
    grid_z = max(1, remaining)
    if grid_z > max_blocks:
        raise ValueError(
            "impacted row count exceeds the supported CUDA repair-grid range: "
            f"{row_count_i} rows for max_blocks={max_blocks}."
        )
    return (int(grid_x), int(grid_y), int(grid_z)), 1


def _launch_direct_epfd_row_repairs_cp(
    *,
    impacted_rows_cp: Any,
    row_ptr_cp: Any,
    row_kernel: Any,
    kernel_args: tuple[Any, ...],
    sky_count: int,
    cell_count: int,
    debug_direct_epfd: bool,
) -> dict[str, int]:
    impacted_row_count = int(impacted_rows_cp.size)
    if impacted_row_count <= 0:
        return {"impacted_row_count": 0, "impacted_candidate_edge_count": 0, "repair_launch_count": 0}

    if debug_direct_epfd:
        if sky_count > 1:
            rows_per_time = int(sky_count) * int(cell_count)
            base_row_cp = (
                (impacted_rows_cp // np.int32(rows_per_time)) * np.int32(int(cell_count))
                + (impacted_rows_cp % np.int32(int(cell_count)))
            ).astype(cp.int32, copy=False)
        else:
            base_row_cp = impacted_rows_cp.astype(cp.int32, copy=False)
        impacted_candidate_edge_count = int(
            cp.sum(row_ptr_cp[base_row_cp + np.int32(1)] - row_ptr_cp[base_row_cp]).item()
        )
    else:
        impacted_candidate_edge_count = 0

    repair_grid, repair_launch_count = _direct_epfd_repair_launch_grid(
        row_count=impacted_row_count
    )
    row_kernel[repair_grid, (GPU_DIRECT_REPAIR_BLOCK_SIZE, 1, 1)](
        cuda.as_cuda_array(impacted_rows_cp),
        *kernel_args,
    )
    return {
        "impacted_row_count": int(impacted_row_count),
        "impacted_candidate_edge_count": int(impacted_candidate_edge_count),
        "repair_launch_count": int(repair_launch_count),
    }


def _launch_direct_epfd_sparse_row_repairs_cp(
    *,
    impacted_rows_cp: Any,
    local_needs_repair_cp: Any,
    local_row_slot_sat_cp: Any,
    row_ptr_cp: Any,
    row_kernel: Any,
    kernel_args_prefix: tuple[Any, ...],
    kernel_args_suffix: tuple[Any, ...],
    sky_count: int,
    cell_count: int,
    debug_direct_epfd: bool,
) -> dict[str, int]:
    impacted_row_count = int(impacted_rows_cp.size)
    if impacted_row_count <= 0:
        return {"impacted_row_count": 0, "impacted_candidate_edge_count": 0, "repair_launch_count": 0}

    if debug_direct_epfd:
        rows_per_time = int(sky_count) * int(cell_count)
        base_row_cp = (
            (impacted_rows_cp // np.int32(rows_per_time)) * np.int32(int(cell_count))
            + (impacted_rows_cp % np.int32(int(cell_count)))
        ).astype(cp.int32, copy=False)
        impacted_candidate_edge_count = int(
            cp.sum(row_ptr_cp[base_row_cp + np.int32(1)] - row_ptr_cp[base_row_cp]).item()
        )
    else:
        impacted_candidate_edge_count = 0

    repair_grid, repair_launch_count = _direct_epfd_repair_launch_grid(
        row_count=impacted_row_count
    )
    row_kernel[repair_grid, (GPU_DIRECT_REPAIR_BLOCK_SIZE, 1, 1)](
        cuda.as_cuda_array(impacted_rows_cp),
        *kernel_args_prefix,
        cuda.as_cuda_array(local_needs_repair_cp),
        cuda.as_cuda_array(local_row_slot_sat_cp),
        *kernel_args_suffix,
    )
    return {
        "impacted_row_count": int(impacted_row_count),
        "impacted_candidate_edge_count": int(impacted_candidate_edge_count),
        "repair_launch_count": int(repair_launch_count),
    }

def _finalize_beam_count_outputs_cp(
    *,
    sat_slot_used_cp: Any,
    output_sat_indices_cp: Any,
    sat_output_count: int,
    reserved_present_cp: Any | None = None,
) -> tuple[Any, Any, Any]:
    """
    Finalise beam-count outputs with correct full-network semantics.

    ``sat_slot_used_cp`` tracks realised service beams only in the current
    staged implementation. Reserved guard markers are reported separately via
    ``reserved_count_cp`` and must not be subtracted from the service counts.

    Returns
    -------
    counts_cp
        Compact per-output-satellite service-beam counts:
        - (T, S_out) without boresight
        - (T, sky, S_out) with boresight

    service_counts_full_cp
        Full-network per-satellite service-beam counts:
        - (T, S_full) without boresight
        - (T, sky, S_full) with boresight

    reserved_count_cp
        Per-time reserved boresight slot totals:
        - (T,) without boresight
        - (T, sky) with boresight
    """
    sat_slot_used_use = cp.asarray(sat_slot_used_cp, dtype=cp.int32)

    if reserved_present_cp is None:
        reserved_mask_cp = cp.zeros_like(sat_slot_used_use, dtype=cp.bool_)
    else:
        reserved_mask_cp = cp.asarray(reserved_present_cp, dtype=cp.bool_)

        if reserved_mask_cp.shape != sat_slot_used_use.shape:
            # Allow disabled guard-state placeholders such as shape (1,1,1),
            # but only when they are effectively all-false.
            if int(reserved_mask_cp.size) == 1 and not bool(cp.any(reserved_mask_cp).get()):
                reserved_mask_cp = cp.zeros_like(sat_slot_used_use, dtype=cp.bool_)
            else:
                raise ValueError(
                    "reserved_present_cp must match sat_slot_used_cp shape; "
                    f"got {tuple(reserved_mask_cp.shape)!r} vs {tuple(sat_slot_used_use.shape)!r}."
                )

    reserved_counts_full_cp = reserved_mask_cp.astype(cp.int32, copy=False)
    service_counts_full_cp = sat_slot_used_use.astype(cp.int32, copy=False)

    if sat_slot_used_use.ndim == 3:
        time_count = int(sat_slot_used_use.shape[0])
        sky_count = int(sat_slot_used_use.shape[1])
        counts_cp = (
            cp.take(service_counts_full_cp, output_sat_indices_cp, axis=2)
            if sat_output_count > 0
            else cp.zeros((time_count, sky_count, 0), dtype=cp.int32)
        )
        reserved_count_cp = reserved_counts_full_cp.sum(axis=2, dtype=cp.int32)
        return counts_cp, service_counts_full_cp, reserved_count_cp

    if sat_slot_used_use.ndim == 2:
        time_count = int(sat_slot_used_use.shape[0])
        counts_cp = (
            cp.take(service_counts_full_cp, output_sat_indices_cp, axis=1)
            if sat_output_count > 0
            else cp.zeros((time_count, 0), dtype=cp.int32)
        )
        reserved_count_cp = reserved_counts_full_cp.sum(axis=1, dtype=cp.int32)
        return counts_cp, service_counts_full_cp, reserved_count_cp

    raise ValueError(
        "sat_slot_used_cp must have shape (T, S_full) or (T, sky, S_full); "
        f"got {tuple(sat_slot_used_use.shape)!r}."
    )

def _pack_cell_center_first_pass_cp(
    library: GpuSatelliteLinkSelectionLibrary,
    *,
    assignments_cp: Any,
    cone_ok_cp: Any,
    selected_alpha_rad_cp: Any,
    selected_beta_rad_cp: Any,
    sat_output_index_cp: Any,
    output_sat_indices_cp: Any,
    sat_output_count: int,
    include_diagnostics: bool,
    include_full_sat_beam_counts_used: bool,
    exclude_cell: int | None = None,
    return_slot_maps: bool = False,
) -> dict[str, Any]:
    boresight_active = assignments_cp.ndim == 4
    time_count = int(assignments_cp.shape[0])
    sky_count = int(assignments_cp.shape[1]) if boresight_active else 1
    beam_shape = (
        (time_count, sky_count, sat_output_count, library.n_beam)
        if boresight_active
        else (time_count, sat_output_count, library.n_beam)
    )
    beam_idx_cp = cp.full(beam_shape, -1, dtype=cp.int32)
    beam_alpha_cp = cp.full(beam_shape, cp.nan, dtype=cp.float32)
    beam_beta_cp = cp.full(beam_shape, cp.nan, dtype=cp.float32)
    sat_shape = (
        (time_count, sky_count, library.sat_count)
        if boresight_active
        else (time_count, library.sat_count)
    )
    sat_slot_used_cp = cp.zeros(sat_shape, dtype=cp.int32)
    cell_slot_sat_cp = None
    cell_slot_beam_slot_cp = None
    if return_slot_maps:
        cell_slot_shape = assignments_cp.shape
        cell_slot_sat_cp = cp.full(cell_slot_shape, -1, dtype=cp.int32)
        cell_slot_beam_slot_cp = cp.full(cell_slot_shape, -1, dtype=cp.int32)
    edge_info = _gather_realized_direct_edges_cp(
        assignments_cp,
        cone_ok_cp,
        selected_alpha_rad_cp,
        selected_beta_rad_cp,
        exclude_cell=exclude_cell,
    )
    realized_count = int(edge_info["edge_linear"].size)
    if realized_count > 0:
        feasible_mask = edge_info["cone_ok"]
        feasible_pos = cp.nonzero(feasible_mask)[0].astype(cp.int64, copy=False)
        if int(feasible_pos.size) > 0:
            feasible_sats = edge_info["sat"][feasible_pos].astype(cp.int32, copy=False)
            if not boresight_active:
                group_key_cp = (
                    edge_info["t"][feasible_pos].astype(cp.int32, copy=False) * np.int32(int(library.sat_count))
                    + feasible_sats
                ).astype(cp.int32, copy=False)
                keep_order_cp, keep_slot_cp = _stable_group_rank_cp(
                    group_key_cp,
                    edge_info["edge_linear"][feasible_pos].astype(cp.int64, copy=False),
                )
                kept_feasible_pos = feasible_pos[keep_order_cp].astype(cp.int64, copy=False)
                _scatter_direct_edge_selection_cp(
                    edge_info=edge_info,
                    selected_positions_cp=kept_feasible_pos,
                    slot_cp=keep_slot_cp,
                    sat_output_index_cp=sat_output_index_cp,
                    n_links=library.n_links,
                    beam_idx_cp=beam_idx_cp,
                    beam_alpha_cp=beam_alpha_cp,
                    beam_beta_cp=beam_beta_cp,
                    cell_slot_sat_cp=cell_slot_sat_cp,
                    cell_slot_beam_slot_cp=cell_slot_beam_slot_cp,
                )
                sat_slot_used_cp[...] = _count_edges_per_satellite_group_cp(
                    group_key_cp=group_key_cp,
                    base_shape=sat_shape,
                )
                direct_kept_count_cp = _count_edges_per_time_axis_cp(
                    boresight_active=False,
                    t_cp=edge_info["t"][kept_feasible_pos],
                    sky_cp=None,
                    time_count=time_count,
                    sky_count=1,
                )
            else:
                group_key_cp = (
                    (edge_info["t"][feasible_pos].astype(cp.int32, copy=False) * np.int32(int(sky_count))
                     + edge_info["sky"][feasible_pos].astype(cp.int32, copy=False))
                    * np.int32(int(library.sat_count))
                    + feasible_sats
                ).astype(cp.int32, copy=False)
                group_limit_flat_cp = cp.full(
                    (time_count * sky_count * int(library.sat_count),),
                    np.int32(int(library.n_beam)),
                    dtype=cp.int32,
                )
                keep_local_cp, keep_slot_cp = _select_group_limited_edges_cp(
                    group_key_cp=group_key_cp,
                    order_key_cp=edge_info["edge_linear"][feasible_pos],
                    group_limit_flat_cp=group_limit_flat_cp,
                )
                kept_feasible_pos = feasible_pos[keep_local_cp].astype(cp.int64, copy=False)
                _scatter_direct_edge_selection_cp(
                    edge_info=edge_info,
                    selected_positions_cp=kept_feasible_pos,
                    slot_cp=keep_slot_cp,
                    sat_output_index_cp=sat_output_index_cp,
                    n_links=library.n_links,
                    beam_idx_cp=beam_idx_cp,
                    beam_alpha_cp=beam_alpha_cp,
                    beam_beta_cp=beam_beta_cp,
                    cell_slot_sat_cp=cell_slot_sat_cp,
                    cell_slot_beam_slot_cp=cell_slot_beam_slot_cp,
                )
                sat_slot_used_cp[...] = _count_edges_per_satellite_group_cp(
                    group_key_cp=group_key_cp[keep_local_cp],
                    base_shape=sat_shape,
                )
                direct_kept_count_cp = _count_edges_per_time_axis_cp(
                    boresight_active=boresight_active,
                    t_cp=edge_info["t"][kept_feasible_pos],
                    sky_cp=edge_info["sky"][kept_feasible_pos],
                    time_count=time_count,
                    sky_count=sky_count,
                )
        else:
            direct_kept_count_cp = (
                cp.zeros((time_count, sky_count), dtype=cp.int32)
                if boresight_active
                else cp.zeros((time_count,), dtype=cp.int32)
            )
        dropped_link_count_cp = (
            _count_edges_per_time_axis_cp(
                boresight_active=boresight_active,
                t_cp=edge_info["t"],
                sky_cp=(edge_info["sky"] if boresight_active else None),
                time_count=time_count,
                sky_count=sky_count,
            )
            - direct_kept_count_cp
        ).astype(cp.int32, copy=False)
    else:
        direct_kept_count_cp = (
            cp.zeros((time_count, sky_count), dtype=cp.int32)
            if boresight_active
            else cp.zeros((time_count,), dtype=cp.int32)
        )
        dropped_link_count_cp = cp.zeros_like(direct_kept_count_cp)

    counts_cp, service_counts_full_cp, reserved_count_cp = _finalize_beam_count_outputs_cp(
        sat_slot_used_cp=sat_slot_used_cp,
        output_sat_indices_cp=output_sat_indices_cp,
        sat_output_count=int(sat_output_count),
        reserved_present_cp=None,
    )

    result_cp: dict[str, Any] = {
        "beam_idx": beam_idx_cp,
        "beam_alpha_rad": beam_alpha_cp,
        "beam_beta_rad": beam_beta_cp,
        "sat_beam_counts_used": counts_cp,
    }
    if include_full_sat_beam_counts_used:
        result_cp["sat_beam_counts_used_full"] = service_counts_full_cp
    if return_slot_maps:
        result_cp["cell_slot_sat"] = cell_slot_sat_cp
        result_cp["cell_slot_beam_slot"] = cell_slot_beam_slot_cp
    if include_diagnostics:
        zeros_cp = cp.zeros_like(direct_kept_count_cp)
        result_cp["ras_retargeted_count"] = zeros_cp
        result_cp["ras_reserved_count"] = reserved_count_cp
        result_cp["direct_kept_count"] = direct_kept_count_cp
        result_cp["repaired_link_count"] = zeros_cp
        result_cp["dropped_link_count"] = dropped_link_count_cp
    return result_cp


def _build_base_packed_edge_info_cp(
    assignments_cp: Any,
    cone_ok_cp: Any,
    alpha_cp: Any,
    beta_cp: Any,
    *,
    base_cell_slot_beam_slot_cp: Any,
    exclude_cell: int | None = None,
) -> dict[str, Any]:
    edge_info = _gather_realized_direct_edges_cp(
        assignments_cp,
        cone_ok_cp,
        alpha_cp,
        beta_cp,
        exclude_cell=exclude_cell,
    )
    empty = {
        "edge_linear": cp.empty((0,), dtype=cp.int64),
        "t": cp.empty((0,), dtype=cp.int32),
        "cell": cp.empty((0,), dtype=cp.int32),
        "link": cp.empty((0,), dtype=cp.int32),
        "sat": cp.empty((0,), dtype=cp.int32),
        "cone_ok": cp.empty((0,), dtype=cp.bool_),
        "alpha": cp.empty((0,), dtype=cp.float32),
        "beta": cp.empty((0,), dtype=cp.float32),
        "beam_slot": cp.empty((0,), dtype=cp.int32),
    }
    if int(edge_info["sat"].size) <= 0:
        return empty

    feasible_pos_cp = cp.nonzero(edge_info["cone_ok"])[0].astype(cp.int64, copy=False)
    if int(feasible_pos_cp.size) <= 0:
        return empty

    t_cp = edge_info["t"][feasible_pos_cp].astype(cp.int32, copy=False)
    cell_cp = edge_info["cell"][feasible_pos_cp].astype(cp.int32, copy=False)
    link_cp = edge_info["link"][feasible_pos_cp].astype(cp.int32, copy=False)
    beam_slot_cp = base_cell_slot_beam_slot_cp[t_cp, cell_cp, link_cp].astype(cp.int32, copy=False)
    keep_mask_cp = beam_slot_cp >= 0
    if int(cp.count_nonzero(keep_mask_cp)) <= 0:
        return empty

    result: dict[str, Any] = {}
    for key in ("edge_linear", "t", "cell", "link", "sat", "cone_ok", "alpha", "beta"):
        result[key] = edge_info[key][feasible_pos_cp][keep_mask_cp]
    result["beam_slot"] = beam_slot_cp[keep_mask_cp].astype(cp.int32, copy=False)
    return result


def _build_realized_edge_reverse_index_cp(
    *,
    edge_info: dict[str, Any],
    time_count: int,
    sat_count: int,
) -> dict[str, Any]:
    row_count = int(time_count) * int(sat_count)
    row_ptr_cp = cp.zeros((row_count + 1,), dtype=cp.int64)
    edge_count = int(edge_info["sat"].size)
    if edge_count <= 0:
        return {
            "row_ptr": row_ptr_cp,
            "edge_pos": cp.empty((0,), dtype=cp.int64),
        }

    row_key_cp = (
        edge_info["t"].astype(cp.int32, copy=False) * np.int32(int(sat_count))
        + edge_info["sat"].astype(cp.int32, copy=False)
    ).astype(cp.int32, copy=False)
    row_ptr_cp[1:] = cp.cumsum(
        cp.bincount(row_key_cp, minlength=row_count).astype(cp.int64, copy=False),
        dtype=cp.int64,
    )
    order_cp, _ = _stable_group_rank_cp(
        row_key_cp,
        edge_info["edge_linear"].astype(cp.int64, copy=False),
    )
    return {
        "row_ptr": row_ptr_cp,
        "edge_pos": order_cp.astype(cp.int64, copy=False),
    }


def _csr_row_sat_pairs_cp(
    row_ptr_cp: Any,
    sat_idx_cp: Any,
) -> tuple[Any, Any]:
    total = int(sat_idx_cp.size)
    if total <= 0:
        return cp.empty((0,), dtype=cp.int32), cp.empty((0,), dtype=cp.int32)
    dest_idx_cp = cp.arange(total, dtype=cp.int64)
    row_idx_cp = cp.searchsorted(
        row_ptr_cp[1:],
        dest_idx_cp,
        side="right",
    ).astype(cp.int32, copy=False)
    return row_idx_cp, sat_idx_cp.astype(cp.int32, copy=False)


def _extract_impacted_edges_from_row_sat_pairs_cp(
    *,
    row_idx_cp: Any,
    sat_idx_cp: Any,
    reverse_index: dict[str, Any],
    base_edge_info: dict[str, Any],
    sky_count: int,
    sat_count: int,
    theta2_cell_mask_cp: Any | None = None,
) -> tuple[Any, Any]:
    pair_count = int(sat_idx_cp.size)
    if pair_count <= 0:
        return cp.empty((0,), dtype=cp.int32), cp.empty((0,), dtype=cp.int64)

    reverse_row_cp = (
        (row_idx_cp.astype(cp.int32, copy=False) // np.int32(int(sky_count))) * np.int32(int(sat_count))
        + sat_idx_cp.astype(cp.int32, copy=False)
    ).astype(cp.int32, copy=False)
    slice_row_ptr_cp, edge_pos_cp = _slice_csr_rows_cp(
        reverse_index["row_ptr"],
        reverse_index["edge_pos"],
        reverse_row_cp,
    )
    total = int(edge_pos_cp.size)
    if total <= 0:
        return cp.empty((0,), dtype=cp.int32), cp.empty((0,), dtype=cp.int64)

    dest_idx_cp = cp.arange(total, dtype=cp.int64)
    pair_ids_cp = cp.searchsorted(
        slice_row_ptr_cp[1:],
        dest_idx_cp,
        side="right",
    ).astype(cp.int32, copy=False)
    out_row_idx_cp = row_idx_cp[pair_ids_cp].astype(cp.int32, copy=False)
    out_edge_pos_cp = edge_pos_cp.astype(cp.int64, copy=False)
    if theta2_cell_mask_cp is not None:
        keep_mask_cp = theta2_cell_mask_cp[
            base_edge_info["cell"][out_edge_pos_cp].astype(cp.int32, copy=False)
        ]
        out_row_idx_cp = out_row_idx_cp[keep_mask_cp]
        out_edge_pos_cp = out_edge_pos_cp[keep_mask_cp]
    return out_row_idx_cp, out_edge_pos_cp


def _extract_impacted_edges_from_sparse_rows_cp(
    *,
    sparse_row_ptr_cp: Any,
    sparse_sat_idx_cp: Any,
    reverse_index: dict[str, Any],
    base_edge_info: dict[str, Any],
    sky_count: int,
    sat_count: int,
    theta2_cell_mask_cp: Any | None = None,
) -> tuple[Any, Any]:
    row_idx_cp, sat_idx_cp = _csr_row_sat_pairs_cp(sparse_row_ptr_cp, sparse_sat_idx_cp)
    return _extract_impacted_edges_from_row_sat_pairs_cp(
        row_idx_cp=row_idx_cp,
        sat_idx_cp=sat_idx_cp,
        reverse_index=reverse_index,
        base_edge_info=base_edge_info,
        sky_count=sky_count,
        sat_count=sat_count,
        theta2_cell_mask_cp=theta2_cell_mask_cp,
    )


def _dedupe_impacted_edge_pairs_cp(
    row_idx_cp: Any,
    edge_pos_cp: Any,
    *,
    base_edge_count: int,
) -> tuple[Any, Any]:
    pair_count = int(edge_pos_cp.size)
    if pair_count <= 0:
        return cp.empty((0,), dtype=cp.int32), cp.empty((0,), dtype=cp.int64)
    key_cp = (
        row_idx_cp.astype(cp.int64, copy=False) * np.int64(int(base_edge_count))
        + edge_pos_cp.astype(cp.int64, copy=False)
    )
    unique_key_cp = cp.unique(key_cp)
    row_out_cp = (unique_key_cp // np.int64(int(base_edge_count))).astype(cp.int32, copy=False)
    edge_out_cp = (unique_key_cp % np.int64(int(base_edge_count))).astype(cp.int64, copy=False)
    return row_out_cp, edge_out_cp


def _pack_1d_arrays_cp(
    parts: Iterable[Any],
    *,
    dtype: Any,
) -> Any:
    total = 0
    nonempty_parts: list[Any] = []
    for part in parts:
        if part is None:
            continue
        size = int(part.size)
        if size <= 0:
            continue
        nonempty_parts.append(part)
        total += size
    if total <= 0:
        return cp.empty((0,), dtype=dtype)
    packed_cp = cp.empty((int(total),), dtype=dtype)
    offset = 0
    for part in nonempty_parts:
        size = int(part.size)
        packed_cp[offset:offset + size] = cp.asarray(part, dtype=dtype)
        offset += size
    return packed_cp


def _dedupe_impacted_edge_pair_parts_cp(
    *,
    pair_parts: Iterable[tuple[Any, Any]],
    base_edge_count: int,
) -> tuple[Any, Any, dict[str, int]]:
    base_edge_count_i = max(int(base_edge_count), 1)
    key_parts: list[Any] = []
    raw_edge_count = 0
    for row_idx_cp, edge_pos_cp in pair_parts:
        size = int(edge_pos_cp.size)
        if size <= 0:
            continue
        raw_edge_count += size
        key_parts.append(
            row_idx_cp.astype(cp.int64, copy=False) * np.int64(base_edge_count_i)
            + edge_pos_cp.astype(cp.int64, copy=False)
        )
    unique_key_cp = cp.unique(
        _pack_1d_arrays_cp(key_parts, dtype=cp.int64)
    ) if raw_edge_count > 0 else cp.empty((0,), dtype=cp.int64)
    row_out_cp = (unique_key_cp // np.int64(base_edge_count_i)).astype(cp.int32, copy=False)
    edge_out_cp = (unique_key_cp % np.int64(base_edge_count_i)).astype(cp.int64, copy=False)
    return row_out_cp, edge_out_cp, {
        "raw_impacted_edge_count": int(raw_edge_count),
        "deduped_impacted_edge_count": int(unique_key_cp.size),
    }


def _dedupe_impacted_row_parts_cp(
    *,
    row_parts: Iterable[Any],
    cell_count: int,
    exclude_cell: int | None = None,
) -> tuple[Any, dict[str, int]]:
    packed_rows_cp = _pack_1d_arrays_cp(row_parts, dtype=cp.int32)
    raw_row_count = int(packed_rows_cp.size)
    if raw_row_count <= 0:
        return cp.empty((0,), dtype=cp.int32), {
            "raw_impacted_row_count": 0,
            "deduped_impacted_row_count": 0,
        }
    impacted_rows_cp = cp.unique(packed_rows_cp.astype(cp.int32, copy=False))
    if exclude_cell is not None:
        impacted_rows_cp = impacted_rows_cp[
            (impacted_rows_cp % np.int32(int(cell_count))) != np.int32(int(exclude_cell))
        ].astype(cp.int32, copy=False)
    return impacted_rows_cp, {
        "raw_impacted_row_count": int(raw_row_count),
        "deduped_impacted_row_count": int(impacted_rows_cp.size),
    }


def _expand_invalid_row_slots_cp(
    assignments_cp: Any,
    cone_ok_cp: Any,
    *,
    sky_count: int,
    exclude_cell: int | None = None,
) -> tuple[Any, Any]:
    invalid_mask_cp = cp.asarray((assignments_cp >= 0) & (~cone_ok_cp), dtype=cp.bool_)
    if exclude_cell is not None and 0 <= int(exclude_cell) < int(assignments_cp.shape[1]):
        invalid_mask_cp = invalid_mask_cp.copy()
        invalid_mask_cp[:, int(exclude_cell), :] = False
    invalid_t_cp, invalid_cell_cp, invalid_link_cp = cp.nonzero(invalid_mask_cp)
    invalid_count = int(invalid_t_cp.size)
    if invalid_count <= 0:
        return cp.empty((0,), dtype=cp.int32), cp.empty((0,), dtype=cp.int32)
    sky_axis_cp = cp.arange(int(sky_count), dtype=cp.int32)
    row_ids_cp = (
        (
            invalid_t_cp.astype(cp.int32, copy=False)[:, None] * np.int32(int(sky_count))
            + sky_axis_cp[None, :]
        ) * np.int32(int(assignments_cp.shape[1]))
        + invalid_cell_cp.astype(cp.int32, copy=False)[:, None]
    ).reshape(-1)
    slot_cp = cp.broadcast_to(
        invalid_link_cp.astype(cp.int32, copy=False)[:, None],
        (invalid_count, int(sky_count)),
    ).reshape(-1)
    return row_ids_cp.astype(cp.int32, copy=False), slot_cp.astype(cp.int32, copy=False)


def _build_sparse_impacted_row_state_cp(
    *,
    impacted_rows_cp: Any,
    base_cell_slot_sat_cp: Any,
    sky_count: int,
    cell_count: int,
    n_links: int,
    workspace: dict[str, Any] | None = None,
) -> tuple[Any, Any]:
    row_count = int(impacted_rows_cp.size)
    shape = (int(row_count), int(n_links))
    if workspace is None:
        local_row_slot_sat_cp = cp.full(shape, -1, dtype=cp.int32)
        local_needs_repair_cp = cp.zeros(shape, dtype=cp.bool_)
    else:
        local_row_slot_sat_full = workspace.get("local_row_slot_sat_cp")
        local_needs_repair_full = workspace.get("local_needs_repair_cp")
        if (
            local_row_slot_sat_full is None
            or local_row_slot_sat_full.dtype != cp.int32
            or local_row_slot_sat_full.ndim != 2
            or local_row_slot_sat_full.shape[0] < int(row_count)
            or local_row_slot_sat_full.shape[1] != int(n_links)
        ):
            local_row_slot_sat_full = cp.full(shape, -1, dtype=cp.int32)
            workspace["local_row_slot_sat_cp"] = local_row_slot_sat_full
        if (
            local_needs_repair_full is None
            or local_needs_repair_full.dtype != cp.bool_
            or local_needs_repair_full.ndim != 2
            or local_needs_repair_full.shape[0] < int(row_count)
            or local_needs_repair_full.shape[1] != int(n_links)
        ):
            local_needs_repair_full = cp.zeros(shape, dtype=cp.bool_)
            workspace["local_needs_repair_cp"] = local_needs_repair_full
        local_row_slot_sat_cp = local_row_slot_sat_full[: int(row_count), :]
        local_needs_repair_cp = local_needs_repair_full[: int(row_count), :]
        if int(row_count) > 0:
            local_needs_repair_cp[...] = False
    if row_count <= 0:
        return local_needs_repair_cp, local_row_slot_sat_cp
    rows_per_time = int(sky_count) * int(cell_count)
    t_cp = (impacted_rows_cp.astype(cp.int32, copy=False) // np.int32(rows_per_time)).astype(cp.int32, copy=False)
    cell_cp = (impacted_rows_cp.astype(cp.int32, copy=False) % np.int32(int(cell_count))).astype(cp.int32, copy=False)
    local_row_slot_sat_cp[...] = base_cell_slot_sat_cp[t_cp, cell_cp, :].astype(cp.int32, copy=False)
    return local_needs_repair_cp, local_row_slot_sat_cp


def _allocate_direct_guard_state_cp(
    *,
    shape: tuple[int, ...],
    enabled: bool,
) -> tuple[Any, Any, Any]:
    """
    Allocate guard-state tensors.

    When enabled=False, returns tiny dummy placeholders to avoid allocating
    full (T, sky, S) buffers. These placeholders must not be passed to logic
    that requires exact sat_slot_used_cp shape matching; use None for that.
    """
    if enabled:
        return (
            cp.full(shape, cp.nan, dtype=cp.float32),
            cp.full(shape, cp.nan, dtype=cp.float32),
            cp.zeros(shape, dtype=cp.bool_),
        )
    dummy_shape = tuple(1 for _ in shape)
    return (
        cp.asarray(np.full(dummy_shape, np.nan, dtype=np.float32)),
        cp.asarray(np.full(dummy_shape, np.nan, dtype=np.float32)),
        cp.asarray(np.zeros(dummy_shape, dtype=np.bool_)),
    )


def _estimate_local_sat_count_peak_cp(*sat_arrays: Any) -> int:
    valid_parts: list[Any] = []
    for sat_array in sat_arrays:
        if sat_array is None:
            continue
        sat_cp = cp.asarray(sat_array, dtype=cp.int32)
        if int(sat_cp.size) <= 0:
            continue
        valid_cp = sat_cp[sat_cp >= np.int32(0)].astype(cp.int32, copy=False)
        if int(valid_cp.size) > 0:
            valid_parts.append(valid_cp)
    if not valid_parts:
        return 0
    if len(valid_parts) == 1:
        return int(cp.unique(valid_parts[0]).size)
    return int(cp.unique(cp.concatenate(valid_parts, axis=0)).size)


def _apply_sparse_impacted_edge_removals_cp(
    *,
    impacted_rows_cp: Any,
    remove_row_ids_cp: Any,
    remove_edge_pos_cp: Any,
    base_edge_info: dict[str, Any],
    local_needs_repair_cp: Any,
    local_row_slot_sat_cp: Any,
    sat_output_index_cp: Any,
    beam_idx_cp: Any,
    beam_alpha_cp: Any,
    beam_beta_cp: Any,
    sat_slot_used_cp: Any,
    direct_kept_count_cp: Any,
    sky_count: int,
    cell_count: int,
    sat_count: int,
) -> int:
    remove_count = int(remove_edge_pos_cp.size)
    if remove_count <= 0 or int(impacted_rows_cp.size) <= 0:
        return 0

    rows_per_time = int(sky_count) * int(cell_count)
    row_ids_cp = remove_row_ids_cp.astype(cp.int32, copy=False)
    edge_pos_cp = remove_edge_pos_cp.astype(cp.int64, copy=False)
    t_cp = (row_ids_cp // np.int32(rows_per_time)).astype(cp.int32, copy=False)
    rem_cp = row_ids_cp - t_cp * np.int32(rows_per_time)
    sky_cp = (rem_cp // np.int32(int(cell_count))).astype(cp.int32, copy=False)
    link_cp = base_edge_info["link"][edge_pos_cp].astype(cp.int32, copy=False)
    sat_cp = base_edge_info["sat"][edge_pos_cp].astype(cp.int32, copy=False)
    beam_slot_cp = base_edge_info["beam_slot"][edge_pos_cp].astype(cp.int32, copy=False)
    local_idx_cp = cp.searchsorted(
        impacted_rows_cp.astype(cp.int32, copy=False),
        row_ids_cp,
        side="left",
    ).astype(cp.int32, copy=False)
    valid_cp = local_row_slot_sat_cp[local_idx_cp, link_cp] == sat_cp
    if int(cp.count_nonzero(valid_cp)) <= 0:
        return 0

    valid_local_idx_cp = local_idx_cp[valid_cp].astype(cp.int32, copy=False)
    valid_link_cp = link_cp[valid_cp].astype(cp.int32, copy=False)
    local_row_slot_sat_cp[valid_local_idx_cp, valid_link_cp] = np.int32(-1)
    local_needs_repair_cp[valid_local_idx_cp, valid_link_cp] = True

    valid_t_cp = t_cp[valid_cp].astype(cp.int32, copy=False)
    valid_sky_cp = sky_cp[valid_cp].astype(cp.int32, copy=False)
    valid_sat_cp = sat_cp[valid_cp].astype(cp.int32, copy=False)
    valid_slot_cp = beam_slot_cp[valid_cp].astype(cp.int32, copy=False)
    sat_flat_key_cp = (
        (
            valid_t_cp * np.int32(int(sky_count))
            + valid_sky_cp
        ) * np.int32(int(sat_count))
        + valid_sat_cp
    ).astype(cp.int64, copy=False)
    _apply_flat_count_delta_cp(
        sat_slot_used_cp.reshape(-1),
        key_cp=sat_flat_key_cp,
        delta=np.int32(-1),
    )
    _apply_flat_count_delta_cp(
        direct_kept_count_cp.reshape(-1),
        key_cp=(
            valid_t_cp * np.int32(int(sky_count)) + valid_sky_cp
        ).astype(cp.int64, copy=False),
        delta=np.int32(-1),
    )

    sat_out_cp = sat_output_index_cp[valid_sat_cp].astype(cp.int32, copy=False)
    valid_out_cp = sat_out_cp >= 0
    if int(cp.count_nonzero(valid_out_cp)) > 0:
        beam_idx_cp[
            valid_t_cp[valid_out_cp],
            valid_sky_cp[valid_out_cp],
            sat_out_cp[valid_out_cp],
            valid_slot_cp[valid_out_cp],
        ] = np.int32(-1)
        beam_alpha_cp[
            valid_t_cp[valid_out_cp],
            valid_sky_cp[valid_out_cp],
            sat_out_cp[valid_out_cp],
            valid_slot_cp[valid_out_cp],
        ] = np.float32(np.nan)
        beam_beta_cp[
            valid_t_cp[valid_out_cp],
            valid_sky_cp[valid_out_cp],
            sat_out_cp[valid_out_cp],
            valid_slot_cp[valid_out_cp],
        ] = np.float32(np.nan)
    return int(cp.count_nonzero(valid_cp))


def _select_reserved_edge_removals_cp(
    *,
    sky_row_idx_cp: Any,
    edge_pos_cp: Any,
    base_edge_info: dict[str, Any],
    reserved_present_cp: Any,
    reserved_alpha_cp: Any,
    reserved_beta_cp: Any,
    sky_count: int,
    sat_count: int,
    n_beam: int,
    use_ras_guard: bool,
    ras_guard_cos: np.float32,
) -> tuple[Any, Any]:
    edge_count = int(edge_pos_cp.size)
    if edge_count <= 0:
        return cp.empty((0,), dtype=cp.int32), cp.empty((0,), dtype=cp.int64)

    sky_row_idx_cp = sky_row_idx_cp.astype(cp.int32, copy=False)
    edge_pos_cp = edge_pos_cp.astype(cp.int64, copy=False)
    t_cp = (sky_row_idx_cp // np.int32(int(sky_count))).astype(cp.int32, copy=False)
    sky_cp = (sky_row_idx_cp % np.int32(int(sky_count))).astype(cp.int32, copy=False)
    sat_cp = base_edge_info["sat"][edge_pos_cp].astype(cp.int32, copy=False)
    guard_conflict_cp = cp.zeros((edge_count,), dtype=cp.bool_)
    if use_ras_guard:
        alpha_ras_cp = reserved_alpha_cp[t_cp, sky_cp, sat_cp].astype(cp.float32, copy=False)
        beta_ras_cp = reserved_beta_cp[t_cp, sky_cp, sat_cp].astype(cp.float32, copy=False)
        alpha_cp = base_edge_info["alpha"][edge_pos_cp].astype(cp.float32, copy=False)
        beta_cp = base_edge_info["beta"][edge_pos_cp].astype(cp.float32, copy=False)
        guard_valid_cp = (
            reserved_present_cp[t_cp, sky_cp, sat_cp]
            & cp.isfinite(alpha_ras_cp)
            & cp.isfinite(beta_ras_cp)
            & cp.isfinite(alpha_cp)
            & cp.isfinite(beta_cp)
        )
        if int(cp.count_nonzero(guard_valid_cp)) > 0:
            cos_da_cp = cp.cos(alpha_ras_cp - alpha_cp)
            cos_gamma_cp = cp.cos(beta_ras_cp) * cp.cos(beta_cp)
            cos_gamma_cp += cp.sin(beta_ras_cp) * cp.sin(beta_cp) * cos_da_cp
            guard_conflict_cp = guard_valid_cp & (cos_gamma_cp > np.float32(ras_guard_cos))

    keep_mask_cp = cp.zeros((edge_count,), dtype=cp.bool_)
    candidate_pos_cp = cp.nonzero(~guard_conflict_cp)[0].astype(cp.int64, copy=False)
    if int(candidate_pos_cp.size) > 0:
        group_key_cp = (
            (
                t_cp[candidate_pos_cp].astype(cp.int32, copy=False) * np.int32(int(sky_count))
                + sky_cp[candidate_pos_cp].astype(cp.int32, copy=False)
            ) * np.int32(int(sat_count))
            + sat_cp[candidate_pos_cp].astype(cp.int32, copy=False)
        ).astype(cp.int32, copy=False)
        group_limit_flat_cp = cp.maximum(
            np.int32(0),
            np.int32(int(n_beam))
            - reserved_present_cp.reshape(-1).astype(cp.int32, copy=False),
        ).astype(cp.int32, copy=False)
        keep_local_cp, _ = _select_group_limited_edges_cp(
            group_key_cp=group_key_cp,
            order_key_cp=base_edge_info["edge_linear"][edge_pos_cp[candidate_pos_cp]].astype(cp.int64, copy=False),
            group_limit_flat_cp=group_limit_flat_cp,
        )
        if int(keep_local_cp.size) > 0:
            keep_mask_cp[candidate_pos_cp[keep_local_cp].astype(cp.int64, copy=False)] = True

    remove_mask_cp = ~keep_mask_cp
    return (
        sky_row_idx_cp[remove_mask_cp].astype(cp.int32, copy=False),
        edge_pos_cp[remove_mask_cp].astype(cp.int64, copy=False),
    )


def _scatter_reserved_ras_beams_cp(
    *,
    reserved_present_cp: Any,
    reserved_alpha_cp: Any,
    reserved_beta_cp: Any,
    sat_output_index_cp: Any,
    sat_slot_used_cp: Any,
    beam_idx_cp: Any,
    beam_alpha_cp: Any,
    beam_beta_cp: Any,
    sky_count: int,
    sat_count: int,
) -> int:
    """
    Scatter virtual reserved RAS guard slots into the compact beam tables.

    Important semantics:
    - These slots are encoded as beam_idx == -2 for guard/diagnostic purposes.
    - They do NOT increment sat_slot_used_cp.
    - sat_slot_used_cp remains the count of realised service beams only.
    """
    t_cp, sky_cp, sat_cp = cp.nonzero(reserved_present_cp)
    reserved_count = int(sat_cp.size)
    if reserved_count <= 0:
        return 0

    group_key_cp = (
        (
            t_cp.astype(cp.int32, copy=False) * np.int32(int(sky_count))
            + sky_cp.astype(cp.int32, copy=False)
        ) * np.int32(int(sat_count))
        + sat_cp.astype(cp.int32, copy=False)
    ).astype(cp.int32, copy=False)

    # Place the virtual guard marker after the currently realised service beams.
    # This uses sat_slot_used_cp only as a placement baseline, not as something
    # to be modified by the reservation itself.
    sat_slot_used_flat_cp = sat_slot_used_cp.reshape(-1)
    order_cp, rank_cp = _stable_group_rank_cp(
        group_key_cp,
        cp.arange(reserved_count, dtype=cp.int64),
    )
    slot_cp = cp.empty((reserved_count,), dtype=cp.int32)
    slot_cp[order_cp] = (
        sat_slot_used_flat_cp[group_key_cp[order_cp]].astype(cp.int32, copy=False)
        + rank_cp.astype(cp.int32, copy=False)
    )

    sat_out_cp = sat_output_index_cp[
        sat_cp.astype(cp.int32, copy=False)
    ].astype(cp.int32, copy=False)
    valid_out_cp = sat_out_cp >= 0
    if int(cp.count_nonzero(valid_out_cp)) > 0:
        beam_idx_cp[
            t_cp[valid_out_cp],
            sky_cp[valid_out_cp],
            sat_out_cp[valid_out_cp],
            slot_cp[valid_out_cp],
        ] = np.int32(-2)
        beam_alpha_cp[
            t_cp[valid_out_cp],
            sky_cp[valid_out_cp],
            sat_out_cp[valid_out_cp],
            slot_cp[valid_out_cp],
        ] = reserved_alpha_cp[
            t_cp[valid_out_cp],
            sky_cp[valid_out_cp],
            sat_cp[valid_out_cp],
        ].astype(cp.float32, copy=False)
        beam_beta_cp[
            t_cp[valid_out_cp],
            sky_cp[valid_out_cp],
            sat_out_cp[valid_out_cp],
            slot_cp[valid_out_cp],
        ] = reserved_beta_cp[
            t_cp[valid_out_cp],
            sky_cp[valid_out_cp],
            sat_cp[valid_out_cp],
        ].astype(cp.float32, copy=False)

    return reserved_count


def _compact_beam_slots_boresight_cp(
    beam_idx_cp: Any,
    beam_alpha_cp: Any,
    beam_beta_cp: Any,
) -> None:
    if beam_idx_cp.ndim != 4:
        return
    total_group_count = int(np.prod(beam_idx_cp.shape[:3], dtype=np.int64))
    if total_group_count <= 0 or int(beam_idx_cp.shape[-1]) <= 1:
        return
    block = 128
    grid = (total_group_count + block - 1) // block
    _compact_beam_slots_boresight_kernel[grid, block](
        cuda.as_cuda_array(beam_idx_cp),
        cuda.as_cuda_array(beam_alpha_cp),
        cuda.as_cuda_array(beam_beta_cp),
    )


def _compute_realized_boresight_forbidden_cp(
    edge_info: dict[str, Any],
    *,
    boresight_sparse_slab: dict[str, Any],
    theta2_cell_mask_cp: Any,
    sky_count: int,
) -> Any:
    edge_count = int(edge_info["sat"].size)
    if edge_count <= 0:
        return cp.zeros((0,), dtype=cp.bool_)
    forbidden_cp = cp.zeros((edge_count,), dtype=cp.bool_)
    block = 128
    grid = (edge_count + block - 1) // block
    _mark_realized_boresight_forbidden_kernel[grid, block](
        cuda.as_cuda_array(edge_info["t"].astype(cp.int32, copy=False)),
        cuda.as_cuda_array(edge_info["sky"].astype(cp.int32, copy=False)),
        cuda.as_cuda_array(edge_info["cell"].astype(cp.int32, copy=False)),
        cuda.as_cuda_array(edge_info["sat"].astype(cp.int32, copy=False)),
        int(sky_count),
        cuda.as_cuda_array(boresight_sparse_slab["theta1_row_ptr"]),
        cuda.as_cuda_array(boresight_sparse_slab["theta1_sat_idx"]),
        cuda.as_cuda_array(boresight_sparse_slab["theta2_row_ptr"]),
        cuda.as_cuda_array(boresight_sparse_slab["theta2_sat_idx"]),
        cuda.as_cuda_array(theta2_cell_mask_cp),
        cuda.as_cuda_array(forbidden_cp),
    )
    return forbidden_cp


def _finalize_ras_station_parallel_cp(
    library: GpuSatelliteLinkSelectionLibrary,
    *,
    assignments_cp: Any,
    cone_ok_cp: Any,
    selected_alpha_rad_cp: Any,
    selected_beta_rad_cp: Any,
    direct_candidate_slab: dict[str, Any],
    sat_output_index_cp: Any,
    output_sat_indices_cp: Any,
    sat_output_count: int,
    ras_cell_index: int,
    ras_elevation_deg_cp: Any,
    ras_alpha_rad_cp: Any,
    ras_beta_rad_cp: Any,
    ras_sat_axis_is_compact: bool,
    sat_beta_max_rad_cp: Any,
    beta_tol_rad: np.float32,
    use_ras_guard: bool,
    ras_guard_cos: np.float32,
    include_diagnostics: bool,
    include_full_sat_beam_counts_used: bool,
    boresight_sparse_slab: dict[str, Any] | None = None,
    theta2_cell_mask_cp: Any | None = None,
    working_memory_budget_bytes: int | None = None,
    finalize_workspace: dict[str, Any] | None = None,
    debug_direct_epfd: bool = False,
) -> dict[str, Any]:
    boresight_active = boresight_sparse_slab is not None
    time_count = int(assignments_cp.shape[0])
    sky_count = int(boresight_sparse_slab["theta1_row_ptr"].shape[0] - 1) // max(time_count, 1) if boresight_active else 1
    if boresight_active:
        if theta2_cell_mask_cp is None:
            theta2_cell_mask_cp = cp.zeros((library.cell_count,), dtype=cp.bool_)
        base_pack = _pack_cell_center_first_pass_cp(
            library,
            assignments_cp=assignments_cp,
            cone_ok_cp=cone_ok_cp,
            selected_alpha_rad_cp=selected_alpha_rad_cp,
            selected_beta_rad_cp=selected_beta_rad_cp,
            sat_output_index_cp=sat_output_index_cp,
            output_sat_indices_cp=output_sat_indices_cp,
            sat_output_count=sat_output_count,
            include_diagnostics=True,
            include_full_sat_beam_counts_used=True,
            exclude_cell=int(ras_cell_index),
            return_slot_maps=True,
        )
        beam_idx_cp = cp.full((time_count, sky_count, sat_output_count, library.n_beam), -1, dtype=cp.int32)
        beam_alpha_cp = cp.full(beam_idx_cp.shape, cp.nan, dtype=cp.float32)
        beam_beta_cp = cp.full(beam_idx_cp.shape, cp.nan, dtype=cp.float32)
        beam_idx_cp[...] = base_pack["beam_idx"][:, None, :, :]
        beam_alpha_cp[...] = base_pack["beam_alpha_rad"][:, None, :, :]
        beam_beta_cp[...] = base_pack["beam_beta_rad"][:, None, :, :]
        sat_slot_used_cp = cp.zeros((time_count, sky_count, library.sat_count), dtype=cp.int32)
        sat_slot_used_cp[...] = base_pack["sat_beam_counts_used_full"][:, None, :]
        ras_retargeted_count_cp = cp.zeros((time_count, sky_count), dtype=cp.int32)
        direct_kept_count_cp = cp.zeros((time_count, sky_count), dtype=cp.int32)
        direct_kept_count_cp[...] = base_pack["direct_kept_count"][:, None]
        repaired_link_count_cp = cp.zeros((time_count, sky_count), dtype=cp.int32)
        dropped_link_count_cp = cp.zeros((time_count, sky_count), dtype=cp.int32)
        reserved_alpha_cp = cp.full((time_count, sky_count, library.sat_count), cp.nan, dtype=cp.float32)
        reserved_beta_cp = cp.full((time_count, sky_count, library.sat_count), cp.nan, dtype=cp.float32)
        reserved_present_cp = cp.zeros((time_count, sky_count, library.sat_count), dtype=cp.bool_)
        ras_row_slot_sat_cp = cp.full((time_count, sky_count, library.n_links), -1, dtype=cp.int32)

        _select_ras_row_reserved_boresight_kernel[(time_count, sky_count, 1), (1, 1, 1)](
            cuda.as_cuda_array(assignments_cp),
            cuda.as_cuda_array(direct_candidate_slab["row_ptr"]),
            cuda.as_cuda_array(direct_candidate_slab["candidate_sat"]),
            cuda.as_cuda_array(ras_elevation_deg_cp),
            cuda.as_cuda_array(ras_alpha_rad_cp),
            cuda.as_cuda_array(ras_beta_rad_cp),
            cuda.as_cuda_array(sat_output_index_cp),
            bool(ras_sat_axis_is_compact),
            cuda.as_cuda_array(library.sat_min_elev_cp),
            cuda.as_cuda_array(sat_beta_max_rad_cp),
            cuda.as_cuda_array(boresight_sparse_slab["theta1_row_ptr"]),
            cuda.as_cuda_array(boresight_sparse_slab["theta1_sat_idx"]),
            cuda.as_cuda_array(boresight_sparse_slab["theta2_row_ptr"]),
            cuda.as_cuda_array(boresight_sparse_slab["theta2_sat_idx"]),
            cuda.as_cuda_array(theta2_cell_mask_cp),
            int(ras_cell_index),
            int(sky_count),
            int(library.n_links),
            bool(library.use_cone_check),
            np.float32(beta_tol_rad),
            cuda.as_cuda_array(ras_row_slot_sat_cp),
            cuda.as_cuda_array(reserved_alpha_cp),
            cuda.as_cuda_array(reserved_beta_cp),
            cuda.as_cuda_array(reserved_present_cp),
            cuda.as_cuda_array(ras_retargeted_count_cp),
            cuda.as_cuda_array(dropped_link_count_cp),
        )
        _debug_cuda_sync_cp(enabled=bool(debug_direct_epfd), stage="ras_station.retarget")

        base_edge_info = _build_base_packed_edge_info_cp(
            assignments_cp,
            cone_ok_cp,
            selected_alpha_rad_cp,
            selected_beta_rad_cp,
            base_cell_slot_beam_slot_cp=base_pack["cell_slot_beam_slot"],
            exclude_cell=int(ras_cell_index),
        )
        reverse_index = _build_realized_edge_reverse_index_cp(
            edge_info=base_edge_info,
            time_count=time_count,
            sat_count=int(library.sat_count),
        )
        base_edge_count = int(base_edge_info["sat"].size)

        compaction_t0 = time.perf_counter()
        invalid_row_ids_cp, invalid_slot_cp = _expand_invalid_row_slots_cp(
            assignments_cp,
            cone_ok_cp,
            sky_count=int(sky_count),
            exclude_cell=int(ras_cell_index),
        )
        theta1_sky_row_cp, theta1_edge_pos_cp = _extract_impacted_edges_from_sparse_rows_cp(
            sparse_row_ptr_cp=boresight_sparse_slab["theta1_row_ptr"],
            sparse_sat_idx_cp=boresight_sparse_slab["theta1_sat_idx"],
            reverse_index=reverse_index,
            base_edge_info=base_edge_info,
            sky_count=int(sky_count),
            sat_count=int(library.sat_count),
        )
        theta2_sky_row_cp, theta2_edge_pos_cp = _extract_impacted_edges_from_sparse_rows_cp(
            sparse_row_ptr_cp=boresight_sparse_slab["theta2_row_ptr"],
            sparse_sat_idx_cp=boresight_sparse_slab["theta2_sat_idx"],
            reverse_index=reverse_index,
            base_edge_info=base_edge_info,
            sky_count=int(sky_count),
            sat_count=int(library.sat_count),
            theta2_cell_mask_cp=theta2_cell_mask_cp,
        )
        reserved_t_cp, reserved_sky_cp, reserved_sat_cp = cp.nonzero(reserved_present_cp)
        reserved_sky_row_idx_cp = (
            reserved_t_cp.astype(cp.int32, copy=False) * np.int32(int(sky_count))
            + reserved_sky_cp.astype(cp.int32, copy=False)
        ).astype(cp.int32, copy=False)
        reserved_edge_sky_row_cp, reserved_edge_pos_cp = _extract_impacted_edges_from_row_sat_pairs_cp(
            row_idx_cp=reserved_sky_row_idx_cp,
            sat_idx_cp=reserved_sat_cp.astype(cp.int32, copy=False),
            reverse_index=reverse_index,
            base_edge_info=base_edge_info,
            sky_count=int(sky_count),
            sat_count=int(library.sat_count),
        )
        reserved_remove_sky_row_cp, reserved_remove_edge_pos_cp = _select_reserved_edge_removals_cp(
            sky_row_idx_cp=reserved_edge_sky_row_cp,
            edge_pos_cp=reserved_edge_pos_cp,
            base_edge_info=base_edge_info,
            reserved_present_cp=reserved_present_cp,
            reserved_alpha_cp=reserved_alpha_cp,
            reserved_beta_cp=reserved_beta_cp,
            sky_count=int(sky_count),
            sat_count=int(library.sat_count),
            n_beam=int(library.n_beam),
            use_ras_guard=bool(use_ras_guard),
            ras_guard_cos=np.float32(ras_guard_cos),
        )

        remove_sky_row_cp, remove_edge_pos_cp, edge_compaction_stats = (
            _dedupe_impacted_edge_pair_parts_cp(
                pair_parts=(
                    (theta1_sky_row_cp, theta1_edge_pos_cp),
                    (theta2_sky_row_cp, theta2_edge_pos_cp),
                    (reserved_remove_sky_row_cp, reserved_remove_edge_pos_cp),
                ),
                base_edge_count=max(base_edge_count, 1),
            )
        )
        remove_row_ids_cp = (
            remove_sky_row_cp.astype(cp.int32, copy=False) * np.int32(int(library.cell_count))
            + base_edge_info["cell"][remove_edge_pos_cp].astype(cp.int32, copy=False)
        ).astype(cp.int32, copy=False) if int(remove_edge_pos_cp.size) > 0 else cp.empty((0,), dtype=cp.int32)

        impacted_rows_cp, row_compaction_stats = _dedupe_impacted_row_parts_cp(
            row_parts=(invalid_row_ids_cp, remove_row_ids_cp),
            cell_count=int(library.cell_count),
            exclude_cell=int(ras_cell_index),
        )
        sparse_row_workspace = None
        if finalize_workspace is not None:
            sparse_row_workspace = finalize_workspace.setdefault("ras_station_sparse_state", {})
        local_needs_repair_cp, local_row_slot_sat_cp = _build_sparse_impacted_row_state_cp(
            impacted_rows_cp=impacted_rows_cp,
            base_cell_slot_sat_cp=base_pack["cell_slot_sat"],
            sky_count=int(sky_count),
            cell_count=int(library.cell_count),
            n_links=int(library.n_links),
            workspace=sparse_row_workspace,
        )
        compaction_seconds = max(time.perf_counter() - compaction_t0, 0.0)
        if int(invalid_row_ids_cp.size) > 0 and int(impacted_rows_cp.size) > 0:
            valid_invalid_mask_cp = (
                (invalid_row_ids_cp % np.int32(int(library.cell_count))) != np.int32(int(ras_cell_index))
            )
            invalid_local_idx_cp = cp.searchsorted(
                impacted_rows_cp.astype(cp.int32, copy=False),
                invalid_row_ids_cp[valid_invalid_mask_cp].astype(cp.int32, copy=False),
                side="left",
            ).astype(cp.int32, copy=False)
            local_needs_repair_cp[
                invalid_local_idx_cp,
                invalid_slot_cp[valid_invalid_mask_cp].astype(cp.int32, copy=False),
            ] = True

        removed_edge_count = _apply_sparse_impacted_edge_removals_cp(
            impacted_rows_cp=impacted_rows_cp,
            remove_row_ids_cp=remove_row_ids_cp,
            remove_edge_pos_cp=remove_edge_pos_cp,
            base_edge_info=base_edge_info,
            local_needs_repair_cp=local_needs_repair_cp,
            local_row_slot_sat_cp=local_row_slot_sat_cp,
            sat_output_index_cp=sat_output_index_cp,
            beam_idx_cp=beam_idx_cp,
            beam_alpha_cp=beam_alpha_cp,
            beam_beta_cp=beam_beta_cp,
            sat_slot_used_cp=sat_slot_used_cp,
            direct_kept_count_cp=direct_kept_count_cp,
            sky_count=int(sky_count),
            cell_count=int(library.cell_count),
            sat_count=int(library.sat_count),
        )
        _compact_beam_slots_boresight_cp(
            beam_idx_cp,
            beam_alpha_cp,
            beam_beta_cp,
        )
        _debug_cuda_sync_cp(enabled=bool(debug_direct_epfd), stage="ras_station.compact_beams")

        reserved_scattered_count = _scatter_reserved_ras_beams_cp(
            reserved_present_cp=reserved_present_cp,
            reserved_alpha_cp=reserved_alpha_cp,
            reserved_beta_cp=reserved_beta_cp,
            sat_output_index_cp=sat_output_index_cp,
            sat_slot_used_cp=sat_slot_used_cp,
            beam_idx_cp=beam_idx_cp,
            beam_alpha_cp=beam_alpha_cp,
            beam_beta_cp=beam_beta_cp,
            sky_count=int(sky_count),
            sat_count=int(library.sat_count),
        )
        repair_stats = _launch_direct_epfd_sparse_row_repairs_cp(
            impacted_rows_cp=impacted_rows_cp,
            local_needs_repair_cp=local_needs_repair_cp,
            local_row_slot_sat_cp=local_row_slot_sat_cp,
            row_ptr_cp=direct_candidate_slab["row_ptr"],
            row_kernel=_repair_direct_epfd_sparse_rows_boresight_kernel,
            kernel_args_prefix=(
                cuda.as_cuda_array(direct_candidate_slab["row_ptr"]),
                cuda.as_cuda_array(direct_candidate_slab["candidate_sat"]),
                cuda.as_cuda_array(direct_candidate_slab["candidate_alpha_rad"]),
                cuda.as_cuda_array(direct_candidate_slab["candidate_beta_rad"]),
                cuda.as_cuda_array(boresight_sparse_slab["theta1_row_ptr"]),
                cuda.as_cuda_array(boresight_sparse_slab["theta1_sat_idx"]),
                cuda.as_cuda_array(boresight_sparse_slab["theta2_row_ptr"]),
                cuda.as_cuda_array(boresight_sparse_slab["theta2_sat_idx"]),
                cuda.as_cuda_array(theta2_cell_mask_cp),
                cuda.as_cuda_array(sat_beta_max_rad_cp),
                int(sky_count),
                int(library.cell_count),
                int(library.n_links),
                int(library.n_beam),
                bool(library.use_cone_check),
                np.float32(beta_tol_rad),
                bool(use_ras_guard),
                np.float32(ras_guard_cos),
                cuda.as_cuda_array(sat_output_index_cp),
            ),
            kernel_args_suffix=(
                cuda.as_cuda_array(sat_slot_used_cp),
                cuda.as_cuda_array(reserved_alpha_cp),
                cuda.as_cuda_array(reserved_beta_cp),
                cuda.as_cuda_array(reserved_present_cp),
                cuda.as_cuda_array(beam_idx_cp),
                cuda.as_cuda_array(beam_alpha_cp),
                cuda.as_cuda_array(beam_beta_cp),
                cuda.as_cuda_array(repaired_link_count_cp),
                cuda.as_cuda_array(dropped_link_count_cp),
            ),
            sky_count=int(sky_count),
            cell_count=int(library.cell_count),
            debug_direct_epfd=bool(debug_direct_epfd),
        )
        _debug_cuda_sync_cp(enabled=bool(debug_direct_epfd), stage="ras_station.repair_rows")
        counts_cp, service_counts_full_cp, reserved_count_cp = _finalize_beam_count_outputs_cp(
            sat_slot_used_cp=sat_slot_used_cp,
            output_sat_indices_cp=output_sat_indices_cp,
            sat_output_count=int(sat_output_count),
            reserved_present_cp=reserved_present_cp,
        )

        result_cp: dict[str, Any] = {
            "beam_idx": beam_idx_cp,
            "beam_alpha_rad": beam_alpha_cp,
            "beam_beta_rad": beam_beta_cp,
            "sat_beam_counts_used": counts_cp,
        }
        if include_full_sat_beam_counts_used:
            result_cp["sat_beam_counts_used_full"] = service_counts_full_cp
        if include_diagnostics:
            result_cp["ras_retargeted_count"] = ras_retargeted_count_cp
            result_cp["ras_reserved_count"] = reserved_count_cp
            result_cp["direct_kept_count"] = direct_kept_count_cp
            result_cp["repaired_link_count"] = repaired_link_count_cp
            result_cp["dropped_link_count"] = dropped_link_count_cp
            if debug_direct_epfd:
                local_sat_count_peak = _estimate_local_sat_count_peak_cp(
                    local_row_slot_sat_cp,
                    base_edge_info["sat"][remove_edge_pos_cp] if int(remove_edge_pos_cp.size) > 0 else None,
                    reserved_sat_cp.astype(cp.int32, copy=False) if int(reserved_sat_cp.size) > 0 else None,
                )
                result_cp["debug_direct_epfd_stats"] = {
                    "mode": "ras_station",
                    "boresight_active": True,
                    "realized_edge_count": int(int(base_edge_count) * int(sky_count)),
                    "feasible_realized_edge_count": int(int(base_edge_count) * int(sky_count)),
                    "kept_realized_edge_count": int(cp.sum(direct_kept_count_cp).item()),
                    "impacted_row_count": int(repair_stats["impacted_row_count"]),
                    "impacted_candidate_edge_count": int(repair_stats["impacted_candidate_edge_count"]),
                    "repair_launch_count": int(repair_stats["repair_launch_count"]),
                    "repaired_link_count": int(cp.sum(repaired_link_count_cp).item()),
                    "dropped_link_count": int(cp.sum(dropped_link_count_cp).item()),
                    "ras_retargeted_count": int(cp.sum(ras_retargeted_count_cp).item()),
                    "max_sat_beam_count": int(cp.max(sat_slot_used_cp).item()) if sat_slot_used_cp.size > 0 else 0,
                    "invalid_slot_repair_count": int(invalid_row_ids_cp.size),
                    "impacted_edge_extract_count": int(remove_edge_pos_cp.size),
                    "removed_base_edge_count": int(removed_edge_count),
                    "reserved_scattered_count": int(reserved_scattered_count),
                    "repair_row_count": int(repair_stats["impacted_row_count"]),
                    "repair_candidate_edge_count": int(repair_stats["impacted_candidate_edge_count"]),
                    "local_sat_count_peak": int(local_sat_count_peak),
                }
        return result_cp

    beam_shape = (
        (time_count, sky_count, sat_output_count, library.n_beam)
        if boresight_active
        else (time_count, sat_output_count, library.n_beam)
    )
    sat_shape = (
        (time_count, sky_count, library.sat_count)
        if boresight_active
        else (time_count, library.sat_count)
    )
    cell_slot_shape = (
        (time_count, sky_count, library.cell_count, library.n_links)
        if boresight_active
        else (time_count, library.cell_count, library.n_links)
    )
    count_shape = (time_count, sky_count) if boresight_active else (time_count,)

    # Workspace pooling: reuse GPU arrays across finalize calls.
    # On first call, allocate; on subsequent calls, reset to initial
    # values (memset is ~10x cheaper than alloc+dealloc).
    _ws = library._finalize_workspace
    _ws_key = (beam_shape, sat_shape, cell_slot_shape, count_shape)
    if _ws.get("_key") != _ws_key:
        # Shape changed (first call or different batch geometry) — reallocate
        _ws["beam_idx"] = cp.empty(beam_shape, dtype=cp.int32)
        _ws["beam_alpha"] = cp.empty(beam_shape, dtype=cp.float32)
        _ws["beam_beta"] = cp.empty(beam_shape, dtype=cp.float32)
        _ws["sat_slot_used"] = cp.empty(sat_shape, dtype=cp.int32)
        _ws["cell_slot_sat"] = cp.empty(cell_slot_shape, dtype=cp.int32)
        _ws["needs_repair"] = cp.empty(cell_slot_shape, dtype=cp.bool_)
        _ws["reserved_alpha"] = cp.empty(sat_shape, dtype=cp.float32)
        _ws["reserved_beta"] = cp.empty(sat_shape, dtype=cp.float32)
        _ws["reserved_present"] = cp.empty(sat_shape, dtype=cp.bool_)
        _ws["ras_retargeted"] = cp.empty(count_shape, dtype=cp.int32)
        _ws["direct_kept"] = cp.empty(count_shape, dtype=cp.int32)
        _ws["repaired_link"] = cp.empty(count_shape, dtype=cp.int32)
        _ws["dropped_link"] = cp.empty(count_shape, dtype=cp.int32)
        _ws["_key"] = _ws_key

    # Reset workspace arrays. cp.full writes the fill value in a single
    # kernel launch; we reuse the existing allocation to avoid alloc churn.
    beam_idx_cp = _ws["beam_idx"]
    beam_alpha_cp = _ws["beam_alpha"]
    beam_beta_cp = _ws["beam_beta"]
    sat_slot_used_cp = _ws["sat_slot_used"]
    cell_slot_sat_cp = _ws["cell_slot_sat"]
    needs_repair_cp = _ws["needs_repair"]
    reserved_alpha_cp = _ws["reserved_alpha"]
    reserved_beta_cp = _ws["reserved_beta"]
    reserved_present_cp = _ws["reserved_present"]
    ras_retargeted_count_cp = _ws["ras_retargeted"]
    direct_kept_count_cp = _ws["direct_kept"]
    repaired_link_count_cp = _ws["repaired_link"]
    dropped_link_count_cp = _ws["dropped_link"]
    # Group resets by fill value to reduce kernel launch count:
    # -1 fills (int32): beam_idx, cell_slot_sat
    beam_idx_cp[...] = -1; cell_slot_sat_cp[...] = -1
    # NaN fills (float32): beam_alpha, beam_beta, reserved_alpha, reserved_beta
    beam_alpha_cp[...] = cp.nan; beam_beta_cp[...] = cp.nan
    reserved_alpha_cp[...] = cp.nan; reserved_beta_cp[...] = cp.nan
    # Zero fills (int32): sat_slot_used, counters
    sat_slot_used_cp[...] = 0
    ras_retargeted_count_cp[...] = 0; direct_kept_count_cp[...] = 0
    repaired_link_count_cp[...] = 0; dropped_link_count_cp[...] = 0
    # Bool zeros: needs_repair, reserved_present
    needs_repair_cp[...] = False; reserved_present_cp[...] = False

    if boresight_active:
        # 32 sky cells per block → proper warp-level utilization.
        _bore_sky_block = 32
        _bore_sky_grid = (int(sky_count) + _bore_sky_block - 1) // _bore_sky_block
        grid = (time_count, _bore_sky_grid, 1)
        _retarget_ras_row_boresight_kernel[grid, (_bore_sky_block, 1, 1)](
            cuda.as_cuda_array(assignments_cp),
            cuda.as_cuda_array(direct_candidate_slab["row_ptr"]),
            cuda.as_cuda_array(direct_candidate_slab["candidate_sat"]),
            cuda.as_cuda_array(ras_elevation_deg_cp),
            cuda.as_cuda_array(ras_alpha_rad_cp),
            cuda.as_cuda_array(ras_beta_rad_cp),
            cuda.as_cuda_array(library.sat_min_elev_cp),
            cuda.as_cuda_array(sat_beta_max_rad_cp),
            cuda.as_cuda_array(boresight_sparse_slab["theta1_row_ptr"]),
            cuda.as_cuda_array(boresight_sparse_slab["theta1_sat_idx"]),
            cuda.as_cuda_array(boresight_sparse_slab["theta2_row_ptr"]),
            cuda.as_cuda_array(boresight_sparse_slab["theta2_sat_idx"]),
            cuda.as_cuda_array(theta2_cell_mask_cp),
            int(ras_cell_index),
            int(sky_count),
            int(library.n_links),
            int(library.n_beam),
            bool(library.use_cone_check),
            np.float32(beta_tol_rad),
            cuda.as_cuda_array(sat_output_index_cp),
            bool(ras_sat_axis_is_compact),
            cuda.as_cuda_array(cell_slot_sat_cp),
            cuda.as_cuda_array(sat_slot_used_cp),
            cuda.as_cuda_array(reserved_alpha_cp),
            cuda.as_cuda_array(reserved_beta_cp),
            cuda.as_cuda_array(reserved_present_cp),
            cuda.as_cuda_array(beam_idx_cp),
            cuda.as_cuda_array(beam_alpha_cp),
            cuda.as_cuda_array(beam_beta_cp),
            cuda.as_cuda_array(ras_retargeted_count_cp),
            cuda.as_cuda_array(dropped_link_count_cp),
        )
    elif getattr(library, '_use_parallel_finalize', False) and not boresight_active:
        # ── Parallel finalize kernel: replaces retarget + CuPy edge
        # pipeline + repair with a single Numba CUDA launch.
        # One block per timestep, 128 threads per block. ──
        _par_grid = (time_count, 1, 1)
        _par_block = (GPU_FINALIZE_BLOCK_SIZE, 1, 1)
        _finalize_direct_epfd_beam_tables_parallel_kernel[_par_grid, _par_block](
            cuda.as_cuda_array(assignments_cp),
            cuda.as_cuda_array(cone_ok_cp),
            cuda.as_cuda_array(selected_alpha_rad_cp),
            cuda.as_cuda_array(selected_beta_rad_cp),
            cuda.as_cuda_array(direct_candidate_slab["row_ptr"]),
            cuda.as_cuda_array(direct_candidate_slab["candidate_sat"]),
            cuda.as_cuda_array(direct_candidate_slab["candidate_alpha_rad"]),
            cuda.as_cuda_array(direct_candidate_slab["candidate_beta_rad"]),
            cuda.as_cuda_array(ras_elevation_deg_cp),
            cuda.as_cuda_array(ras_alpha_rad_cp),
            cuda.as_cuda_array(ras_beta_rad_cp),
            cuda.as_cuda_array(library.sat_min_elev_cp),
            cuda.as_cuda_array(sat_beta_max_rad_cp),
            int(ras_cell_index),
            int(library.n_links),
            int(library.n_beam),
            bool(library.use_cone_check),
            np.float32(beta_tol_rad),
            bool(use_ras_guard),
            np.float32(ras_guard_cos),
            cuda.as_cuda_array(sat_output_index_cp),
            bool(ras_sat_axis_is_compact),
            cuda.as_cuda_array(cell_slot_sat_cp),
            cuda.as_cuda_array(needs_repair_cp),
            cuda.as_cuda_array(sat_slot_used_cp),
            cuda.as_cuda_array(reserved_alpha_cp),
            cuda.as_cuda_array(reserved_beta_cp),
            cuda.as_cuda_array(reserved_present_cp),
            cuda.as_cuda_array(beam_idx_cp),
            cuda.as_cuda_array(beam_alpha_cp),
            cuda.as_cuda_array(beam_beta_cp),
            cuda.as_cuda_array(ras_retargeted_count_cp),
            cuda.as_cuda_array(direct_kept_count_cp),
            cuda.as_cuda_array(repaired_link_count_cp),
            cuda.as_cuda_array(dropped_link_count_cp),
        )
        # Skip the CuPy edge pipeline — the parallel kernel did it all.
        # Canonicalize beam slot ordering for deterministic output.
        _canonicalize_direct_beam_slots_cp(beam_idx_cp, beam_alpha_cp, beam_beta_cp)
    else:
        grid = (time_count, 1, 1)
        _retarget_ras_row_kernel[grid, (1, 1, 1)](
            cuda.as_cuda_array(assignments_cp),
            cuda.as_cuda_array(direct_candidate_slab["row_ptr"]),
            cuda.as_cuda_array(direct_candidate_slab["candidate_sat"]),
            cuda.as_cuda_array(ras_elevation_deg_cp),
            cuda.as_cuda_array(ras_alpha_rad_cp),
            cuda.as_cuda_array(ras_beta_rad_cp),
            cuda.as_cuda_array(library.sat_min_elev_cp),
            cuda.as_cuda_array(sat_beta_max_rad_cp),
            int(ras_cell_index),
            int(library.n_links),
            int(library.n_beam),
            bool(library.use_cone_check),
            np.float32(beta_tol_rad),
            cuda.as_cuda_array(sat_output_index_cp),
            bool(ras_sat_axis_is_compact),
            cuda.as_cuda_array(cell_slot_sat_cp),
            cuda.as_cuda_array(sat_slot_used_cp),
            cuda.as_cuda_array(reserved_alpha_cp),
            cuda.as_cuda_array(reserved_beta_cp),
            cuda.as_cuda_array(reserved_present_cp),
            cuda.as_cuda_array(beam_idx_cp),
            cuda.as_cuda_array(beam_alpha_cp),
            cuda.as_cuda_array(beam_beta_cp),
            cuda.as_cuda_array(ras_retargeted_count_cp),
            cuda.as_cuda_array(dropped_link_count_cp),
        )

    edge_info = _gather_realized_direct_edges_cp(
        assignments_cp,
        cone_ok_cp,
        selected_alpha_rad_cp,
        selected_beta_rad_cp,
        exclude_cell=int(ras_cell_index),
    )
    if boresight_active and "sky" not in edge_info:
        base_edge_count = int(edge_info["edge_linear"].size)
        if base_edge_count > 0:
            sky_idx_cp = cp.tile(
                cp.arange(int(sky_count), dtype=cp.int32),
                int(base_edge_count),
            )
            for key in ("edge_linear", "t", "cell", "link", "sat", "cone_ok", "alpha", "beta"):
                edge_info[key] = cp.repeat(edge_info[key], int(sky_count), axis=0)
            edge_info["sky"] = sky_idx_cp
        else:
            edge_info["sky"] = cp.empty((0,), dtype=cp.int32)
    realized_count = int(edge_info["edge_linear"].size)
    feasible_realized_count = 0
    kept_realized_count = 0
    repair_stats = {"impacted_row_count": 0, "impacted_candidate_edge_count": 0, "repair_launch_count": 0}
    if realized_count > 0:
        if not boresight_active and use_ras_guard:
            # Fused feasibility kernel: cone_ok + RAS guard in one CUDA launch.
            # Replaces ~18 CuPy dispatches with a single RawModule kernel.
            _feas_mod = _get_edge_feasibility_kernel()
            _feas_k = _feas_mod.get_function("compute_edge_feasibility")
            _n_edges = int(edge_info["cone_ok"].size)
            feasible_mask = cp.empty(_n_edges, dtype=cp.bool_)
            _block = 256
            _feas_k(
                ((_n_edges + _block - 1) // _block,), (_block,),
                (
                    edge_info["cone_ok"],
                    edge_info["t"].astype(cp.int32, copy=False),
                    edge_info["sat"].astype(cp.int32, copy=False),
                    edge_info["alpha"].astype(cp.float32, copy=False),
                    edge_info["beta"].astype(cp.float32, copy=False),
                    reserved_present_cp,
                    reserved_alpha_cp,
                    reserved_beta_cp,
                    np.float32(ras_guard_cos),
                    np.int32(1),
                    np.int32(library.sat_count),
                    np.int32(_n_edges),
                    feasible_mask,
                ),
            )
        else:
            feasible_mask = cp.asarray(edge_info["cone_ok"], dtype=cp.bool_)
            if boresight_active:
                forbidden_cp = _compute_realized_boresight_forbidden_cp(
                    edge_info,
                    boresight_sparse_slab=boresight_sparse_slab,
                    theta2_cell_mask_cp=theta2_cell_mask_cp,
                    sky_count=sky_count,
                )
                feasible_mask &= ~forbidden_cp
            if use_ras_guard:
                if boresight_active:
                    reserved_present_edge = reserved_present_cp[
                        edge_info["t"],
                        edge_info["sky"],
                        edge_info["sat"],
                    ]
                    alpha_ras = reserved_alpha_cp[
                        edge_info["t"],
                        edge_info["sky"],
                        edge_info["sat"],
                    ]
                    beta_ras = reserved_beta_cp[
                        edge_info["t"],
                        edge_info["sky"],
                        edge_info["sat"],
                    ]
                else:
                    reserved_present_edge = reserved_present_cp[
                        edge_info["t"],
                        edge_info["sat"],
                    ]
                    alpha_ras = reserved_alpha_cp[
                        edge_info["t"],
                        edge_info["sat"],
                    ]
                    beta_ras = reserved_beta_cp[
                        edge_info["t"],
                        edge_info["sat"],
                    ]
                guard_valid = (
                    reserved_present_edge
                    & cp.isfinite(alpha_ras)
                    & cp.isfinite(beta_ras)
                    & cp.isfinite(edge_info["alpha"])
                    & cp.isfinite(edge_info["beta"])
                )
                cos_da = cp.cos(alpha_ras - edge_info["alpha"])
                cos_gamma = (
                    cp.cos(beta_ras) * cp.cos(edge_info["beta"])
                    + cp.sin(beta_ras) * cp.sin(edge_info["beta"]) * cos_da
                )
                feasible_mask &= ~(guard_valid & (cos_gamma > np.float32(ras_guard_cos)))

        # Pure-CuPy orchestration.  An earlier iteration tried a Cython
        # wrapper around this block (``scepter._finalize_accel``) on the
        # theory that eliminating Python dict lookups between CuPy calls
        # would be a win.  Benchmarking showed 0.00 ms improvement
        # (within noise): the dispatch loop is dominated by CUDA launch
        # latency, not Python interpreter overhead.  The Cython module
        # has been removed; see memory ``optimization_progress.md``.
        feasible_pos = cp.nonzero(feasible_mask)[0].astype(cp.int64, copy=False)
        feasible_realized_count = int(feasible_pos.size)
        kept_realized_mask = cp.zeros((realized_count,), dtype=cp.bool_)
        if int(feasible_pos.size) > 0:
            feasible_sat = edge_info["sat"][feasible_pos].astype(cp.int32, copy=False)
            if boresight_active:
                group_key_cp = (
                    (edge_info["t"][feasible_pos].astype(cp.int32, copy=False) * np.int32(int(sky_count))
                     + edge_info["sky"][feasible_pos].astype(cp.int32, copy=False))
                    * np.int32(int(library.sat_count))
                    + feasible_sat
                ).astype(cp.int32, copy=False)
            else:
                group_key_cp = (
                    edge_info["t"][feasible_pos].astype(cp.int32, copy=False) * np.int32(int(library.sat_count))
                    + feasible_sat
                ).astype(cp.int32, copy=False)
            reserved_flat_cp = sat_slot_used_cp.reshape(-1).astype(cp.int32, copy=False)
            group_limit_flat_cp = cp.maximum(
                np.int32(0),
                np.int32(int(library.n_beam)) - reserved_flat_cp,
            ).astype(cp.int32, copy=False)
            _base_order = edge_info["edge_linear"][feasible_pos]
            if getattr(library, '_load_balanced_beams', False):
                _cap_remaining = group_limit_flat_cp[group_key_cp].astype(cp.int64, copy=False)
                _penalty = (np.int64(int(library.n_beam)) - _cap_remaining) * np.int64(1_000_000)
                _base_order = _base_order + _penalty
            keep_local_cp, keep_rank_cp = _select_group_limited_edges_cp(
                group_key_cp=group_key_cp,
                order_key_cp=_base_order,
                group_limit_flat_cp=group_limit_flat_cp,
            )
            kept_feasible_pos = feasible_pos[keep_local_cp].astype(cp.int64, copy=False)
            keep_slot_cp = (
                keep_rank_cp.astype(cp.int32, copy=False)
                + reserved_flat_cp[group_key_cp[keep_local_cp]].astype(cp.int32, copy=False)
            )
            _scatter_direct_edge_selection_cp(
                edge_info=edge_info,
                selected_positions_cp=kept_feasible_pos,
                slot_cp=keep_slot_cp,
                sat_output_index_cp=sat_output_index_cp,
                n_links=library.n_links,
                beam_idx_cp=beam_idx_cp,
                beam_alpha_cp=beam_alpha_cp,
                beam_beta_cp=beam_beta_cp,
                cell_slot_sat_cp=cell_slot_sat_cp,
            )
            keep_counts_cp = _count_edges_per_satellite_group_cp(
                group_key_cp=group_key_cp[keep_local_cp],
                base_shape=sat_shape,
            )
            sat_slot_used_cp += keep_counts_cp
            kept_realized_mask[kept_feasible_pos] = True
            kept_realized_count = int(kept_feasible_pos.size)
            direct_kept_count_cp[...] = _count_edges_per_time_axis_cp(
                boresight_active=boresight_active,
                t_cp=edge_info["t"][kept_feasible_pos],
                sky_cp=(edge_info["sky"][kept_feasible_pos] if boresight_active else None),
                time_count=time_count,
                sky_count=sky_count,
            )

        needs_repair_pos = cp.nonzero(~kept_realized_mask)[0].astype(cp.int64, copy=False)
        if int(needs_repair_pos.size) > 0:
            if boresight_active:
                needs_repair_cp[
                    edge_info["t"][needs_repair_pos],
                    edge_info["sky"][needs_repair_pos],
                    edge_info["cell"][needs_repair_pos],
                    edge_info["link"][needs_repair_pos],
                ] = True
                impacted_mask = cp.any(needs_repair_cp, axis=3)
                impacted_mask[:, :, int(ras_cell_index)] = False
                impacted_rows_cp = cp.nonzero(impacted_mask.reshape(-1))[0].astype(cp.int32, copy=False)
            else:
                needs_repair_cp[
                    edge_info["t"][needs_repair_pos],
                    edge_info["cell"][needs_repair_pos],
                    edge_info["link"][needs_repair_pos],
                ] = True
                impacted_mask = cp.any(needs_repair_cp, axis=2)
                impacted_mask[:, int(ras_cell_index)] = False
                impacted_rows_cp = cp.nonzero(impacted_mask.reshape(-1))[0].astype(cp.int32, copy=False)
            if boresight_active:
                repair_stats = _launch_direct_epfd_row_repairs_cp(
                    impacted_rows_cp=impacted_rows_cp,
                    row_ptr_cp=direct_candidate_slab["row_ptr"],
                    row_kernel=_repair_direct_epfd_rows_boresight_kernel,
                    kernel_args=(
                        cuda.as_cuda_array(direct_candidate_slab["row_ptr"]),
                        cuda.as_cuda_array(direct_candidate_slab["candidate_sat"]),
                        cuda.as_cuda_array(direct_candidate_slab["candidate_alpha_rad"]),
                        cuda.as_cuda_array(direct_candidate_slab["candidate_beta_rad"]),
                        cuda.as_cuda_array(boresight_sparse_slab["theta1_row_ptr"]),
                        cuda.as_cuda_array(boresight_sparse_slab["theta1_sat_idx"]),
                        cuda.as_cuda_array(boresight_sparse_slab["theta2_row_ptr"]),
                        cuda.as_cuda_array(boresight_sparse_slab["theta2_sat_idx"]),
                        cuda.as_cuda_array(theta2_cell_mask_cp),
                        cuda.as_cuda_array(sat_beta_max_rad_cp),
                        int(sky_count),
                        int(library.n_links),
                        int(library.n_beam),
                        bool(library.use_cone_check),
                        np.float32(beta_tol_rad),
                        bool(use_ras_guard),
                        np.float32(ras_guard_cos),
                        cuda.as_cuda_array(sat_output_index_cp),
                        cuda.as_cuda_array(needs_repair_cp),
                        cuda.as_cuda_array(cell_slot_sat_cp),
                        cuda.as_cuda_array(sat_slot_used_cp),
                        cuda.as_cuda_array(reserved_alpha_cp),
                        cuda.as_cuda_array(reserved_beta_cp),
                        cuda.as_cuda_array(reserved_present_cp),
                        cuda.as_cuda_array(beam_idx_cp),
                        cuda.as_cuda_array(beam_alpha_cp),
                        cuda.as_cuda_array(beam_beta_cp),
                        cuda.as_cuda_array(repaired_link_count_cp),
                        cuda.as_cuda_array(dropped_link_count_cp),
                    ),
                    sky_count=int(sky_count),
                    cell_count=int(library.cell_count),
                    debug_direct_epfd=bool(debug_direct_epfd),
                )
            else:
                repair_stats = _launch_direct_epfd_row_repairs_cp(
                    impacted_rows_cp=impacted_rows_cp,
                    row_ptr_cp=direct_candidate_slab["row_ptr"],
                    row_kernel=_repair_direct_epfd_rows_kernel,
                    kernel_args=(
                        cuda.as_cuda_array(direct_candidate_slab["row_ptr"]),
                        cuda.as_cuda_array(direct_candidate_slab["candidate_sat"]),
                        cuda.as_cuda_array(direct_candidate_slab["candidate_alpha_rad"]),
                        cuda.as_cuda_array(direct_candidate_slab["candidate_beta_rad"]),
                        cuda.as_cuda_array(sat_beta_max_rad_cp),
                        int(library.n_links),
                        int(library.n_beam),
                        bool(library.use_cone_check),
                        np.float32(beta_tol_rad),
                        bool(use_ras_guard),
                        np.float32(ras_guard_cos),
                        cuda.as_cuda_array(sat_output_index_cp),
                        cuda.as_cuda_array(needs_repair_cp),
                        cuda.as_cuda_array(cell_slot_sat_cp),
                        cuda.as_cuda_array(sat_slot_used_cp),
                        cuda.as_cuda_array(reserved_alpha_cp),
                        cuda.as_cuda_array(reserved_beta_cp),
                        cuda.as_cuda_array(reserved_present_cp),
                        cuda.as_cuda_array(beam_idx_cp),
                        cuda.as_cuda_array(beam_alpha_cp),
                        cuda.as_cuda_array(beam_beta_cp),
                        cuda.as_cuda_array(repaired_link_count_cp),
                        cuda.as_cuda_array(dropped_link_count_cp),
                    ),
                    sky_count=1,
                    cell_count=int(library.cell_count),
                    debug_direct_epfd=bool(debug_direct_epfd),
                )

    counts_cp, service_counts_full_cp, reserved_count_cp = _finalize_beam_count_outputs_cp(
        sat_slot_used_cp=sat_slot_used_cp,
        output_sat_indices_cp=output_sat_indices_cp,
        sat_output_count=int(sat_output_count),
        reserved_present_cp=reserved_present_cp,
    )

    result_cp: dict[str, Any] = {
        "beam_idx": beam_idx_cp,
        "beam_alpha_rad": beam_alpha_cp,
        "beam_beta_rad": beam_beta_cp,
        "sat_beam_counts_used": counts_cp,
    }
    if include_full_sat_beam_counts_used:
        result_cp["sat_beam_counts_used_full"] = service_counts_full_cp
    if include_diagnostics:
        result_cp["ras_retargeted_count"] = ras_retargeted_count_cp
        result_cp["ras_reserved_count"] = reserved_count_cp
        result_cp["direct_kept_count"] = direct_kept_count_cp
        result_cp["repaired_link_count"] = repaired_link_count_cp
        result_cp["dropped_link_count"] = dropped_link_count_cp
    if debug_direct_epfd:
        result_cp["debug_direct_epfd_stats"] = {
            "mode": "ras_station",
            "boresight_active": bool(boresight_active),
            "realized_edge_count": int(realized_count),
            "feasible_realized_edge_count": int(feasible_realized_count),
            "kept_realized_edge_count": int(kept_realized_count),
            "impacted_row_count": int(repair_stats["impacted_row_count"]),
            "impacted_candidate_edge_count": int(repair_stats["impacted_candidate_edge_count"]),
            "repair_launch_count": int(repair_stats["repair_launch_count"]),
            "repaired_link_count": int(cp.sum(repaired_link_count_cp).item()),
            "dropped_link_count": int(cp.sum(dropped_link_count_cp).item()),
            "ras_retargeted_count": int(cp.sum(ras_retargeted_count_cp).item()),
            "max_sat_beam_count": int(cp.max(sat_slot_used_cp).item()) if sat_slot_used_cp.size > 0 else 0,
        }
        if boresight_active:
            result_cp["debug_direct_epfd_stats"].update(
                raw_impacted_edge_count=int(edge_compaction_stats["raw_impacted_edge_count"]),
                deduped_impacted_edge_count=int(edge_compaction_stats["deduped_impacted_edge_count"]),
                raw_impacted_row_count=int(row_compaction_stats["raw_impacted_row_count"]),
                deduped_impacted_row_count=int(row_compaction_stats["deduped_impacted_row_count"]),
            )
    if boresight_active:
        result_cp["_boresight_compaction_seconds"] = float(compaction_seconds)
        result_cp["_boresight_compaction_stats"] = {
            "raw_impacted_edge_count": int(edge_compaction_stats["raw_impacted_edge_count"]),
            "deduped_impacted_edge_count": int(edge_compaction_stats["deduped_impacted_edge_count"]),
            "raw_impacted_row_count": int(row_compaction_stats["raw_impacted_row_count"]),
            "deduped_impacted_row_count": int(row_compaction_stats["deduped_impacted_row_count"]),
            "removed_base_edge_count": int(removed_edge_count),
            "invalid_row_slot_count": int(invalid_row_ids_cp.size),
        }
    return result_cp


def _finalize_staged_cell_center_parallel_cp(
    library: GpuSatelliteLinkSelectionLibrary,
    *,
    assignments_cp: Any,
    cone_ok_cp: Any,
    selected_alpha_rad_cp: Any,
    selected_beta_rad_cp: Any,
    direct_candidate_slab: dict[str, Any],
    boresight_sparse_slab: dict[str, Any],
    sat_output_index_cp: Any,
    output_sat_indices_cp: Any,
    sat_output_count: int,
    sat_beta_max_rad_cp: Any,
    beta_tol_rad: np.float32,
    include_diagnostics: bool,
    include_full_sat_beam_counts_used: bool,
    working_memory_budget_bytes: int | None = None,
    finalize_workspace: dict[str, Any] | None = None,
    debug_direct_epfd: bool = False,
) -> dict[str, Any]:
    time_count = int(assignments_cp.shape[0])
    sky_count = int(boresight_sparse_slab["theta1_row_ptr"].shape[0] - 1) // max(time_count, 1)
    theta2_cell_mask_cp = library.boresight_theta2_cell_mask_cp
    if theta2_cell_mask_cp is None:
        theta2_cell_mask_cp = cp.zeros((library.cell_count,), dtype=cp.bool_)
    base_pack = _pack_cell_center_first_pass_cp(
        library,
        assignments_cp=assignments_cp,
        cone_ok_cp=cone_ok_cp,
        selected_alpha_rad_cp=selected_alpha_rad_cp,
        selected_beta_rad_cp=selected_beta_rad_cp,
        sat_output_index_cp=sat_output_index_cp,
        output_sat_indices_cp=output_sat_indices_cp,
        sat_output_count=sat_output_count,
        include_diagnostics=True,
        include_full_sat_beam_counts_used=True,
        return_slot_maps=True,
    )
    beam_idx_cp = cp.full((time_count, sky_count, sat_output_count, library.n_beam), -1, dtype=cp.int32)
    beam_alpha_cp = cp.full(beam_idx_cp.shape, cp.nan, dtype=cp.float32)
    beam_beta_cp = cp.full(beam_idx_cp.shape, cp.nan, dtype=cp.float32)
    beam_idx_cp[...] = base_pack["beam_idx"][:, None, :, :]
    beam_alpha_cp[...] = base_pack["beam_alpha_rad"][:, None, :, :]
    beam_beta_cp[...] = base_pack["beam_beta_rad"][:, None, :, :]

    sat_slot_used_cp = cp.zeros((time_count, sky_count, library.sat_count), dtype=cp.int32)
    sat_slot_used_cp[...] = base_pack["sat_beam_counts_used_full"][:, None, :]
    direct_kept_count_cp = cp.zeros((time_count, sky_count), dtype=cp.int32)
    direct_kept_count_cp[...] = base_pack["direct_kept_count"][:, None]
    repaired_link_count_cp = cp.zeros((time_count, sky_count), dtype=cp.int32)
    dropped_link_count_cp = cp.zeros((time_count, sky_count), dtype=cp.int32)
    reserved_alpha_cp, reserved_beta_cp, reserved_present_cp = _allocate_direct_guard_state_cp(
        shape=(time_count, sky_count, library.sat_count),
        enabled=False,
    )

    base_edge_info = _build_base_packed_edge_info_cp(
        assignments_cp,
        cone_ok_cp,
        selected_alpha_rad_cp,
        selected_beta_rad_cp,
        base_cell_slot_beam_slot_cp=base_pack["cell_slot_beam_slot"],
    )
    reverse_index = _build_realized_edge_reverse_index_cp(
        edge_info=base_edge_info,
        time_count=time_count,
        sat_count=int(library.sat_count),
    )
    base_edge_count = int(base_edge_info["sat"].size)

    compaction_t0 = time.perf_counter()
    invalid_row_ids_cp, invalid_slot_cp = _expand_invalid_row_slots_cp(
        assignments_cp,
        cone_ok_cp,
        sky_count=int(sky_count),
    )
    theta1_sky_row_cp, theta1_edge_pos_cp = _extract_impacted_edges_from_sparse_rows_cp(
        sparse_row_ptr_cp=boresight_sparse_slab["theta1_row_ptr"],
        sparse_sat_idx_cp=boresight_sparse_slab["theta1_sat_idx"],
        reverse_index=reverse_index,
        base_edge_info=base_edge_info,
        sky_count=int(sky_count),
        sat_count=int(library.sat_count),
    )
    theta2_sky_row_cp, theta2_edge_pos_cp = _extract_impacted_edges_from_sparse_rows_cp(
        sparse_row_ptr_cp=boresight_sparse_slab["theta2_row_ptr"],
        sparse_sat_idx_cp=boresight_sparse_slab["theta2_sat_idx"],
        reverse_index=reverse_index,
        base_edge_info=base_edge_info,
        sky_count=int(sky_count),
        sat_count=int(library.sat_count),
        theta2_cell_mask_cp=theta2_cell_mask_cp,
    )
    remove_sky_row_cp, remove_edge_pos_cp, edge_compaction_stats = (
        _dedupe_impacted_edge_pair_parts_cp(
            pair_parts=(
                (theta1_sky_row_cp, theta1_edge_pos_cp),
                (theta2_sky_row_cp, theta2_edge_pos_cp),
            ),
            base_edge_count=max(base_edge_count, 1),
        )
    )
    remove_row_ids_cp = (
        remove_sky_row_cp.astype(cp.int32, copy=False) * np.int32(int(library.cell_count))
        + base_edge_info["cell"][remove_edge_pos_cp].astype(cp.int32, copy=False)
    ).astype(cp.int32, copy=False) if int(remove_edge_pos_cp.size) > 0 else cp.empty((0,), dtype=cp.int32)

    impacted_rows_cp, row_compaction_stats = _dedupe_impacted_row_parts_cp(
        row_parts=(invalid_row_ids_cp, remove_row_ids_cp),
        cell_count=int(library.cell_count),
    )
    sparse_row_workspace = None
    if finalize_workspace is not None:
        sparse_row_workspace = finalize_workspace.setdefault("cell_center_sparse_state", {})
    local_needs_repair_cp, local_row_slot_sat_cp = _build_sparse_impacted_row_state_cp(
        impacted_rows_cp=impacted_rows_cp,
        base_cell_slot_sat_cp=base_pack["cell_slot_sat"],
        sky_count=int(sky_count),
        cell_count=int(library.cell_count),
        n_links=int(library.n_links),
        workspace=sparse_row_workspace,
    )
    compaction_seconds = max(time.perf_counter() - compaction_t0, 0.0)
    if int(invalid_row_ids_cp.size) > 0 and int(impacted_rows_cp.size) > 0:
        invalid_local_idx_cp = cp.searchsorted(
            impacted_rows_cp.astype(cp.int32, copy=False),
            invalid_row_ids_cp.astype(cp.int32, copy=False),
            side="left",
        ).astype(cp.int32, copy=False)
        local_needs_repair_cp[invalid_local_idx_cp, invalid_slot_cp.astype(cp.int32, copy=False)] = True

    removed_edge_count = _apply_sparse_impacted_edge_removals_cp(
        impacted_rows_cp=impacted_rows_cp,
        remove_row_ids_cp=remove_row_ids_cp,
        remove_edge_pos_cp=remove_edge_pos_cp,
        base_edge_info=base_edge_info,
        local_needs_repair_cp=local_needs_repair_cp,
        local_row_slot_sat_cp=local_row_slot_sat_cp,
        sat_output_index_cp=sat_output_index_cp,
        beam_idx_cp=beam_idx_cp,
        beam_alpha_cp=beam_alpha_cp,
        beam_beta_cp=beam_beta_cp,
        sat_slot_used_cp=sat_slot_used_cp,
        direct_kept_count_cp=direct_kept_count_cp,
        sky_count=int(sky_count),
        cell_count=int(library.cell_count),
        sat_count=int(library.sat_count),
    )
    _compact_beam_slots_boresight_cp(
        beam_idx_cp,
        beam_alpha_cp,
        beam_beta_cp,
    )
    _debug_cuda_sync_cp(enabled=bool(debug_direct_epfd), stage="cell_center.compact_beams")

    repair_stats = _launch_direct_epfd_sparse_row_repairs_cp(
        impacted_rows_cp=impacted_rows_cp,
        local_needs_repair_cp=local_needs_repair_cp,
        local_row_slot_sat_cp=local_row_slot_sat_cp,
        row_ptr_cp=direct_candidate_slab["row_ptr"],
        row_kernel=_repair_direct_epfd_sparse_rows_boresight_kernel,
        kernel_args_prefix=(
            cuda.as_cuda_array(direct_candidate_slab["row_ptr"]),
            cuda.as_cuda_array(direct_candidate_slab["candidate_sat"]),
            cuda.as_cuda_array(direct_candidate_slab["candidate_alpha_rad"]),
            cuda.as_cuda_array(direct_candidate_slab["candidate_beta_rad"]),
            cuda.as_cuda_array(boresight_sparse_slab["theta1_row_ptr"]),
            cuda.as_cuda_array(boresight_sparse_slab["theta1_sat_idx"]),
            cuda.as_cuda_array(boresight_sparse_slab["theta2_row_ptr"]),
            cuda.as_cuda_array(boresight_sparse_slab["theta2_sat_idx"]),
            cuda.as_cuda_array(theta2_cell_mask_cp),
            cuda.as_cuda_array(sat_beta_max_rad_cp),
            int(sky_count),
            int(library.cell_count),
            int(library.n_links),
            int(library.n_beam),
            bool(library.use_cone_check),
            np.float32(beta_tol_rad),
            False,
            np.float32(0.0),
            cuda.as_cuda_array(sat_output_index_cp),
        ),
        kernel_args_suffix=(
            cuda.as_cuda_array(sat_slot_used_cp),
            cuda.as_cuda_array(reserved_alpha_cp),
            cuda.as_cuda_array(reserved_beta_cp),
            cuda.as_cuda_array(reserved_present_cp),
            cuda.as_cuda_array(beam_idx_cp),
            cuda.as_cuda_array(beam_alpha_cp),
            cuda.as_cuda_array(beam_beta_cp),
            cuda.as_cuda_array(repaired_link_count_cp),
            cuda.as_cuda_array(dropped_link_count_cp),
        ),
        sky_count=int(sky_count),
        cell_count=int(library.cell_count),
        debug_direct_epfd=bool(debug_direct_epfd),
    )
    _debug_cuda_sync_cp(enabled=bool(debug_direct_epfd), stage="cell_center.repair_rows")
    counts_cp, service_counts_full_cp, reserved_count_cp = _finalize_beam_count_outputs_cp(
        sat_slot_used_cp=sat_slot_used_cp,
        output_sat_indices_cp=output_sat_indices_cp,
        sat_output_count=int(sat_output_count),
        reserved_present_cp=None,
    )

    result_cp: dict[str, Any] = {
        "beam_idx": beam_idx_cp,
        "beam_alpha_rad": beam_alpha_cp,
        "beam_beta_rad": beam_beta_cp,
        "sat_beam_counts_used": counts_cp,
    }
    if include_full_sat_beam_counts_used:
        result_cp["sat_beam_counts_used_full"] = service_counts_full_cp
    if include_diagnostics:
        zeros_cp = cp.zeros_like(direct_kept_count_cp)
        result_cp["ras_retargeted_count"] = zeros_cp
        result_cp["ras_reserved_count"] = zeros_cp
        result_cp["direct_kept_count"] = direct_kept_count_cp
        result_cp["repaired_link_count"] = repaired_link_count_cp
        result_cp["dropped_link_count"] = dropped_link_count_cp
    if debug_direct_epfd:
        local_sat_count_peak = _estimate_local_sat_count_peak_cp(
            local_row_slot_sat_cp,
            base_edge_info["sat"][remove_edge_pos_cp] if int(remove_edge_pos_cp.size) > 0 else None,
        )
        result_cp["debug_direct_epfd_stats"] = {
            "mode": "cell_center",
            "boresight_active": True,
            "realized_edge_count": int(int(base_edge_count) * int(sky_count)),
            "feasible_realized_edge_count": int(int(base_edge_count) * int(sky_count) - int(invalid_row_ids_cp.size)),
            "kept_realized_edge_count": int(cp.sum(direct_kept_count_cp).item()),
            "impacted_row_count": int(repair_stats["impacted_row_count"]),
            "impacted_candidate_edge_count": int(repair_stats["impacted_candidate_edge_count"]),
            "repair_launch_count": int(repair_stats["repair_launch_count"]),
            "repaired_link_count": int(cp.sum(repaired_link_count_cp).item()),
            "dropped_link_count": int(cp.sum(dropped_link_count_cp).item()),
            "max_sat_beam_count": int(cp.max(sat_slot_used_cp).item()) if sat_slot_used_cp.size > 0 else 0,
            "invalid_slot_repair_count": int(invalid_row_ids_cp.size),
            "impacted_edge_extract_count": int(remove_edge_pos_cp.size),
            "removed_base_edge_count": int(removed_edge_count),
            "repair_row_count": int(repair_stats["impacted_row_count"]),
            "repair_candidate_edge_count": int(repair_stats["impacted_candidate_edge_count"]),
            "local_sat_count_peak": int(local_sat_count_peak),
            "raw_impacted_edge_count": int(edge_compaction_stats["raw_impacted_edge_count"]),
            "deduped_impacted_edge_count": int(edge_compaction_stats["deduped_impacted_edge_count"]),
            "raw_impacted_row_count": int(row_compaction_stats["raw_impacted_row_count"]),
            "deduped_impacted_row_count": int(row_compaction_stats["deduped_impacted_row_count"]),
        }
    result_cp["_boresight_compaction_seconds"] = float(compaction_seconds)
    result_cp["_boresight_compaction_stats"] = {
        "raw_impacted_edge_count": int(edge_compaction_stats["raw_impacted_edge_count"]),
        "deduped_impacted_edge_count": int(edge_compaction_stats["deduped_impacted_edge_count"]),
        "raw_impacted_row_count": int(row_compaction_stats["raw_impacted_row_count"]),
        "deduped_impacted_row_count": int(row_compaction_stats["deduped_impacted_row_count"]),
        "removed_base_edge_count": int(removed_edge_count),
        "invalid_row_slot_count": int(invalid_row_ids_cp.size),
    }
    return result_cp


def _finalize_direct_epfd_beams_slab_cp(
    library: GpuSatelliteLinkSelectionLibrary,
    *,
    first_pass_slab: dict[str, Any],
    direct_candidate_slab: dict[str, Any],
    sat_output_index_cp: Any,
    output_sat_indices_cp: Any,
    sat_output_count: int,
    ras_cell_index: int | None,
    ras_elevation_deg_cp: Any | None,
    ras_alpha_rad_cp: Any | None,
    ras_beta_rad_cp: Any | None,
    ras_sat_axis_is_compact: bool,
    sat_beta_max_rad_cp: Any | None,
    beta_tol_rad: np.float32,
    use_ras_guard: bool,
    ras_guard_cos: np.float32,
    mode: str,
    include_diagnostics: bool,
    include_full_sat_beam_counts_used: bool,
    working_memory_budget_bytes: int | None = None,
    finalize_workspace: dict[str, Any] | None = None,
    debug_direct_epfd: bool = False,
) -> dict[str, Any]:
    assignments_cp = first_pass_slab["assignments"]
    cone_ok_cp = first_pass_slab["cone_ok"]
    selected_alpha_rad_cp = first_pass_slab["selected_alpha_rad"]
    selected_beta_rad_cp = first_pass_slab["selected_beta_rad"]
    boresight_active = assignments_cp.ndim == 4

    if mode == "cell_center":
        result_cp = _pack_cell_center_first_pass_cp(
            library,
            assignments_cp=assignments_cp,
            cone_ok_cp=cone_ok_cp,
            selected_alpha_rad_cp=selected_alpha_rad_cp,
            selected_beta_rad_cp=selected_beta_rad_cp,
            sat_output_index_cp=sat_output_index_cp,
            output_sat_indices_cp=output_sat_indices_cp,
            sat_output_count=sat_output_count,
            include_diagnostics=include_diagnostics,
            include_full_sat_beam_counts_used=include_full_sat_beam_counts_used,
        )
        if debug_direct_epfd:
            result_cp["debug_direct_epfd_stats"] = {
                "mode": "cell_center",
                "boresight_active": bool(boresight_active),
                "realized_edge_count": int(cp.count_nonzero(cp.asarray(assignments_cp) >= 0)),
            }
        return result_cp

    assert ras_cell_index is not None
    assert ras_elevation_deg_cp is not None
    assert ras_alpha_rad_cp is not None
    assert ras_beta_rad_cp is not None
    assert sat_beta_max_rad_cp is not None
    if boresight_active:
        slab_time_count = int(assignments_cp.shape[0])
        slab_sky_count = int(assignments_cp.shape[1])
        beam_idx_cp = cp.full((slab_time_count, slab_sky_count, sat_output_count, library.n_beam), -1, dtype=cp.int32)
        beam_alpha_cp = cp.full(beam_idx_cp.shape, cp.nan, dtype=cp.float32)
        beam_beta_cp = cp.full(beam_idx_cp.shape, cp.nan, dtype=cp.float32)
        sat_slot_used_cp = cp.zeros((slab_time_count, slab_sky_count, library.sat_count), dtype=cp.int32)
        cell_slot_sat_cp = cp.full((slab_time_count, slab_sky_count, library.cell_count, library.n_links), -1, dtype=cp.int32)
        needs_repair_cp = cp.zeros((slab_time_count, slab_sky_count, library.cell_count, library.n_links), dtype=cp.bool_)
        reserved_alpha_cp = cp.full((slab_time_count, slab_sky_count, library.sat_count), cp.nan, dtype=cp.float32)
        reserved_beta_cp = cp.full((slab_time_count, slab_sky_count, library.sat_count), cp.nan, dtype=cp.float32)
        reserved_present_cp = cp.zeros((slab_time_count, slab_sky_count, library.sat_count), dtype=cp.bool_)
        ras_retargeted_count_cp = cp.zeros((slab_time_count, slab_sky_count), dtype=cp.int32)
        direct_kept_count_cp = cp.zeros((slab_time_count, slab_sky_count), dtype=cp.int32)
        repaired_link_count_cp = cp.zeros((slab_time_count, slab_sky_count), dtype=cp.int32)
        dropped_link_count_cp = cp.zeros((slab_time_count, slab_sky_count), dtype=cp.int32)
        grid = (slab_time_count, slab_sky_count, 1)
        block = (1, 1, 1)
        _finalize_direct_epfd_beam_tables_boresight_kernel[grid, block](
            cuda.as_cuda_array(assignments_cp),
            cuda.as_cuda_array(cone_ok_cp),
            cuda.as_cuda_array(selected_alpha_rad_cp),
            cuda.as_cuda_array(selected_beta_rad_cp),
            cuda.as_cuda_array(direct_candidate_slab["row_ptr"]),
            cuda.as_cuda_array(direct_candidate_slab["candidate_sat"]),
            cuda.as_cuda_array(direct_candidate_slab["candidate_alpha_rad"]),
            cuda.as_cuda_array(direct_candidate_slab["candidate_beta_rad"]),
            cuda.as_cuda_array(ras_elevation_deg_cp),
            cuda.as_cuda_array(ras_alpha_rad_cp),
            cuda.as_cuda_array(ras_beta_rad_cp),
            cuda.as_cuda_array(library.sat_min_elev_cp),
            cuda.as_cuda_array(sat_beta_max_rad_cp),
            int(ras_cell_index),
            int(library.n_links),
            int(library.n_beam),
            bool(library.use_cone_check),
            np.float32(beta_tol_rad),
            bool(use_ras_guard),
            np.float32(ras_guard_cos),
            cuda.as_cuda_array(sat_output_index_cp),
            bool(ras_sat_axis_is_compact),
            cuda.as_cuda_array(cell_slot_sat_cp),
            cuda.as_cuda_array(needs_repair_cp),
            cuda.as_cuda_array(sat_slot_used_cp),
            cuda.as_cuda_array(reserved_alpha_cp),
            cuda.as_cuda_array(reserved_beta_cp),
            cuda.as_cuda_array(reserved_present_cp),
            cuda.as_cuda_array(beam_idx_cp),
            cuda.as_cuda_array(beam_alpha_cp),
            cuda.as_cuda_array(beam_beta_cp),
            cuda.as_cuda_array(ras_retargeted_count_cp),
            cuda.as_cuda_array(direct_kept_count_cp),
            cuda.as_cuda_array(repaired_link_count_cp),
            cuda.as_cuda_array(dropped_link_count_cp),
        )
        counts_cp, service_counts_full_cp, reserved_count_cp = _finalize_beam_count_outputs_cp(
            sat_slot_used_cp=sat_slot_used_cp,
            output_sat_indices_cp=output_sat_indices_cp,
            sat_output_count=int(sat_output_count),
            reserved_present_cp=reserved_present_cp,
        )

        result_cp = {
            "beam_idx": beam_idx_cp,
            "beam_alpha_rad": beam_alpha_cp,
            "beam_beta_rad": beam_beta_cp,
            "sat_beam_counts_used": counts_cp,
        }
        if include_full_sat_beam_counts_used:
            result_cp["sat_beam_counts_used_full"] = service_counts_full_cp
        if include_diagnostics:
            result_cp["ras_retargeted_count"] = ras_retargeted_count_cp
            result_cp["ras_reserved_count"] = reserved_count_cp
            result_cp["direct_kept_count"] = direct_kept_count_cp
            result_cp["repaired_link_count"] = repaired_link_count_cp
            result_cp["dropped_link_count"] = dropped_link_count_cp
        return result_cp
    return _finalize_ras_station_parallel_cp(
        library,
        assignments_cp=assignments_cp,
        cone_ok_cp=cone_ok_cp,
        selected_alpha_rad_cp=selected_alpha_rad_cp,
        selected_beta_rad_cp=selected_beta_rad_cp,
        direct_candidate_slab=direct_candidate_slab,
        sat_output_index_cp=sat_output_index_cp,
        output_sat_indices_cp=output_sat_indices_cp,
        sat_output_count=sat_output_count,
        ras_cell_index=int(ras_cell_index),
        ras_elevation_deg_cp=ras_elevation_deg_cp,
        ras_alpha_rad_cp=ras_alpha_rad_cp,
        ras_beta_rad_cp=ras_beta_rad_cp,
        ras_sat_axis_is_compact=bool(ras_sat_axis_is_compact),
        sat_beta_max_rad_cp=sat_beta_max_rad_cp,
        beta_tol_rad=np.float32(beta_tol_rad),
        use_ras_guard=bool(use_ras_guard),
        ras_guard_cos=np.float32(ras_guard_cos),
        include_diagnostics=include_diagnostics,
        include_full_sat_beam_counts_used=include_full_sat_beam_counts_used,
        working_memory_budget_bytes=working_memory_budget_bytes,
        finalize_workspace=finalize_workspace,
        debug_direct_epfd=bool(debug_direct_epfd),
    )


def _finalize_direct_epfd_beams_staged_slab_cp(
    library: GpuSatelliteLinkSelectionLibrary,
    *,
    first_pass_slab: dict[str, Any],
    direct_candidate_slab: dict[str, Any],
    boresight_sparse_slab: dict[str, Any],
    sat_output_index_cp: Any,
    output_sat_indices_cp: Any,
    sat_output_count: int,
    ras_cell_index: int | None,
    ras_elevation_deg_cp: Any | None,
    ras_alpha_rad_cp: Any | None,
    ras_beta_rad_cp: Any | None,
    ras_sat_axis_is_compact: bool,
    sat_beta_max_rad_cp: Any | None,
    beta_tol_rad: np.float32,
    use_ras_guard: bool,
    ras_guard_cos: np.float32,
    mode: str,
    include_diagnostics: bool,
    include_full_sat_beam_counts_used: bool,
    working_memory_budget_bytes: int | None = None,
    finalize_workspace: dict[str, Any] | None = None,
    debug_direct_epfd: bool = False,
) -> dict[str, Any]:
    assignments_cp = first_pass_slab["assignments"]
    cone_ok_cp = first_pass_slab["cone_ok"]
    selected_alpha_rad_cp = first_pass_slab["selected_alpha_rad"]
    selected_beta_rad_cp = first_pass_slab["selected_beta_rad"]
    if assignments_cp.ndim != 3:
        raise RuntimeError("staged boresight direct finalization requires ordinary (T, C, N_links) assignments.")

    slab_time_count = int(assignments_cp.shape[0])
    if int(boresight_sparse_slab["theta1_row_ptr"].shape[0] - 1) // max(slab_time_count, 1) <= 0:
        raise RuntimeError("staged boresight slab must include at least one sky row.")

    theta2_cell_mask_cp = library.boresight_theta2_cell_mask_cp
    if theta2_cell_mask_cp is None:
        theta2_cell_mask_cp = cp.zeros((library.cell_count,), dtype=cp.bool_)

    if mode == "cell_center":
        assert sat_beta_max_rad_cp is not None
        return _finalize_staged_cell_center_parallel_cp(
            library,
            assignments_cp=assignments_cp,
            cone_ok_cp=cone_ok_cp,
            selected_alpha_rad_cp=selected_alpha_rad_cp,
            selected_beta_rad_cp=selected_beta_rad_cp,
            direct_candidate_slab=direct_candidate_slab,
            boresight_sparse_slab=boresight_sparse_slab,
            sat_output_index_cp=sat_output_index_cp,
            output_sat_indices_cp=output_sat_indices_cp,
            sat_output_count=sat_output_count,
            sat_beta_max_rad_cp=sat_beta_max_rad_cp,
            beta_tol_rad=np.float32(beta_tol_rad),
            include_diagnostics=include_diagnostics,
            include_full_sat_beam_counts_used=include_full_sat_beam_counts_used,
            working_memory_budget_bytes=working_memory_budget_bytes,
            finalize_workspace=finalize_workspace,
            debug_direct_epfd=bool(debug_direct_epfd),
        )
    else:
        assert ras_cell_index is not None
        assert ras_elevation_deg_cp is not None
        assert ras_alpha_rad_cp is not None
        assert ras_beta_rad_cp is not None
        assert sat_beta_max_rad_cp is not None
        return _finalize_ras_station_parallel_cp(
            library,
            assignments_cp=assignments_cp,
            cone_ok_cp=cone_ok_cp,
            selected_alpha_rad_cp=selected_alpha_rad_cp,
            selected_beta_rad_cp=selected_beta_rad_cp,
            direct_candidate_slab=direct_candidate_slab,
            sat_output_index_cp=sat_output_index_cp,
            output_sat_indices_cp=output_sat_indices_cp,
            sat_output_count=sat_output_count,
            ras_cell_index=int(ras_cell_index),
            ras_elevation_deg_cp=ras_elevation_deg_cp,
            ras_alpha_rad_cp=ras_alpha_rad_cp,
            ras_beta_rad_cp=ras_beta_rad_cp,
            ras_sat_axis_is_compact=bool(ras_sat_axis_is_compact),
            sat_beta_max_rad_cp=sat_beta_max_rad_cp,
            beta_tol_rad=np.float32(beta_tol_rad),
            use_ras_guard=bool(use_ras_guard),
            ras_guard_cos=np.float32(ras_guard_cos),
            include_diagnostics=include_diagnostics,
            include_full_sat_beam_counts_used=include_full_sat_beam_counts_used,
            boresight_sparse_slab=boresight_sparse_slab,
            theta2_cell_mask_cp=theta2_cell_mask_cp,
            working_memory_budget_bytes=working_memory_budget_bytes,
            finalize_workspace=finalize_workspace,
            debug_direct_epfd=bool(debug_direct_epfd),
        )


def _prepare_direct_finalize_execution_cp(
    library: GpuSatelliteLinkSelectionLibrary,
    *,
    ras_cell_index: int | None,
    ras_sat_azel: Any | None,
    ras_guard_angle_rad: float,
    ras_pointing_mode: str,
    include_diagnostics: bool,
    include_full_sat_beam_counts_used: bool,
    output_sat_indices: Any | None,
    working_memory_budget_bytes: int | None,
    return_device: bool,
    scheduler_target_profile: str | float | None = "high_throughput",
) -> dict[str, Any]:
    _require_cupy()
    library.session._ensure_owner_thread()
    library.session._ensure_open()
    if not np.all(library._cells_seen):
        missing = np.flatnonzero(~library._cells_seen)
        raise RuntimeError(
            f"Missing cell chunks for {missing.size} cells; first missing index is {int(missing[0])}."
        )
    if not library.include_payload:
        raise RuntimeError("finalize_direct_epfd_beams requires include_payload=True on the link library.")

    mode = _normalise_direct_epfd_ras_pointing_mode(ras_pointing_mode)
    if mode == "ras_station":
        if library.ras_topo_cp is None:
            raise RuntimeError("finalize_direct_epfd_beams requires ras_topo to be available on the link library.")
        if ras_cell_index is None:
            raise ValueError("ras_cell_index is required when ras_pointing_mode='ras_station'.")
        if ras_cell_index < 0 or ras_cell_index >= library.cell_count:
            raise ValueError(
                f"ras_cell_index must be in [0, {library.cell_count}), got {int(ras_cell_index)}."
            )
        if ras_sat_azel is None:
            raise ValueError("ras_sat_azel is required when ras_pointing_mode='ras_station'.")

    output_sat_indices_cp, sat_output_index_cp, sat_output_count = _normalise_direct_output_sat_indices(
        output_sat_indices,
        sat_count=library.sat_count,
    )

    ras_elevation_deg_cp = None
    ras_alpha_rad_cp = None
    ras_beta_rad_cp = None
    ras_sat_axis_is_compact = False
    sat_beta_max_rad_cp = None
    beta_tol_rad = np.float32(float(library.beta_tol_deg) * np.pi / 180.0)
    if mode == "ras_station":
        ras_lookup = _prepare_finalize_ras_station_lookup_cupy(
            ras_sat_azel,
            time_count=library.time_count,
            library_sat_count=library.sat_count,
            output_sat_indices_cp=output_sat_indices_cp,
            ras_topo_cp=_to_cupy_array(library.ras_topo_cp, dtype=cp.float32),
        )
        ras_elevation_deg_cp = ras_lookup["ras_elevation_deg_cp"]
        ras_alpha_rad_cp = ras_lookup["ras_alpha_rad_cp"]
        ras_beta_rad_cp = ras_lookup["ras_beta_rad_cp"]
        ras_sat_axis_is_compact = bool(ras_lookup["ras_sat_axis_is_compact"])
        sat_beta_max_rad_cp = (
            _to_cupy_array(library.sat_beta_max_cp, dtype=cp.float32) * cp.float32(np.pi / 180.0)
        ).astype(cp.float32, copy=False)
    elif library.boresight_active:
        sat_beta_max_rad_cp = (
            _to_cupy_array(library.sat_beta_max_cp, dtype=cp.float32) * cp.float32(np.pi / 180.0)
        ).astype(cp.float32, copy=False)

    use_ras_guard = bool(float(ras_guard_angle_rad) > 0.0)
    ras_guard_cos = np.float32(np.cos(np.float32(max(0.0, float(ras_guard_angle_rad)))))
    slab_plan = _plan_direct_finalize_slabs(
        library,
        sat_output_count=sat_output_count,
        include_diagnostics=include_diagnostics,
        mode=mode,
        working_memory_budget_bytes=working_memory_budget_bytes,
        scheduler_target_profile=scheduler_target_profile,
        return_device=return_device,
    )

    return {
        "mode": mode,
        "include_diagnostics": bool(include_diagnostics),
        "include_full_sat_beam_counts_used": bool(include_full_sat_beam_counts_used),
        "output_sat_indices_cp": output_sat_indices_cp,
        "sat_output_index_cp": sat_output_index_cp,
        "sat_output_count": int(sat_output_count),
        "ras_cell_index": None if ras_cell_index is None else int(ras_cell_index),
        "ras_elevation_deg_cp": ras_elevation_deg_cp,
        "ras_alpha_rad_cp": ras_alpha_rad_cp,
        "ras_beta_rad_cp": ras_beta_rad_cp,
        "ras_sat_axis_is_compact": bool(ras_sat_axis_is_compact),
        "sat_beta_max_rad_cp": sat_beta_max_rad_cp,
        "beta_tol_rad": np.float32(beta_tol_rad),
        "use_ras_guard": bool(use_ras_guard),
        "ras_guard_cos": np.float32(ras_guard_cos),
        "slab_plan": dict(slab_plan),
        "sky_total": int(library.boresight_sky_count if library.boresight_active else 1),
        "time_chunk_size": int(slab_plan["time_chunk_size"]),
        "sky_chunk_size": int(slab_plan["sky_chunk_size"]),
        "finalize_chunk_shape": {
            "time_chunk_size": int(slab_plan["time_chunk_size"]),
            "sky_chunk_size": int(slab_plan["sky_chunk_size"]),
        },
        "estimated_component_bytes": dict(slab_plan.get("estimated_component_bytes") or {}),
        "workspace": {},
    }


def _build_direct_finalize_time_slab_results_cp(
    library: GpuSatelliteLinkSelectionLibrary,
    *,
    context: Mapping[str, Any],
    time_start: int,
    debug_direct_epfd: bool,
    slab_handler: Callable[[dict[str, Any]], None] | None = None,
) -> list[dict[str, Any]]:
    time_start_i = int(time_start)
    time_stop_i = min(
        time_start_i + int(context["time_chunk_size"]),
        int(library.time_count),
    )
    slab_infos: list[dict[str, Any]] = []
    if time_stop_i <= time_start_i:
        return slab_infos

    def _emit_slab_info(
        *,
        slab_result: dict[str, Any],
        sky_start: int,
        sky_stop: int,
        boresight_sparse_seconds: float,
        compaction_seconds: float,
        finalize_seconds: float,
        observed_memory: Mapping[str, Any],
        direct_candidate_seconds_share: float,
        first_pass_seconds_share: float,
        boresight_active_local: bool,
    ) -> None:
        compaction_stats = dict(slab_result.pop("_boresight_compaction_stats", {}) or {})
        compaction_seconds_use = float(
            slab_result.pop("_boresight_compaction_seconds", compaction_seconds) or compaction_seconds
        )
        if debug_direct_epfd and "debug_direct_epfd_stats" in slab_result:
            slab_stats = dict(slab_result.get("debug_direct_epfd_stats", {}))
            slab_result["debug_direct_epfd_stats"] = slab_stats
        slab_info = {
            "time_start": int(time_start_i),
            "time_stop": int(time_stop_i),
            "sky_start": int(sky_start),
            "sky_stop": int(sky_stop),
            "boresight_active": bool(boresight_active_local),
            "result": slab_result,
            "substage_timings": {
                "direct_candidate_extraction": float(direct_candidate_seconds_share),
                "first_pass_selector": float(first_pass_seconds_share),
                "boresight_sparse_restrictions": float(boresight_sparse_seconds),
                "boresight_compaction": float(compaction_seconds_use),
                "retarget_repair_finalize": float(finalize_seconds),
                "slab_result_storage": 0.0,
            },
            "observed_memory": dict(observed_memory),
            "estimated_component_bytes": dict(context["estimated_component_bytes"]),
            "chunk_shape": dict(context.get("finalize_chunk_shape") or {}),
            "compaction_stats": dict(compaction_stats),
        }
        if slab_handler is None:
            slab_infos.append(slab_info)
        else:
            slab_handler(slab_info)

    working_memory_budget_bytes = int(context["slab_plan"]["working_memory_budget_bytes"])
    time_slab_memory_observation = _start_gpu_memory_observation_cp()
    direct_candidate_t0 = time.perf_counter()
    direct_candidate_slab = _direct_candidate_slab_cp(
        library,
        time_start=time_start_i,
        time_stop=time_stop_i,
    )
    direct_candidate_seconds = max(time.perf_counter() - direct_candidate_t0, 0.0)
    time_slab_memory_observation = _update_gpu_memory_observation_cp(time_slab_memory_observation)

    if library.boresight_active:
        n_sky_slabs_for_time = int(
            max(
                1,
                np.ceil(
                    float(int(context["sky_total"]))
                    / float(max(1, int(context["sky_chunk_size"])))
                ),
            )
        )
        first_pass_t0 = time.perf_counter()
        first_pass_slab = _finalize_link_selection_library_minimal_slab_cp(
            library,
            time_start=time_start_i,
            time_stop=time_stop_i,
            force_ordinary=True,
            selector_backend=GPU_DIRECT_SELECTOR_BACKEND_FAST,
            working_memory_budget_bytes=working_memory_budget_bytes,
            debug_direct_epfd=bool(debug_direct_epfd),
        )
        first_pass_seconds = max(time.perf_counter() - first_pass_t0, 0.0)
        time_slab_memory_observation = _update_gpu_memory_observation_cp(time_slab_memory_observation)
        try:
            for sky_start in range(0, int(context["sky_total"]), int(context["sky_chunk_size"])):
                sky_stop = min(
                    sky_start + int(context["sky_chunk_size"]),
                    int(context["sky_total"]),
                )
                slab_memory_observation = dict(time_slab_memory_observation)
                boresight_sparse_t0 = time.perf_counter()
                boresight_sparse_slab = _build_boresight_sparse_restrictions_slab_cp(
                    library,
                    time_start=time_start_i,
                    time_stop=time_stop_i,
                    sky_start=sky_start,
                    sky_stop=sky_stop,
                    working_memory_budget_bytes=working_memory_budget_bytes,
                )
                boresight_sparse_seconds = max(time.perf_counter() - boresight_sparse_t0, 0.0)
                slab_memory_observation = _update_gpu_memory_observation_cp(slab_memory_observation)
                try:
                    finalize_t0 = time.perf_counter()
                    slab_result = _finalize_direct_epfd_beams_staged_slab_cp(
                        library,
                        first_pass_slab=first_pass_slab,
                        direct_candidate_slab=direct_candidate_slab,
                        boresight_sparse_slab=boresight_sparse_slab,
                        sat_output_index_cp=context["sat_output_index_cp"],
                        output_sat_indices_cp=context["output_sat_indices_cp"],
                        sat_output_count=int(context["sat_output_count"]),
                        ras_cell_index=context["ras_cell_index"],
                        ras_elevation_deg_cp=(
                            None
                            if context["ras_elevation_deg_cp"] is None
                            else context["ras_elevation_deg_cp"][time_start_i:time_stop_i]
                        ),
                        ras_alpha_rad_cp=(
                            None
                            if context["ras_alpha_rad_cp"] is None
                            else context["ras_alpha_rad_cp"][time_start_i:time_stop_i]
                        ),
                        ras_beta_rad_cp=(
                            None
                            if context["ras_beta_rad_cp"] is None
                            else context["ras_beta_rad_cp"][time_start_i:time_stop_i]
                        ),
                        ras_sat_axis_is_compact=bool(context["ras_sat_axis_is_compact"]),
                        sat_beta_max_rad_cp=context["sat_beta_max_rad_cp"],
                        beta_tol_rad=np.float32(context["beta_tol_rad"]),
                        use_ras_guard=bool(context["use_ras_guard"]),
                        ras_guard_cos=np.float32(context["ras_guard_cos"]),
                        mode=str(context["mode"]),
                        include_diagnostics=bool(context["include_diagnostics"]),
                        include_full_sat_beam_counts_used=bool(
                            context["include_full_sat_beam_counts_used"]
                        ),
                        working_memory_budget_bytes=working_memory_budget_bytes,
                        finalize_workspace=context.get("workspace"),
                        debug_direct_epfd=bool(debug_direct_epfd),
                    )
                    finalize_seconds = max(time.perf_counter() - finalize_t0, 0.0)
                    slab_memory_observation = _update_gpu_memory_observation_cp(
                        slab_memory_observation
                    )
                    if debug_direct_epfd:
                        slab_stats = dict(slab_result.get("debug_direct_epfd_stats", {}))
                        slab_stats.update(first_pass_slab.get("debug_direct_epfd_stats", {}))
                        slab_result["debug_direct_epfd_stats"] = slab_stats
                    _emit_slab_info(
                        slab_result=slab_result,
                        sky_start=int(sky_start),
                        sky_stop=int(sky_stop),
                        boresight_sparse_seconds=float(boresight_sparse_seconds),
                        compaction_seconds=0.0,
                        finalize_seconds=float(finalize_seconds),
                        observed_memory=_finalize_gpu_memory_observation_cp(
                            slab_memory_observation
                        ),
                        direct_candidate_seconds_share=float(
                            direct_candidate_seconds / float(max(1, n_sky_slabs_for_time))
                        ),
                        first_pass_seconds_share=float(
                            first_pass_seconds / float(max(1, n_sky_slabs_for_time))
                        ),
                        boresight_active_local=True,
                    )
                finally:
                    del boresight_sparse_slab
        finally:
            del first_pass_slab
            del direct_candidate_slab
        return slab_infos

    first_pass_t0 = time.perf_counter()
    first_pass_slab = _finalize_link_selection_library_minimal_slab_cp(
        library,
        time_start=time_start_i,
        time_stop=time_stop_i,
        selector_backend=GPU_DIRECT_SELECTOR_BACKEND_FAST,
        working_memory_budget_bytes=working_memory_budget_bytes,
        debug_direct_epfd=bool(debug_direct_epfd),
    )
    first_pass_seconds = max(time.perf_counter() - first_pass_t0, 0.0)
    time_slab_memory_observation = _update_gpu_memory_observation_cp(time_slab_memory_observation)
    try:
        finalize_t0 = time.perf_counter()
        slab_result = _finalize_direct_epfd_beams_slab_cp(
            library,
            first_pass_slab=first_pass_slab,
            direct_candidate_slab=direct_candidate_slab,
            sat_output_index_cp=context["sat_output_index_cp"],
            output_sat_indices_cp=context["output_sat_indices_cp"],
            sat_output_count=int(context["sat_output_count"]),
            ras_cell_index=context["ras_cell_index"],
            ras_elevation_deg_cp=(
                None
                if context["ras_elevation_deg_cp"] is None
                else context["ras_elevation_deg_cp"][time_start_i:time_stop_i]
            ),
            ras_alpha_rad_cp=(
                None
                if context["ras_alpha_rad_cp"] is None
                else context["ras_alpha_rad_cp"][time_start_i:time_stop_i]
            ),
            ras_beta_rad_cp=(
                None
                if context["ras_beta_rad_cp"] is None
                else context["ras_beta_rad_cp"][time_start_i:time_stop_i]
            ),
            ras_sat_axis_is_compact=bool(context["ras_sat_axis_is_compact"]),
            sat_beta_max_rad_cp=context["sat_beta_max_rad_cp"],
            beta_tol_rad=np.float32(context["beta_tol_rad"]),
            use_ras_guard=bool(context["use_ras_guard"]),
            ras_guard_cos=np.float32(context["ras_guard_cos"]),
            mode=str(context["mode"]),
            include_diagnostics=bool(context["include_diagnostics"]),
            include_full_sat_beam_counts_used=bool(context["include_full_sat_beam_counts_used"]),
            working_memory_budget_bytes=working_memory_budget_bytes,
            finalize_workspace=context.get("workspace"),
            debug_direct_epfd=bool(debug_direct_epfd),
        )
        finalize_seconds = max(time.perf_counter() - finalize_t0, 0.0)
        time_slab_memory_observation = _update_gpu_memory_observation_cp(time_slab_memory_observation)
        if debug_direct_epfd:
            slab_stats = dict(slab_result.get("debug_direct_epfd_stats", {}))
            slab_stats.update(first_pass_slab.get("debug_direct_epfd_stats", {}))
            slab_result["debug_direct_epfd_stats"] = slab_stats
        _emit_slab_info(
            slab_result=slab_result,
            sky_start=0,
            sky_stop=1,
            boresight_sparse_seconds=0.0,
            compaction_seconds=0.0,
            finalize_seconds=float(finalize_seconds),
            observed_memory=_finalize_gpu_memory_observation_cp(
                time_slab_memory_observation
            ),
            direct_candidate_seconds_share=float(direct_candidate_seconds),
            first_pass_seconds_share=float(first_pass_seconds),
            boresight_active_local=False,
        )
    finally:
        del first_pass_slab
        del direct_candidate_slab
    return slab_infos


def _iter_direct_finalize_slab_results_cp(
    library: GpuSatelliteLinkSelectionLibrary,
    *,
    ras_cell_index: int | None,
    ras_sat_azel: Any | None,
    ras_guard_angle_rad: float,
    ras_pointing_mode: str,
    include_diagnostics: bool,
    include_full_sat_beam_counts_used: bool,
    output_sat_indices: Any | None,
    working_memory_budget_bytes: int | None,
    debug_direct_epfd: bool = False,
    return_device: bool = True,
    scheduler_target_profile: str | float | None = "high_throughput",
) -> Iterator[dict[str, Any]]:
    with library.session._temporary_activation():
        context = _prepare_direct_finalize_execution_cp(
            library,
            ras_cell_index=ras_cell_index,
            ras_sat_azel=ras_sat_azel,
            ras_guard_angle_rad=ras_guard_angle_rad,
            ras_pointing_mode=ras_pointing_mode,
            include_diagnostics=include_diagnostics,
            include_full_sat_beam_counts_used=include_full_sat_beam_counts_used,
            output_sat_indices=output_sat_indices,
            working_memory_budget_bytes=working_memory_budget_bytes,
            return_device=return_device,
            scheduler_target_profile=scheduler_target_profile,
        )
        for time_start in range(0, int(library.time_count), int(context["time_chunk_size"])):
            for slab_info in _build_direct_finalize_time_slab_results_cp(
                library,
                context=context,
                time_start=int(time_start),
                debug_direct_epfd=bool(debug_direct_epfd),
            ):
                yield slab_info


def _finalize_direct_epfd_beams_cp(
    library: GpuSatelliteLinkSelectionLibrary,
    *,
    ras_cell_index: int | None,
    ras_sat_azel: Any | None,
    ras_guard_angle_rad: float,
    ras_pointing_mode: str,
    include_diagnostics: bool,
    include_full_sat_beam_counts_used: bool,
    output_sat_indices: Any | None,
    working_memory_budget_bytes: int | None,
    debug_direct_epfd: bool,
    return_device: bool,
    scheduler_target_profile: str | float | None = "high_throughput",
) -> dict[str, Any]:
    with library.session._temporary_activation():
        context = _prepare_direct_finalize_execution_cp(
            library,
            ras_cell_index=ras_cell_index,
            ras_sat_azel=ras_sat_azel,
            ras_guard_angle_rad=ras_guard_angle_rad,
            ras_pointing_mode=ras_pointing_mode,
            include_diagnostics=include_diagnostics,
            include_full_sat_beam_counts_used=include_full_sat_beam_counts_used,
            output_sat_indices=output_sat_indices,
            working_memory_budget_bytes=working_memory_budget_bytes,
            return_device=return_device,
            scheduler_target_profile=scheduler_target_profile,
        )
        result = _allocate_direct_finalize_result(
            time_count=library.time_count,
            sky_count=int(context["sky_total"]),
            sat_output_count=int(context["sat_output_count"]),
            sat_count=library.sat_count,
            n_beam=library.n_beam,
            include_diagnostics=include_diagnostics,
            include_full_sat_beam_counts_used=include_full_sat_beam_counts_used,
            boresight_active=bool(library.boresight_active),
            return_device=return_device,
        )
        debug_stats_all: list[dict[str, Any]] = []
        def _store_slab_info(slab_info: dict[str, Any]) -> None:
            _store_direct_finalize_slab_result(
                result,
                slab_info["result"],
                boresight_active=bool(slab_info["boresight_active"]),
                time_start=int(slab_info["time_start"]),
                time_stop=int(slab_info["time_stop"]),
                sky_start=int(slab_info["sky_start"]),
                sky_stop=int(slab_info["sky_stop"]),
                return_device=return_device,
            )
            if debug_direct_epfd and "debug_direct_epfd_stats" in slab_info["result"]:
                slab_stats = dict(slab_info["result"]["debug_direct_epfd_stats"])
                slab_stats.update(
                    time_start=int(slab_info["time_start"]),
                    time_stop=int(slab_info["time_stop"]),
                    sky_start=int(slab_info["sky_start"]),
                    sky_stop=int(slab_info["sky_stop"]),
                )
                debug_stats_all.append(slab_stats)
        for time_start in range(0, int(library.time_count), int(context["time_chunk_size"])):
            _build_direct_finalize_time_slab_results_cp(
                library,
                context=context,
                time_start=int(time_start),
                debug_direct_epfd=bool(debug_direct_epfd),
                slab_handler=_store_slab_info,
            )
    if debug_direct_epfd:
        result["debug_direct_epfd"] = True
        result["debug_direct_epfd_stats"] = debug_stats_all
    if return_device:
        _canonicalize_direct_beam_slots_cp(
            result["beam_idx"],
            result["beam_alpha_rad"],
            result["beam_beta_rad"],
        )
        return _device_result_dict_from_cupy(result)
    _canonicalize_direct_beam_slots_np(
        result["beam_idx"],
        result["beam_alpha_rad"],
        result["beam_beta_rad"],
    )
    return result


@dataclass(slots=True)
class GpuConditionedTemplatePlan:
    """
    Execution plan for conditioned sampler template generation.

    Parameters
    ----------
    mode_requested, mode_used : {"per_source", "per_row", "hybrid"}
        Requested template-generation mode and the actual mode selected after
        scratch-memory checks.
    active_row_count, unit_count, pool_size, template_size : int
        Compact problem dimensions used by the conditioned-template kernels.
    estimated_scratch_bytes : int
        Estimated scratch-memory requirement for the chosen execution mode.
    flat_shape : tuple[int, int]
        Flattened row/template shape produced by the template planner.

    Notes
    -----
    The ``d_*`` fields hold the compact device metadata used by the
    conditioned-sampling kernels. They are session-owned scratch allocations.
    """
    mode_requested: str
    mode_used: str
    active_row_count: int
    unit_count: int
    pool_size: int
    template_size: int
    estimated_scratch_bytes: int
    flat_shape: tuple[int, int]
    d_active_rows: Any = field(repr=False)
    d_row_to_unit: Any = field(repr=False)
    d_unit_source_kind: Any = field(repr=False)
    d_unit_source_id: Any = field(repr=False)
    d_unit_beta_max_rad: Any = field(repr=False)


def _resolve_conditioned_mode_used(
    *,
    requested_mode: str,
    active_row_count: int,
    pool_size: int,
) -> tuple[str, int]:
    scratch_bytes = _conditioned_template_scratch_bytes(active_row_count, pool_size)
    if requested_mode == CONDITIONED_TEMPLATE_MODE_HYBRID:
        if (
            active_row_count * pool_size <= _CONDITIONED_TEMPLATE_PER_ROW_ELEMENT_LIMIT
            and scratch_bytes <= _CONDITIONED_TEMPLATE_PER_ROW_SCRATCH_LIMIT_BYTES
        ):
            return CONDITIONED_TEMPLATE_MODE_PER_ROW, scratch_bytes
        return CONDITIONED_TEMPLATE_MODE_PER_SOURCE, scratch_bytes
    return requested_mode, scratch_bytes


def _resolve_sampler_sources_cp(
    context: GpuAngleSamplerContext,
    sat_azimuth_deg: Any,
    sat_elevation_deg: Any,
    sat_belt_id: Any,
) -> dict[str, Any]:
    az = _to_cupy_array(sat_azimuth_deg, dtype=cp.float32)
    el = _to_cupy_array(sat_elevation_deg, dtype=cp.float32)
    belt = _to_cupy_array(sat_belt_id, dtype=cp.float32)
    if az.shape != el.shape or az.shape != belt.shape:
        raise ValueError(
            "sat_azimuth_deg, sat_elevation_deg, and sat_belt_id must share the same shape."
        )
    if context.skycell_mode != "s1586":
        raise NotImplementedError(
            "The EPFDflow GPU conditioned sampler currently supports only skycell_mode='s1586'."
        )

    sky = _s1586_skycell_id_device(az, el)
    source_kind = cp.full(az.shape, SAMPLER_SOURCE_INVALID, dtype=cp.int8)
    source_id = cp.full(az.shape, -1, dtype=cp.int32)

    valid = cp.isfinite(az) & cp.isfinite(el) & cp.isfinite(belt)
    belt_i64 = cp.rint(belt).astype(cp.int64, copy=False)
    belt_is_int = cp.abs(belt - belt_i64.astype(cp.float32)) <= cp.float32(1.0e-6)
    in_belt = valid & belt_is_int & (belt_i64 >= 0) & (belt_i64 < context.n_belts)
    in_sky = in_belt & (sky >= 0) & (sky < context.n_skycells)

    if int(cp.nonzero(in_sky)[0].size) <= 0:
        return {
            "skycell_id": sky,
            "source_kind": source_kind,
            "source_id": source_id,
            "valid_mask": in_sky,
        }

    group_ptr = _to_cupy_array(context.d_group_ptr, dtype=cp.int64)
    group_raw = _to_cupy_array(context.d_group_raw_counts, dtype=cp.int32)
    belt_ptr = _to_cupy_array(context.d_belt_ptr, dtype=cp.int64)
    belt_raw = _to_cupy_array(context.d_belt_raw_counts, dtype=cp.int32)

    group_id = belt_i64 * cp.int64(context.n_skycells) + sky.astype(cp.int64, copy=False)
    use_group = in_sky & (
        group_raw[group_id] >= np.int32(context.cond_min_group_samples)
    ) & (group_ptr[group_id + 1] > group_ptr[group_id])
    use_belt = in_sky & (~use_group) & (
        belt_raw[belt_i64] >= np.int32(context.cond_min_belt_samples)
    ) & (belt_ptr[belt_i64 + 1] > belt_ptr[belt_i64])
    use_global = in_sky & (~use_group) & (~use_belt)

    source_kind[use_group] = SAMPLER_SOURCE_GROUP
    source_id[use_group] = group_id[use_group].astype(cp.int32, copy=False)
    source_kind[use_belt] = SAMPLER_SOURCE_BELT
    source_id[use_belt] = belt_i64[use_belt].astype(cp.int32, copy=False)
    source_kind[use_global] = SAMPLER_SOURCE_GLOBAL
    source_id[use_global] = cp.int32(0)
    return {
        "skycell_id": sky,
        "source_kind": source_kind,
        "source_id": source_id,
        "valid_mask": in_sky,
    }


def _make_conditioned_template_plan_cp(
    source_kind: Any,
    source_id: Any,
    vis_mask_horizon: Any,
    beta_max_rad_per_sat: Any,
    *,
    mode: str,
    pool_size: int,
    template_size: int,
) -> GpuConditionedTemplatePlan:
    source_kind_cp = _to_cupy_array(source_kind, dtype=cp.int8)
    source_id_cp = _to_cupy_array(source_id, dtype=cp.int32)
    vis_cp = _to_cupy_array(vis_mask_horizon, dtype=cp.bool_)
    if source_kind_cp.shape != source_id_cp.shape or source_kind_cp.shape != vis_cp.shape:
        raise ValueError("source_kind, source_id, and vis_mask_horizon must share the same shape.")

    flat_shape = tuple(int(v) for v in source_kind_cp.shape)
    flat_rows = int(np.prod(flat_shape, dtype=np.int64))
    beta_max_sat = _to_cupy_array(beta_max_rad_per_sat, dtype=cp.float32).reshape(-1)
    if beta_max_sat.size != flat_shape[-1]:
        raise ValueError(
            "beta_max_rad_per_sat must have length equal to the satellite axis "
            f"{flat_shape[-1]}, got {int(beta_max_sat.size)}."
        )
    beta_max_row = cp.broadcast_to(beta_max_sat[None, :], flat_shape).reshape(flat_rows)

    active_mask = vis_cp.reshape(flat_rows) & (source_kind_cp.reshape(flat_rows) != SAMPLER_SOURCE_INVALID)
    active_rows = cp.nonzero(active_mask)[0].astype(cp.int32, copy=False)
    active_row_count = int(active_rows.size)
    mode_used, scratch_bytes = _resolve_conditioned_mode_used(
        requested_mode=_normalise_conditioned_template_mode(mode),
        active_row_count=active_row_count,
        pool_size=int(pool_size),
    )

    if active_row_count == 0:
        empty_i32 = cp.empty(0, dtype=cp.int32)
        empty_i8 = cp.empty(0, dtype=cp.int8)
        empty_f32 = cp.empty(0, dtype=cp.float32)
        return GpuConditionedTemplatePlan(
            mode_requested=_normalise_conditioned_template_mode(mode),
            mode_used=mode_used,
            active_row_count=0,
            unit_count=0,
            pool_size=int(pool_size),
            template_size=int(template_size),
            estimated_scratch_bytes=int(scratch_bytes),
            flat_shape=flat_shape,
            d_active_rows=empty_i32,
            d_row_to_unit=empty_i32,
            d_unit_source_kind=empty_i8,
            d_unit_source_id=empty_i32,
            d_unit_beta_max_rad=empty_f32,
        )

    source_kind_flat = source_kind_cp.reshape(flat_rows)[active_rows]
    source_id_flat = source_id_cp.reshape(flat_rows)[active_rows]
    beta_max_active = beta_max_row[active_rows]

    if mode_used == CONDITIONED_TEMPLATE_MODE_PER_ROW:
        row_to_unit = cp.arange(active_row_count, dtype=cp.int32)
        unit_source_kind = source_kind_flat.astype(cp.int8, copy=False)
        unit_source_id = source_id_flat.astype(cp.int32, copy=False)
        unit_beta_max = beta_max_active.astype(cp.float32, copy=False)
        unit_count = active_row_count
    else:
        encoded = (source_kind_flat.astype(cp.int64, copy=False) + cp.int64(1)) * cp.int64(1_000_000_000_000)
        encoded = encoded + source_id_flat.astype(cp.int64, copy=False)
        unique_encoded, row_to_unit = cp.unique(encoded, return_inverse=True)
        unit_source_kind = (unique_encoded // cp.int64(1_000_000_000_000) - cp.int64(1)).astype(cp.int8, copy=False)
        unit_source_id = (unique_encoded % cp.int64(1_000_000_000_000)).astype(cp.int32, copy=False)
        unit_beta_max = cp.full(unique_encoded.shape, cp.float32(0.0), dtype=cp.float32)
        cp.maximum.at(unit_beta_max, row_to_unit, beta_max_active.astype(cp.float32, copy=False))
        unit_count = int(unique_encoded.size)

    return GpuConditionedTemplatePlan(
        mode_requested=_normalise_conditioned_template_mode(mode),
        mode_used=mode_used,
        active_row_count=active_row_count,
        unit_count=unit_count,
        pool_size=int(pool_size),
        template_size=int(template_size),
        estimated_scratch_bytes=int(scratch_bytes),
        flat_shape=flat_shape,
        d_active_rows=active_rows,
        d_row_to_unit=row_to_unit.astype(cp.int32, copy=False),
        d_unit_source_kind=unit_source_kind,
        d_unit_source_id=unit_source_id,
        d_unit_beta_max_rad=unit_beta_max,
    )


def _sample_unconditional_flat_cp(
    context: GpuAngleSamplerContext,
    rng: Any,
    n_draws: int,
) -> tuple[Any, Any]:
    n = int(n_draws)
    if n < 0:
        raise ValueError("n_draws must be non-negative.")
    if n == 0:
        empty = cp.empty(0, dtype=cp.float32)
        return empty, empty

    cdf = _to_cupy_array(context.d_cdf)
    beta_edges = _to_cupy_array(context.d_beta_edges, dtype=cp.float32)
    alpha_edges = _to_cupy_array(context.d_alpha_edges, dtype=cp.float32)

    u0 = rng.random_sample(n).astype(cdf.dtype, copy=False)
    idx_flat = cp.searchsorted(cdf, u0, side="right")
    i_beta = idx_flat // int(context.n_alpha)
    i_alpha = idx_flat - i_beta * int(context.n_alpha)

    b0 = beta_edges[i_beta]
    b1 = beta_edges[i_beta + 1]
    a0 = alpha_edges[i_alpha]
    a1 = alpha_edges[i_alpha + 1]

    wb = rng.random_sample(n).astype(cp.float32, copy=False)
    wa = rng.random_sample(n).astype(cp.float32, copy=False)
    beta = b0 + wb * (b1 - b0)
    alpha = a0 + wa * (a1 - a0)
    return beta.astype(cp.float32, copy=False), alpha.astype(cp.float32, copy=False)


def _sample_conditioned_candidate_batch_cp(
    context: GpuAngleSamplerContext,
    source_kind: Any,
    source_id: Any,
    *,
    chunk_size: int,
    seed: int,
) -> dict[str, Any]:
    kind = _to_cupy_array(source_kind, dtype=cp.int8).reshape(-1)
    source = _to_cupy_array(source_id, dtype=cp.int32).reshape(-1)
    if kind.shape != source.shape:
        raise ValueError("source_kind and source_id must share the same shape.")

    size = int(chunk_size)
    if size <= 0:
        raise ValueError("chunk_size must be positive.")

    row_count = int(kind.size)
    alpha_deg = cp.full((row_count, size), cp.nan, dtype=cp.float32)
    beta_deg = cp.full((row_count, size), cp.nan, dtype=cp.float32)
    if row_count == 0:
        return {
            "alpha_rad": alpha_deg,
            "beta_rad": beta_deg,
        }

    valid_kind = kind != SAMPLER_SOURCE_INVALID
    if bool(cp.any(valid_kind).get()):
        rng = _cupy_rng(seed)
        group_ptr = _to_cupy_array(context.d_group_ptr, dtype=cp.int64)
        group_beta_pool = _to_cupy_array(context.d_group_beta_pool, dtype=cp.float32)
        group_alpha_pool = _to_cupy_array(context.d_group_alpha_pool, dtype=cp.float32)
        belt_ptr = _to_cupy_array(context.d_belt_ptr, dtype=cp.int64)
        belt_beta_pool = _to_cupy_array(context.d_belt_beta_pool, dtype=cp.float32)
        belt_alpha_pool = _to_cupy_array(context.d_belt_alpha_pool, dtype=cp.float32)

        for source_kind_value, ptr, beta_pool, alpha_pool in (
            (SAMPLER_SOURCE_GROUP, group_ptr, group_beta_pool, group_alpha_pool),
            (SAMPLER_SOURCE_BELT, belt_ptr, belt_beta_pool, belt_alpha_pool),
        ):
            mask = valid_kind & (kind == source_kind_value)
            if not bool(cp.any(mask).get()):
                continue
            rows = cp.nonzero(mask)[0].astype(cp.int32, copy=False)
            ids = source[rows].astype(cp.int64, copy=False)
            start = ptr[ids]
            stop = ptr[ids + 1]
            span = stop - start
            if bool(cp.any(span <= 0).get()):
                raise RuntimeError("Conditioned sampler source resolved an empty candidate pool.")
            u = rng.random_sample((int(rows.size), size)).astype(cp.float32, copy=False)
            draws = start[:, None] + cp.floor(u * span[:, None].astype(cp.float32, copy=False)).astype(cp.int64)
            beta_deg[rows, :] = beta_pool[draws]
            alpha_deg[rows, :] = alpha_pool[draws]

        global_mask = valid_kind & (kind == SAMPLER_SOURCE_GLOBAL)
        if bool(cp.any(global_mask).get()):
            rows = cp.nonzero(global_mask)[0].astype(cp.int32, copy=False)
            beta_global, alpha_global = _sample_unconditional_flat_cp(
                context,
                rng,
                int(rows.size) * size,
            )
            beta_deg[rows, :] = beta_global.reshape(int(rows.size), size)
            alpha_deg[rows, :] = alpha_global.reshape(int(rows.size), size)

    deg2rad = cp.float32(np.pi / 180.0)
    two_pi = cp.float32(2.0 * np.pi)
    return {
        "alpha_rad": cp.remainder(alpha_deg * deg2rad, two_pi).astype(cp.float32, copy=False),
        "beta_rad": (beta_deg * deg2rad).astype(cp.float32, copy=False),
    }


def _sample_conditioned_candidate_pools_cp(
    context: GpuAngleSamplerContext,
    source_kind: Any,
    source_id: Any,
    *,
    pool_size: int,
    seed: int,
) -> dict[str, Any]:
    kind = _to_cupy_array(source_kind, dtype=cp.int8).reshape(-1)
    source = _to_cupy_array(source_id, dtype=cp.int32).reshape(-1)
    if kind.shape != source.shape:
        raise ValueError("source_kind and source_id must share the same shape.")
    size = int(pool_size)
    if size <= 0:
        raise ValueError("pool_size must be positive.")

    unit_count = int(kind.size)
    rng = _cupy_rng(seed)
    beta_deg = cp.full((unit_count, size), cp.nan, dtype=cp.float32)
    alpha_deg = cp.full((unit_count, size), cp.nan, dtype=cp.float32)

    valid_kind = kind != SAMPLER_SOURCE_INVALID
    if bool(cp.any(valid_kind).get()):
        group_ptr = _to_cupy_array(context.d_group_ptr, dtype=cp.int64)
        group_beta_pool = _to_cupy_array(context.d_group_beta_pool, dtype=cp.float32)
        group_alpha_pool = _to_cupy_array(context.d_group_alpha_pool, dtype=cp.float32)
        belt_ptr = _to_cupy_array(context.d_belt_ptr, dtype=cp.int64)
        belt_beta_pool = _to_cupy_array(context.d_belt_beta_pool, dtype=cp.float32)
        belt_alpha_pool = _to_cupy_array(context.d_belt_alpha_pool, dtype=cp.float32)

        for source_kind_value, ptr, beta_pool, alpha_pool in (
            (SAMPLER_SOURCE_GROUP, group_ptr, group_beta_pool, group_alpha_pool),
            (SAMPLER_SOURCE_BELT, belt_ptr, belt_beta_pool, belt_alpha_pool),
        ):
            mask = valid_kind & (kind == source_kind_value)
            if not bool(cp.any(mask).get()):
                continue
            rows = cp.nonzero(mask)[0].astype(cp.int32, copy=False)
            ids = source[rows].astype(cp.int64, copy=False)
            start = ptr[ids]
            stop = ptr[ids + 1]
            span = stop - start
            if bool(cp.any(span <= 0).get()):
                raise RuntimeError("Conditioned sampler source resolved an empty candidate pool.")
            u = rng.random_sample((int(rows.size), size)).astype(cp.float32, copy=False)
            draws = start[:, None] + cp.floor(u * span[:, None].astype(cp.float32, copy=False)).astype(cp.int64)
            beta_deg[rows, :] = beta_pool[draws]
            alpha_deg[rows, :] = alpha_pool[draws]

        mask_global = valid_kind & (kind == SAMPLER_SOURCE_GLOBAL)
        if bool(cp.any(mask_global).get()):
            rows = cp.nonzero(mask_global)[0].astype(cp.int32, copy=False)
            beta_global, alpha_global = _sample_unconditional_flat_cp(
                context,
                rng,
                int(rows.size) * size,
            )
            beta_deg[rows, :] = beta_global.reshape(int(rows.size), size)
            alpha_deg[rows, :] = alpha_global.reshape(int(rows.size), size)

    deg2rad = cp.float32(np.pi / 180.0)
    two_pi = cp.float32(2.0 * np.pi)
    alpha_rad = cp.remainder(alpha_deg * deg2rad, two_pi).astype(cp.float32, copy=False)
    beta_rad = (beta_deg * deg2rad).astype(cp.float32, copy=False)
    sin_alpha = cp.sin(alpha_rad).astype(cp.float32, copy=False)
    cos_alpha = cp.cos(alpha_rad).astype(cp.float32, copy=False)
    sin_beta = cp.sin(beta_rad).astype(cp.float32, copy=False)
    cos_beta = cp.cos(beta_rad).astype(cp.float32, copy=False)
    return {
        "beta_deg": beta_deg,
        "alpha_deg": alpha_deg,
        "beta_rad": beta_rad,
        "alpha_rad": alpha_rad,
        "sin_alpha": sin_alpha,
        "cos_alpha": cos_alpha,
        "sin_beta": sin_beta,
        "cos_beta": cos_beta,
    }


def _build_conditioned_templates_cp(
    plan: GpuConditionedTemplatePlan,
    candidate_pools: dict[str, Any],
    *,
    cos_min_sep: float,
    start_offsets: Any | None = None,
    seed: int,
) -> dict[str, Any]:
    unit_count = int(plan.unit_count)
    template_size = int(plan.template_size)
    pool_size = int(plan.pool_size)
    if template_size <= 0:
        raise ValueError("template_size must be positive.")

    template_idx = cp.full((unit_count, template_size), -1, dtype=cp.int32)
    template_alpha = cp.full((unit_count, template_size), cp.nan, dtype=cp.float32)
    template_beta = cp.full((unit_count, template_size), cp.nan, dtype=cp.float32)
    template_sina = cp.full((unit_count, template_size), cp.nan, dtype=cp.float32)
    template_cosa = cp.full((unit_count, template_size), cp.nan, dtype=cp.float32)
    template_sinb = cp.full((unit_count, template_size), cp.nan, dtype=cp.float32)
    template_cosb = cp.full((unit_count, template_size), cp.nan, dtype=cp.float32)
    template_valid = cp.zeros(unit_count, dtype=cp.int32)

    if unit_count == 0:
        return {
            "template_idx": template_idx,
            "template_alpha_rad": template_alpha,
            "template_beta_rad": template_beta,
            "template_sin_alpha": template_sina,
            "template_cos_alpha": template_cosa,
            "template_sin_beta": template_sinb,
            "template_cos_beta": template_cosb,
            "template_valid_count": template_valid,
            "template_start_offsets": cp.empty(0, dtype=cp.int32),
        }

    beta_max = _to_cupy_array(plan.d_unit_beta_max_rad, dtype=cp.float32).reshape(unit_count)
    pool_alpha = _to_cupy_array(candidate_pools["alpha_rad"], dtype=cp.float32).reshape(unit_count, pool_size)
    pool_beta = _to_cupy_array(candidate_pools["beta_rad"], dtype=cp.float32).reshape(unit_count, pool_size)
    pool_sina = _to_cupy_array(candidate_pools["sin_alpha"], dtype=cp.float32).reshape(unit_count, pool_size)
    pool_cosa = _to_cupy_array(candidate_pools["cos_alpha"], dtype=cp.float32).reshape(unit_count, pool_size)
    pool_sinb = _to_cupy_array(candidate_pools["sin_beta"], dtype=cp.float32).reshape(unit_count, pool_size)
    pool_cosb = _to_cupy_array(candidate_pools["cos_beta"], dtype=cp.float32).reshape(unit_count, pool_size)

    if start_offsets is None:
        rng = _cupy_rng(seed)
        start = cp.floor(rng.random_sample(unit_count) * max(1, pool_size)).astype(cp.int32, copy=False)
    else:
        start = _to_cupy_array(start_offsets, dtype=cp.int32).reshape(unit_count)
    rows = cp.arange(unit_count, dtype=cp.int32)
    cos_limit = cp.float32(cos_min_sep)

    for scan_offset in range(pool_size):
        open_rows = template_valid < template_size
        if not bool(cp.any(open_rows).get()):
            break
        pool_pos = (start + np.int32(scan_offset)) % np.int32(pool_size)
        cand_beta = pool_beta[rows, pool_pos]
        valid = open_rows & cp.isfinite(cand_beta) & (cand_beta <= beta_max)
        if not bool(cp.any(valid).get()):
            continue

        cand_sina = pool_sina[rows, pool_pos]
        cand_cosa = pool_cosa[rows, pool_pos]
        cand_sinb = pool_sinb[rows, pool_pos]
        cand_cosb = pool_cosb[rows, pool_pos]

        existing_mask = cp.arange(template_size, dtype=cp.int32)[None, :] < template_valid[:, None]
        if bool(cp.any(existing_mask).get()):
            cos_da = template_cosa * cand_cosa[:, None] + template_sina * cand_sina[:, None]
            cos_gamma = template_cosb * cand_cosb[:, None] + template_sinb * cand_sinb[:, None] * cos_da
            valid &= ~cp.any(existing_mask & (cos_gamma > cos_limit), axis=1)
            if not bool(cp.any(valid).get()):
                continue

        accept_rows = cp.nonzero(valid)[0].astype(cp.int32, copy=False)
        accept_pos = template_valid[accept_rows]
        template_idx[accept_rows, accept_pos] = pool_pos[accept_rows].astype(cp.int32, copy=False)
        template_alpha[accept_rows, accept_pos] = pool_alpha[accept_rows, pool_pos[accept_rows]]
        template_beta[accept_rows, accept_pos] = pool_beta[accept_rows, pool_pos[accept_rows]]
        template_sina[accept_rows, accept_pos] = pool_sina[accept_rows, pool_pos[accept_rows]]
        template_cosa[accept_rows, accept_pos] = pool_cosa[accept_rows, pool_pos[accept_rows]]
        template_sinb[accept_rows, accept_pos] = pool_sinb[accept_rows, pool_pos[accept_rows]]
        template_cosb[accept_rows, accept_pos] = pool_cosb[accept_rows, pool_pos[accept_rows]]
        template_valid[accept_rows] += 1

    return {
        "template_idx": template_idx,
        "template_alpha_rad": template_alpha,
        "template_beta_rad": template_beta,
        "template_sin_alpha": template_sina,
        "template_cos_alpha": template_cosa,
        "template_sin_beta": template_sinb,
        "template_cos_beta": template_cosb,
        "template_valid_count": template_valid,
        "template_start_offsets": start,
    }


def _assign_conditioned_beams_cp(
    plan: GpuConditionedTemplatePlan,
    templates: dict[str, Any],
    *,
    vis_mask_horizon: Any,
    is_co_sat: Any,
    alpha0_rad: Any,
    beta0_rad: Any,
    sina0: Any,
    cosa0: Any,
    sinb0: Any,
    cosb0: Any,
    beta_max_rad_per_sat: Any,
    n_beams: int,
    cos_min_sep: float,
    start_offsets: Any | None = None,
    seed: int,
) -> dict[str, Any]:
    flat_rows = int(np.prod(plan.flat_shape, dtype=np.int64))
    sat_count = int(plan.flat_shape[-1])
    beam_count = int(n_beams)
    if beam_count <= 0:
        raise ValueError("n_beams must be positive.")

    beam_idx_flat = cp.full((flat_rows, beam_count), -1, dtype=cp.int32)
    beam_alpha_flat = cp.full((flat_rows, beam_count), cp.nan, dtype=cp.float32)
    beam_beta_flat = cp.full((flat_rows, beam_count), cp.nan, dtype=cp.float32)
    beam_valid_flat = cp.zeros(flat_rows, dtype=cp.int16)
    if int(plan.active_row_count) == 0:
        return {
            "beam_idx": beam_idx_flat.reshape(plan.flat_shape + (beam_count,)),
            "beam_alpha_rad": beam_alpha_flat.reshape(plan.flat_shape + (beam_count,)),
            "beam_beta_rad": beam_beta_flat.reshape(plan.flat_shape + (beam_count,)),
            "beam_valid": beam_valid_flat.reshape(plan.flat_shape),
        }

    active_rows = _to_cupy_array(plan.d_active_rows, dtype=cp.int32).reshape(-1)
    row_to_unit = _to_cupy_array(plan.d_row_to_unit, dtype=cp.int32).reshape(-1)
    unit_template_count = _to_cupy_array(templates["template_valid_count"], dtype=cp.int32).reshape(-1)
    template_idx = _to_cupy_array(templates["template_idx"], dtype=cp.int32)
    template_alpha = _to_cupy_array(templates["template_alpha_rad"], dtype=cp.float32)
    template_beta = _to_cupy_array(templates["template_beta_rad"], dtype=cp.float32)
    template_sina = _to_cupy_array(templates["template_sin_alpha"], dtype=cp.float32)
    template_cosa = _to_cupy_array(templates["template_cos_alpha"], dtype=cp.float32)
    template_sinb = _to_cupy_array(templates["template_sin_beta"], dtype=cp.float32)
    template_cosb = _to_cupy_array(templates["template_cos_beta"], dtype=cp.float32)

    vis_flat = _to_cupy_array(vis_mask_horizon, dtype=cp.bool_).reshape(flat_rows)
    is_co_flat = _to_cupy_array(is_co_sat, dtype=cp.bool_).reshape(flat_rows)
    alpha0_flat = _to_cupy_array(alpha0_rad, dtype=cp.float32).reshape(flat_rows)
    beta0_flat = _to_cupy_array(beta0_rad, dtype=cp.float32).reshape(flat_rows)
    sina0_flat = _to_cupy_array(sina0, dtype=cp.float32).reshape(flat_rows)
    cosa0_flat = _to_cupy_array(cosa0, dtype=cp.float32).reshape(flat_rows)
    sinb0_flat = _to_cupy_array(sinb0, dtype=cp.float32).reshape(flat_rows)
    cosb0_flat = _to_cupy_array(cosb0, dtype=cp.float32).reshape(flat_rows)

    beta_max_sat = _to_cupy_array(beta_max_rad_per_sat, dtype=cp.float32).reshape(-1)
    if int(beta_max_sat.size) != sat_count:
        raise ValueError(
            "beta_max_rad_per_sat must have length equal to the satellite axis "
            f"{sat_count}, got {int(beta_max_sat.size)}."
        )
    beta_max_row = cp.broadcast_to(beta_max_sat[None, :], plan.flat_shape).reshape(flat_rows)

    active_count = int(active_rows.size)
    unit_for_row = row_to_unit
    template_count_row = unit_template_count[unit_for_row]

    active_alpha0 = alpha0_flat[active_rows]
    active_beta0 = beta0_flat[active_rows]
    active_sina0 = sina0_flat[active_rows]
    active_cosa0 = cosa0_flat[active_rows]
    active_sinb0 = sinb0_flat[active_rows]
    active_cosb0 = cosb0_flat[active_rows]
    active_beta_max = beta_max_row[active_rows]
    active_is_co = is_co_flat[active_rows]
    active_visible = vis_flat[active_rows]

    beam_idx_active = cp.full((active_count, beam_count), -1, dtype=cp.int32)
    beam_alpha_active = cp.full((active_count, beam_count), cp.nan, dtype=cp.float32)
    beam_beta_active = cp.full((active_count, beam_count), cp.nan, dtype=cp.float32)
    beam_valid_active = cp.zeros(active_count, dtype=cp.int32)

    forced = active_visible & active_is_co & (active_beta0 <= active_beta_max)
    if int(cp.count_nonzero(forced).get()) > 0:
        beam_idx_active[forced, 0] = np.int32(-2)
        beam_alpha_active[forced, 0] = active_alpha0[forced]
        beam_beta_active[forced, 0] = active_beta0[forced]
        beam_valid_active[forced] = 1

    if start_offsets is None:
        rng = _cupy_rng(seed)
        denom = cp.maximum(template_count_row, np.int32(1)).astype(cp.float32, copy=False)
        row_start = cp.floor(rng.random_sample(active_count).astype(cp.float32, copy=False) * denom).astype(
            cp.int32,
            copy=False,
        )
    else:
        row_start = _to_cupy_array(start_offsets, dtype=cp.int32).reshape(active_count)

    scan_step = cp.zeros(active_count, dtype=cp.int32)
    cos_limit = cp.float32(cos_min_sep)

    while True:
        pending = (beam_valid_active < beam_count) & (scan_step < template_count_row)
        if int(cp.count_nonzero(pending).get()) == 0:
            break

        safe_count = cp.maximum(template_count_row, np.int32(1))
        template_pos = (row_start + scan_step) % safe_count

        cand_idx = template_idx[unit_for_row, template_pos]
        cand_alpha = template_alpha[unit_for_row, template_pos]
        cand_beta = template_beta[unit_for_row, template_pos]
        cand_sina = template_sina[unit_for_row, template_pos]
        cand_cosa = template_cosa[unit_for_row, template_pos]
        cand_sinb = template_sinb[unit_for_row, template_pos]
        cand_cosb = template_cosb[unit_for_row, template_pos]

        accept = pending & (cand_idx >= 0) & cp.isfinite(cand_beta) & (cand_beta <= active_beta_max)
        if int(cp.count_nonzero(accept).get()) > 0:
            need_sep = active_is_co & (beam_valid_active > 0)
            if int(cp.count_nonzero(need_sep & accept).get()) > 0:
                cos_da = active_cosa0 * cand_cosa + active_sina0 * cand_sina
                cos_gamma0 = active_cosb0 * cand_cosb + active_sinb0 * cand_sinb * cos_da
                accept &= ~(need_sep & (cos_gamma0 > cos_limit))

        if int(cp.count_nonzero(accept).get()) > 0:
            rows = cp.nonzero(accept)[0].astype(cp.int32, copy=False)
            slots = beam_valid_active[rows]
            beam_idx_active[rows, slots] = cand_idx[rows]
            beam_alpha_active[rows, slots] = cand_alpha[rows]
            beam_beta_active[rows, slots] = cand_beta[rows]
            beam_valid_active[rows] += 1

        scan_step[pending] += 1

    beam_idx_flat[active_rows, :] = beam_idx_active
    beam_alpha_flat[active_rows, :] = beam_alpha_active
    beam_beta_flat[active_rows, :] = beam_beta_active
    beam_valid_flat[active_rows] = beam_valid_active.astype(cp.int16, copy=False)
    return {
        "beam_idx": beam_idx_flat.reshape(plan.flat_shape + (beam_count,)),
        "beam_alpha_rad": beam_alpha_flat.reshape(plan.flat_shape + (beam_count,)),
        "beam_beta_rad": beam_beta_flat.reshape(plan.flat_shape + (beam_count,)),
        "beam_valid": beam_valid_flat.reshape(plan.flat_shape),
    }


def _fill_conditioned_beams_streaming_cp(
    context: GpuAngleSamplerContext,
    source_kind: Any,
    source_id: Any,
    *,
    vis_mask_horizon: Any,
    is_co_sat: Any,
    alpha0_rad: Any,
    beta0_rad: Any,
    beta_max_rad_per_sat: Any,
    n_beams: int,
    cos_min_sep: float,
    seed: int,
    chunk_size: int,
    max_rounds: int,
    rescue_chunk_size: int,
    max_rescue_rounds: int,
    beam_placement_policy: str,
    ras_sat_azel: Any | None,
    orbit_radius_m_per_sat: Any | None,
    ras_exclusion_radius_km: float | None,
    target_alt_km: float,
) -> dict[str, Any]:
    source_kind_cp = _to_cupy_array(source_kind, dtype=cp.int8)
    source_id_cp = _to_cupy_array(source_id, dtype=cp.int32)
    vis_cp = _to_cupy_array(vis_mask_horizon, dtype=cp.bool_)
    is_co_cp = _to_cupy_array(is_co_sat, dtype=cp.bool_)
    alpha0_cp = _to_cupy_array(alpha0_rad, dtype=cp.float32)
    beta0_cp = _to_cupy_array(beta0_rad, dtype=cp.float32)

    if (
        source_kind_cp.shape != source_id_cp.shape
        or source_kind_cp.shape != vis_cp.shape
        or source_kind_cp.shape != is_co_cp.shape
        or source_kind_cp.shape != alpha0_cp.shape
        or source_kind_cp.shape != beta0_cp.shape
    ):
        raise ValueError(
            "source_kind, source_id, vis_mask_horizon, is_co_sat, alpha0_rad, "
            "and beta0_rad must share the same shape."
        )

    beam_count = int(n_beams)
    if beam_count <= 0:
        raise ValueError("n_beams must be positive.")
    if int(chunk_size) <= 0 or int(rescue_chunk_size) <= 0:
        raise ValueError("chunk sizes must be positive.")
    if int(max_rounds) < 0 or int(max_rescue_rounds) < 0:
        raise ValueError("round limits must be non-negative.")
    target_alt_km_value = float(target_alt_km)
    if target_alt_km_value < 0.0:
        raise ValueError("target_alt_km must be non-negative.")

    flat_shape = tuple(int(v) for v in vis_cp.shape)
    flat_rows = int(np.prod(flat_shape, dtype=np.int64))
    sat_count = int(flat_shape[-1])
    beam_policy = _normalise_step2_beam_placement_policy(beam_placement_policy)
    use_ras_exclusion = beam_policy == STEP2_BEAM_PLACEMENT_EXCLUDE_RAS_RADIUS

    beta_max_sat = _to_cupy_array(beta_max_rad_per_sat, dtype=cp.float32).reshape(-1)
    if int(beta_max_sat.size) != sat_count:
        raise ValueError(
            "beta_max_rad_per_sat must have length equal to the satellite axis "
            f"{sat_count}, got {int(beta_max_sat.size)}."
        )
    ras_alpha_row = cp.zeros(flat_rows, dtype=cp.float32)
    ras_beta_row = cp.zeros(flat_rows, dtype=cp.float32)
    orbit_radius_row = cp.zeros(flat_rows, dtype=cp.float32)
    target_radius_m = np.float32(float(_EARTH_RADIUS_M_F32) + target_alt_km_value * 1000.0)
    exclusion_radius_m = np.float32(0.0)
    if use_ras_exclusion:
        if ras_sat_azel is None:
            raise ValueError("ras_sat_azel is required when beam_placement_policy='exclude_ras_radius'.")
        if orbit_radius_m_per_sat is None:
            raise ValueError("orbit_radius_m_per_sat is required when beam_placement_policy='exclude_ras_radius'.")
        if ras_exclusion_radius_km is None:
            raise ValueError("ras_exclusion_radius_km is required when beam_placement_policy='exclude_ras_radius'.")
        ras_exclusion_radius_value = float(ras_exclusion_radius_km)
        if ras_exclusion_radius_value < 0.0:
            raise ValueError("ras_exclusion_radius_km must be non-negative.")
        ras_sat_azel_cp = _normalise_ras_sat_azel_cupy(
            ras_sat_azel,
            time_count=int(flat_shape[0]),
            sat_count=sat_count,
        )
        orbit_radius_sat = _to_cupy_array(orbit_radius_m_per_sat, dtype=cp.float32).reshape(-1)
        if int(orbit_radius_sat.size) != sat_count:
            raise ValueError(
                "orbit_radius_m_per_sat must have length equal to the satellite axis "
                f"{sat_count}, got {int(orbit_radius_sat.size)}."
            )
        ras_alpha_row = cp.remainder(
            ras_sat_azel_cp[..., 0].astype(cp.float32, copy=False) * cp.float32(np.pi / 180.0),
            cp.float32(2.0 * np.pi),
        ).reshape(flat_rows)
        ras_beta_row = cp.abs(
            ras_sat_azel_cp[..., 1].astype(cp.float32, copy=False) * cp.float32(np.pi / 180.0)
        ).reshape(flat_rows)
        orbit_radius_row = cp.broadcast_to(orbit_radius_sat[None, :], flat_shape).reshape(flat_rows)
        exclusion_radius_m = np.float32(ras_exclusion_radius_value * 1000.0)

    source_kind_flat = source_kind_cp.reshape(flat_rows)
    source_id_flat = source_id_cp.reshape(flat_rows)
    vis_flat = vis_cp.reshape(flat_rows)
    is_co_flat = is_co_cp.reshape(flat_rows)
    alpha0_flat = alpha0_cp.reshape(flat_rows)
    beta0_flat = beta0_cp.reshape(flat_rows)
    beta_max_row = cp.broadcast_to(beta_max_sat[None, :], flat_shape).reshape(flat_rows)

    invalid_visible = vis_flat & (source_kind_flat == SAMPLER_SOURCE_INVALID)
    if int(cp.count_nonzero(invalid_visible).get()) > 0:
        raise ValueError("Visible rows contain unresolved conditioned sampler sources.")

    beam_idx_flat = cp.full((flat_rows, beam_count), -1, dtype=cp.int32)
    beam_alpha_flat = cp.full((flat_rows, beam_count), cp.nan, dtype=cp.float32)
    beam_beta_flat = cp.full((flat_rows, beam_count), cp.nan, dtype=cp.float32)
    beam_valid_flat = cp.zeros(flat_rows, dtype=cp.int16)

    active_rows = cp.nonzero(vis_flat)[0].astype(cp.int32, copy=False)
    active_row_count = int(active_rows.size)
    if active_row_count == 0:
        return {
            "beam_idx": beam_idx_flat.reshape(flat_shape + (beam_count,)),
            "beam_alpha_rad": beam_alpha_flat.reshape(flat_shape + (beam_count,)),
            "beam_beta_rad": beam_beta_flat.reshape(flat_shape + (beam_count,)),
            "beam_valid": beam_valid_flat.reshape(flat_shape),
            "draws_attempted": np.int64(0),
            "rounds_used": np.int32(0),
            "unfinished_row_count": np.int32(0),
        }

    active_source_kind = source_kind_flat[active_rows].astype(cp.int8, copy=False)
    active_source_id = source_id_flat[active_rows].astype(cp.int32, copy=False)
    active_is_co = is_co_flat[active_rows]
    active_alpha0 = alpha0_flat[active_rows].astype(cp.float32, copy=False)
    active_beta0 = beta0_flat[active_rows].astype(cp.float32, copy=False)
    active_beta_max = beta_max_row[active_rows].astype(cp.float32, copy=False)
    active_ras_alpha = ras_alpha_row[active_rows].astype(cp.float32, copy=False)
    active_ras_beta = ras_beta_row[active_rows].astype(cp.float32, copy=False)
    active_orbit_radius = orbit_radius_row[active_rows].astype(cp.float32, copy=False)

    beam_idx_active = cp.full((active_row_count, beam_count), -1, dtype=cp.int32)
    beam_alpha_active = cp.full((active_row_count, beam_count), cp.nan, dtype=cp.float32)
    beam_beta_active = cp.full((active_row_count, beam_count), cp.nan, dtype=cp.float32)
    beam_valid_active = cp.zeros(active_row_count, dtype=cp.int16)

    forced = (
        active_is_co & (active_beta0 <= active_beta_max)
        if beam_policy == STEP2_BEAM_PLACEMENT_FORCED_CO_RAS
        else cp.zeros(active_row_count, dtype=cp.bool_)
    )
    if int(cp.count_nonzero(forced).get()) > 0:
        beam_idx_active[forced, 0] = np.int32(-2)
        beam_alpha_active[forced, 0] = active_alpha0[forced]
        beam_beta_active[forced, 0] = active_beta0[forced]
        beam_valid_active[forced] = np.int16(1)

    draws_attempted = 0
    rounds_used = 0
    round_seed = int(seed)
    draw_index_base = 0
    threads_per_block = 128

    for current_chunk_size, current_max_rounds in (
        (int(chunk_size), int(max_rounds)),
        (int(rescue_chunk_size), int(max_rescue_rounds)),
    ):
        for _ in range(current_max_rounds):
            pending_active_idx = cp.nonzero(beam_valid_active < np.int16(beam_count))[0].astype(cp.int32, copy=False)
            pending_count = int(pending_active_idx.size)
            if pending_count == 0:
                break

            candidate_batch = _sample_conditioned_candidate_batch_cp(
                context,
                active_source_kind[pending_active_idx],
                active_source_id[pending_active_idx],
                chunk_size=current_chunk_size,
                seed=round_seed,
            )
            round_seed += 1

            blocks_per_grid = max(1, (pending_count + threads_per_block - 1) // threads_per_block)
            _accept_conditioned_candidate_batch_kernel[blocks_per_grid, threads_per_block](
                pending_active_idx,
                beam_idx_active,
                beam_alpha_active,
                beam_beta_active,
                beam_valid_active,
                candidate_batch["alpha_rad"],
                candidate_batch["beta_rad"],
                active_beta_max,
                active_ras_alpha,
                active_ras_beta,
                active_orbit_radius,
                np.float32(cos_min_sep),
                np.int32(draw_index_base),
                np.int32(beam_count),
                bool(use_ras_exclusion),
                np.float32(target_radius_m),
                np.float32(exclusion_radius_m),
            )
            draws_attempted += pending_count * current_chunk_size
            draw_index_base += current_chunk_size
            rounds_used += 1

        if int(cp.count_nonzero(beam_valid_active < np.int16(beam_count)).get()) == 0:
            break

    unfinished_row_count = int(cp.count_nonzero(beam_valid_active < np.int16(beam_count)).get())
    if unfinished_row_count > 0:
        raise RuntimeError(
            "Streaming conditioned beam generation could not satisfy "
            f"n_beams={beam_count} for {unfinished_row_count} visible rows "
            f"after {draws_attempted} candidate draws."
        )

    beam_idx_flat[active_rows, :] = beam_idx_active
    beam_alpha_flat[active_rows, :] = beam_alpha_active
    beam_beta_flat[active_rows, :] = beam_beta_active
    beam_valid_flat[active_rows] = beam_valid_active
    return {
        "beam_idx": beam_idx_flat.reshape(flat_shape + (beam_count,)),
        "beam_alpha_rad": beam_alpha_flat.reshape(flat_shape + (beam_count,)),
        "beam_beta_rad": beam_beta_flat.reshape(flat_shape + (beam_count,)),
        "beam_valid": beam_valid_flat.reshape(flat_shape),
        "draws_attempted": np.int64(draws_attempted),
        "rounds_used": np.int32(rounds_used),
        "unfinished_row_count": np.int32(0),
    }


def _sample_s1586_pointings_cp(
    context: GpuS1586PointingContext,
    *,
    n_samples: int,
    seed: int,
) -> dict[str, Any]:
    sample_count = int(n_samples)
    if sample_count <= 0:
        raise ValueError("n_samples must be positive.")
    cell_count = int(context.n_cells)
    rng = _cupy_rng(seed)

    az_low = _to_cupy_array(context.d_az_low_deg, dtype=cp.float32)
    az_high = _to_cupy_array(context.d_az_high_deg, dtype=cp.float32)
    sin_el_low = _to_cupy_array(context.d_sin_el_low, dtype=cp.float32)
    sin_el_high = _to_cupy_array(context.d_sin_el_high, dtype=cp.float32)

    azimuth_deg = (
        az_low[None, :]
        + rng.random_sample((sample_count, cell_count)).astype(cp.float32, copy=False)
        * (az_high - az_low)[None, :]
    ).astype(cp.float32, copy=False)
    sin_el = (
        sin_el_low[None, :]
        + rng.random_sample((sample_count, cell_count)).astype(cp.float32, copy=False)
        * (sin_el_high - sin_el_low)[None, :]
    ).astype(cp.float32, copy=False)
    sin_el = cp.clip(sin_el, cp.float32(-1.0), cp.float32(1.0))
    elevation_deg = cp.rad2deg(cp.arcsin(sin_el)).astype(cp.float32, copy=False)
    return {
        "azimuth_deg": azimuth_deg,
        "elevation_deg": elevation_deg,
    }


_S1528_LUT_STEP_DEG = 0.0001
_S1528_LUT_MAX_DEG = 180.0

# 2-D LUT for asymmetric S.1528 Rec 1.4 (lt_m != lr_m). The analytical
# u-formula depends on cos(phi)^2 and sin(phi)^2, giving a 4-fold symmetric
# pattern in phi — we only sample phi in [0, 90] deg and fold arbitrary
# phi into that quadrant at runtime. Theta is sampled at the same
# resolution as the 1-D LUT would use near the main beam; phi at 0.5 deg.
_S1528_LUT_2D_THETA_STEP_DEG = 0.01
_S1528_LUT_2D_PHI_STEP_DEG = 0.5
_S1528_LUT_2D_THETA_MAX_DEG = 180.0
_S1528_LUT_2D_PHI_MAX_DEG = 90.0

_s1528_lut_1d_interp_kernel = None
_s1528_lut_1d_interp_fp16_kernel = None


def _get_s1528_lut_1d_interp_kernel():
    """Return (and cache) a CuPy ElementwiseKernel for fast LUT interpolation."""
    global _s1528_lut_1d_interp_kernel
    if _s1528_lut_1d_interp_kernel is not None:
        return _s1528_lut_1d_interp_kernel
    _s1528_lut_1d_interp_kernel = cp.ElementwiseKernel(
        "float32 theta_deg, raw float32 lut, float32 inv_step, float32 max_deg, int32 n_lut",
        "float32 gain_db",
        """
        float t = fabsf(theta_deg);
        if (t > max_deg) t = max_deg;
        float fidx = t * inv_step;
        int idx0 = __float2int_rd(fidx);
        if (idx0 < 0) idx0 = 0;
        int idx1 = idx0 + 1;
        if (idx1 >= n_lut) { idx1 = n_lut - 1; idx0 = idx1 - 1; if (idx0 < 0) idx0 = 0; }
        float frac = fidx - (float)idx0;
        gain_db = lut[idx0] + frac * (lut[idx1] - lut[idx0]);
        """,
        "s1528_lut_1d_interp",
    )
    return _s1528_lut_1d_interp_kernel


def _get_s1528_lut_1d_interp_fp16_kernel():
    """fp16-LUT variant of :func:`_get_s1528_lut_1d_interp_kernel`.

    Identical body, only the ``raw`` LUT input is ``float16``; the two
    corner loads cast ``__half → float`` implicitly before the linear
    weight multiplies.  Halves the persistent 1-D LUT memory (720 KB fp32
    → 360 KB fp16) when the session runs at ``pattern_dtype=float16``.
    """
    global _s1528_lut_1d_interp_fp16_kernel
    if _s1528_lut_1d_interp_fp16_kernel is not None:
        return _s1528_lut_1d_interp_fp16_kernel
    _s1528_lut_1d_interp_fp16_kernel = cp.ElementwiseKernel(
        "float32 theta_deg, raw float16 lut, float32 inv_step, float32 max_deg, int32 n_lut",
        "float32 gain_db",
        """
        float t = fabsf(theta_deg);
        if (t > max_deg) t = max_deg;
        float fidx = t * inv_step;
        int idx0 = __float2int_rd(fidx);
        if (idx0 < 0) idx0 = 0;
        int idx1 = idx0 + 1;
        if (idx1 >= n_lut) { idx1 = n_lut - 1; idx0 = idx1 - 1; if (idx0 < 0) idx0 = 0; }
        float frac = fidx - (float)idx0;
        float v0 = (float)lut[idx0];
        float v1 = (float)lut[idx1];
        gain_db = v0 + frac * (v1 - v0);
        """,
        "s1528_lut_1d_interp_fp16",
    )
    return _s1528_lut_1d_interp_fp16_kernel


def _ensure_s1528_gain_lut_1d(
    context: GpuS1528PatternContext | GpuS1528Rec12PatternContext,
) -> None:
    """Build and cache a 1-D gain LUT on the GPU for fast pattern evaluation.

    **Valid only for axisymmetric patterns** — Rec 1.2 is axisymmetric by
    definition, and Rec 1.4 is axisymmetric when ``lt_m == lr_m``. For
    asymmetric Rec 1.4 (``lt_m != lr_m``) a 2-D LUT in ``(theta, phi)``
    is required; see ``_ensure_s1528_gain_lut_2d``.

    For asymmetric Rec 1.4 contexts (``context.is_2d`` is ``True``), this
    function transparently delegates to ``_ensure_s1528_gain_lut_2d``;
    callers that directly invoke the 1-D LUT evaluators on an asymmetric
    context hit an explicit ``NotImplementedError`` (see
    ``_evaluate_s1528_pattern_cp_lut_1d``).
    """
    if getattr(context, "is_2d", False):
        _ensure_s1528_gain_lut_2d(context)
        return
    if context.d_gain_lut is not None:
        return
    step = float(_S1528_LUT_STEP_DEG)
    max_deg = float(_S1528_LUT_MAX_DEG)
    n = int(max_deg / step) + 2
    theta_host = np.arange(n, dtype=np.float32) * np.float32(step)
    theta_cp = cp.asarray(theta_host)
    if isinstance(context, GpuS1528Rec12PatternContext):
        gain_cp = _evaluate_s1528_rec12_pattern_cp(context, theta_cp)
    else:
        gain_cp = _evaluate_s1528_pattern_cp_analytical(context, theta_cp)
    # Downcast the LUT to fp16 when the session's pattern stage runs at
    # fp16.  Halves the persistent LUT memory (720 KB → 360 KB on the
    # standard 0.0001° grid) with no extra eval cost — the fp16 kernel
    # loads ``__half`` and promotes to fp32 inside the linear-in-dB
    # interpolation, identical arithmetic to the fp32 path.
    _session_pattern_dtype = getattr(
        getattr(context, "session", None), "pattern_dtype", None,
    )
    if _session_pattern_dtype is not None and np.dtype(_session_pattern_dtype) == np.dtype(np.float16):
        gain_cp = gain_cp.astype(cp.float16, copy=False)
    context.d_gain_lut = gain_cp
    context.gain_lut_step_deg = step
    context.gain_lut_max_deg = max_deg
    context.gain_lut_n = n


def _ensure_s1528_gain_lut_2d(context: GpuS1528PatternContext) -> None:
    """Build and cache a 2-D gain LUT ``G(theta, phi)`` for asymmetric Rec 1.4.

    The Rec 1.4 u-formula,

        u(theta, phi) = (pi/lambda) * sqrt((lr * sin(theta) * cos(phi))^2
                                         + (lt * sin(theta) * sin(phi))^2),

    depends on ``cos^2(phi)`` and ``sin^2(phi)`` only, so the pattern has
    4-fold symmetry in phi (period 180 deg, mirror-symmetric about 0 and
    90 deg). The LUT therefore samples phi in ``[0, 90]`` deg and the
    bilinear-lookup kernel (``_get_s1528_lut_2d_interp_kernel``) folds
    arbitrary phi into that quadrant via
    ``phi' = min(|phi mod 180|, 180 - |phi mod 180|)``.

    Modelled on ``_ensure_m2101_element_lut_2d`` but parameterised in the
    S.1528 ``(theta, phi)`` convention (not the M.2101 body-frame
    ``(alpha, beta)``).
    """
    if context.d_gain_lut_2d is not None:
        return
    theta_step = float(_S1528_LUT_2D_THETA_STEP_DEG)
    phi_step = float(_S1528_LUT_2D_PHI_STEP_DEG)
    theta_max = float(_S1528_LUT_2D_THETA_MAX_DEG)
    phi_max = float(_S1528_LUT_2D_PHI_MAX_DEG)
    n_theta = int(round(theta_max / theta_step)) + 1
    n_phi = int(round(phi_max / phi_step)) + 1
    theta_1d = cp.arange(n_theta, dtype=cp.float32) * cp.float32(theta_step)
    phi_1d = cp.arange(n_phi, dtype=cp.float32) * cp.float32(phi_step)
    # (n_phi, n_theta) — phi is the slow axis so the row stride matches the
    # bilinear-lookup convention used by the M.2101 2-D kernel.
    theta_2d, phi_2d = cp.meshgrid(theta_1d, phi_1d, indexing="xy")
    gain_flat = _evaluate_s1528_pattern_cp_analytical(
        context, theta_2d.ravel(), phi_deg=phi_2d.ravel()
    )
    gain_2d_cp = gain_flat.reshape(n_phi, n_theta).astype(
        cp.float32, copy=False
    )
    # Downcast the 2-D LUT to fp16 when the session's pattern stage runs
    # at fp16.  Halves the persistent LUT memory (≈13 MB → 6.5 MB on the
    # standard 0.01° × 0.5° grid) with no extra eval cost.
    _session_pattern_dtype = getattr(
        getattr(context, "session", None), "pattern_dtype", None,
    )
    if _session_pattern_dtype is not None and np.dtype(_session_pattern_dtype) == np.dtype(np.float16):
        gain_2d_cp = gain_2d_cp.astype(cp.float16, copy=False)
    context.d_gain_lut_2d = gain_2d_cp
    context.gain_lut_2d_theta_step_deg = theta_step
    context.gain_lut_2d_phi_step_deg = phi_step
    context.gain_lut_2d_n_theta = n_theta
    context.gain_lut_2d_n_phi = n_phi
    context.gain_lut_2d_theta_max_deg = theta_max
    context.gain_lut_2d_phi_max_deg = phi_max


def _evaluate_s1528_pattern_cp_lut_1d(
    context: GpuS1528PatternContext,
    theta_deg: Any,
) -> Any:
    """Fast S.1528 pattern evaluation using precomputed 1-D gain LUT.

    Axisymmetric path only (Rec 1.2, or Rec 1.4 with ``lt_m == lr_m``).
    The dispatcher in ``_evaluate_s1528_pattern_cp`` must not route
    asymmetric Rec 1.4 contexts here.
    """
    if getattr(context, "is_2d", False):
        raise NotImplementedError(
            "Asymmetric S.1528 Rec 1.4 context (lt_m != lr_m) routed "
            "into the 1-D LUT evaluator; use the 2-D (theta, phi) path "
            "via _evaluate_s1528_pattern_cp(theta, phi_deg=...) instead."
        )
    _ensure_s1528_gain_lut_1d(context)
    theta = _to_cupy_array(theta_deg, dtype=cp.float32)
    kernel = (
        _get_s1528_lut_1d_interp_fp16_kernel()
        if context.d_gain_lut.dtype == cp.float16
        else _get_s1528_lut_1d_interp_kernel()
    )
    return kernel(
        theta,
        context.d_gain_lut,
        cp.float32(1.0 / context.gain_lut_step_deg),
        cp.float32(context.gain_lut_max_deg),
        np.int32(context.gain_lut_n),
    )


_s1528_lut_2d_interp_kernel = None
_s1528_lut_2d_interp_fp16_kernel = None


def _get_s1528_lut_2d_interp_kernel():
    """ElementwiseKernel: bilinear lookup of the asymmetric S.1528 Rec 1.4
    gain LUT ``G(theta, phi)``.

    The LUT is stored as ``(n_phi, n_theta)`` float32 dB. Phi is folded
    into ``[0, phi_max]`` using the pattern's 4-fold symmetry
    (``cos^2(phi)``/``sin^2(phi)`` dependence); theta is taken as
    ``fabs(theta)`` and clamped to ``theta_max``.
    """
    global _s1528_lut_2d_interp_kernel
    if _s1528_lut_2d_interp_kernel is not None:
        return _s1528_lut_2d_interp_kernel
    _s1528_lut_2d_interp_kernel = cp.ElementwiseKernel(
        "float32 theta_deg, float32 phi_deg, raw float32 lut, "
        "float32 inv_theta_step, float32 inv_phi_step, "
        "float32 theta_max, float32 phi_max, "
        "int32 n_theta, int32 n_phi",
        "float32 gain_db",
        """
        /* theta folding: |theta|, clamp to [0, theta_max] */
        float t = fabsf(theta_deg);
        if (t > theta_max) t = theta_max;
        /* phi folding: |phi| mod 180, then mirror about 90 deg so p in [0, 90] */
        float p = fabsf(phi_deg);
        p = fmodf(p, 180.0f);
        if (p > 90.0f) p = 180.0f - p;
        if (p > phi_max) p = phi_max;

        float tf = t * inv_theta_step;
        float pf = p * inv_phi_step;
        int t0 = __float2int_rd(tf);
        int p0 = __float2int_rd(pf);
        if (t0 < 0) t0 = 0;
        if (p0 < 0) p0 = 0;
        int t1 = t0 + 1;
        int p1 = p0 + 1;
        if (t1 >= n_theta) { t1 = n_theta - 1; t0 = t1 > 0 ? t1 - 1 : 0; }
        if (p1 >= n_phi)   { p1 = n_phi   - 1; p0 = p1 > 0 ? p1 - 1 : 0; }
        float ft = tf - (float)t0;
        float fp = pf - (float)p0;
        float v00 = lut[p0 * n_theta + t0];
        float v10 = lut[p0 * n_theta + t1];
        float v01 = lut[p1 * n_theta + t0];
        float v11 = lut[p1 * n_theta + t1];
        gain_db = v00 * (1.0f - ft) * (1.0f - fp)
                + v10 * ft * (1.0f - fp)
                + v01 * (1.0f - ft) * fp
                + v11 * ft * fp;
        """,
        "s1528_lut_2d_interp",
    )
    return _s1528_lut_2d_interp_kernel


def _get_s1528_lut_2d_interp_fp16_kernel():
    """fp16-LUT variant of :func:`_get_s1528_lut_2d_interp_kernel`.

    Same bilinear body over the (n_phi, n_theta) LUT, only the ``raw``
    LUT is ``float16``.  The four corner loads promote ``__half``→
    ``float`` before the bilinear weighted sum, so the interpolation
    remains in fp32 precision.  Halves the persistent 2-D LUT memory
    (13 MB fp32 → 6.5 MB fp16) when the session runs at
    ``pattern_dtype=float16``.
    """
    global _s1528_lut_2d_interp_fp16_kernel
    if _s1528_lut_2d_interp_fp16_kernel is not None:
        return _s1528_lut_2d_interp_fp16_kernel
    _s1528_lut_2d_interp_fp16_kernel = cp.ElementwiseKernel(
        "float32 theta_deg, float32 phi_deg, raw float16 lut, "
        "float32 inv_theta_step, float32 inv_phi_step, "
        "float32 theta_max, float32 phi_max, "
        "int32 n_theta, int32 n_phi",
        "float32 gain_db",
        """
        float t = fabsf(theta_deg);
        if (t > theta_max) t = theta_max;
        float p = fabsf(phi_deg);
        p = fmodf(p, 180.0f);
        if (p > 90.0f) p = 180.0f - p;
        if (p > phi_max) p = phi_max;

        float tf = t * inv_theta_step;
        float pf = p * inv_phi_step;
        int t0 = __float2int_rd(tf);
        int p0 = __float2int_rd(pf);
        if (t0 < 0) t0 = 0;
        if (p0 < 0) p0 = 0;
        int t1 = t0 + 1;
        int p1 = p0 + 1;
        if (t1 >= n_theta) { t1 = n_theta - 1; t0 = t1 > 0 ? t1 - 1 : 0; }
        if (p1 >= n_phi)   { p1 = n_phi   - 1; p0 = p1 > 0 ? p1 - 1 : 0; }
        float ft = tf - (float)t0;
        float fp = pf - (float)p0;
        float v00 = (float)lut[p0 * n_theta + t0];
        float v10 = (float)lut[p0 * n_theta + t1];
        float v01 = (float)lut[p1 * n_theta + t0];
        float v11 = (float)lut[p1 * n_theta + t1];
        gain_db = v00 * (1.0f - ft) * (1.0f - fp)
                + v10 * ft * (1.0f - fp)
                + v01 * (1.0f - ft) * fp
                + v11 * ft * fp;
        """,
        "s1528_lut_2d_interp_fp16",
    )
    return _s1528_lut_2d_interp_fp16_kernel


def _evaluate_s1528_pattern_cp_lut_2d(
    context: GpuS1528PatternContext,
    theta_deg: Any,
    phi_deg: Any,
) -> Any:
    """Bilinear 2-D LUT evaluation of asymmetric S.1528 Rec 1.4.

    Requires ``context.is_2d`` and a provided ``phi_deg``. The dispatcher
    in ``_evaluate_s1528_pattern_cp`` is responsible for enforcing this.
    """
    _ensure_s1528_gain_lut_2d(context)
    theta = _to_cupy_array(theta_deg, dtype=cp.float32)
    phi = _to_cupy_array(phi_deg, dtype=cp.float32)
    theta, phi = cp.broadcast_arrays(theta, phi)
    kernel = (
        _get_s1528_lut_2d_interp_fp16_kernel()
        if context.d_gain_lut_2d.dtype == cp.float16
        else _get_s1528_lut_2d_interp_kernel()
    )
    return kernel(
        theta,
        phi,
        context.d_gain_lut_2d,
        cp.float32(1.0 / context.gain_lut_2d_theta_step_deg),
        cp.float32(1.0 / context.gain_lut_2d_phi_step_deg),
        cp.float32(context.gain_lut_2d_theta_max_deg),
        cp.float32(context.gain_lut_2d_phi_max_deg),
        np.int32(context.gain_lut_2d_n_theta),
        np.int32(context.gain_lut_2d_n_phi),
    )


_s1528_lut_2d_to_linear_kernel = None
_s1528_lut_2d_to_linear_fp16_kernel = None


def _get_s1528_lut_2d_to_linear_kernel():
    """Fused 2-D bilinear LUT lookup + dB→linear + relative gain in one kernel.

    Matches the 1-D fused kernel ``_get_s1528_lut_1d_to_linear_kernel`` and
    the M.2101 fused kernel — collapses the old two-step "LUT → dB, then
    ``cp.power(10, g/10) * inv_gmax`` two extra CuPy ops" path into a
    single ElementwiseKernel launch.
    """
    global _s1528_lut_2d_to_linear_kernel
    if _s1528_lut_2d_to_linear_kernel is not None:
        return _s1528_lut_2d_to_linear_kernel
    _s1528_lut_2d_to_linear_kernel = cp.ElementwiseKernel(
        "float32 theta_deg, float32 phi_deg, raw float32 lut, "
        "float32 inv_theta_step, float32 inv_phi_step, "
        "float32 theta_max, float32 phi_max, "
        "int32 n_theta, int32 n_phi, float32 inv_gmax_lin",
        "float32 gain_rel_lin",
        """
        /* theta folding: |theta|, clamp to [0, theta_max] */
        float t = fabsf(theta_deg);
        if (t > theta_max) t = theta_max;
        /* phi folding: |phi| mod 180, mirror about 90 so p in [0, 90] */
        float p = fabsf(phi_deg);
        p = fmodf(p, 180.0f);
        if (p > 90.0f) p = 180.0f - p;
        if (p > phi_max) p = phi_max;

        float tf = t * inv_theta_step;
        float pf = p * inv_phi_step;
        int t0 = __float2int_rd(tf);
        int p0 = __float2int_rd(pf);
        if (t0 < 0) t0 = 0;
        if (p0 < 0) p0 = 0;
        int t1 = t0 + 1;
        int p1 = p0 + 1;
        if (t1 >= n_theta) { t1 = n_theta - 1; t0 = t1 > 0 ? t1 - 1 : 0; }
        if (p1 >= n_phi)   { p1 = n_phi   - 1; p0 = p1 > 0 ? p1 - 1 : 0; }
        float ft = tf - (float)t0;
        float fp = pf - (float)p0;
        float v00 = lut[p0 * n_theta + t0];
        float v10 = lut[p0 * n_theta + t1];
        float v01 = lut[p1 * n_theta + t0];
        float v11 = lut[p1 * n_theta + t1];
        float gain_db = v00 * (1.0f - ft) * (1.0f - fp)
                      + v10 * ft * (1.0f - fp)
                      + v01 * (1.0f - ft) * fp
                      + v11 * ft * fp;
        /* 10^(x/10) = exp(x * ln(10)/10) */
        gain_rel_lin = __expf(gain_db * 0.23025850929f) * inv_gmax_lin;
        """,
        "s1528_lut_2d_to_linear",
    )
    return _s1528_lut_2d_to_linear_kernel


def _get_s1528_lut_2d_to_linear_fp16_kernel():
    """fp16-LUT variant of :func:`_get_s1528_lut_2d_to_linear_kernel`.

    Same fused bilinear + dB→linear + relative-gain chain over the
    asymmetric Rec 1.4 LUT, with ``raw float16`` storage.  Four
    ``__half``→``float`` promotions at the corner loads keep the
    bilinear interpolation and the subsequent ``__expf`` in fp32.
    """
    global _s1528_lut_2d_to_linear_fp16_kernel
    if _s1528_lut_2d_to_linear_fp16_kernel is not None:
        return _s1528_lut_2d_to_linear_fp16_kernel
    _s1528_lut_2d_to_linear_fp16_kernel = cp.ElementwiseKernel(
        "float32 theta_deg, float32 phi_deg, raw float16 lut, "
        "float32 inv_theta_step, float32 inv_phi_step, "
        "float32 theta_max, float32 phi_max, "
        "int32 n_theta, int32 n_phi, float32 inv_gmax_lin",
        "float32 gain_rel_lin",
        """
        float t = fabsf(theta_deg);
        if (t > theta_max) t = theta_max;
        float p = fabsf(phi_deg);
        p = fmodf(p, 180.0f);
        if (p > 90.0f) p = 180.0f - p;
        if (p > phi_max) p = phi_max;

        float tf = t * inv_theta_step;
        float pf = p * inv_phi_step;
        int t0 = __float2int_rd(tf);
        int p0 = __float2int_rd(pf);
        if (t0 < 0) t0 = 0;
        if (p0 < 0) p0 = 0;
        int t1 = t0 + 1;
        int p1 = p0 + 1;
        if (t1 >= n_theta) { t1 = n_theta - 1; t0 = t1 > 0 ? t1 - 1 : 0; }
        if (p1 >= n_phi)   { p1 = n_phi   - 1; p0 = p1 > 0 ? p1 - 1 : 0; }
        float ft = tf - (float)t0;
        float fp = pf - (float)p0;
        float v00 = (float)lut[p0 * n_theta + t0];
        float v10 = (float)lut[p0 * n_theta + t1];
        float v01 = (float)lut[p1 * n_theta + t0];
        float v11 = (float)lut[p1 * n_theta + t1];
        float gain_db = v00 * (1.0f - ft) * (1.0f - fp)
                      + v10 * ft * (1.0f - fp)
                      + v01 * (1.0f - ft) * fp
                      + v11 * ft * fp;
        gain_rel_lin = __expf(gain_db * 0.23025850929f) * inv_gmax_lin;
        """,
        "s1528_lut_2d_to_linear_fp16",
    )
    return _s1528_lut_2d_to_linear_fp16_kernel


def _evaluate_s1528_pattern_cp_lut_2d_to_linear(
    context: GpuS1528PatternContext,
    theta_deg: Any,
    phi_deg: Any,
    inv_gmax_lin: float,
) -> Any:
    """Fused asymmetric 2-D LUT + dB→linear + relative-gain evaluation.

    Mirrors ``_evaluate_s1528_pattern_cp_lut_1d_to_linear`` for the
    asymmetric case.  Inputs: ``theta_deg`` (off-axis from boresight),
    ``phi_deg`` (azimuth around boresight in the pattern frame).
    Output: ``10^(gain_db/10) / gmax_lin`` = relative linear gain.
    """
    _ensure_s1528_gain_lut_2d(context)
    theta = _to_cupy_array(theta_deg, dtype=cp.float32)
    phi = _to_cupy_array(phi_deg, dtype=cp.float32)
    theta, phi = cp.broadcast_arrays(theta, phi)
    kernel = (
        _get_s1528_lut_2d_to_linear_fp16_kernel()
        if context.d_gain_lut_2d.dtype == cp.float16
        else _get_s1528_lut_2d_to_linear_kernel()
    )
    return kernel(
        theta, phi,
        context.d_gain_lut_2d,
        cp.float32(1.0 / context.gain_lut_2d_theta_step_deg),
        cp.float32(1.0 / context.gain_lut_2d_phi_step_deg),
        cp.float32(context.gain_lut_2d_theta_max_deg),
        cp.float32(context.gain_lut_2d_phi_max_deg),
        np.int32(context.gain_lut_2d_n_theta),
        np.int32(context.gain_lut_2d_n_phi),
        cp.float32(float(inv_gmax_lin)),
    )


_s1528_lut_1d_to_linear_kernel = None
_s1528_lut_1d_to_linear_fp16_kernel = None


def _get_s1528_lut_1d_to_linear_kernel():
    """Return (and cache) an ElementwiseKernel that reads the S.1528 LUT and
    outputs *linear relative gain* (``10^(gain_db/10) * inv_gmax_lin``) in a
    single kernel launch, avoiding two extra CuPy operations."""
    global _s1528_lut_1d_to_linear_kernel
    if _s1528_lut_1d_to_linear_kernel is not None:
        return _s1528_lut_1d_to_linear_kernel
    _s1528_lut_1d_to_linear_kernel = cp.ElementwiseKernel(
        "float32 theta_deg, raw float32 lut, float32 inv_step, float32 max_deg, "
        "int32 n_lut, float32 inv_gmax_lin",
        "float32 gain_rel_lin",
        """
        float t = fabsf(theta_deg);
        if (t > max_deg) t = max_deg;
        float fidx = t * inv_step;
        int idx0 = __float2int_rd(fidx);
        if (idx0 < 0) idx0 = 0;
        int idx1 = idx0 + 1;
        if (idx1 >= n_lut) { idx1 = n_lut - 1; idx0 = idx1 - 1; if (idx0 < 0) idx0 = 0; }
        float frac = fidx - (float)idx0;
        float gain_db = lut[idx0] + frac * (lut[idx1] - lut[idx0]);
        /* 10^(x/10) = exp(x * ln(10)/10);  ln(10)/10 ≈ 0.23025850929 */
        gain_rel_lin = __expf(gain_db * 0.23025850929f) * inv_gmax_lin;
        """,
        "s1528_lut_1d_to_linear",
    )
    return _s1528_lut_1d_to_linear_kernel


def _get_s1528_lut_1d_to_linear_fp16_kernel():
    """fp16-LUT variant of :func:`_get_s1528_lut_1d_to_linear_kernel`.

    Fused LUT → dB → linear → relative-gain chain, with the ``raw`` LUT
    input now ``float16``.  The two corner loads promote ``__half``→
    ``float`` before the linear-in-dB interpolation and subsequent
    ``__expf`` remain in fp32 to avoid accumulating half-precision
    error.  Used when the session's ``pattern_dtype`` is ``float16``.
    """
    global _s1528_lut_1d_to_linear_fp16_kernel
    if _s1528_lut_1d_to_linear_fp16_kernel is not None:
        return _s1528_lut_1d_to_linear_fp16_kernel
    _s1528_lut_1d_to_linear_fp16_kernel = cp.ElementwiseKernel(
        "float32 theta_deg, raw float16 lut, float32 inv_step, float32 max_deg, "
        "int32 n_lut, float32 inv_gmax_lin",
        "float32 gain_rel_lin",
        """
        float t = fabsf(theta_deg);
        if (t > max_deg) t = max_deg;
        float fidx = t * inv_step;
        int idx0 = __float2int_rd(fidx);
        if (idx0 < 0) idx0 = 0;
        int idx1 = idx0 + 1;
        if (idx1 >= n_lut) { idx1 = n_lut - 1; idx0 = idx1 - 1; if (idx0 < 0) idx0 = 0; }
        float frac = fidx - (float)idx0;
        float v0 = (float)lut[idx0];
        float v1 = (float)lut[idx1];
        float gain_db = v0 + frac * (v1 - v0);
        gain_rel_lin = __expf(gain_db * 0.23025850929f) * inv_gmax_lin;
        """,
        "s1528_lut_1d_to_linear_fp16",
    )
    return _s1528_lut_1d_to_linear_fp16_kernel


def _evaluate_s1528_pattern_cp_lut_1d_to_linear(
    context: GpuS1528PatternContext,
    theta_deg: Any,
    inv_gmax_lin: float,
) -> Any:
    """S.1528 LUT evaluation returning relative linear gain in a single kernel."""
    if getattr(context, "is_2d", False):
        raise NotImplementedError(
            "Asymmetric S.1528 Rec 1.4 context (lt_m != lr_m) routed "
            "into the 1-D LUT fused evaluator; use the 2-D (theta, phi) "
            "path via _evaluate_s1528_pattern_cp(theta, phi_deg=...) instead."
        )
    _ensure_s1528_gain_lut_1d(context)
    theta = _to_cupy_array(theta_deg, dtype=cp.float32)
    kernel = (
        _get_s1528_lut_1d_to_linear_fp16_kernel()
        if context.d_gain_lut.dtype == cp.float16
        else _get_s1528_lut_1d_to_linear_kernel()
    )
    return kernel(
        theta,
        context.d_gain_lut,
        cp.float32(1.0 / context.gain_lut_step_deg),
        cp.float32(context.gain_lut_max_deg),
        np.int32(context.gain_lut_n),
        cp.float32(float(inv_gmax_lin)),
    )


_ras_pattern_to_linear_kernel = None


def _get_ras_pattern_to_linear_kernel():
    """Return (and cache) a fused kernel that evaluates the RAS pattern and
    converts from dB to linear gain in a single pass."""
    global _ras_pattern_to_linear_kernel
    if _ras_pattern_to_linear_kernel is not None:
        return _ras_pattern_to_linear_kernel
    _ras_pattern_to_linear_kernel = cp.ElementwiseKernel(
        "float32 phi_deg, float32 d_wlen, float32 gmax, float32 g1, "
        "float32 phi_m, float32 phi_r",
        "float32 gain_lin",
        """
        float phi = fabsf(phi_deg);
        float gain_db;
        if (phi < phi_m) {
            float dw_phi = d_wlen * phi;
            gain_db = gmax - 2.5e-3f * dw_phi * dw_phi;
        } else if (phi < phi_r) {
            gain_db = g1;
        } else if (phi < 10.0f) {
            gain_db = 29.0f - 25.0f * log10f(phi);
        } else if (phi < 34.1f) {
            gain_db = 34.0f - 30.0f * log10f(phi);
        } else if (phi < 80.0f) {
            gain_db = -12.0f;
        } else if (phi < 120.0f) {
            gain_db = -7.0f;
        } else {
            gain_db = -12.0f;
        }
        gain_lin = __expf(gain_db * 0.23025850929f);
        """,
        "ras_pattern_to_linear",
    )
    return _ras_pattern_to_linear_kernel


def _evaluate_ras_pattern_cp_to_linear(
    context: Any,
    theta_deg: Any,
    phi_deg: Any = None,
) -> Any:
    """RAS pattern evaluation returning linear gain in a single kernel launch.

    Dispatches by context type:
      * ``GpuRasPatternContext`` (RA.1631) → existing fused kernel.
      * ``GpuCustomPattern1DContext`` → custom-1D LUT eval in dB → exp.
      * ``GpuCustomPattern2DContext`` → Custom-2D (θ, φ) LUT eval, where
        φ is the rotation around the RAS boresight (callers derive it
        from the telescope pointing + satellite direction geometry).
        Raises :class:`ValueError` if ``phi_deg`` is omitted.

    ``theta_deg`` is the former ``phi_deg`` parameter (renamed for
    clarity — it is the angle between RAS boresight and the target).
    """
    if isinstance(context, GpuCustomPattern1DContext):
        # Absolute linear gain: fused kernel with inv_gmax_lin=1.0 gives
        # ``10^(gain_db / 10)`` in a single launch, avoiding the extra
        # ``cp.power(10, g/10)`` round-trip.
        return _evaluate_custom_1d_pattern_cp_to_linear(
            context, theta_deg, inv_gmax_lin=1.0,
        )
    if isinstance(context, GpuCustomPattern2DContext):
        if phi_deg is None:
            raise ValueError(
                "Custom-2D RAS pattern requires a ``phi_deg`` argument — "
                "the rotation around the RAS boresight. Callers must "
                "derive it from the telescope pointing and satellite "
                "direction before invoking the RAS evaluator."
            )
        return _evaluate_custom_2d_from_theta_phi_to_linear(
            context, theta_deg, phi_deg, inv_gmax_lin=1.0,
        )
    phi_cp = _to_cupy_array(theta_deg, dtype=cp.float32)
    d_wlen = np.float32(context.diameter_m / context.wavelength_m)
    gmax = np.float32(10.0 * np.log10(context.eta_a_dimless * (np.pi * d_wlen) ** 2))
    g1 = np.float32(-1.0 + 15.0 * np.log10(d_wlen))
    phi_m = np.float32(20.0 / d_wlen * np.sqrt(gmax - g1))
    phi_r = np.float32(15.85 * d_wlen ** -0.6)
    kernel = _get_ras_pattern_to_linear_kernel()
    return kernel(phi_cp, d_wlen, gmax, g1, phi_m, phi_r)


_slant_range_power_kernel = None


def _get_slant_range_power_kernel():
    """Fused kernel: computes variable transmit power (linear) from slant range.

    Power is linearly interpolated in dB between max_db (at R_min = altitude)
    and min_db (at R_max = max slant range at min elevation).
    """
    global _slant_range_power_kernel
    if _slant_range_power_kernel is not None:
        return _slant_range_power_kernel
    _slant_range_power_kernel = cp.ElementwiseKernel(
        "float32 range_m, float32 orbit_r, float32 earth_r, "
        "float32 sin_el_min, float32 cos_el_min, "
        "float32 pwr_min_db, float32 pwr_max_db",
        "float32 pwr_lin",
        """
        /* R_min = altitude (directly overhead) */
        float r_min = orbit_r - earth_r;
        /* R_max = slant range at minimum elevation angle */
        float r_max_sq = orbit_r * orbit_r - earth_r * earth_r * cos_el_min * cos_el_min;
        float r_max = (r_max_sq > 0.0f)
            ? sqrtf(r_max_sq) - earth_r * sin_el_min
            : r_min;
        if (r_max <= r_min) r_max = r_min + 1.0f;
        /* Fractional position: 0 at overhead, 1 at horizon */
        float frac = (range_m - r_min) / (r_max - r_min);
        if (frac < 0.0f) frac = 0.0f;
        if (frac > 1.0f) frac = 1.0f;
        /* Linear interpolation in dB: max at overhead, min at horizon */
        float pwr_db = pwr_max_db - frac * (pwr_max_db - pwr_min_db);
        /* dB to linear: 10^(x/10) = exp(x * ln(10)/10) */
        pwr_lin = __expf(pwr_db * 0.23025850929f);
        """,
        "slant_range_power",
    )
    return _slant_range_power_kernel


_tx_trig_geometry_kernel = None


def _get_tx_trig_geometry_kernel():
    """Fused kernel: compute beam and satellite-frame trig plus cos_gamma_tx
    from sat az/el and beam α/β in a single kernel launch.

    Replaces ~14 separate CuPy operations (remainder, deg2rad, sin×4, cos×4,
    sin, cos, where×2, multiply, clip) with one ElementwiseKernel.

    Inputs (broadcast from (T, S) sat angles and (T, S, K) beam angles):
      sat_az_deg  — satellite azimuth in degrees (T, S)
      sat_el_deg  — satellite elevation in degrees (T, S)
      beam_alpha  — beam steering azimuth in radians (T, S, K)
      beam_beta   — beam steering elevation in radians (T, S, K)
      beam_idx    — beam validity flag (≥ 0 valid, -2 boresight)

    Outputs:
      beam_sinb     — sin(beam_beta)
      beam_cosb     — cos(beam_beta)
      cos_gamma_tx  — cosine of TX off-axis angle (clamped to [-1, 1])
      sinb0         — sin(satellite elevation β₀)
      cosb0         — cos(satellite elevation β₀)
      sin_da        — sin(α₀ − α_beam), Δα in radians
      cos_da        — cos(α₀ − α_beam)

    The last four outputs let downstream consumers (asymmetric S.1528
    Rec 1.4, future custom 2-D patterns) derive the azimuth around the
    beam boresight without redoing the satellite-frame trig. Invalid
    slots still produce deterministic values but the meaning of φ for
    invalid slots is undefined — callers must respect the valid_beam
    mask when consuming these outputs.
    """
    global _tx_trig_geometry_kernel
    if _tx_trig_geometry_kernel is not None:
        return _tx_trig_geometry_kernel
    _tx_trig_geometry_kernel = cp.ElementwiseKernel(
        "float32 sat_az_deg, float32 sat_el_deg, "
        "float32 beam_alpha_rad, float32 beam_beta_rad, "
        "int32 beam_idx",
        "float32 beam_sinb, float32 beam_cosb, float32 cos_gamma_tx, "
        "float32 sinb0, float32 cosb0, float32 sin_da, float32 cos_da",
        """
        const float d2r = 0.017453292519943295f;
        const float two_pi = 6.283185307179586f;

        bool valid = (beam_idx >= 0) || (beam_idx == -2);
        bool boresight = (beam_idx == -2);

        /* Beam trig (zero for invalid beams) */
        float bb = valid ? beam_beta_rad : 0.0f;
        beam_sinb = sinf(bb);
        beam_cosb = cosf(bb);

        /* Satellite-frame trig — always computed so asymmetric consumers
         * have β₀ and Δα trig without a second kernel. */
        float a0 = fmodf(sat_az_deg * d2r, two_pi);
        if (a0 < 0.0f) a0 += two_pi;
        float b0 = sat_el_deg * d2r;
        sinb0 = sinf(b0);
        cosb0 = cosf(b0);
        float ba = valid ? beam_alpha_rad : 0.0f;
        float da = a0 - ba;
        sin_da = sinf(da);
        cos_da = cosf(da);

        if (boresight) {
            cos_gamma_tx = 1.0f;
        } else if (!valid) {
            cos_gamma_tx = -1.0f;
        } else {
            float cg = cosb0 * beam_cosb + sinb0 * beam_sinb * cos_da;
            if (cg > 1.0f) cg = 1.0f;
            if (cg < -1.0f) cg = -1.0f;
            cos_gamma_tx = cg;
        }
        """,
        "tx_trig_geometry_fused",
    )
    return _tx_trig_geometry_kernel


_beam_geometry_kernel = None


def _get_beam_geometry_kernel():
    """Fused kernel: beam→ground slant range + target elevation angle.

    Computes ``d_target_geom_m`` and ``e_target_deg`` from orbit radius,
    beam sin/cos(β), beam validity, and Earth radius in a single launch.
    Replaces ~16 separate CuPy operations (astype×2, multiply×3, subtract,
    comparison×3, and×2, where, sqrt, clip, arccos, multiply, where, max).
    """
    global _beam_geometry_kernel
    if _beam_geometry_kernel is not None:
        return _beam_geometry_kernel
    _beam_geometry_kernel = cp.ElementwiseKernel(
        "float32 beam_sinb, float32 beam_cosb, "
        "float32 orbit_r, float32 earth_r, "
        "int32 beam_idx, float32 atm_elev_min_deg",
        "float32 d_target, float32 e_target_deg, bool valid_geom",
        """
        bool valid = (beam_idx >= 0);    /* exclude boresight -2 and invalid -1 */
        bool cosb_positive = (beam_cosb > 0.0f);

        float term = orbit_r * beam_cosb;
        float disc = term * term - (orbit_r * orbit_r - earth_r * earth_r);
        bool hit = (disc >= 0.0f);
        bool vg = valid && hit && cosb_positive;
        valid_geom = vg;

        if (vg) {
            d_target = term - sqrtf(disc);
            /* Target elevation: arccos(clip((r/R_e)*sin(beta), 0, 1)) */
            float cos_e = (orbit_r / earth_r) * beam_sinb;
            if (cos_e < 0.0f) cos_e = 0.0f;
            if (cos_e > 1.0f) cos_e = 1.0f;
            float e_deg = acosf(cos_e) * 57.29577951308232f;
            if (e_deg < atm_elev_min_deg) e_deg = atm_elev_min_deg;
            e_target_deg = e_deg;
        } else {
            d_target = 0.0f;
            e_target_deg = 0.0f;
        }
        """,
        "beam_geometry_fused",
    )
    return _beam_geometry_kernel


_4d_trig_kernel = None


def _get_4d_trig_kernel():
    """Fused trig kernel for the 4-D boresight-avoidance power path.

    Computes sin(β), cos(β), Δα, sin(Δα), cos(Δα), and cos(γ_tx) from
    pre-gathered flat active-index arrays in a single launch.

    Replaces 9 separate CuPy operations: sin, cos, subtract, sin, cos,
    multiply×3, add, clip → 1 ElementwiseKernel.

    The 3-D equivalent is ``_get_tx_trig_geometry_kernel()`` which takes
    raw sat az/el in degrees. This kernel takes α₀, sinβ₀, cosβ₀ in
    radians (already gathered per active index in the 4-D path).
    """
    global _4d_trig_kernel
    if _4d_trig_kernel is not None:
        return _4d_trig_kernel
    _4d_trig_kernel = cp.ElementwiseKernel(
        "float32 active_alpha, float32 active_beta, "
        "float32 alpha0, float32 sinb0, float32 cosb0",
        "float32 beam_sinb, float32 beam_cosb, "
        "float32 cos_gamma_tx, float32 sin_da, float32 cos_da",
        r"""
        beam_sinb = sinf(active_beta);
        beam_cosb = cosf(active_beta);

        float da = alpha0 - active_alpha;
        sin_da = sinf(da);
        cos_da = cosf(da);

        float cg = cosb0 * beam_cosb + sinb0 * beam_sinb * cos_da;
        if (cg > 1.0f) cg = 1.0f;
        if (cg < -1.0f) cg = -1.0f;
        cos_gamma_tx = cg;
        """,
        "trig_4d_fused",
    )
    return _4d_trig_kernel


_4d_eirp_kernel = None


def _get_4d_eirp_kernel():
    """Fused EIRP kernel for the 4-D boresight-avoidance power path.

    Computes d_target, e_target_deg, valid_geom, and the boresight
    EIRP (for both co-frequency and geometry-based modes) from orbit
    radius, beam sin/cos(β), range, atmosphere factors, and the target
    PFD in a single launch.

    Replaces ~15 separate CuPy operations in the geometry + EIRP
    block: multiply×2, subtract, compare×2, and, where+sqrt, clip,
    divide, multiply, arccos, where+maximum, where, multiply×3, divide,
    where → 1 ElementwiseKernel.

    The atmosphere LUT lookup for target elevation must still be done
    AFTER this kernel (as a separate call to ``_lookup_atmosphere_lut_cp``),
    and the atmospheric correction is applied by dividing the geometry
    EIRP by atm_target. This kernel outputs the raw (un-atm-corrected)
    geometry EIRP for non-boresight slots.
    """
    global _4d_eirp_kernel
    if _4d_eirp_kernel is not None:
        return _4d_eirp_kernel
    _4d_eirp_kernel = cp.ElementwiseKernel(
        "float32 beam_sinb, float32 beam_cosb, "
        "float32 orbit_r, float32 earth_r, "
        "float32 atm_elev_min_deg, "
        "float32 range_m, float32 atm_ras, "
        "float32 target_pfd_4pi, "
        "bool use_ras_alt_co, bool is_boresight_slot",
        "float32 d_target, float32 e_target_deg, bool valid_geom, "
        "float32 boresight_eirp",
        r"""
        float term = orbit_r * beam_cosb;
        float disc = term * term - (orbit_r * orbit_r - earth_r * earth_r);
        bool hit = (disc >= 0.0f);
        bool cos_pos = (beam_cosb > 0.0f);
        bool vg = hit && cos_pos;
        valid_geom = vg;

        float dt_m = 0.0f;
        float et_deg = 0.0f;
        if (vg) {
            dt_m = term - sqrtf(disc);
            float cos_e = (orbit_r / earth_r) * beam_sinb;
            if (cos_e < 0.0f) cos_e = 0.0f;
            if (cos_e > 1.0f) cos_e = 1.0f;
            et_deg = acosf(cos_e) * 57.29577951308232f;
            if (et_deg < atm_elev_min_deg) et_deg = atm_elev_min_deg;
        }
        d_target = dt_m;
        e_target_deg = et_deg;

        float eirp;
        if (is_boresight_slot) {
            float atm_co = use_ras_alt_co ? atm_ras : 1.0f;
            eirp = target_pfd_4pi * range_m * range_m / atm_co;
        } else if (vg) {
            /* Raw geometry EIRP (atm_target applied after LUT lookup) */
            eirp = target_pfd_4pi * dt_m * dt_m;
        } else {
            eirp = 0.0f;
        }
        boresight_eirp = eirp;
        """,
        "eirp_4d_fused",
    )
    return _4d_eirp_kernel


_beam_geometry_fp64_kernel = None


def _get_beam_geometry_fp64_kernel():
    """Fused kernel: beam→ground geometry for fp64 power dtype.

    Same computation as ``_get_beam_geometry_kernel()`` but in float64.
    Computes d_target, e_target_deg, valid_geom from orbit radius,
    beam sin/cos(β), beam validity, boresight mask, and Earth radius.

    Replaces ~12 separate CuPy operations in the fp64 fallback path.
    """
    global _beam_geometry_fp64_kernel
    if _beam_geometry_fp64_kernel is not None:
        return _beam_geometry_fp64_kernel
    _beam_geometry_fp64_kernel = cp.ElementwiseKernel(
        "float64 beam_sinb, float64 beam_cosb, "
        "float64 orbit_r, float64 earth_r, "
        "bool valid_beam, bool mask_bore, float64 atm_elev_min_deg",
        "float64 d_target, float64 e_target_deg, bool valid_geom",
        r"""
        double term = orbit_r * beam_cosb;
        double disc = term * term - (orbit_r * orbit_r - earth_r * earth_r);
        bool hit = (disc >= 0.0);
        bool cos_pos = (beam_cosb > 0.0);
        bool vg = valid_beam && (!mask_bore) && hit && cos_pos;
        valid_geom = vg;

        if (vg) {
            d_target = term - sqrt(disc);
            double cos_e = (orbit_r / earth_r) * beam_sinb;
            if (cos_e < 0.0) cos_e = 0.0;
            if (cos_e > 1.0) cos_e = 1.0;
            double e_deg = acos(cos_e) * 57.29577951308232;
            if (e_deg < atm_elev_min_deg) e_deg = atm_elev_min_deg;
            e_target_deg = e_deg;
        } else {
            d_target = 0.0;
            e_target_deg = 0.0;
        }
        """,
        "beam_geometry_fp64_fused",
    )
    return _beam_geometry_fp64_kernel


_rx_angular_distance_only_kernel = None


def _get_rx_angular_distance_only_kernel():
    """Fused kernel: compute angular distance γ (deg) between telescope
    pointing and satellite direction.  Does NOT evaluate any pattern —
    just the trig.  Used as the first step for Custom RAS patterns
    where the pattern evaluation is a separate kernel.

    Replaces ~14 sequential CuPy operations (sin×4, cos×4, multiply×3,
    add, clip, arccos, multiply) with one ElementwiseKernel."""
    global _rx_angular_distance_only_kernel
    if _rx_angular_distance_only_kernel is not None:
        return _rx_angular_distance_only_kernel
    _rx_angular_distance_only_kernel = cp.ElementwiseKernel(
        "float32 tel_az_deg, float32 tel_el_deg, "
        "float32 sat_az_deg, float32 sat_el_deg",
        "float32 gamma_deg",
        r"""
        const float d2r = 0.017453292519943295f;
        const float r2d = 57.29577951308232f;
        float t_az = tel_az_deg * d2r;
        float t_el = tel_el_deg * d2r;
        float s_az = sat_az_deg * d2r;
        float s_el = sat_el_deg * d2r;
        float cos_daz = cosf(t_az) * cosf(s_az) + sinf(t_az) * sinf(s_az);
        float cos_gamma = sinf(t_el) * sinf(s_el)
                        + cosf(t_el) * cosf(s_el) * cos_daz;
        if (cos_gamma > 1.0f) cos_gamma = 1.0f;
        if (cos_gamma < -1.0f) cos_gamma = -1.0f;
        gamma_deg = acosf(cos_gamma) * r2d;
        """,
        "rx_angular_distance_only_fused",
    )
    return _rx_angular_distance_only_kernel


_rx_angular_distance_ras_lin_kernel = None


def _get_rx_angular_distance_ras_lin_kernel():
    """Fused kernel: computes RX angular distance from 4 az/el inputs, then
    evaluates the RAS antenna pattern and converts to linear gain — all in a
    single kernel launch.  Replaces ~10 separate CuPy calls."""
    global _rx_angular_distance_ras_lin_kernel
    if _rx_angular_distance_ras_lin_kernel is not None:
        return _rx_angular_distance_ras_lin_kernel
    _rx_angular_distance_ras_lin_kernel = cp.ElementwiseKernel(
        "float32 tel_az_deg, float32 tel_el_deg, "
        "float32 sat_az_deg, float32 sat_el_deg, "
        "float32 d_wlen, float32 gmax, float32 g1, "
        "float32 phi_m, float32 phi_r",
        "float32 grx_lin",
        """
        /* --- angular distance (true_angular_distance) --- */
        const float d2r = 0.017453292519943295f;
        const float r2d = 57.29577951308232f;
        float t_az = tel_az_deg * d2r;
        float t_el = tel_el_deg * d2r;
        float s_az = sat_az_deg * d2r;
        float s_el = sat_el_deg * d2r;
        float cos_daz = cosf(t_az) * cosf(s_az) + sinf(t_az) * sinf(s_az);
        float cos_gamma = sinf(t_el) * sinf(s_el)
                        + cosf(t_el) * cosf(s_el) * cos_daz;
        if (cos_gamma > 1.0f) cos_gamma = 1.0f;
        if (cos_gamma < -1.0f) cos_gamma = -1.0f;
        float phi = acosf(cos_gamma) * r2d;

        /* --- RAS pattern (ITU-R piecewise) --- */
        float gain_db;
        if (phi < phi_m) {
            float dw_phi = d_wlen * phi;
            gain_db = gmax - 2.5e-3f * dw_phi * dw_phi;
        } else if (phi < phi_r) {
            gain_db = g1;
        } else if (phi < 10.0f) {
            gain_db = 29.0f - 25.0f * log10f(phi);
        } else if (phi < 34.1f) {
            gain_db = 34.0f - 30.0f * log10f(phi);
        } else if (phi < 80.0f) {
            gain_db = -12.0f;
        } else if (phi < 120.0f) {
            gain_db = -7.0f;
        } else {
            gain_db = -12.0f;
        }
        /* dB to linear: 10^(x/10) = exp(x * ln(10)/10) */
        grx_lin = __expf(gain_db * 0.23025850929f);
        """,
        "rx_angular_distance_ras_lin",
    )
    return _rx_angular_distance_ras_lin_kernel


_m2101_composite_kernel = None


def _get_m2101_composite_kernel():
    """Return (and cache) a CuPy ElementwiseKernel for the ITU-R M.2101
    composite phased-array antenna pattern.

    Inputs are the observation direction (az, el) and the beam steering
    direction (az_i, el_i) in degrees, plus the array parameters.
    Uses the closed-form array factor for a uniform rectangular array.
    """
    global _m2101_composite_kernel
    if _m2101_composite_kernel is not None:
        return _m2101_composite_kernel
    _m2101_composite_kernel = cp.ElementwiseKernel(
        "float32 az_deg, float32 el_deg, float32 az_i_deg, float32 el_i_deg, "
        "float32 g_emax, float32 a_m, float32 sla_nu, "
        "float32 phi_3db, float32 theta_3db, "
        "float32 d_h, float32 d_v, int32 n_h, int32 n_v, float32 k",
        "float32 gain_db",
        """
        const float d2r = 0.017453292519943295f;

        /* --- Single element pattern A_E(az, el) --- */
        float az = az_deg * d2r;
        float el = el_deg * d2r;
        /* Horizontal cut: A_H = -min(k*(az/phi_3db)^2, A_m) */
        float az_norm = az_deg / phi_3db;
        float A_H = -fminf(k * az_norm * az_norm, a_m);
        /* Vertical cut: A_V = -min(k*(el/theta_3db)^2, SLA_nu) */
        float el_norm = el_deg / theta_3db;
        float A_V = -fminf(k * el_norm * el_norm, sla_nu);
        /* Combined element: A_E = G_Emax - min(-(A_H + A_V), A_m) */
        float A_E = g_emax - fminf(-(A_H + A_V), a_m);

        /* --- Closed-form array factor for uniform rectangular array --- */
        float az_i = az_i_deg * d2r;
        float el_i = el_i_deg * d2r;
        /* Direction cosine differences */
        float du = sinf(az) * cosf(el) - sinf(az_i) * cosf(el_i);
        float dv = sinf(el) - sinf(el_i);
        /* Horizontal array factor: sin(N*pi*d*u) / (N*sin(pi*d*u)) */
        float pi_d_h_du = 3.14159265f * d_h * du;
        float num_h = sinf((float)n_h * pi_d_h_du);
        float den_h = (float)n_h * sinf(pi_d_h_du);
        float af_h = (fabsf(den_h) > 1.0e-10f) ? (num_h / den_h) : 1.0f;
        /* Vertical array factor */
        float pi_d_v_dv = 3.14159265f * d_v * dv;
        float num_v = sinf((float)n_v * pi_d_v_dv);
        float den_v = (float)n_v * sinf(pi_d_v_dv);
        float af_v = (fabsf(den_v) > 1.0e-10f) ? (num_v / den_v) : 1.0f;
        /* Combined array factor in dB.
           Peak value = N_H * N_V (the closed-form sinc² evaluates to 1
           at the steering direction, so the N factor comes from the
           coherent sum of N_H*N_V elements). */
        float af_lin = af_h * af_h * af_v * af_v * (float)(n_h * n_v);
        float AF_db = (af_lin > 1.0e-20f) ? 10.0f * log10f(af_lin) : -200.0f;

        /* --- Composite gain --- */
        gain_db = A_E + AF_db;
        """,
        "m2101_composite_pattern",
    )
    return _m2101_composite_kernel


def _evaluate_m2101_pattern_cp(
    context: GpuM2101PatternContext,
    az_deg: Any,
    el_deg: Any,
    az_i_deg: Any,
    el_i_deg: Any,
) -> Any:
    """Evaluate the ITU-R M.2101 composite pattern on GPU."""
    kernel = _get_m2101_composite_kernel()
    return kernel(
        _to_cupy_array(az_deg, dtype=cp.float32),
        _to_cupy_array(el_deg, dtype=cp.float32),
        _to_cupy_array(az_i_deg, dtype=cp.float32),
        _to_cupy_array(el_i_deg, dtype=cp.float32),
        cp.float32(context.g_emax_db),
        cp.float32(context.a_m_db),
        cp.float32(context.sla_nu_db),
        cp.float32(context.phi_3db_deg),
        cp.float32(context.theta_3db_deg),
        cp.float32(context.d_h),
        cp.float32(context.d_v),
        np.int32(context.n_h),
        np.int32(context.n_v),
        cp.float32(context.k),
    )


# ---------------------------------------------------------------------------
#  M.2101 2-D element pattern LUT
# ---------------------------------------------------------------------------

_M2101_LUT_STEP_DEG = 0.1
_M2101_LUT_AZ_RANGE = (-180.0, 180.0)
_M2101_LUT_EL_RANGE = (-90.0, 90.0)


def _ensure_m2101_element_lut_2d(context: GpuM2101PatternContext) -> None:
    """Build and cache a 2-D element-pattern LUT ``A_E(az, el)`` on the GPU.

    The element pattern depends only on (az, el) and the scalar parameters
    ``g_emax``, ``a_m``, ``sla_nu``, ``phi_3db``, ``theta_3db``, ``k``.
    The array factor is NOT included — it depends on the steering direction
    and is kept analytical in the composite kernel.
    """
    if context.d_element_lut is not None:
        return
    step = float(_M2101_LUT_STEP_DEG)
    az_min, az_max = _M2101_LUT_AZ_RANGE
    el_min, el_max = _M2101_LUT_EL_RANGE
    n_az = int((az_max - az_min) / step) + 1
    n_el = int((el_max - el_min) / step) + 1
    # Build 2-D grid on GPU
    az_1d = cp.arange(n_az, dtype=cp.float32) * cp.float32(step) + cp.float32(az_min)
    el_1d = cp.arange(n_el, dtype=cp.float32) * cp.float32(step) + cp.float32(el_min)
    az_2d, el_2d = cp.meshgrid(az_1d, el_1d, indexing="xy")  # (n_el, n_az)
    az_flat = az_2d.ravel()
    el_flat = el_2d.ravel()
    # Evaluate element pattern only (no array factor) using a dedicated kernel
    kernel = _get_m2101_element_kernel()
    lut_flat = kernel(
        az_flat, el_flat,
        cp.float32(context.g_emax_db),
        cp.float32(context.a_m_db),
        cp.float32(context.sla_nu_db),
        cp.float32(context.phi_3db_deg),
        cp.float32(context.theta_3db_deg),
        cp.float32(context.k),
    )
    element_lut_cp = lut_flat.reshape(n_el, n_az)
    # Downcast the LUT to fp16 when the session's pattern stage runs at
    # fp16.  Halves the persistent LUT memory (26 MB → 13 MB on the
    # standard 0.1° grid) with essentially no extra eval cost — the
    # fp16 kernel loads ``__half`` and promotes to fp32 inside the
    # bilinear interpolation, same trig / AF / exp chain as the fp32
    # path.  For all other precision profiles the LUT stays fp32.
    _session_pattern_dtype = getattr(
        getattr(context, "session", None), "pattern_dtype", None,
    )
    if _session_pattern_dtype is not None and np.dtype(_session_pattern_dtype) == np.dtype(np.float16):
        element_lut_cp = element_lut_cp.astype(cp.float16, copy=False)
    context.d_element_lut = element_lut_cp
    context.element_lut_az_step_deg = step
    context.element_lut_el_step_deg = step
    context.element_lut_az_min_deg = az_min
    context.element_lut_el_min_deg = el_min
    context.element_lut_n_az = n_az
    context.element_lut_n_el = n_el


_m2101_element_kernel = None


def _get_m2101_element_kernel():
    """CuPy kernel for the M.2101 single-element pattern A_E(az, el) only."""
    global _m2101_element_kernel
    if _m2101_element_kernel is not None:
        return _m2101_element_kernel
    _m2101_element_kernel = cp.ElementwiseKernel(
        "float32 az_deg, float32 el_deg, "
        "float32 g_emax, float32 a_m, float32 sla_nu, "
        "float32 phi_3db, float32 theta_3db, float32 k",
        "float32 ae_db",
        """
        float az_norm = az_deg / phi_3db;
        float A_H = -fminf(k * az_norm * az_norm, a_m);
        float el_norm = el_deg / theta_3db;
        float A_V = -fminf(k * el_norm * el_norm, sla_nu);
        ae_db = g_emax - fminf(-(A_H + A_V), a_m);
        """,
        "m2101_element_pattern",
    )
    return _m2101_element_kernel


_m2101_lut_composite_kernel = None


def _get_m2101_lut_composite_kernel():
    """Hybrid kernel: 2-D bilinear LUT for element pattern + analytical array factor."""
    global _m2101_lut_composite_kernel
    if _m2101_lut_composite_kernel is not None:
        return _m2101_lut_composite_kernel
    _m2101_lut_composite_kernel = cp.ElementwiseKernel(
        "float32 az_deg, float32 el_deg, float32 az_i_deg, float32 el_i_deg, "
        "raw float32 lut, float32 az_min, float32 el_min, "
        "float32 inv_az_step, float32 inv_el_step, "
        "int32 n_az, int32 n_el, "
        "float32 d_h, float32 d_v, int32 n_h, int32 n_v",
        "float32 gain_db",
        """
        /* --- Element pattern from 2-D LUT (bilinear interpolation) --- */
        float az_f = (az_deg - az_min) * inv_az_step;
        float el_f = (el_deg - el_min) * inv_el_step;
        int az0 = __float2int_rd(az_f);
        int el0 = __float2int_rd(el_f);
        if (az0 < 0) az0 = 0;
        if (el0 < 0) el0 = 0;
        int az1 = az0 + 1;
        int el1 = el0 + 1;
        if (az1 >= n_az) { az1 = n_az - 1; az0 = az1 > 0 ? az1 - 1 : 0; }
        if (el1 >= n_el) { el1 = n_el - 1; el0 = el1 > 0 ? el1 - 1 : 0; }
        float fa = az_f - (float)az0;
        float fe = el_f - (float)el0;
        float v00 = lut[el0 * n_az + az0];
        float v10 = lut[el0 * n_az + az1];
        float v01 = lut[el1 * n_az + az0];
        float v11 = lut[el1 * n_az + az1];
        float A_E = v00 * (1.0f - fa) * (1.0f - fe)
                  + v10 * fa * (1.0f - fe)
                  + v01 * (1.0f - fa) * fe
                  + v11 * fa * fe;

        /* --- Analytical array factor (unchanged from full kernel) --- */
        const float d2r = 0.017453292519943295f;
        float az = az_deg * d2r;
        float el = el_deg * d2r;
        float az_i = az_i_deg * d2r;
        float el_i = el_i_deg * d2r;
        float du = sinf(az) * cosf(el) - sinf(az_i) * cosf(el_i);
        float dv = sinf(el) - sinf(el_i);
        float pi_d_h_du = 3.14159265f * d_h * du;
        float num_h = sinf((float)n_h * pi_d_h_du);
        float den_h = (float)n_h * sinf(pi_d_h_du);
        float af_h = (fabsf(den_h) > 1.0e-10f) ? (num_h / den_h) : 1.0f;
        float pi_d_v_dv = 3.14159265f * d_v * dv;
        float num_v = sinf((float)n_v * pi_d_v_dv);
        float den_v = (float)n_v * sinf(pi_d_v_dv);
        float af_v = (fabsf(den_v) > 1.0e-10f) ? (num_v / den_v) : 1.0f;
        float af_lin = af_h * af_h * af_v * af_v * (float)(n_h * n_v);
        float AF_db = (af_lin > 1.0e-20f) ? 10.0f * log10f(af_lin) : -200.0f;

        gain_db = A_E + AF_db;
        """,
        "m2101_lut_composite",
    )
    return _m2101_lut_composite_kernel


_m2101_lut_to_linear_kernel = None
_m2101_lut_to_linear_fp16_kernel = None


def _get_m2101_lut_to_linear_kernel():
    """Fused kernel: 2-D element LUT + analytical AF + dB→linear in one launch.

    Algebraic simplification: the previous version computed
    ``AF_db = 10·log10(af_lin)`` then did ``10^((A_E + AF_db) / 10)``,
    which is algebraically equal to ``10^(A_E/10) · af_lin``.  Dropping
    the log/exp round-trip on the array-factor side saves one ``log10f``
    and one branch per element; the element-pattern dB→linear step still
    needs the ``__expf`` call.  The ``af_lin`` floor is now a simple
    clamp that replaces the dB-floor branch.
    """
    global _m2101_lut_to_linear_kernel
    if _m2101_lut_to_linear_kernel is not None:
        return _m2101_lut_to_linear_kernel
    _m2101_lut_to_linear_kernel = cp.ElementwiseKernel(
        "float32 az_deg, float32 el_deg, float32 az_i_deg, float32 el_i_deg, "
        "raw float32 lut, float32 az_min, float32 el_min, "
        "float32 inv_az_step, float32 inv_el_step, "
        "int32 n_az, int32 n_el, "
        "float32 d_h, float32 d_v, int32 n_h, int32 n_v, "
        "float32 inv_gmax_lin",
        "float32 gain_rel_lin",
        """
        /* --- Element pattern from 2-D LUT --- */
        float az_f = (az_deg - az_min) * inv_az_step;
        float el_f = (el_deg - el_min) * inv_el_step;
        int az0 = __float2int_rd(az_f);
        int el0 = __float2int_rd(el_f);
        if (az0 < 0) az0 = 0;
        if (el0 < 0) el0 = 0;
        int az1 = az0 + 1;
        int el1 = el0 + 1;
        if (az1 >= n_az) { az1 = n_az - 1; az0 = az1 > 0 ? az1 - 1 : 0; }
        if (el1 >= n_el) { el1 = n_el - 1; el0 = el1 > 0 ? el1 - 1 : 0; }
        float fa = az_f - (float)az0;
        float fe = el_f - (float)el0;
        float v00 = lut[el0 * n_az + az0];
        float v10 = lut[el0 * n_az + az1];
        float v01 = lut[el1 * n_az + az0];
        float v11 = lut[el1 * n_az + az1];
        float A_E = v00 * (1.0f - fa) * (1.0f - fe)
                  + v10 * fa * (1.0f - fe)
                  + v01 * (1.0f - fa) * fe
                  + v11 * fa * fe;

        /* --- Analytical array factor --- */
        const float d2r = 0.017453292519943295f;
        float az = az_deg * d2r;
        float el = el_deg * d2r;
        float az_i = az_i_deg * d2r;
        float el_i = el_i_deg * d2r;
        float du = sinf(az) * cosf(el) - sinf(az_i) * cosf(el_i);
        float dv = sinf(el) - sinf(el_i);
        float pi_d_h_du = 3.14159265f * d_h * du;
        float num_h = sinf((float)n_h * pi_d_h_du);
        float den_h = (float)n_h * sinf(pi_d_h_du);
        float af_h = (fabsf(den_h) > 1.0e-10f) ? (num_h / den_h) : 1.0f;
        float pi_d_v_dv = 3.14159265f * d_v * dv;
        float num_v = sinf((float)n_v * pi_d_v_dv);
        float den_v = (float)n_v * sinf(pi_d_v_dv);
        float af_v = (fabsf(den_v) > 1.0e-10f) ? (num_v / den_v) : 1.0f;
        float af_lin = af_h * af_h * af_v * af_v * (float)(n_h * n_v);
        if (af_lin < 1.0e-20f) af_lin = 1.0e-20f;

        /* dB→linear on A_E only, then multiply by af_lin.  The old path
         * built AF_db = 10·log10(af_lin) and then 10^((A_E + AF_db)/10);
         * algebraically equal to this cheaper form. */
        float A_E_lin = __expf(A_E * 0.23025850929f);
        gain_rel_lin = A_E_lin * af_lin * inv_gmax_lin;
        """,
        "m2101_lut_to_linear",
    )
    return _m2101_lut_to_linear_kernel


def _get_m2101_lut_to_linear_fp16_kernel():
    """fp16-LUT variant of :func:`_get_m2101_lut_to_linear_kernel`.

    Identical body + same 9-op bilinear + analytical AF + dB→linear +
    inv_gmax chain, only the ``raw`` LUT input is ``float16``.  The 4
    corner loads cast ``__half → float`` implicitly before the bilinear
    weights multiply.  Halves the persistent M.2101 element-LUT memory
    (26 MB fp32 → 13 MB fp16) when the session runs at pattern_dtype
    fp16; no extra intermediate allocation or promotion kernels needed.
    The ULP-level difference from fp16 storage is well inside the
    precision already granted by the ``pattern_dtype=float16`` profile.
    """
    global _m2101_lut_to_linear_fp16_kernel
    if _m2101_lut_to_linear_fp16_kernel is not None:
        return _m2101_lut_to_linear_fp16_kernel
    _m2101_lut_to_linear_fp16_kernel = cp.ElementwiseKernel(
        "float32 az_deg, float32 el_deg, float32 az_i_deg, float32 el_i_deg, "
        "raw float16 lut, float32 az_min, float32 el_min, "
        "float32 inv_az_step, float32 inv_el_step, "
        "int32 n_az, int32 n_el, "
        "float32 d_h, float32 d_v, int32 n_h, int32 n_v, "
        "float32 inv_gmax_lin",
        "float32 gain_rel_lin",
        """
        float az_f = (az_deg - az_min) * inv_az_step;
        float el_f = (el_deg - el_min) * inv_el_step;
        int az0 = __float2int_rd(az_f);
        int el0 = __float2int_rd(el_f);
        if (az0 < 0) az0 = 0;
        if (el0 < 0) el0 = 0;
        int az1 = az0 + 1;
        int el1 = el0 + 1;
        if (az1 >= n_az) { az1 = n_az - 1; az0 = az1 > 0 ? az1 - 1 : 0; }
        if (el1 >= n_el) { el1 = n_el - 1; el0 = el1 > 0 ? el1 - 1 : 0; }
        float fa = az_f - (float)az0;
        float fe = el_f - (float)el0;
        /* Cast fp16 → fp32 at read; bilinear done in fp32 to avoid
         * accumulating half-precision error across 4 weighted taps. */
        float v00 = (float)lut[el0 * n_az + az0];
        float v10 = (float)lut[el0 * n_az + az1];
        float v01 = (float)lut[el1 * n_az + az0];
        float v11 = (float)lut[el1 * n_az + az1];
        float A_E = v00 * (1.0f - fa) * (1.0f - fe)
                  + v10 * fa * (1.0f - fe)
                  + v01 * (1.0f - fa) * fe
                  + v11 * fa * fe;

        const float d2r = 0.017453292519943295f;
        float az = az_deg * d2r;
        float el = el_deg * d2r;
        float az_i = az_i_deg * d2r;
        float el_i = el_i_deg * d2r;
        float du = sinf(az) * cosf(el) - sinf(az_i) * cosf(el_i);
        float dv = sinf(el) - sinf(el_i);
        float pi_d_h_du = 3.14159265f * d_h * du;
        float num_h = sinf((float)n_h * pi_d_h_du);
        float den_h = (float)n_h * sinf(pi_d_h_du);
        float af_h = (fabsf(den_h) > 1.0e-10f) ? (num_h / den_h) : 1.0f;
        float pi_d_v_dv = 3.14159265f * d_v * dv;
        float num_v = sinf((float)n_v * pi_d_v_dv);
        float den_v = (float)n_v * sinf(pi_d_v_dv);
        float af_v = (fabsf(den_v) > 1.0e-10f) ? (num_v / den_v) : 1.0f;
        float af_lin = af_h * af_h * af_v * af_v * (float)(n_h * n_v);
        if (af_lin < 1.0e-20f) af_lin = 1.0e-20f;

        float A_E_lin = __expf(A_E * 0.23025850929f);
        gain_rel_lin = A_E_lin * af_lin * inv_gmax_lin;
        """,
        "m2101_lut_to_linear_fp16",
    )
    return _m2101_lut_to_linear_fp16_kernel


def _evaluate_m2101_pattern_cp_lut(
    context: GpuM2101PatternContext,
    az_deg: Any,
    el_deg: Any,
    az_i_deg: Any,
    el_i_deg: Any,
) -> Any:
    """Evaluate M.2101 composite pattern using 2-D element LUT + analytical AF."""
    _ensure_m2101_element_lut_2d(context)
    kernel = _get_m2101_lut_composite_kernel()
    return kernel(
        _to_cupy_array(az_deg, dtype=cp.float32),
        _to_cupy_array(el_deg, dtype=cp.float32),
        _to_cupy_array(az_i_deg, dtype=cp.float32),
        _to_cupy_array(el_i_deg, dtype=cp.float32),
        context.d_element_lut.ravel(),
        cp.float32(context.element_lut_az_min_deg),
        cp.float32(context.element_lut_el_min_deg),
        cp.float32(1.0 / context.element_lut_az_step_deg),
        cp.float32(1.0 / context.element_lut_el_step_deg),
        np.int32(context.element_lut_n_az),
        np.int32(context.element_lut_n_el),
        cp.float32(context.d_h),
        cp.float32(context.d_v),
        np.int32(context.n_h),
        np.int32(context.n_v),
    )


def _evaluate_m2101_pattern_cp_lut_to_linear(
    context: GpuM2101PatternContext,
    az_deg: Any,
    el_deg: Any,
    az_i_deg: Any,
    el_i_deg: Any,
    inv_gmax_lin: float,
) -> Any:
    """M.2101 fused LUT evaluation returning relative linear gain.

    Dispatches to the fp16-LUT kernel when the element LUT is stored as
    fp16 (mixed-precision profiles) — same fused bilinear + AF + dB→linear
    body, just with a 13 MB vs 26 MB persistent LUT footprint.
    """
    _ensure_m2101_element_lut_2d(context)
    kernel = (
        _get_m2101_lut_to_linear_fp16_kernel()
        if context.d_element_lut.dtype == cp.float16
        else _get_m2101_lut_to_linear_kernel()
    )
    return kernel(
        _to_cupy_array(az_deg, dtype=cp.float32),
        _to_cupy_array(el_deg, dtype=cp.float32),
        _to_cupy_array(az_i_deg, dtype=cp.float32),
        _to_cupy_array(el_i_deg, dtype=cp.float32),
        context.d_element_lut.ravel(),
        cp.float32(context.element_lut_az_min_deg),
        cp.float32(context.element_lut_el_min_deg),
        cp.float32(1.0 / context.element_lut_az_step_deg),
        cp.float32(1.0 / context.element_lut_el_step_deg),
        np.int32(context.element_lut_n_az),
        np.int32(context.element_lut_n_el),
        cp.float32(context.d_h),
        cp.float32(context.d_v),
        np.int32(context.n_h),
        np.int32(context.n_v),
        cp.float32(float(inv_gmax_lin)),
    )


_s1528_rec12_pattern_kernel = None


def _get_s1528_rec12_pattern_kernel():
    """Return (and cache) a CuPy ElementwiseKernel for S.1528 Rec 1.2 piecewise envelope."""
    global _s1528_rec12_pattern_kernel
    if _s1528_rec12_pattern_kernel is not None:
        return _s1528_rec12_pattern_kernel
    _s1528_rec12_pattern_kernel = cp.ElementwiseKernel(
        "float32 theta_deg, float32 gm, float32 ln, float32 psi_b, "
        "float32 a, float32 b, float32 alpha, "
        "float32 lf, float32 lb, float32 x_coeff, float32 y_deg, float32 z_val",
        "float32 gain",
        """
        float ang = fabsf(theta_deg);
        float a_psi_b = a * psi_b;
        float half_b_psi_b = 0.5f * b * psi_b;
        float b_psi_b = b * psi_b;
        if (ang <= a_psi_b) {
            gain = gm - 3.0f * powf(ang / psi_b, alpha);
        } else if (ang <= half_b_psi_b) {
            gain = gm + ln + 20.0f * log10f(z_val > 0.0f ? z_val : 1.0f);
        } else if (ang <= b_psi_b) {
            gain = gm + ln;
        } else if (ang <= y_deg) {
            gain = x_coeff - 25.0f * log10f(ang);
        } else if (ang <= 90.0f) {
            gain = lf;
        } else if (ang <= 180.0f) {
            gain = lb;
        } else {
            gain = lb;
        }
        """,
        "s1528_rec12_pattern",
    )
    return _s1528_rec12_pattern_kernel


def _evaluate_s1528_rec12_pattern_cp(
    context: GpuS1528Rec12PatternContext,
    theta_deg: Any,
) -> Any:
    """Evaluate the S.1528 Rec 1.2 piecewise envelope on GPU."""
    theta = _to_cupy_array(theta_deg, dtype=cp.float32)
    kernel = _get_s1528_rec12_pattern_kernel()
    return kernel(
        theta,
        cp.float32(context.gm_db),
        cp.float32(context.ln_db),
        cp.float32(context.psi_b),
        cp.float32(context.a),
        cp.float32(context.b),
        cp.float32(context.alpha),
        cp.float32(context.lf_db),
        cp.float32(context.lb_db),
        cp.float32(context.x_coeff),
        cp.float32(context.y_deg),
        cp.float32(context.z),
    )


_ras_pattern_kernel = None


def _get_ras_pattern_kernel():
    """Return (and cache) a fused CuPy ElementwiseKernel for RAS pattern."""
    global _ras_pattern_kernel
    if _ras_pattern_kernel is not None:
        return _ras_pattern_kernel
    _ras_pattern_kernel = cp.ElementwiseKernel(
        "float32 phi_deg, float32 d_wlen, float32 gmax, float32 g1, "
        "float32 phi_m, float32 phi_r",
        "float32 gain",
        """
        float phi = fabsf(phi_deg);
        if (phi < phi_m) {
            float dw_phi = d_wlen * phi;
            gain = gmax - 2.5e-3f * dw_phi * dw_phi;
        } else if (phi < phi_r) {
            gain = g1;
        } else if (phi < 10.0f) {
            gain = 29.0f - 25.0f * log10f(phi);
        } else if (phi < 34.1f) {
            gain = 34.0f - 30.0f * log10f(phi);
        } else if (phi < 80.0f) {
            gain = -12.0f;
        } else if (phi < 120.0f) {
            gain = -7.0f;
        } else {
            gain = -12.0f;
        }
        """,
        "ras_pattern_fused",
    )
    return _ras_pattern_kernel


_ras_boresight_phi_kernel = None


def _get_ras_boresight_phi_kernel():
    """Fused kernel: compute φ angle (deg) of a target about the RAS
    boresight in one launch.  Replaces ~10 separate CuPy operations
    (sin×3, cos×3, multiply×3, subtract, arctan2, multiply)."""
    global _ras_boresight_phi_kernel
    if _ras_boresight_phi_kernel is not None:
        return _ras_boresight_phi_kernel
    _ras_boresight_phi_kernel = cp.ElementwiseKernel(
        "float32 tel_az_rad, float32 tel_el_rad, "
        "float32 sat_az_rad, float32 sat_el_rad",
        "float32 phi_deg",
        r"""
        float daz = sat_az_rad - tel_az_rad;
        float cos_sat_el = cosf(sat_el_rad);
        float u = cos_sat_el * sinf(daz);
        float v = cos_sat_el * sinf(tel_el_rad) * cosf(daz)
                - sinf(sat_el_rad) * cosf(tel_el_rad);
        phi_deg = atan2f(v, u) * 57.29577951308232f;
        """,
        "ras_boresight_phi_fused",
    )
    return _ras_boresight_phi_kernel


def _ras_boresight_frame_phi_deg(
    tel_az_rad: Any,
    tel_el_rad: Any,
    sat_az_rad: Any,
    sat_el_rad: Any,
) -> Any:
    """Return the φ angle (deg) of a target about the RAS boresight.

    ``φ = 0°`` is defined as the horizontal-right direction when
    looking down the telescope boresight — i.e. the unit vector
    ``ê₁ = (cos(az_tel), −sin(az_tel), 0)``. ``φ`` increases
    counter-clockwise (right-handed) around the boresight, with
    ``ê₂ = p̂ × ê₁`` the "up-in-boresight-frame" axis pointing toward
    the zenith-side of the pointing.

    Consumed only by Custom-2D RAS patterns — derivation is
    intentionally isolated from the hot-path ``cos γ`` computation so
    the 1-D fast-paths incur zero extra trig. All inputs are CuPy
    arrays of matching shape (broadcasts naturally). The derivation
    uses the closed-form simplification:

    .. math::

        u &= \\cos(e_s) \\sin(a_s - a_t) \\\\
        v &= \\cos(e_s) \\sin(e_t) \\cos(a_s - a_t) - \\sin(e_s) \\cos(e_t) \\\\
        \\varphi &= \\operatorname{atan2}(v, u)
    """
    # Use fused kernel for fp32 inputs (the common GPU path).
    _tel_az = _to_cupy_array(tel_az_rad)
    _tel_el = _to_cupy_array(tel_el_rad)
    _sat_az = _to_cupy_array(sat_az_rad)
    _sat_el = _to_cupy_array(sat_el_rad)
    if _tel_az.dtype == cp.float32:
        return _get_ras_boresight_phi_kernel()(
            _tel_az, _tel_el, _sat_az, _sat_el,
        )
    # Fallback for non-fp32 dtypes.
    daz = _sat_az - _tel_az
    sin_daz = cp.sin(daz)
    cos_daz = cp.cos(daz)
    sin_tel_el = cp.sin(_tel_el)
    cos_tel_el = cp.cos(_tel_el)
    sin_sat_el = cp.sin(_sat_el)
    cos_sat_el = cp.cos(_sat_el)
    u = cos_sat_el * sin_daz
    v = cos_sat_el * sin_tel_el * cos_daz - sin_sat_el * cos_tel_el
    return cp.arctan2(v, u) * cp.float32(180.0 / np.pi)


def _evaluate_ras_pattern_cp(
    context: Any,
    theta_deg: Any,
    phi_deg: Any = None,
) -> Any:
    """Evaluate the RAS antenna pattern in dBi.

    ``theta_deg`` is the angle between the telescope boresight and
    the target (previously named ``phi_deg``). ``phi_deg`` is the
    rotation around the boresight and is only consumed by Custom-2D
    patterns — other context types ignore it.

    Dispatches by context type — RA.1631 takes the existing fused
    kernel, user-supplied custom patterns take the LUT-interp path
    (same context types as the satellite side, so a user can load
    the same file on either axis if desired).
    """
    if isinstance(context, GpuCustomPattern1DContext):
        return _evaluate_custom_1d_pattern_cp(context, theta_deg)
    if isinstance(context, GpuCustomPattern2DContext):
        if phi_deg is None:
            raise ValueError(
                "Custom-2D RAS pattern requires a ``phi_deg`` argument — "
                "the rotation around the RAS boresight. Callers must "
                "derive it from the telescope pointing and satellite "
                "direction before invoking the RAS evaluator."
            )
        return _evaluate_custom_2d_from_theta_phi(context, theta_deg, phi_deg)
    # Use fused single-kernel evaluation instead of 6 separate cp.where calls
    phi_cp = _to_cupy_array(theta_deg, dtype=cp.float32)
    d_wlen = np.float32(context.diameter_m / context.wavelength_m)
    gmax = np.float32(10.0 * np.log10(context.eta_a_dimless * (np.pi * d_wlen) ** 2))
    g1 = np.float32(-1.0 + 15.0 * np.log10(d_wlen))
    phi_m = np.float32(20.0 / d_wlen * np.sqrt(gmax - g1))
    phi_r = np.float32(15.85 * d_wlen ** -0.6)
    kernel = _get_ras_pattern_kernel()
    return kernel(phi_cp, d_wlen, gmax, g1, phi_m, phi_r)


def _evaluate_s1528_pattern_cp_analytical(
    context: GpuS1528PatternContext,
    theta_deg: Any,
    phi_deg: Any | None = None,
) -> Any:
    """Analytical S.1528 pattern evaluation (Bessel + product formulation)."""
    theta = _to_cupy_array(theta_deg, dtype=cp.float32)
    if phi_deg is None:
        # Optimized: when phi=0, cos_ph=1, sin_ph=0,
        # so u_val = (pi/lambda) * lr * |sin(theta)|
        sin_th = cp.sin(cp.deg2rad(theta))
        u_val = cp.float32(np.pi / float(context.wavelength_m) * float(context.lr_m)) * cp.abs(sin_th)
    else:
        phi = _to_cupy_array(phi_deg, dtype=cp.float32)
        theta, phi = cp.broadcast_arrays(theta, phi)
        sin_th = cp.sin(cp.deg2rad(theta))
        cos_ph = cp.cos(cp.deg2rad(phi))
        sin_ph = cp.sin(cp.deg2rad(phi))
        u_val = cp.float32(np.pi / float(context.wavelength_m)) * cp.sqrt(
            (np.float32(context.lr_m) * sin_th * cos_ph) ** np.float32(2.0)
            + (np.float32(context.lt_m) * sin_th * sin_ph) ** np.float32(2.0)
        )

    term1 = 2.0 * cupy_special.j1(u_val) / u_val
    term1 = cp.where(u_val == 0.0, cp.float32(1.0), term1).astype(cp.float32, copy=False)

    uu = u_val.reshape(1, -1).astype(cp.float32, copy=False) ** np.float32(2.0)
    mu_roots = _to_cupy_array(context.d_mu_roots, dtype=cp.float32)
    i = cp.arange(1, int(context.l), dtype=cp.float32)[:, None]
    if int(i.size) == 0:
        prod = cp.ones_like(u_val, dtype=cp.float32)
    else:
        num = 1.0 - uu / (np.float32(context.pi2sig2) * (np.float32(context.A * context.A) + (i - 0.5) ** 2))
        den = 1.0 - uu / ((np.float32(np.pi) * mu_roots[: int(context.l) - 1, None]) ** np.float32(2.0))
        prod = cp.prod(num / den, axis=0).reshape(u_val.shape).astype(cp.float32, copy=False)

    F = cp.abs(term1 * prod).astype(cp.float32, copy=False)
    gain = (np.float32(20.0) * cp.log10(F)).astype(cp.float32, copy=False)
    if context.gm_db is not None:
        gain = gain + np.float32(context.gm_db)
    if context.far_sidelobe_start_deg is not None and context.far_sidelobe_level_db is not None:
        far_mask = cp.abs(theta) >= np.float32(context.far_sidelobe_start_deg)
        gain = cp.where(far_mask, np.float32(context.far_sidelobe_level_db), gain)
    return gain.astype(cp.float32, copy=False)


# Module-level pattern evaluation mode.  Controls whether the TX
# antenna pattern is evaluated via a precomputed LUT (fast, default)
# or the exact analytical formula (Bessel/product for S.1528,
# composite element+array for M.2101).  Applies to all analytical
# pattern types — S.1528 Rec 1.2/1.4, M.2101.  RA.1631 is always
# analytical regardless of this flag.
_pattern_eval_mode = "lut"


def set_pattern_eval_mode(mode: str) -> None:
    """Set the antenna pattern evaluation mode ('lut' or 'analytical')."""
    global _pattern_eval_mode
    if mode not in ("lut", "analytical"):
        raise ValueError(f"pattern_eval_mode must be 'lut' or 'analytical'; got {mode!r}.")
    _pattern_eval_mode = str(mode)


def get_pattern_eval_mode() -> str:
    """Return the current antenna pattern evaluation mode."""
    return _pattern_eval_mode


def _evaluate_isotropic_pattern_cp(
    context: GpuIsotropicPatternContext,
    theta_deg: Any,
    phi_deg: Any | None = None,
) -> Any:
    """Isotropic pattern evaluation — returns 0 dB (Gtx = 0 dBi) at every angle.

    The output matches ``theta_deg`` in shape and dtype so it can substitute
    for any S.1528 / S.1528 Rec 1.2 result in the dispatcher. ``phi_deg`` is
    accepted for call-site symmetry but is unused.
    """
    del context, phi_deg
    theta_cp = _to_cupy_array(theta_deg, dtype=cp.float32)
    return cp.zeros_like(theta_cp)


# ---------------------------------------------------------------------------
# Custom 1-D (axisymmetric) pattern evaluation
# ---------------------------------------------------------------------------

# Regular-grid resolution used when resampling a user-supplied
# CustomAntennaPattern onto the device LUT. 0.001° × 180° → 180001
# entries × float32 ≈ 720 KB per context — fine for any realistic
# user-authored pattern (real-world LUTs are coarser than 0.001°), and
# much cheaper than the 0.0001° that S.1528 Rec 1.2 uses internally for
# its analytical narrow-beam envelope.
_CUSTOM_1D_LUT_STEP_DEG: float = 0.001
_CUSTOM_1D_LUT_MAX_DEG: float = 180.0


# ---------------------------------------------------------------------------
# Custom 2-D pattern evaluation — generic bilinear LUT with per-axis
# wrap-or-clip policy.
# ---------------------------------------------------------------------------

# Default resample resolutions, chosen to fit comfortably under any
# realistic user-authored source density while staying under a few
# tens of MB per context at 16-bit / 32-bit storage.
_CUSTOM_2D_AZEL_AZ_STEP_DEG: float = 0.1      # 3601 samples over [-180, 180]
_CUSTOM_2D_AZEL_EL_STEP_DEG: float = 0.1      # 1801 samples over [-90, 90]
_CUSTOM_2D_THETAPHI_THETA_STEP_DEG: float = 0.05  # 3601 samples over [0, 180]
_CUSTOM_2D_THETAPHI_PHI_STEP_DEG: float = 0.1     # 3601 samples over [-180, 180]

# Safety cap on LUT element count. 16M float32 = 64 MB — covers the
# Ultimate density tier (3601 × 3601 ≈ 13M for θ/φ, 3601 × 1801 ≈
# 6.5M for az/el) while preventing pathologically fine grids from
# blowing VRAM (e.g. 0.01° × 0.01° over full az/el = 648M elements).
_CUSTOM_2D_MAX_LUT_ELEMENTS: int = 16_000_000


# LRU budget for the session's custom-pattern context cache, expressed
# per registered system. Each cached context pins a device-side LUT
# (≈720 KB for a 1-D context at 0.001°, a few MB for a typical 2-D
# context), and the mutation-friendly content-hash key means a user
# interactively tweaking a pattern creates a new entry on every change.
# Capping at 5 slots per system lets the last handful of edits stay
# warm while preventing unbounded growth across long GUI sessions.
# Multi-system aware: the effective cap is scaled by the number of
# registered systems so each system's working set gets its own budget.
_CUSTOM_PATTERN_CACHE_SLOTS_PER_SYSTEM: int = 5


_custom_2d_lut_interp_kernel = None
_custom_2d_lut_interp_fp16_kernel = None


def _get_custom_2d_lut_interp_kernel():
    """Return (and cache) the generic 2-D LUT bilinear-interp kernel.

    Matches the bilinear layout used by the M.2101 element LUT and the
    S.1528 2-D (θ, φ) LUT but without either pattern's axis symmetries —
    the schema allows arbitrary user-defined gain surfaces so we cannot
    fold into a canonical sub-quadrant. Per-axis wrap-vs-clip behaviour
    is selected at call time by the ``axis*_wraps`` flags.
    """
    global _custom_2d_lut_interp_kernel
    if _custom_2d_lut_interp_kernel is not None:
        return _custom_2d_lut_interp_kernel
    _custom_2d_lut_interp_kernel = cp.ElementwiseKernel(
        "float32 a0, float32 a1, raw float32 lut, "
        "float32 a0_min, float32 a0_range, float32 a0_inv_step, "
        "int32 a0_n, int32 a0_wraps, "
        "float32 a1_min, float32 a1_range, float32 a1_inv_step, "
        "int32 a1_n, int32 a1_wraps",
        "float32 gain_db",
        """
        /* Axis 0 wrap-or-clip. For wrap mode we fold ``x - min`` into
         * ``[0, range)`` via floorf; for clip we saturate to the grid
         * endpoints. ``range`` is ``(n-1) * step``, so after folding
         * the query always lies in the half-open interval covered by
         * cells ``[0 .. n-2]``. */
        float a0q = a0;
        if (a0_wraps != 0) {
            float rel = a0q - a0_min;
            rel = rel - floorf(rel / a0_range) * a0_range;
            if (rel < 0.0f) rel += a0_range;
            if (rel >= a0_range) rel -= a0_range;
            a0q = a0_min + rel;
        } else {
            float a0_max = a0_min + a0_range;
            if (a0q < a0_min) a0q = a0_min;
            if (a0q > a0_max) a0q = a0_max;
        }

        float a1q = a1;
        if (a1_wraps != 0) {
            float rel = a1q - a1_min;
            rel = rel - floorf(rel / a1_range) * a1_range;
            if (rel < 0.0f) rel += a1_range;
            if (rel >= a1_range) rel -= a1_range;
            a1q = a1_min + rel;
        } else {
            float a1_max = a1_min + a1_range;
            if (a1q < a1_min) a1q = a1_min;
            if (a1q > a1_max) a1q = a1_max;
        }

        float fidx0 = (a0q - a0_min) * a0_inv_step;
        float fidx1 = (a1q - a1_min) * a1_inv_step;
        int i0 = __float2int_rd(fidx0);
        int j0 = __float2int_rd(fidx1);
        if (i0 < 0) i0 = 0;
        if (j0 < 0) j0 = 0;
        if (i0 > a0_n - 2) i0 = a0_n - 2;
        if (j0 > a1_n - 2) j0 = a1_n - 2;
        int i1 = i0 + 1;
        int j1 = j0 + 1;
        float f0 = fidx0 - (float)i0;
        float f1 = fidx1 - (float)j0;
        if (f0 < 0.0f) f0 = 0.0f;
        if (f0 > 1.0f) f0 = 1.0f;
        if (f1 < 0.0f) f1 = 0.0f;
        if (f1 > 1.0f) f1 = 1.0f;

        float v00 = lut[i0 * a1_n + j0];
        float v10 = lut[i1 * a1_n + j0];
        float v01 = lut[i0 * a1_n + j1];
        float v11 = lut[i1 * a1_n + j1];
        gain_db = v00 * (1.0f - f0) * (1.0f - f1)
                + v10 * f0 * (1.0f - f1)
                + v01 * (1.0f - f0) * f1
                + v11 * f0 * f1;
        """,
        "custom_2d_lut_interp",
    )
    return _custom_2d_lut_interp_kernel


def _get_custom_2d_lut_interp_fp16_kernel():
    """fp16-LUT variant of :func:`_get_custom_2d_lut_interp_kernel`.

    Same wrap-or-clip + bilinear body, with the ``raw`` LUT input now
    ``float16``. Halves the persistent Custom-2D LUT memory (typical
    user pattern ≈ 3-13 MB fp32 → 1.5-6.5 MB fp16; capped at 32 MB
    fp16 under the 16 M element safety cap) when the session runs
    at ``pattern_dtype=float16``.
    """
    global _custom_2d_lut_interp_fp16_kernel
    if _custom_2d_lut_interp_fp16_kernel is not None:
        return _custom_2d_lut_interp_fp16_kernel
    _custom_2d_lut_interp_fp16_kernel = cp.ElementwiseKernel(
        "float32 a0, float32 a1, raw float16 lut, "
        "float32 a0_min, float32 a0_range, float32 a0_inv_step, "
        "int32 a0_n, int32 a0_wraps, "
        "float32 a1_min, float32 a1_range, float32 a1_inv_step, "
        "int32 a1_n, int32 a1_wraps",
        "float32 gain_db",
        """
        float a0q = a0;
        if (a0_wraps != 0) {
            float rel = a0q - a0_min;
            rel = rel - floorf(rel / a0_range) * a0_range;
            if (rel < 0.0f) rel += a0_range;
            if (rel >= a0_range) rel -= a0_range;
            a0q = a0_min + rel;
        } else {
            float a0_max = a0_min + a0_range;
            if (a0q < a0_min) a0q = a0_min;
            if (a0q > a0_max) a0q = a0_max;
        }

        float a1q = a1;
        if (a1_wraps != 0) {
            float rel = a1q - a1_min;
            rel = rel - floorf(rel / a1_range) * a1_range;
            if (rel < 0.0f) rel += a1_range;
            if (rel >= a1_range) rel -= a1_range;
            a1q = a1_min + rel;
        } else {
            float a1_max = a1_min + a1_range;
            if (a1q < a1_min) a1q = a1_min;
            if (a1q > a1_max) a1q = a1_max;
        }

        float fidx0 = (a0q - a0_min) * a0_inv_step;
        float fidx1 = (a1q - a1_min) * a1_inv_step;
        int i0 = __float2int_rd(fidx0);
        int j0 = __float2int_rd(fidx1);
        if (i0 < 0) i0 = 0;
        if (j0 < 0) j0 = 0;
        if (i0 > a0_n - 2) i0 = a0_n - 2;
        if (j0 > a1_n - 2) j0 = a1_n - 2;
        int i1 = i0 + 1;
        int j1 = j0 + 1;
        float f0 = fidx0 - (float)i0;
        float f1 = fidx1 - (float)j0;
        if (f0 < 0.0f) f0 = 0.0f;
        if (f0 > 1.0f) f0 = 1.0f;
        if (f1 < 0.0f) f1 = 0.0f;
        if (f1 > 1.0f) f1 = 1.0f;

        float v00 = (float)lut[i0 * a1_n + j0];
        float v10 = (float)lut[i1 * a1_n + j0];
        float v01 = (float)lut[i0 * a1_n + j1];
        float v11 = (float)lut[i1 * a1_n + j1];
        gain_db = v00 * (1.0f - f0) * (1.0f - f1)
                + v10 * f0 * (1.0f - f1)
                + v01 * (1.0f - f0) * f1
                + v11 * f0 * f1;
        """,
        "custom_2d_lut_interp_fp16",
    )
    return _custom_2d_lut_interp_fp16_kernel


def _evaluate_custom_2d_pattern_cp(
    context: GpuCustomPattern2DContext,
    axis0_deg: Any,
    axis1_deg: Any,
) -> Any:
    """Evaluate a user-supplied 2-D custom pattern on GPU via bilinear LUT.

    The two input axes map to ``(az, el)`` when
    ``context.grid_mode == "az_el"`` and to ``(θ, φ)`` when
    ``grid_mode == "theta_phi"`` — matching the
    :func:`scepter.custom_antenna.evaluate_pattern_2d` convention so
    callers can switch between CPU and GPU paths with identical
    argument semantics.
    """
    a0 = _to_cupy_array(axis0_deg, dtype=cp.float32)
    a1 = _to_cupy_array(axis1_deg, dtype=cp.float32)
    a0, a1 = cp.broadcast_arrays(a0, a1)
    kernel = (
        _get_custom_2d_lut_interp_fp16_kernel()
        if context.d_gain_lut.dtype == cp.float16
        else _get_custom_2d_lut_interp_kernel()
    )
    return kernel(
        a0, a1,
        context.d_gain_lut,
        cp.float32(context.axis0_min_deg),
        cp.float32(context.axis0_range_deg),
        cp.float32(1.0 / context.axis0_step_deg),
        np.int32(context.axis0_n),
        np.int32(1 if context.axis0_wraps else 0),
        cp.float32(context.axis1_min_deg),
        cp.float32(context.axis1_range_deg),
        cp.float32(1.0 / context.axis1_step_deg),
        np.int32(context.axis1_n),
        np.int32(1 if context.axis1_wraps else 0),
    )


_custom_2d_lut_to_linear_kernel = None
_custom_2d_lut_to_linear_fp16_kernel = None


def _get_custom_2d_lut_to_linear_kernel():
    """Fused Custom-2D LUT bilinear + dB→linear + relative gain in one launch.

    Matches the fused pattern used by S.1528 1-D / 2-D and M.2101 —
    collapses the two-step ``LUT → dB → cp.power(10, g/10) * inv_gmax``
    call chain into a single ElementwiseKernel.  Saves 1 ``log10f``,
    1 branch, and 1-2 extra CuPy launches per evaluation.
    """
    global _custom_2d_lut_to_linear_kernel
    if _custom_2d_lut_to_linear_kernel is not None:
        return _custom_2d_lut_to_linear_kernel
    _custom_2d_lut_to_linear_kernel = cp.ElementwiseKernel(
        "float32 a0, float32 a1, raw float32 lut, "
        "float32 a0_min, float32 a0_range, float32 a0_inv_step, "
        "int32 a0_n, int32 a0_wraps, "
        "float32 a1_min, float32 a1_range, float32 a1_inv_step, "
        "int32 a1_n, int32 a1_wraps, "
        "float32 inv_gmax_lin",
        "float32 gain_rel_lin",
        """
        float a0q = a0;
        if (a0_wraps != 0) {
            float rel = a0q - a0_min;
            rel = rel - floorf(rel / a0_range) * a0_range;
            if (rel < 0.0f) rel += a0_range;
            if (rel >= a0_range) rel -= a0_range;
            a0q = a0_min + rel;
        } else {
            float a0_max = a0_min + a0_range;
            if (a0q < a0_min) a0q = a0_min;
            if (a0q > a0_max) a0q = a0_max;
        }
        float a1q = a1;
        if (a1_wraps != 0) {
            float rel = a1q - a1_min;
            rel = rel - floorf(rel / a1_range) * a1_range;
            if (rel < 0.0f) rel += a1_range;
            if (rel >= a1_range) rel -= a1_range;
            a1q = a1_min + rel;
        } else {
            float a1_max = a1_min + a1_range;
            if (a1q < a1_min) a1q = a1_min;
            if (a1q > a1_max) a1q = a1_max;
        }
        float fidx0 = (a0q - a0_min) * a0_inv_step;
        float fidx1 = (a1q - a1_min) * a1_inv_step;
        int i0 = __float2int_rd(fidx0);
        int j0 = __float2int_rd(fidx1);
        if (i0 < 0) i0 = 0;
        if (j0 < 0) j0 = 0;
        if (i0 > a0_n - 2) i0 = a0_n - 2;
        if (j0 > a1_n - 2) j0 = a1_n - 2;
        int i1 = i0 + 1;
        int j1 = j0 + 1;
        float f0 = fidx0 - (float)i0;
        float f1 = fidx1 - (float)j0;
        if (f0 < 0.0f) f0 = 0.0f;
        if (f0 > 1.0f) f0 = 1.0f;
        if (f1 < 0.0f) f1 = 0.0f;
        if (f1 > 1.0f) f1 = 1.0f;
        float v00 = lut[i0 * a1_n + j0];
        float v10 = lut[i1 * a1_n + j0];
        float v01 = lut[i0 * a1_n + j1];
        float v11 = lut[i1 * a1_n + j1];
        float gain_db = v00 * (1.0f - f0) * (1.0f - f1)
                      + v10 * f0 * (1.0f - f1)
                      + v01 * (1.0f - f0) * f1
                      + v11 * f0 * f1;
        /* 10^(x/10) = exp(x * ln(10)/10) */
        gain_rel_lin = __expf(gain_db * 0.23025850929f) * inv_gmax_lin;
        """,
        "custom_2d_lut_to_linear",
    )
    return _custom_2d_lut_to_linear_kernel


def _get_custom_2d_lut_to_linear_fp16_kernel():
    """fp16-LUT variant of :func:`_get_custom_2d_lut_to_linear_kernel`.

    Fused wrap-or-clip + bilinear + dB→linear + relative-gain chain
    over a ``raw float16`` LUT.  Matches the S.1528 2-D fp16 path:
    corner loads promote to fp32, interpolation and ``__expf`` stay
    in fp32.
    """
    global _custom_2d_lut_to_linear_fp16_kernel
    if _custom_2d_lut_to_linear_fp16_kernel is not None:
        return _custom_2d_lut_to_linear_fp16_kernel
    _custom_2d_lut_to_linear_fp16_kernel = cp.ElementwiseKernel(
        "float32 a0, float32 a1, raw float16 lut, "
        "float32 a0_min, float32 a0_range, float32 a0_inv_step, "
        "int32 a0_n, int32 a0_wraps, "
        "float32 a1_min, float32 a1_range, float32 a1_inv_step, "
        "int32 a1_n, int32 a1_wraps, "
        "float32 inv_gmax_lin",
        "float32 gain_rel_lin",
        """
        float a0q = a0;
        if (a0_wraps != 0) {
            float rel = a0q - a0_min;
            rel = rel - floorf(rel / a0_range) * a0_range;
            if (rel < 0.0f) rel += a0_range;
            if (rel >= a0_range) rel -= a0_range;
            a0q = a0_min + rel;
        } else {
            float a0_max = a0_min + a0_range;
            if (a0q < a0_min) a0q = a0_min;
            if (a0q > a0_max) a0q = a0_max;
        }
        float a1q = a1;
        if (a1_wraps != 0) {
            float rel = a1q - a1_min;
            rel = rel - floorf(rel / a1_range) * a1_range;
            if (rel < 0.0f) rel += a1_range;
            if (rel >= a1_range) rel -= a1_range;
            a1q = a1_min + rel;
        } else {
            float a1_max = a1_min + a1_range;
            if (a1q < a1_min) a1q = a1_min;
            if (a1q > a1_max) a1q = a1_max;
        }
        float fidx0 = (a0q - a0_min) * a0_inv_step;
        float fidx1 = (a1q - a1_min) * a1_inv_step;
        int i0 = __float2int_rd(fidx0);
        int j0 = __float2int_rd(fidx1);
        if (i0 < 0) i0 = 0;
        if (j0 < 0) j0 = 0;
        if (i0 > a0_n - 2) i0 = a0_n - 2;
        if (j0 > a1_n - 2) j0 = a1_n - 2;
        int i1 = i0 + 1;
        int j1 = j0 + 1;
        float f0 = fidx0 - (float)i0;
        float f1 = fidx1 - (float)j0;
        if (f0 < 0.0f) f0 = 0.0f;
        if (f0 > 1.0f) f0 = 1.0f;
        if (f1 < 0.0f) f1 = 0.0f;
        if (f1 > 1.0f) f1 = 1.0f;
        float v00 = (float)lut[i0 * a1_n + j0];
        float v10 = (float)lut[i1 * a1_n + j0];
        float v01 = (float)lut[i0 * a1_n + j1];
        float v11 = (float)lut[i1 * a1_n + j1];
        float gain_db = v00 * (1.0f - f0) * (1.0f - f1)
                      + v10 * f0 * (1.0f - f1)
                      + v01 * (1.0f - f0) * f1
                      + v11 * f0 * f1;
        gain_rel_lin = __expf(gain_db * 0.23025850929f) * inv_gmax_lin;
        """,
        "custom_2d_lut_to_linear_fp16",
    )
    return _custom_2d_lut_to_linear_fp16_kernel


def _evaluate_custom_2d_pattern_cp_to_linear(
    context: GpuCustomPattern2DContext,
    axis0_deg: Any,
    axis1_deg: Any,
    inv_gmax_lin: float,
) -> Any:
    """Fused Custom-2D LUT evaluation returning relative linear gain.

    Mirrors :func:`_evaluate_s1528_pattern_cp_lut_2d_to_linear` and the
    M.2101 fused path.  Inputs: ``(axis0_deg, axis1_deg)`` in the
    pattern's native grid basis (``(az, el)`` or ``(θ, φ)`` depending on
    ``context.grid_mode``).  Output: ``10^(gain_db/10) / gmax_lin``.
    """
    a0 = _to_cupy_array(axis0_deg, dtype=cp.float32)
    a1 = _to_cupy_array(axis1_deg, dtype=cp.float32)
    a0, a1 = cp.broadcast_arrays(a0, a1)
    kernel = (
        _get_custom_2d_lut_to_linear_fp16_kernel()
        if context.d_gain_lut.dtype == cp.float16
        else _get_custom_2d_lut_to_linear_kernel()
    )
    return kernel(
        a0, a1,
        context.d_gain_lut,
        cp.float32(context.axis0_min_deg),
        cp.float32(context.axis0_range_deg),
        cp.float32(1.0 / context.axis0_step_deg),
        np.int32(context.axis0_n),
        np.int32(1 if context.axis0_wraps else 0),
        cp.float32(context.axis1_min_deg),
        cp.float32(context.axis1_range_deg),
        cp.float32(1.0 / context.axis1_step_deg),
        np.int32(context.axis1_n),
        np.int32(1 if context.axis1_wraps else 0),
        cp.float32(float(inv_gmax_lin)),
    )


_theta_phi_to_azel_kernel = None


def _get_theta_phi_to_azel_kernel():
    """Fused (θ, φ) → (az, el) coordinate conversion for Custom-2D az_el
    grid mode.  Replaces 6 separate CuPy operations (sin×2, cos×2,
    arctan2, arcsin) with one ElementwiseKernel launch."""
    global _theta_phi_to_azel_kernel
    if _theta_phi_to_azel_kernel is not None:
        return _theta_phi_to_azel_kernel
    _theta_phi_to_azel_kernel = cp.ElementwiseKernel(
        "float32 theta_deg, float32 phi_deg",
        "float32 az_deg, float32 el_deg",
        r"""
        const float d2r = 0.017453292519943295f;
        const float r2d = 57.29577951308232f;
        float th = theta_deg * d2r;
        float ph = phi_deg * d2r;
        float sin_th = sinf(th);
        float cos_th = cosf(th);
        float sin_ph = sinf(ph);
        float cos_ph = cosf(ph);
        az_deg = atan2f(sin_th * cos_ph, cos_th) * r2d;
        float sp = sin_th * sin_ph;
        if (sp > 1.0f) sp = 1.0f;
        if (sp < -1.0f) sp = -1.0f;
        el_deg = asinf(sp) * r2d;
        """,
        "theta_phi_to_azel_fused",
    )
    return _theta_phi_to_azel_kernel


def _evaluate_custom_2d_from_theta_phi(
    context: GpuCustomPattern2DContext,
    theta_deg: Any,
    phi_deg: Any,
) -> Any:
    """Evaluate a Custom-2D pattern given boresight-relative ``(θ, φ)``.

    The power path carries ``(θ, φ)`` around the beam boresight (Stage 5
    derivation). Custom-2D patterns may be authored in either
    ``grid_mode="theta_phi"`` (direct match) or ``grid_mode="az_el"``
    (schema's datasheet-style, boresight at the (0, 0) origin). This
    helper absorbs the conversion so every hot-path call site can feed
    ``(θ, φ)`` without knowing which authoring mode the user chose.

    Conversion (schema doc, "Conversion between the two 2-D modes"):

    - ``az = atan2(sin(θ)·cos(φ), cos(θ))`` — signed, ``[-180°, 180°]``
    - ``el = arcsin(sin(θ)·sin(φ))`` — signed, ``[-90°, 90°]``
    """
    theta = _to_cupy_array(theta_deg, dtype=cp.float32)
    phi = _to_cupy_array(phi_deg, dtype=cp.float32)
    if context.grid_mode == "theta_phi":
        return _evaluate_custom_2d_pattern_cp(context, theta, phi)
    if context.grid_mode == "az_el":
        # Fused coordinate conversion (6 ops → 1 kernel) + LUT lookup.
        _conv_kernel = _get_theta_phi_to_azel_kernel()
        az, el = _conv_kernel(theta, phi)
        return _evaluate_custom_2d_pattern_cp(context, az, el)
    raise ValueError(f"Unsupported Custom-2D grid_mode={context.grid_mode!r}.")


def _evaluate_custom_2d_from_theta_phi_to_linear(
    context: GpuCustomPattern2DContext,
    theta_deg: Any,
    phi_deg: Any,
    inv_gmax_lin: float,
) -> Any:
    """Fused Custom-2D ``(θ, φ)`` evaluation returning relative linear gain.

    Mirrors :func:`_evaluate_custom_2d_from_theta_phi` but returns the
    fused-kernel linear output (saves the ``cp.power(10, g/10) * inv_gmax``
    round-trip that every hot-path caller would otherwise add).

    **Preferred hot-path entry point:** for az_el-authored patterns
    the caller should compute body-frame ``(az, el)`` from the beam
    trig components it already has and call
    :func:`_evaluate_custom_2d_from_azel_to_linear` directly — that
    skips the θ/φ intermediate entirely.  This helper is kept as a
    fallback for callers that already have (θ, φ) in hand and would
    need to redo the geometry to get (az, el); it converts on the
    GPU via ``_theta_phi_to_azel_fused`` then dispatches.
    """
    theta = _to_cupy_array(theta_deg, dtype=cp.float32)
    phi = _to_cupy_array(phi_deg, dtype=cp.float32)
    if context.grid_mode == "theta_phi":
        return _evaluate_custom_2d_pattern_cp_to_linear(
            context, theta, phi, inv_gmax_lin=inv_gmax_lin,
        )
    if context.grid_mode == "az_el":
        _conv_kernel = _get_theta_phi_to_azel_kernel()
        az, el = _conv_kernel(theta, phi)
        return _evaluate_custom_2d_pattern_cp_to_linear(
            context, az, el, inv_gmax_lin=inv_gmax_lin,
        )
    raise ValueError(f"Unsupported Custom-2D grid_mode={context.grid_mode!r}.")


# Fused body-frame → pattern-eval kernels.  2 modes × 2 LUT dtypes ×
# 2 compute dtypes = 8 kernel variants.  The LUT storage dtype tracks
# the context's ``d_gain_lut`` (fp32 default, fp16 when
# ``pattern_dtype == fp16``).  The compute dtype tracks the session's
# ``pwr_dt`` (fp32 default, fp64 for ``float64`` / ``float64/float32``
# precision profiles).  fp16 compute is NOT offered — FSPL values
# underflow fp16 downstream, so power always runs at fp32+.
_custom_2d_body_to_lin_kernel_cache: dict[tuple[str, str, str], Any] = {}


def _build_custom_2d_body_kernel(
    *, mode: str, lut_dtype: str, compute_dtype: str,
) -> "cp.ElementwiseKernel":
    """Build the fused body-frame → (az, el) or (θ, φ) → LUT lookup
    → dB→linear → inv_gmax kernel.

    Takes beam body-frame unit-vector components ``(x_body, y_body,
    z_body)`` (already computed in the 3-D / 4-D power kernels) and
    produces relative linear gain in one CUDA launch — no
    intermediate ``(az, el)`` / ``(θ, φ)`` tensors, no per-axis
    conversion kernel, no dB→linear follow-up.

    Parameters
    ----------
    mode : {"az_el", "theta_phi"}
        Pattern grid mode — decides the coord formulas at the top
        of the kernel.
    lut_dtype : {"float32", "float16"}
        Storage dtype of the LUT on device.  fp16 corner loads
        promote to fp32.
    compute_dtype : {"float32", "float64"}
        Input (body-frame) + output (gain_rel_lin) precision.
        Interior arithmetic stays fp32 (LUT is fp32/fp16 anyway; no
        fp64 benefit in the interp itself), but at fp64 the output
        is promoted so downstream FSPL × gain at ``pwr_dt=fp64``
        carries full precision.  fp16 NOT supported for compute —
        FSPL underflows fp16 downstream.
    """
    if compute_dtype not in ("float32", "float64"):
        raise ValueError(
            f"compute_dtype must be float32 or float64; got {compute_dtype!r}."
        )

    # Coord conversion block. Uses fp32 sinf/atan2f/asinf regardless of
    # compute dtype because angular precision at one-cell resolution is
    # dominated by the LUT's bin step (0.05°-5°), not float precision.
    # fp64 callers cast to fp32 for the transcendentals then back for
    # the output path.  Matches how analytical mega-kernel does trig.
    if mode == "az_el":
        coord_block = r"""
        float a0 = atan2f((float)x_body, (float)z_body) * 57.29577951308232f;
        float y_clip = (float)y_body;
        if (y_clip >  1.0f) y_clip =  1.0f;
        if (y_clip < -1.0f) y_clip = -1.0f;
        float a1 = asinf(y_clip) * 57.29577951308232f;
        """
    elif mode == "theta_phi":
        coord_block = r"""
        float z_clip = (float)z_body;
        if (z_clip >  1.0f) z_clip =  1.0f;
        if (z_clip < -1.0f) z_clip = -1.0f;
        float a0 = acosf(z_clip) * 57.29577951308232f;
        float a1 = atan2f((float)y_body, (float)x_body) * 57.29577951308232f;
        """
    else:
        raise ValueError(f"Unknown grid mode: {mode!r}")

    corner_cast = "(float)" if lut_dtype == "float16" else ""
    out_cast = (
        "" if compute_dtype == "float32"
        else "(double)"  # promote final product to fp64 for fp64 output
    )

    body = coord_block + r"""
        /* Wrap-or-clip axis 0. */
        float a0q = a0;
        if (a0_wraps != 0) {
            float rel = a0q - a0_min;
            rel = rel - floorf(rel / a0_range) * a0_range;
            if (rel < 0.0f) rel += a0_range;
            if (rel >= a0_range) rel -= a0_range;
            a0q = a0_min + rel;
        } else {
            float a0_max = a0_min + a0_range;
            if (a0q < a0_min) a0q = a0_min;
            if (a0q > a0_max) a0q = a0_max;
        }
        /* Wrap-or-clip axis 1. */
        float a1q = a1;
        if (a1_wraps != 0) {
            float rel = a1q - a1_min;
            rel = rel - floorf(rel / a1_range) * a1_range;
            if (rel < 0.0f) rel += a1_range;
            if (rel >= a1_range) rel -= a1_range;
            a1q = a1_min + rel;
        } else {
            float a1_max = a1_min + a1_range;
            if (a1q < a1_min) a1q = a1_min;
            if (a1q > a1_max) a1q = a1_max;
        }
        float fidx0 = (a0q - a0_min) * a0_inv_step;
        float fidx1 = (a1q - a1_min) * a1_inv_step;
        int i0 = __float2int_rd(fidx0);
        int j0 = __float2int_rd(fidx1);
        if (i0 < 0) i0 = 0;
        if (j0 < 0) j0 = 0;
        if (i0 > a0_n - 2) i0 = a0_n - 2;
        if (j0 > a1_n - 2) j0 = a1_n - 2;
        int i1 = i0 + 1;
        int j1 = j0 + 1;
        float f0 = fidx0 - (float)i0;
        float f1 = fidx1 - (float)j0;
        if (f0 < 0.0f) f0 = 0.0f;
        if (f0 > 1.0f) f0 = 1.0f;
        if (f1 < 0.0f) f1 = 0.0f;
        if (f1 > 1.0f) f1 = 1.0f;
        float v00 = """ + corner_cast + r"""lut[i0 * a1_n + j0];
        float v10 = """ + corner_cast + r"""lut[i1 * a1_n + j0];
        float v01 = """ + corner_cast + r"""lut[i0 * a1_n + j1];
        float v11 = """ + corner_cast + r"""lut[i1 * a1_n + j1];
        float gain_db = v00 * (1.0f - f0) * (1.0f - f1)
                      + v10 * f0 * (1.0f - f1)
                      + v01 * (1.0f - f0) * f1
                      + v11 * f0 * f1;
        gain_rel_lin = """ + out_cast + r"""(__expf(gain_db * 0.23025850929f) * (float)inv_gmax_lin);
        """

    lut_in = (
        "raw float16 lut" if lut_dtype == "float16" else "raw float32 lut"
    )
    compute_in = "float64" if compute_dtype == "float64" else "float32"
    kernel_name = (
        f"custom_2d_body_{mode}_to_lin_"
        f"{'fp64' if compute_dtype == 'float64' else 'fp32'}_"
        f"{'fp16' if lut_dtype == 'float16' else 'fp32'}lut"
    )
    return cp.ElementwiseKernel(
        f"{compute_in} x_body, {compute_in} y_body, {compute_in} z_body, "
        f"{lut_in}, "
        "float32 a0_min, float32 a0_range, float32 a0_inv_step, "
        "int32 a0_n, int32 a0_wraps, "
        "float32 a1_min, float32 a1_range, float32 a1_inv_step, "
        "int32 a1_n, int32 a1_wraps, "
        f"{compute_in} inv_gmax_lin",
        f"{compute_in} gain_rel_lin",
        body,
        kernel_name,
    )


def _get_custom_2d_body_kernel(
    *, mode: str, lut_is_fp16: bool, compute_is_fp64: bool,
) -> "cp.ElementwiseKernel":
    key = (
        mode,
        "float16" if lut_is_fp16 else "float32",
        "float64" if compute_is_fp64 else "float32",
    )
    kernel = _custom_2d_body_to_lin_kernel_cache.get(key)
    if kernel is None:
        kernel = _build_custom_2d_body_kernel(
            mode=key[0], lut_dtype=key[1], compute_dtype=key[2],
        )
        _custom_2d_body_to_lin_kernel_cache[key] = kernel
    return kernel


# Lever #2: mega pattern-eval kernel — takes raw beam trig (the
# outputs of _get_tx_trig_geometry_kernel / _get_4d_trig_kernel) and
# emits BOTH rel and abs linear gain in one launch.  Compared to the
# split "body-frame kernel + x_body/y_body compute + gmax multiply"
# path, fuses 3-5 launches into 1.  Mirrors the analytical mega
# pattern where upstream trig → pattern eval is a single launch.
_custom_2d_trig_to_gain_kernel_cache: dict[tuple[str, str, str], Any] = {}


def _build_custom_2d_trig_to_gain_kernel(
    *, mode: str, lut_dtype: str, compute_dtype: str,
) -> "cp.ElementwiseKernel":
    """Build the mega kernel: raw beam trig → body-frame coords →
    pattern eval → dB→linear → inv_gmax → emit rel AND abs linear gain.

    Inputs per thread:
      beam_sinb, beam_cosb, sin_da, cos_da, sinb0, cosb0, cos_gamma_tx
    Outputs per thread:
      gtx_rel_lin = pattern(coord) / gmax
      gtx_abs_lin = pattern(coord)        (= gtx_rel_lin × gmax)

    Parameters mirror :func:`_build_custom_2d_body_kernel`.
    """
    if compute_dtype not in ("float32", "float64"):
        raise ValueError(f"compute_dtype must be float32 or float64; got {compute_dtype!r}.")

    if mode == "az_el":
        coord_block = r"""
        /* Body-frame components from raw beam trig -- what
         * _convert_surface_between_grids / _accumulate_*_cp used to
         * do in 2-3 separate CuPy launches.  x_body = beam_cosb * sin_da,
         * y_body = cosb0 * beam_sinb - sinb0 * beam_cosb * cos_da,
         * z_body = cos_gamma_tx. */
        float xb = (float)beam_cosb * (float)sin_da;
        float yb = (float)cosb0 * (float)beam_sinb
                 - (float)sinb0 * (float)beam_cosb * (float)cos_da;
        float zb = (float)cos_gamma_tx;
        float a0 = atan2f(xb, zb) * 57.29577951308232f;
        if (yb >  1.0f) yb =  1.0f;
        if (yb < -1.0f) yb = -1.0f;
        float a1 = asinf(yb) * 57.29577951308232f;
        """
    elif mode == "theta_phi":
        coord_block = r"""
        float xb = (float)beam_cosb * (float)sin_da;
        float yb = (float)cosb0 * (float)beam_sinb
                 - (float)sinb0 * (float)beam_cosb * (float)cos_da;
        float zb = (float)cos_gamma_tx;
        if (zb >  1.0f) zb =  1.0f;
        if (zb < -1.0f) zb = -1.0f;
        float a0 = acosf(zb) * 57.29577951308232f;
        float a1 = atan2f(yb, xb) * 57.29577951308232f;
        """
    else:
        raise ValueError(f"Unknown grid mode: {mode!r}")

    corner_cast = "(float)" if lut_dtype == "float16" else ""
    out_type = "double" if compute_dtype == "float64" else "float"

    body = coord_block + r"""
        float a0q = a0;
        if (a0_wraps != 0) {
            float rel = a0q - a0_min;
            rel = rel - floorf(rel / a0_range) * a0_range;
            if (rel < 0.0f) rel += a0_range;
            if (rel >= a0_range) rel -= a0_range;
            a0q = a0_min + rel;
        } else {
            float a0_max = a0_min + a0_range;
            if (a0q < a0_min) a0q = a0_min;
            if (a0q > a0_max) a0q = a0_max;
        }
        float a1q = a1;
        if (a1_wraps != 0) {
            float rel = a1q - a1_min;
            rel = rel - floorf(rel / a1_range) * a1_range;
            if (rel < 0.0f) rel += a1_range;
            if (rel >= a1_range) rel -= a1_range;
            a1q = a1_min + rel;
        } else {
            float a1_max = a1_min + a1_range;
            if (a1q < a1_min) a1q = a1_min;
            if (a1q > a1_max) a1q = a1_max;
        }
        float fidx0 = (a0q - a0_min) * a0_inv_step;
        float fidx1 = (a1q - a1_min) * a1_inv_step;
        int i0 = __float2int_rd(fidx0);
        int j0 = __float2int_rd(fidx1);
        if (i0 < 0) i0 = 0;
        if (j0 < 0) j0 = 0;
        if (i0 > a0_n - 2) i0 = a0_n - 2;
        if (j0 > a1_n - 2) j0 = a1_n - 2;
        int i1 = i0 + 1;
        int j1 = j0 + 1;
        float f0 = fidx0 - (float)i0;
        float f1 = fidx1 - (float)j0;
        if (f0 < 0.0f) f0 = 0.0f;
        if (f0 > 1.0f) f0 = 1.0f;
        if (f1 < 0.0f) f1 = 0.0f;
        if (f1 > 1.0f) f1 = 1.0f;
        float v00 = """ + corner_cast + r"""lut[i0 * a1_n + j0];
        float v10 = """ + corner_cast + r"""lut[i1 * a1_n + j0];
        float v01 = """ + corner_cast + r"""lut[i0 * a1_n + j1];
        float v11 = """ + corner_cast + r"""lut[i1 * a1_n + j1];
        float gain_db = v00 * (1.0f - f0) * (1.0f - f1)
                      + v10 * f0 * (1.0f - f1)
                      + v01 * (1.0f - f0) * f1
                      + v11 * f0 * f1;
        float abs_lin_f = __expf(gain_db * 0.23025850929f);
        gtx_abs_lin = (""" + out_type + r""")abs_lin_f;
        gtx_rel_lin = (""" + out_type + r""")(abs_lin_f * (float)inv_gmax_lin);
        """

    lut_in = "raw float16 lut" if lut_dtype == "float16" else "raw float32 lut"
    compute_in = "float64" if compute_dtype == "float64" else "float32"
    kernel_name = (
        f"custom_2d_trig_to_gain_{mode}_"
        f"{'fp64' if compute_dtype == 'float64' else 'fp32'}_"
        f"{'fp16' if lut_dtype == 'float16' else 'fp32'}lut"
    )
    return cp.ElementwiseKernel(
        f"{compute_in} beam_sinb, {compute_in} beam_cosb, "
        f"{compute_in} sin_da, {compute_in} cos_da, "
        f"{compute_in} sinb0, {compute_in} cosb0, "
        f"{compute_in} cos_gamma_tx, "
        f"{lut_in}, "
        "float32 a0_min, float32 a0_range, float32 a0_inv_step, "
        "int32 a0_n, int32 a0_wraps, "
        "float32 a1_min, float32 a1_range, float32 a1_inv_step, "
        "int32 a1_n, int32 a1_wraps, "
        f"{compute_in} inv_gmax_lin",
        f"{compute_in} gtx_rel_lin, {compute_in} gtx_abs_lin",
        body,
        kernel_name,
    )


def _get_custom_2d_trig_to_gain_kernel(
    *, mode: str, lut_is_fp16: bool, compute_is_fp64: bool,
) -> "cp.ElementwiseKernel":
    key = (
        mode,
        "float16" if lut_is_fp16 else "float32",
        "float64" if compute_is_fp64 else "float32",
    )
    kernel = _custom_2d_trig_to_gain_kernel_cache.get(key)
    if kernel is None:
        kernel = _build_custom_2d_trig_to_gain_kernel(
            mode=key[0], lut_dtype=key[1], compute_dtype=key[2],
        )
        _custom_2d_trig_to_gain_kernel_cache[key] = kernel
    return kernel


def _evaluate_custom_2d_from_beam_trig_to_rel_abs_linear(
    context: GpuCustomPattern2DContext,
    beam_sinb: Any,
    beam_cosb: Any,
    sin_da: Any,
    cos_da: Any,
    sinb0: Any,
    cosb0: Any,
    cos_gamma_tx: Any,
    inv_gmax_lin: float,
    *,
    compute_dtype: Any = None,
) -> tuple[Any, Any]:
    """Mega pattern-eval entry point: raw beam trig → (gtx_rel_lin,
    gtx_abs_lin) in a single CUDA launch.

    Replaces 3-5 launches from the previous path (x_body compute,
    y_body compute, body-frame kernel, gmax multiply) with one.
    Mirrors the analytical path where fused TX trig + fused pattern
    LUT feed K1 with minimal intermediate materialisation.

    Both outputs are emitted by the same kernel pass — no second
    CuPy multiply for gtx_abs_lin = gtx_rel_lin × gmax.
    """
    if compute_dtype is None:
        compute_dtype = cp.float32
    is_fp64 = np.dtype(compute_dtype) == np.dtype(np.float64)
    elem_dt = cp.float64 if is_fp64 else cp.float32
    bs = _to_cupy_array(beam_sinb, dtype=elem_dt)
    bc = _to_cupy_array(beam_cosb, dtype=elem_dt)
    sa = _to_cupy_array(sin_da, dtype=elem_dt)
    ca = _to_cupy_array(cos_da, dtype=elem_dt)
    sb0 = _to_cupy_array(sinb0, dtype=elem_dt)
    cb0 = _to_cupy_array(cosb0, dtype=elem_dt)
    cgt = _to_cupy_array(cos_gamma_tx, dtype=elem_dt)
    bs, bc, sa, ca, sb0, cb0, cgt = cp.broadcast_arrays(bs, bc, sa, ca, sb0, cb0, cgt)
    lut_is_fp16 = context.d_gain_lut.dtype == cp.float16
    kernel = _get_custom_2d_trig_to_gain_kernel(
        mode=context.grid_mode,
        lut_is_fp16=lut_is_fp16,
        compute_is_fp64=is_fp64,
    )
    return kernel(
        bs, bc, sa, ca, sb0, cb0, cgt,
        context.d_gain_lut,
        cp.float32(context.axis0_min_deg),
        cp.float32(context.axis0_range_deg),
        cp.float32(1.0 / context.axis0_step_deg),
        np.int32(context.axis0_n),
        np.int32(1 if context.axis0_wraps else 0),
        cp.float32(context.axis1_min_deg),
        cp.float32(context.axis1_range_deg),
        cp.float32(1.0 / context.axis1_step_deg),
        np.int32(context.axis1_n),
        np.int32(1 if context.axis1_wraps else 0),
        elem_dt(float(inv_gmax_lin)),
    )


def _evaluate_custom_2d_from_body_frame_to_linear(
    context: GpuCustomPattern2DContext,
    x_body: Any,
    y_body: Any,
    z_body: Any,
    inv_gmax_lin: float,
    *,
    compute_dtype: Any = None,
) -> Any:
    """Fused body-frame → pattern-eval-to-linear in **one kernel launch**.

    Preferred hot-path entry point.  Takes the beam body-frame unit
    vector components the upstream trig already has
    (``x_body = beam_cosb * sin_da``,
    ``y_body = cosb0 * beam_sinb - sinb0 * beam_cosb * cos_da``,
    ``z_body = cos_gamma_tx``) and produces the relative linear gain
    in one ElementwiseKernel launch — no intermediate ``(az, el)``
    or ``(θ, φ)`` tensors, no per-axis conversion kernels.

    Dispatches to the az_el or theta_phi kernel variant based on
    ``context.grid_mode``, to fp32 or fp64 compute variant based on
    the caller's ``compute_dtype`` (pass ``cp.float64`` for the
    ``float64`` or ``float64/float32`` precision profiles), and to
    the fp16 or fp32 LUT variant based on
    ``context.d_gain_lut.dtype``.
    """
    if compute_dtype is None:
        compute_dtype = cp.float32
    is_fp64 = np.dtype(compute_dtype) == np.dtype(np.float64)
    elem_dt = cp.float64 if is_fp64 else cp.float32
    xb = _to_cupy_array(x_body, dtype=elem_dt)
    yb = _to_cupy_array(y_body, dtype=elem_dt)
    zb = _to_cupy_array(z_body, dtype=elem_dt)
    xb, yb, zb = cp.broadcast_arrays(xb, yb, zb)
    lut_is_fp16 = context.d_gain_lut.dtype == cp.float16
    kernel = _get_custom_2d_body_kernel(
        mode=context.grid_mode,
        lut_is_fp16=lut_is_fp16,
        compute_is_fp64=is_fp64,
    )
    return kernel(
        xb, yb, zb,
        context.d_gain_lut,
        cp.float32(context.axis0_min_deg),
        cp.float32(context.axis0_range_deg),
        cp.float32(1.0 / context.axis0_step_deg),
        np.int32(context.axis0_n),
        np.int32(1 if context.axis0_wraps else 0),
        cp.float32(context.axis1_min_deg),
        cp.float32(context.axis1_range_deg),
        cp.float32(1.0 / context.axis1_step_deg),
        np.int32(context.axis1_n),
        np.int32(1 if context.axis1_wraps else 0),
        elem_dt(float(inv_gmax_lin)),
    )


def _evaluate_custom_2d_from_azel_to_linear(
    context: GpuCustomPattern2DContext,
    az_deg: Any,
    el_deg: Any,
    inv_gmax_lin: float,
) -> Any:
    """Custom-2D evaluation with ``(az, el)`` already in hand.

    Preferred hot-path entry point for az_el-authored patterns.  The
    beam body-frame trig already produces the components needed to
    compute ``(az, el)`` directly (``az = atan2(x_body, z_body)``,
    ``el = asin(y_body)``), so callers can skip the ``(θ, φ)``
    intermediate plus the on-GPU conversion kernel entirely.

    Architecture note: this function is the "geometry owns the
    coordinate system" entry point.  Upstream call sites that know
    they're feeding an az_el-authored pattern should compute
    ``(az, el)`` directly from ``cos_bi``, ``sin_bi``, ``cos_bo``,
    ``sin_bo``, ``cos_da``, ``sin_da`` rather than computing
    ``(θ, φ)`` and converting.  Saves one kernel launch + one
    intermediate allocation + avoids the extra trig pass.

    For theta_phi-authored patterns this helper raises — callers
    should use :func:`_evaluate_custom_2d_from_theta_phi_to_linear`
    with the ``(θ, φ)`` they already have.
    """
    if context.grid_mode != "az_el":
        raise ValueError(
            "_evaluate_custom_2d_from_azel_to_linear requires "
            f"grid_mode='az_el'; got {context.grid_mode!r}. Use "
            "_evaluate_custom_2d_from_theta_phi_to_linear for "
            "theta_phi-authored patterns."
        )
    az = _to_cupy_array(az_deg, dtype=cp.float32)
    el = _to_cupy_array(el_deg, dtype=cp.float32)
    return _evaluate_custom_2d_pattern_cp_to_linear(
        context, az, el, inv_gmax_lin=inv_gmax_lin,
    )


def _evaluate_custom_1d_pattern_cp(
    context: GpuCustomPattern1DContext,
    theta_deg: Any,
    phi_deg: Any | None = None,
) -> Any:
    """Evaluate a user-supplied 1-D custom pattern on GPU via regular LUT.

    Reuses the same ``s1528_lut_1d_interp`` ElementwiseKernel as the
    S.1528 1-D path — the kernel is pattern-agnostic (linear-in-dB
    interpolation on a regular grid). ``phi_deg`` is accepted for
    call-site symmetry but ignored (axisymmetric pattern).

    Returns absolute dBi, matching the semantics of
    :func:`scepter.custom_antenna.evaluate_pattern_1d` (relative-mode
    patterns have the peak shift baked into the device LUT at build
    time, so callers see one uniform basis regardless of how the
    source file was normalised).
    """
    del phi_deg
    theta = _to_cupy_array(theta_deg, dtype=cp.float32)
    kernel = (
        _get_s1528_lut_1d_interp_fp16_kernel()
        if context.d_gain_lut.dtype == cp.float16
        else _get_s1528_lut_1d_interp_kernel()
    )
    return kernel(
        theta,
        context.d_gain_lut,
        cp.float32(1.0 / context.gain_lut_step_deg),
        cp.float32(context.gain_lut_max_deg),
        np.int32(context.gain_lut_n),
    )


def _evaluate_custom_1d_pattern_cp_to_linear(
    context: GpuCustomPattern1DContext,
    theta_deg: Any,
    inv_gmax_lin: float,
) -> Any:
    """Fused Custom-1D LUT evaluation returning relative linear gain.

    Reuses the same fused ``s1528_lut_1d_to_linear`` kernel as the S.1528
    1-D path — both are pattern-agnostic regular-grid LUTs in dB.
    Collapses ``LUT → dB → cp.power(10, g/10) * inv_gmax`` into a single
    ElementwiseKernel launch.  Mirrors the 2-D / M.2101 fused path.
    """
    theta = _to_cupy_array(theta_deg, dtype=cp.float32)
    kernel = (
        _get_s1528_lut_1d_to_linear_fp16_kernel()
        if context.d_gain_lut.dtype == cp.float16
        else _get_s1528_lut_1d_to_linear_kernel()
    )
    return kernel(
        theta,
        context.d_gain_lut,
        cp.float32(1.0 / context.gain_lut_step_deg),
        cp.float32(context.gain_lut_max_deg),
        np.int32(context.gain_lut_n),
        cp.float32(float(inv_gmax_lin)),
    )


# ---------------------------------------------------------------------------
# Stage-9 audit — axisymmetry assumptions across every ``pattern_context``
# consumer in this module.
#
# The dispatcher below is the central entry point; every downstream kernel
# in ``gpu_accel.py`` that evaluates a transmit pattern funnels through it
# (directly, or via ``_evaluate_s1528_pattern_cp_lut_1d_to_linear`` /
# ``_evaluate_normalised_pattern_cp`` / ``_evaluate_m2101_pattern_cp_lut_to_linear``).
# Catalogue of every consumer, keyed on whether it assumes axisymmetry
# (θ-only), consumes full (α, β) / (θ, φ) geometry, or is pattern-free:
#
# +----------------------------------------------+---------+-----------------+
# | Consumer                                     | Handles | How             |
# |                                              | 2-D?    |                 |
# +----------------------------------------------+---------+-----------------+
# | ``_evaluate_s1528_pattern_cp``               | YES     | Dispatches on   |
# |   (this dispatcher)                          |         | ``is_2d`` +     |
# |                                              |         | ``phi_deg``.    |
# +----------------------------------------------+---------+-----------------+
# | ``_accumulate_ras_power_cp`` 3-D path        | YES     | ``is_2d``       |
# |   (non-boresight-avoidance)                  |         | branch computes |
# |                                              |         | φ from reused   |
# |                                              |         | fused-kernel    |
# |                                              |         | trig outputs    |
# |                                              |         | (sinb0/cosb0/   |
# |                                              |         | sin_da/cos_da). |
# +----------------------------------------------+---------+-----------------+
# | ``_accumulate_ras_power_cp`` 4-D path        | YES     | Same formula    |
# |   (boresight-avoidance)                      |         | on compacted    |
# |                                              |         | active-beam     |
# |                                              |         | trig.           |
# +----------------------------------------------+---------+-----------------+
# | ``_accumulate_uemr_power_cp``                | N/A     | Isotropic       |
# |                                              |         | (0 dBi         |
# |                                              |         | everywhere).   |
# +----------------------------------------------+---------+-----------------+
# | ``_accumulate_beamforming_collapsed_power_cp``| N/A    | No TX pattern — |
# |                                              |         | cos(θ)-envelope |
# |                                              |         | collapsed EIRP. |
# +----------------------------------------------+---------+-----------------+
# | ``_build_peak_pfd_k_lut_cp`` (1-D builder)   | NO      | Rejects         |
# |                                              |         | asymmetric at   |
# |                                              |         | entry; routes   |
# |                                              |         | to the 2-D /    |
# |                                              |         | asym builders.  |
# +----------------------------------------------+---------+-----------------+
# | ``_build_peak_pfd_k_lut_2d_cp`` (M.2101)     | YES     | Full (az, el)   |
# |                                              |         | K(α, β) sweep.  |
# +----------------------------------------------+---------+-----------------+
# | ``_build_peak_pfd_k_lut_asym_s1528_cp``      | YES     | 2-D (ψ, φ)      |
# |                                              |         | observation     |
# |                                              |         | sweep per β_i;  |
# |                                              |         | K is            |
# |                                              |         | α-invariant so  |
# |                                              |         | output is 1-D   |
# |                                              |         | K(β).           |
# +----------------------------------------------+---------+-----------------+
# | ``_lookup_peak_pfd_k_any_cp``                | YES     | Dispatches 1-D  |
# |                                              |         | vs 2-D lookup   |
# |                                              |         | on              |
# |                                              |         | ``lut_context.  |
# |                                              |         | is_2d``.        |
# +----------------------------------------------+---------+-----------------+
# | ``_compute_aggregate_surface_pfd_cap_cp``    | YES     | Three-way       |
# |                                              |         | dispatch:       |
# |                                              |         | M.2101 → 2-D    |
# |                                              |         | element LUT;    |
# |                                              |         | asymmetric      |
# |                                              |         | S.1528 → 2-D    |
# |                                              |         | (θ, φ) LUT with |
# |                                              |         | φ derived from  |
# |                                              |         | the same        |
# |                                              |         | spherical-      |
# |                                              |         | azimuth formula |
# |                                              |         | as the main     |
# |                                              |         | power path;     |
# |                                              |         | symmetric       |
# |                                              |         | S.1528 /        |
# |                                              |         | Rec 1.2 / iso → |
# |                                              |         | the 1-D         |
# |                                              |         | normalised path.|
# +----------------------------------------------+---------+-----------------+
#
# Naming convention reminder: the *context* flag is
# ``GpuS1528PatternContext.is_2d`` (asymmetric Rec 1.4), the *LUT-context*
# flag is ``GpuPeakPfdLutContext.is_2d`` (2-D K(α, β)). They are distinct —
# the first is set whenever ``lt_m != lr_m``, the second is set only for
# M.2101 because S.1528 Rec 1.4's K(β) is α-invariant (aperture rotates
# with the beam; see ``_build_peak_pfd_k_lut_asym_s1528_cp`` docstring).
# ---------------------------------------------------------------------------
#
# Stage-10 decision — how each consumer will absorb the Custom-1D /
# Custom-2D pattern contexts planned for Phase 4 (Stages 12-17) of the
# 30-stage custom-antenna plan. No code changes in this stage — it
# records the design decisions so Phase 4 work has a single source of
# truth.
#
# Two new context types are planned:
#   * ``GpuCustomPattern1DContext`` — user-supplied LUT ``G(γ)``,
#     axisymmetric. Feeds the same θ-only path that S.1528 Rec 1.2 /
#     symmetric Rec 1.4 / RA.1631 use today.
#   * ``GpuCustomPattern2DContext`` — user-supplied LUT in either
#     ``(az, el)`` relative to boresight (``grid_mode="az_el"``) or
#     ``(θ, φ)`` around boresight (``grid_mode="theta_phi"``). The
#     schema stores boresight-relative angles either way, so the
#     aperture rotates with the beam — *same* aperture-rotates-with-
#     beam property as asymmetric S.1528, NOT the body-frame-fixed
#     element pattern of M.2101.
#
# Per-consumer decision (status refers to the Custom-2D rollout only;
# Custom-1D uniformly lands in the existing 1-D paths):
#
# +----------------------------------------------+---------+-----------------+
# | Consumer                                     | Decision| Phase-4 work    |
# +----------------------------------------------+---------+-----------------+
# | ``_evaluate_s1528_pattern_cp`` (dispatcher)  | NEEDS   | Stage 13 will   |
# |                                              | UPGRADE | add a Custom-2D |
# |                                              |         | branch *or*     |
# |                                              |         | introduce a     |
# |                                              |         | separate        |
# |                                              |         | top-level       |
# |                                              |         | ``_evaluate_    |
# |                                              |         | transmit_       |
# |                                              |         | pattern_cp``    |
# |                                              |         | dispatcher that |
# |                                              |         | routes by       |
# |                                              |         | context type.   |
# |                                              |         | Leaning toward  |
# |                                              |         | the latter —    |
# |                                              |         | keeps S.1528    |
# |                                              |         | and custom      |
# |                                              |         | paths decoupled.|
# +----------------------------------------------+---------+-----------------+
# | ``_accumulate_ras_power_cp`` (3-D and 4-D)   | NEEDS   | Stage 15 — the  |
# |                                              | UPGRADE | θ/φ geometry    |
# |                                              |         | derivation in   |
# |                                              |         | the ``is_2d``   |
# |                                              |         | branches of     |
# |                                              |         | both paths is   |
# |                                              |         | pattern-        |
# |                                              |         | agnostic and    |
# |                                              |         | *reusable* for  |
# |                                              |         | Custom-2D. Only |
# |                                              |         | the pattern-    |
# |                                              |         | evaluator call  |
# |                                              |         | changes.        |
# +----------------------------------------------+---------+-----------------+
# | ``_accumulate_uemr_power_cp``                | STAYS   | Isotropic-only  |
# |                                              | 1-D     | by design.      |
# |                                              |         | Custom contexts |
# |                                              |         | are rejected at |
# |                                              |         | the scenario-   |
# |                                              |         | level validator |
# |                                              |         | (UEMR mode is   |
# |                                              |         | mutually        |
# |                                              |         | exclusive with  |
# |                                              |         | directive       |
# |                                              |         | patterns).      |
# +----------------------------------------------+---------+-----------------+
# | ``_accumulate_beamforming_collapsed_power_cp``| STAYS  | Collapsed OOBE  |
# |                                              | PATTERN-| uses a          |
# |                                              | FREE    | cos(θ)-envelope |
# |                                              |         | scalar — no     |
# |                                              |         | antenna context |
# |                                              |         | enters this     |
# |                                              |         | path.           |
# +----------------------------------------------+---------+-----------------+
# | ``_compute_aggregate_surface_pfd_cap_cp``    | NEEDS   | Stage 15.       |
# |                                              | UPGRADE | Geometry block  |
# |                                              |         | is reusable     |
# |                                              |         | (already        |
# |                                              |         | computes        |
# |                                              |         | (θ, φ) per      |
# |                                              |         | (candidate,     |
# |                                              |         | beam) pair for  |
# |                                              |         | asymmetric      |
# |                                              |         | S.1528 in       |
# |                                              |         | Stage 9b). Swap |
# |                                              |         | the pattern     |
# |                                              |         | evaluator for   |
# |                                              |         | Custom-2D.      |
# +----------------------------------------------+---------+-----------------+
# | ``_build_peak_pfd_k_lut_cp`` (axisymmetric)  | ALREADY | Accepts         |
# |                                              | HANDLES | Custom-1D via   |
# |                                              | 1-D     | ``_evaluate_    |
# |                                              |         | normalised_     |
# |                                              |         | pattern_cp``    |
# |                                              |         | isinstance      |
# |                                              |         | extension       |
# |                                              |         | (one-line add). |
# +----------------------------------------------+---------+-----------------+
# | ``_build_peak_pfd_k_lut_2d_cp`` (M.2101)     | STAYS   | M.2101-specific |
# |                                              | M.2101  | — Custom-2D     |
# |                                              | ONLY    | does *not*      |
# |                                              |         | reuse this      |
# |                                              |         | builder because |
# |                                              |         | Custom-2D's     |
# |                                              |         | asymmetry       |
# |                                              |         | rotates with    |
# |                                              |         | the beam,       |
# |                                              |         | whereas M.2101  |
# |                                              |         | is body-frame-  |
# |                                              |         | fixed. Their    |
# |                                              |         | K-LUT           |
# |                                              |         | dimensionality  |
# |                                              |         | differs for a   |
# |                                              |         | physical reason.|
# +----------------------------------------------+---------+-----------------+
# | ``_build_peak_pfd_k_lut_asym_s1528_cp`` +    | DONE    | Stage 17        |
# | ``_build_peak_pfd_k_lut_custom2d_cp``        | (both)  | shipped the     |
# |                                              |         | Custom-2D       |
# |                                              |         | sibling —       |
# |                                              |         | structurally    |
# |                                              |         | identical to    |
# |                                              |         | the asym-S.1528 |
# |                                              |         | builder, only   |
# |                                              |         | the pattern     |
# |                                              |         | evaluator       |
# |                                              |         | differs. Both   |
# |                                              |         | produce 1-D     |
# |                                              |         | K(β) output via |
# |                                              |         | a 2-D (ψ, φ)    |
# |                                              |         | sweep; K is     |
# |                                              |         | α-invariant     |
# |                                              |         | because the     |
# |                                              |         | aperture        |
# |                                              |         | rotates with    |
# |                                              |         | the beam in     |
# |                                              |         | both cases.     |
# +----------------------------------------------+---------+-----------------+
# | ``_lookup_peak_pfd_k_any_cp``                | ALREADY | Dispatches on   |
# |                                              | HANDLES | ``lut_context.  |
# |                                              | BOTH    | is_2d``. As     |
# |                                              |         | long as         |
# |                                              |         | Custom-1D /     |
# |                                              |         | Custom-2D       |
# |                                              |         | builders        |
# |                                              |         | produce a       |
# |                                              |         | ``GpuPeakPfd-   |
# |                                              |         | LutContext``    |
# |                                              |         | with the right  |
# |                                              |         | ``is_2d`` flag  |
# |                                              |         | (Custom-2D      |
# |                                              |         | produces 1-D    |
# |                                              |         | per above),     |
# |                                              |         | the runtime     |
# |                                              |         | lookup needs    |
# |                                              |         | no change.      |
# +----------------------------------------------+---------+-----------------+
#
# Net Phase-4 surface: four code touches (dispatcher, directive power
# kernel, aggregate cap, Custom-2D K-LUT builder) and one isinstance
# extension (1-D K-LUT builder's normalised-pattern evaluator). Every
# other consumer either stays as-is or inherits the Phase-4 changes
# transparently.
# ---------------------------------------------------------------------------


def _evaluate_s1528_pattern_cp(
    context: GpuS1528PatternContext | GpuS1528Rec12PatternContext | GpuIsotropicPatternContext,
    theta_deg: Any,
    phi_deg: Any | None = None,
) -> Any:
    """S.1528 pattern evaluation — dispatches to Rec 1.2 or Rec 1.4 based on context type."""
    if isinstance(context, GpuIsotropicPatternContext):
        return _evaluate_isotropic_pattern_cp(context, theta_deg, phi_deg=phi_deg)
    if isinstance(context, GpuS1528Rec12PatternContext):
        # Rec 1.2: use LUT if available, else direct piecewise kernel
        if context.d_gain_lut is not None:
            return _evaluate_s1528_pattern_cp_lut_1d(context, theta_deg)
        return _evaluate_s1528_rec12_pattern_cp(context, theta_deg)
    # Rec 1.4 asymmetric (lt_m != lr_m) depends on phi — the phi=None fast
    # path would collapse to the phi=0 slice and silently drop all
    # dependence on lt_m. Callers in the main power path thread phi via
    # the azimuth-around-boresight geometry (see `_accumulate_ras_power_cp`);
    # any other entry point that reaches here without phi is a bug.
    if getattr(context, "is_2d", False) and phi_deg is None:
        raise NotImplementedError(
            "Asymmetric S.1528 Rec 1.4 context (lt_m != lr_m) requires phi_deg; "
            "the phi=None fast path would silently collapse to the phi=0 slice."
        )
    # Rec 1.4 asymmetric with phi: use 2-D LUT in 'lut' mode, analytical otherwise.
    if getattr(context, "is_2d", False):
        if _pattern_eval_mode == "lut":
            return _evaluate_s1528_pattern_cp_lut_2d(context, theta_deg, phi_deg)
        return _evaluate_s1528_pattern_cp_analytical(context, theta_deg, phi_deg=phi_deg)
    # Rec 1.4 symmetric: LUT or analytical Bessel/Taylor
    if phi_deg is None and _pattern_eval_mode == "lut":
        return _evaluate_s1528_pattern_cp_lut_1d(context, theta_deg)
    return _evaluate_s1528_pattern_cp_analytical(context, theta_deg, phi_deg=phi_deg)


_atmosphere_lut_fused_kernel = None


def _get_atmosphere_lut_fused_kernel():
    """Fused kernel: elevation clamp + bin index + LUT gather + visibility mask.

    Replaces ~9 separate CuPy operations (clip, rint, astype, clip, gather,
    where) with a single element-wise CUDA launch.
    """
    global _atmosphere_lut_fused_kernel
    if _atmosphere_lut_fused_kernel is not None:
        return _atmosphere_lut_fused_kernel
    _atmosphere_lut_fused_kernel = cp.ElementwiseKernel(
        "float32 elev_deg, raw float32 lut, "
        "float32 elev_min, float32 elev_max, "
        "float32 inv_bin_deg, int32 n_bins",
        "float32 atm_lin",
        """
        if (elev_deg <= 0.0f) {
            atm_lin = 1.0f;
        } else {
            float e = elev_deg;
            if (e < elev_min) e = elev_min;
            if (e > elev_max) e = elev_max;
            int bin = __float2int_rn((e - elev_min) * inv_bin_deg);
            if (bin < 0) bin = 0;
            if (bin >= n_bins) bin = n_bins - 1;
            atm_lin = lut[bin];
        }
        """,
        "atmosphere_lut_fused",
    )
    return _atmosphere_lut_fused_kernel


def _lookup_atmosphere_lut_cp(
    context: GpuAtmosphereLutContext,
    elevation_deg: Any,
    *,
    altitude_km: float,
) -> Any:
    elev = _to_cupy_array(elevation_deg, dtype=cp.float32)

    alt_key = int(np.rint(np.float32(altitude_km) * np.float32(100.0)))
    try:
        alt_index = context.altitude_keys.index(alt_key)
    except ValueError as exc:
        raise ValueError(
            f"Atmosphere LUT was not prepared for altitude key {alt_key} "
            f"(altitude_km={altitude_km!r})."
        ) from exc

    lut = _to_cupy_array(context.d_attenuation_lut, dtype=cp.float32)[alt_index]
    kernel = _get_atmosphere_lut_fused_kernel()
    return kernel(
        elev,
        lut,
        cp.float32(context.elev_min_deg),
        cp.float32(context.elev_max_deg),
        cp.float32(1.0 / context.bin_deg),
        np.int32(int(lut.size)),
    )


def _pattern_peak_gain_linear(pattern_context: Any) -> float:
    """Return the linear peak gain of a supported transmit pattern context.

    For S.1528 this is ``10 ** (gm_db / 10)``; for S.1528 Rec 1.2 the same
    formula applies.  Raises ``TypeError`` for unsupported pattern types.
    """
    if isinstance(pattern_context, GpuS1528PatternContext):
        gm_db = float(pattern_context.gm_db) if pattern_context.gm_db is not None else 0.0
        return float(10.0 ** (gm_db / 10.0)) if gm_db != 0.0 else 1.0
    if isinstance(pattern_context, GpuS1528Rec12PatternContext):
        gm_db = float(pattern_context.gm_db)
        return float(10.0 ** (gm_db / 10.0)) if gm_db != 0.0 else 1.0
    if isinstance(pattern_context, GpuM2101PatternContext):
        g_emax_db = float(pattern_context.g_emax_db)
        n_elements = max(
            1, int(pattern_context.n_h) * int(pattern_context.n_v),
        )
        gm_db = g_emax_db + 10.0 * math.log10(float(n_elements))
        return float(10.0 ** (gm_db / 10.0))
    if isinstance(pattern_context, GpuIsotropicPatternContext):
        return 1.0
    if isinstance(
        pattern_context,
        (GpuCustomPattern1DContext, GpuCustomPattern2DContext),
    ):
        # Custom contexts store the authoritative peak verbatim from
        # the schema's ``peak_gain_dbi`` / ``peak_gain_source=explicit``
        # field — no peak re-computation, matching the schema doc's
        # "peak-gain semantics" rule (the LUT is allowed to sit below
        # the declared peak for ITU regulatory masks).
        return float(10.0 ** (float(pattern_context.peak_gain_dbi) / 10.0))
    raise TypeError(
        f"Unsupported transmit pattern for peak-gain lookup: {type(pattern_context).__name__}"
    )


def _evaluate_normalised_pattern_cp(
    pattern_context: Any,
    theta_deg_cp: Any,
    inv_gmax_lin: float,
) -> Any:
    """Evaluate ``p(θ) / p_max`` on GPU for a supported pattern context.

    Dispatches on the module-level ``_pattern_eval_mode`` so the LUT
    build path mirrors whatever the Review & Run "Pattern evaluation"
    setting selected for the main power kernel (``lut`` or ``analytical``).
    """
    use_lut = (_pattern_eval_mode == "lut")
    if isinstance(pattern_context, GpuS1528PatternContext):
        if use_lut:
            return _evaluate_s1528_pattern_cp_lut_1d_to_linear(
                pattern_context, theta_deg_cp, inv_gmax_lin=float(inv_gmax_lin),
            )
        gain_db_cp = _evaluate_s1528_pattern_cp_analytical(pattern_context, theta_deg_cp)
        lin_cp = cp.power(cp.float32(10.0), gain_db_cp.astype(cp.float32, copy=False) * cp.float32(0.1))
        return lin_cp * cp.float32(float(inv_gmax_lin))
    if isinstance(pattern_context, GpuS1528Rec12PatternContext):
        # Rec 1.2 also builds a 1-D regular-grid LUT (via
        # ``_ensure_s1528_gain_lut_1d`` which dispatches to the Rec 1.2
        # piecewise analytical evaluator at build time), so the same
        # fused ``LUT → dB → linear`` kernel can be reused here.
        return _evaluate_s1528_pattern_cp_lut_1d_to_linear(
            pattern_context, theta_deg_cp, inv_gmax_lin=float(inv_gmax_lin),
        )
    if isinstance(pattern_context, GpuIsotropicPatternContext):
        theta_cp = _to_cupy_array(theta_deg_cp, dtype=cp.float32)
        return cp.full(theta_cp.shape, cp.float32(float(inv_gmax_lin)), dtype=cp.float32)
    if isinstance(pattern_context, GpuCustomPattern1DContext):
        # Custom 1-D: same regular-grid LUT structure as Rec 1.2 / Rec 1.4
        # symmetric, so the same fused kernel applies.
        return _evaluate_custom_1d_pattern_cp_to_linear(
            pattern_context, theta_deg_cp, inv_gmax_lin=float(inv_gmax_lin),
        )
    if isinstance(pattern_context, GpuCustomPattern2DContext):
        raise NotImplementedError(
            "Custom 2-D pattern routed into the 1-D normalised evaluator — "
            "callers with a phi-aware geometry (aggregate surface-PFD cap, "
            "main power path) must take the Custom-2D branch explicitly. "
            "θ-only aggregate PFD with a 2-D custom pattern is not "
            "physically meaningful."
        )
    raise TypeError(
        f"Unsupported transmit pattern for normalised evaluation: {type(pattern_context).__name__}"
    )


def _build_peak_pfd_k_lut_cp(
    *,
    pattern_context: Any,
    orbit_radius_m: float,
    earth_radius_m: float,
    atmosphere_lut_context: GpuAtmosphereLutContext | None,
    target_alt_km: float,
    beta_step_deg: float = 0.01,
    beta_extra_margin_deg: float = 10.0,
    psi_step_deg: float = 0.005,
    beta_chunk: int = 256,
) -> tuple[Any, float, float, int, float]:
    """Build ``K(β)`` for one orbit shell and return it on device.

    Parameters
    ----------
    pattern_context : GpuS1528PatternContext or GpuS1528Rec12PatternContext
        Transmit pattern shared by every satellite in this shell. Must be a
        1-D axisymmetric pattern — ``GpuM2101PatternContext`` is rejected.
    orbit_radius_m : float
        Satellite orbit radius in metres (not altitude above Earth).
    earth_radius_m : float
        Effective Earth radius used for the sat→ground intersection.
    atmosphere_lut_context : GpuAtmosphereLutContext or None
        Atmosphere LUT to query at each ψ slice.  ``None`` disables the
        atmospheric term so the cap operates in free-space mode.
    target_alt_km : float
        Altitude of the ground candidate points used for atmospheric
        slant-path lookup.  Mirrors the ``target_alt_km`` argument on the
        hot power kernel so the cap and the emitted PFD cannot disagree.
    beta_step_deg, beta_extra_margin_deg : float
        β grid step (degrees) and how far past the visible horizon the grid
        extends to cover numerically-slightly-off-horizon beam pointings.
    psi_step_deg : float
        ψ sweep step.  Default 0.005° resolves any S.1528 main lobe that
        the current pipeline supports without excessive memory pressure.
    beta_chunk : int
        Number of β values processed per GPU launch.  Keeps the transient
        ``(chunk, n_psi)`` intermediate under a few tens of MB.

    Returns
    -------
    tuple
        ``(k_lut_cp, beta_step_deg, beta_max_deg, n_beta, psi_horizon_deg)``.
        ``k_lut_cp`` has shape ``(n_beta,)`` dtype float32 in units 1/m².
    """
    if isinstance(pattern_context, GpuM2101PatternContext):
        raise TypeError(
            "_build_peak_pfd_k_lut_cp expects an axisymmetric pattern; "
            "route M.2101 contexts through _build_peak_pfd_k_lut_2d_cp."
        )
    if isinstance(pattern_context, GpuS1528PatternContext) and pattern_context.is_2d:
        raise TypeError(
            "_build_peak_pfd_k_lut_cp expects an axisymmetric pattern; "
            "route asymmetric S.1528 Rec 1.4 contexts (lt_m != lr_m) "
            "through _build_peak_pfd_k_lut_asym_s1528_cp."
        )
    if isinstance(pattern_context, GpuCustomPattern2DContext):
        raise TypeError(
            "_build_peak_pfd_k_lut_cp expects an axisymmetric pattern; "
            "route Custom-2D pattern contexts through the dedicated "
            "Custom-2D builder (Stage 17)."
        )
    if not isinstance(
        pattern_context,
        (
            GpuS1528PatternContext,
            GpuS1528Rec12PatternContext,
            GpuIsotropicPatternContext,
            GpuCustomPattern1DContext,
        ),
    ):
        raise TypeError(
            "Surface-PFD cap LUT requires an S.1528 / S.1528 Rec 1.2 / "
            "isotropic / Custom-1D pattern context; "
            f"got {type(pattern_context).__name__}."
        )

    earth_r = float(earth_radius_m)
    r_orbit = float(orbit_radius_m)
    if not np.isfinite(r_orbit) or r_orbit <= earth_r:
        raise ValueError(
            f"orbit_radius_m ({r_orbit!r}) must be finite and greater than "
            f"earth_radius_m ({earth_r!r})."
        )
    if not np.isfinite(beta_step_deg) or beta_step_deg <= 0.0:
        raise ValueError("beta_step_deg must be positive.")
    if not np.isfinite(psi_step_deg) or psi_step_deg <= 0.0:
        raise ValueError("psi_step_deg must be positive.")

    sin_horizon = earth_r / r_orbit
    psi_horizon_rad = float(np.arcsin(sin_horizon))
    psi_horizon_deg = float(np.degrees(psi_horizon_rad))

    beta_max_deg = float(min(psi_horizon_deg + float(beta_extra_margin_deg), 89.99))
    n_beta = int(math.floor(beta_max_deg / float(beta_step_deg))) + 1
    beta_grid_host = (np.arange(n_beta, dtype=np.float32) * np.float32(beta_step_deg))
    beta_max_deg = float(beta_grid_host[-1])

    n_psi_half = int(math.floor(psi_horizon_deg / float(psi_step_deg)))
    n_psi = 2 * n_psi_half + 1
    if n_psi < 3:
        raise ValueError(
            f"ψ grid is too coarse: psi_horizon={psi_horizon_deg:.3f}° with step "
            f"{psi_step_deg!r}° only yields {n_psi} samples."
        )
    psi_grid_host = (np.arange(-n_psi_half, n_psi_half + 1, dtype=np.float32) * np.float32(psi_step_deg))

    four_pi = float(4.0 * np.pi)
    psi_deg_cp = cp.asarray(psi_grid_host, dtype=cp.float32)
    psi_rad_cp = psi_deg_cp * cp.float32(np.pi / 180.0)
    sin_psi_cp = cp.sin(psi_rad_cp)
    cos_psi_cp = cp.cos(psi_rad_cp)

    r_orbit_f32 = cp.float32(r_orbit)
    earth_r_f32 = cp.float32(earth_r)
    term_cp = r_orbit_f32 * cos_psi_cp
    disc_cp = term_cp * term_cp - cp.float32(r_orbit * r_orbit - earth_r * earth_r)
    disc_cp = cp.maximum(disc_cp, cp.float32(0.0))
    d_psi_cp = term_cp - cp.sqrt(disc_cp)
    # Guard against pathological ψ values right at the horizon where d → 0
    d_psi_cp = cp.maximum(d_psi_cp, cp.float32(1.0))

    if atmosphere_lut_context is not None:
        cos_e_ground_cp = cp.clip(
            cp.float32(r_orbit / earth_r) * cp.abs(sin_psi_cp),
            cp.float32(0.0), cp.float32(1.0),
        )
        e_ground_deg_cp = cp.arccos(cos_e_ground_cp) * cp.float32(180.0 / np.pi)
        e_ground_deg_cp = cp.maximum(
            e_ground_deg_cp, cp.float32(atmosphere_lut_context.elev_min_deg)
        )
        atm_psi_cp = _lookup_atmosphere_lut_cp(
            atmosphere_lut_context, e_ground_deg_cp, altitude_km=float(target_alt_km),
        ).astype(cp.float32, copy=False)
        # ``_lookup_atmosphere_lut_cp`` returns linear *transmission* ∈ (0, 1].
        # Clamp to [0, 1] so the forward PFD formula below cannot exceed the
        # free-space value due to LUT rounding.
        atm_psi_cp = cp.clip(atm_psi_cp, cp.float32(0.0), cp.float32(1.0))
    else:
        atm_psi_cp = cp.ones((n_psi,), dtype=cp.float32)

    # Forward physics: ``PFD = EIRP · p · atm / (4π · d²)`` — so the K
    # integrand **multiplies** by atmospheric transmission (≤ 1), it does
    # not divide by it.
    geom_factor_cp = atm_psi_cp / (cp.float32(four_pi) * d_psi_cp * d_psi_cp)

    gmax_lin = _pattern_peak_gain_linear(pattern_context)
    inv_gmax_lin = 1.0 / gmax_lin if gmax_lin > 0.0 else 1.0

    k_out_cp = cp.empty((n_beta,), dtype=cp.float32)
    beta_grid_cp = cp.asarray(beta_grid_host, dtype=cp.float32)

    chunk = max(1, int(beta_chunk))
    for chunk_start in range(0, n_beta, chunk):
        chunk_end = min(chunk_start + chunk, n_beta)
        betas_cp = beta_grid_cp[chunk_start:chunk_end]
        theta_off_cp = cp.abs(psi_deg_cp[None, :] - betas_cp[:, None])
        flat_theta_cp = theta_off_cp.reshape(-1)
        p_rel_flat_cp = _evaluate_normalised_pattern_cp(
            pattern_context, flat_theta_cp, inv_gmax_lin=inv_gmax_lin,
        )
        p_rel_cp = p_rel_flat_cp.reshape(theta_off_cp.shape)
        pfd_norm_cp = p_rel_cp * geom_factor_cp[None, :]
        k_out_cp[chunk_start:chunk_end] = cp.max(pfd_norm_cp, axis=1)

    return k_out_cp, float(beta_step_deg), float(beta_max_deg), int(n_beta), float(psi_horizon_deg)


def _build_peak_pfd_k_lut_2d_cp(
    *,
    pattern_context: "GpuM2101PatternContext",
    orbit_radius_m: float,
    earth_radius_m: float,
    atmosphere_lut_context: "GpuAtmosphereLutContext | None",
    target_alt_km: float,
    beta_step_deg: float = 0.5,
    alpha_step_deg: float = 2.0,
    alpha_min_deg: float = -180.0,
    alpha_max_deg: float = 180.0,
    beta_extra_margin_deg: float = 10.0,
    psi_step_deg: float = 0.5,
    phi_step_deg: float = 2.0,
    steer_chunk: int = 256,
) -> tuple[Any, float, float, int, float, float, float, int, float]:
    """Build a 2-D ``K(α, β)`` surface-PFD cap LUT for an M.2101 pattern.

    Unlike the S.1528 case, the M.2101 phased-array gain is not symmetric
    around the nadir axis, so ``K`` must be tabulated over the full beam
    steering direction ``(α, β)`` in the satellite body frame.  For each
    steering entry, the maximum PFD on Earth is computed by sweeping a
    2-D observation grid ``(α_o, β_o)`` over the visible disc and taking
    the worst-case value of

        p(α_o, β_o ; α_i, β_i) · atm(β_o) / (4π · d(β_o)²)

    where the pattern is evaluated with the existing M.2101 LUT/composite
    kernel so the cap matches the hot-path pattern exactly.

    Parameters
    ----------
    pattern_context : GpuM2101PatternContext
        The phased-array pattern context whose LUT is being built.
    orbit_radius_m, earth_radius_m : float
        Shell orbit radius and effective Earth radius in metres.
    atmosphere_lut_context : GpuAtmosphereLutContext or None
        Atmosphere LUT mirrored from the host run (``None`` → free space).
    target_alt_km : float
        Ground candidate altitude for atmosphere lookup.
    beta_step_deg, alpha_step_deg : float
        Steering-grid step sizes (degrees).  Defaults chosen to resolve a
        reasonable phased-array main lobe while keeping the transient GPU
        footprint small.
    alpha_min_deg, alpha_max_deg : float
        Inclusive azimuth range the LUT must cover.
    beta_extra_margin_deg : float
        How far past the visible horizon the ``β`` grid extends.
    psi_step_deg, phi_step_deg : float
        Observation-grid step sizes in the sat body frame.  Smaller values
        resolve narrower main lobes at the cost of more build time.
    steer_chunk : int
        Number of steering entries processed per kernel launch.  Bounds
        the ``(chunk, n_cand)`` intermediate tensor to a few tens of MB.

    Returns
    -------
    tuple
        ``(k_lut_cp, beta_step_deg, beta_max_deg, n_beta, psi_horizon_deg,
        alpha_step_deg, alpha_min_deg, n_alpha, alpha_max_actual_deg)``
        where ``k_lut_cp`` has shape ``(n_alpha, n_beta)`` and dtype
        float32 in units of 1/m².
    """
    if not isinstance(pattern_context, GpuM2101PatternContext):
        raise TypeError(
            "_build_peak_pfd_k_lut_2d_cp requires an M.2101 pattern context; "
            f"got {type(pattern_context).__name__}."
        )

    earth_r = float(earth_radius_m)
    r_orbit = float(orbit_radius_m)
    if not np.isfinite(r_orbit) or r_orbit <= earth_r:
        raise ValueError(
            f"orbit_radius_m ({r_orbit!r}) must be finite and greater than "
            f"earth_radius_m ({earth_r!r})."
        )
    if beta_step_deg <= 0.0 or alpha_step_deg <= 0.0:
        raise ValueError("beta_step_deg and alpha_step_deg must be positive.")
    if psi_step_deg <= 0.0 or phi_step_deg <= 0.0:
        raise ValueError("psi_step_deg and phi_step_deg must be positive.")

    sin_horizon = earth_r / r_orbit
    psi_horizon_rad = float(np.arcsin(sin_horizon))
    psi_horizon_deg = float(np.degrees(psi_horizon_rad))

    # --- Steering grid ----------------------------------------------------
    beta_max_deg = float(min(psi_horizon_deg + float(beta_extra_margin_deg), 89.99))
    n_beta = int(math.floor(beta_max_deg / float(beta_step_deg))) + 1
    beta_grid_host = (np.arange(n_beta, dtype=np.float32) * np.float32(beta_step_deg))
    beta_max_deg = float(beta_grid_host[-1])

    n_alpha = int(math.floor((float(alpha_max_deg) - float(alpha_min_deg)) / float(alpha_step_deg))) + 1
    alpha_grid_host = (
        np.arange(n_alpha, dtype=np.float32) * np.float32(alpha_step_deg)
        + np.float32(alpha_min_deg)
    )
    alpha_max_actual_deg = float(alpha_grid_host[-1])

    # --- Observation grid -------------------------------------------------
    # β_o sweeps the off-nadir angle; α_o sweeps azimuth around nadir.
    n_psi = int(math.floor(psi_horizon_deg / float(psi_step_deg))) + 1
    if n_psi < 2:
        raise ValueError(
            f"ψ grid too coarse: psi_horizon={psi_horizon_deg:.3f}° with step "
            f"{psi_step_deg!r}° only yields {n_psi} samples."
        )
    psi_grid_host = np.arange(n_psi, dtype=np.float32) * np.float32(psi_step_deg)

    # Full 360° azimuth sweep, wrap-around is implicit.
    n_phi = int(math.floor(360.0 / float(phi_step_deg)))
    if n_phi < 4:
        raise ValueError(
            f"φ grid too coarse: step {phi_step_deg!r}° only yields {n_phi} samples."
        )
    phi_grid_host = np.arange(n_phi, dtype=np.float32) * np.float32(phi_step_deg)

    n_cand = int(n_psi) * int(n_phi)

    # Build a flat observation (α_o, β_o) vector pair of length n_cand.
    # Layout: outer loop is ψ (β_o), inner loop is φ (α_o).  α_o is the
    # observation azimuth in the sat body frame; β_o is the off-nadir angle.
    psi_cp = cp.asarray(psi_grid_host, dtype=cp.float32)         # (n_psi,)
    phi_cp = cp.asarray(phi_grid_host, dtype=cp.float32)         # (n_phi,)
    psi_flat_cp = cp.broadcast_to(psi_cp[:, None], (n_psi, n_phi)).reshape(-1)
    phi_flat_cp = cp.broadcast_to(phi_cp[None, :], (n_psi, n_phi)).reshape(-1)

    # --- Per-candidate geometry (depends only on β_o) --------------------
    r_orbit_f32 = cp.float32(r_orbit)
    earth_r_f32 = cp.float32(earth_r)
    psi_rad_cp = psi_flat_cp * cp.float32(np.pi / 180.0)
    cos_psi_cp = cp.cos(psi_rad_cp)
    sin_psi_cp = cp.sin(psi_rad_cp)
    term_cp = r_orbit_f32 * cos_psi_cp
    disc_cp = term_cp * term_cp - cp.float32(r_orbit * r_orbit - earth_r * earth_r)
    disc_cp = cp.maximum(disc_cp, cp.float32(0.0))
    d_cp = term_cp - cp.sqrt(disc_cp)
    d_cp = cp.maximum(d_cp, cp.float32(1.0))

    if atmosphere_lut_context is not None:
        cos_e_ground_cp = cp.clip(
            cp.float32(r_orbit / earth_r) * cp.abs(sin_psi_cp),
            cp.float32(0.0), cp.float32(1.0),
        )
        e_ground_deg_cp = cp.arccos(cos_e_ground_cp) * cp.float32(180.0 / np.pi)
        e_ground_deg_cp = cp.maximum(
            e_ground_deg_cp, cp.float32(atmosphere_lut_context.elev_min_deg),
        )
        atm_cp = _lookup_atmosphere_lut_cp(
            atmosphere_lut_context, e_ground_deg_cp, altitude_km=float(target_alt_km),
        ).astype(cp.float32, copy=False)
        atm_cp = cp.clip(atm_cp, cp.float32(0.0), cp.float32(1.0))
    else:
        atm_cp = cp.ones((n_cand,), dtype=cp.float32)

    four_pi_f32 = cp.float32(4.0 * np.pi)
    geom_factor_cp = atm_cp / (four_pi_f32 * d_cp * d_cp)        # (n_cand,)

    # --- M.2101 peak gain ------------------------------------------------
    g_emax_db_val = float(pattern_context.g_emax_db)
    n_elements = int(
        max(1, int(pattern_context.n_h) * int(pattern_context.n_v))
    )
    gm_db_val = g_emax_db_val + 10.0 * math.log10(float(n_elements))
    gmax_lin = float(10.0 ** (gm_db_val / 10.0))
    inv_gmax_lin = float(1.0 / gmax_lin) if gmax_lin > 0.0 else 1.0

    # --- Steering-grid iteration ----------------------------------------
    n_steer = n_alpha * n_beta
    k_flat_cp = cp.empty((n_steer,), dtype=cp.float32)
    # Outer index → alpha, inner index → beta, matching the final shape
    # ``(n_alpha, n_beta)``.
    alpha_grid_cp = cp.asarray(alpha_grid_host, dtype=cp.float32)
    beta_grid_cp = cp.asarray(beta_grid_host, dtype=cp.float32)
    # Flatten steering: steer_idx = a * n_beta + b
    a_idx_cp = cp.arange(n_steer, dtype=cp.int32) // cp.int32(n_beta)
    b_idx_cp = cp.arange(n_steer, dtype=cp.int32) % cp.int32(n_beta)
    alpha_steer_all_cp = alpha_grid_cp[a_idx_cp]
    beta_steer_all_cp = beta_grid_cp[b_idx_cp]

    chunk = max(1, int(steer_chunk))
    for chunk_start in range(0, n_steer, chunk):
        chunk_end = min(chunk_start + chunk, n_steer)
        chunk_len = int(chunk_end - chunk_start)

        # Broadcast steering across candidates → (chunk_len, n_cand)
        alpha_i_2d = cp.broadcast_to(
            alpha_steer_all_cp[chunk_start:chunk_end, None], (chunk_len, n_cand),
        ).reshape(-1)
        beta_i_2d = cp.broadcast_to(
            beta_steer_all_cp[chunk_start:chunk_end, None], (chunk_len, n_cand),
        ).reshape(-1)
        # Broadcast observation across steerings
        alpha_o_2d = cp.broadcast_to(
            phi_flat_cp[None, :], (chunk_len, n_cand),
        ).reshape(-1)
        beta_o_2d = cp.broadcast_to(
            psi_flat_cp[None, :], (chunk_len, n_cand),
        ).reshape(-1)

        # Evaluate the M.2101 pattern → linear gain / peak.  We reuse the
        # fused LUT-to-linear kernel when available so this path matches
        # what the hot power kernel evaluates.
        _ensure_m2101_element_lut_2d(pattern_context)
        p_rel_flat_cp = _evaluate_m2101_pattern_cp_lut_to_linear(
            pattern_context,
            alpha_o_2d, beta_o_2d,
            alpha_i_2d, beta_i_2d,
            inv_gmax_lin=inv_gmax_lin,
        )
        p_rel_chunk = p_rel_flat_cp.reshape((chunk_len, n_cand))

        # K = max over candidates of (p_rel * geom_factor)
        pfd_norm_chunk = p_rel_chunk * geom_factor_cp[None, :]
        k_flat_cp[chunk_start:chunk_end] = cp.max(pfd_norm_chunk, axis=1)

    k_lut_2d_cp = k_flat_cp.reshape((n_alpha, n_beta))
    return (
        k_lut_2d_cp,
        float(beta_step_deg),
        float(beta_max_deg),
        int(n_beta),
        float(psi_horizon_deg),
        float(alpha_step_deg),
        float(alpha_min_deg),
        int(n_alpha),
        float(alpha_max_actual_deg),
    )


def _build_peak_pfd_k_lut_asym_s1528_cp(
    *,
    pattern_context: "GpuS1528PatternContext",
    orbit_radius_m: float,
    earth_radius_m: float,
    atmosphere_lut_context: "GpuAtmosphereLutContext | None",
    target_alt_km: float,
    beta_step_deg: float = 0.01,
    beta_extra_margin_deg: float = 10.0,
    psi_step_deg: float = 0.005,
    phi_step_deg: float = 2.0,
    beta_chunk: int = 64,
) -> tuple[Any, float, float, int, float]:
    """Build ``K(β)`` for an asymmetric S.1528 Rec 1.4 pattern.

    Produces a 1-D LUT with the same shape and semantics as the
    axisymmetric 1-D builder. The asymmetric pattern has the elegant
    property that the on-surface peak PFD is α-invariant: the aperture
    axes rotate with the beam, so sweeping observation over the full
    360° around nadir gives the same max for any steering azimuth.

    Unlike the axisymmetric 1-D builder, this function sweeps a 2-D
    observation grid ``(ψ, φ)`` — because the asymmetric pattern gain
    depends on both the off-boresight angle ``θ`` AND the azimuth
    around boresight, a 1-D ``|ψ − β|`` sweep would miss the true max
    whenever the main-lobe peak sits at a non-symmetric φ.

    With ``α_i = 0`` (WLOG by α-invariance), per steering ``β_i`` the
    observation direction is ``(α_o=φ, β_o=ψ)``; θ and φ (relative to
    boresight) are derived via standard spherical geometry. The max
    over observation candidates gives ``K(β_i)``.
    """
    if not (
        isinstance(pattern_context, GpuS1528PatternContext)
        and pattern_context.is_2d
    ):
        raise TypeError(
            "_build_peak_pfd_k_lut_asym_s1528_cp requires an asymmetric "
            "GpuS1528PatternContext (is_2d=True); got "
            f"{type(pattern_context).__name__}."
        )

    earth_r = float(earth_radius_m)
    r_orbit = float(orbit_radius_m)
    if not np.isfinite(r_orbit) or r_orbit <= earth_r:
        raise ValueError(
            f"orbit_radius_m ({r_orbit!r}) must be finite and greater than "
            f"earth_radius_m ({earth_r!r})."
        )
    if not np.isfinite(beta_step_deg) or beta_step_deg <= 0.0:
        raise ValueError("beta_step_deg must be positive.")
    if not np.isfinite(psi_step_deg) or psi_step_deg <= 0.0:
        raise ValueError("psi_step_deg must be positive.")
    if not np.isfinite(phi_step_deg) or phi_step_deg <= 0.0:
        raise ValueError("phi_step_deg must be positive.")

    sin_horizon = earth_r / r_orbit
    psi_horizon_rad = float(np.arcsin(sin_horizon))
    psi_horizon_deg = float(np.degrees(psi_horizon_rad))

    beta_max_deg = float(min(psi_horizon_deg + float(beta_extra_margin_deg), 89.99))
    n_beta = int(math.floor(beta_max_deg / float(beta_step_deg))) + 1
    beta_grid_host = np.arange(n_beta, dtype=np.float32) * np.float32(beta_step_deg)
    beta_max_deg = float(beta_grid_host[-1])

    # 2-D observation grid: ψ ∈ [0, psi_horizon], φ ∈ [0, 360).
    n_psi = int(math.floor(psi_horizon_deg / float(psi_step_deg))) + 1
    if n_psi < 2:
        raise ValueError(
            f"ψ grid too coarse: psi_horizon={psi_horizon_deg:.3f}° with step "
            f"{psi_step_deg!r}° only yields {n_psi} samples."
        )
    psi_grid_host = np.arange(n_psi, dtype=np.float32) * np.float32(psi_step_deg)
    n_phi = int(math.floor(360.0 / float(phi_step_deg)))
    if n_phi < 4:
        raise ValueError(
            f"φ grid too coarse: step {phi_step_deg!r}° only yields {n_phi} samples."
        )
    phi_grid_host = np.arange(n_phi, dtype=np.float32) * np.float32(phi_step_deg)
    n_cand = int(n_psi) * int(n_phi)

    psi_cp = cp.asarray(psi_grid_host, dtype=cp.float32)
    phi_cp = cp.asarray(phi_grid_host, dtype=cp.float32)
    psi_flat_cp = cp.broadcast_to(psi_cp[:, None], (n_psi, n_phi)).reshape(-1)
    phi_flat_cp = cp.broadcast_to(phi_cp[None, :], (n_psi, n_phi)).reshape(-1)

    # Per-candidate slant range + atmosphere (depends only on β_o = ψ).
    d2r = cp.float32(np.pi / 180.0)
    r2d = cp.float32(180.0 / np.pi)
    r_orbit_f32 = cp.float32(r_orbit)
    psi_rad_cp = psi_flat_cp * d2r
    cos_psi_cp = cp.cos(psi_rad_cp)
    sin_psi_cp = cp.sin(psi_rad_cp)
    term_cp = r_orbit_f32 * cos_psi_cp
    disc_cp = term_cp * term_cp - cp.float32(r_orbit * r_orbit - earth_r * earth_r)
    disc_cp = cp.maximum(disc_cp, cp.float32(0.0))
    d_cp = term_cp - cp.sqrt(disc_cp)
    d_cp = cp.maximum(d_cp, cp.float32(1.0))

    if atmosphere_lut_context is not None:
        cos_e_ground_cp = cp.clip(
            cp.float32(r_orbit / earth_r) * cp.abs(sin_psi_cp),
            cp.float32(0.0), cp.float32(1.0),
        )
        e_ground_deg_cp = cp.arccos(cos_e_ground_cp) * cp.float32(180.0 / np.pi)
        e_ground_deg_cp = cp.maximum(
            e_ground_deg_cp, cp.float32(atmosphere_lut_context.elev_min_deg),
        )
        atm_cp = _lookup_atmosphere_lut_cp(
            atmosphere_lut_context, e_ground_deg_cp, altitude_km=float(target_alt_km),
        ).astype(cp.float32, copy=False)
        atm_cp = cp.clip(atm_cp, cp.float32(0.0), cp.float32(1.0))
    else:
        atm_cp = cp.ones((n_cand,), dtype=cp.float32)

    four_pi_f32 = cp.float32(4.0 * np.pi)
    geom_factor_cp = atm_cp / (four_pi_f32 * d_cp * d_cp)           # (n_cand,)

    gmax_lin = _pattern_peak_gain_linear(pattern_context)
    inv_gmax_lin = cp.float32(1.0 / gmax_lin if gmax_lin > 0.0 else 1.0)

    # Observation trig (α_i = 0, so Δα = α_o itself).
    sin_bo_1d = sin_psi_cp                                          # (n_cand,)
    cos_bo_1d = cos_psi_cp
    delta_a_1d = phi_flat_cp * d2r                                  # α_i = 0
    cos_da_1d = cp.cos(delta_a_1d)
    sin_da_1d = cp.sin(delta_a_1d)

    beta_grid_cp = cp.asarray(beta_grid_host, dtype=cp.float32)
    k_out_cp = cp.empty((n_beta,), dtype=cp.float32)

    chunk = max(1, int(beta_chunk))
    for chunk_start in range(0, n_beta, chunk):
        chunk_end = min(chunk_start + chunk, n_beta)
        beta_i = beta_grid_cp[chunk_start:chunk_end, None] * d2r    # (chunk, 1)
        sin_bi = cp.sin(beta_i)
        cos_bi = cp.cos(beta_i)

        # θ, φ of observation relative to beam boresight.
        cos_theta = cos_bi * cos_bo_1d[None, :] * cos_da_1d[None, :] + sin_bi * sin_bo_1d[None, :]
        cos_theta = cp.clip(cos_theta, cp.float32(-1.0), cp.float32(1.0))
        theta_deg = cp.arccos(cos_theta) * r2d

        phi_rad = cp.arctan2(
            cos_bi * sin_bo_1d[None, :] - sin_bi * cos_bo_1d[None, :] * cos_da_1d[None, :],
            cos_bo_1d[None, :] * sin_da_1d[None, :],
        )
        phi_deg = phi_rad * r2d

        # Fused 2-D LUT + dB→linear + inv_gmax in one kernel.
        p_rel = _evaluate_s1528_pattern_cp_lut_2d_to_linear(
            pattern_context,
            theta_deg.ravel(), phi_deg.ravel(),
            inv_gmax_lin=float(inv_gmax_lin),
        ).reshape(theta_deg.shape)

        pfd_norm = p_rel * geom_factor_cp[None, :]
        k_out_cp[chunk_start:chunk_end] = cp.max(pfd_norm, axis=1)

    return k_out_cp, float(beta_step_deg), float(beta_max_deg), int(n_beta), float(psi_horizon_deg)


def _build_peak_pfd_k_lut_custom2d_cp(
    *,
    pattern_context: "GpuCustomPattern2DContext",
    orbit_radius_m: float,
    earth_radius_m: float,
    atmosphere_lut_context: "GpuAtmosphereLutContext | None",
    target_alt_km: float,
    beta_step_deg: float = 0.01,
    beta_extra_margin_deg: float = 10.0,
    psi_step_deg: float = 0.005,
    phi_step_deg: float = 2.0,
    beta_chunk: int = 64,
) -> tuple[Any, float, float, int, float]:
    """Build ``K(β)`` for a Custom-2D pattern — 1-D LUT output.

    Stage 17 of the 30-stage custom-antenna plan. *Design correction
    from the original plan* (see Stage-10 decision doc): Custom-2D
    patterns are authored in boresight-relative angles (either
    ``(az, el)`` with boresight at the origin or ``(θ, φ)`` around
    boresight), so the aperture rotates with the beam — just like
    asymmetric S.1528 Rec 1.4. That makes K α-invariant and a 1-D
    ``K(β)`` table correct and much cheaper than a 2-D ``K(α, β)``.
    Only M.2101's body-frame-fixed element pattern justifies a 2-D
    K-LUT.

    Structurally identical to :func:`_build_peak_pfd_k_lut_asym_s1528_cp`
    — same 2-D ``(ψ, φ)`` observation sweep per steering ``β_i``,
    same α_i=0 WLOG trick, same free-space-PFD integrand. Only the
    pattern evaluator differs: ``_evaluate_custom_2d_from_theta_phi``
    dispatches the user's chosen ``grid_mode`` (``theta_phi`` → direct;
    ``az_el`` → schema ``(θ, φ) → (az, el)`` conversion) so this
    builder stays grid-mode-agnostic.
    """
    if not isinstance(pattern_context, GpuCustomPattern2DContext):
        raise TypeError(
            "_build_peak_pfd_k_lut_custom2d_cp requires a "
            "GpuCustomPattern2DContext; "
            f"got {type(pattern_context).__name__}."
        )

    earth_r = float(earth_radius_m)
    r_orbit = float(orbit_radius_m)
    if not np.isfinite(r_orbit) or r_orbit <= earth_r:
        raise ValueError(
            f"orbit_radius_m ({r_orbit!r}) must be finite and greater than "
            f"earth_radius_m ({earth_r!r})."
        )
    if not np.isfinite(beta_step_deg) or beta_step_deg <= 0.0:
        raise ValueError("beta_step_deg must be positive.")
    if not np.isfinite(psi_step_deg) or psi_step_deg <= 0.0:
        raise ValueError("psi_step_deg must be positive.")
    if not np.isfinite(phi_step_deg) or phi_step_deg <= 0.0:
        raise ValueError("phi_step_deg must be positive.")

    sin_horizon = earth_r / r_orbit
    psi_horizon_rad = float(np.arcsin(sin_horizon))
    psi_horizon_deg = float(np.degrees(psi_horizon_rad))

    beta_max_deg = float(min(psi_horizon_deg + float(beta_extra_margin_deg), 89.99))
    n_beta = int(math.floor(beta_max_deg / float(beta_step_deg))) + 1
    beta_grid_host = np.arange(n_beta, dtype=np.float32) * np.float32(beta_step_deg)
    beta_max_deg = float(beta_grid_host[-1])

    n_psi = int(math.floor(psi_horizon_deg / float(psi_step_deg))) + 1
    if n_psi < 2:
        raise ValueError(
            f"ψ grid too coarse: psi_horizon={psi_horizon_deg:.3f}° with step "
            f"{psi_step_deg!r}° only yields {n_psi} samples."
        )
    psi_grid_host = np.arange(n_psi, dtype=np.float32) * np.float32(psi_step_deg)
    n_phi = int(math.floor(360.0 / float(phi_step_deg)))
    if n_phi < 4:
        raise ValueError(
            f"φ grid too coarse: step {phi_step_deg!r}° only yields {n_phi} samples."
        )
    phi_grid_host = np.arange(n_phi, dtype=np.float32) * np.float32(phi_step_deg)
    n_cand = int(n_psi) * int(n_phi)

    psi_cp = cp.asarray(psi_grid_host, dtype=cp.float32)
    phi_cp = cp.asarray(phi_grid_host, dtype=cp.float32)
    psi_flat_cp = cp.broadcast_to(psi_cp[:, None], (n_psi, n_phi)).reshape(-1)
    phi_flat_cp = cp.broadcast_to(phi_cp[None, :], (n_psi, n_phi)).reshape(-1)

    d2r = cp.float32(np.pi / 180.0)
    r2d = cp.float32(180.0 / np.pi)
    r_orbit_f32 = cp.float32(r_orbit)
    psi_rad_cp = psi_flat_cp * d2r
    cos_psi_cp = cp.cos(psi_rad_cp)
    sin_psi_cp = cp.sin(psi_rad_cp)
    term_cp = r_orbit_f32 * cos_psi_cp
    disc_cp = term_cp * term_cp - cp.float32(r_orbit * r_orbit - earth_r * earth_r)
    disc_cp = cp.maximum(disc_cp, cp.float32(0.0))
    d_cp = term_cp - cp.sqrt(disc_cp)
    d_cp = cp.maximum(d_cp, cp.float32(1.0))

    if atmosphere_lut_context is not None:
        cos_e_ground_cp = cp.clip(
            cp.float32(r_orbit / earth_r) * cp.abs(sin_psi_cp),
            cp.float32(0.0), cp.float32(1.0),
        )
        e_ground_deg_cp = cp.arccos(cos_e_ground_cp) * cp.float32(180.0 / np.pi)
        e_ground_deg_cp = cp.maximum(
            e_ground_deg_cp, cp.float32(atmosphere_lut_context.elev_min_deg),
        )
        atm_cp = _lookup_atmosphere_lut_cp(
            atmosphere_lut_context, e_ground_deg_cp, altitude_km=float(target_alt_km),
        ).astype(cp.float32, copy=False)
        atm_cp = cp.clip(atm_cp, cp.float32(0.0), cp.float32(1.0))
    else:
        atm_cp = cp.ones((n_cand,), dtype=cp.float32)

    four_pi_f32 = cp.float32(4.0 * np.pi)
    geom_factor_cp = atm_cp / (four_pi_f32 * d_cp * d_cp)

    gmax_lin = _pattern_peak_gain_linear(pattern_context)
    inv_gmax_lin = cp.float32(1.0 / gmax_lin if gmax_lin > 0.0 else 1.0)

    sin_bo_1d = sin_psi_cp
    cos_bo_1d = cos_psi_cp
    delta_a_1d = phi_flat_cp * d2r
    cos_da_1d = cp.cos(delta_a_1d)
    sin_da_1d = cp.sin(delta_a_1d)

    beta_grid_cp = cp.asarray(beta_grid_host, dtype=cp.float32)
    k_out_cp = cp.empty((n_beta,), dtype=cp.float32)

    chunk = max(1, int(beta_chunk))
    for chunk_start in range(0, n_beta, chunk):
        chunk_end = min(chunk_start + chunk, n_beta)
        beta_i = beta_grid_cp[chunk_start:chunk_end, None] * d2r
        sin_bi = cp.sin(beta_i)
        cos_bi = cp.cos(beta_i)

        cos_theta = cos_bi * cos_bo_1d[None, :] * cos_da_1d[None, :] + sin_bi * sin_bo_1d[None, :]
        cos_theta = cp.clip(cos_theta, cp.float32(-1.0), cp.float32(1.0))
        theta_deg = cp.arccos(cos_theta) * r2d

        phi_rad = cp.arctan2(
            cos_bi * sin_bo_1d[None, :] - sin_bi * cos_bo_1d[None, :] * cos_da_1d[None, :],
            cos_bo_1d[None, :] * sin_da_1d[None, :],
        )
        phi_deg = phi_rad * r2d

        # Fused Custom-2D LUT + dB→linear + inv_gmax in one kernel.
        p_rel = _evaluate_custom_2d_from_theta_phi_to_linear(
            pattern_context,
            theta_deg.ravel(), phi_deg.ravel(),
            inv_gmax_lin=float(inv_gmax_lin),
        ).reshape(theta_deg.shape)

        pfd_norm = p_rel * geom_factor_cp[None, :]
        k_out_cp[chunk_start:chunk_end] = cp.max(pfd_norm, axis=1)

    return k_out_cp, float(beta_step_deg), float(beta_max_deg), int(n_beta), float(psi_horizon_deg)


def _lookup_peak_pfd_k_cp(
    lut_context: GpuPeakPfdLutContext,
    beta_rad_cp: Any,
    shell_id_per_beam_cp: Any,
) -> Any:
    """Return K(β) in 1/m² for each beam.

    Parameters
    ----------
    beta_rad_cp : cupy.ndarray
        Per-beam off-nadir angle in radians. Can be any shape.
    shell_id_per_beam_cp : cupy.ndarray
        Per-beam orbit-shell index, matching ``beta_rad_cp.shape`` or
        broadcastable to it.  Caller is responsible for expanding
        ``d_shell_id_per_sat`` through the beam→satellite mapping.

    Returns
    -------
    cupy.ndarray
        K values in 1/m², dtype float32, same shape as ``beta_rad_cp``.
    """
    if lut_context.is_2d:
        raise TypeError(
            "_lookup_peak_pfd_k_cp is a 1-D helper; the supplied context "
            "carries a 2-D M.2101 LUT — use _lookup_peak_pfd_k_any_cp or "
            "_lookup_peak_pfd_k_2d_cp which also consume the beam α."
        )
    beta_deg_cp = cp.abs(beta_rad_cp).astype(cp.float32, copy=False) * cp.float32(180.0 / np.pi)
    inv_step = cp.float32(1.0 / lut_context.beta_step_deg)
    n_beta = int(lut_context.n_beta)
    beta_max_clip = cp.float32(lut_context.beta_max_deg)
    beta_clipped_cp = cp.minimum(beta_deg_cp, beta_max_clip)
    fidx_cp = beta_clipped_cp * inv_step
    idx0_cp = cp.floor(fidx_cp).astype(cp.int32, copy=False)
    idx0_cp = cp.clip(idx0_cp, 0, n_beta - 2)
    idx1_cp = idx0_cp + cp.int32(1)
    frac_cp = fidx_cp - idx0_cp.astype(cp.float32, copy=False)
    frac_cp = cp.clip(frac_cp, cp.float32(0.0), cp.float32(1.0))
    shell_idx_cp = shell_id_per_beam_cp.astype(cp.int32, copy=False)
    lut = lut_context.d_k_lut
    k0_cp = lut[shell_idx_cp, idx0_cp]
    k1_cp = lut[shell_idx_cp, idx1_cp]
    return k0_cp + frac_cp * (k1_cp - k0_cp)


def _lookup_peak_pfd_k_2d_cp(
    lut_context: GpuPeakPfdLutContext,
    alpha_rad_cp: Any,
    beta_rad_cp: Any,
    shell_id_per_beam_cp: Any,
) -> Any:
    """Return ``K(α, β)`` in 1/m² for each beam via a bilinear lookup.

    The 2-D LUT is indexed by ``shell`` on the outer axis and by
    ``(α, β)`` on the inner two axes (shape ``(n_shells, n_alpha,
    n_beta)``).  The α axis is wrapped to ``[alpha_min, alpha_min + 360)``
    so beams can pass arbitrary real-valued α without a host round trip.
    """
    if not lut_context.is_2d:
        raise TypeError(
            "_lookup_peak_pfd_k_2d_cp requires a 2-D LUT context; "
            "supplied context has is_2d=False."
        )
    deg_per_rad = cp.float32(180.0 / np.pi)
    alpha_deg_cp = alpha_rad_cp.astype(cp.float32, copy=False) * deg_per_rad
    beta_deg_cp = cp.abs(beta_rad_cp).astype(cp.float32, copy=False) * deg_per_rad

    # Wrap α into the LUT's range (centimetre fold at 360°).
    alpha_range = cp.float32(float(lut_context.alpha_step_deg) * float(lut_context.n_alpha - 1) + 1.0e-9)
    alpha_min = cp.float32(float(lut_context.alpha_min_deg))
    alpha_offset_cp = alpha_deg_cp - alpha_min
    alpha_wrapped_cp = cp.remainder(alpha_offset_cp, cp.float32(360.0))
    alpha_wrapped_cp = cp.minimum(alpha_wrapped_cp, alpha_range)

    inv_alpha_step = cp.float32(1.0 / float(lut_context.alpha_step_deg))
    inv_beta_step = cp.float32(1.0 / float(lut_context.beta_step_deg))
    n_alpha = int(lut_context.n_alpha)
    n_beta = int(lut_context.n_beta)
    beta_max_clip = cp.float32(float(lut_context.beta_max_deg))
    beta_clipped_cp = cp.minimum(beta_deg_cp, beta_max_clip)

    fa_cp = alpha_wrapped_cp * inv_alpha_step
    fb_cp = beta_clipped_cp * inv_beta_step

    ia0_cp = cp.floor(fa_cp).astype(cp.int32, copy=False)
    ib0_cp = cp.floor(fb_cp).astype(cp.int32, copy=False)
    ia0_cp = cp.clip(ia0_cp, 0, n_alpha - 2 if n_alpha >= 2 else 0)
    ib0_cp = cp.clip(ib0_cp, 0, n_beta - 2 if n_beta >= 2 else 0)
    ia1_cp = ia0_cp + cp.int32(1 if n_alpha >= 2 else 0)
    ib1_cp = ib0_cp + cp.int32(1 if n_beta >= 2 else 0)

    fa_cp = cp.clip(fa_cp - ia0_cp.astype(cp.float32, copy=False), cp.float32(0.0), cp.float32(1.0))
    fb_cp = cp.clip(fb_cp - ib0_cp.astype(cp.float32, copy=False), cp.float32(0.0), cp.float32(1.0))

    shell_idx_cp = shell_id_per_beam_cp.astype(cp.int32, copy=False)
    lut = lut_context.d_k_lut  # (n_shells, n_alpha, n_beta)
    k00 = lut[shell_idx_cp, ia0_cp, ib0_cp]
    k01 = lut[shell_idx_cp, ia0_cp, ib1_cp]
    k10 = lut[shell_idx_cp, ia1_cp, ib0_cp]
    k11 = lut[shell_idx_cp, ia1_cp, ib1_cp]
    one = cp.float32(1.0)
    return (
        k00 * (one - fa_cp) * (one - fb_cp)
        + k10 * fa_cp * (one - fb_cp)
        + k01 * (one - fa_cp) * fb_cp
        + k11 * fa_cp * fb_cp
    )


def _lookup_peak_pfd_k_any_cp(
    lut_context: GpuPeakPfdLutContext,
    alpha_rad_cp: Any,
    beta_rad_cp: Any,
    shell_id_per_beam_cp: Any,
) -> Any:
    """Unified K lookup that dispatches to the 1-D or 2-D helper.

    Callers pass both α and β for every beam; for 1-D LUTs the α is
    ignored (S.1528 is axisymmetric), and for 2-D M.2101 LUTs both
    coordinates are used for the bilinear interpolation.
    """
    if lut_context.is_2d:
        return _lookup_peak_pfd_k_2d_cp(
            lut_context, alpha_rad_cp, beta_rad_cp, shell_id_per_beam_cp,
        )
    return _lookup_peak_pfd_k_cp(lut_context, beta_rad_cp, shell_id_per_beam_cp)


def _compute_aggregate_surface_pfd_cap_cp(
    *,
    beam_alpha_cp: Any,
    beam_beta_cp: Any,
    beam_valid_cp: Any,
    eirp_peak_cp: Any,
    orbit_radius_per_sat_cp: Any,
    sat_axis_index: int,
    pattern_context: Any,
    atmosphere_lut_context: "GpuAtmosphereLutContext | None",
    target_alt_km: float,
    max_surface_pfd_lin: float,
    chunk_groups: int | None = None,
    chunk_memory_budget_bytes: int | None = None,
) -> tuple[Any, Any, dict[str, float]]:
    """Aggregate per-satellite surface-PFD cap.

    For every leading-axis group (``(t, sat)`` in the 3-D path, or
    ``(t, sky, sat)`` in the 4-D boresight-avoidance path), this helper
    computes the peak aggregate PFD on Earth by sampling a dense
    candidate set derived from the beam geometry and returns a
    ``cap_factor`` that bounds the sum of emitted EIRPs from all beams
    of the same satellite.

    Candidate set per group (for ``K`` beam slots):

    1. ``K`` beam footprint centres — the main-lobe peak of each beam.
    2. Nadir — the regime where a wide-pattern sidelobe dominates due
       to the shorter slant range (``h`` vs ``d_target``).
    3. ``K·(K−1)/2`` pairwise great-circle midpoints — captures
       constructive main-lobe overlap between close-by beams.
    4. ``K`` beam↔nadir midpoints — captures the transition regime
       between each beam's near-in sidelobe and the nadir contribution.

    Total: ``3·K + 1 + K·(K−1)/2`` candidates.  For a typical LEO
    satellite with ≤30 beams this is ≤500 candidates, evaluated on the
    GPU via batched matmul + pattern-LUT gather.

    Parameters
    ----------
    beam_alpha_cp, beam_beta_cp : cupy.ndarray
        Per-beam ``(α, β)`` in satellite-nadir frame (radians). Shape
        ``(*leading_shape, K)`` where ``leading_shape`` is ``(T, S)``
        for the 3-D path or ``(T, N_sky, S)`` for the 4-D path.
    beam_valid_cp : cupy.ndarray
        Boolean validity mask for each beam slot, same shape as
        ``beam_alpha_cp``.  Invalid slots are zeroed out of the
        aggregate sum but still contribute a (harmless) candidate
        direction — keeping the candidate count uniform per group.
    eirp_peak_cp : cupy.ndarray or scalar
        Per-beam peak EIRP (linear W).  Must be broadcastable to
        ``beam_alpha_cp``'s shape.  Invalid slots will be masked.
    orbit_radius_per_sat_cp : cupy.ndarray
        Orbit radii in metres, shape ``(S,)``, matched to the
        satellite axis of ``leading_shape``.
    sat_axis_index : int
        Position of the satellite axis within ``leading_shape``
        (``1`` for 3-D path, ``2`` for 4-D).
    pattern_context : GpuS1528PatternContext or GpuS1528Rec12PatternContext
        Transmit pattern used to evaluate the normalised gain at each
        candidate/beam pair via the already-resident pattern LUT.
        ``GpuM2101PatternContext`` is rejected upstream.
    atmosphere_lut_context : GpuAtmosphereLutContext or None
        Atmosphere LUT used to include/bypass atmospheric transmission
        in the candidate PFD, mirroring the hot power path.
    target_alt_km : float
        Ground candidate altitude passed to the atmosphere LUT.
    max_surface_pfd_lin : float
        Cap limit in linear W/m² (already converted from dBW/m²).
    chunk_groups : int, optional
        Number of groups processed per GPU launch.  Bounds the
        transient ``(chunk, n_cand, K)`` intermediate to a few tens of
        MB; 512 fits comfortably in the laptop budget.

    Returns
    -------
    cap_factor_cp : cupy.ndarray
        Per-group cap factor, dtype float32, shape ``leading_shape``.
    peak_pfd_cp : cupy.ndarray
        Per-group peak aggregate PFD on Earth (W/m²), same shape.
        Exposed for stats reporting / debugging.
    stats : dict
        ``{"n_capped": int, "cap_db_sum": float, "cap_db_max": float}``
        — aggregated over all leading-axis groups.
    """
    import math as _math

    _require_cupy()
    is_m2101 = isinstance(pattern_context, GpuM2101PatternContext)
    is_custom2d = isinstance(pattern_context, GpuCustomPattern2DContext)
    if not is_m2101 and not is_custom2d and not isinstance(
        pattern_context,
        (
            GpuS1528PatternContext,
            GpuS1528Rec12PatternContext,
            GpuCustomPattern1DContext,
        ),
    ):
        raise TypeError(
            "Aggregate surface-PFD cap requires an S.1528 / S.1528 Rec 1.2 / "
            "M.2101 / Custom-1D / Custom-2D pattern context; got "
            f"{type(pattern_context).__name__}."
        )

    leading_shape = tuple(int(x) for x in beam_alpha_cp.shape[:-1])
    if len(leading_shape) < 1:
        raise ValueError("beam_alpha_cp must have at least one leading axis.")
    if not (0 <= int(sat_axis_index) < len(leading_shape)):
        raise ValueError(
            f"sat_axis_index {sat_axis_index} is out of range for leading shape {leading_shape!r}."
        )
    n_beam_slots = int(beam_alpha_cp.shape[-1])
    n_groups = 1
    for dim in leading_shape:
        n_groups *= int(dim)

    if beam_beta_cp.shape != beam_alpha_cp.shape:
        raise ValueError("beam_alpha_cp and beam_beta_cp must share the same shape.")
    if beam_valid_cp.shape != beam_alpha_cp.shape:
        raise ValueError("beam_valid_cp must share the shape of beam_alpha_cp.")
    sat_count = int(leading_shape[int(sat_axis_index)])
    orbit_radius_cp = cp.asarray(orbit_radius_per_sat_cp, dtype=cp.float32).reshape(-1)
    if int(orbit_radius_cp.size) != sat_count:
        raise ValueError(
            f"orbit_radius_per_sat_cp size {int(orbit_radius_cp.size)} "
            f"does not match sat axis length {sat_count}."
        )

    if n_groups == 0 or n_beam_slots == 0:
        cap_factor_cp = cp.ones(leading_shape, dtype=cp.float32)
        peak_pfd_cp = cp.zeros(leading_shape, dtype=cp.float32)
        return cap_factor_cp, peak_pfd_cp, {
            "n_capped": 0,
            "cap_db_sum": 0.0,
            "cap_db_max": 0.0,
        }

    # Resolve the transient-tensor memory budget dynamically.  We size the
    # cap helper to a small fraction of *currently free* GPU memory so
    # this optimisation doesn't starve the main power path, while still
    # letting the helper process realistic batches in a single pass.
    # The caller can override via ``chunk_memory_budget_bytes``.
    if chunk_memory_budget_bytes is None:
        try:
            free_bytes, _total_bytes = cp.cuda.Device().mem_info
            budget_from_free = int(free_bytes * 0.25)
            chunk_memory_budget_bytes = int(
                max(64 * 1024 * 1024, min(1024 * 1024 * 1024, budget_from_free))
            )
        except Exception:
            chunk_memory_budget_bytes = 256 * 1024 * 1024

    earth_r_m = float(R_earth.to_value(u.m))
    four_pi = cp.float32(4.0 * _math.pi)

    # Flatten beams → (n_groups, K_alloc).  K_alloc is the upstream slot
    # capacity, which for realistic configurations (e.g. ``nbeam=100`` in
    # the WRC benchmark) can be much larger than the number of beams a
    # satellite actually radiates at any given timestep.  We compact to
    # the active-beam subset below so the O(K²) candidate machinery runs
    # on the smallest possible K.
    beam_alpha_flat = beam_alpha_cp.reshape(n_groups, n_beam_slots).astype(cp.float32, copy=False)
    beam_beta_flat = beam_beta_cp.reshape(n_groups, n_beam_slots).astype(cp.float32, copy=False)
    beam_valid_flat = beam_valid_cp.reshape(n_groups, n_beam_slots)
    eirp_broad = cp.broadcast_to(
        cp.asarray(eirp_peak_cp, dtype=cp.float32), leading_shape + (n_beam_slots,),
    )
    eirp_flat = eirp_broad.reshape(n_groups, n_beam_slots).astype(cp.float32, copy=False)
    eirp_masked_flat = cp.where(beam_valid_flat, eirp_flat, cp.float32(0.0))

    # --- Active-beam compaction ------------------------------------------
    # Stable sort by ``valid`` descending: valid (=1) first, invalid (=0)
    # last, preserving original order within each group.  Taking the first
    # ``max_active_k`` slots after sort gives a (n_groups, K_act) tensor
    # whose inactive trailing positions still have EIRP=0, so they
    # contribute nothing to the aggregate sum.
    per_group_valid_counts = cp.sum(beam_valid_flat.astype(cp.int32, copy=False), axis=1)
    max_active_k_host = int(cp.asnumpy(cp.max(per_group_valid_counts)).item())
    if max_active_k_host == 0:
        cap_factor_cp = cp.ones(leading_shape, dtype=cp.float32)
        peak_pfd_cp = cp.zeros(leading_shape, dtype=cp.float32)
        return cap_factor_cp, peak_pfd_cp, {
            "n_capped": 0,
            "cap_db_sum": 0.0,
            "cap_db_max": 0.0,
        }
    if max_active_k_host < n_beam_slots:
        # Sort valid beams first, stable.  ``cp.where`` gives 0 for valid
        # (sorts first) and 1 for invalid.
        sort_key = cp.where(
            beam_valid_flat, cp.int32(0), cp.int32(1)
        ).astype(cp.int32, copy=False)
        perm = cp.argsort(sort_key, axis=1, kind="stable")
        top_perm = perm[:, :max_active_k_host]
        row_idx = cp.arange(n_groups, dtype=cp.int32)[:, None]
        beam_alpha_c = beam_alpha_flat[row_idx, top_perm]
        beam_beta_c = beam_beta_flat[row_idx, top_perm]
        eirp_c = eirp_masked_flat[row_idx, top_perm]
    else:
        beam_alpha_c = beam_alpha_flat
        beam_beta_c = beam_beta_flat
        eirp_c = eirp_masked_flat
    K_act = max_active_k_host

    # Broadcast per-sat orbit radius → (leading_shape,) → (n_groups,)
    broadcast_target = tuple(
        int(dim) if idx == int(sat_axis_index) else 1
        for idx, dim in enumerate(leading_shape)
    )
    orbit_reshaped_cp = orbit_radius_cp.reshape(broadcast_target)
    orbit_flat = cp.broadcast_to(orbit_reshaped_cp, leading_shape).reshape(n_groups).astype(
        cp.float32, copy=False,
    )

    # Unit vectors per compacted beam slot in sat frame
    sin_beta_c = cp.sin(beam_beta_c)
    cos_beta_c = cp.cos(beam_beta_c)
    sin_alpha_c = cp.sin(beam_alpha_c)
    cos_alpha_c = cp.cos(beam_alpha_c)
    v_beams = cp.stack(
        [
            sin_beta_c * cos_alpha_c,
            sin_beta_c * sin_alpha_c,
            cos_beta_c,
        ],
        axis=-1,
    )  # (n_groups, K_act, 3)

    # Host-side: candidate enumeration constants (based on compacted K_act).
    # For large ``K_act`` the ``K·(K-1)/2`` pair-midpoint term dominates
    # the transient memory footprint and scales as ``O(K³)`` in compute.
    # Above a heuristic cutoff we drop pair midpoints and keep only
    # footprints + nadir + beam↔nadir midpoints.  This is exact for
    # constellations whose beams do not have overlapping main lobes
    # (the regime in which pair midpoints would otherwise matter): when
    # every pair of beams is more than ~3 beamwidths apart, the pair
    # midpoint sits in both beams' sidelobe region and cannot produce a
    # PFD higher than either beam's own footprint candidate.  For small
    # ``K_act`` the full set is kept for maximum physical accuracy.
    _PAIR_MIDPOINT_K_ACT_CUTOFF = 32
    include_pair_midpoints = K_act <= _PAIR_MIDPOINT_K_ACT_CUTOFF
    n_pair = (K_act * (K_act - 1)) // 2 if include_pair_midpoints else 0
    n_cand_total = K_act + 1 + n_pair + K_act
    nadir_vec = cp.asarray([0.0, 0.0, 1.0], dtype=cp.float32)

    gmax_lin = _pattern_peak_gain_linear(pattern_context)
    inv_gmax_lin = 1.0 / gmax_lin if gmax_lin > 0.0 else 1.0
    max_pfd_lin_cp = cp.float32(max_surface_pfd_lin)

    # Build candidate directions for the WHOLE n_groups in a single pass
    # (no Python loop).  Memory footprint: (n_groups, n_cand_total, K_act)
    # float32 for cos_theta/theta_deg/p_rel ≈
    # ``n_groups · n_cand · K_act · 4 B``.  For small-to-medium batches
    # this fits in the transient budget (≤ 1 GB).  For larger n_groups
    # (4-D boresight with many sky cells × visible sats) we chunk over
    # the n_groups axis: each group is independent, so chunking does
    # not change the physics — only the transient memory footprint.
    est_bytes_per_group = int(n_cand_total) * int(K_act) * 4 * 3
    est_bytes_per_group = max(est_bytes_per_group, 1)
    total_bytes = int(n_groups) * est_bytes_per_group
    if total_bytes > int(chunk_memory_budget_bytes):
        chunk_size = max(1, int(chunk_memory_budget_bytes) // est_bytes_per_group)
    else:
        chunk_size = int(n_groups)

    if include_pair_midpoints and n_pair > 0:
        i_pair_host, j_pair_host = np.triu_indices(K_act, k=1)
        i_pair_cp = cp.asarray(i_pair_host, dtype=cp.int32)
        j_pair_cp = cp.asarray(j_pair_host, dtype=cp.int32)
    else:
        i_pair_cp = None
        j_pair_cp = None

    peak_pfd_flat_cp = cp.zeros((n_groups,), dtype=cp.float32)

    def _process_slice(start: int, stop: int) -> None:
        chunk = int(stop) - int(start)
        if chunk <= 0:
            return
        v_beams_s = v_beams[start:stop]
        eirp_c_s = eirp_c[start:stop]
        orbit_flat_s = orbit_flat[start:stop]
        beam_alpha_c_s = beam_alpha_c[start:stop]
        beam_beta_c_s = beam_beta_c[start:stop]
        sin_beta_c_s = sin_beta_c[start:stop]
        cos_beta_c_s = cos_beta_c[start:stop]

        # Nadir: (1, 1, 3) broadcast → (chunk, 1, 3)
        nadir_slice_s = cp.broadcast_to(nadir_vec[None, None, :], (chunk, 1, 3))
        # Pair midpoints for this chunk
        if include_pair_midpoints and n_pair > 0:
            v_i = v_beams_s[:, i_pair_cp, :]
            v_j = v_beams_s[:, j_pair_cp, :]
            pair_sum = v_i + v_j
            pair_norm = cp.linalg.norm(pair_sum, axis=-1, keepdims=True)
            pair_mid_s = pair_sum / cp.maximum(pair_norm, cp.float32(1.0e-30))
        else:
            pair_mid_s = cp.empty((chunk, 0, 3), dtype=cp.float32)
        # Beam↔nadir midpoints: (chunk, K_act, 3)
        bn_sum = v_beams_s + nadir_vec[None, None, :]
        bn_norm = cp.linalg.norm(bn_sum, axis=-1, keepdims=True)
        bn_mid_s = bn_sum / cp.maximum(bn_norm, cp.float32(1.0e-30))

        candidates_s = cp.concatenate(
            [v_beams_s, nadir_slice_s, pair_mid_s, bn_mid_s], axis=1,
        )  # (chunk, n_cand_total, 3)

        # ψ_c = arccos(v_c.z); use cos/sin directly to avoid an arccos
        cos_psi_c = cp.clip(candidates_s[:, :, 2], cp.float32(-1.0), cp.float32(1.0))
        sin_psi_c = cp.sqrt(
            cp.maximum(cp.float32(1.0) - cos_psi_c * cos_psi_c, cp.float32(0.0))
        )

        r_exp = orbit_flat_s[:, None]
        term = r_exp * cos_psi_c
        disc = term * term - (r_exp * r_exp - cp.float32(earth_r_m * earth_r_m))
        disc = cp.maximum(disc, cp.float32(0.0))
        d_c = term - cp.sqrt(disc)
        d_c = cp.maximum(d_c, cp.float32(1.0))

        if atmosphere_lut_context is not None:
            cos_e_ground = cp.clip(
                (r_exp / cp.float32(earth_r_m)) * cp.abs(sin_psi_c),
                cp.float32(0.0), cp.float32(1.0),
            )
            e_ground_deg = cp.arccos(cos_e_ground) * cp.float32(180.0 / np.pi)
            e_ground_deg = cp.maximum(
                e_ground_deg, cp.float32(atmosphere_lut_context.elev_min_deg)
            )
            atm_c = _lookup_atmosphere_lut_cp(
                atmosphere_lut_context, e_ground_deg,
                altitude_km=float(target_alt_km),
            ).astype(cp.float32, copy=False)
            atm_c = cp.clip(atm_c, cp.float32(0.0), cp.float32(1.0))
        else:
            atm_c = cp.ones_like(d_c)

        geom_factor_s = atm_c / (four_pi * d_c * d_c)

        if is_m2101:
            cand_cos_beta = cp.clip(candidates_s[..., 2], cp.float32(-1.0), cp.float32(1.0))
            cand_beta_rad = cp.arccos(cand_cos_beta)
            cand_alpha_rad = cp.arctan2(candidates_s[..., 1], candidates_s[..., 0])
            deg_per_rad = cp.float32(180.0 / np.pi)
            cand_az_deg = cand_alpha_rad * deg_per_rad
            cand_el_deg = cand_beta_rad * deg_per_rad
            beam_az_deg = beam_alpha_c_s * deg_per_rad
            beam_el_deg = beam_beta_c_s * deg_per_rad
            az_o_b = cp.broadcast_to(cand_az_deg[:, :, None], (chunk, n_cand_total, K_act))
            el_o_b = cp.broadcast_to(cand_el_deg[:, :, None], (chunk, n_cand_total, K_act))
            az_i_b = cp.broadcast_to(beam_az_deg[:, None, :], (chunk, n_cand_total, K_act))
            el_i_b = cp.broadcast_to(beam_el_deg[:, None, :], (chunk, n_cand_total, K_act))
            p_rel_flat = _evaluate_m2101_pattern_cp_lut_to_linear(
                pattern_context,
                az_o_b.reshape(-1), el_o_b.reshape(-1),
                az_i_b.reshape(-1), el_i_b.reshape(-1),
                inv_gmax_lin=float(inv_gmax_lin),
            )
            p_rel_s = p_rel_flat.reshape((chunk, n_cand_total, K_act))
        else:
            cos_theta = cp.matmul(candidates_s, v_beams_s.transpose(0, 2, 1))
            cos_theta = cp.clip(cos_theta, cp.float32(-1.0), cp.float32(1.0))
            theta_deg = cp.arccos(cos_theta) * cp.float32(180.0 / np.pi)

            if getattr(pattern_context, "is_2d", False):
                cand_cos_beta = cp.clip(candidates_s[..., 2], cp.float32(-1.0), cp.float32(1.0))
                cand_sin_beta = cp.sqrt(
                    cp.maximum(cp.float32(1.0) - cand_cos_beta * cand_cos_beta, cp.float32(0.0))
                )
                cand_alpha = cp.arctan2(candidates_s[..., 1], candidates_s[..., 0])
                delta_a = beam_alpha_c_s[:, None, :] - cand_alpha[:, :, None]
                cos_da = cp.cos(delta_a)
                sin_da = cp.sin(delta_a)
                phi_rad = cp.arctan2(
                    cos_beta_c_s[:, None, :] * cand_sin_beta[:, :, None]
                    - sin_beta_c_s[:, None, :] * cand_cos_beta[:, :, None] * cos_da,
                    cand_cos_beta[:, :, None] * sin_da,
                )
                phi_deg = phi_rad * cp.float32(180.0 / np.pi)
                p_rel_flat = _evaluate_s1528_pattern_cp_lut_2d_to_linear(
                    pattern_context,
                    theta_deg.reshape(-1), phi_deg.reshape(-1),
                    inv_gmax_lin=float(inv_gmax_lin),
                )
            elif is_custom2d:
                # Body-frame native routing (lever #1 extended to
                # aggregate-cap path).  Compute x_body / y_body / z_body
                # components of the candidate direction in the BEAM's
                # body frame, then hand them to the single-launch fused
                # kernel.  Eliminates arccos(cos_theta) for theta_deg,
                # the phi atan2 + rad→deg multiply, AND the separate
                # θ/φ → az/el conversion kernel that
                # ``_evaluate_custom_2d_from_theta_phi_to_linear`` would
                # otherwise invoke for az_el-authored Custom-2D
                # patterns.  Reuses the exact trig components the
                # analytical-S.1528 2-D branch above also computes,
                # so the only extra arithmetic per call is the two
                # body-frame formulas below.
                cand_cos_beta = cp.clip(candidates_s[..., 2], cp.float32(-1.0), cp.float32(1.0))
                cand_sin_beta = cp.sqrt(
                    cp.maximum(cp.float32(1.0) - cand_cos_beta * cand_cos_beta, cp.float32(0.0))
                )
                cand_alpha = cp.arctan2(candidates_s[..., 1], candidates_s[..., 0])
                delta_a = beam_alpha_c_s[:, None, :] - cand_alpha[:, :, None]
                cos_da = cp.cos(delta_a)
                sin_da = cp.sin(delta_a)
                # Body-frame unit-vector components of the candidate in
                # the beam's local frame (beam boresight along +Z):
                #   x_body = cand_cos_beta * sin_da
                #   y_body = cos_beta_c * cand_sin_beta
                #          - sin_beta_c * cand_cos_beta * cos_da
                #   z_body = cos_theta   (already computed via matmul)
                # Matches the body-frame derivation used in the 3-D /
                # 4-D power paths post-lever-2.
                x_body = cand_cos_beta[:, :, None] * sin_da
                y_body = (
                    cos_beta_c_s[:, None, :] * cand_sin_beta[:, :, None]
                    - sin_beta_c_s[:, None, :] * cand_cos_beta[:, :, None] * cos_da
                )
                z_body = cos_theta
                p_rel_flat = _evaluate_custom_2d_from_body_frame_to_linear(
                    pattern_context,
                    x_body.reshape(-1),
                    y_body.reshape(-1),
                    z_body.reshape(-1),
                    inv_gmax_lin=float(inv_gmax_lin),
                )
            else:
                p_rel_flat = _evaluate_normalised_pattern_cp(
                    pattern_context, theta_deg.reshape(-1), inv_gmax_lin=inv_gmax_lin,
                )
            p_rel_s = p_rel_flat.reshape(theta_deg.shape)

        # Aggregate sum across beam axis, then max across candidates
        pfd_per_beam = eirp_c_s[:, None, :] * p_rel_s * geom_factor_s[:, :, None]
        pfd_agg = cp.sum(pfd_per_beam, axis=-1)
        peak_pfd_s = cp.max(pfd_agg, axis=-1)
        peak_pfd_flat_cp[start:stop] = peak_pfd_s

    for _start in range(0, n_groups, chunk_size):
        _stop = min(_start + chunk_size, n_groups)
        _process_slice(_start, _stop)

    # Guard against NaN from groups with zero valid beams.  When
    # ``K_act > 0`` (because at least one group has active beams) but a
    # specific group has zero active beams, its compacted beam slots
    # contain NaN directions → candidate PFD evaluates to NaN → peak is
    # NaN.  Replace NaN peaks with 0 (no emission → no cap needed).
    peak_pfd_flat_cp = cp.where(
        cp.isnan(peak_pfd_flat_cp), cp.float32(0.0), peak_pfd_flat_cp,
    )
    peak_safe = cp.maximum(peak_pfd_flat_cp, cp.float32(1.0e-30))
    cap_factor_flat_cp = cp.minimum(
        cp.float32(1.0), max_pfd_lin_cp / peak_safe,
    )

    cap_factor_cp = cap_factor_flat_cp.reshape(leading_shape)
    peak_pfd_cp = peak_pfd_flat_cp.reshape(leading_shape)

    cap_mask_flat = cap_factor_flat_cp < cp.float32(1.0 - 1.0e-6)
    cap_db_flat = cp.where(
        cap_mask_flat,
        cp.float32(-10.0) * cp.log10(cp.maximum(cap_factor_flat_cp, cp.float32(1.0e-30))),
        cp.float32(0.0),
    )
    # Single D2H sync for all three stats scalars
    _stats_dev = cp.array([
        cp.count_nonzero(cap_mask_flat).astype(cp.float32),
        cp.sum(cap_db_flat),
        cp.max(cap_db_flat) if int(cap_db_flat.size) > 0 else cp.float32(0.0),
    ])
    _stats_host = _stats_dev.get()

    return cap_factor_cp, peak_pfd_cp, {
        "n_capped": int(_stats_host[0]),
        "cap_db_sum": float(_stats_host[1]),
        "cap_db_max": float(_stats_host[2]),
    }


def _coerce_step2_topo_tensor_cp(value: Any, *, name: str) -> Any:
    arr = _to_cupy_array(value, dtype=cp.float32)
    if arr.ndim == 4:
        if int(arr.shape[1]) != 1:
            raise ValueError(f"{name} second axis must be singleton when ndim=4; got {tuple(arr.shape)!r}.")
        arr = arr[:, 0, :, :]
    elif arr.ndim != 3:
        raise ValueError(f"{name} must have shape (T, 1, S, K) or (T, S, K); got {tuple(arr.shape)!r}.")
    return arr

def _coerce_per_satellite_heatmap_tensor_cp(value: Any, *, name: str) -> Any:
    arr = _to_cupy_array(value, dtype=cp.float32)
    if arr.ndim == 4:
        if int(arr.shape[1]) != 1:
            raise ValueError(
                f"{name} second axis must be singleton when ndim=4; got {tuple(arr.shape)!r}."
            )
        arr = arr[:, 0, :, :]
    elif arr.ndim == 2:
        arr = arr[:, :, None]
    elif arr.ndim != 3:
        raise ValueError(
            f"{name} must have shape (T, S), (T, 1, S, K), or (T, S, K); got {tuple(arr.shape)!r}."
        )
    return arr


_log10_masked_minmax_kernel = None


def _get_log10_masked_minmax_kernel():
    """Fused kernel: computes 10*log10(x) + offset for positive finite values,
    writing +inf (for min) and -inf (for max) for invalid elements.
    Replaces 4 separate CuPy calls (isfinite+gt, log10+where, 2×where)."""
    global _log10_masked_minmax_kernel
    if _log10_masked_minmax_kernel is not None:
        return _log10_masked_minmax_kernel
    _log10_masked_minmax_kernel = cp.ElementwiseKernel(
        "float32 x, float32 db_offset",
        "float32 dbw_for_min, float32 dbw_for_max",
        """
        if (isfinite(x) && x > 0.0f) {
            float dbw = log10f(x) * 10.0f + db_offset;
            dbw_for_min = dbw;
            dbw_for_max = dbw;
        } else {
            dbw_for_min = 1.0e30f;
            dbw_for_max = -1.0e30f;
        }
        """,
        "log10_masked_minmax",
    )
    return _log10_masked_minmax_kernel


def _positive_value_range_db_cp(
    value_linear: Any,
    *,
    db_offset_db: float = 0.0,
) -> tuple[float, float] | None:
    value_cp = _to_cupy_array(value_linear, dtype=cp.float32)
    flat = value_cp.reshape(-1)
    kernel = _get_log10_masked_minmax_kernel()
    dbw_for_min, dbw_for_max = kernel(flat, cp.float32(float(db_offset_db)))
    # Single D2H sync for both min and max
    extrema = cp.array([cp.min(dbw_for_min), cp.max(dbw_for_max)])
    extrema_host = extrema.get()
    min_val, max_val = float(extrema_host[0]), float(extrema_host[1])
    if min_val >= 1e29:
        return None
    # Clamp to -500 dB floor — values below this are physically meaningless
    # and would bloat dynamic histogram ranges (e.g. sliding-window averages
    # near zero can produce -3000 dB).
    min_val = max(min_val, -500.0)
    return min_val, max_val


def _positive_value_range_dbw_cp(
    value_w_per_mhz: Any,
    *,
    bw_mhz: float,
) -> tuple[float, float] | None:
    value_cp = _coerce_per_satellite_heatmap_tensor_cp(
        value_w_per_mhz,
        name="value_w_per_mhz",
    )
    return _positive_value_range_db_cp(
        value_cp,
        db_offset_db=(10.0 * math.log10(float(bw_mhz))),
    )


_log10_masked_dbw_kernel = None


def _get_log10_masked_dbw_kernel():
    """Fused kernel: computes 10*log10(x) + offset for valid elements, NaN otherwise."""
    global _log10_masked_dbw_kernel
    if _log10_masked_dbw_kernel is not None:
        return _log10_masked_dbw_kernel
    _log10_masked_dbw_kernel = cp.ElementwiseKernel(
        "float32 x, float32 db_offset",
        "float32 dbw",
        """
        if (isfinite(x) && x > 0.0f) {
            dbw = log10f(x) * 10.0f + db_offset;
        } else {
            dbw = nanf("");
        }
        """,
        "log10_masked_dbw",
    )
    return _log10_masked_dbw_kernel


_fused_db_minmax_kernel = None


def _get_fused_db_minmax_kernel():
    """Fused kernel: valid check + 10*log10(x) + offset + masked sentinels for min/max.

    Outputs three arrays in a single pass:
    - dbw: the dB value (NaN for invalid)
    - dbw_for_min: dB value for valid, +1e30 for invalid (min sentinel)
    - dbw_for_max: dB value for valid, -1e30 for invalid (max sentinel)
    """
    global _fused_db_minmax_kernel
    if _fused_db_minmax_kernel is not None:
        return _fused_db_minmax_kernel
    _fused_db_minmax_kernel = cp.ElementwiseKernel(
        "float32 x, float32 db_offset",
        "float32 dbw, float32 dbw_for_min, float32 dbw_for_max",
        """
        if (isfinite(x) && x > 0.0f) {
            float v = log10f(x) * 10.0f + db_offset;
            dbw = v;
            dbw_for_min = v;
            dbw_for_max = v;
        } else {
            dbw = nanf("");
            dbw_for_min = 1.0e30f;
            dbw_for_max = -1.0e30f;
        }
        """,
        "fused_db_minmax",
    )
    return _fused_db_minmax_kernel


_heatmap_2d_bin_kernel = None


def _get_heatmap_2d_bin_kernel():
    """Fused 2D heatmap binning: (x_bin, raw_y_searchsorted, dbw, x_valid) → (pair_index, weight).

    Combines validity checks, y-bin range clamping, and 2D→1D pair index
    computation into a single kernel — replaces cp.nonzero + sparse gather +
    second cp.nonzero + pair computation.
    """
    global _heatmap_2d_bin_kernel
    if _heatmap_2d_bin_kernel is not None:
        return _heatmap_2d_bin_kernel
    _heatmap_2d_bin_kernel = cp.ElementwiseKernel(
        "int64 x_bin, int64 raw_y_plus1, float32 dbw, bool x_valid, int64 nx, int64 ny",
        "int64 pair, float64 weight",
        """
        long long yb = raw_y_plus1 - 1;
        bool valid = x_valid && isfinite(dbw) && (x_bin >= 0) && (x_bin < nx)
                     && (yb >= 0) && (yb < ny);
        pair = valid ? (x_bin * ny + yb) : 0;
        weight = valid ? 1.0 : 0.0;
        """,
        "heatmap_2d_bin_fused",
    )
    return _heatmap_2d_bin_kernel


_group_key_encode_kernel = None


def _get_group_key_encode_kernel():
    """Fused (t, sky, sat) → flat group key in one kernel."""
    global _group_key_encode_kernel
    if _group_key_encode_kernel is not None:
        return _group_key_encode_kernel
    _group_key_encode_kernel = cp.ElementwiseKernel(
        "int32 t, int32 sky, int32 sat, int32 sky_count, int32 sat_count",
        "int32 key",
        "key = (t * sky_count + sky) * sat_count + sat",
        "group_key_encode",
    )
    return _group_key_encode_kernel


_group_key_decode_kernel = None


def _get_group_key_decode_kernel():
    """Fused flat_key → (t, sky, sat) in one kernel."""
    global _group_key_decode_kernel
    if _group_key_decode_kernel is not None:
        return _group_key_decode_kernel
    _group_key_decode_kernel = cp.ElementwiseKernel(
        "int64 flat_key, int64 sky_sat_stride, int64 sat_count",
        "int32 t, int32 sky, int32 sat",
        """
        long long t_val = flat_key / sky_sat_stride;
        long long rem = flat_key - t_val * sky_sat_stride;
        t = (int)t_val;
        sky = (int)(rem / sat_count);
        sat = (int)(rem % sat_count);
        """,
        "group_key_decode",
    )
    return _group_key_decode_kernel


_hist_bin_mask_kernel = None


def _get_hist_bin_mask_kernel():
    """Fused: valid check + searchsorted result masking → (kept_bin, weight) in one pass.

    Takes the raw searchsorted result and the dB values, produces the bin index
    (clamped to 0 for invalid) and the weight (1.0 for valid, 0.0 for invalid)
    in a single kernel launch — replaces 7 separate CuPy operations.
    """
    global _hist_bin_mask_kernel
    if _hist_bin_mask_kernel is not None:
        return _hist_bin_mask_kernel
    _hist_bin_mask_kernel = cp.ElementwiseKernel(
        "int64 raw_bin_plus1, float32 dbw, int64 n_bins",
        "int64 kept_bin, float64 weight",
        """
        long long b = raw_bin_plus1 - 1;
        bool valid = isfinite(dbw) && (b >= 0) && (b < n_bins);
        kept_bin = valid ? b : 0;
        weight = valid ? 1.0 : 0.0;
        """,
        "hist_bin_mask_fused",
    )
    return _hist_bin_mask_kernel


_histogram_1d_atomic_raw_module = None


def _get_histogram_1d_atomic_kernel():
    """Fused atomic accumulator kernel for
    :func:`_histogram_positive_value_db_cp`.

    1-D analogue of ``_get_histogram_2d_atomic_kernel``: replaces the
    ``_dbw_k`` + ``cp.searchsorted`` + ``_hist_bin_mask_kernel`` +
    ``cp.bincount`` + ``astype(int64)`` chain with a single atomicAdd
    kernel.  Used by every 1-D distribution collector (EPFD, Prx total,
    Total PFD RAS, per-satellite PFD), each called up to 4× per batch.
    """
    global _histogram_1d_atomic_raw_module
    if _histogram_1d_atomic_raw_module is not None:
        return _histogram_1d_atomic_raw_module
    _histogram_1d_atomic_raw_module = cp.RawModule(code=r"""
extern "C" __global__
void histogram_1d_atomic(
    const float* __restrict__ value_flat,
    const float* __restrict__ value_edges,
    long long* __restrict__ hist,
    const long long n_total,
    const int n_bins,
    const int n_edges,
    const float db_offset_db)
{
    long long i = (long long)blockIdx.x * blockDim.x + threadIdx.x;
    if (i >= n_total) return;
    float v_lin = value_flat[i];
    if (!isfinite(v_lin) || v_lin <= 0.0f) return;
    float dbw = log10f(v_lin) * 10.0f + db_offset_db;
    if (!isfinite(dbw)) return;

    /* Binary search: upper_bound in value_edges, matches
     * cp.searchsorted(value_edges, dbw, side="right") - 1. */
    int lo = 0, hi = n_edges;
    while (lo < hi) {
        int mid = (lo + hi) >> 1;
        if (value_edges[mid] <= dbw) lo = mid + 1;
        else hi = mid;
    }
    int yb = lo - 1;
    if (yb < 0 || yb >= n_bins) return;

    atomicAdd((unsigned long long*)&hist[yb], (unsigned long long)1);
}
""")
    return _histogram_1d_atomic_raw_module


def _histogram_positive_value_db_cp(
    *,
    value_linear: Any,
    value_edges_dbw: np.ndarray,
    db_offset_db: float = 0.0,
) -> Any:
    value_cp = _to_cupy_array(value_linear, dtype=cp.float32)
    value_edges_cp = cp.asarray(np.asarray(value_edges_dbw, dtype=np.float32))
    n_bins = int(value_edges_cp.size) - 1
    if n_bins <= 0:
        raise ValueError("value_edges_dbw must define at least one histogram bin.")

    flat = value_cp.reshape(-1)
    # The raw kernel indexes ``value_flat[i]`` assuming a contiguous
    # float32 layout; non-contiguous ``reshape`` views would read wrong
    # data (see iteration 15 contiguity-bug write-up). Enforce
    # contiguity explicitly before the launch.
    if (not flat.flags.c_contiguous) or flat.dtype != cp.float32:
        flat = cp.ascontiguousarray(flat, dtype=cp.float32)

    hist = cp.zeros(n_bins, dtype=cp.int64)
    n_total = int(flat.size)
    if n_total <= 0:
        return hist
    kernel = _get_histogram_1d_atomic_kernel().get_function("histogram_1d_atomic")
    threads = 256
    blocks = (n_total + threads - 1) // threads
    kernel(
        (blocks,), (threads,),
        (
            flat,
            value_edges_cp,
            hist,
            np.int64(n_total),
            np.int32(n_bins),
            np.int32(int(value_edges_cp.size)),
            np.float32(float(db_offset_db)),
        ),
    )
    return hist


_histogram_2d_atomic_raw_module = None


def _get_histogram_2d_atomic_kernel():
    """Fused atomic accumulator kernel for ``_histogram_value_vs_elevation_cp``.

    Replaces the per-slab chain of ``cp.tile(x_bin)`` +
    ``cp.tile(x_valid)`` + ``_get_log10_masked_dbw_kernel`` +
    ``cp.searchsorted`` + ``_get_heatmap_2d_bin_kernel`` +
    ``cp.bincount(pair, weights=weight, minlength=nx*ny)`` +
    ``reshape`` + ``astype(int64)`` + in-place ``hist += …`` with a
    single ``atomicAdd`` kernel.

    Per thread:
      - derive ``base_idx = i % n_base`` to look up the precomputed
        ``x_bin`` / ``x_valid`` without materialising a tiled copy
      - compute ``dBw = 10·log10(v) + offset`` inline
      - binary-search the ``value_edges`` array (matches
        ``cp.searchsorted(side="right") - 1``)
      - ``atomicAdd`` one count into the output ``hist[xb * ny + yb]``

    Eliminates 6 intermediate arrays (x_bin_rep, x_valid_rep, dbw,
    raw_y, pair, weight) and 6-7 kernel launches per sky slab.
    """
    global _histogram_2d_atomic_raw_module
    if _histogram_2d_atomic_raw_module is not None:
        return _histogram_2d_atomic_raw_module
    _histogram_2d_atomic_raw_module = cp.RawModule(code=r"""
extern "C" __global__
void histogram_2d_atomic(
    const float* __restrict__ value_flat,
    const long long* __restrict__ x_bin_base,
    const bool* __restrict__ x_valid_base,
    const float* __restrict__ value_edges,
    long long* __restrict__ hist,
    const long long n_total,
    const long long n_base,
    const int nx,
    const int ny,
    const int ny_edges,
    const float db_offset_db)
{
    long long i = (long long)blockIdx.x * blockDim.x + threadIdx.x;
    if (i >= n_total) return;
    long long base_idx = (n_base > 0) ? (i % n_base) : 0;
    long long xb = x_bin_base[base_idx];
    bool xv = x_valid_base[base_idx];
    if (!xv || xb < 0 || xb >= nx) return;

    float v_lin = value_flat[i];
    if (!isfinite(v_lin) || v_lin <= 0.0f) return;
    float dbw = log10f(v_lin) * 10.0f + db_offset_db;
    if (!isfinite(dbw)) return;

    /* Binary search: upper_bound in value_edges, matches
     * cp.searchsorted(value_edges, dbw, side="right") - 1. */
    int lo = 0, hi = ny_edges;
    while (lo < hi) {
        int mid = (lo + hi) >> 1;
        if (value_edges[mid] <= dbw) lo = mid + 1;
        else hi = mid;
    }
    int yb = lo - 1;
    if (yb < 0 || yb >= ny) return;

    atomicAdd((unsigned long long*)&hist[xb * (long long)ny + yb],
              (unsigned long long)1);
}
""")
    return _histogram_2d_atomic_raw_module


def _histogram_value_vs_elevation_cp(
    *,
    value_linear: Any,
    sat_elevation_deg: Any,
    elevation_edges_deg: np.ndarray,
    value_edges_dbw: np.ndarray,
    db_offset_db: float = 0.0,
    sky_slab: int = 16,
) -> Any:
    value_cp = _coerce_per_satellite_heatmap_tensor_cp(
        value_linear,
        name="value_linear",
    )
    elev_cp = _to_cupy_array(sat_elevation_deg, dtype=cp.float32)

    if elev_cp.ndim != 2:
        raise ValueError(
            f"sat_elevation_deg must have shape (T, S); got {tuple(elev_cp.shape)!r}."
        )
    if tuple(elev_cp.shape) != tuple(value_cp.shape[:2]):
        raise ValueError(
            "sat_elevation_deg must align with value_w_per_mhz over (T, S); "
            f"got {tuple(elev_cp.shape)!r} vs {tuple(value_cp.shape)!r}."
        )

    elev_edges_cp = cp.asarray(np.asarray(elevation_edges_deg, dtype=np.float32))
    value_edges_cp = cp.asarray(np.asarray(value_edges_dbw, dtype=np.float32))

    nx = int(elev_edges_cp.size) - 1
    ny = int(value_edges_cp.size) - 1
    hist = cp.zeros((nx, ny), dtype=cp.int64)

    elev_flat = elev_cp.reshape(-1)
    x_bin = cp.searchsorted(elev_edges_cp, elev_flat, side="right") - 1
    x_valid = cp.isfinite(elev_flat) & (x_bin >= 0) & (x_bin < nx)
    x_bin = x_bin.astype(cp.int32, copy=False)

    db_offset_f = float(db_offset_db)
    slab_width = max(1, int(sky_slab))
    n_sky = int(value_cp.shape[2])

    # Fused atomic-add histogram kernel — single-launch replacement for the
    # tile + dbw + searchsorted + heatmap_2d_bin + bincount chain.
    atomic_kernel = _get_histogram_2d_atomic_kernel().get_function("histogram_2d_atomic")
    # Persistent inputs to every slab call
    x_bin_base = x_bin.astype(cp.int64, copy=False)
    x_valid_base = x_valid.astype(cp.bool_, copy=False)
    n_base = x_bin_base.size
    hist_flat = hist.reshape(-1)
    nx_i32 = np.int32(nx)
    ny_i32 = np.int32(ny)
    ny_edges_i32 = np.int32(int(value_edges_cp.size))
    db_offset_f32 = np.float32(db_offset_f)

    def _launch_atomic(slab_flat: Any) -> None:
        n_total = int(slab_flat.size)
        if n_total <= 0:
            return
        # The raw kernel reads ``value_flat[i]`` assuming a contiguous
        # float32 layout.  CuPy's ``reshape(-1)`` on a non-contiguous
        # slice (e.g. ``value_cp[:, :, a:b]`` when the sky axis is the
        # inner axis) returns a **strided view**, not a copy — same
        # `shape=(N,)`` but ``strides != (4,)``.  Force contiguity
        # explicitly so the kernel's linear index math holds.
        if (not slab_flat.flags.c_contiguous) or slab_flat.dtype != cp.float32:
            slab_flat = cp.ascontiguousarray(slab_flat, dtype=cp.float32)
        threads = 256
        blocks = (n_total + threads - 1) // threads
        atomic_kernel(
            (blocks,), (threads,),
            (
                slab_flat,
                x_bin_base,
                x_valid_base,
                value_edges_cp,
                hist_flat,
                np.int64(n_total),
                np.int64(int(n_base)),
                nx_i32,
                ny_i32,
                ny_edges_i32,
                db_offset_f32,
            ),
        )

    if n_sky == 1:
        _launch_atomic(value_cp.reshape(-1))
    else:
        for sky_start in range(0, n_sky, slab_width):
            sky_stop = min(sky_start + slab_width, n_sky)
            _launch_atomic(value_cp[:, :, sky_start:sky_stop].reshape(-1))

    return hist


def _histogram_per_satellite_value_vs_elevation_cp(
    *,
    value_w_per_mhz: Any,
    sat_elevation_deg: Any,
    elevation_edges_deg: np.ndarray,
    value_edges_dbw: np.ndarray,
    bw_mhz: float,
    sky_slab: int = 16,
) -> Any:
    return _histogram_value_vs_elevation_cp(
        value_linear=value_w_per_mhz,
        sat_elevation_deg=sat_elevation_deg,
        elevation_edges_deg=elevation_edges_deg,
        value_edges_dbw=value_edges_dbw,
        db_offset_db=(10.0 * math.log10(float(bw_mhz))),
        sky_slab=int(sky_slab),
    )


_beamforming_collapsed_kernel = None


def _get_beamforming_collapsed_kernel():
    """Return (and cache) an ElementwiseKernel for the beamforming-collapsed
    OOBE power formula.

    For each visible satellite, computes:
        EIRP_oobe = baseline + 20*log10(f_eval/f_ref) + 10*log10(cos(theta))
    where theta is the off-nadir angle.  Then applies FSPL and atmosphere to
    produce received power in Watts.
    """
    global _beamforming_collapsed_kernel
    if _beamforming_collapsed_kernel is not None:
        return _beamforming_collapsed_kernel
    _beamforming_collapsed_kernel = cp.ElementwiseKernel(
        "float32 range_m, float32 sat_el_deg, float32 orbit_r_m, float32 earth_r_m, "
        "float32 wavelength_m, float32 atm_lin, "
        "float32 baseline_dbw_hz, float32 freq_term_db, float32 ras_bw_hz",
        "float32 prx_w",
        """
        /* Off-nadir angle theta: cos(theta) = range_component / orbit_radius
           For a satellite at elevation el as seen from ground:
           cos(theta) ≈ sin(el) + R_earth * cos^2(el) / orbit_r  (approx)
           More precisely: cos(theta) = (R_e/r) * cos(el) via geometry,
           but the simplest correct form uses the nadir angle directly.

           Actually, the off-nadir angle can be computed from the geometry:
           cos(theta) is the component along the nadir axis / distance.
           For the satellite looking at the observer:
           sin(theta) = R_earth * cos(el_ground) / range
           cos(theta) = sqrt(1 - sin²(theta))
           But the filing formula uses cos(θ) where θ is from nadir.

           Use: cos(θ) = (orbit_r² + range² - earth_r²) / (2 * orbit_r * range)
           which is the law of cosines for the triangle (center, sat, obs).
        */
        float cos_theta = (orbit_r_m * orbit_r_m + range_m * range_m - earth_r_m * earth_r_m)
                        / (2.0f * orbit_r_m * range_m);
        if (cos_theta < 0.001f) cos_theta = 0.001f;  /* guard against log(0) */
        if (cos_theta > 1.0f) cos_theta = 1.0f;

        /* EIRP spectral density in dBW/Hz */
        float eirp_dbw_hz = baseline_dbw_hz + freq_term_db + 10.0f * log10f(cos_theta);

        /* Convert to total power over RAS bandwidth: P = EIRP_sd * BW */
        float eirp_w = __expf((eirp_dbw_hz + 10.0f * log10f(ras_bw_hz)) * 0.23025850929f);

        /* FSPL = (lambda / 4*pi*R)^2 */
        float fspl = wavelength_m / (12.5663706f * range_m);  /* 4*pi ≈ 12.566 */
        fspl = fspl * fspl;

        /* Received power (no beam gain — this IS the collapsed pattern) */
        prx_w = eirp_w * fspl * atm_lin;

        /* Zero out satellites below horizon */
        if (sat_el_deg <= 0.0f) prx_w = 0.0f;
        """,
        "beamforming_collapsed_power",
    )
    return _beamforming_collapsed_kernel


def _accumulate_beamforming_collapsed_power_cp(
    *,
    sat_topo: Any,
    orbit_radius_m_per_sat: Any,
    observer_alt_km: float,
    wavelength_m: float,
    atmosphere_lut_context: Any | None,
    ras_pattern_context: Any | None,
    telescope_azimuth_deg: Any | None,
    telescope_elevation_deg: Any | None,
    collapsed_baseline_eirp_dbw_hz: float,
    collapsed_eval_freq_mhz: float,
    collapsed_ref_freq_mhz: float,
    ras_bandwidth_hz: float,
    include_epfd: bool = True,
    include_prx_total: bool = True,
    include_total_pfd: bool = False,
) -> dict[str, Any]:
    """Compute interference from all visible satellites using the
    beamforming-collapsed OOBE formula.

    No beam assignment or link library is needed — every visible satellite
    contributes based on the cos(θ) envelope formula.
    """
    import math as _math

    sat_topo_cp = _to_cupy_array(sat_topo, dtype=cp.float32)
    time_count, sat_count = int(sat_topo_cp.shape[0]), int(sat_topo_cp.shape[1])
    orbit_radius = _to_cupy_array(orbit_radius_m_per_sat, dtype=cp.float32).reshape(-1)
    earth_r = cp.float32(float(R_earth.to_value(u.m)))
    wavelength = cp.float32(float(wavelength_m))

    range_m = sat_topo_cp[:, :, 2] * cp.float32(1000.0)  # km → m
    sat_elevation_deg = sat_topo_cp[:, :, 1]

    # Atmosphere at RAS station elevation
    if atmosphere_lut_context is not None:
        atm_lin = _lookup_atmosphere_lut_cp(
            atmosphere_lut_context, sat_elevation_deg, altitude_km=observer_alt_km,
        ).astype(cp.float32, copy=False)
    else:
        atm_lin = cp.ones((time_count, sat_count), dtype=cp.float32)

    # Pre-compute frequency term (constant for all sats/timesteps)
    freq_term_db = cp.float32(
        20.0 * _math.log10(max(float(collapsed_eval_freq_mhz), 0.1) / max(float(collapsed_ref_freq_mhz), 0.1))
    )
    ras_bw_hz = cp.float32(float(ras_bandwidth_hz))

    # Broadcast orbit_radius to (T, S) shape
    orbit_r_broadcast = orbit_radius[None, :].astype(cp.float32, copy=False)
    orbit_r_2d = cp.broadcast_to(orbit_r_broadcast, (time_count, sat_count)).copy()

    kernel = _get_beamforming_collapsed_kernel()
    # base_per_sat = power AT the antenna site WITHOUT receive gain. This is
    # the "isotropic-RX" reference power: PFD × A_iso. Keep it cleanly
    # separate from the receive-gain-multiplied per-sat Prx so we don't have
    # to "divide out" Grx later (the previous code did that — fragile when
    # Grx is small in deep sidelobes).
    base_per_sat = kernel(
        range_m, sat_elevation_deg, orbit_r_2d, earth_r,
        wavelength, atm_lin,
        cp.float32(float(collapsed_baseline_eirp_dbw_hz)),
        freq_term_db, ras_bw_hz,
    )

    # The S.1586 sky-cell scan is the telescope's own strategy and is
    # independent of which satellite system is on the transmit side. We
    # therefore ALWAYS compute per-(t, sky, sat) Grx when pointings carry
    # a real sky axis (N_sky > 1). Using `tel_az[:, 0]` was a bug —
    # see CHANGELOG / CLAUDE.md note on per-sky-cell Grx.
    sky_count = 1
    grx_per_sky_sat = None  # (T, N_sky, S) when computed
    grx_lin_2d = None       # (T, S) for the legacy single-pointing path
    if (
        ras_pattern_context is not None
        and telescope_azimuth_deg is not None
        and telescope_elevation_deg is not None
    ):
        tel_az = _to_cupy_array(telescope_azimuth_deg, dtype=cp.float32)
        tel_el = _to_cupy_array(telescope_elevation_deg, dtype=cp.float32)
        d2r = cp.float32(0.017453292519943295)
        sat_az_rad = sat_topo_cp[:, :, 0] * d2r
        sat_el_rad = sat_elevation_deg * d2r
        if tel_az.ndim >= 2:
            sky_count = int(tel_az.shape[1])
        _ras_is_custom_2d = isinstance(
            ras_pattern_context, GpuCustomPattern2DContext,
        )
        # Try fused RX kernel (angular distance + RA.1631 pattern + dB→linear
        # in one launch) — same kernel used by the directive path.
        _use_fused_rx_bc = isinstance(ras_pattern_context, GpuRasPatternContext)
        if _use_fused_rx_bc:
            _d_wlen = np.float32(ras_pattern_context.diameter_m / ras_pattern_context.wavelength_m)
            _gmax_r = np.float32(10.0 * np.log10(ras_pattern_context.eta_a_dimless * (np.pi * _d_wlen) ** 2))
            _g1_r = np.float32(-1.0 + 15.0 * np.log10(_d_wlen))
            _phi_m_r = np.float32(20.0 / _d_wlen * np.sqrt(_gmax_r - _g1_r))
            _phi_r_r = np.float32(15.85 * _d_wlen ** -0.6)
            _rx_k = _get_rx_angular_distance_ras_lin_kernel()
            sat_az_deg_f32 = sat_topo_cp[:, :, 0].astype(cp.float32, copy=False)
            if sky_count > 1:
                grx_per_sky_sat = _rx_k(
                    tel_az[:, :, None].astype(cp.float32, copy=False),
                    tel_el[:, :, None].astype(cp.float32, copy=False),
                    sat_az_deg_f32[:, None, :],
                    sat_elevation_deg[:, None, :].astype(cp.float32, copy=False),
                    _d_wlen, _gmax_r, _g1_r, _phi_m_r, _phi_r_r,
                )
            else:
                tel_az_use = tel_az[:, 0] if tel_az.ndim >= 2 else tel_az
                tel_el_use = tel_el[:, 0] if tel_el.ndim >= 2 else tel_el
                grx_lin_2d = _rx_k(
                    (tel_az_use[:, None] if tel_az_use.ndim == 1 else tel_az_use).astype(cp.float32, copy=False),
                    (tel_el_use[:, None] if tel_el_use.ndim == 1 else tel_el_use).astype(cp.float32, copy=False),
                    sat_az_deg_f32,
                    sat_elevation_deg.astype(cp.float32, copy=False),
                    _d_wlen, _gmax_r, _g1_r, _phi_m_r, _phi_r_r,
                )
        elif sky_count > 1:
            # Fallback for custom RAS patterns (Custom-1D/2D).
            # Fused angular distance (14 ops → 1) + fused phi (10 ops → 1).
            _ang_k = _get_rx_angular_distance_only_kernel()
            grx_offset_deg = _ang_k(
                tel_az[:, :, None].astype(cp.float32, copy=False),
                tel_el[:, :, None].astype(cp.float32, copy=False),
                sat_az_deg_f32[:, None, :],
                sat_elevation_deg[:, None, :].astype(cp.float32, copy=False),
            )
            grx_phi_deg = (
                _ras_boresight_frame_phi_deg(
                    (tel_az * d2r)[:, :, None],
                    (tel_el * d2r)[:, :, None],
                    sat_az_rad[:, None, :],
                    sat_el_rad[:, None, :],
                )
                if _ras_is_custom_2d else None
            )
            grx_db = _evaluate_ras_pattern_cp(
                ras_pattern_context, grx_offset_deg, grx_phi_deg,
            )
            grx_per_sky_sat = cp.power(cp.float32(10.0), grx_db * cp.float32(0.1))
        else:
            tel_az_use = tel_az[:, 0] if tel_az.ndim >= 2 else tel_az
            tel_el_use = tel_el[:, 0] if tel_el.ndim >= 2 else tel_el
            _ang_k = _get_rx_angular_distance_only_kernel()
            grx_offset_deg = _ang_k(
                (tel_az_use[:, None] if tel_az_use.ndim == 1 else tel_az_use).astype(cp.float32, copy=False),
                (tel_el_use[:, None] if tel_el_use.ndim == 1 else tel_el_use).astype(cp.float32, copy=False),
                sat_az_deg_f32,
                sat_elevation_deg.astype(cp.float32, copy=False),
            )
            grx_phi_deg = (
                _ras_boresight_frame_phi_deg(
                    ((tel_az_use[:, None] if tel_az_use.ndim == 1 else tel_az_use) * d2r).astype(cp.float32, copy=False),
                    ((tel_el_use[:, None] if tel_el_use.ndim == 1 else tel_el_use) * d2r).astype(cp.float32, copy=False),
                    sat_az_rad,
                    sat_el_rad,
                )
                if _ras_is_custom_2d else None
            )
            grx_db = _evaluate_ras_pattern_cp(
                ras_pattern_context, grx_offset_deg, grx_phi_deg,
            )
            grx_lin_2d = cp.power(cp.float32(10.0), grx_db * cp.float32(0.1))

    pfd_scale = cp.float32(4.0 * float(np.pi) / (float(wavelength_m) ** 2))
    result: dict[str, Any] = {}

    # Sky-aware aggregations: per-(t, sky) Prx_total and EPFD when N_sky > 1,
    # collapsed (T, 1, 1) for the legacy single-pointing path. Layout
    # matches the directive kernel's writer contract: (T, 1, N_sky) so the
    # cell axis stays size-1 (collapsed power has no per-cell dependence).
    if grx_per_sky_sat is not None:
        prx_per_sky_sat = base_per_sat[:, None, :] * grx_per_sky_sat   # (T, N_sky, S)
        prx_total_t_sky = cp.sum(prx_per_sky_sat, axis=2)              # (T, N_sky)
        if include_prx_total:
            result["Prx_total_W"] = prx_total_t_sky[:, None, :]        # (T, 1, N_sky)
        if include_epfd:
            result["EPFD_W_m2"] = (prx_total_t_sky * pfd_scale)[:, None, :]
    else:
        prx_per_sat_2d = base_per_sat
        if grx_lin_2d is not None:
            prx_per_sat_2d = prx_per_sat_2d * grx_lin_2d
        prx_total_t = cp.sum(prx_per_sat_2d, axis=1)                   # (T,)
        if include_prx_total:
            result["Prx_total_W"] = prx_total_t[:, None, None]
        if include_epfd:
            result["EPFD_W_m2"] = (prx_total_t * pfd_scale)[:, None, None]

    if include_total_pfd:
        # PFD at the antenna site does NOT involve receive gain — sum the
        # gain-free per-sat contribution and scale. Independent of sky
        # pointing direction, so always (T, 1, 1).
        pfd_total = cp.sum(base_per_sat, axis=1) * pfd_scale
        result["PFD_total_RAS_STATION_W_m2"] = pfd_total[:, None, None]
    return result


def _accumulate_uemr_power_cp(
    *,
    uemr_pattern_context: "GpuIsotropicPatternContext",
    ras_pattern_context: (
        "GpuRasPatternContext | GpuCustomPattern1DContext"
        " | GpuCustomPattern2DContext | None"
    ),
    atmosphere_lut_context: "GpuAtmosphereLutContext | None",
    sat_topo: Any,
    telescope_azimuth_deg: Any | None,
    telescope_elevation_deg: Any | None,
    observer_alt_km: float,
    bandwidth_mhz: float,
    power_input_quantity: str,
    target_pfd_dbw_m2_channel: float | None,
    satellite_ptx_dbw_channel: float | None,
    satellite_eirp_dbw_channel: float | None,
    eirp_slab_fraction_lin: float = 1.0,
    visibility_elev_threshold_deg: float = 0.0,
    include_epfd: bool = True,
    include_prx_total: bool = True,
    include_per_satellite_prx: bool = False,
    include_total_pfd: bool = False,
    include_per_satellite_pfd: bool = False,
    random_power_variation: bool = False,
    power_dtype: Any = None,
    pattern_dtype: Any = None,
) -> dict[str, Any]:
    """Compute per-satellite power / PFD / EPFD for a UEMR-mode system.

    When ``random_power_variation=True``, each satellite at each
    timestep radiates a uniformly distributed fraction ``U(0, 1)``
    of the configured EIRP — models stochastic unwanted emissions.

    UEMR (unwanted emissions from internal circuitry) radiates isotropically,
    Gtx = 0 dBi in every direction, with no beam mechanics. Each visible
    satellite contributes

        PFD_s   = EIRP_channel · atm(el) / (4π · d²)
        Prx_s   = EIRP_channel · (λ / 4π d)² · atm(el) · Grx(γ)
        EPFD_s  = Prx_s · (4π / λ²)

    and the per-time totals are the sums over satellites.

    Parameters
    ----------
    uemr_pattern_context
        Isotropic pattern context — only its ``wavelength_m`` is consumed.
    ras_pattern_context
        RAS receive pattern. Used to weight Prx / EPFD by Grx(γ) where γ is
        the angle between each satellite and the telescope pointing.
    sat_topo
        ``(T, S, 3)`` array of (az_deg, el_deg, range_km) in the RAS-station
        topocentric frame.
    telescope_azimuth_deg, telescope_elevation_deg
        RAS pointing either as ``(T,)`` or ``(T, N_sky)`` device tensors. Only
        the first sky-cell is consumed (UEMR is direction-agnostic; the
        receive-side Grx is the only place pointing matters).
    eirp_slab_fraction_lin
        Per-slab linear scaling applied to EIRP_channel. The caller (scenario
        pipeline) multiplies in the in-band fraction of the transmit
        spectrum for the current spectral slab so the emission mask can
        shape UEMR power across frequency. Default ``1.0`` (no mask).
    power_dtype
        Dtype for power-stage accumulation (EIRP, FSPL, PFD, Prx).
        Must be at least fp32 (fp16 silently promoted). ``None`` → fp32.
    pattern_dtype
        Dtype for RAS pattern evaluation (Grx angles and gain). Can be
        fp16 for LUT-based patterns. ``None`` → fp32.

    Returns
    -------
    dict
        Result arrays keyed the same as ``_accumulate_ras_power_cp`` but
        shaped ``(T, 1, 1)`` to broadcast into the writer's
        ``(T, N_sky, N_cell)`` layout. Per-satellite fields have shape
        ``(T, S)``.
    """
    import math as _math

    if not isinstance(uemr_pattern_context, GpuIsotropicPatternContext):
        raise TypeError(
            "_accumulate_uemr_power_cp requires a GpuIsotropicPatternContext; "
            f"got {type(uemr_pattern_context).__name__}."
        )

    quantity = str(power_input_quantity).strip().lower()
    if quantity not in {"target_pfd", "satellite_ptx", "satellite_eirp"}:
        raise ValueError(
            "power_input_quantity must be 'target_pfd', 'satellite_ptx', or "
            f"'satellite_eirp'; got {power_input_quantity!r}."
        )
    bandwidth_value = float(bandwidth_mhz)
    if not np.isfinite(bandwidth_value) or bandwidth_value <= 0.0:
        raise ValueError("bandwidth_mhz must be finite and > 0.")

    # Resolve per-stage precision — mirrors the directive kernel's logic.
    # Power must be >= fp32 (FSPL ~1e-16 underflows fp16).
    # Pattern evaluation can use fp16; trig (sin/cos/arccos) always >= fp32.
    pwr_dt = cp.float32
    pat_dt = cp.float32
    if power_dtype is not None:
        _pwr = np.dtype(power_dtype)
        if _pwr == np.dtype(np.float64):
            pwr_dt = cp.float64
        # fp16 not allowed for power — silently promote to fp32
    if pattern_dtype is not None:
        _pat = np.dtype(pattern_dtype)
        if _pat == np.dtype(np.float64):
            pat_dt = cp.float64
        elif _pat == np.dtype(np.float16):
            pat_dt = cp.float16
    trig_dt = cp.float32 if pat_dt == cp.float16 else pat_dt

    sat_topo_cp = _to_cupy_array(sat_topo, dtype=pwr_dt)
    if sat_topo_cp.ndim != 3 or sat_topo_cp.shape[2] != 3:
        raise ValueError(
            "sat_topo must have shape (T, S, 3); got "
            f"{tuple(sat_topo_cp.shape)!r}."
        )
    time_count, sat_count = int(sat_topo_cp.shape[0]), int(sat_topo_cp.shape[1])
    wavelength_m = float(uemr_pattern_context.wavelength_m)
    range_m = sat_topo_cp[..., 2] * pwr_dt(1000.0)
    sat_el_deg = sat_topo_cp[..., 1]
    sat_az_deg = sat_topo_cp[..., 0]
    # Radio-horizon aware visibility: use the same threshold the rest of
    # the pipeline applies (can be slightly negative when use_radio_horizon
    # extends visibility via tropospheric/ionospheric refraction).
    vis = sat_el_deg > pwr_dt(float(visibility_elev_threshold_deg))

    if atmosphere_lut_context is not None:
        atm_lin = _lookup_atmosphere_lut_cp(
            atmosphere_lut_context, sat_el_deg, altitude_km=observer_alt_km,
        ).astype(pwr_dt, copy=False)
        # Atmosphere LUT returns linear transmission ∈ (0, 1]; clip so
        # LUT rounding artifacts cannot push the computed PFD above the
        # free-space value. Mirrors the directive power kernel behaviour.
        atm_lin = cp.clip(atm_lin, pwr_dt(0.0), pwr_dt(1.0))
    else:
        atm_lin = cp.ones((time_count, sat_count), dtype=pwr_dt)

    # Resolve EIRP_channel in linear watts. Target-PFD mode reverse-maps the
    # user's requested surface PFD to an equivalent EIRP via a reference
    # slant range (nadir from the mean orbit radius). For UEMR this is less
    # meaningful than for directive patterns — we accept it for API parity
    # and warn callers that EIRP / Ptx are the natural UEMR inputs.
    if quantity == "satellite_eirp":
        if satellite_eirp_dbw_channel is None:
            raise ValueError("satellite_eirp_dbw_channel must be set in satellite_eirp mode.")
        eirp_lin_channel = float(10.0 ** (float(satellite_eirp_dbw_channel) / 10.0))
    elif quantity == "satellite_ptx":
        if satellite_ptx_dbw_channel is None:
            raise ValueError("satellite_ptx_dbw_channel must be set in satellite_ptx mode.")
        # Gtx = 0 dBi → EIRP_dBW = Ptx_dBW
        eirp_lin_channel = float(10.0 ** (float(satellite_ptx_dbw_channel) / 10.0))
    else:
        if target_pfd_dbw_m2_channel is None:
            raise ValueError("target_pfd_dbw_m2_channel must be set in target_pfd mode.")
        # Invert PFD = EIRP / (4π r²) using r = nadir range of a nominal
        # 550 km LEO shell. This path is mostly a compatibility shim; UEMR
        # users should drive with Ptx or EIRP in practice.
        nominal_range_m = 550.0e3
        eirp_lin_channel = float(
            (10.0 ** (float(target_pfd_dbw_m2_channel) / 10.0))
            * (4.0 * _math.pi * nominal_range_m * nominal_range_m)
        )

    slab_frac = float(eirp_slab_fraction_lin)
    if not np.isfinite(slab_frac) or slab_frac < 0.0:
        raise ValueError("eirp_slab_fraction_lin must be finite and non-negative.")

    if random_power_variation:
        # Each satellite at each timestep gets a random uniform [0, 1]
        # factor multiplied into the EIRP — models stochastic UEMR.
        rand_factor = cp.random.uniform(
            low=0.0, high=1.0,
            size=(time_count, sat_count),
        ).astype(pwr_dt, copy=False)
        eirp_effective_w = pwr_dt(eirp_lin_channel * slab_frac) * rand_factor
    else:
        eirp_effective_w = pwr_dt(eirp_lin_channel * slab_frac)

    # FSPL = (λ / 4π·d)². Guard against zero range.
    wavelength_w = pwr_dt(wavelength_m)
    four_pi_w = pwr_dt(4.0 * _math.pi)
    range_safe = cp.where(vis, range_m, pwr_dt(1.0))
    fspl = cp.power(wavelength_w / (four_pi_w * range_safe), pwr_dt(2.0))
    fspl = cp.where(vis, fspl, pwr_dt(0.0))

    pfd_scale = pwr_dt(4.0 * _math.pi / (wavelength_m * wavelength_m))
    pfd_per_sat = eirp_effective_w * atm_lin / (
        four_pi_w * range_safe * range_safe
    )
    pfd_per_sat = cp.where(vis, pfd_per_sat, pwr_dt(0.0))

    # Grx(γ) for Prx / EPFD. UEMR is direction-agnostic on TX, but the
    # received Prx absolutely depends on RAS pointing direction because
    # the receive antenna gain Grx(γ) varies with the angle between the
    # RAS sky-cell pointing and each satellite. The telescope pointings
    # tensor has shape (T, N_sky) — one independent pointing per sky cell
    # per timestep. We MUST compute γ per (t, sky, sat) and broadcast Grx
    # accordingly; using `tel_az[:, 0]` (only the first sky cell) was a
    # bug that made the heatmap depend on RAS operational range in a
    # spurious way (changing the operational range shifted which cell was
    # at index 0 → effective RAS pointing direction changed → peak Prx
    # shifted by ~10 dB with no physical justification).
    sky_count = 1
    grx_lin: Any = pwr_dt(1.0)
    grx_per_sky_sat = None  # shape (T, N_sky, S) when computed
    if (
        ras_pattern_context is not None
        and telescope_azimuth_deg is not None
        and telescope_elevation_deg is not None
    ):
        tel_az = _to_cupy_array(telescope_azimuth_deg, dtype=trig_dt)
        tel_el = _to_cupy_array(telescope_elevation_deg, dtype=trig_dt)
        d2r = trig_dt(_math.pi / 180.0)
        sat_az_r = sat_az_deg.astype(trig_dt, copy=False) * d2r
        sat_el_r = sat_el_deg.astype(trig_dt, copy=False) * d2r
        if tel_az.ndim >= 2:
            sky_count = int(tel_az.shape[1])
        _ras_is_custom_2d = isinstance(
            ras_pattern_context, GpuCustomPattern2DContext,
        )
        # Try fused RX kernel: angular distance + RA.1631 pattern + dB→linear
        # in one launch.  Works for both sky_count>1 (3D broadcast) and
        # sky_count==1 (2D) because it's an ElementwiseKernel.
        _use_fused_rx = (
            pwr_dt == cp.float32
            and isinstance(ras_pattern_context, GpuRasPatternContext)
        )
        if _use_fused_rx:
            d_wlen = np.float32(ras_pattern_context.diameter_m / ras_pattern_context.wavelength_m)
            _gmax_ras = np.float32(10.0 * np.log10(ras_pattern_context.eta_a_dimless * (np.pi * d_wlen) ** 2))
            _g1_ras = np.float32(-1.0 + 15.0 * np.log10(d_wlen))
            _phi_m_ras = np.float32(20.0 / d_wlen * np.sqrt(_gmax_ras - _g1_ras))
            _phi_r_ras = np.float32(15.85 * d_wlen ** -0.6)
            _rx_kernel = _get_rx_angular_distance_ras_lin_kernel()
            if sky_count > 1:
                # Per-(t, sky, sat): broadcast (T,N_sky,1) × (T,1,S) → (T,N_sky,S)
                grx_per_sky_sat = _rx_kernel(
                    tel_az[:, :, None].astype(cp.float32, copy=False),
                    tel_el[:, :, None].astype(cp.float32, copy=False),
                    sat_az_deg[:, None, :].astype(cp.float32, copy=False),
                    sat_el_deg[:, None, :].astype(cp.float32, copy=False),
                    d_wlen, _gmax_ras, _g1_ras, _phi_m_ras, _phi_r_ras,
                )
            else:
                tel_az_use = tel_az[:, 0] if tel_az.ndim >= 2 else tel_az
                tel_el_use = tel_el[:, 0] if tel_el.ndim >= 2 else tel_el
                grx_lin = _rx_kernel(
                    (tel_az_use[:, None] if tel_az_use.ndim == 1 else tel_az_use).astype(cp.float32, copy=False),
                    (tel_el_use[:, None] if tel_el_use.ndim == 1 else tel_el_use).astype(cp.float32, copy=False),
                    sat_az_deg.astype(cp.float32, copy=False),
                    sat_el_deg.astype(cp.float32, copy=False),
                    d_wlen, _gmax_ras, _g1_ras, _phi_m_ras, _phi_r_ras,
                )
        elif trig_dt == cp.float32 and sky_count > 1:
            # Fused angular distance for Custom RAS patterns (fp32).
            _ang_k = _get_rx_angular_distance_only_kernel()
            gamma_deg = _ang_k(
                tel_az[:, :, None].astype(cp.float32, copy=False),
                tel_el[:, :, None].astype(cp.float32, copy=False),
                sat_az_deg[:, None, :].astype(cp.float32, copy=False),
                sat_el_deg[:, None, :].astype(cp.float32, copy=False),
            )
            phi_deg_cp = (
                _ras_boresight_frame_phi_deg(
                    (tel_az * d2r)[:, :, None], (tel_el * d2r)[:, :, None],
                    sat_az_r[:, None, :], sat_el_r[:, None, :],
                )
                if _ras_is_custom_2d else None
            )
            grx_db = _evaluate_ras_pattern_cp(
                ras_pattern_context, gamma_deg, phi_deg_cp,
            )
            grx_per_sky_sat = cp.power(
                pwr_dt(10.0),
                grx_db.astype(pwr_dt, copy=False) * pwr_dt(0.1),
            )
        elif trig_dt == cp.float32:
            # Fused angular distance for Custom RAS patterns (fp32, single-sky).
            tel_az_use = tel_az[:, 0] if tel_az.ndim >= 2 else tel_az
            tel_el_use = tel_el[:, 0] if tel_el.ndim >= 2 else tel_el
            _ang_k = _get_rx_angular_distance_only_kernel()
            gamma_deg = _ang_k(
                (tel_az_use[:, None] if tel_az_use.ndim == 1 else tel_az_use).astype(cp.float32, copy=False),
                (tel_el_use[:, None] if tel_el_use.ndim == 1 else tel_el_use).astype(cp.float32, copy=False),
                sat_az_deg.astype(cp.float32, copy=False),
                sat_el_deg.astype(cp.float32, copy=False),
            )
            tel_az_r_1d = (tel_az_use[:, None] * d2r) if tel_az_use.ndim == 1 else tel_az_use * d2r
            tel_el_r_1d = (tel_el_use[:, None] * d2r) if tel_el_use.ndim == 1 else tel_el_use * d2r
            phi_deg_cp = (
                _ras_boresight_frame_phi_deg(
                    tel_az_r_1d.astype(cp.float32, copy=False),
                    tel_el_r_1d.astype(cp.float32, copy=False),
                    sat_az_r, sat_el_r,
                )
                if _ras_is_custom_2d else None
            )
            grx_db = _evaluate_ras_pattern_cp(
                ras_pattern_context, gamma_deg, phi_deg_cp,
            )
            grx_lin = cp.power(pwr_dt(10.0), grx_db.astype(pwr_dt, copy=False) * pwr_dt(0.1))
        elif sky_count > 1:
            # fp64 fallback: per-(t, sky, sat) γ.
            tel_az_r = (tel_az * d2r)[:, :, None]
            tel_el_r = (tel_el * d2r)[:, :, None]
            sat_az_r3 = sat_az_r[:, None, :]
            sat_el_r3 = sat_el_r[:, None, :]
            cos_gamma = (
                cp.sin(tel_el_r) * cp.sin(sat_el_r3)
                + cp.cos(tel_el_r) * cp.cos(sat_el_r3) * cp.cos(tel_az_r - sat_az_r3)
            )
            cp.clip(cos_gamma, trig_dt(-1.0), trig_dt(1.0), out=cos_gamma)
            gamma_deg = cp.arccos(cos_gamma) * trig_dt(180.0 / _math.pi)
            phi_deg_cp = (
                _ras_boresight_frame_phi_deg(
                    tel_az_r, tel_el_r, sat_az_r3, sat_el_r3,
                )
                if _ras_is_custom_2d else None
            )
            grx_db = _evaluate_ras_pattern_cp(
                ras_pattern_context, gamma_deg, phi_deg_cp,
            )
            grx_per_sky_sat = cp.power(
                pwr_dt(10.0),
                grx_db.astype(pwr_dt, copy=False) * pwr_dt(0.1),
            )
        else:
            # fp64 fallback: single-sky.
            tel_az_use = tel_az[:, 0] if tel_az.ndim >= 2 else tel_az
            tel_el_use = tel_el[:, 0] if tel_el.ndim >= 2 else tel_el
            tel_az_r = (tel_az_use[:, None] * d2r) if tel_az_use.ndim == 1 else tel_az_use * d2r
            tel_el_r = (tel_el_use[:, None] * d2r) if tel_el_use.ndim == 1 else tel_el_use * d2r
            cos_gamma = (
                cp.sin(tel_el_r) * cp.sin(sat_el_r)
                + cp.cos(tel_el_r) * cp.cos(sat_el_r) * cp.cos(tel_az_r - sat_az_r)
            )
            cp.clip(cos_gamma, trig_dt(-1.0), trig_dt(1.0), out=cos_gamma)
            gamma_deg = cp.arccos(cos_gamma) * trig_dt(180.0 / _math.pi)
            phi_deg_cp = (
                _ras_boresight_frame_phi_deg(
                    tel_az_r, tel_el_r, sat_az_r, sat_el_r,
                )
                if _ras_is_custom_2d else None
            )
            grx_db = _evaluate_ras_pattern_cp(
                ras_pattern_context, gamma_deg, phi_deg_cp,
            )
            grx_lin = cp.power(pwr_dt(10.0), grx_db.astype(pwr_dt, copy=False) * pwr_dt(0.1))

    # Base per-sat power with FSPL + atmosphere (no RAS-receive gain yet).
    base_per_sat = eirp_effective_w * fspl * atm_lin   # shape (T, S)
    result: dict[str, Any] = {}

    if grx_per_sky_sat is not None:
        # Per-(t, sky, sat) Prx. Memory: T*N_sky*S*4 bytes for float32.
        prx_per_sky_sat = base_per_sat[:, None, :] * grx_per_sky_sat
    else:
        prx_per_sat_1d = base_per_sat
        if not isinstance(grx_lin, float):
            prx_per_sat_1d = prx_per_sat_1d * grx_lin
        elif grx_lin != 1.0:
            prx_per_sat_1d = prx_per_sat_1d * grx_lin
        prx_per_sky_sat = prx_per_sat_1d[:, None, :]   # (T, 1, S) for shape consistency

    # Aggregations now have a real sky axis. Match the directive kernel's
    # (T, 1, N_sky) layout for compatibility with the writer pipeline (which
    # expects axis 2 = sky for total quantities). UEMR is uniform across
    # earth-grid cells, so axis 1 stays size 1.
    if include_prx_total:
        prx_total = cp.sum(prx_per_sky_sat, axis=2)        # (T, N_sky)
        result["Prx_total_W"] = prx_total[:, None, :]      # (T, 1, N_sky)
    if include_per_satellite_prx:
        # Per-sat output contract matches the directive kernel's non-
        # boresight branch: shape (T, S). When the kernel evaluated Grx
        # across N_sky cells, the per-sat value is the MEAN over sky cells
        # — a physically meaningful estimator of "expected Prx contribution
        # from this satellite under random RAS pointing within the
        # operational range". Per-sky variation is still observable via
        # the (T, N_sky, n_cells) aggregates (Prx_total, EPFD).
        if grx_per_sky_sat is not None:
            result["Prx_per_sat_RAS_STATION_W"] = cp.mean(prx_per_sky_sat, axis=1)
        else:
            result["Prx_per_sat_RAS_STATION_W"] = prx_per_sky_sat[:, 0, :]
    if include_epfd:
        epfd = cp.sum(prx_per_sky_sat * pfd_scale, axis=2)  # (T, N_sky)
        result["EPFD_W_m2"] = epfd[:, None, :]              # (T, 1, N_sky)
    if include_total_pfd:
        # PFD at the antenna site is independent of RAS pointing direction
        # (no antenna gain in the PFD definition). Match directive's
        # non-boresight contract: a 1-D (T,) tensor. The writer broadcasts
        # to its storage layout. Using (T, 1, 1) here would mismatch the
        # directive shape and break the multi-system combiner.
        pfd_total = cp.sum(pfd_per_sat, axis=1)
        result["PFD_total_RAS_STATION_W_m2"] = pfd_total
    if include_per_satellite_pfd:
        result["PFD_per_sat_RAS_STATION_W_m2"] = pfd_per_sat
    return result


_leakage_scale_fused_kernel: Any = None
_cap_apply_fused_kernel: Any = None


def _get_cap_apply_fused_kernel():
    """Fused kernel: K × EIRP_peak → peak PFD → safety clamp → cap ratio →
    validity mask → multiply into emitted EIRP.  Replaces 6 CuPy dispatches."""
    global _cap_apply_fused_kernel
    if _cap_apply_fused_kernel is not None:
        return _cap_apply_fused_kernel
    _cap_apply_fused_kernel = cp.ElementwiseKernel(
        "float32 emitted_eirp, float32 k_val, float32 eirp_peak, "
        "float32 cap_limit, bool valid_beam",
        "float32 capped_eirp",
        """
        if (!valid_beam) {
            capped_eirp = emitted_eirp;
            return;
        }
        float peak_pfd = eirp_peak * k_val;
        float peak_safe = peak_pfd > 1.0e-30f ? peak_pfd : 1.0e-30f;
        float cap_factor = cap_limit / peak_safe;
        if (cap_factor > 1.0f) cap_factor = 1.0f;
        capped_eirp = emitted_eirp * cap_factor;
        """,
        "cap_apply_fused",
    )
    return _cap_apply_fused_kernel


def _get_leakage_scale_fused_kernel():
    """Fused kernel: beam-index → cell-index + boresight override + validity
    check + leakage gather + EIRP multiply — replaces ~7 CuPy dispatches."""
    global _leakage_scale_fused_kernel
    if _leakage_scale_fused_kernel is not None:
        return _leakage_scale_fused_kernel
    _leakage_scale_fused_kernel = cp.ElementwiseKernel(
        "int32 beam_idx, bool valid_beam, bool mask_bore, "
        "float32 emitted_eirp_in, "
        "raw float32 leakage_factors, "
        "int32 n_links, int32 ras_cell_idx, int32 n_cells, "
        "int32 use_bore",
        "float32 emitted_eirp_out",
        """
        if (!valid_beam || beam_idx < 0) {
            emitted_eirp_out = emitted_eirp_in;
            return;
        }
        int cell_idx = beam_idx / n_links;
        if (use_bore && mask_bore) {
            cell_idx = ras_cell_idx;
        }
        if (cell_idx < 0 || cell_idx >= n_cells) {
            emitted_eirp_out = 0.0f;
            return;
        }
        emitted_eirp_out = emitted_eirp_in * leakage_factors[cell_idx];
        """,
        "leakage_scale_fused",
    )
    return _leakage_scale_fused_kernel


def _accumulate_ras_power_cp(
    *,
    s1528_pattern_context: GpuS1528PatternContext | GpuS1528Rec12PatternContext | GpuM2101PatternContext,
    ras_pattern_context: (
        GpuRasPatternContext
        | GpuCustomPattern1DContext
        | GpuCustomPattern2DContext
        | None
    ),
    atmosphere_lut_context: GpuAtmosphereLutContext | None,
    sat_topo: Any,
    sat_azel: Any,
    beam_idx: Any,
    power_dtype: Any = None,
    pattern_dtype: Any = None,
    beam_alpha_rad: Any,
    beam_beta_rad: Any,
    telescope_azimuth_deg: Any | None,
    telescope_elevation_deg: Any | None,
    orbit_radius_m_per_sat: Any,
    observer_alt_km: float,
    spectrum_plan_context: GpuSpectrumPlanContext | None,
    cell_spectral_weight: Any | None,
    bandwidth_mhz: float,
    power_input_quantity: str,
    target_pfd_dbw_m2_channel: float | None,
    satellite_ptx_dbw_channel: float | None,
    satellite_eirp_dbw_channel: float | None,
    power_variation_mode: str = "fixed",
    power_range_min_dbw_channel: float | None = None,
    power_range_max_dbw_channel: float | None = None,
    n_links: int,
    ras_service_cell_index: int | None,
    target_alt_km: float,
    use_ras_station_alt_for_co: bool,
    include_epfd: bool,
    include_prx_total: bool,
    include_per_satellite_prx: bool,
    include_total_pfd: bool,
    include_per_satellite_pfd: bool,
    peak_pfd_lut_context: "GpuPeakPfdLutContext | None" = None,
    max_surface_pfd_lin_channel: float | None = None,
    surface_pfd_cap_mode: str = "per_beam",
    surface_pfd_stats_enabled: bool = False,
    precomputed_cap_factor_cp: Any | None = None,
    precomputed_cap_stats: dict[str, float] | None = None,
    visibility_elev_threshold_deg: float = 0.0,
) -> dict[str, Any]:
    # Resolve per-stage precision.  The power stage must be at least fp32
    # because FSPL values (~1e-16) underflow fp16.  Pattern evaluation can
    # use fp16 for the angle/gain arrays when the final accumulation stays
    # in fp32+.  Trig functions that need sub-degree accuracy (arccos for
    # angular distance) always promote to at least fp32 internally.
    pwr_dt = cp.float32
    pat_dt = cp.float32
    if power_dtype is not None:
        _pwr = np.dtype(power_dtype)
        if _pwr == np.dtype(np.float64):
            pwr_dt = cp.float64
        # fp16 not allowed for power — silently promote to fp32
    if pattern_dtype is not None:
        _pat = np.dtype(pattern_dtype)
        if _pat == np.dtype(np.float64):
            pat_dt = cp.float64
        elif _pat == np.dtype(np.float16):
            pat_dt = cp.float16
    # Trig-safe dtype: at least fp32 for sin/cos/arccos precision
    trig_dt = cp.float32 if pat_dt == cp.float16 else pat_dt

    sat_topo_cp = _coerce_step2_topo_tensor_cp(sat_topo, name="sat_topo")
    sat_azel_cp = _coerce_step2_topo_tensor_cp(sat_azel, name="sat_azel")
    if sat_topo_cp.shape[:2] != sat_azel_cp.shape[:2]:
        raise ValueError(
            "sat_topo and sat_azel must align over (T, S); "
            f"got {tuple(sat_topo_cp.shape)!r} vs {tuple(sat_azel_cp.shape)!r}."
        )

    beam_idx_cp = _to_cupy_array(beam_idx, dtype=cp.int32)
    beam_alpha_cp = _to_cupy_array(beam_alpha_rad, dtype=pat_dt)
    beam_beta_cp = _to_cupy_array(beam_beta_rad, dtype=pat_dt)
    if beam_idx_cp.shape != beam_alpha_cp.shape or beam_idx_cp.shape != beam_beta_cp.shape:
        raise ValueError("beam_idx, beam_alpha_rad, and beam_beta_rad must share the same shape.")

    time_count, sat_count = int(sat_topo_cp.shape[0]), int(sat_topo_cp.shape[1])
    include_receive_outputs = bool(
        include_epfd or include_prx_total or include_per_satellite_prx
    )
    include_any_output = bool(
        include_receive_outputs or include_total_pfd or include_per_satellite_pfd
    )
    if not include_any_output:
        raise ValueError("At least one accumulate_ras_power output flag must be enabled.")
    n_links_i = int(max(1, n_links))
    leakage_factors_cp = None
    expected_cell_count = None
    if spectrum_plan_context is not None:
        if spectrum_plan_context.session is not s1528_pattern_context.session:
            raise ValueError("spectrum_plan_context must belong to this session.")
        leakage_factors_cp = _to_cupy_array(
            spectrum_plan_context.d_cell_leakage_factors,
            dtype=cp.float32,
        ).reshape(-1)
        expected_cell_count = int(leakage_factors_cp.size)
    cell_spectral_weight_cp = _normalise_cell_spectral_weight_cupy(
        cell_spectral_weight,
        time_count=int(time_count),
        cell_count=expected_cell_count,
    )

    telescope_az_cp = None
    telescope_el_cp = None
    if include_receive_outputs:
        if ras_pattern_context is None:
            raise ValueError(
                "ras_pattern_context is required when include_epfd, "
                "include_prx_total, or include_per_satellite_prx is enabled."
            )
        if telescope_azimuth_deg is None or telescope_elevation_deg is None:
            raise ValueError(
                "telescope_azimuth_deg and telescope_elevation_deg are required "
                "when receive-side outputs are enabled."
            )
        telescope_az_cp = _to_cupy_array(telescope_azimuth_deg, dtype=cp.float32)
        telescope_el_cp = _to_cupy_array(telescope_elevation_deg, dtype=cp.float32)
        if telescope_az_cp.shape != telescope_el_cp.shape:
            raise ValueError("telescope_azimuth_deg and telescope_elevation_deg must share the same shape.")
        if int(telescope_az_cp.shape[0]) != time_count:
            raise ValueError(
                "Telescope pointing time axis must match sat_topo. "
                f"Expected {time_count}, got {int(telescope_az_cp.shape[0])}."
            )

    quantity_name = str(power_input_quantity).strip().lower()
    if quantity_name not in {"target_pfd", "satellite_ptx", "satellite_eirp"}:
        raise ValueError(
            "power_input_quantity must be 'target_pfd', 'satellite_ptx', or "
            f"'satellite_eirp'; got {power_input_quantity!r}."
        )
    bandwidth_value = float(bandwidth_mhz)
    if not np.isfinite(bandwidth_value) or bandwidth_value <= 0.0:
        raise ValueError("bandwidth_mhz must be finite and > 0.")
    target_pfd_lin_channel = cp.float32(0.0)
    satellite_ptx_lin_channel = cp.float32(0.0)
    satellite_eirp_lin_channel = cp.float32(0.0)
    if quantity_name == "target_pfd":
        if target_pfd_dbw_m2_channel is None or not np.isfinite(float(target_pfd_dbw_m2_channel)):
            raise ValueError("target_pfd_dbw_m2_channel must be finite in target_pfd mode.")
        target_pfd_lin_channel = cp.float32(
            10.0 ** (float(target_pfd_dbw_m2_channel) / 10.0)
        )
    elif quantity_name == "satellite_ptx":
        if satellite_ptx_dbw_channel is None or not np.isfinite(float(satellite_ptx_dbw_channel)):
            raise ValueError("satellite_ptx_dbw_channel must be finite in satellite_ptx mode.")
        satellite_ptx_lin_channel = cp.float32(
            10.0 ** (float(satellite_ptx_dbw_channel) / 10.0)
        )
    else:
        if satellite_eirp_dbw_channel is None or not np.isfinite(float(satellite_eirp_dbw_channel)):
            raise ValueError("satellite_eirp_dbw_channel must be finite in satellite_eirp mode.")
        satellite_eirp_lin_channel = cp.float32(
            10.0 ** (float(satellite_eirp_dbw_channel) / 10.0)
        )

    deg2rad = cp.float32(np.pi / 180.0)
    rad2deg = cp.float32(180.0 / np.pi)
    four_pi = cp.float32(4.0 * np.pi)
    wavelength_m = cp.float32(s1528_pattern_context.wavelength_m)
    # Derive peak gain: S.1528 uses gm_db directly; M.2101 uses element gain + array gain;
    # isotropic (UEMR leakage) has Gmax = 0 dBi = 1.0 linear.
    is_isotropic_ctx = isinstance(s1528_pattern_context, GpuIsotropicPatternContext)
    # Peak linear gain; ``_pattern_peak_gain_linear`` handles every
    # supported context type including Custom-1D / Custom-2D.
    gmax_lin = cp.float32(_pattern_peak_gain_linear(s1528_pattern_context))
    pfd_from_prx_iso_scale = cp.float32((4.0 * np.pi) / (float(s1528_pattern_context.wavelength_m) ** 2))
    earth_radius_m = cp.float32(R_earth.to_value(u.m))

    # --- Surface-PFD cap configuration -----------------------------------
    cap_active = bool(
        peak_pfd_lut_context is not None
        and max_surface_pfd_lin_channel is not None
        and float(max_surface_pfd_lin_channel) > 0.0
        and np.isfinite(float(max_surface_pfd_lin_channel))
    )
    if cap_active:
        if peak_pfd_lut_context.session is not s1528_pattern_context.session:
            raise ValueError("peak_pfd_lut_context must belong to the same session.")
        cap_mode_normalised = str(surface_pfd_cap_mode or "per_beam").strip().lower()
        if cap_mode_normalised not in {"per_beam", "per_satellite"}:
            raise ValueError(
                "surface_pfd_cap_mode must be 'per_beam' or 'per_satellite'; "
                f"got {surface_pfd_cap_mode!r}."
            )
        cap_limit_w = float(max_surface_pfd_lin_channel)
        # Derive the effective ``shell_id_per_sat`` entirely on-device so
        # the power kernel stays GPU-native even when called many times
        # per batch (e.g. once per spectral slab).  For the common
        # single-shell case we short-circuit to a zeros vector; otherwise
        # we broadcast-compare rounded orbit radii against the LUT's
        # per-shell radii.  Both branches avoid host⇄device round trips
        # and Python loops over the satellite axis.  The LUT's shell axis
        # is always axis 0 for both the 1-D ``(n_shells, n_beta)`` and
        # 2-D ``(n_shells, n_alpha, n_beta)`` layouts.
        n_shells_in_lut = int(peak_pfd_lut_context.n_beta > 0) * int(
            peak_pfd_lut_context.d_k_lut.shape[0]
        )
        if n_shells_in_lut == 1:
            cap_shell_id_per_sat_cp = cp.zeros((int(sat_count),), dtype=cp.int32)
        else:
            shell_radii_cp = cp.asarray(
                peak_pfd_lut_context.orbit_radius_m_per_shell, dtype=cp.float64,
            ).reshape(-1)
            shell_cm_cp = cp.rint(shell_radii_cp * cp.float64(100.0)).astype(cp.int64)
            orbit_sat_cp = _to_cupy_array(
                orbit_radius_m_per_sat, dtype=cp.float32,
            ).reshape(-1).astype(cp.float64, copy=False)
            orbit_cm_cp = cp.rint(orbit_sat_cp * cp.float64(100.0)).astype(cp.int64)
            matches_cp = orbit_cm_cp[:, None] == shell_cm_cp[None, :]
            any_match_cp = cp.any(matches_cp, axis=1)
            # Single host sync across the whole sat axis at once.
            if not bool(cp.all(any_match_cp).get()):
                missing_mask = cp.logical_not(any_match_cp)
                bad_sat_cp = orbit_sat_cp[missing_mask]
                bad_host = cp.asnumpy(bad_sat_cp[:5]).tolist()
                raise ValueError(
                    "One or more effective orbit radii do not match any "
                    "shell in peak_pfd_lut_context.orbit_radius_m_per_shell. "
                    f"First mismatches (m): {bad_host!r}. Re-build the "
                    "cap LUT with the full satellite set before running "
                    "the kernel."
                )
            cap_shell_id_per_sat_cp = cp.argmax(matches_cp, axis=1).astype(
                cp.int32, copy=False,
            )
        if int(cap_shell_id_per_sat_cp.size) != int(sat_count):
            raise ValueError(
                "Effective shell mapping size does not match sat_count "
                f"({int(cap_shell_id_per_sat_cp.size)} vs {int(sat_count)})."
            )
        # Per-satellite aggregate cap in the 4-D boresight-avoidance path
        # is supported only via the hoist: the fused direct-EPFD wrapper
        # computes a ``(T, N_sky, S)`` cap factor once per batch and
        # passes it in through ``precomputed_cap_factor_cp``.  Direct
        # callers that hit this function without going through the fused
        # wrapper and without providing a precomputed factor get a clear
        # error instead of a silently-wrong result.
        if (
            cap_mode_normalised == "per_satellite"
            and beam_idx_cp.ndim == 4
            and precomputed_cap_factor_cp is None
        ):
            raise NotImplementedError(
                "surface_pfd_cap_mode='per_satellite' in the 4-D "
                "boresight-avoidance path requires the hoisted cap factor "
                "from accumulate_direct_epfd_from_link_library. Direct "
                "callers must either switch to 'per_beam' mode, disable "
                "boresight avoidance, or pass ``precomputed_cap_factor_cp`` "
                "with shape (T, N_sky, S)."
            )
    else:
        cap_mode_normalised = "per_beam"
        cap_limit_w = 0.0
        cap_shell_id_per_sat_cp = None
    cap_stats_accum: dict[str, Any] = {
        "n_beams_capped": 0,
        "cap_db_sum_over_capped": 0.0,
        "cap_db_max": 0.0,
    }

    def _finalize_cap_stats(result_dict: dict[str, Any]) -> dict[str, Any]:
        """Attach scalar surface-PFD cap stats to ``result_dict`` in place.

        Only runs when the caller requested stats and the cap was enabled.
        Values are packaged as 0-d NumPy arrays (not bare scalars) so the
        session wrapper's host-copy path — which dispatches on array-like
        types — can pass them through unchanged to the HDF5 writer.
        """
        if not (cap_active and surface_pfd_stats_enabled):
            return result_dict
        n_capped = int(cap_stats_accum["n_beams_capped"])
        sum_db = float(cap_stats_accum["cap_db_sum_over_capped"])
        max_db = float(cap_stats_accum["cap_db_max"])
        mean_db = (sum_db / float(n_capped)) if n_capped > 0 else 0.0
        result_dict["surface_pfd_cap_n_beams_capped"] = np.asarray(n_capped, dtype=np.int64)
        result_dict["surface_pfd_cap_mean_cap_db"] = np.asarray(mean_db, dtype=np.float32)
        result_dict["surface_pfd_cap_max_cap_db"] = np.asarray(max_db, dtype=np.float32)
        return result_dict

    if beam_idx_cp.ndim == 4:
        if int(beam_idx_cp.shape[0]) != time_count or int(beam_idx_cp.shape[2]) != sat_count:
            raise ValueError(
                "Skycell-dependent beam tensors must align with sat_topo over (T, S); "
                f"got {tuple(beam_idx_cp.shape)!r} for sat_topo {tuple(sat_topo_cp.shape)!r}."
            )
        if include_receive_outputs and int(beam_idx_cp.shape[1]) != int(telescope_az_cp.shape[1]):
            raise ValueError(
                "Skycell-dependent beam tensors must align with the telescope sky-cell axis; "
                f"got beam sky axis {int(beam_idx_cp.shape[1])} and telescope axis {int(telescope_az_cp.shape[1])}."
            )

        sky_count = int(beam_idx_cp.shape[1])
        alpha0_rad = cp.remainder(
            sat_azel_cp[..., 0].astype(trig_dt, copy=False) * trig_dt(np.pi / 180.0),
            trig_dt(2.0 * np.pi),
        )
        beta0_rad = sat_azel_cp[..., 1].astype(trig_dt, copy=False) * trig_dt(np.pi / 180.0)
        sinb0 = cp.sin(beta0_rad)
        cosb0 = cp.cos(beta0_rad)
        range_m = sat_topo_cp[..., 2].astype(pwr_dt, copy=False) * pwr_dt(1000.0)
        sat_elevation_deg = sat_topo_cp[..., 1].astype(pwr_dt, copy=False)
        vis_horizon = sat_elevation_deg > pwr_dt(float(visibility_elev_threshold_deg))
        orbit_radius = _to_cupy_array(orbit_radius_m_per_sat, dtype=pwr_dt).reshape(-1)
        if int(orbit_radius.size) != sat_count:
            raise ValueError(
                "orbit_radius_m_per_sat must have length equal to the satellite axis "
                f"{sat_count}, got {int(orbit_radius.size)}."
            )
        if atmosphere_lut_context is None:
            atm_ras_station = cp.ones((time_count, sat_count), dtype=pwr_dt)
        else:
            atm_ras_station = _lookup_atmosphere_lut_cp(
                atmosphere_lut_context,
                sat_elevation_deg,
                altitude_km=observer_alt_km,
            ).astype(pwr_dt, copy=False)
        wavelength_w = pwr_dt(float(wavelength_m))
        four_pi_w = pwr_dt(4.0 * np.pi)
        fspl_lin = cp.power(wavelength_w / (four_pi_w * range_m), pwr_dt(2.0))
        fspl_lin *= atm_ras_station

        valid_beam = beam_idx_cp >= 0
        # Gate on satellite visibility BEFORE extracting active indices.
        # This skips pattern + geometry + EIRP computation for invisible
        # satellites (~40% of beam slots typically), giving a large
        # reduction in power-stage work.  vis_horizon is (T, S), broadcast
        # to (T, N_sky, S, K) via [:, None, :, None].
        valid_beam &= vis_horizon[:, None, :, None]
        active_t_cp, active_sky_cp, active_sat_cp, active_slot_cp = cp.nonzero(valid_beam)
        if int(active_t_cp.size) > 0:
            # Pattern stage: trig in trig_dt, gain output in pat_dt
            active_alpha_cp = beam_alpha_cp[
                active_t_cp, active_sky_cp, active_sat_cp, active_slot_cp,
            ].astype(trig_dt, copy=False)
            active_beta_cp = beam_beta_cp[
                active_t_cp, active_sky_cp, active_sat_cp, active_slot_cp,
            ].astype(trig_dt, copy=False)
            alpha0_active_cp = alpha0_rad[active_t_cp, active_sat_cp]
            sinb0_active_cp = sinb0[active_t_cp, active_sat_cp]
            cosb0_active_cp = cosb0[active_t_cp, active_sat_cp]
            # Fused trig: sin/cos β, Δα, sin/cos Δα, cos γ_tx in one launch.
            # Replaces 9 separate CuPy operations.
            if trig_dt == cp.float32:
                _trig_4d_kernel = _get_4d_trig_kernel()
                beam_sinb_cp, beam_cosb_cp, cos_gamma_tx_cp, sin_da_cp, cos_da_cp = (
                    _trig_4d_kernel(
                        active_alpha_cp, active_beta_cp,
                        alpha0_active_cp, sinb0_active_cp, cosb0_active_cp,
                    )
                )
            else:
                # Non-fp32 trig: keep unfused path (kernel is fp32-only)
                beam_sinb_cp = cp.sin(active_beta_cp)
                beam_cosb_cp = cp.cos(active_beta_cp)
                delta_a_cp = alpha0_active_cp - active_alpha_cp
                cos_da_cp = cp.cos(delta_a_cp)
                cos_gamma_tx_cp = cosb0_active_cp * beam_cosb_cp + sinb0_active_cp * beam_sinb_cp * cos_da_cp
                cp.clip(cos_gamma_tx_cp, trig_dt(-1.0), trig_dt(1.0), out=cos_gamma_tx_cp)
            if is_isotropic_ctx:
                # Isotropic UEMR leakage: Gtx = 0 dBi ⇒ abs=rel=1.0 everywhere.
                gtx_abs_lin_cp = cp.ones(active_t_cp.shape, dtype=pwr_dt)
                gtx_rel_lin_cp = gtx_abs_lin_cp
            elif isinstance(s1528_pattern_context, GpuCustomPattern2DContext):
                # Custom 2-D: MEGA pattern-eval kernel (lever #2).
                # Takes raw beam trig directly (skips x_body/y_body
                # intermediate compute) and emits BOTH rel and abs
                # linear gain in ONE launch — replaces 3-5 launches
                # (x_body mult, y_body arithmetic, body-frame kernel,
                # gmax multiply) with 1.
                sin_da_cp_c2d = (
                    sin_da_cp if trig_dt == cp.float32
                    else cp.sin(alpha0_active_cp - active_alpha_cp)
                )
                if pwr_dt in (cp.float32, cp.float64):
                    gtx_rel_lin_cp, gtx_abs_lin_cp = (
                        _evaluate_custom_2d_from_beam_trig_to_rel_abs_linear(
                            s1528_pattern_context,
                            beam_sinb_cp, beam_cosb_cp,
                            sin_da_cp_c2d, cos_da_cp,
                            sinb0_active_cp, cosb0_active_cp,
                            cos_gamma_tx_cp,
                            inv_gmax_lin=1.0 / float(gmax_lin),
                            compute_dtype=pwr_dt,
                        )
                    )
                else:
                    # dead branch (pwr_dt always fp32 or fp64 today)
                    # kept as a sentinel; fallback below handles
                    # fp16/other compute dtype using body-frame path.
                    x_body_cp = beam_cosb_cp * sin_da_cp_c2d
                    y_body_cp = (
                        cosb0_active_cp * beam_sinb_cp
                        - sinb0_active_cp * beam_cosb_cp * cos_da_cp
                    )
                    z_body_cp = cos_gamma_tx_cp
                    # fp16 / other compute dtype: body-frame kernel not
                    # offered (fp16 power underflows FSPL downstream
                    # anyway).  Fall back to the unfused path.
                    if s1528_pattern_context.grid_mode == "az_el":
                        az_rad_fb = cp.arctan2(x_body_cp, z_body_cp)
                        y_clip_fb = cp.clip(y_body_cp, trig_dt(-1.0), trig_dt(1.0))
                        el_rad_fb = cp.arcsin(y_clip_fb)
                        a0_deg_fb = (az_rad_fb * trig_dt(180.0 / np.pi)).astype(pat_dt, copy=False)
                        a1_deg_fb = (el_rad_fb * trig_dt(180.0 / np.pi)).astype(pat_dt, copy=False)
                    else:
                        z_clip_fb = cp.clip(z_body_cp, trig_dt(-1.0), trig_dt(1.0))
                        th_rad_fb = cp.arccos(z_clip_fb)
                        ph_rad_fb = cp.arctan2(y_body_cp, x_body_cp)
                        a0_deg_fb = (th_rad_fb * trig_dt(180.0 / np.pi)).astype(pat_dt, copy=False)
                        a1_deg_fb = (ph_rad_fb * trig_dt(180.0 / np.pi)).astype(pat_dt, copy=False)
                    gtx_db_cp = _evaluate_custom_2d_pattern_cp(
                        s1528_pattern_context, a0_deg_fb, a1_deg_fb,
                    )
                    gtx_abs_lin_cp = cp.power(
                        pwr_dt(10.0),
                        gtx_db_cp.astype(pwr_dt, copy=False) * pwr_dt(0.1),
                    )
                    gtx_rel_lin_cp = gtx_abs_lin_cp * pwr_dt(
                        1.0 / float(gmax_lin)
                    )
            elif isinstance(s1528_pattern_context, GpuCustomPattern1DContext):
                # Custom 1-D axisymmetric: drop-in for symmetric S.1528 —
                # same cos_gamma_tx → theta pipeline, same fused LUT kernel.
                gtx_offset_deg_cp = (
                    cp.arccos(cos_gamma_tx_cp) * trig_dt(180.0 / np.pi)
                ).astype(pat_dt, copy=False)
                if pwr_dt == cp.float32:
                    gtx_rel_lin_cp = _evaluate_custom_1d_pattern_cp_to_linear(
                        s1528_pattern_context,
                        gtx_offset_deg_cp,
                        inv_gmax_lin=1.0 / float(gmax_lin),
                    )
                    gtx_abs_lin_cp = gtx_rel_lin_cp * pwr_dt(float(gmax_lin))
                else:
                    gtx_db_cp = _evaluate_custom_1d_pattern_cp(
                        s1528_pattern_context, gtx_offset_deg_cp,
                    )
                    gtx_abs_lin_cp = cp.power(
                        pwr_dt(10.0), gtx_db_cp.astype(pwr_dt, copy=False) * pwr_dt(0.1),
                    )
                    gtx_rel_lin_cp = gtx_abs_lin_cp * pwr_dt(1.0 / float(gmax_lin))
            elif isinstance(s1528_pattern_context, GpuM2101PatternContext):
                # M.2101 phased array: need satellite-frame az/el for both
                # the RAS direction (from sat_azel) and beam steering direction
                # (from beam alpha/beta).
                ras_az_cp = sat_azel_cp[active_t_cp, active_sat_cp, 0].astype(cp.float32, copy=False)
                ras_el_cp = sat_azel_cp[active_t_cp, active_sat_cp, 1].astype(cp.float32, copy=False)
                steer_az_cp = (active_alpha_cp * trig_dt(180.0 / np.pi)).astype(cp.float32, copy=False)
                steer_el_cp = (active_beta_cp * trig_dt(180.0 / np.pi)).astype(cp.float32, copy=False)
                if _pattern_eval_mode == "lut" and pwr_dt == cp.float32:
                    gtx_rel_lin_cp = _evaluate_m2101_pattern_cp_lut_to_linear(
                        s1528_pattern_context, ras_az_cp, ras_el_cp, steer_az_cp, steer_el_cp,
                        inv_gmax_lin=1.0 / float(gmax_lin),
                    ).astype(pwr_dt, copy=False)
                    gtx_abs_lin_cp = gtx_rel_lin_cp * pwr_dt(float(gmax_lin))
                else:
                    gtx_db_cp = _evaluate_m2101_pattern_cp(
                        s1528_pattern_context, ras_az_cp, ras_el_cp, steer_az_cp, steer_el_cp,
                    )
                    gtx_abs_lin_cp = cp.power(pwr_dt(10.0), gtx_db_cp.astype(pwr_dt, copy=False) * pwr_dt(0.1))
                    gtx_rel_lin_cp = gtx_abs_lin_cp * pwr_dt(1.0 / float(gmax_lin))
            else:
                gtx_offset_deg_cp = (cp.arccos(cos_gamma_tx_cp) * trig_dt(180.0 / np.pi)).astype(pat_dt, copy=False)
                if getattr(s1528_pattern_context, "is_2d", False):
                    # Asymmetric S.1528 Rec 1.4: need azimuth phi around the
                    # beam boresight. Derived from spherical geometry with
                    # the boresight as pole — phi=0 aligned with the lr axis
                    # (conventionally horizontal / azimuthal). The 4-fold
                    # symmetry of the pattern in phi means the quadrant
                    # choice does not matter (the LUT folds arbitrary phi).
                    _sin_da_asym = sin_da_cp if trig_dt == cp.float32 else cp.sin(delta_a_cp)
                    phi_rad_cp = cp.arctan2(
                        cosb0_active_cp * beam_sinb_cp
                        - sinb0_active_cp * beam_cosb_cp * cos_da_cp,
                        beam_cosb_cp * _sin_da_asym,
                    )
                    phi_deg_cp = (phi_rad_cp * trig_dt(180.0 / np.pi)).astype(pat_dt, copy=False)
                    if pwr_dt == cp.float32:
                        # Fused 2-D LUT + dB→linear + inv_gmax in one kernel,
                        # matching the 1-D fused path and the M.2101 kernel.
                        # Avoids a separate ``cp.power(10, g/10) * inv_gmax``
                        # round-trip that was ~2× the LUT-kernel cost.
                        gtx_rel_lin_cp = _evaluate_s1528_pattern_cp_lut_2d_to_linear(
                            s1528_pattern_context,
                            gtx_offset_deg_cp, phi_deg_cp,
                            inv_gmax_lin=1.0 / float(gmax_lin),
                        )
                        gtx_abs_lin_cp = gtx_rel_lin_cp * pwr_dt(float(gmax_lin))
                    else:
                        gtx_db_cp = _evaluate_s1528_pattern_cp(
                            s1528_pattern_context, gtx_offset_deg_cp, phi_deg=phi_deg_cp,
                        )
                        gtx_abs_lin_cp = cp.power(pwr_dt(10.0), gtx_db_cp.astype(pwr_dt, copy=False) * pwr_dt(0.1))
                        gtx_rel_lin_cp = gtx_abs_lin_cp * pwr_dt(1.0 / float(gmax_lin))
                elif _pattern_eval_mode == "lut" and pwr_dt == cp.float32:
                    # Fused path: LUT interpolation + dB→linear + relative gain in 1 kernel
                    gtx_rel_lin_cp = _evaluate_s1528_pattern_cp_lut_1d_to_linear(
                        s1528_pattern_context,
                        gtx_offset_deg_cp,
                        inv_gmax_lin=1.0 / float(gmax_lin),
                    )
                    gtx_abs_lin_cp = gtx_rel_lin_cp * pwr_dt(float(gmax_lin))
                else:
                    gtx_db_cp = _evaluate_s1528_pattern_cp(s1528_pattern_context, gtx_offset_deg_cp)
                    gtx_abs_lin_cp = cp.power(pwr_dt(10.0), gtx_db_cp.astype(pwr_dt, copy=False) * pwr_dt(0.1))
                    gtx_rel_lin_cp = gtx_abs_lin_cp * pwr_dt(1.0 / float(gmax_lin))

            # Power stage: geometry, EIRP, accumulation in pwr_dt
            earth_r = pwr_dt(float(earth_radius_m))
            target_pfd_w = pwr_dt(float(target_pfd_lin_channel))
            range_active_cp = range_m[active_t_cp, active_sat_cp]
            orbit_active_cp = orbit_radius[active_sat_cp]
            atm_ras_active_cp = atm_ras_station[active_t_cp, active_sat_cp]
            mask_bore_cp = active_slot_cp == 0

            # Fused geometry+EIRP kernel: replaces ~15 separate CuPy ops
            # (term, disc, hit_earth, cos_positive, valid_geom, d_target,
            # e_target, cos_e, clip, arccos, max, EIRP) with one launch.
            if pwr_dt == cp.float32:
                _eirp_4d_kernel = _get_4d_eirp_kernel()
                _atm_elev_min = cp.float32(
                    atmosphere_lut_context.elev_min_deg if atmosphere_lut_context is not None else 0.0
                )
                d_target_geom_m_cp, e_target_deg_cp, valid_geom_cp, boresight_eirp_raw_cp = (
                    _eirp_4d_kernel(
                        beam_sinb_cp.astype(cp.float32, copy=False),
                        beam_cosb_cp.astype(cp.float32, copy=False),
                        orbit_active_cp, earth_r,
                        _atm_elev_min,
                        range_active_cp, atm_ras_active_cp,
                        pwr_dt(float(target_pfd_lin_channel) * 4.0 * np.pi),
                        bool(use_ras_station_alt_for_co), mask_bore_cp,
                    )
                )
                # Apply atmosphere correction for non-boresight geometry EIRP
                if atmosphere_lut_context is not None:
                    atm_target_cp = _lookup_atmosphere_lut_cp(
                        atmosphere_lut_context, e_target_deg_cp, altitude_km=target_alt_km,
                    ).astype(pwr_dt, copy=False)
                    atm_target_safe_cp = cp.where(valid_geom_cp, atm_target_cp, pwr_dt(1.0))
                    # Geometry EIRP needs atm correction: divide out for non-boresight
                    boresight_eirp_cp = cp.where(
                        mask_bore_cp,
                        boresight_eirp_raw_cp,
                        cp.where(valid_geom_cp, boresight_eirp_raw_cp / atm_target_safe_cp, pwr_dt(0.0)),
                    )
                else:
                    boresight_eirp_cp = boresight_eirp_raw_cp
            else:
                # Non-fp32: keep unfused path
                beam_cosb_w = beam_cosb_cp.astype(pwr_dt, copy=False)
                beam_sinb_w = beam_sinb_cp.astype(pwr_dt, copy=False)
                term_cp = orbit_active_cp * beam_cosb_w
                disc_cp = term_cp * term_cp - (orbit_active_cp * orbit_active_cp - earth_r * earth_r)
                hit_earth_cp = disc_cp >= pwr_dt(0.0)
                cos_positive_cp = beam_cosb_w > pwr_dt(0.0)
                valid_geom_cp = hit_earth_cp & cos_positive_cp
                d_target_geom_m_cp = term_cp - cp.sqrt(cp.where(valid_geom_cp, disc_cp, pwr_dt(0.0)))
                if atmosphere_lut_context is None:
                    atm_target_safe_cp = cp.ones((int(active_t_cp.size),), dtype=pwr_dt)
                else:
                    cos_e_target_cp = cp.clip(
                        (orbit_active_cp / earth_r) * beam_sinb_w,
                        pwr_dt(0.0), pwr_dt(1.0),
                    )
                    e_target_deg_cp = (
                        cp.arccos(cos_e_target_cp.astype(trig_dt, copy=False)) * trig_dt(180.0 / np.pi)
                    ).astype(pwr_dt, copy=False)
                    e_target_deg_cp = cp.where(
                        valid_geom_cp,
                        cp.maximum(e_target_deg_cp, pwr_dt(atmosphere_lut_context.elev_min_deg)),
                        pwr_dt(0.0),
                    )
                    atm_target_cp = _lookup_atmosphere_lut_cp(
                        atmosphere_lut_context, e_target_deg_cp, altitude_km=target_alt_km,
                    ).astype(pwr_dt, copy=False)
                    atm_target_safe_cp = cp.where(valid_geom_cp, atm_target_cp, pwr_dt(1.0))
                boresight_eirp_geom_cp = cp.where(
                    valid_geom_cp,
                    target_pfd_w * four_pi_w * d_target_geom_m_cp * d_target_geom_m_cp / atm_target_safe_cp,
                    pwr_dt(0.0),
                )
                atm_co_cp = atm_ras_active_cp if use_ras_station_alt_for_co else pwr_dt(1.0)
                boresight_eirp_co_cp = target_pfd_w * four_pi_w * range_active_cp * range_active_cp / atm_co_cp
                boresight_eirp_cp = cp.where(mask_bore_cp, boresight_eirp_co_cp, boresight_eirp_geom_cp)

            # Compute variable power for satellite_eirp / satellite_ptx modes
            _var_mode = str(power_variation_mode or "fixed").strip().lower()
            _var_power_lin_cp: Any = None
            if _var_mode != "fixed" and quantity_name in {"satellite_eirp", "satellite_ptx"}:
                _pmin = float(power_range_min_dbw_channel or 0.0)
                _pmax = float(power_range_max_dbw_channel or 0.0)
                if _var_mode == "slant_range":
                    kernel = _get_slant_range_power_kernel()
                    _var_power_lin_cp = kernel(
                        range_active_cp.astype(cp.float32, copy=False),
                        orbit_active_cp.astype(cp.float32, copy=False),
                        cp.float32(float(earth_radius_m)),
                        cp.float32(0.0),  # sin(0°) — conservative: use 0° min elev for max range
                        cp.float32(1.0),  # cos(0°)
                        cp.float32(_pmin),
                        cp.float32(_pmax),
                    ).astype(pwr_dt, copy=False)
                elif _var_mode == "uniform_random":
                    _rand_db = cp.float32(_pmin) + (cp.float32(_pmax) - cp.float32(_pmin)) * cp.random.random(
                        active_sat_cp.shape, dtype=cp.float32,
                    )
                    _var_power_lin_cp = cp.power(pwr_dt(10.0), _rand_db.astype(pwr_dt, copy=False) * pwr_dt(0.1))

            if quantity_name == "target_pfd":
                emitted_eirp_cp = boresight_eirp_cp * gtx_rel_lin_cp
            elif quantity_name == "satellite_eirp":
                if _var_power_lin_cp is not None:
                    emitted_eirp_cp = _var_power_lin_cp * gtx_rel_lin_cp
                else:
                    emitted_eirp_cp = pwr_dt(float(satellite_eirp_lin_channel)) * gtx_rel_lin_cp
            else:
                if _var_power_lin_cp is not None:
                    emitted_eirp_cp = _var_power_lin_cp * gtx_abs_lin_cp
                else:
                    emitted_eirp_cp = pwr_dt(float(satellite_ptx_lin_channel)) * gtx_abs_lin_cp

            # Surface-PFD cap — must happen BEFORE the spectral / leakage
            # scaling below because the cap targets the radiated EIRP
            # from the antenna itself, not the post-spectrum version.
            if cap_active:
                # Fast path: the fused direct-EPFD wrapper has already
                # computed the cap factor for the whole slab (either
                # per-beam ``(T, N_sky, S, K)`` or per-satellite
                # ``(T, N_sky, S)``).  Gather it at the active indices
                # and apply directly — no K lookup, no EIRP recomputation.
                if precomputed_cap_factor_cp is not None:
                    precomp_cp = precomputed_cap_factor_cp.astype(pwr_dt, copy=False)
                    expected_per_beam_shape = (
                        int(time_count), int(sky_count),
                        int(sat_count), int(beam_idx_cp.shape[3]),
                    )
                    expected_per_sat_shape = (
                        int(time_count), int(sky_count), int(sat_count),
                    )
                    if tuple(precomp_cp.shape) == expected_per_beam_shape:
                        cap_factor_active_cp = precomp_cp[
                            active_t_cp, active_sky_cp,
                            active_sat_cp, active_slot_cp,
                        ]
                    elif tuple(precomp_cp.shape) == expected_per_sat_shape:
                        cap_factor_active_cp = precomp_cp[
                            active_t_cp, active_sky_cp, active_sat_cp,
                        ]
                    else:
                        raise ValueError(
                            "precomputed_cap_factor_cp in the 4-D "
                            "boresight-avoidance path must have shape "
                            f"{expected_per_beam_shape!r} (per-beam) or "
                            f"{expected_per_sat_shape!r} (per-satellite); "
                            f"got {tuple(precomp_cp.shape)!r}."
                        )
                    emitted_eirp_cp = emitted_eirp_cp * cap_factor_active_cp.astype(
                        pwr_dt, copy=False,
                    )
                    if (
                        surface_pfd_stats_enabled
                        and precomputed_cap_stats is not None
                    ):
                        cap_stats_accum["n_beams_capped"] = (
                            int(cap_stats_accum["n_beams_capped"])
                            + int(precomputed_cap_stats.get("n_capped", 0))
                        )
                        cap_stats_accum["cap_db_sum_over_capped"] = (
                            float(cap_stats_accum["cap_db_sum_over_capped"])
                            + float(precomputed_cap_stats.get("cap_db_sum", 0.0))
                        )
                        cap_stats_accum["cap_db_max"] = float(
                            max(
                                float(cap_stats_accum["cap_db_max"]),
                                float(precomputed_cap_stats.get("cap_db_max", 0.0)),
                            )
                        )
                else:
                    # In-kernel per-beam cap: operate on the compact
                    # ``(active,)`` arrays directly.  Per-satellite
                    # aggregate in this path was already rejected by the
                    # cap-config validation block above (needs the
                    # hoisted precomputed factor).
                    if quantity_name == "target_pfd":
                        eirp_peak_cp = boresight_eirp_cp  # (active_count,) already
                    elif quantity_name == "satellite_eirp":
                        if _var_power_lin_cp is not None:
                            eirp_peak_cp = _var_power_lin_cp
                        else:
                            eirp_peak_cp = pwr_dt(float(satellite_eirp_lin_channel))
                    else:  # satellite_ptx
                        if _var_power_lin_cp is not None:
                            eirp_peak_cp = _var_power_lin_cp * pwr_dt(float(gmax_lin))
                        else:
                            eirp_peak_cp = pwr_dt(
                                float(satellite_ptx_lin_channel) * float(gmax_lin)
                            )
                    shell_per_active_cp = cap_shell_id_per_sat_cp[active_sat_cp]
                    k_active_cp = _lookup_peak_pfd_k_any_cp(
                        peak_pfd_lut_context,
                        active_alpha_cp,
                        active_beta_cp,
                        shell_per_active_cp,
                    ).astype(pwr_dt, copy=False)
                    peak_pfd_per_beam_cp = eirp_peak_cp * k_active_cp
                    limit_w_cp = pwr_dt(cap_limit_w)
                    peak_safe_cp = cp.maximum(peak_pfd_per_beam_cp, pwr_dt(1.0e-30))
                    cap_factor_active_cp = cp.minimum(
                        pwr_dt(1.0), limit_w_cp / peak_safe_cp,
                    ).astype(pwr_dt, copy=False)
                    emitted_eirp_cp = emitted_eirp_cp * cap_factor_active_cp

                    if surface_pfd_stats_enabled:
                        capped_mask_cp = cap_factor_active_cp < pwr_dt(1.0 - 1.0e-6)
                        cap_db_cp = cp.where(
                            capped_mask_cp,
                            pwr_dt(-10.0) * cp.log10(
                                cp.maximum(cap_factor_active_cp, pwr_dt(1.0e-30))
                            ),
                            pwr_dt(0.0),
                        )
                        _stats_4d = cp.array([
                            cp.count_nonzero(capped_mask_cp).astype(cp.float32),
                            cp.sum(cap_db_cp).astype(cp.float32),
                            (cp.max(cap_db_cp).astype(cp.float32)
                             if int(cap_db_cp.size) > 0 else cp.float32(0.0)),
                        ])
                        _sh = _stats_4d.get()
                        cap_stats_accum["n_beams_capped"] = (
                            int(cap_stats_accum["n_beams_capped"]) + int(_sh[0])
                        )
                        cap_stats_accum["cap_db_sum_over_capped"] = (
                            float(cap_stats_accum["cap_db_sum_over_capped"]) + float(_sh[1])
                        )
                        cap_stats_accum["cap_db_max"] = float(
                            max(float(cap_stats_accum["cap_db_max"]), float(_sh[2]))
                        )

            if cell_spectral_weight_cp is not None:
                source_cell_idx_cp = (
                    beam_idx_cp[active_t_cp, active_sky_cp, active_sat_cp, active_slot_cp,
                    ].astype(cp.int64, copy=False) // np.int64(n_links_i)
                ).astype(cp.int32, copy=False)
                valid_source_cp = (source_cell_idx_cp >= 0) & (source_cell_idx_cp < int(cell_spectral_weight_cp.shape[1]))
                spectral_scale_cp = cp.where(
                    valid_source_cp, cell_spectral_weight_cp[active_t_cp, source_cell_idx_cp], pwr_dt(0.0),
                ).astype(pwr_dt, copy=False)
                emitted_eirp_cp *= spectral_scale_cp
            elif leakage_factors_cp is not None:
                source_cell_idx_cp = (
                    beam_idx_cp[active_t_cp, active_sky_cp, active_sat_cp, active_slot_cp,
                    ].astype(cp.int64, copy=False) // np.int64(n_links_i)
                ).astype(cp.int32, copy=False)
                valid_source_cp = (source_cell_idx_cp >= 0) & (source_cell_idx_cp < int(leakage_factors_cp.size))
                leakage_scale_cp = cp.where(
                    valid_source_cp, leakage_factors_cp[source_cell_idx_cp], pwr_dt(0.0),
                ).astype(pwr_dt, copy=False)
                emitted_eirp_cp *= leakage_scale_cp

            group_key_cp = _get_group_key_encode_kernel()(
                active_t_cp.astype(cp.int32, copy=False),
                active_sky_cp.astype(cp.int32, copy=False),
                active_sat_cp.astype(cp.int32, copy=False),
                np.int32(int(sky_count)),
                np.int32(int(sat_count)),
            )
            # Compact per-(t, sky, sat) reduction.  The earlier version built
            # a dense ``(T*N_sky*S,)`` bincount buffer here and then ran
            # ``cp.nonzero`` over the whole thing to find the populated
            # groups.  At production sizes (T=65, N_sky≈500-1734, S=3360)
            # that buffer is 400 MB-1.5 GB of transient scratch, and the
            # nonzero sweep has to scan it end-to-end.  Only N_unique ≤
            # N_active groups are actually populated (≈ 10-100 k), so use
            # ``cp.unique`` to get the compact key set and ``bincount`` on
            # the inverse map for an O(N_unique) reduction.  Downstream
            # consumers still treat ``active_group_flat_cp`` as the set of
            # global flat keys (sorted ascending), so no behavioural change.
            unique_keys_cp, inverse_cp = cp.unique(group_key_cp, return_inverse=True)
            eirp_sum_active_cp = cp.bincount(
                inverse_cp,
                weights=emitted_eirp_cp.astype(pwr_dt, copy=False),
                minlength=int(unique_keys_cp.size),
            ).astype(pwr_dt, copy=False)
            active_group_flat_cp = unique_keys_cp.astype(cp.int64, copy=False)
        else:
            active_group_flat_cp = cp.empty((0,), dtype=cp.int64)
            eirp_sum_active_cp = cp.empty((0,), dtype=pwr_dt)
        active_group_key_cp = cp.empty((0,), dtype=cp.int32)
        active_group_scale_cp = cp.empty((0,), dtype=pwr_dt)
        active_group_t_cp = cp.empty((0,), dtype=cp.int32)
        active_group_sky_cp = cp.empty((0,), dtype=cp.int32)
        active_group_sat_cp = cp.empty((0,), dtype=cp.int32)
        if int(active_group_flat_cp.size) > 0:
            sky_sat_stride = np.int64(int(sky_count) * int(sat_count))
            active_group_t_cp, active_group_sky_cp, active_group_sat_cp = _get_group_key_decode_kernel()(
                active_group_flat_cp,
                np.int64(sky_sat_stride),
                np.int64(int(sat_count)),
            )
            active_group_scale_cp = (
                eirp_sum_active_cp
                * fspl_lin[active_group_t_cp, active_group_sat_cp]
            )
            active_group_scale_cp *= vis_horizon[active_group_t_cp, active_group_sat_cp].astype(pwr_dt, copy=False)
            active_group_mask_cp = active_group_scale_cp > pwr_dt(0.0)
            # Apply mask unconditionally — empty result is handled by size check below
            active_group_flat_cp = active_group_flat_cp[active_group_mask_cp]
            active_group_t_cp = active_group_t_cp[active_group_mask_cp]
            active_group_sky_cp = active_group_sky_cp[active_group_mask_cp]
            active_group_sat_cp = active_group_sat_cp[active_group_mask_cp]
            active_group_scale_cp = active_group_scale_cp[active_group_mask_cp]
            active_group_key_cp = (
                active_group_t_cp * np.int32(int(sky_count)) + active_group_sky_cp
            ).astype(cp.int32, copy=False)
        pfd_scale = pwr_dt(float(pfd_from_prx_iso_scale))
        result: dict[str, Any] = {}
        if include_receive_outputs:
            prx_group_cp = cp.empty((0,), dtype=pwr_dt)
            if int(active_group_flat_cp.size) > 0:
                # Receive-side: angular distance + RAS pattern + dB→linear
                tel_az_deg_cp = telescope_az_cp[active_group_t_cp, active_group_sky_cp].astype(cp.float32, copy=False)
                tel_el_deg_cp = telescope_el_cp[active_group_t_cp, active_group_sky_cp].astype(cp.float32, copy=False)
                sat_az_deg_cp = sat_topo_cp[active_group_t_cp, active_group_sat_cp, 0].astype(cp.float32, copy=False)
                sat_el_deg_cp = sat_elevation_deg[active_group_t_cp, active_group_sat_cp].astype(cp.float32, copy=False)
                if pwr_dt == cp.float32 and isinstance(
                    ras_pattern_context, GpuRasPatternContext,
                ):
                    # Fused path: angular distance + RA.1631 RAS pattern +
                    # dB→linear in 1 kernel. Only applies to the native
                    # RA.1631 context — Custom-1D / Custom-2D contexts
                    # don't expose the closed-form (D/λ, η) parameters
                    # the fused kernel needs, so they fall through to
                    # the per-op path below.
                    d_wlen = np.float32(ras_pattern_context.diameter_m / ras_pattern_context.wavelength_m)
                    _gmax_ras = np.float32(10.0 * np.log10(ras_pattern_context.eta_a_dimless * (np.pi * d_wlen) ** 2))
                    _g1_ras = np.float32(-1.0 + 15.0 * np.log10(d_wlen))
                    _phi_m_ras = np.float32(20.0 / d_wlen * np.sqrt(_gmax_ras - _g1_ras))
                    _phi_r_ras = np.float32(15.85 * d_wlen ** -0.6)
                    kernel = _get_rx_angular_distance_ras_lin_kernel()
                    grx_lin_cp = kernel(
                        tel_az_deg_cp, tel_el_deg_cp,
                        sat_az_deg_cp, sat_el_deg_cp,
                        d_wlen, _gmax_ras, _g1_ras, _phi_m_ras, _phi_r_ras,
                    )
                else:
                    # Fallback: separate operations for fp64 precision
                    _d2r = trig_dt(np.pi / 180.0)
                    _r2d = trig_dt(180.0 / np.pi)
                    tel_az_rad_cp = tel_az_deg_cp.astype(trig_dt, copy=False) * _d2r
                    tel_el_rad_cp = tel_el_deg_cp.astype(trig_dt, copy=False) * _d2r
                    sat_az_rad_cp = sat_az_deg_cp.astype(trig_dt, copy=False) * _d2r
                    sat_el_rad_cp = sat_el_deg_cp.astype(trig_dt, copy=False) * _d2r
                    cos_daz_cp = cp.cos(tel_az_rad_cp) * cp.cos(sat_az_rad_cp) + cp.sin(tel_az_rad_cp) * cp.sin(sat_az_rad_cp)
                    cos_gamma_rx_cp = (
                        cp.sin(tel_el_rad_cp) * cp.sin(sat_el_rad_cp)
                        + cp.cos(tel_el_rad_cp) * cp.cos(sat_el_rad_cp) * cos_daz_cp
                    )
                    cp.clip(cos_gamma_rx_cp, trig_dt(-1.0), trig_dt(1.0), out=cos_gamma_rx_cp)
                    grx_offset_deg_cp = (cp.arccos(cos_gamma_rx_cp) * _r2d).astype(pat_dt, copy=False)
                    grx_phi_deg_cp = (
                        _ras_boresight_frame_phi_deg(
                            tel_az_rad_cp, tel_el_rad_cp,
                            sat_az_rad_cp, sat_el_rad_cp,
                        ).astype(pat_dt, copy=False)
                        if isinstance(ras_pattern_context, GpuCustomPattern2DContext)
                        else None
                    )
                    grx_db_cp = _evaluate_ras_pattern_cp(
                        ras_pattern_context, grx_offset_deg_cp, grx_phi_deg_cp,
                    )
                    grx_lin_cp = cp.power(pwr_dt(10.0), grx_db_cp.astype(pwr_dt, copy=False) * pwr_dt(0.1))
                prx_group_cp = grx_lin_cp.astype(pwr_dt, copy=False) * active_group_scale_cp
            prx_total_ts = None
            if include_prx_total or include_epfd:
                if int(active_group_key_cp.size) > 0:
                    prx_total_ts = cp.bincount(
                        active_group_key_cp, weights=prx_group_cp, minlength=int(time_count) * int(sky_count),
                    ).astype(pwr_dt, copy=False).reshape((time_count, sky_count))
                else:
                    prx_total_ts = cp.zeros((time_count, sky_count), dtype=pwr_dt)
            if include_prx_total and prx_total_ts is not None:
                result["Prx_total_W"] = prx_total_ts[:, None, :]
            if include_per_satellite_prx:
                prx_flat_cp = cp.zeros((int(time_count) * int(sky_count) * int(sat_count),), dtype=pwr_dt)
                if int(active_group_flat_cp.size) > 0:
                    prx_flat_cp[active_group_flat_cp] = prx_group_cp
                result["Prx_per_sat_RAS_STATION_W"] = cp.transpose(
                    prx_flat_cp.reshape((time_count, sky_count, sat_count)), (0, 2, 1),
                )[:, None, :, :]
            if include_epfd:
                if prx_total_ts is None:
                    if int(active_group_key_cp.size) > 0:
                        prx_total_ts = cp.bincount(
                            active_group_key_cp, weights=prx_group_cp, minlength=int(time_count) * int(sky_count),
                        ).astype(pwr_dt, copy=False).reshape((time_count, sky_count))
                    else:
                        prx_total_ts = cp.zeros((time_count, sky_count), dtype=pwr_dt)
                result["EPFD_W_m2"] = (prx_total_ts * pfd_scale)[:, None, :]
        if include_total_pfd:
            if int(active_group_key_cp.size) > 0:
                total_pfd_ts = cp.bincount(
                    active_group_key_cp, weights=active_group_scale_cp * pfd_scale,
                    minlength=int(time_count) * int(sky_count),
                ).astype(pwr_dt, copy=False).reshape((time_count, sky_count))
            else:
                total_pfd_ts = cp.zeros((time_count, sky_count), dtype=pwr_dt)
            result["PFD_total_RAS_STATION_W_m2"] = total_pfd_ts[:, None, :]
        if include_per_satellite_pfd:
            pfd_flat_cp = cp.zeros((int(time_count) * int(sky_count) * int(sat_count),), dtype=pwr_dt)
            if int(active_group_flat_cp.size) > 0:
                pfd_flat_cp[active_group_flat_cp] = active_group_scale_cp * pfd_scale
            result["PFD_per_sat_RAS_STATION_W_m2"] = cp.transpose(
                pfd_flat_cp.reshape((time_count, sky_count, sat_count)), (0, 2, 1),
            )[:, None, :, :]
        return _finalize_cap_stats(result)

    if tuple(beam_idx_cp.shape[:2]) != (time_count, sat_count):
        raise ValueError(
            "Beam tensors must align with sat_topo over (T, S); "
            f"got {tuple(beam_idx_cp.shape)!r} for sat_topo {tuple(sat_topo_cp.shape)!r}."
        )

    # --- Pattern stage: transmit off-axis angle ---------------------------
    # Angles and trig use trig_dt (at least fp32 for arccos precision);
    # beam arrays and gain evaluation use pat_dt.
    _zero_p = pat_dt(0.0)
    _one_p = pat_dt(1.0)
    _neg1_p = pat_dt(-1.0)

    valid_beam = (beam_idx_cp >= 0) | (beam_idx_cp == -2)
    mask_bore = beam_idx_cp == -2

    if trig_dt == cp.float32:
        # Fused trig geometry: compute beam_sinb, beam_cosb, and
        # cos_gamma_tx in a single kernel launch instead of ~12 separate
        # ops.  Only used for fp32 precision profile (the production
        # default); fp64 profiles fall back to the sequential path below
        # to preserve double-precision trig.
        _tx_geom_kernel = _get_tx_trig_geometry_kernel()
        _sat_az_bcast = cp.broadcast_to(
            sat_azel_cp[..., 0].astype(cp.float32, copy=False)[:, :, None],
            beam_idx_cp.shape,
        )
        _sat_el_bcast = cp.broadcast_to(
            sat_azel_cp[..., 1].astype(cp.float32, copy=False)[:, :, None],
            beam_idx_cp.shape,
        )
        (
            beam_sinb, beam_cosb, cos_gamma_tx,
            sinb0_geom, cosb0_geom, sin_da_geom, cos_da_geom,
        ) = _tx_geom_kernel(
            _sat_az_bcast,
            _sat_el_bcast,
            beam_alpha_cp.astype(cp.float32, copy=False),
            beam_beta_cp.astype(cp.float32, copy=False),
            beam_idx_cp.astype(cp.int32, copy=False),
        )
    else:
        # Sequential path for fp64 precision profiles.
        alpha0_rad = cp.remainder(
            sat_azel_cp[..., 0].astype(trig_dt, copy=False) * trig_dt(np.pi / 180.0),
            trig_dt(2.0 * np.pi),
        )
        beta0_rad = sat_azel_cp[..., 1].astype(trig_dt, copy=False) * trig_dt(np.pi / 180.0)
        sinb0 = cp.sin(beta0_rad)
        cosb0 = cp.cos(beta0_rad)
        beam_alpha_safe = cp.where(valid_beam, beam_alpha_cp.astype(trig_dt, copy=False), trig_dt(0.0))
        beam_beta_safe = cp.where(valid_beam, beam_beta_cp.astype(trig_dt, copy=False), trig_dt(0.0))
        beam_sinb = cp.sin(beam_beta_safe)
        beam_cosb = cp.cos(beam_beta_safe)
        delta_a = alpha0_rad[:, :, None] - beam_alpha_safe
        cos_da = cp.cos(delta_a)
        sin_da = cp.sin(delta_a)
        cos_gamma_tx = cosb0[:, :, None] * beam_cosb + sinb0[:, :, None] * beam_sinb * cos_da
        cos_gamma_tx = cp.where(mask_bore, trig_dt(1.0), cos_gamma_tx)
        cos_gamma_tx = cp.where(valid_beam, cos_gamma_tx, trig_dt(-1.0))
        cp.clip(cos_gamma_tx, trig_dt(-1.0), trig_dt(1.0), out=cos_gamma_tx)
        # Expose the asymmetric-pattern inputs under a common name so the
        # is_2d branch below can be shape-agnostic across trig precisions.
        sinb0_geom = sinb0[:, :, None]
        cosb0_geom = cosb0[:, :, None]
        sin_da_geom = sin_da
        cos_da_geom = cos_da

    if is_isotropic_ctx:
        # Isotropic UEMR: flat 0 dBi, masked to active beams.
        gtx_abs_lin = cp.where(valid_beam, pwr_dt(1.0), pwr_dt(0.0))
        gtx_rel_lin = gtx_abs_lin
    elif isinstance(s1528_pattern_context, GpuCustomPattern2DContext):
        # Custom 2-D (4-D boresight path).  MEGA pattern-eval kernel
        # (lever #2): raw beam trig → (rel, abs) linear gain in ONE
        # launch.  No x_body/y_body intermediate, no separate gmax
        # multiply.  Same architecture as the 3-D path.
        if pwr_dt in (cp.float32, cp.float64):
            gtx_rel_lin, gtx_abs_lin = (
                _evaluate_custom_2d_from_beam_trig_to_rel_abs_linear(
                    s1528_pattern_context,
                    beam_sinb, beam_cosb,
                    sin_da_geom, cos_da_geom,
                    sinb0_geom, cosb0_geom,
                    cos_gamma_tx,
                    inv_gmax_lin=1.0 / float(gmax_lin),
                    compute_dtype=pwr_dt,
                )
            )
            gtx_rel_lin = cp.where(valid_beam, gtx_rel_lin, pwr_dt(0.0))
            gtx_abs_lin = cp.where(valid_beam, gtx_abs_lin, pwr_dt(0.0))
        else:
            x_body = beam_cosb * sin_da_geom
            y_body = cosb0_geom * beam_sinb - sinb0_geom * beam_cosb * cos_da_geom
            z_body = cos_gamma_tx
            # fp16 / other compute dtype: fall back to the unfused
            # path (fp16 FSPL underflows downstream anyway).
            if s1528_pattern_context.grid_mode == "az_el":
                az_rad_fb = cp.arctan2(x_body, z_body)
                y_clip_fb = cp.clip(y_body, trig_dt(-1.0), trig_dt(1.0))
                el_rad_fb = cp.arcsin(y_clip_fb)
                a0_deg_fb = (az_rad_fb * trig_dt(180.0 / np.pi)).astype(pat_dt, copy=False)
                a1_deg_fb = (el_rad_fb * trig_dt(180.0 / np.pi)).astype(pat_dt, copy=False)
            else:
                z_clip_fb = cp.clip(z_body, trig_dt(-1.0), trig_dt(1.0))
                th_rad_fb = cp.arccos(z_clip_fb)
                ph_rad_fb = cp.arctan2(y_body, x_body)
                a0_deg_fb = (th_rad_fb * trig_dt(180.0 / np.pi)).astype(pat_dt, copy=False)
                a1_deg_fb = (ph_rad_fb * trig_dt(180.0 / np.pi)).astype(pat_dt, copy=False)
            gtx_db = _evaluate_custom_2d_pattern_cp(
                s1528_pattern_context, a0_deg_fb, a1_deg_fb,
            )
            gtx_abs_lin = cp.power(
                pwr_dt(10.0),
                gtx_db.astype(pwr_dt, copy=False) * pwr_dt(0.1),
            )
            gtx_abs_lin = cp.where(valid_beam, gtx_abs_lin, pwr_dt(0.0))
            gtx_rel_lin = gtx_abs_lin * pwr_dt(1.0 / float(gmax_lin))
    elif isinstance(s1528_pattern_context, GpuCustomPattern1DContext):
        # Custom 1-D axisymmetric: θ-only path, drop-in for symmetric
        # S.1528 / Rec 1.2 — reuses the same fused ``s1528_lut_1d_to_linear``
        # kernel on the pattern-agnostic regular-grid LUT.
        gtx_offset_deg = (
            cp.arccos(cos_gamma_tx) * trig_dt(180.0 / np.pi)
        ).astype(pat_dt, copy=False)
        if pwr_dt == cp.float32:
            gtx_rel_lin = _evaluate_custom_1d_pattern_cp_to_linear(
                s1528_pattern_context, gtx_offset_deg,
                inv_gmax_lin=1.0 / float(gmax_lin),
            )
            gtx_rel_lin = cp.where(valid_beam, gtx_rel_lin, pwr_dt(0.0))
            gtx_abs_lin = gtx_rel_lin * pwr_dt(float(gmax_lin))
        else:
            gtx_db = _evaluate_custom_1d_pattern_cp(
                s1528_pattern_context, gtx_offset_deg,
            )
            gtx_abs_lin = cp.power(
                pwr_dt(10.0), gtx_db.astype(pwr_dt, copy=False) * pwr_dt(0.1),
            )
            gtx_abs_lin = cp.where(valid_beam, gtx_abs_lin, pwr_dt(0.0))
            gtx_rel_lin = gtx_abs_lin * pwr_dt(1.0 / float(gmax_lin))
    elif isinstance(s1528_pattern_context, GpuM2101PatternContext):
        # M.2101: 2D pattern from satellite-frame angles
        ras_az_3d = sat_azel_cp[..., 0].astype(cp.float32, copy=False)
        ras_el_3d = sat_azel_cp[..., 1].astype(cp.float32, copy=False)
        steer_az_3d = (beam_alpha_cp.astype(trig_dt, copy=False) * trig_dt(180.0 / np.pi)).astype(cp.float32, copy=False)
        steer_el_3d = (beam_beta_cp.astype(trig_dt, copy=False) * trig_dt(180.0 / np.pi)).astype(cp.float32, copy=False)
        if _pattern_eval_mode == "lut" and pwr_dt == cp.float32:
            gtx_rel_lin = _evaluate_m2101_pattern_cp_lut_to_linear(
                s1528_pattern_context,
                ras_az_3d[:, :, None], ras_el_3d[:, :, None],
                steer_az_3d, steer_el_3d,
                inv_gmax_lin=1.0 / float(gmax_lin),
            ).astype(pwr_dt, copy=False)
            gtx_rel_lin = cp.where(valid_beam, gtx_rel_lin, pwr_dt(0.0))
            gtx_abs_lin = gtx_rel_lin * pwr_dt(float(gmax_lin))
        else:
            gtx_db_3d = _evaluate_m2101_pattern_cp(
                s1528_pattern_context,
                ras_az_3d[:, :, None], ras_el_3d[:, :, None],
                steer_az_3d, steer_el_3d,
            )
            gtx_abs_lin = cp.power(pwr_dt(10.0), gtx_db_3d.astype(pwr_dt, copy=False) * pwr_dt(0.1))
            gtx_abs_lin = cp.where(valid_beam, gtx_abs_lin, pwr_dt(0.0))
            gtx_rel_lin = gtx_abs_lin * pwr_dt(1.0 / float(gmax_lin))
    elif getattr(s1528_pattern_context, "is_2d", False):
        # Asymmetric S.1528 Rec 1.4 (lt_m != lr_m): compute theta AND phi
        # per (t, sat, k) and dispatch through the 2-D (theta, phi) LUT.
        # sinb0/cosb0/sin_da/cos_da come from the trig stage above — the
        # fused fp32 kernel emits them directly, the fp64 sequential path
        # exposes the same names with [:, :, None] broadcast. phi is the
        # azimuth of the pointing around the beam boresight, derived from
        # spherical geometry with the boresight as pole (phi=0 along the
        # lr axis by convention). The LUT's 4-fold folding absorbs any
        # quadrant / sign convention difference.
        # Note: sin_da_geom has sign `sin(α₀ − α_beam)` — the sign of
        # the atan2 second argument is therefore flipped relative to
        # the `sin(α_beam − α₀)` convention in the derivation, but
        # pattern symmetry makes this harmless.
        phi_rad = cp.arctan2(
            cosb0_geom * beam_sinb - sinb0_geom * beam_cosb * cos_da_geom,
            beam_cosb * sin_da_geom,
        )
        phi_deg = (phi_rad * trig_dt(180.0 / np.pi)).astype(pat_dt, copy=False)
        gtx_offset_deg = (cp.arccos(cos_gamma_tx) * trig_dt(180.0 / np.pi)).astype(pat_dt, copy=False)
        gtx_db = _evaluate_s1528_pattern_cp(
            s1528_pattern_context, gtx_offset_deg, phi_deg=phi_deg,
        )
        gtx_abs_lin = cp.power(pwr_dt(10.0), gtx_db.astype(pwr_dt, copy=False) * pwr_dt(0.1))
        gtx_abs_lin = cp.where(valid_beam, gtx_abs_lin, pwr_dt(0.0))
        gtx_rel_lin = gtx_abs_lin * pwr_dt(1.0 / float(gmax_lin))
    else:
        gtx_offset_deg = (cp.arccos(cos_gamma_tx) * trig_dt(180.0 / np.pi)).astype(pat_dt, copy=False)

        if _pattern_eval_mode == "lut" and pwr_dt == cp.float32:
            gtx_rel_lin = _evaluate_s1528_pattern_cp_lut_1d_to_linear(
                s1528_pattern_context,
                gtx_offset_deg,
                inv_gmax_lin=1.0 / float(gmax_lin),
            )
            gtx_rel_lin = cp.where(valid_beam, gtx_rel_lin, pwr_dt(0.0))
            gtx_abs_lin = gtx_rel_lin * pwr_dt(float(gmax_lin))
        else:
            gtx_db = _evaluate_s1528_pattern_cp(s1528_pattern_context, gtx_offset_deg)
            gtx_abs_lin = cp.power(pwr_dt(10.0), gtx_db.astype(pwr_dt, copy=False) * pwr_dt(0.1))
            gtx_abs_lin = cp.where(valid_beam, gtx_abs_lin, pwr_dt(0.0))
            gtx_rel_lin = gtx_abs_lin * pwr_dt(1.0 / float(gmax_lin))

    # --- Power stage: geometry, EIRP, FSPL, accumulation ----------------
    _zero_w = pwr_dt(0.0)
    _one_w = pwr_dt(1.0)

    range_m = sat_topo_cp[..., 2].astype(pwr_dt, copy=False) * pwr_dt(1000.0)
    sat_elevation_deg = sat_topo_cp[..., 1].astype(pwr_dt, copy=False)
    vis_horizon = sat_elevation_deg > pwr_dt(float(visibility_elev_threshold_deg))

    orbit_radius = _to_cupy_array(orbit_radius_m_per_sat, dtype=pwr_dt).reshape(-1)
    if int(orbit_radius.size) != sat_count:
        raise ValueError(
            "orbit_radius_m_per_sat must have length equal to the satellite axis "
            f"{sat_count}, got {int(orbit_radius.size)}."
        )
    earth_r = pwr_dt(float(earth_radius_m))
    r_m = orbit_radius[None, :, None]

    if pwr_dt == cp.float32:
        # Fused beam→ground geometry: compute d_target + target elevation
        # in a single kernel launch instead of ~16 separate ops.  Only
        # used for fp32 power dtype; fp64 falls back to sequential path.
        _geom_kernel = _get_beam_geometry_kernel()
        _atm_elev_min = cp.float32(
            atmosphere_lut_context.elev_min_deg if atmosphere_lut_context is not None else 0.0
        )
        _orbit_r_bcast = cp.broadcast_to(
            orbit_radius.astype(cp.float32, copy=False)[None, :, None],
            beam_idx_cp.shape,
        )
        d_target_geom_m, e_target_deg, valid_geom = _geom_kernel(
            beam_sinb.astype(cp.float32, copy=False),
            beam_cosb.astype(cp.float32, copy=False),
            _orbit_r_bcast,
            cp.float32(float(earth_radius_m)),
            beam_idx_cp.astype(cp.int32, copy=False),
            _atm_elev_min,
        )
    elif pwr_dt == cp.float64:
        # Fused fp64 beam geometry kernel — replaces ~12 sequential ops.
        _geom_fp64 = _get_beam_geometry_fp64_kernel()
        _atm_elev_min_64 = cp.float64(
            atmosphere_lut_context.elev_min_deg if atmosphere_lut_context is not None else 0.0
        )
        _orbit_r_bcast_64 = cp.broadcast_to(
            orbit_radius.astype(cp.float64, copy=False)[None, :, None],
            beam_idx_cp.shape,
        )
        d_target_geom_m, e_target_deg, valid_geom = _geom_fp64(
            beam_sinb.astype(cp.float64, copy=False),
            beam_cosb.astype(cp.float64, copy=False),
            _orbit_r_bcast_64,
            cp.float64(float(earth_radius_m)),
            valid_beam,
            mask_bore,
            _atm_elev_min_64,
        )
    else:
        # Generic sequential fallback for unexpected dtypes.
        beam_cosb_w = beam_cosb.astype(pwr_dt, copy=False)
        beam_sinb_w = beam_sinb.astype(pwr_dt, copy=False)
        term = r_m * beam_cosb_w
        disc = term * term - (r_m * r_m - earth_r * earth_r)
        hit_earth = disc >= _zero_w
        cos_positive = beam_cosb_w > _zero_w
        valid_geom = valid_beam & (~mask_bore) & hit_earth & cos_positive
        d_target_geom_m = term - cp.sqrt(cp.where(valid_geom, disc, _zero_w))
        if atmosphere_lut_context is not None:
            cos_e_target = cp.clip(
                (r_m / earth_r) * beam_sinb_w,
                _zero_w, _one_w,
            )
            e_target_deg = cp.arccos(cos_e_target.astype(trig_dt, copy=False)).astype(pwr_dt, copy=False) * pwr_dt(180.0 / np.pi)
            e_target_deg = cp.where(
                valid_geom,
                cp.maximum(e_target_deg, pwr_dt(atmosphere_lut_context.elev_min_deg)),
                _zero_w,
            )
        else:
            e_target_deg = cp.zeros_like(d_target_geom_m)

    if atmosphere_lut_context is None:
        atm_ras_station = cp.ones((time_count, sat_count), dtype=pwr_dt)
        atm_target_safe = cp.ones_like(beam_alpha_cp, dtype=pwr_dt)
    else:
        atm_ras_station = _lookup_atmosphere_lut_cp(
            atmosphere_lut_context,
            sat_elevation_deg,
            altitude_km=observer_alt_km,
        ).astype(pwr_dt, copy=False)
        atm_target = _lookup_atmosphere_lut_cp(
            atmosphere_lut_context, e_target_deg, altitude_km=target_alt_km,
        ).astype(pwr_dt, copy=False)
        atm_target_safe = cp.where(valid_geom, atm_target, _one_w)

    four_pi_w = pwr_dt(4.0 * np.pi)
    target_pfd_w = pwr_dt(float(target_pfd_lin_channel))

    # Variable power for the 3D path (range_m shape: (T, S))
    _var_mode_3d = str(power_variation_mode or "fixed").strip().lower()
    _var_power_3d: Any = None
    if _var_mode_3d != "fixed" and quantity_name in {"satellite_eirp", "satellite_ptx"}:
        _pmin_3d = float(power_range_min_dbw_channel or 0.0)
        _pmax_3d = float(power_range_max_dbw_channel or 0.0)
        if _var_mode_3d == "slant_range":
            kernel = _get_slant_range_power_kernel()
            _var_power_3d = kernel(
                range_m.astype(cp.float32, copy=False),
                orbit_radius[None, :].astype(cp.float32, copy=False),
                cp.float32(float(earth_radius_m)),
                cp.float32(0.0), cp.float32(1.0),
                cp.float32(_pmin_3d), cp.float32(_pmax_3d),
            ).astype(pwr_dt, copy=False)
        elif _var_mode_3d == "uniform_random":
            _rand_3d = cp.float32(_pmin_3d) + (cp.float32(_pmax_3d) - cp.float32(_pmin_3d)) * cp.random.random(
                range_m.shape, dtype=cp.float32,
            )
            _var_power_3d = cp.power(pwr_dt(10.0), _rand_3d.astype(pwr_dt, copy=False) * pwr_dt(0.1))

    # Mega-fused power kernel: EIRP + leakage + sum + FSPL in 2 launches.
    # Active for fp32 mode without variable power or per-channel spectral
    # weights.  When cap is active with a precomputed factor, the mega
    # kernel still runs — the cap multiply is inserted between K1 and K2.
    _cap_compatible_with_mega = (
        not cap_active
        or precomputed_cap_factor_cp is not None  # hoisted cap: apply between K1 and K2
    )
    _use_mega_fused = (
        pwr_dt == cp.float32
        and _var_power_3d is None
        and _cap_compatible_with_mega
        and cell_spectral_weight_cp is None  # mega kernel handles static leakage only
    )
    if _use_mega_fused:
        _mega_mod = _get_power_mega_kernel()
        _n_beams = int(beam_idx_cp.shape[-1])
        _total_tsk = int(time_count) * int(sat_count) * int(_n_beams)
        _total_ts = int(time_count) * int(sat_count)
        _block = 256

        # Kernel 1: compute emitted_eirp with leakage
        emitted_eirp = cp.empty(
            (time_count, sat_count, _n_beams), dtype=cp.float32,
        )
        _qmode = {"target_pfd": 0, "satellite_eirp": 1, "satellite_ptx": 2}.get(quantity_name, 0)
        _k1 = _mega_mod.get_function("compute_emitted_eirp_with_leakage")
        _k1(
            ((_total_tsk + _block - 1) // _block,), (_block,),
            (
                valid_geom, mask_bore, valid_beam,
                d_target_geom_m, atm_target_safe,
                range_m, atm_ras_station,
                gtx_rel_lin, gtx_abs_lin if gtx_abs_lin is not None else gtx_rel_lin,
                beam_idx_cp.astype(cp.int32, copy=False),
                leakage_factors_cp if leakage_factors_cp is not None else cp.zeros(1, dtype=cp.float32),
                np.float32(float(target_pfd_lin_channel)),
                np.float32(float(satellite_eirp_lin_channel) if satellite_eirp_lin_channel is not None else 0.0),
                np.float32(float(satellite_ptx_lin_channel) if satellite_ptx_lin_channel is not None else 0.0),
                np.int32(_qmode),
                np.int32(1 if use_ras_station_alt_for_co else 0),
                np.int32(n_links_i),
                np.int32(int(ras_service_cell_index or 0)),
                np.int32(int(leakage_factors_cp.size) if leakage_factors_cp is not None else 0),
                np.int32(1 if leakage_factors_cp is not None else 0),
                np.int32(time_count), np.int32(sat_count), np.int32(_n_beams),
                emitted_eirp,
            ),
        )

        # Apply precomputed surface-PFD cap between K1 (EIRP) and K2
        # (reduction).  Only runs when cap is active AND the cap factor
        # was hoisted by the fused direct-EPFD wrapper.  In-kernel cap
        # (non-precomputed) still disables the mega kernel.
        if cap_active and precomputed_cap_factor_cp is not None:
            _precomp = precomputed_cap_factor_cp.astype(cp.float32, copy=False)
            _expected_per_beam = (int(time_count), int(sat_count), _n_beams)
            _expected_per_sat = (int(time_count), int(sat_count))
            if tuple(_precomp.shape) == _expected_per_beam:
                # Per-beam (T, S, K) factor
                emitted_eirp *= _precomp
            elif tuple(_precomp.shape) == _expected_per_sat:
                # Per-satellite (T, S) factor — broadcast to (T, S, K)
                emitted_eirp *= _precomp[:, :, None]
            else:
                raise ValueError(
                    "precomputed_cap_factor_cp in the mega-fused 3-D path "
                    f"must have shape {_expected_per_beam!r} (per-beam) or "
                    f"{_expected_per_sat!r} (per-satellite); "
                    f"got {tuple(_precomp.shape)!r}."
                )
            # Propagate hoisted cap stats
            if surface_pfd_stats_enabled and precomputed_cap_stats is not None:
                cap_stats_accum["n_beams_capped"] = (
                    int(cap_stats_accum["n_beams_capped"])
                    + int(precomputed_cap_stats.get("n_capped", 0))
                )
                cap_stats_accum["cap_db_sum_over_capped"] = (
                    float(cap_stats_accum["cap_db_sum_over_capped"])
                    + float(precomputed_cap_stats.get("cap_db_sum", 0.0))
                )
                cap_stats_accum["cap_db_max"] = float(
                    max(
                        float(cap_stats_accum["cap_db_max"]),
                        float(precomputed_cap_stats.get("cap_db_max", 0.0)),
                    )
                )

        # Kernel 2: reduce over beams + FSPL + atm + vis → scale_w_channel
        scale_w_channel = cp.empty((time_count, sat_count), dtype=cp.float32)
        _k2 = _mega_mod.get_function("reduce_eirp_to_scale")
        _k2(
            ((_total_ts + _block - 1) // _block,), (_block,),
            (
                emitted_eirp, range_m, atm_ras_station, vis_horizon,
                np.float32(float(wavelength_m)),
                np.int32(time_count), np.int32(sat_count), np.int32(_n_beams),
                scale_w_channel,
            ),
        )
        # Skip the CuPy EIRP + sum + FSPL + scale path below.
        # Jump directly to receive-side pattern evaluation.

    # Original single-EIRP fused kernel (fallback when mega not available)
    elif not _use_mega_fused and (
        pwr_dt == cp.float32
        and quantity_name == "target_pfd"
        and _var_power_3d is None
        and not cap_active
    ):
        _use_fused_eirp = True
        _eirp_mod = _get_eirp_fspl_fused_kernel()
        _eirp_kernel = _eirp_mod.get_function("compute_eirp_and_scale")
        emitted_eirp = cp.empty_like(gtx_rel_lin)
        _n_beams = int(beam_idx_cp.shape[-1])
        _total_elems = int(time_count) * int(sat_count) * int(_n_beams)
        _block = 256
        _grid = (_total_elems + _block - 1) // _block
        _eirp_kernel(
            (_grid,), (_block,),
            (
                valid_geom, mask_bore, valid_beam,
                d_target_geom_m, atm_target_safe,
                range_m, atm_ras_station,
                gtx_rel_lin, vis_horizon,
                np.float32(float(target_pfd_lin_channel)),
                np.float32(float(wavelength_m)),
                np.int32(1 if use_ras_station_alt_for_co else 0),
                np.int32(time_count), np.int32(sat_count), np.int32(_n_beams),
                emitted_eirp,
            ),
        )
    else:
        # Fallback: separate CuPy operations (fp64, satellite_eirp/ptx modes,
        # variable power, or non-standard configurations).
        boresight_eirp_geom = cp.where(
            valid_geom,
            target_pfd_w * four_pi_w * d_target_geom_m * d_target_geom_m / atm_target_safe,
            _zero_w,
        )
        atm_co = atm_ras_station if use_ras_station_alt_for_co else _one_w
        boresight_eirp_co = target_pfd_w * four_pi_w * range_m * range_m / atm_co
        boresight_eirp_w = cp.where(mask_bore, boresight_eirp_co[:, :, None], boresight_eirp_geom)

        if quantity_name == "target_pfd":
            emitted_eirp = boresight_eirp_w * gtx_rel_lin
        elif quantity_name == "satellite_eirp":
            if _var_power_3d is not None:
                emitted_eirp = _var_power_3d[:, :, None] * gtx_rel_lin
            else:
                emitted_eirp = pwr_dt(float(satellite_eirp_lin_channel)) * gtx_rel_lin
        else:
            if _var_power_3d is not None:
                emitted_eirp = _var_power_3d[:, :, None] * gtx_abs_lin
            else:
                emitted_eirp = pwr_dt(float(satellite_ptx_lin_channel)) * gtx_abs_lin

    # Free-space path loss × atmosphere
    wavelength_w = pwr_dt(float(wavelength_m))
    fspl_lin = cp.power(wavelength_w / (four_pi_w * range_m), pwr_dt(2.0))
    fspl_lin *= atm_ras_station

    # Surface-PFD cap — inserted BEFORE spectral / leakage scaling so
    # the cap targets the antenna's radiated EIRP, matching the 4-D
    # boresight-avoidance path above.  The ``per_satellite`` aggregate
    # mode broadcasts a (T, S) scale factor to all beams of each
    # satellite; the ``per_beam`` mode applies a per-(T, S, K) factor.
    # Skip when the mega kernel already applied the precomputed cap
    # between K1 and K2 above.
    if cap_active and not _use_mega_fused:
        # Per-beam peak EIRP (shared between both cap modes)
        if quantity_name == "target_pfd":
            eirp_peak_3d = boresight_eirp_w  # (T, S, K)
        elif quantity_name == "satellite_eirp":
            if _var_power_3d is not None:
                eirp_peak_3d = _var_power_3d[:, :, None]  # (T, S, 1)
            else:
                eirp_peak_3d = pwr_dt(float(satellite_eirp_lin_channel))
        else:  # satellite_ptx
            if _var_power_3d is not None:
                eirp_peak_3d = _var_power_3d[:, :, None] * pwr_dt(float(gmax_lin))
            else:
                eirp_peak_3d = pwr_dt(
                    float(satellite_ptx_lin_channel) * float(gmax_lin)
                )

        if cap_mode_normalised == "per_beam":
            if precomputed_cap_factor_cp is not None:
                # Hoisted fast path — the fused direct-EPFD wrapper has
                # already computed the cap factor for the whole slab.
                # Accept either a (T, S, K) per-beam factor or a
                # (T, S) per-satellite factor and apply it directly.
                precomp_cp = precomputed_cap_factor_cp.astype(pwr_dt, copy=False)
                if precomp_cp.shape == beam_beta_cp.shape:
                    cap_factor_3d_cp = cp.where(
                        valid_beam, precomp_cp, pwr_dt(1.0),
                    )
                elif precomp_cp.shape == (int(time_count), int(sat_count)):
                    cap_factor_3d_cp = cp.broadcast_to(
                        precomp_cp[:, :, None], beam_beta_cp.shape,
                    )
                    cap_factor_3d_cp = cp.where(
                        valid_beam, cap_factor_3d_cp, pwr_dt(1.0),
                    )
                else:
                    raise ValueError(
                        "precomputed_cap_factor_cp for per_beam mode must "
                        f"have shape {tuple(beam_beta_cp.shape)!r} (per-beam) "
                        f"or ({int(time_count)}, {int(sat_count)}) (per-sat); "
                        f"got {tuple(precomp_cp.shape)!r}."
                    )
                emitted_eirp = emitted_eirp * cap_factor_3d_cp
                if surface_pfd_stats_enabled and precomputed_cap_stats is not None:
                    cap_stats_accum["n_beams_capped"] = (
                        int(cap_stats_accum["n_beams_capped"])
                        + int(precomputed_cap_stats.get("n_capped", 0))
                    )
                    cap_stats_accum["cap_db_sum_over_capped"] = (
                        float(cap_stats_accum["cap_db_sum_over_capped"])
                        + float(precomputed_cap_stats.get("cap_db_sum", 0.0))
                    )
                    cap_stats_accum["cap_db_max"] = float(
                        max(
                            float(cap_stats_accum["cap_db_max"]),
                            float(precomputed_cap_stats.get("cap_db_max", 0.0)),
                        )
                    )
            else:
                # In-kernel fallback: compute K(β), the per-beam peak
                # PFD, and the cap factor from scratch.
                shell_per_beam_3d_cp = cp.broadcast_to(
                    cap_shell_id_per_sat_cp[None, :, None],
                    beam_beta_cp.shape,
                )
                k_3d_cp = _lookup_peak_pfd_k_any_cp(
                    peak_pfd_lut_context,
                    beam_alpha_cp,
                    beam_beta_cp,
                    shell_per_beam_3d_cp,
                ).astype(cp.float32, copy=False)
                # Fuse: K × EIRP_peak → peak PFD → safety clamp → cap
                # ratio → validity mask → apply.  6 ops → 1 kernel.
                _eirp_peak_broadcast = cp.broadcast_to(
                    cp.asarray(eirp_peak_3d, dtype=cp.float32),
                    k_3d_cp.shape,
                ) if hasattr(eirp_peak_3d, 'shape') and eirp_peak_3d.shape != k_3d_cp.shape else (
                    cp.full(k_3d_cp.shape, float(eirp_peak_3d), dtype=cp.float32)
                    if not hasattr(eirp_peak_3d, 'shape') or eirp_peak_3d.ndim == 0
                    else cp.asarray(eirp_peak_3d, dtype=cp.float32)
                )
                emitted_eirp = _get_cap_apply_fused_kernel()(
                    emitted_eirp.astype(cp.float32, copy=False),
                    k_3d_cp,
                    _eirp_peak_broadcast,
                    cp.float32(float(cap_limit_w)),
                    valid_beam,
                ).astype(pwr_dt, copy=False)

                if surface_pfd_stats_enabled:
                    # Recompute cap_factor for stats reporting (not on hot path)
                    _peak_pfd_stats = _eirp_peak_broadcast * k_3d_cp
                    _peak_safe_stats = cp.maximum(_peak_pfd_stats, cp.float32(1.0e-30))
                    _cap_factor_stats = cp.minimum(
                        cp.float32(1.0), cp.float32(float(cap_limit_w)) / _peak_safe_stats,
                    )
                    _cap_factor_stats = cp.where(valid_beam, _cap_factor_stats, cp.float32(1.0))
                    capped_mask_3d_cp = (
                        (_cap_factor_stats < pwr_dt(1.0 - 1.0e-6)) & valid_beam
                    )
                    cap_db_3d_cp = cp.where(
                        capped_mask_3d_cp,
                        pwr_dt(-10.0) * cp.log10(
                            cp.maximum(_cap_factor_stats, pwr_dt(1.0e-30))
                        ),
                        pwr_dt(0.0),
                    )
                    _stats_3d = cp.array([
                        cp.count_nonzero(capped_mask_3d_cp).astype(cp.float32),
                        cp.sum(cap_db_3d_cp).astype(cp.float32),
                        (cp.max(cap_db_3d_cp).astype(cp.float32)
                         if int(cap_db_3d_cp.size) > 0 else cp.float32(0.0)),
                    ])
                    _sh = _stats_3d.get()
                    cap_stats_accum["n_beams_capped"] = (
                        int(cap_stats_accum["n_beams_capped"]) + int(_sh[0])
                    )
                    cap_stats_accum["cap_db_sum_over_capped"] = (
                        float(cap_stats_accum["cap_db_sum_over_capped"]) + float(_sh[1])
                    )
                    cap_stats_accum["cap_db_max"] = float(
                        max(float(cap_stats_accum["cap_db_max"]), float(_sh[2]))
                    )
        else:
            # Aggregate per-(t, sat) cap.  When the caller has pre-computed
            # the cap factor (e.g. the fused direct-EPFD path hoists this
            # out of the spectral-slab loop so it is computed once per
            # batch rather than once per slab), just apply it.  Otherwise
            # fall through to the in-kernel computation — correct but
            # slower for callers that invoke the kernel repeatedly with
            # the same geometry.
            if precomputed_cap_factor_cp is not None:
                precomp_cp = precomputed_cap_factor_cp.astype(pwr_dt, copy=False)
                if precomp_cp.shape != (int(time_count), int(sat_count)):
                    raise ValueError(
                        "precomputed_cap_factor_cp must have shape "
                        f"(time_count, sat_count) = ({int(time_count)}, "
                        f"{int(sat_count)}); got {tuple(precomp_cp.shape)!r}."
                    )
                emitted_eirp = emitted_eirp * precomp_cp[:, :, None]
                if surface_pfd_stats_enabled and precomputed_cap_stats is not None:
                    cap_stats_accum["n_beams_capped"] = (
                        int(cap_stats_accum["n_beams_capped"])
                        + int(precomputed_cap_stats.get("n_capped", 0))
                    )
                    cap_stats_accum["cap_db_sum_over_capped"] = (
                        float(cap_stats_accum["cap_db_sum_over_capped"])
                        + float(precomputed_cap_stats.get("cap_db_sum", 0.0))
                    )
                    cap_stats_accum["cap_db_max"] = float(
                        max(
                            float(cap_stats_accum["cap_db_max"]),
                            float(precomputed_cap_stats.get("cap_db_max", 0.0)),
                        )
                    )
            else:
                # Materialise a broadcastable ``(T, S, K)`` peak-EIRP tensor
                # first so the helper can broadcast it uniformly regardless
                # of the upstream mode.
                eirp_peak_full = cp.broadcast_to(
                    eirp_peak_3d
                    if isinstance(eirp_peak_3d, cp.ndarray)
                    else cp.full(beam_beta_cp.shape, eirp_peak_3d, dtype=pwr_dt),
                    beam_beta_cp.shape,
                ).astype(pwr_dt, copy=False)
                cap_factor_ts_cp, _, stats = _compute_aggregate_surface_pfd_cap_cp(
                    beam_alpha_cp=beam_alpha_cp,
                    beam_beta_cp=beam_beta_cp,
                    beam_valid_cp=valid_beam,
                    eirp_peak_cp=eirp_peak_full,
                    orbit_radius_per_sat_cp=orbit_radius,
                    sat_axis_index=1,
                    pattern_context=s1528_pattern_context,
                    atmosphere_lut_context=atmosphere_lut_context,
                    target_alt_km=float(target_alt_km),
                    max_surface_pfd_lin=cap_limit_w,
                )
                # cap_factor_ts_cp has shape (T, S) → broadcast to (T, S, 1)
                cap_factor_ts_cp = cap_factor_ts_cp.astype(pwr_dt, copy=False)
                emitted_eirp = emitted_eirp * cap_factor_ts_cp[:, :, None]

                if surface_pfd_stats_enabled:
                    cap_stats_accum["n_beams_capped"] = (
                        int(cap_stats_accum["n_beams_capped"]) + int(stats["n_capped"])
                    )
                    cap_stats_accum["cap_db_sum_over_capped"] = (
                        float(cap_stats_accum["cap_db_sum_over_capped"])
                        + float(stats["cap_db_sum"])
                    )
                    cap_stats_accum["cap_db_max"] = float(
                        max(
                            float(cap_stats_accum["cap_db_max"]),
                            float(stats["cap_db_max"]),
                        )
                    )

    if cell_spectral_weight_cp is not None:
        source_cell_idx = (beam_idx_cp.astype(cp.int64, copy=False) // np.int64(n_links_i)).astype(cp.int32, copy=False)
        if ras_service_cell_index is not None:
            source_cell_idx = cp.where(mask_bore, cp.int32(int(ras_service_cell_index)), source_cell_idx)
        valid_source = valid_beam & (source_cell_idx >= 0) & (
            source_cell_idx < int(cell_spectral_weight_cp.shape[1])
        )
        spectral_scale = cp.where(
            valid_source,
            cell_spectral_weight_cp[
                cp.arange(int(time_count), dtype=cp.int32)[:, None, None],
                source_cell_idx,
            ],
            _zero_w,
        ).astype(pwr_dt, copy=False)
        emitted_eirp *= spectral_scale
    elif leakage_factors_cp is not None:
        _lk_kernel = _get_leakage_scale_fused_kernel()
        emitted_eirp = _lk_kernel(
            beam_idx_cp.astype(cp.int32, copy=False),
            valid_beam,
            mask_bore,
            emitted_eirp.astype(cp.float32, copy=False),
            leakage_factors_cp.astype(cp.float32, copy=False),
            cp.int32(n_links_i),
            cp.int32(int(ras_service_cell_index or 0)),
            cp.int32(int(leakage_factors_cp.size)),
            cp.int32(1 if ras_service_cell_index is not None else 0),
        ).astype(pwr_dt, copy=False)

    if not _use_mega_fused:
        eirp_sum = cp.sum(emitted_eirp, axis=2, dtype=pwr_dt)
        scale_w_channel = eirp_sum * fspl_lin
        scale_w_channel *= vis_horizon.astype(pwr_dt, copy=False)
    result: dict[str, Any] = {}
    if include_receive_outputs:
        # Receive-side angular distance + RAS pattern evaluation.
        # For fp32 (the common production path) use the fused kernel
        # that does trig + angular distance + RAS pattern + dB→linear
        # in a single CUDA launch (~16 separate ops → 1).
        if pwr_dt == cp.float32 and isinstance(
            ras_pattern_context, GpuRasPatternContext,
        ):
            n_tel = int(telescope_az_cp.shape[1])
            d_wlen = np.float32(ras_pattern_context.diameter_m / ras_pattern_context.wavelength_m)
            _gmax_ras = np.float32(10.0 * np.log10(ras_pattern_context.eta_a_dimless * (np.pi * d_wlen) ** 2))
            _g1_ras = np.float32(-1.0 + 15.0 * np.log10(d_wlen))
            _phi_m_ras = np.float32(20.0 / d_wlen * np.sqrt(_gmax_ras - _g1_ras))
            _phi_r_ras = np.float32(15.85 * d_wlen ** -0.6)
            # Broadcast tel (T, N_tel, 1) and sat (T, 1, S) to (T, N_tel, S)
            _rx_out_shape = (int(time_count), int(n_tel), int(sat_count))
            kernel = _get_rx_angular_distance_ras_lin_kernel()
            grx_lin = kernel(
                cp.broadcast_to(telescope_az_cp.astype(cp.float32, copy=False)[:, :, None], _rx_out_shape),
                cp.broadcast_to(telescope_el_cp.astype(cp.float32, copy=False)[:, :, None], _rx_out_shape),
                cp.broadcast_to(sat_topo_cp[..., 0].astype(cp.float32, copy=False)[:, None, :], _rx_out_shape),
                cp.broadcast_to(sat_elevation_deg.astype(cp.float32, copy=False)[:, None, :], _rx_out_shape),
                d_wlen, _gmax_ras, _g1_ras, _phi_m_ras, _phi_r_ras,
            )
        elif trig_dt == cp.float32:
            # Fused angular distance: 14 sequential trig ops → 1 kernel.
            # Used for Custom RAS patterns where pattern eval is separate.
            n_tel = int(telescope_az_cp.shape[1])
            _rx_out_shape_fb = (int(time_count), int(n_tel), int(sat_count))
            _ang_kernel = _get_rx_angular_distance_only_kernel()
            grx_offset_deg = _ang_kernel(
                cp.broadcast_to(telescope_az_cp.astype(cp.float32, copy=False)[:, :, None], _rx_out_shape_fb),
                cp.broadcast_to(telescope_el_cp.astype(cp.float32, copy=False)[:, :, None], _rx_out_shape_fb),
                cp.broadcast_to(sat_topo_cp[..., 0].astype(cp.float32, copy=False)[:, None, :], _rx_out_shape_fb),
                cp.broadcast_to(sat_elevation_deg.astype(cp.float32, copy=False)[:, None, :], _rx_out_shape_fb),
            ).astype(pat_dt, copy=False)
            grx_phi_deg_bs = None
            if isinstance(ras_pattern_context, GpuCustomPattern2DContext):
                # Fused phi uses radians — convert from degrees inline
                _d2r_f32 = cp.float32(np.pi / 180.0)
                grx_phi_deg_bs = _ras_boresight_frame_phi_deg(
                    telescope_az_cp.astype(cp.float32, copy=False)[:, :, None] * _d2r_f32,
                    telescope_el_cp.astype(cp.float32, copy=False)[:, :, None] * _d2r_f32,
                    sat_topo_cp[..., 0].astype(cp.float32, copy=False)[:, None, :] * _d2r_f32,
                    sat_elevation_deg.astype(cp.float32, copy=False)[:, None, :] * _d2r_f32,
                ).astype(pat_dt, copy=False)
            grx_db = _evaluate_ras_pattern_cp(
                ras_pattern_context, grx_offset_deg, grx_phi_deg_bs,
            )
            grx_lin = cp.power(pwr_dt(10.0), grx_db.astype(pwr_dt, copy=False) * pwr_dt(0.1))
        else:
            # fp64 fallback: unfused trig for maximum precision.
            n_tel = int(telescope_az_cp.shape[1])
            tel_az_rad = telescope_az_cp.astype(trig_dt, copy=False) * trig_dt(np.pi / 180.0)
            tel_el_rad = telescope_el_cp.astype(trig_dt, copy=False) * trig_dt(np.pi / 180.0)
            sat_az_rad = sat_topo_cp[..., 0].astype(trig_dt, copy=False) * trig_dt(np.pi / 180.0)
            sat_el_rad = sat_elevation_deg.astype(trig_dt, copy=False) * trig_dt(np.pi / 180.0)
            cos_daz = (
                cp.cos(tel_az_rad[:, :, None]) * cp.cos(sat_az_rad[:, None, :])
                + cp.sin(tel_az_rad[:, :, None]) * cp.sin(sat_az_rad[:, None, :])
            )
            cos_gamma_rx = (
                cp.sin(tel_el_rad[:, :, None]) * cp.sin(sat_el_rad[:, None, :])
                + cp.cos(tel_el_rad[:, :, None]) * cp.cos(sat_el_rad[:, None, :]) * cos_daz
            )
            cp.clip(cos_gamma_rx, trig_dt(-1.0), trig_dt(1.0), out=cos_gamma_rx)
            grx_offset_deg = (cp.arccos(cos_gamma_rx) * trig_dt(180.0 / np.pi)).astype(pat_dt, copy=False)
            grx_phi_deg_bs = (
                _ras_boresight_frame_phi_deg(
                    tel_az_rad[:, :, None], tel_el_rad[:, :, None],
                    sat_az_rad[:, None, :], sat_el_rad[:, None, :],
                ).astype(pat_dt, copy=False)
                if isinstance(ras_pattern_context, GpuCustomPattern2DContext)
                else None
            )
            grx_db = _evaluate_ras_pattern_cp(
                ras_pattern_context, grx_offset_deg, grx_phi_deg_bs,
            )
            grx_lin = cp.power(pwr_dt(10.0), grx_db.astype(pwr_dt, copy=False) * pwr_dt(0.1))
        grx_lin *= vis_horizon[:, None, :].astype(pwr_dt, copy=False)

        # Fused Prx + EPFD output kernel for fp32 non-boresight path.
        # Works with any EIRP computation path (mega, single-EIRP, or
        # fallback) as long as scale_w_channel is fp32 and we don't
        # need per-satellite Prx output.
        _use_prx_fused = (
            pwr_dt == cp.float32
            and not include_per_satellite_prx  # per-sat Prx needs the full (T, N_tel, S) tensor
        )
        if _use_prx_fused:
            _prx_mod = _get_prx_output_kernel()
            _prx_k = _prx_mod.get_function("compute_prx_and_reduce")
            _n_tel = int(grx_lin.shape[1])
            _want_prx = bool(include_prx_total)
            _want_epfd = bool(include_epfd)
            _want_pfd = bool(include_total_pfd)
            _prx_total_buf = cp.empty((time_count, _n_tel), dtype=cp.float32) if _want_prx or _want_epfd else cp.empty(1, dtype=cp.float32)
            _epfd_buf = cp.empty((time_count, _n_tel), dtype=cp.float32) if _want_epfd else cp.empty(1, dtype=cp.float32)
            _pfd_buf = cp.empty((time_count,), dtype=cp.float32) if _want_pfd else cp.empty(1, dtype=cp.float32)
            _max_idx = max(int(time_count) * int(_n_tel), int(time_count))
            _block = 256
            _prx_k(
                ((_max_idx + _block - 1) // _block,), (_block,),
                (
                    grx_lin, scale_w_channel, vis_horizon,
                    np.float32(float(pfd_from_prx_iso_scale)),
                    np.int32(time_count), np.int32(_n_tel), np.int32(sat_count),
                    np.int32(1 if _want_prx else 0),
                    np.int32(1 if _want_epfd else 0),
                    np.int32(1 if _want_pfd else 0),
                    _prx_total_buf, _epfd_buf, _pfd_buf,
                ),
            )
            if _want_prx:
                result["Prx_total_W"] = _prx_total_buf[:, None, :]
            if _want_epfd:
                result["EPFD_W_m2"] = _epfd_buf[:, None, :]
            if _want_pfd:
                result["PFD_total_RAS_STATION_W_m2"] = _pfd_buf
        else:
            prx_scale_cp = grx_lin * scale_w_channel[:, None, :]
            prx_total_ts = None
            if include_prx_total or include_epfd:
                prx_total_ts = cp.sum(prx_scale_cp, axis=2, dtype=pwr_dt)
            if include_prx_total and prx_total_ts is not None:
                result["Prx_total_W"] = prx_total_ts[:, None, :]
            if include_per_satellite_prx:
                result["Prx_per_sat_RAS_STATION_W"] = cp.transpose(
                    prx_scale_cp, (0, 2, 1),
                )[:, None, :, :]
            if include_epfd:
                if prx_total_ts is None:
                    prx_total_ts = cp.sum(prx_scale_cp, axis=2, dtype=pwr_dt)
                result["EPFD_W_m2"] = (prx_total_ts * pwr_dt(float(pfd_from_prx_iso_scale)))[:, None, :]
    _prx_fused_active = include_receive_outputs and locals().get('_use_prx_fused', False)
    if not _prx_fused_active and include_total_pfd:
        result["PFD_total_RAS_STATION_W_m2"] = (
            cp.sum(scale_w_channel, axis=1, dtype=pwr_dt) * pwr_dt(float(pfd_from_prx_iso_scale))
        )
    if include_per_satellite_pfd:
        result["PFD_per_sat_RAS_STATION_W_m2"] = scale_w_channel * pwr_dt(float(pfd_from_prx_iso_scale))
    return _finalize_cap_stats(result)


def _allocate_chunked_ras_power_result_cp(
    sample: dict[str, Any],
    *,
    sky_total: int,
) -> dict[str, Any]:
    result: dict[str, Any] = {}
    for key, value in sample.items():
        shape = list(cp.asarray(value).shape)
        if not shape:
            result[key] = cp.asarray(value)
            continue
        shape[-1] = int(sky_total)
        result[key] = cp.empty(tuple(shape), dtype=cp.asarray(value).dtype)
    return result


def _store_chunked_ras_power_result_cp(
    target: dict[str, Any],
    slab: dict[str, Any],
    *,
    sky_start: int,
    sky_stop: int,
) -> None:
    for key, value in slab.items():
        target[key][..., sky_start:sky_stop] = value


class _DirectEpfdStageExecutionError(RuntimeError):
    """Wrapped direct-EPFD stage failure with owning stage metadata."""

    def __init__(self, stage: str, original_exception: BaseException) -> None:
        self.stage = str(stage)
        self.original_exception = original_exception
        super().__init__(f"{self.stage}: {original_exception}")


def _allocate_direct_epfd_power_result_cp(
    sample: Mapping[str, Any],
    *,
    time_count: int,
    sky_count: int,
    boresight_active: bool,
) -> dict[str, Any]:
    result: dict[str, Any] = {}
    for key, value in sample.items():
        sample_cp = cp.asarray(value)
        shape = list(sample_cp.shape)
        if not shape:
            result[key] = sample_cp
            continue
        shape[0] = int(time_count)
        if boresight_active:
            shape[-1] = int(sky_count)
        result[key] = cp.zeros(tuple(shape), dtype=sample_cp.dtype)
    return result


def _store_direct_epfd_power_slab_result_cp(
    target: Mapping[str, Any],
    slab: Mapping[str, Any],
    *,
    boresight_active: bool,
    time_start: int,
    time_stop: int,
    sky_start: int,
    sky_stop: int,
) -> None:
    for key, value in slab.items():
        if key not in target:
            continue
        if boresight_active:
            if target[key].ndim == 4:
                target[key][time_start:time_stop, :, :, sky_start:sky_stop] = value
            elif target[key].ndim == 3:
                target[key][time_start:time_stop, :, sky_start:sky_stop] = value
            else:
                target[key][time_start:time_stop, sky_start:sky_stop] = value
        else:
            target[key][time_start:time_stop, ...] = value


def _update_max_numeric_map(
    target: Mapping[str, Any] | None,
    incoming: Mapping[str, Any] | None,
) -> dict[str, Any]:
    merged = dict(target or {})
    if not isinstance(incoming, Mapping):
        return merged
    for key, value in dict(incoming).items():
        key_str = str(key)
        if value is None:
            continue
        try:
            numeric_value = int(value)
        except Exception:
            merged[key_str] = value
            continue
        merged[key_str] = int(max(int(merged.get(key_str, 0) or 0), numeric_value))
    return merged


def _accumulate_cell_group_weighted_sum_cp(
    *,
    group_active_mask_cp: Any,
    cell_group_leakage_factors_cp: Any,
    out_cp: Any,
    group_valid_mask_cp: Any | None = None,
) -> Any:
    """Accumulate `(T, C)` group-weighted leakage without a `(T, C, G)` temp."""
    group_mask_cp = cp.asarray(group_active_mask_cp, dtype=cp.float32)
    leakage_cp = cp.asarray(cell_group_leakage_factors_cp, dtype=cp.float32)
    weighted_sum_cp = cp.asarray(out_cp, dtype=cp.float32)
    effective_leakage_cp = leakage_cp
    if group_valid_mask_cp is not None:
        effective_leakage_cp = effective_leakage_cp * cp.asarray(
            group_valid_mask_cp,
            dtype=cp.float32,
        )
    weighted_sum_cp[...] = cp.einsum(
        "tcg,cg->tc",
        group_mask_cp,
        effective_leakage_cp,
        optimize=True,
    )
    return weighted_sum_cp


def _accumulate_active_group_count_cp(
    *,
    group_active_mask_cp: Any,
    out_cp: Any,
    group_valid_mask_cp: Any | None = None,
) -> Any:
    """Accumulate `(T, C)` active-group counts on device."""
    group_mask_cp = cp.asarray(group_active_mask_cp, dtype=cp.float32)
    active_groups_cp = cp.asarray(out_cp, dtype=cp.float32)
    if group_valid_mask_cp is None:
        active_groups_cp[...] = cp.sum(group_mask_cp, axis=2, dtype=cp.float32)
        return active_groups_cp
    active_groups_cp[...] = cp.einsum(
        "tcg,cg->tc",
        group_mask_cp,
        cp.asarray(group_valid_mask_cp, dtype=cp.float32),
        optimize=True,
    )
    return active_groups_cp


def _configured_group_denominator_cp(
    *,
    configured_groups_per_cell_cp: Any,
    cell_count: int,
) -> tuple[Any, Any]:
    denominator_cp = cp.asarray(configured_groups_per_cell_cp, dtype=cp.float32)
    if getattr(denominator_cp, "ndim", 0) == 0:
        scalar_value = cp.float32(max(1.0, float(denominator_cp)))
        return scalar_value, scalar_value
    if tuple(int(v) for v in denominator_cp.shape) != (int(cell_count),):
        raise ValueError(
            "configured_groups_per_cell must be a scalar or shape "
            f"({int(cell_count)},); got {tuple(denominator_cp.shape)!r}."
        )
    safe_denominator_cp = cp.where(
        denominator_cp > cp.float32(0.0),
        denominator_cp,
        cp.float32(1.0),
    )
    return denominator_cp, safe_denominator_cp


def _get_dynamic_spectral_weight_scratch_cp(
    scratch_cache: dict[tuple[int, int, bool], dict[str, Any]],
    *,
    slab_timesteps: int,
    cell_count: int,
    need_active_group_counts: bool,
) -> dict[str, Any]:
    key = (int(slab_timesteps), int(cell_count), bool(need_active_group_counts))
    cached = scratch_cache.get(key)
    if cached is not None:
        return cached
    cached = {
        "weighted_sum": cp.zeros((int(slab_timesteps), int(cell_count)), dtype=cp.float32),
    }
    if bool(need_active_group_counts):
        cached["active_groups"] = cp.zeros(
            (int(slab_timesteps), int(cell_count)),
            dtype=cp.float32,
        )
    scratch_cache[key] = cached
    return cached


def _compute_dynamic_cell_spectral_weight_slab_cp(
    *,
    group_active_mask_cp: Any,
    cell_group_leakage_factors_cp: Any,
    power_policy: str,
    split_total_group_denominator_mode: str,
    configured_groups_per_cell_cp: Any,
    group_valid_mask_cp: Any | None,
    scratch_cache: dict[tuple[int, int, bool], dict[str, Any]],
) -> Any:
    slab_group_mask_cp = cp.asarray(group_active_mask_cp, dtype=cp.bool_)
    leakage_cp = cp.asarray(cell_group_leakage_factors_cp, dtype=cp.float32)
    slab_timesteps = int(slab_group_mask_cp.shape[0])
    cell_count = int(slab_group_mask_cp.shape[1])
    need_active_group_counts = bool(
        str(power_policy) == "split_total_cell_power"
        and str(split_total_group_denominator_mode) == "active_groups"
    )
    scratch = _get_dynamic_spectral_weight_scratch_cp(
        scratch_cache,
        slab_timesteps=slab_timesteps,
        cell_count=cell_count,
        need_active_group_counts=need_active_group_counts,
    )
    weighted_sum_cp = _accumulate_cell_group_weighted_sum_cp(
        group_active_mask_cp=slab_group_mask_cp,
        cell_group_leakage_factors_cp=leakage_cp,
        out_cp=scratch["weighted_sum"],
        group_valid_mask_cp=group_valid_mask_cp,
    )
    if str(power_policy) == "repeat_per_group":
        return weighted_sum_cp
    if need_active_group_counts:
        active_groups_cp = _accumulate_active_group_count_cp(
            group_active_mask_cp=slab_group_mask_cp,
            out_cp=scratch["active_groups"],
            group_valid_mask_cp=group_valid_mask_cp,
        )
        safe_active_groups_cp = cp.where(
            active_groups_cp > cp.float32(0.0),
            active_groups_cp,
            cp.float32(1.0),
        )
        weighted_sum_cp[...] = cp.where(
            active_groups_cp > cp.float32(0.0),
            weighted_sum_cp / safe_active_groups_cp,
            cp.float32(0.0),
        ).astype(cp.float32, copy=False)
        return weighted_sum_cp
    denominator_cp, safe_denominator_cp = _configured_group_denominator_cp(
        configured_groups_per_cell_cp=configured_groups_per_cell_cp,
        cell_count=int(cell_count),
    )
    if getattr(cp.asarray(denominator_cp), "ndim", 0) == 0:
        weighted_sum_cp[...] = (weighted_sum_cp / safe_denominator_cp).astype(
            cp.float32,
            copy=False,
        )
        return weighted_sum_cp
    weighted_sum_cp[...] = cp.where(
        denominator_cp[None, :] > cp.float32(0.0),
        weighted_sum_cp / safe_denominator_cp[None, :],
        cp.float32(0.0),
    ).astype(cp.float32, copy=False)
    return weighted_sum_cp


def _accumulate_direct_epfd_from_link_library_cp(
    *,
    library: GpuSatelliteLinkSelectionLibrary,
    s1528_pattern_context: Any,
    ras_pattern_context: Any | None,
    sat_topo: Any,
    sat_azel: Any,
    orbit_radius_m_per_sat: Any,
    observer_alt_km: float,
    telescope_azimuth_deg: Any | None,
    telescope_elevation_deg: Any | None,
    atmosphere_lut_context: Any | None,
    spectrum_plan_context: Any | None,
    cell_spectral_weight: Any | None,
    dynamic_group_active_mask: Any | None,
    dynamic_cell_group_leakage_factors: Any | None,
    dynamic_group_valid_mask: Any | None,
    dynamic_power_policy: str | None,
    dynamic_split_total_group_denominator_mode: str | None,
    dynamic_configured_groups_per_cell: Any | None,
    bandwidth_mhz: float,
    power_input_quantity: str,
    target_pfd_dbw_m2_mhz: float | None,
    target_pfd_dbw_m2_channel: float | None,
    satellite_ptx_dbw_mhz: float | None,
    satellite_ptx_dbw_channel: float | None,
    satellite_eirp_dbw_mhz: float | None,
    satellite_eirp_dbw_channel: float | None,
    power_variation_mode: str = "fixed",
    power_range_min_dbw_channel: float | None = None,
    power_range_max_dbw_channel: float | None = None,
    n_links: int,
    ras_service_cell_index: int | None,
    ras_pointing_mode: str,
    ras_guard_angle_rad: float,
    target_alt_km: float,
    use_ras_station_alt_for_co: bool,
    include_epfd: bool,
    include_prx_total: bool,
    include_per_satellite_prx: bool,
    include_total_pfd: bool,
    include_per_satellite_pfd: bool,
    include_diagnostics: bool,
    include_full_sat_beam_counts_used: bool,
    include_sat_eligible_mask: bool,
    output_sat_indices: Any | None,
    finalize_working_memory_budget_bytes: int | None,
    power_working_memory_budget_bytes: int | None,
    power_sky_slab: int | None,
    spectral_slab: int | None,
    peak_pfd_lut_context: "GpuPeakPfdLutContext | None" = None,
    max_surface_pfd_lin_channel: float | None = None,
    surface_pfd_cap_mode: str = "per_beam",
    surface_pfd_stats_enabled: bool = False,
    scheduler_target_profile: str | float | None = "high_throughput",
    debug_direct_epfd: bool = False,
    return_device: bool = True,
    visibility_elev_threshold_deg: float = 0.0,
) -> dict[str, Any]:
    boresight_active = bool(library.boresight_active)
    sky_count_total = int(library.boresight_sky_count if boresight_active else 1)
    sat_topo_cp = _coerce_step2_topo_tensor_cp(sat_topo, name="sat_topo")
    sat_azel_cp = _coerce_step2_topo_tensor_cp(sat_azel, name="sat_azel")
    orbit_radius_cp = _to_cupy_array(orbit_radius_m_per_sat, dtype=cp.float32)
    telescope_az_cp = None if telescope_azimuth_deg is None else _to_cupy_array(
        telescope_azimuth_deg,
        dtype=cp.float32,
    )
    telescope_el_cp = None if telescope_elevation_deg is None else _to_cupy_array(
        telescope_elevation_deg,
        dtype=cp.float32,
    )
    cell_spectral_weight_cp = (
        None
        if cell_spectral_weight is None
        else _to_cupy_array(cell_spectral_weight, dtype=cp.float32)
    )
    dynamic_group_active_mask_cp = (
        None
        if dynamic_group_active_mask is None
        else _to_cupy_array(dynamic_group_active_mask, dtype=cp.bool_)
    )
    dynamic_cell_group_leakage_factors_cp = (
        None
        if dynamic_cell_group_leakage_factors is None
        else _to_cupy_array(dynamic_cell_group_leakage_factors, dtype=cp.float32)
    )
    dynamic_group_valid_mask_cp = (
        None
        if dynamic_group_valid_mask is None
        else _to_cupy_array(dynamic_group_valid_mask, dtype=cp.bool_)
    )
    dynamic_configured_groups_per_cell_cp = (
        None
        if dynamic_configured_groups_per_cell is None
        else _to_cupy_array(dynamic_configured_groups_per_cell)
    )
    spectral_slab_i = int(
        max(
            1,
            min(
                int(library.time_count),
                int(library.time_count if spectral_slab is None else spectral_slab),
            ),
        )
    )
    if dynamic_group_active_mask_cp is not None:
        if getattr(dynamic_group_active_mask_cp, "ndim", 0) != 3:
            raise ValueError("dynamic_group_active_mask must have shape (T, C, G).")
        if int(dynamic_group_active_mask_cp.shape[0]) != int(library.time_count):
            raise ValueError(
                "dynamic_group_active_mask time axis must match link_library.time_count; "
                f"expected {int(library.time_count)}, got {int(dynamic_group_active_mask_cp.shape[0])}."
            )
        if dynamic_cell_group_leakage_factors_cp is None:
            raise ValueError(
                "dynamic_cell_group_leakage_factors are required when dynamic_group_active_mask is provided."
            )
        if tuple(int(v) for v in dynamic_cell_group_leakage_factors_cp.shape) != (
            int(dynamic_group_active_mask_cp.shape[1]),
            int(dynamic_group_active_mask_cp.shape[2]),
        ):
            raise ValueError(
                "dynamic_cell_group_leakage_factors must align with dynamic_group_active_mask over (C, G)."
            )
        if dynamic_group_valid_mask_cp is not None and tuple(
            int(v) for v in dynamic_group_valid_mask_cp.shape
        ) != (
            int(dynamic_group_active_mask_cp.shape[1]),
            int(dynamic_group_active_mask_cp.shape[2]),
        ):
            raise ValueError(
                "dynamic_group_valid_mask must align with dynamic_group_active_mask over (C, G)."
            )
        if dynamic_configured_groups_per_cell_cp is None:
            raise ValueError(
                "dynamic_configured_groups_per_cell is required when dynamic_group_active_mask is provided."
            )

    any_power_outputs = bool(
        include_epfd
        or include_prx_total
        or include_per_satellite_prx
        or include_total_pfd
        or include_per_satellite_pfd
    )
    need_direct_outputs = bool(
        any_power_outputs
        or include_full_sat_beam_counts_used
        or include_diagnostics
        or include_sat_eligible_mask
    )
    if not need_direct_outputs:
        return {
            "power_result": None,
            "sat_beam_counts_used_full": None,
            "diag_result": None,
            "debug_direct_epfd_stats": [],
            "beam_finalize_substage_timings": {},
            "stage_timings": {},
            "beam_finalize_observed_memory": {},
            "power_observed_memory": {},
            "beam_finalize_chunk_shape": {},
            "boresight_compaction_stats": {},
            "hot_path_device_to_host_copy_count": 0,
            "hot_path_device_to_host_copy_bytes": 0,
            "device_scalar_sync_count": 0,
            "sat_eligible_mask": None,
        }

    power_result: dict[str, Any] | None = None
    sat_beam_counts_used_full = None
    diag_result: dict[str, Any] | None = None
    debug_direct_epfd_stats: list[dict[str, Any]] = []
    beam_finalize_substage_timings: dict[str, float] = {}
    stage_timings = {"beam_finalize": 0.0, "power_accumulation": 0.0}
    beam_finalize_observed_memory: dict[str, Any] = {}
    power_observed_memory: dict[str, Any] = {}
    sat_eligible_mask = None
    beam_finalize_slab_count = 0
    dynamic_spectral_weight_scratch_cache: dict[tuple[int, int, bool], dict[str, Any]] = {}

    def _resolve_dynamic_cell_spectral_weight(
        *,
        time_start: int,
        time_stop: int,
    ) -> Any | None:
        if dynamic_group_active_mask_cp is None:
            if cell_spectral_weight_cp is None:
                return None
            return cell_spectral_weight_cp[time_start:time_stop, :]
        spectrum_t0 = time.perf_counter()
        spectral_weight_cp = _compute_dynamic_cell_spectral_weight_slab_cp(
            group_active_mask_cp=dynamic_group_active_mask_cp[time_start:time_stop, :, :],
            cell_group_leakage_factors_cp=dynamic_cell_group_leakage_factors_cp,
            power_policy=str(dynamic_power_policy or "repeat_per_group"),
            split_total_group_denominator_mode=str(
                dynamic_split_total_group_denominator_mode or "configured_groups"
            ),
            configured_groups_per_cell_cp=dynamic_configured_groups_per_cell_cp,
            group_valid_mask_cp=dynamic_group_valid_mask_cp,
            scratch_cache=dynamic_spectral_weight_scratch_cache,
        )
        stage_timings["spectrum_activity_weighting"] = float(
            stage_timings.get("spectrum_activity_weighting", 0.0)
        ) + max(time.perf_counter() - spectrum_t0, 0.0)
        return spectral_weight_cp

    with library.session._temporary_activation():
        finalize_context = _prepare_direct_finalize_execution_cp(
            library,
            ras_cell_index=None if ras_service_cell_index is None else int(ras_service_cell_index),
            ras_sat_azel=sat_azel_cp if str(ras_pointing_mode).strip().lower() == "ras_station" else None,
            ras_guard_angle_rad=float(ras_guard_angle_rad),
            ras_pointing_mode=str(ras_pointing_mode),
            include_diagnostics=bool(include_diagnostics),
            include_full_sat_beam_counts_used=bool(include_full_sat_beam_counts_used),
            output_sat_indices=output_sat_indices,
            working_memory_budget_bytes=finalize_working_memory_budget_bytes,
            return_device=True,
            scheduler_target_profile=scheduler_target_profile,
        )
        beam_finalize_chunk_shape = dict(finalize_context.get("finalize_chunk_shape") or {})
        boresight_compaction_stats: dict[str, Any] = {}

        def _accumulate_slab_info(slab_info: dict[str, Any]) -> None:
            nonlocal power_result
            nonlocal sat_beam_counts_used_full
            nonlocal diag_result
            nonlocal beam_finalize_slab_count
            nonlocal beam_finalize_observed_memory
            nonlocal power_observed_memory
            nonlocal boresight_compaction_stats

            beam_finalize_slab_count += 1
            slab_finalize_seconds = 0.0
            for name, value in dict(slab_info.get("substage_timings") or {}).items():
                try:
                    value_f = float(value)
                    beam_finalize_substage_timings[str(name)] = float(
                        beam_finalize_substage_timings.get(str(name), 0.0)
                    ) + value_f
                    slab_finalize_seconds += value_f
                except Exception:
                    continue
            stage_timings["beam_finalize"] += float(slab_finalize_seconds)
            beam_finalize_observed_memory = _update_max_numeric_map(
                beam_finalize_observed_memory,
                slab_info.get("observed_memory"),
            )
            boresight_compaction_stats = _update_max_numeric_map(
                boresight_compaction_stats,
                slab_info.get("compaction_stats"),
            )

            slab_result = slab_info["result"]
            slab_time_start = int(slab_info["time_start"])
            slab_time_stop = int(slab_info["time_stop"])
            slab_sky_start = int(slab_info["sky_start"])
            slab_sky_stop = int(slab_info["sky_stop"])
            if debug_direct_epfd and "debug_direct_epfd_stats" in slab_result:
                slab_debug = dict(slab_result["debug_direct_epfd_stats"])
                slab_debug.update(
                    time_start=slab_time_start,
                    time_stop=slab_time_stop,
                    sky_start=slab_sky_start,
                    sky_stop=slab_sky_stop,
                )
                debug_direct_epfd_stats.append(slab_debug)

            if include_full_sat_beam_counts_used:
                counts_sample = cp.asarray(slab_result["sat_beam_counts_used_full"])
                if sat_beam_counts_used_full is None:
                    full_shape = (
                        (int(library.time_count), int(sky_count_total), int(library.sat_count))
                        if boresight_active
                        else (int(library.time_count), int(library.sat_count))
                    )
                    sat_beam_counts_used_full = cp.zeros(full_shape, dtype=counts_sample.dtype)
                if boresight_active:
                    sat_beam_counts_used_full[
                        slab_time_start:slab_time_stop,
                        slab_sky_start:slab_sky_stop,
                        :,
                    ] = counts_sample
                else:
                    sat_beam_counts_used_full[slab_time_start:slab_time_stop, :] = counts_sample

            if include_diagnostics:
                diag_keys = (
                    "ras_retargeted_count",
                    "ras_reserved_count",
                    "direct_kept_count",
                    "repaired_link_count",
                    "dropped_link_count",
                )
                if diag_result is None:
                    diag_shape = (
                        (int(library.time_count), int(sky_count_total))
                        if boresight_active
                        else (int(library.time_count),)
                    )
                    diag_result = {key: cp.zeros(diag_shape, dtype=cp.int32) for key in diag_keys}
                for key in diag_keys:
                    if boresight_active:
                        diag_result[key][
                            slab_time_start:slab_time_stop,
                            slab_sky_start:slab_sky_stop,
                        ] = cp.asarray(slab_result[key])
                    else:
                        diag_result[key][slab_time_start:slab_time_stop] = cp.asarray(slab_result[key])

            if not any_power_outputs:
                return

            slab_duration = int(max(0, slab_time_stop - slab_time_start))
            inner_spectral_slab = int(max(1, min(int(spectral_slab_i), max(1, slab_duration))))
            slab_beam_idx_cp = cp.asarray(slab_result["beam_idx"])
            slab_beam_alpha_cp = cp.asarray(slab_result["beam_alpha_rad"])
            slab_beam_beta_cp = cp.asarray(slab_result["beam_beta_rad"])
            slab_sat_topo_cp = sat_topo_cp[slab_time_start:slab_time_stop, :, :]
            slab_sat_azel_cp = sat_azel_cp[slab_time_start:slab_time_stop, :, :]
            slab_telescope_az_cp = None
            slab_telescope_el_cp = None
            if telescope_az_cp is not None:
                slab_telescope_az_cp = (
                    telescope_az_cp[slab_time_start:slab_time_stop, slab_sky_start:slab_sky_stop]
                    if boresight_active
                    else telescope_az_cp[slab_time_start:slab_time_stop]
                )
            if telescope_el_cp is not None:
                slab_telescope_el_cp = (
                    telescope_el_cp[slab_time_start:slab_time_stop, slab_sky_start:slab_sky_stop]
                    if boresight_active
                    else telescope_el_cp[slab_time_start:slab_time_stop]
                )

            # ----------------------------------------------------------------
            # Surface-PFD cap hoist.
            # ----------------------------------------------------------------
            # The power kernel below is invoked once per spectral slab
            # (typically ``inner_spectral_slab=1`` when cell activity is
            # ``whole_cell``), which means the cap computation would
            # otherwise re-run for every timestep inside this slab even
            # though its inputs (beam geometry + per-beam peak EIRP) are
            # identical across slabs.  Compute the cap factor ONCE here
            # for the full ``slab_duration`` window and pass a per-slab
            # slice into each power call.  This keeps the helper's GPU
            # work amortised across all spectral slabs in the batch.
            #
            # Both ``per_beam`` and ``per_satellite`` modes benefit —
            # per-satellite went from ~94% overhead to ~0% when it was
            # first hoisted, and per-beam drops from ~10% to ~1%.  The
            # in-kernel fallback paths stay in place for callers that
            # invoke ``_accumulate_ras_power_cp`` directly without the
            # fused direct-EPFD wrapper.
            cap_mode_hoist = str(surface_pfd_cap_mode or "per_beam").strip().lower()
            hoisted_cap_factor_cp: Any | None = None
            hoisted_cap_stats: dict[str, float] | None = None
            # The hoist handles both the 3-D classical path and the 4-D
            # boresight-avoidance path.  For 4-D the slab beam tensors
            # carry an extra ``N_sky`` axis, so the slab-wide EIRP peak
            # and cap-factor tensors are four-dimensional.  The sat axis
            # index passed to ``_compute_aggregate_surface_pfd_cap_cp``
            # tracks that axis position in each case.
            if (
                peak_pfd_lut_context is not None
                and max_surface_pfd_lin_channel is not None
                and float(max_surface_pfd_lin_channel) > 0.0
                and cap_mode_hoist in {"per_beam", "per_satellite"}
                and slab_duration > 0
                and not isinstance(s1528_pattern_context, GpuIsotropicPatternContext)
            ):
                # Derive per-beam peak EIRP for the whole slab, matching
                # the semantics inside the power kernel. Use the
                # canonical ``_pattern_peak_gain_linear`` resolver so
                # Custom-1D / Custom-2D contexts (whose peak comes from
                # the schema's ``peak_gain_dbi`` field, not a
                # closed-form ``gm_db`` / ``g_emax_db``) pick up their
                # actual peak rather than silently falling back to
                # ``gmax_lin=1`` (0 dB).
                _gmax_lin_loc = float(_pattern_peak_gain_linear(s1528_pattern_context))
                quantity_loc = str(power_input_quantity).strip().lower()
                # Resolve the channel-total power inputs the same way the
                # hot kernel does via ``session.accumulate_ras_power``.
                bw_mhz_loc = float(bandwidth_mhz)
                def _coerce_ch(ch, spec):
                    if ch is not None and np.isfinite(float(ch)):
                        return float(ch)
                    if spec is not None and np.isfinite(float(spec)):
                        return float(spec) + 10.0 * math.log10(bw_mhz_loc)
                    return None
                target_pfd_ch_loc = _coerce_ch(target_pfd_dbw_m2_channel, target_pfd_dbw_m2_mhz)
                ptx_ch_loc = _coerce_ch(satellite_ptx_dbw_channel, satellite_ptx_dbw_mhz)
                eirp_ch_loc = _coerce_ch(satellite_eirp_dbw_channel, satellite_eirp_dbw_mhz)

                earth_r_loc = float(R_earth.to_value(u.m))
                orbit_r_cp_loc = orbit_radius_cp.astype(cp.float32, copy=False).reshape(-1)
                slab_valid_beam_cp = slab_beam_idx_cp >= 0
                slab_beta_w = slab_beam_beta_cp.astype(cp.float32, copy=False)
                slab_cosb = cp.cos(slab_beta_w)
                slab_sinb = cp.sin(slab_beta_w)
                # Broadcast orbit radius along the sat axis.  Slab beam
                # tensors are ``(T_slab, S, K)`` for the 3-D path and
                # ``(T_slab, N_sky, S, K)`` for the 4-D boresight-
                # avoidance path; the sat axis is the second-to-last.
                if slab_beam_beta_cp.ndim == 4:
                    r_bcast = orbit_r_cp_loc[None, None, :, None]
                    hoist_sat_axis_index = 2
                else:
                    r_bcast = orbit_r_cp_loc[None, :, None]
                    hoist_sat_axis_index = 1
                term_full = r_bcast * slab_cosb
                disc_full = term_full * term_full - (
                    r_bcast * r_bcast - cp.float32(earth_r_loc * earth_r_loc)
                )
                valid_geom_full = disc_full >= cp.float32(0.0)
                d_target_full = term_full - cp.sqrt(cp.maximum(disc_full, cp.float32(0.0)))

                if atmosphere_lut_context is not None:
                    cos_e_target_full = cp.clip(
                        (r_bcast / cp.float32(earth_r_loc)) * slab_sinb,
                        cp.float32(0.0), cp.float32(1.0),
                    )
                    e_target_deg_full = cp.arccos(cos_e_target_full) * cp.float32(
                        180.0 / np.pi
                    )
                    e_target_deg_full = cp.maximum(
                        e_target_deg_full,
                        cp.float32(atmosphere_lut_context.elev_min_deg),
                    )
                    atm_target_full = _lookup_atmosphere_lut_cp(
                        atmosphere_lut_context,
                        e_target_deg_full,
                        altitude_km=float(target_alt_km),
                    ).astype(cp.float32, copy=False)
                    atm_target_full = cp.maximum(atm_target_full, cp.float32(1.0e-30))
                else:
                    atm_target_full = cp.ones_like(d_target_full)

                four_pi_loc = cp.float32(4.0 * np.pi)
                if quantity_loc == "target_pfd" and target_pfd_ch_loc is not None:
                    tgt_lin = cp.float32(10.0 ** (float(target_pfd_ch_loc) / 10.0))
                    eirp_peak_loc = cp.where(
                        valid_geom_full,
                        tgt_lin * four_pi_loc * d_target_full * d_target_full / atm_target_full,
                        cp.float32(0.0),
                    )
                elif quantity_loc == "satellite_eirp" and eirp_ch_loc is not None:
                    eirp_peak_loc = cp.full(
                        slab_beam_beta_cp.shape,
                        cp.float32(10.0 ** (float(eirp_ch_loc) / 10.0)),
                        dtype=cp.float32,
                    )
                elif quantity_loc == "satellite_ptx" and ptx_ch_loc is not None:
                    eirp_peak_loc = cp.full(
                        slab_beam_beta_cp.shape,
                        cp.float32(
                            (10.0 ** (float(ptx_ch_loc) / 10.0)) * float(_gmax_lin_loc)
                        ),
                        dtype=cp.float32,
                    )
                else:
                    eirp_peak_loc = cp.zeros(
                        slab_beam_beta_cp.shape, dtype=cp.float32,
                    )

                if cap_mode_hoist == "per_satellite":
                    (
                        hoisted_cap_factor_cp,
                        _hoisted_peak_pfd_cp,
                        hoisted_cap_stats,
                    ) = _compute_aggregate_surface_pfd_cap_cp(
                        beam_alpha_cp=slab_beam_alpha_cp,
                        beam_beta_cp=slab_beam_beta_cp,
                        beam_valid_cp=slab_valid_beam_cp,
                        eirp_peak_cp=eirp_peak_loc,
                        orbit_radius_per_sat_cp=orbit_r_cp_loc,
                        sat_axis_index=hoist_sat_axis_index,
                        pattern_context=s1528_pattern_context,
                        atmosphere_lut_context=atmosphere_lut_context,
                        target_alt_km=float(target_alt_km),
                        max_surface_pfd_lin=float(max_surface_pfd_lin_channel),
                    )
                else:
                    # Per-beam hoist: compute the (T_slab, S, K) cap
                    # factor tensor directly without running the
                    # aggregate helper — one K lookup + one multiply
                    # per beam slot is the entire computation.
                    sat_count_loc = int(orbit_r_cp_loc.size)
                    # Match the current sat axis to the LUT via the
                    # same centimetre-precision shell matching the hot
                    # kernel uses (see ``_accumulate_ras_power_cp``).
                    n_shells_loc = int(
                        peak_pfd_lut_context.d_k_lut.shape[0]
                    )
                    if n_shells_loc == 1:
                        cap_shell_id_loc = cp.zeros(
                            (sat_count_loc,), dtype=cp.int32,
                        )
                    else:
                        shell_radii_loc = cp.asarray(
                            peak_pfd_lut_context.orbit_radius_m_per_shell,
                            dtype=cp.float64,
                        ).reshape(-1)
                        shell_cm_loc = cp.rint(
                            shell_radii_loc * cp.float64(100.0),
                        ).astype(cp.int64)
                        orbit_cm_loc = cp.rint(
                            orbit_r_cp_loc.astype(cp.float64, copy=False)
                            * cp.float64(100.0),
                        ).astype(cp.int64)
                        matches_loc = (
                            orbit_cm_loc[:, None] == shell_cm_loc[None, :]
                        )
                        if not bool(cp.all(cp.any(matches_loc, axis=1)).get()):
                            raise ValueError(
                                "Hoisted per-beam cap: one or more satellite "
                                "orbit radii do not match any shell in the "
                                "peak-PFD LUT context."
                            )
                        cap_shell_id_loc = cp.argmax(
                            matches_loc, axis=1,
                        ).astype(cp.int32, copy=False)

                    # Broadcast ``cap_shell_id_loc`` along the sat axis
                    # only.  Shape depends on whether the slab is 3-D
                    # or 4-D (boresight-avoidance adds an ``N_sky`` dim).
                    if slab_beam_beta_cp.ndim == 4:
                        shell_per_beam_slab = cp.broadcast_to(
                            cap_shell_id_loc[None, None, :, None],
                            slab_beam_beta_cp.shape,
                        )
                    else:
                        shell_per_beam_slab = cp.broadcast_to(
                            cap_shell_id_loc[None, :, None],
                            slab_beam_beta_cp.shape,
                        )
                    k_per_beam_slab = _lookup_peak_pfd_k_any_cp(
                        peak_pfd_lut_context,
                        slab_beam_alpha_cp,
                        slab_beam_beta_cp,
                        shell_per_beam_slab,
                    ).astype(cp.float32, copy=False)
                    peak_pfd_slab = (
                        eirp_peak_loc.astype(cp.float32, copy=False)
                        * k_per_beam_slab
                    )
                    peak_safe_slab = cp.maximum(
                        peak_pfd_slab, cp.float32(1.0e-30),
                    )
                    cap_factor_slab = cp.minimum(
                        cp.float32(1.0),
                        cp.float32(float(max_surface_pfd_lin_channel))
                        / peak_safe_slab,
                    ).astype(cp.float32, copy=False)
                    # Invalid beams get a unit cap factor so stats
                    # computed downstream cannot count them as "capped".
                    cap_factor_slab = cp.where(
                        slab_valid_beam_cp, cap_factor_slab, cp.float32(1.0),
                    )
                    hoisted_cap_factor_cp = cap_factor_slab
                    if surface_pfd_stats_enabled:
                        _mask_loc = (
                            (cap_factor_slab < cp.float32(1.0 - 1.0e-6))
                            & slab_valid_beam_cp
                        )
                        _cap_db_loc = cp.where(
                            _mask_loc,
                            cp.float32(-10.0)
                            * cp.log10(
                                cp.maximum(cap_factor_slab, cp.float32(1.0e-30))
                            ),
                            cp.float32(0.0),
                        )
                        # Single D2H sync for all three stats scalars
                        _stats_dev = cp.array([
                            cp.count_nonzero(_mask_loc).astype(cp.float32),
                            cp.sum(_cap_db_loc),
                            cp.max(_cap_db_loc) if int(_cap_db_loc.size) > 0 else cp.float32(0.0),
                        ])
                        _stats_host = _stats_dev.get()
                        hoisted_cap_stats = {
                            "n_capped": int(_stats_host[0]),
                            "cap_db_sum": float(_stats_host[1]),
                            "cap_db_max": float(_stats_host[2]),
                        }
                    else:
                        hoisted_cap_stats = None

            for slab_local_start in range(0, max(1, slab_duration), inner_spectral_slab):
                slab_local_stop = min(slab_duration, slab_local_start + inner_spectral_slab)
                spectral_time_start = slab_time_start + slab_local_start
                spectral_time_stop = slab_time_start + slab_local_stop
                power_memory_observation = _start_gpu_memory_observation_cp()
                power_t0 = time.perf_counter()
                try:
                    slab_power = library.session.accumulate_ras_power(
                        s1528_pattern_context=s1528_pattern_context,
                        ras_pattern_context=ras_pattern_context,
                        sat_topo=slab_sat_topo_cp[slab_local_start:slab_local_stop, :, :],
                        sat_azel=slab_sat_azel_cp[slab_local_start:slab_local_stop, :, :],
                        beam_idx=slab_beam_idx_cp[slab_local_start:slab_local_stop, ...],
                        beam_alpha_rad=slab_beam_alpha_cp[slab_local_start:slab_local_stop, ...],
                        beam_beta_rad=slab_beam_beta_cp[slab_local_start:slab_local_stop, ...],
                        telescope_azimuth_deg=(
                            None
                            if slab_telescope_az_cp is None
                            else slab_telescope_az_cp[slab_local_start:slab_local_stop, ...]
                        ),
                        telescope_elevation_deg=(
                            None
                            if slab_telescope_el_cp is None
                            else slab_telescope_el_cp[slab_local_start:slab_local_stop, ...]
                        ),
                        orbit_radius_m_per_sat=orbit_radius_cp,
                        observer_alt_km=float(observer_alt_km),
                        atmosphere_lut_context=atmosphere_lut_context,
                        spectrum_plan_context=spectrum_plan_context,
                    cell_spectral_weight=_resolve_dynamic_cell_spectral_weight(
                        time_start=spectral_time_start,
                        time_stop=spectral_time_stop,
                    ),
                    bandwidth_mhz=float(bandwidth_mhz),
                    power_input_quantity=str(power_input_quantity),
                    pfd0_dbw_m2_mhz=None,
                    target_pfd_dbw_m2_mhz=target_pfd_dbw_m2_mhz,
                    target_pfd_dbw_m2_channel=target_pfd_dbw_m2_channel,
                    satellite_ptx_dbw_mhz=satellite_ptx_dbw_mhz,
                    satellite_ptx_dbw_channel=satellite_ptx_dbw_channel,
                    satellite_eirp_dbw_mhz=satellite_eirp_dbw_mhz,
                    satellite_eirp_dbw_channel=satellite_eirp_dbw_channel,
                    power_variation_mode=power_variation_mode,
                    power_range_min_dbw_channel=power_range_min_dbw_channel,
                    power_range_max_dbw_channel=power_range_max_dbw_channel,
                    n_links=int(n_links),
                        ras_service_cell_index=(
                            None if ras_service_cell_index is None else int(ras_service_cell_index)
                        ),
                        target_alt_km=float(target_alt_km),
                        use_ras_station_alt_for_co=bool(use_ras_station_alt_for_co),
                        include_epfd=bool(include_epfd),
                        include_prx_total=bool(include_prx_total),
                        include_per_satellite_prx=bool(include_per_satellite_prx),
                        include_total_pfd=bool(include_total_pfd),
                        include_per_satellite_pfd=bool(include_per_satellite_pfd),
                        peak_pfd_lut_context=peak_pfd_lut_context,
                        # Forward the pre-computed linear value directly —
                        # the public wrapper accepts ``max_surface_pfd_lin_channel``
                        # as an internal fast path that skips the dB↔linear
                        # round-trip through fp32.
                        max_surface_pfd_lin_channel=max_surface_pfd_lin_channel,
                        surface_pfd_cap_mode=str(surface_pfd_cap_mode),
                        surface_pfd_stats_enabled=bool(surface_pfd_stats_enabled),
                        precomputed_cap_factor_cp=(
                            None
                            if hoisted_cap_factor_cp is None
                            else hoisted_cap_factor_cp[slab_local_start:slab_local_stop]
                        ),
                        precomputed_cap_stats=(
                            None
                            if hoisted_cap_stats is None
                            or slab_local_start != 0
                            else hoisted_cap_stats
                        ),
                        working_memory_budget_bytes=power_working_memory_budget_bytes,
                        sky_slab=power_sky_slab,
                        return_device=True,
                        visibility_elev_threshold_deg=float(visibility_elev_threshold_deg),
                    )
                except Exception as exc:
                    raise _DirectEpfdStageExecutionError("power_accumulation", exc) from exc
                stage_timings["power_accumulation"] += max(time.perf_counter() - power_t0, 0.0)
                power_observed_memory = _update_max_numeric_map(
                    power_observed_memory,
                    _finalize_gpu_memory_observation_cp(
                        _update_gpu_memory_observation_cp(power_memory_observation)
                    ),
                )
                if power_result is None:
                    power_result = _allocate_direct_epfd_power_result_cp(
                        slab_power,
                        time_count=int(library.time_count),
                        sky_count=int(sky_count_total),
                        boresight_active=boresight_active,
                    )
                try:
                    _store_direct_epfd_power_slab_result_cp(
                        power_result,
                        slab_power,
                        boresight_active=boresight_active,
                        time_start=spectral_time_start,
                        time_stop=spectral_time_stop,
                        sky_start=slab_sky_start,
                        sky_stop=slab_sky_stop,
                    )
                except Exception as exc:
                    raise _DirectEpfdStageExecutionError("power_accumulation", exc) from exc

        for time_start in range(0, int(library.time_count), int(finalize_context["time_chunk_size"])):
            try:
                _build_direct_finalize_time_slab_results_cp(
                    library,
                    context=finalize_context,
                    time_start=int(time_start),
                    debug_direct_epfd=bool(debug_direct_epfd),
                    slab_handler=_accumulate_slab_info,
                )
            except Exception as exc:
                raise _DirectEpfdStageExecutionError("beam_finalize", exc) from exc

    if include_sat_eligible_mask:
        sat_eligible_mask = getattr(library, "eligible_mask_cp", None)
    if not return_device:
        power_result = (
            None
            if power_result is None
            else {key: copy_device_to_host(value) for key, value in power_result.items()}
        )
        sat_beam_counts_used_full = (
            None
            if sat_beam_counts_used_full is None
            else copy_device_to_host(sat_beam_counts_used_full)
        )
        diag_result = (
            None
            if diag_result is None
            else {key: copy_device_to_host(value) for key, value in diag_result.items()}
        )
        sat_eligible_mask = None if sat_eligible_mask is None else copy_device_to_host(sat_eligible_mask)

    return {
        "power_result": power_result,
        "sat_beam_counts_used_full": sat_beam_counts_used_full,
        "diag_result": diag_result,
        "debug_direct_epfd_stats": debug_direct_epfd_stats,
        "beam_finalize_substage_timings": dict(beam_finalize_substage_timings),
        "stage_timings": dict(stage_timings),
        "beam_finalize_observed_memory": dict(beam_finalize_observed_memory),
        "power_observed_memory": dict(power_observed_memory),
        "beam_finalize_slab_count": int(beam_finalize_slab_count),
        "beam_finalize_chunk_shape": dict(beam_finalize_chunk_shape),
        "boresight_compaction_stats": dict(boresight_compaction_stats),
        "hot_path_device_to_host_copy_count": 0,
        "hot_path_device_to_host_copy_bytes": 0,
        "device_scalar_sync_count": 0,
        "sat_eligible_mask": sat_eligible_mask,
    }


def _slice_pointing_sky_axis(
    value: Any | None,
    *,
    sky_start: int,
    sky_stop: int,
) -> Any | None:
    if value is None:
        return None
    return value[:, sky_start:sky_stop]


# Session lifecycle and cooperative cache eviction live here so the owner-thread
# rules are visible next to the session class that enforces them.
class _SessionRegistry:
    def __init__(self) -> None:
        self._lock = threading.RLock()
        self._sessions: dict[tuple[int, int], set["GpuScepterSession"]] = {}

    def register(self, session: "GpuScepterSession") -> None:
        with self._lock:
            key = (session.owner_thread_id, session.device_id)
            self._sessions.setdefault(key, set()).add(session)

    def unregister(self, session: "GpuScepterSession") -> bool:
        with self._lock:
            key = (session.owner_thread_id, session.device_id)
            sessions = self._sessions.get(key)
            if sessions is None:
                return True
            sessions.discard(session)
            if not sessions:
                self._sessions.pop(key, None)
                return True
            return False

    def owner_thread_has_sessions(self, owner_thread_id: int) -> bool:
        with self._lock:
            return any(key[0] == owner_thread_id for key in self._sessions)


_SESSION_REGISTRY = _SessionRegistry()


class _SessionActivation:
    def __init__(self, session: "GpuScepterSession") -> None:
        self._session = session

    def __enter__(self) -> "GpuScepterSession":
        self._session._enter_activation()
        return self._session

    def __exit__(self, exc_type: Any, exc: Any, tb: Any) -> None:
        self._session._exit_activation()

    def __call__(self, func: Callable[..., Any]) -> Callable[..., Any]:
        @functools.wraps(func)
        def _wrapped(*args: Any, **kwargs: Any) -> Any:
            with self._session.activate():
                return func(*args, **kwargs)

        return _wrapped


def _detach_cached_device_refs(obj: Any) -> list[Any]:
    """
    Drop cached device-array references from a tracked session object.

    Parameters
    ----------
    obj : Any
        Cached session object, typically a prepared context or propagation
        workspace dataclass.

    Returns
    -------
    list[Any]
        References to the detached device objects. The caller can hold these
        temporarily until after synchronization to avoid freeing memory while
        queued GPU work may still be completing.
    """
    fields = getattr(type(obj), "__dataclass_fields__", None)
    if fields is None:
        return []

    detached: list[Any] = []
    for name in fields:
        value = getattr(obj, name)
        if name == "d_params":
            if isinstance(value, dict):
                detached.extend(
                    item
                    for item in value.values()
                    if item is not None
                )
            setattr(obj, name, {})
        elif name.startswith("d_"):
            if value is not None:
                detached.append(value)
            setattr(obj, name, None)
    return detached


class GpuScepterSession:
    """
    Persistent GPU workflow session for repeated SCEPTer loop workflows.

    Parameters
    ----------
    device_id : int, optional
        CUDA device index used for all work performed by this session.
    compute_dtype : {numpy.float64, numpy.float32}, optional
        GPU compute dtype used for propagation and observer geometry.
    sat_frame : {"xyz", "zxy"}, optional
        Satellite reference frame used by the downstream geometry pipeline.
        ``"xyz"`` follows the ITU-R SM.1413-style convention used by
        `cysgp4` for beam geometry: ``x`` along the instantaneous velocity
        vector, ``z`` toward nadir after orthogonalization, and ``y`` closing
        the right-handed triad. ``"zxy"`` matches the `cysgp4`
        `calc_sat_azel` convention.
    gravity_model : {"wgs72", "wgs84"}, optional
        Earth-gravity constant set used when initialising TLE propagation
        state. The default ``"wgs72"`` preserves `pycraf` and current
        `cysgp4`-style behaviour.
    ellipsoid_model : {"wgs72", "wgs84"}, optional
        Reference ellipsoid used for host/device geodetic conversions and
        observer ECEF coordinates. The default ``"wgs72"`` preserves current
        backend behaviour.
    idle_timeout_s : float, optional
        Idle timeout in seconds for cooperative idle cache eviction. Cached
        device state is only evicted when the owner thread next re-enters the
        session after being idle for at least this long.
    watchdog_enabled : bool, optional
        Whether cooperative idle cache eviction should be enabled for this
        session. No background thread performs CUDA work.

    Notes
    -----
    The session is the canonical GPU workflow container in this module. Keep a
    surrounding ``with session.activate():`` scope across repeated loops when
    chaining propagation, geometry-only derivations, angular-distance
    calculations, or future GPU post-processing helpers.
    """

    def __init__(
        self,
        device_id: int = 0,
        compute_dtype: Any = np.float64,
        sat_frame: str = "xyz",
        gravity_model: str = EARTH_MODEL_WGS72,
        ellipsoid_model: str = EARTH_MODEL_WGS72,
        idle_timeout_s: float = 900.0,
        watchdog_enabled: bool = True,
    ) -> None:
        _require_cuda()
        _require_supported_geometry_flags(sat_frame=sat_frame)
        self.device_id = int(device_id)
        self.compute_dtype = _normalise_compute_dtype(compute_dtype)
        self.pattern_dtype = np.dtype(np.float32)
        self.power_dtype = np.dtype(np.float32)
        self.sat_frame = sat_frame
        self.gravity_model = _normalise_earth_model(gravity_model, default=EARTH_MODEL_WGS72)
        self.ellipsoid_model = _normalise_earth_model(ellipsoid_model, default=EARTH_MODEL_WGS72)
        self.idle_timeout_s = float(idle_timeout_s)
        self.watchdog_enabled = bool(watchdog_enabled)
        self.owner_thread_id = threading.get_ident()
        self._lock = threading.RLock()
        self._activation_depth = 0
        self._closed = False
        self._last_used_monotonic = time.monotonic()
        self._primary_context: Any | None = None
        self._satellite_context_cache: dict[tuple[Any, ...], GpuSatelliteContext] = {}
        self._observer_context_cache: dict[tuple[Any, ...], GpuObserverContext] = {}
        self._workspace_cache: dict[tuple[Any, ...], GpuPropagationWorkspace] = {}
        self._angle_sampler_context_cache: dict[tuple[Any, ...], GpuAngleSamplerContext] = {}
        self._s1586_pointing_context_cache: dict[tuple[Any, ...], GpuS1586PointingContext] = {}
        self._s1528_pattern_context_cache: dict[tuple[Any, ...], GpuS1528PatternContext] = {}
        self._ras_pattern_context_cache: dict[tuple[Any, ...], GpuRasPatternContext] = {}
        # Custom-pattern contexts are two-level:
        # ``{system_id: OrderedDict[content-hash key -> context]}``.
        # The outer dict gives every registered system its own LRU
        # bucket so cross-system eviction can't happen (system A's
        # in-place pattern tweaks don't evict system B's contexts).
        # Each bucket is an ``OrderedDict`` with ``LRU`` semantics —
        # move-to-end on hit, pop-oldest on overflow — capped at
        # ``_CUSTOM_PATTERN_CACHE_SLOTS_PER_SYSTEM``. Callers that
        # don't pass ``system_id`` (tests, GUI previews) use a
        # single shared ``None`` bucket with the same per-bucket cap.
        # Keys use the pattern's ``content_fingerprint()`` — a BLAKE2b
        # -128 hash over every radiation-affecting field — so a
        # mutating caller flips the hash and the cache automatically
        # misses on the next ``prepare_*`` call.
        self._custom_pattern_context_cache: dict[
            Any, OrderedDict[tuple[Any, ...], Any]
        ] = {}
        self._atmosphere_lut_context_cache: dict[tuple[Any, ...], GpuAtmosphereLutContext] = {}
        self._peak_pfd_lut_context_cache: dict[tuple[Any, ...], GpuPeakPfdLutContext] = {}
        self._spectrum_plan_context_cache: dict[tuple[Any, ...], GpuSpectrumPlanContext] = {}
        # Dedicated non-default stream for export-stage device-to-host
        # transfers.  Lazy-built on first access so sessions that don't
        # run the direct-EPFD pipeline (pure geometry, tests) don't pay
        # the per-session stream creation cost.  See
        # ``copy_device_to_host_async`` and ``sync_export_stream``.
        self._export_stream: Any | None = None
        _SESSION_REGISTRY.register(self)

    def activate(self) -> _SessionActivation:
        """
        Return a re-entrant activation scope for repeated GPU calls.

        The returned object works both as a context manager and as a decorator.

        Returns
        -------
        _SessionActivation
            Re-entrant helper that activates the session on entry and restores
            the previous activation depth on exit.

        Notes
        -----
        Use the context-manager form for explicit loop bodies and the decorator
        form for helper functions that should execute inside one persistent GPU
        activation scope. Cooperative idle eviction, when enabled, runs only
        when the owner thread enters such a scope.
        """
        return _SessionActivation(self)

    @property
    def is_active(self) -> bool:
        """Whether the owning thread currently has this session activated."""
        return self._activation_depth > 0

    @property
    def is_closed(self) -> bool:
        """Whether :meth:`close` has already been called."""
        return self._closed

    def _ensure_owner_thread(self) -> None:
        if threading.get_ident() != self.owner_thread_id:
            raise RuntimeError("GpuScepterSession may only be used from its owner thread.")

    def _ensure_open(self) -> None:
        if self._closed:
            raise RuntimeError("GpuScepterSession is closed.")

    def _touch(self) -> None:
        self._last_used_monotonic = time.monotonic()

    def _ensure_export_stream(self) -> Any:
        """Lazy-build and cache the dedicated export-stage CUDA stream.

        The stream is created the first time an async D2H is requested on
        this session — avoids paying the ``cp.cuda.Stream`` constructor
        cost for sessions that never export (pure-geometry tests, GUI
        previews).  Used by ``copy_device_to_host_async`` +
        ``sync_export_stream`` to queue export D2Hs off the null stream
        so host-side payload construction can overlap with in-flight
        transfers.
        """
        if self._export_stream is None and _has_cupy():
            # Non-blocking so it doesn't implicitly serialise against the
            # null stream (the one the hot GPU kernels use) — we sync
            # explicitly at end-of-export instead.
            self._export_stream = cp.cuda.Stream(non_blocking=True)
        return self._export_stream

    def copy_device_to_host_async(self, value: Any) -> np.ndarray:
        """Async variant of :func:`copy_device_to_host`.

        Queues the memcpy on the session's dedicated export stream and
        returns the host numpy array immediately.  The returned buffer
        is NOT safe to read until :meth:`sync_export_stream` has been
        called — callers must sync before handing the array to a
        downstream consumer (writer, caller, hashing, etc.).

        Falls back to the synchronous path for non-CuPy inputs (already
        on host, Numba device arrays, etc.) so callers can use this
        everywhere without type-sniffing.
        """
        if not _has_cupy() or not isinstance(value, cp.ndarray):
            return copy_device_to_host(value)
        stream = self._ensure_export_stream()
        if stream is None:
            return cp.asnumpy(value)
        return cp.asnumpy(value, stream=stream)

    def sync_export_stream(self) -> None:
        """Wait for pending async export D2Hs to complete.

        Call once per batch after all :meth:`copy_device_to_host_async`
        calls finish queueing, BEFORE touching any of the returned host
        buffers or handing them to the writer.  Safe no-op when the
        export stream was never created.
        """
        if self._export_stream is not None:
            self._export_stream.synchronize()

    def _enter_activation(self) -> None:
        self._ensure_owner_thread()
        self._ensure_open()
        with self._lock:
            if self._activation_depth == 0:
                self._primary_context = cuda.gpus[self.device_id].get_primary_context()
                self._primary_context.push()
                self._activation_depth = 1
                try:
                    self._evict_if_idle_on_owner_thread()
                except Exception:
                    self._activation_depth = 0
                    if self._primary_context is not None:
                        self._primary_context.pop()
                        self._primary_context = None
                    raise
            else:
                self._activation_depth += 1
            self._touch()

    def _exit_activation(self) -> None:
        self._ensure_owner_thread()
        with self._lock:
            if self._activation_depth <= 0:
                raise RuntimeError("GpuScepterSession activation underflow.")
            self._activation_depth -= 1
            if self._activation_depth == 0 and self._primary_context is not None:
                self._primary_context.pop()
            self._touch()

    def _temporary_activation(self) -> Iterator[None]:
        session = self

        class _AutoActivation:
            def __enter__(self_inner) -> None:
                if session._activation_depth == 0:
                    session._enter_activation()
                    self_inner.did_activate = True
                else:
                    self_inner.did_activate = False

            def __exit__(self_inner, exc_type: Any, exc: Any, tb: Any) -> None:
                if getattr(self_inner, "did_activate", False):
                    session._exit_activation()

        return _AutoActivation()

    def prepare_satellite_context(
        self,
        tles: Any,
        *,
        method: str = METHOD_VALLADO,
        gravity_model: str | None = None,
    ) -> GpuSatelliteContext:
        """
        Prepare and cache GPU propagation state for a TLE set.

        Parameters
        ----------
        tles : Any
            Scalar, 1-D, or broadcast-style array-like of `cysgp4.PyTle`
            objects. Inputs are flattened to a 1-D ordered unique tuple.
        method : {"vallado", "dwarner"}, optional
            Propagation backend. Both methods use the same fully device-native
            propagation and geometry pipeline. ``"vallado"`` is validated
            against CPU Vallado and ``"dwarner"`` is validated against CPU
            Dwarner. Legacy aliases ``"vallado_gpu"`` and ``"dwarner_gpu"``
            are accepted and normalised.
        gravity_model : {"wgs72", "wgs84"} or None, optional
            Optional gravity-model override for this prepared TLE context. If
            omitted, the session default is used.

        Returns
        -------
        GpuSatelliteContext
            Cached satellite context bound to this session and CUDA device.
            The context stores a 1-D unique ordered satellite list, per-method
            coefficient packs, epoch MJDs in days, and device-resident index
            maps for subset launches.

        Notes
        -----
        The context is reusable across repeated `mjds` batches and observer
        chunk loops. Reusing a prepared satellite context avoids repeated TLE
        parsing, coefficient extraction, and device uploads.
        """
        self._ensure_owner_thread()
        self._ensure_open()
        method = _normalise_method(method, default=METHOD_VALLADO)
        resolved_gravity_model = _normalise_earth_model(
            gravity_model,
            default=self.gravity_model,
        )
        ordered_tles = _ordered_unique(_as_ordered_tuple(tles), key_func=_tle_key)
        key = (
            method,
            self.compute_dtype.str,
            self.sat_frame,
            resolved_gravity_model,
            tuple(_tle_key(tle) for tle in ordered_tles),
        )
        cached = self._satellite_context_cache.get(key)
        if cached is not None:
            self._touch()
            return cached

        with self._temporary_activation():
            satellites = _extract_vallado_satellites(
                ordered_tles,
                gravity_model=resolved_gravity_model,
            )
            params, epoch_mjd, near_indices, deep_indices = _extract_vallado_params(
                satellites,
                compute_dtype=self.compute_dtype,
            )
            d_params = _copy_param_dict_to_device(params)
            context = GpuSatelliteContext(
                session=self,
                method=method,
                compute_dtype=self.compute_dtype,
                sat_frame=self.sat_frame,
                device_id=self.device_id,
                gravity_model=resolved_gravity_model,
                tles=ordered_tles,
                epoch_mjd=epoch_mjd,
                params=params,
                d_params=d_params,
                near_indices=near_indices,
                deep_indices=deep_indices,
                d_near_indices=cuda.to_device(np.ascontiguousarray(near_indices))
                if near_indices.size > 0
                else None,
                d_deep_indices=cuda.to_device(np.ascontiguousarray(deep_indices))
                if deep_indices.size > 0
                else None,
            )
        self._satellite_context_cache[key] = context
        self._touch()
        return context

    def prepare_observer_context(
        self,
        observers: Any | None = None,
        *,
        ellipsoid_model: str | None = None,
    ) -> GpuObserverContext:
        """
        Prepare and cache observer geometry for repeated chunked runs.

        Parameters
        ----------
        observers : Any or None, optional
            Scalar, 1-D, or broadcast-style array-like of `cysgp4.PyObserver`
            objects. If omitted, a default observer at ``(0 deg, 0 deg, 0 km)``
            is created through `cysgp4.PyObserver()`.
        ellipsoid_model : {"wgs72", "wgs84"} or None, optional
            Optional ellipsoid-model override for this prepared observer
            context. If omitted, the session default is used.

        Returns
        -------
        GpuObserverContext
            Cached observer context containing host and device-side geodetic
            and ECEF quantities.
        """
        self._ensure_owner_thread()
        self._ensure_open()
        from cysgp4 import PyObserver

        resolved_ellipsoid_model = _normalise_earth_model(
            ellipsoid_model,
            default=self.ellipsoid_model,
        )
        ordered_observers = _ordered_unique(
            _as_ordered_tuple(observers, default_factory=PyObserver),
            key_func=_observer_key,
        )
        key = (
            self.compute_dtype.str,
            resolved_ellipsoid_model,
            tuple(_observer_key(observer) for observer in ordered_observers),
        )
        cached = self._observer_context_cache.get(key)
        if cached is not None:
            self._touch()
            return cached

        lon_deg, lat_deg, alt_km = _observer_geodetic_arrays(ordered_observers)
        (
            ecef_x_km,
            ecef_y_km,
            ecef_z_km,
            sin_lat,
            cos_lat,
            sin_lon,
            cos_lon,
        ) = _observer_ecef_from_geodetic(
            lon_deg,
            lat_deg,
            alt_km,
            ellipsoid_model=resolved_ellipsoid_model,
        )
        with self._temporary_activation():
            dtype = self.compute_dtype.type
            context = GpuObserverContext(
                session=self,
                compute_dtype=self.compute_dtype,
                device_id=self.device_id,
                ellipsoid_model=resolved_ellipsoid_model,
                observers=ordered_observers,
                observer_lon_deg=lon_deg,
                observer_lat_deg=lat_deg,
                observer_alt_km=alt_km,
                observer_ecef_x_km=ecef_x_km,
                observer_ecef_y_km=ecef_y_km,
                observer_ecef_z_km=ecef_z_km,
                observer_sin_lat=sin_lat,
                observer_cos_lat=cos_lat,
                observer_sin_lon=sin_lon,
                observer_cos_lon=cos_lon,
                d_observer_ecef_x_km=cuda.to_device(ecef_x_km.astype(dtype, copy=False)),
                d_observer_ecef_y_km=cuda.to_device(ecef_y_km.astype(dtype, copy=False)),
                d_observer_ecef_z_km=cuda.to_device(ecef_z_km.astype(dtype, copy=False)),
                d_observer_sin_lat=cuda.to_device(sin_lat.astype(dtype, copy=False)),
                d_observer_cos_lat=cuda.to_device(cos_lat.astype(dtype, copy=False)),
                d_observer_sin_lon=cuda.to_device(sin_lon.astype(dtype, copy=False)),
                d_observer_cos_lon=cuda.to_device(cos_lon.astype(dtype, copy=False)),
            )
        self._observer_context_cache[key] = context
        self._touch()
        return context

    def prepare_angle_sampler_context(
        self,
        sampler: Any,
    ) -> GpuAngleSamplerContext:
        """
        Prepare a conditional angle-sampler context for EPFDflow GPU workflows.

        Parameters
        ----------
        sampler : Any
            `scepter.angle_sampler.JointAngleSampler` instance containing the
            NbeamEstimationFlow conditional sampler artifact. The sampler must expose the
            conditional group and belt pools used by
            :meth:`sample_conditioned_candidate_pools`.

        Returns
        -------
        GpuAngleSamplerContext
            Cached device-resident sampler context bound to this session and
            CUDA device.

        Raises
        ------
        RuntimeError
            If the supplied sampler does not contain a conditional model or if
            the current CuPy-backed EPFDflow GPU path is unavailable.

        Notes
        -----
        The current GPU-conditioned sampler implementation supports the same
        `skycell_mode="s1586"` observer-frame conditioning used by the
        notebook workflow. The uploaded context includes the unconditional CDF,
        group-conditioned pools, belt-conditioned pools, and the threshold
        counts required to reproduce the CPU fallback chain exactly:

        1. group `(belt, skycell)` pool when populated and above threshold
        2. belt pool when populated and above threshold
        3. global unconditional CDF otherwise
        """
        self._ensure_owner_thread()
        self._ensure_open()
        _require_cupy()

        from scepter.angle_sampler import JointAngleSampler

        if not isinstance(sampler, JointAngleSampler):
            raise TypeError("sampler must be a JointAngleSampler instance.")
        if not sampler.has_conditional_model():
            raise RuntimeError(
                "The supplied sampler does not contain a conditional model. "
                "Rebuild or load the NbeamEstimationFlow sampler artifact with conditional pools."
            )
        if str(sampler.skycell_mode).lower() != "s1586":
            raise NotImplementedError(
                "The EPFDflow GPU conditioned sampler currently supports only skycell_mode='s1586'."
            )

        key = (
            id(sampler),
            self.device_id,
            self.compute_dtype.str,
            int(sampler.n_skycells),
            int(sampler.n_belts),
            int(sampler.n_alpha),
            int(sampler.cond_min_group_samples),
            int(sampler.cond_min_belt_samples),
        )
        cached = self._angle_sampler_context_cache.get(key)
        if cached is not None:
            self._touch()
            return cached

        with self._temporary_activation():
            context = GpuAngleSamplerContext(
                session=self,
                compute_dtype=self.compute_dtype,
                device_id=self.device_id,
                skycell_mode=str(sampler.skycell_mode),
                n_skycells=int(sampler.n_skycells),
                n_belts=int(sampler.n_belts),
                n_alpha=int(sampler.n_alpha),
                cond_min_group_samples=int(sampler.cond_min_group_samples),
                cond_min_belt_samples=int(sampler.cond_min_belt_samples),
                beta_edges=np.ascontiguousarray(sampler.beta_edges, dtype=np.float32),
                alpha_edges=np.ascontiguousarray(sampler.alpha_edges, dtype=np.float32),
                cdf=np.ascontiguousarray(sampler.cdf, dtype=np.float64),
                group_ptr=np.ascontiguousarray(sampler.group_ptr, dtype=np.int64),
                group_beta_pool=np.ascontiguousarray(sampler.group_beta_pool, dtype=np.float32),
                group_alpha_pool=np.ascontiguousarray(sampler.group_alpha_pool, dtype=np.float32),
                group_raw_counts=np.ascontiguousarray(sampler.group_raw_counts, dtype=np.int32),
                belt_ptr=np.ascontiguousarray(sampler.belt_ptr, dtype=np.int64),
                belt_beta_pool=np.ascontiguousarray(sampler.belt_beta_pool, dtype=np.float32),
                belt_alpha_pool=np.ascontiguousarray(sampler.belt_alpha_pool, dtype=np.float32),
                belt_raw_counts=np.ascontiguousarray(sampler.belt_raw_counts, dtype=np.int32),
                d_beta_edges=cp.asarray(np.ascontiguousarray(sampler.beta_edges, dtype=np.float32)),
                d_alpha_edges=cp.asarray(np.ascontiguousarray(sampler.alpha_edges, dtype=np.float32)),
                d_cdf=cp.asarray(np.ascontiguousarray(sampler.cdf, dtype=np.float64)),
                d_group_ptr=cp.asarray(np.ascontiguousarray(sampler.group_ptr, dtype=np.int64)),
                d_group_beta_pool=cp.asarray(np.ascontiguousarray(sampler.group_beta_pool, dtype=np.float32)),
                d_group_alpha_pool=cp.asarray(np.ascontiguousarray(sampler.group_alpha_pool, dtype=np.float32)),
                d_group_raw_counts=cp.asarray(np.ascontiguousarray(sampler.group_raw_counts, dtype=np.int32)),
                d_belt_ptr=cp.asarray(np.ascontiguousarray(sampler.belt_ptr, dtype=np.int64)),
                d_belt_beta_pool=cp.asarray(np.ascontiguousarray(sampler.belt_beta_pool, dtype=np.float32)),
                d_belt_alpha_pool=cp.asarray(np.ascontiguousarray(sampler.belt_alpha_pool, dtype=np.float32)),
                d_belt_raw_counts=cp.asarray(np.ascontiguousarray(sampler.belt_raw_counts, dtype=np.int32)),
                d_s1586_az_steps_deg=cp.asarray(_S1586_AZ_STEPS_DEG),
                d_s1586_ring_counts=cp.asarray(_S1586_RING_COUNTS),
                d_s1586_ring_offsets=cp.asarray(_S1586_RING_OFFSETS),
            )
        self._angle_sampler_context_cache[key] = context
        self._touch()
        return context

    def prepare_s1586_pointing_context(
        self,
        *,
        elev_range_deg: tuple[float | u.Quantity, float | u.Quantity] = (15 * u.deg, 90 * u.deg),
    ) -> GpuS1586PointingContext:
        """
        Prepare the clipped ITU-R S.1586 sky-cell grid for GPU sampling.

        Parameters
        ----------
        elev_range_deg : tuple[float or Quantity, float or Quantity], optional
            Inclusive elevation interval used to clip the upper-hemisphere
            S.1586 grid before random point generation. Bare floats are
            interpreted as degrees.

        Returns
        -------
        GpuS1586PointingContext
            Cached device-resident sky-cell context storing per-cell azimuth
            and elevation bounds together with the sine-elevation bounds used
            for uniform-in-solid-angle sampling.

        Notes
        -----
        The context stores one row per retained or clipped S.1586 cell. Use
        :meth:`sample_s1586_pointings` to draw ``(T, N_cells)`` azimuth and
        elevation arrays for a time batch while keeping the random work on the
        GPU.
        """
        self._ensure_owner_thread()
        self._ensure_open()
        _require_cupy()

        from scepter.skynet import pointgen_S_1586_1

        lo, hi = elev_range_deg
        lo_deg = float(u.Quantity(lo).to_value(u.deg) if hasattr(lo, "to") else lo)
        hi_deg = float(u.Quantity(hi).to_value(u.deg) if hasattr(hi, "to") else hi)
        if lo_deg > hi_deg:
            lo_deg, hi_deg = hi_deg, lo_deg
        lo_deg = max(0.0, lo_deg)
        hi_deg = min(90.0, hi_deg)

        key = (
            self.device_id,
            self.compute_dtype.str,
            round(lo_deg, 6),
            round(hi_deg, 6),
        )
        cached = self._s1586_pointing_context_cache.get(key)
        if cached is not None:
            self._touch()
            return cached

        _, _, grid_info = pointgen_S_1586_1(
            niters=1,
            rnd_seed=0,
            elev_range=(lo_deg * u.deg, hi_deg * u.deg),
        )
        az_low = np.ascontiguousarray(grid_info["cell_lon_low"], dtype=np.float32)
        az_high = np.ascontiguousarray(grid_info["cell_lon_high"], dtype=np.float32)
        el_low = np.ascontiguousarray(grid_info["cell_lat_low"], dtype=np.float32)
        el_high = np.ascontiguousarray(grid_info["cell_lat_high"], dtype=np.float32)
        sin_el_low = np.ascontiguousarray(np.sin(np.deg2rad(el_low)), dtype=np.float32)
        sin_el_high = np.ascontiguousarray(np.sin(np.deg2rad(el_high)), dtype=np.float32)

        with self._temporary_activation():
            context = GpuS1586PointingContext(
                session=self,
                compute_dtype=self.compute_dtype,
                device_id=self.device_id,
                elev_range_deg=(float(lo_deg), float(hi_deg)),
                az_low_deg=az_low,
                az_high_deg=az_high,
                el_low_deg=el_low,
                el_high_deg=el_high,
                sin_el_low=sin_el_low,
                sin_el_high=sin_el_high,
                d_az_low_deg=cp.asarray(az_low),
                d_az_high_deg=cp.asarray(az_high),
                d_el_low_deg=cp.asarray(el_low),
                d_el_high_deg=cp.asarray(el_high),
                d_sin_el_low=cp.asarray(sin_el_low),
                d_sin_el_high=cp.asarray(sin_el_high),
            )
        self._s1586_pointing_context_cache[key] = context
        self._touch()
        return context

    def prepare_s1528_pattern_context(
        self,
        *,
        wavelength_m: float | u.Quantity,
        lt_m: float | u.Quantity,
        lr_m: float | u.Quantity,
        slr_db: float | u.Quantity,
        l: int = 4,
        far_sidelobe_start_deg: float | u.Quantity | None = None,
        far_sidelobe_level_db: float | u.Quantity | None = None,
        gm_db: float | u.Quantity | None = None,
        mu_roots: np.ndarray | None = None,
    ) -> GpuS1528PatternContext:
        """
        Prepare an exact S.1528 Taylor-pattern context for GPU evaluation.

        Parameters
        ----------
        wavelength_m, lt_m, lr_m : float or Quantity
            Wavelength and aperture semi-axes in metres.
        slr_db : float or Quantity
            Side-lobe ratio in dB. Astropy logarithmic quantities such as
            ``u.dB`` or ``cnv.dB`` are accepted.
        l : int, optional
            Number of Taylor side-lobes retained in the product.
        far_sidelobe_start_deg : float or Quantity or None, optional
            Optional angular threshold in degrees at or beyond which the gain
            is clamped to `far_sidelobe_level_db`.
        far_sidelobe_level_db : float or Quantity or None, optional
            Optional constant far-sidelobe level in dB. ``cnv.dBi``-style
            logarithmic quantities are accepted.
        gm_db : float or Quantity or None, optional
            Optional absolute boresight peak gain in dB. When omitted, the
            pattern is relative and boresight gain is 0 dB.
        mu_roots : np.ndarray or None, optional
            Optional precomputed `J1(pi * mu) = 0` roots. When omitted the
            first `l` roots are computed once on the host and uploaded.

        Returns
        -------
        GpuS1528PatternContext
            Cached pattern context containing the Taylor synthesis constants
            and uploaded Bessel roots required for exact CuPy evaluation.
        """
        self._ensure_owner_thread()
        self._ensure_open()
        _require_cupy()

        wavelength_val = float(u.Quantity(wavelength_m).to_value(u.m) if hasattr(wavelength_m, "to") else wavelength_m)
        lt_val = float(u.Quantity(lt_m).to_value(u.m) if hasattr(lt_m, "to") else lt_m)
        lr_val = float(u.Quantity(lr_m).to_value(u.m) if hasattr(lr_m, "to") else lr_m)
        for _name, _val in (("wavelength_m", wavelength_val), ("lt_m", lt_val), ("lr_m", lr_val)):
            if not np.isfinite(_val) or _val <= 0.0:
                raise ValueError(f"S.1528 Rec 1.4 context: {_name} must be finite and > 0; got {_val!r}.")
        slr_val = _to_scalar_decibel_value(slr_db, name="slr_db")
        far_start_val = None
        if far_sidelobe_start_deg is not None:
            far_start_val = float(
                u.Quantity(far_sidelobe_start_deg).to_value(u.deg)
                if hasattr(far_sidelobe_start_deg, "to")
                else far_sidelobe_start_deg
            )
        far_level_val = None
        if far_sidelobe_level_db is not None:
            far_level_val = _to_scalar_decibel_value(
                far_sidelobe_level_db,
                name="far_sidelobe_level_db",
            )
        gm_val = None
        if gm_db is not None:
            gm_val = _to_scalar_decibel_value(gm_db, name="gm_db")

        if (far_start_val is None) ^ (far_level_val is None):
            raise ValueError(
                "far_sidelobe_start_deg and far_sidelobe_level_db must be provided together."
            )
        if int(l) < 1:
            raise ValueError("l must be positive.")

        mu_roots_arr = (
            np.ascontiguousarray(scipy_special.jn_zeros(1, int(l)) / np.pi, dtype=np.float32)
            if mu_roots is None
            else np.ascontiguousarray(mu_roots, dtype=np.float32)
        )
        if mu_roots_arr.size < int(l):
            raise ValueError(f"mu_roots must contain at least {int(l)} entries.")

        key = (
            self.device_id,
            self.compute_dtype.str,
            round(wavelength_val, 9),
            round(lt_val, 9),
            round(lr_val, 9),
            round(slr_val, 9),
            int(l),
            None if far_start_val is None else round(far_start_val, 9),
            None if far_level_val is None else round(far_level_val, 9),
            None if gm_val is None else round(gm_val, 9),
            tuple(np.round(mu_roots_arr[: int(l)], 9).tolist()),
        )
        cached = self._s1528_pattern_context_cache.get(key)
        if cached is not None:
            self._touch()
            return cached

        A = float(np.arccosh(10.0 ** (slr_val / 20.0)) / np.pi)
        sigma = float(mu_roots_arr[int(l) - 1] / np.sqrt(A * A + (int(l) - 0.5) ** 2))
        pi2sig2 = float((np.pi ** 2) * (sigma ** 2))

        # Asymmetric Rec 1.4 (lt_m != lr_m) requires a 2-D LUT in (theta, phi).
        # The 1-D LUT path only captures the phi=0 slice and silently drops
        # all dependence on lt_m when applied to an asymmetric aperture.
        is_asymmetric = abs(lt_val - lr_val) > 1e-9

        with self._temporary_activation():
            context = GpuS1528PatternContext(
                session=self,
                compute_dtype=self.compute_dtype,
                device_id=self.device_id,
                wavelength_m=wavelength_val,
                lt_m=lt_val,
                lr_m=lr_val,
                slr_db=slr_val,
                l=int(l),
                far_sidelobe_start_deg=far_start_val,
                far_sidelobe_level_db=far_level_val,
                gm_db=gm_val,
                A=A,
                sigma=sigma,
                pi2sig2=pi2sig2,
                mu_roots=mu_roots_arr[: int(l)].copy(),
                d_mu_roots=cp.asarray(mu_roots_arr[: int(l)].copy()),
                is_2d=is_asymmetric,
            )
        self._s1528_pattern_context_cache[key] = context
        self._touch()
        return context

    def prepare_s1528_rec12_pattern_context(
        self,
        *,
        wavelength_m: float | u.Quantity,
        gm_dbi: float | u.Quantity,
        ln_db: float | u.Quantity = -15.0,
        z: float = 1.0,
        diameter_m: float | u.Quantity | None = None,
    ) -> GpuS1528Rec12PatternContext:
        """Prepare an S.1528 Rec 1.2 piecewise-envelope pattern context.

        Both a direct GPU piecewise kernel and a pre-built LUT are available
        for evaluation.
        """
        self._ensure_owner_thread()
        self._ensure_open()
        _require_cupy()

        wavelength_val = float(u.Quantity(wavelength_m).to_value(u.m) if hasattr(wavelength_m, "to") else wavelength_m)
        if not np.isfinite(wavelength_val) or wavelength_val <= 0.0:
            raise ValueError(f"S.1528 Rec 1.2 context: wavelength_m must be finite and > 0; got {wavelength_val!r}.")
        gm_val = _to_scalar_decibel_value(gm_dbi, name="gm_dbi")
        ln_val = _to_scalar_decibel_value(ln_db, name="ln_db")
        z_val = max(float(z), 1e-9)
        d_val = None
        if diameter_m is not None:
            d_val = float(u.Quantity(diameter_m).to_value(u.m) if hasattr(diameter_m, "to") else diameter_m)
            if not np.isfinite(d_val) or d_val <= 0.0:
                raise ValueError(f"S.1528 Rec 1.2 context: diameter_m must be finite and > 0; got {d_val!r}.")

        key = (
            "rec12",
            self.device_id,
            round(wavelength_val, 9),
            round(gm_val, 4),
            round(ln_val, 4),
            round(z_val, 6),
            None if d_val is None else round(d_val, 6),
        )
        cached = self._s1528_pattern_context_cache.get(key)
        if cached is not None:
            self._touch()
            return cached

        # Compute psi_b (half 3-dB beamwidth in degrees)
        if d_val is not None and d_val > 0:
            d_over_lam = d_val / wavelength_val
        else:
            # Derive D from Gm: Gm = 10*log10((pi*D/lambda)^2) → D/lambda = 10^(Gm/20)/pi
            d_over_lam = 10.0 ** (gm_val / 20.0) / np.pi
        psi_b = float(np.sqrt(1200.0) / d_over_lam)

        # Rec 1.2 Table 1 constants
        ln_int = int(round(ln_val))
        _LN_TABLE = {
            -15: (2.58 * np.sqrt(max(0.0, 1 - 1.4 * np.log10(z_val))), 6.32, 1.5),
            -20: (2.58 * np.sqrt(max(0.0, 1 - 1.0 * np.log10(z_val))), 6.32, 1.5),
            -25: (2.58 * np.sqrt(max(0.0, 1 - 0.6 * np.log10(z_val))), 6.32, 1.5),
            -30: (2.58 * np.sqrt(max(0.0, 1 - 0.4 * np.log10(z_val))), 6.32, 1.5),
        }
        if ln_int not in _LN_TABLE:
            ln_int = min(_LN_TABLE.keys(), key=lambda k: abs(k - ln_int))
        a_val, b_val, alpha_val = _LN_TABLE[ln_int]
        lf_val = 0.0
        lb_val = float(max(15.0 + ln_val + 0.25 * gm_val + 5.0 * np.log10(z_val), 0.0))
        x_coeff = gm_val + ln_val + 25.0 * np.log10(b_val * psi_b)
        y_deg = b_val * psi_b * 10.0 ** (0.04 * (gm_val + ln_val - lf_val))

        context = GpuS1528Rec12PatternContext(
            session=self,
            wavelength_m=wavelength_val,
            gm_db=gm_val,
            ln_db=ln_val,
            z=z_val,
            psi_b=psi_b,
            a=a_val,
            b=b_val,
            alpha=alpha_val,
            lf_db=lf_val,
            lb_db=lb_val,
            x_coeff=x_coeff,
            y_deg=y_deg,
        )
        self._s1528_pattern_context_cache[key] = context
        self._touch()
        return context

    def prepare_isotropic_pattern_context(
        self,
        *,
        wavelength_m: float | u.Quantity = 0.1,
    ) -> GpuIsotropicPatternContext:
        """Prepare an isotropic (UEMR-leakage) transmit pattern context.

        Models an omnidirectional emitter with Gtx = 0 dBi in every
        direction, used for unwanted emissions originating in internal
        satellite circuitry rather than the directive antenna. Only
        ``wavelength_m`` matters (it feeds the FSPL term); all angle
        arguments are ignored.
        """
        self._ensure_owner_thread()
        self._ensure_open()
        _require_cupy()

        wavelength_val = float(
            u.Quantity(wavelength_m).to_value(u.m)
            if hasattr(wavelength_m, "to")
            else wavelength_m
        )
        if not np.isfinite(wavelength_val) or wavelength_val <= 0.0:
            raise ValueError(
                f"Isotropic context: wavelength_m must be finite and > 0; got {wavelength_val!r}."
            )
        key = ("isotropic", self.device_id, round(wavelength_val, 9))
        cached = self._s1528_pattern_context_cache.get(key)
        if cached is not None:
            self._touch()
            return cached
        context = GpuIsotropicPatternContext(
            session=self,
            wavelength_m=wavelength_val,
        )
        self._s1528_pattern_context_cache[key] = context
        self._touch()
        return context

    def prepare_custom_pattern_1d_context(
        self,
        *,
        pattern: "CustomAntennaPattern",
        wavelength_m: float | u.Quantity = 0.1,
        theta_step_deg: float | None = None,
        system_id: Any = None,
    ) -> GpuCustomPattern1DContext:
        """Upload a 1-D axisymmetric custom pattern to GPU as a regular LUT.

        Resamples the user's pattern (which may have an irregular grid
        and/or step discontinuities expressed as duplicate grid angles)
        onto a regular degree-spaced grid via the schema-correct
        right-continuous interpolator, so the hot-path GPU evaluator
        can share the existing S.1528 1-D ElementwiseKernel without
        any custom step-handling logic.

        The returned ``gain_db`` LUT is in **absolute dBi**. Relative-
        mode files have their peak baked in here at build time, so
        downstream evaluators never need to know how the source was
        normalised.

        Parameters
        ----------
        pattern :
            A validated :class:`~scepter.custom_antenna.CustomAntennaPattern`
            with ``kind == KIND_1D``.
        wavelength_m :
            Wavelength for the context's FSPL / PFD conversions,
            matching the convention of the S.1528 / M.2101 contexts.
        theta_step_deg :
            Optional override for the regular-grid resample step in
            degrees. Defaults to ``_CUSTOM_1D_LUT_STEP_DEG`` (0.001°),
            which captures any realistic user-authored source. Pass a
            finer step only for extreme cases (sub-0.001° main-beam
            features). Matches the ``axis0_step_deg`` override exposed
            by :meth:`prepare_custom_pattern_2d_context` for symmetry.
        system_id :
            Optional identifier selecting which per-system bucket of
            the session's LRU cache to use. Multi-system scenarios
            pass the system index here so each system has its own
            bounded cache with no cross-system eviction. Callers that
            don't care (tests, single-system runs, GUI previews) leave
            the default and share a single anonymous bucket.
        """
        from scepter.custom_antenna import (  # local import keeps top-level deps minimal
            CustomAntennaPattern as _CAP,
            KIND_1D as _KIND_1D,
            NORMALISATION_ABSOLUTE as _NORM_ABS,
            PEAK_SOURCE_LUT as _PS_LUT,
            evaluate_pattern_1d as _eval_1d,
        )

        self._ensure_owner_thread()
        self._ensure_open()
        _require_cupy()

        if not isinstance(pattern, _CAP):
            raise TypeError(
                "prepare_custom_pattern_1d_context requires a "
                "CustomAntennaPattern instance; "
                f"got {type(pattern).__name__}."
            )
        if pattern.kind != _KIND_1D:
            raise ValueError(
                "prepare_custom_pattern_1d_context requires kind="
                f"{_KIND_1D!r}; got {pattern.kind!r}. Use the 2-D "
                "builder (Stage 12) for asymmetric patterns."
            )

        wavelength_val = float(
            u.Quantity(wavelength_m).to_value(u.m)
            if hasattr(wavelength_m, "to")
            else wavelength_m
        )
        if not np.isfinite(wavelength_val) or wavelength_val <= 0.0:
            raise ValueError(
                "Custom 1-D context: wavelength_m must be finite and > 0; "
                f"got {wavelength_val!r}."
            )

        step = (
            float(theta_step_deg) if theta_step_deg is not None
            else float(_CUSTOM_1D_LUT_STEP_DEG)
        )
        if not np.isfinite(step) or step <= 0.0:
            raise ValueError(
                f"theta_step_deg must be finite and > 0; got {step!r}."
            )
        max_deg = float(_CUSTOM_1D_LUT_MAX_DEG)

        # Cache key uses a ``CustomAntennaPattern.content_fingerprint``
        # rather than ``id(pattern)`` so the user can mutate the
        # loaded LUT in place (e.g. via a GUI pattern editor) and
        # re-prepare the context without a save-reload round-trip —
        # any radiation-affecting change flips the hash, triggering
        # a fresh LUT build. ``meta`` / ``format_version`` are
        # excluded from the hash (they don't affect gain). The
        # ``system_id`` is *not* part of the key — it selects which
        # per-system LRU bucket to look in, so two systems with the
        # same pattern content get their own contexts rather than
        # sharing one.
        key = (
            "custom_1d",
            self.device_id,
            self.compute_dtype.str,
            pattern.content_fingerprint(),
            round(wavelength_val, 9),
            round(step, 9),
        )
        bucket = self._custom_pattern_context_cache.setdefault(
            system_id, OrderedDict()
        )
        cached = bucket.get(key)
        if cached is not None:
            bucket.move_to_end(key)
            self._touch()
            return cached

        n = int(round(max_deg / step)) + 2
        grid_host = np.arange(n, dtype=np.float64) * np.float64(step)
        # ``evaluate_pattern_1d`` returns absolute dBi, shifting relative
        # patterns by peak_gain_dbi. The returned LUT therefore stores
        # absolute dBi — same convention as the S.1528 1-D LUT.
        gain_host = _eval_1d(pattern, grid_host).astype(np.float32)

        # Resolve the effective peak per the schema's peak-gain rule:
        # ``absolute+lut`` → peak is max of the tabulated LUT;
        # every other (normalisation, peak_gain_source) combination
        # uses the declared ``peak_gain_dbi`` verbatim. This matters
        # for ``peak_source="lut"`` patterns where the LUT maximum
        # and the declared peak can legitimately differ (ITU
        # regulatory masks, undersampled narrow-beam datasheets).
        if (
            pattern.normalisation == _NORM_ABS
            and pattern.peak_gain_source == _PS_LUT
        ):
            resolved_peak_dbi = float(np.max(pattern.gain_db))
        else:
            resolved_peak_dbi = float(pattern.peak_gain_dbi)

        with self._temporary_activation():
            d_gain_lut = cp.asarray(gain_host, dtype=cp.float32)
            # Downcast to fp16 when the session's pattern stage runs at
            # fp16 — the shared ``s1528_lut_1d_*`` evaluators dispatch
            # on LUT dtype, so Custom-1D transparently rides along.
            if np.dtype(self.pattern_dtype) == np.dtype(np.float16):
                d_gain_lut = d_gain_lut.astype(cp.float16, copy=False)
            context = GpuCustomPattern1DContext(
                session=self,
                compute_dtype=self.compute_dtype,
                device_id=self.device_id,
                peak_gain_dbi=resolved_peak_dbi,
                wavelength_m=wavelength_val,
                d_gain_lut=d_gain_lut,
                gain_lut_step_deg=step,
                gain_lut_max_deg=max_deg,
                gain_lut_n=n,
                source_pattern=pattern,
            )
        bucket[key] = context
        self._trim_custom_pattern_cache(system_id)
        self._touch()
        return context

    def prepare_custom_pattern_2d_context(
        self,
        *,
        pattern: "CustomAntennaPattern",
        wavelength_m: float | u.Quantity = 0.1,
        axis0_step_deg: float | None = None,
        axis1_step_deg: float | None = None,
        system_id: Any = None,
    ) -> GpuCustomPattern2DContext:
        """Upload a 2-D custom pattern to GPU as a regular bilinear LUT.

        The user-supplied pattern (possibly on an irregular grid, and
        possibly expressing step discontinuities via duplicate grid
        angles) is resampled onto a regular grid via the schema-correct
        CPU evaluator :func:`scepter.custom_antenna.evaluate_pattern_2d`
        (bilinear with right-continuous step handling) before upload.
        The hot-path GPU kernel is therefore agnostic to both the
        irregularity and the step discontinuities — it sees a plain
        regular-grid LUT.

        Default resample resolutions mirror the internal M.2101 / S.1528
        2-D LUTs (``az/el = 0.5°``, ``θ = 0.05°``, ``φ = 0.5°``) — fine
        enough for any realistic user-authored source, comfortably
        under a few tens of MB on device. Callers who want finer or
        coarser grids pass ``axis0_step_deg`` / ``axis1_step_deg``.

        Parameters
        ----------
        pattern :
            Validated :class:`~scepter.custom_antenna.CustomAntennaPattern`
            with ``kind == KIND_2D``.
        wavelength_m :
            FSPL / PFD-conversion wavelength (matches the other
            pattern contexts).
        axis0_step_deg, axis1_step_deg :
            Optional overrides for the regular-grid resample step on
            each axis. Units are degrees. If omitted, defaults match
            the pattern's ``grid_mode``.
        system_id :
            Optional per-system LRU-bucket selector — see
            :meth:`prepare_custom_pattern_1d_context` for the full
            rationale.
        """
        from scepter.custom_antenna import (  # local import — keeps top-level dep graph minimal
            CustomAntennaPattern as _CAP,
            GRID_MODE_AZEL as _GM_AZEL,
            GRID_MODE_THETAPHI as _GM_THETAPHI,
            KIND_2D as _KIND_2D,
            NORMALISATION_ABSOLUTE as _NORM_ABS,
            PEAK_SOURCE_LUT as _PS_LUT,
            evaluate_pattern_2d as _eval_2d,
        )

        self._ensure_owner_thread()
        self._ensure_open()
        _require_cupy()

        if not isinstance(pattern, _CAP):
            raise TypeError(
                "prepare_custom_pattern_2d_context requires a "
                "CustomAntennaPattern instance; "
                f"got {type(pattern).__name__}."
            )
        if pattern.kind != _KIND_2D:
            raise ValueError(
                "prepare_custom_pattern_2d_context requires kind="
                f"{_KIND_2D!r}; got {pattern.kind!r}. Use the 1-D "
                "builder for axisymmetric patterns."
            )

        wavelength_val = float(
            u.Quantity(wavelength_m).to_value(u.m)
            if hasattr(wavelength_m, "to") else wavelength_m
        )
        if not np.isfinite(wavelength_val) or wavelength_val <= 0.0:
            raise ValueError(
                "Custom 2-D context: wavelength_m must be finite and > 0; "
                f"got {wavelength_val!r}."
            )

        if pattern.grid_mode == _GM_AZEL:
            default_axis0_step = _CUSTOM_2D_AZEL_AZ_STEP_DEG
            default_axis1_step = _CUSTOM_2D_AZEL_EL_STEP_DEG
            axis0_min, axis0_max = -180.0, 180.0
            axis1_min, axis1_max = -90.0, 90.0
            axis0_wraps = bool(pattern.az_wraps if pattern.az_wraps is not None else True)
            axis1_wraps = False   # elevation never wraps
            pat_axis0 = np.asarray(pattern.az_grid_deg, dtype=np.float64)
            pat_axis1 = np.asarray(pattern.el_grid_deg, dtype=np.float64)
        elif pattern.grid_mode == _GM_THETAPHI:
            default_axis0_step = _CUSTOM_2D_THETAPHI_THETA_STEP_DEG
            default_axis1_step = _CUSTOM_2D_THETAPHI_PHI_STEP_DEG
            axis0_min, axis0_max = 0.0, 180.0
            axis1_min, axis1_max = -180.0, 180.0
            axis0_wraps = False   # theta never wraps
            axis1_wraps = bool(pattern.phi_wraps if pattern.phi_wraps is not None else True)
            pat_axis0 = np.asarray(pattern.theta_grid_deg, dtype=np.float64)
            pat_axis1 = np.asarray(pattern.phi_grid_deg, dtype=np.float64)
        else:
            raise ValueError(
                f"Unsupported custom pattern grid_mode={pattern.grid_mode!r}."
            )

        # Choose the GPU LUT step to match the pattern's native grid
        # when the pattern is already on a regular grid.  The old
        # code always promoted to the default 0.1° resolution, which
        # inflated a typical 1°-medium 361×181 editor grid to a
        # 3601×1801 LUT (100× more VRAM + bandwidth for zero extra
        # fidelity — bilinear interpolation of a 1° grid only
        # produces a 1° pattern regardless of how finely the LUT is
        # sampled).  Honour-user-grid policy:
        #
        #   - If the pattern's step is within tolerance of uniform,
        #     use that step exactly. This is the "WYSIWYG" path:
        #     editor's surface grid == exported JSON grid == GPU
        #     LUT grid, so what the user sees is what the GPU
        #     simulates (no silent resample).
        #   - Otherwise (non-uniform grid, rare — mostly hand-authored
        #     JSONs), fall back to the old default step so the
        #     resample at least lands on a regular grid.
        #   - Explicit caller-supplied step always wins.
        def _regular_step(axis: np.ndarray) -> float | None:
            if axis.size < 2:
                return None
            diffs = np.diff(axis.astype(np.float64))
            if diffs.size == 0:
                return None
            nominal = float(np.median(diffs))
            if nominal <= 0.0:
                return None
            spread = float(np.max(diffs) - np.min(diffs))
            # Accept as "regular" if max deviation is ≤ 0.1% of
            # nominal step — covers floating-point drift from linspace
            # reconstructions, rejects hand-authored non-uniform grids.
            if spread > max(1.0e-6, 0.001 * nominal):
                return None
            return nominal

        if axis0_step_deg is None:
            native0 = _regular_step(pat_axis0)
            if native0 is not None:
                default_axis0_step = native0
        if axis1_step_deg is None:
            native1 = _regular_step(pat_axis1)
            if native1 is not None:
                default_axis1_step = native1

        axis0_step = float(axis0_step_deg) if axis0_step_deg is not None else float(default_axis0_step)
        axis1_step = float(axis1_step_deg) if axis1_step_deg is not None else float(default_axis1_step)
        if axis0_step <= 0.0 or not np.isfinite(axis0_step):
            raise ValueError(f"axis0_step_deg must be > 0; got {axis0_step!r}.")
        if axis1_step <= 0.0 or not np.isfinite(axis1_step):
            raise ValueError(f"axis1_step_deg must be > 0; got {axis1_step!r}.")

        # Content-hash cache key — see the matching comment in
        # ``prepare_custom_pattern_1d_context``. The fingerprint
        # already includes ``grid_mode``, ``az_wraps`` / ``phi_wraps``,
        # and every grid / gain array, so we don't need them in the
        # key separately. Per-system bucketing via ``system_id``
        # isolates each system's LRU from the others.
        key = (
            "custom_2d",
            self.device_id,
            self.compute_dtype.str,
            pattern.content_fingerprint(),
            round(wavelength_val, 9),
            round(axis0_step, 9),
            round(axis1_step, 9),
        )
        bucket = self._custom_pattern_context_cache.setdefault(
            system_id, OrderedDict()
        )
        cached = bucket.get(key)
        if cached is not None:
            bucket.move_to_end(key)
            self._touch()
            return cached

        axis0_n = int(round((axis0_max - axis0_min) / axis0_step)) + 1
        axis1_n = int(round((axis1_max - axis1_min) / axis1_step)) + 1
        # Safety: if the pattern-derived step would exceed the VRAM
        # budget, coarsen both axes proportionally until it fits.
        while axis0_n * axis1_n > _CUSTOM_2D_MAX_LUT_ELEMENTS:
            axis0_step *= 2.0
            axis1_step *= 2.0
            axis0_n = int(round((axis0_max - axis0_min) / axis0_step)) + 1
            axis1_n = int(round((axis1_max - axis1_min) / axis1_step)) + 1
        axis0_grid = np.arange(axis0_n, dtype=np.float64) * axis0_step + axis0_min
        axis1_grid = np.arange(axis1_n, dtype=np.float64) * axis1_step + axis1_min

        axis0_mesh, axis1_mesh = np.meshgrid(axis0_grid, axis1_grid, indexing="ij")
        gain_host = _eval_2d(pattern, axis0_mesh, axis1_mesh).astype(np.float32)
        if gain_host.shape != (axis0_n, axis1_n):  # pragma: no cover — defensive
            raise RuntimeError(
                "Custom 2-D resample produced unexpected shape "
                f"{gain_host.shape}, expected ({axis0_n}, {axis1_n})."
            )

        # Schema-correct peak resolution — see the matching comment in
        # ``prepare_custom_pattern_1d_context``. ``absolute+lut``
        # derives the peak from the tabulated maximum; every other
        # (normalisation, peak_gain_source) combination trusts the
        # declared ``peak_gain_dbi`` verbatim.
        if (
            pattern.normalisation == _NORM_ABS
            and pattern.peak_gain_source == _PS_LUT
        ):
            resolved_peak_dbi = float(np.max(pattern.gain_db))
        else:
            resolved_peak_dbi = float(pattern.peak_gain_dbi)

        with self._temporary_activation():
            d_gain_lut = cp.asarray(gain_host, dtype=cp.float32)
            # Downcast to fp16 when the session's pattern stage runs at
            # fp16.  The ``custom_2d_lut_*`` evaluators dispatch on LUT
            # dtype, so the hot path transparently picks the fp16
            # kernel variants.
            if np.dtype(self.pattern_dtype) == np.dtype(np.float16):
                d_gain_lut = d_gain_lut.astype(cp.float16, copy=False)
            context = GpuCustomPattern2DContext(
                session=self,
                compute_dtype=self.compute_dtype,
                device_id=self.device_id,
                peak_gain_dbi=resolved_peak_dbi,
                wavelength_m=wavelength_val,
                grid_mode=pattern.grid_mode,
                axis0_min_deg=float(axis0_min),
                axis0_step_deg=float(axis0_step),
                axis0_n=int(axis0_n),
                axis0_wraps=bool(axis0_wraps),
                axis1_min_deg=float(axis1_min),
                axis1_step_deg=float(axis1_step),
                axis1_n=int(axis1_n),
                axis1_wraps=bool(axis1_wraps),
                d_gain_lut=d_gain_lut,
                source_pattern=pattern,
            )
        bucket[key] = context
        self._trim_custom_pattern_cache(system_id)
        self._touch()
        return context

    def prepare_m2101_pattern_context(
        self,
        *,
        g_emax_db: float = 2.0,
        a_m_db: float = 30.0,
        sla_nu_db: float = 30.0,
        phi_3db_deg: float = 120.0,
        theta_3db_deg: float = 120.0,
        d_h: float = 0.5,
        d_v: float = 0.5,
        n_h: int = 28,
        n_v: int = 28,
        k: float = 12.0,
        wavelength_m: float = 0.1,
    ) -> GpuM2101PatternContext:
        """Prepare an ITU-R M.2101 composite phased-array pattern context."""
        self._ensure_owner_thread()
        self._ensure_open()
        key = (
            "m2101",
            self.device_id,
            round(float(g_emax_db), 4),
            round(float(a_m_db), 4),
            round(float(sla_nu_db), 4),
            round(float(phi_3db_deg), 4),
            round(float(theta_3db_deg), 4),
            round(float(d_h), 6),
            round(float(d_v), 6),
            int(n_h), int(n_v),
            round(float(k), 4),
        )
        cached = self._s1528_pattern_context_cache.get(key)
        if cached is not None:
            self._touch()
            return cached
        # Guard against downstream NaN / Inf in the composite M.2101
        # kernel. Division-by-zero on phi_3db / theta_3db in the CUDA
        # kernel produces Inf → NaN → corrupted PFD outputs.
        for _pname, _pval in (
            ("phi_3db_deg", float(phi_3db_deg)),
            ("theta_3db_deg", float(theta_3db_deg)),
            ("wavelength_m", float(wavelength_m)),
        ):
            if not np.isfinite(_pval) or _pval <= 0.0:
                raise ValueError(
                    f"M.2101 context: {_pname} must be finite and > 0; got {_pval!r}."
                )
        if int(n_h) < 1 or int(n_v) < 1:
            raise ValueError(
                f"M.2101 context: n_h and n_v must be >= 1; got n_h={n_h!r}, n_v={n_v!r}."
            )
        context = GpuM2101PatternContext(
            session=self,
            g_emax_db=float(g_emax_db),
            a_m_db=float(a_m_db),
            sla_nu_db=float(sla_nu_db),
            phi_3db_deg=float(phi_3db_deg),
            theta_3db_deg=float(theta_3db_deg),
            d_h=float(d_h),
            d_v=float(d_v),
            n_h=int(n_h),
            n_v=int(n_v),
            wavelength_m=float(wavelength_m),
            k=float(k),
        )
        self._s1528_pattern_context_cache[key] = context
        self._touch()
        return context

    def prepare_ras_pattern_context(
        self,
        *,
        diameter_m: float | u.Quantity,
        wavelength_m: float | u.Quantity,
        eta_a_dimless: float | u.Quantity = 100 * u.percent,
    ) -> GpuRasPatternContext:
        """
        Prepare an exact RA.1631/`pycraf.antenna.ras_pattern` GPU context.

        Parameters
        ----------
        diameter_m : float or Quantity
            Antenna diameter in metres.
        wavelength_m : float or Quantity
            Wavelength in metres.
        eta_a_dimless : float or Quantity, optional
            Antenna efficiency as a dimensionless factor or percentage.

        Returns
        -------
        GpuRasPatternContext
            Cached pattern context used by :meth:`accumulate_ras_power`.
        """
        self._ensure_owner_thread()
        self._ensure_open()
        _require_cupy()

        diameter_val = float(u.Quantity(diameter_m).to_value(u.m) if hasattr(diameter_m, "to") else diameter_m)
        wavelength_val = float(
            u.Quantity(wavelength_m).to_value(u.m) if hasattr(wavelength_m, "to") else wavelength_m
        )
        if hasattr(eta_a_dimless, "to"):
            eta_val = float(u.Quantity(eta_a_dimless).to_value(cnv.dimless))
        else:
            eta_val = float(eta_a_dimless)
            if eta_val > 1.0:
                eta_val /= 100.0

        key = (
            self.device_id,
            self.compute_dtype.str,
            round(diameter_val, 9),
            round(wavelength_val, 9),
            round(eta_val, 9),
        )
        cached = self._ras_pattern_context_cache.get(key)
        if cached is not None:
            self._touch()
            return cached

        context = GpuRasPatternContext(
            session=self,
            compute_dtype=self.compute_dtype,
            device_id=self.device_id,
            diameter_m=diameter_val,
            wavelength_m=wavelength_val,
            eta_a_dimless=eta_val,
        )
        self._ras_pattern_context_cache[key] = context
        self._touch()
        return context

    def prepare_atmosphere_lut_context(
        self,
        *,
        frequency_ghz: float | u.Quantity,
        altitude_km_values: Any,
        bin_deg: float = 0.1,
        elev_min_deg: float = 0.1,
        elev_max_deg: float = 90.0,
        max_path_length_km: float | u.Quantity = 10_000.0 * u.km,
    ) -> GpuAtmosphereLutContext:
        """
        Prepare the EPFDflow atmosphere lookup table used by the notebook.

        Parameters
        ----------
        frequency_ghz : float or Quantity
            Frequency in GHz used when building `pycraf.atm` slant-loss
            layers.
        altitude_km_values : Any
            One-dimensional iterable of observer or target altitudes in
            kilometres that will be queried during the GPU loop.
        bin_deg : float, optional
            Elevation bin width in degrees.
        elev_min_deg, elev_max_deg : float, optional
            Minimum and maximum clipped elevation in degrees.
        max_path_length_km : float or Quantity, optional
            Maximum slant-path integration length in kilometres.

        Returns
        -------
        GpuAtmosphereLutContext
            Cached device-resident lookup table storing linear attenuation
            factors indexed by rounded altitude key and nearest elevation bin.

        Notes
        -----
        This context reproduces the existing notebook semantics: elevations at
        or below the horizon map to unity loss, positive elevations are clipped
        to ``[elev_min_deg, elev_max_deg]``, and the nearest elevation bin is
        used for lookup.
        """
        self._ensure_owner_thread()
        self._ensure_open()
        _require_cupy()

        from pycraf import atm

        freq_val_ghz = float(
            u.Quantity(frequency_ghz).to_value(u.GHz) if hasattr(frequency_ghz, "to") else frequency_ghz
        )
        altitudes = np.atleast_1d(np.asarray(altitude_km_values, dtype=np.float32))
        if altitudes.ndim != 1:
            raise ValueError("altitude_km_values must be one-dimensional.")
        if altitudes.size == 0:
            raise ValueError("altitude_km_values must contain at least one entry.")
        altitude_keys = tuple(int(np.rint(val * np.float32(100.0))) for val in altitudes.tolist())
        unique_pairs = sorted({(key, float(val)) for key, val in zip(altitude_keys, altitudes.tolist())})
        altitude_keys = tuple(int(key) for key, _ in unique_pairs)
        altitude_values = np.ascontiguousarray([float(val) for _, val in unique_pairs], dtype=np.float32)

        key = (
            self.device_id,
            self.compute_dtype.str,
            round(freq_val_ghz, 9),
            tuple(altitude_keys),
            round(float(bin_deg), 9),
            round(float(elev_min_deg), 9),
            round(float(elev_max_deg), 9),
            round(
                float(
                    u.Quantity(max_path_length_km).to_value(u.km)
                    if hasattr(max_path_length_km, "to")
                    else max_path_length_km
                ),
                9,
            ),
        )
        cached = self._atmosphere_lut_context_cache.get(key)
        if cached is not None:
            self._touch()
            return cached

        elev_min = float(elev_min_deg)
        elev_max = float(elev_max_deg)
        bin_width = float(bin_deg)
        bins_deg = np.arange(elev_min, elev_max + 0.5 * bin_width, bin_width, dtype=np.float32)
        layers = atm.atm_layers(np.array([freq_val_ghz], dtype=np.float64) * u.GHz, atm.profile_standard)
        max_path = (
            u.Quantity(max_path_length_km).to_value(u.km)
            if hasattr(max_path_length_km, "to")
            else float(max_path_length_km)
        )

        attenuation_lut = np.empty((len(altitude_keys), bins_deg.size), dtype=np.float32)
        for alt_idx, alt_km in enumerate(altitude_values.tolist()):
            for bin_idx, elev_deg in enumerate(bins_deg.tolist()):
                atten_db, _, _ = atm.atten_slant_annex1(
                    elev_deg * u.deg,
                    float(alt_km) * u.km,
                    layers,
                    do_tebb=False,
                    max_path_length=float(max_path) * u.km,
                )
                atten_db_val = _to_scalar_decibel_value(atten_db, name="atten_db")
                attenuation_lut[alt_idx, bin_idx] = np.float32(10.0 ** (-atten_db_val / 10.0))

        with self._temporary_activation():
            context = GpuAtmosphereLutContext(
                session=self,
                compute_dtype=self.compute_dtype,
                device_id=self.device_id,
                bin_deg=bin_width,
                elev_min_deg=elev_min,
                elev_max_deg=elev_max,
                altitude_keys=altitude_keys,
                altitude_km_values=altitude_values,
                attenuation_lut=attenuation_lut,
                d_altitude_km_values=cp.asarray(altitude_values),
                d_attenuation_lut=cp.asarray(attenuation_lut),
            )
        self._atmosphere_lut_context_cache[key] = context
        self._touch()
        return context

    def prepare_peak_pfd_lut_context(
        self,
        *,
        pattern_context: Any,
        sat_orbit_radius_m_per_sat: Any,
        atmosphere_lut_context: GpuAtmosphereLutContext | None,
        target_alt_km: float,
        beta_step_deg: float = 0.01,
        beta_extra_margin_deg: float = 10.0,
        psi_step_deg: float = 0.005,
        m2101_beta_step_deg: float = 0.5,
        m2101_alpha_step_deg: float = 2.0,
        m2101_psi_step_deg: float = 0.5,
        m2101_phi_step_deg: float = 2.0,
    ) -> GpuPeakPfdLutContext:
        """
        Build (or reuse) a surface-PFD cap LUT for one transmit pattern.

        The returned context tabulates ``K(β) = max_ψ [p(|ψ − β|) /
        (4π · d(ψ)² · atm(ψ))]`` for each distinct orbit shell found in
        ``sat_orbit_radius_m_per_sat``.  At runtime the cap reads
        ``PFD_peak_on_earth = EIRP_peak · K(β, shell)`` and scales each
        beam's emitted EIRP so that the user-configured
        ``max_surface_pfd`` limit is respected.

        Parameters
        ----------
        pattern_context
            Transmit pattern shared by every satellite the LUT covers.
            Supported context types:

            * **S.1528** (both axisymmetric ``lt_m == lr_m`` and
              asymmetric ``lt_m != lr_m``), **S.1528 Rec 1.2**,
              **isotropic**, **Custom-1D**, **Custom-2D** → build a
              1-D ``K(β)`` table (``is_2d == False``). The asymmetric
              S.1528 and Custom-2D paths sweep a 2-D ``(ψ, φ)``
              observation grid to capture the φ-dependent main-lobe
              peak, but the resulting K is still α-invariant because
              the aperture rotates with the beam (see Stage-10
              decision doc and
              ``_build_peak_pfd_k_lut_custom2d_cp`` docstring).
            * **M.2101** → 2-D ``K(α, β)`` table (``is_2d == True``)
              because the element pattern is fixed in the satellite
              body frame, so K genuinely depends on the beam
              steering azimuth.
        sat_orbit_radius_m_per_sat : array_like
            Per-satellite orbit radius in metres, shape ``(sat_count,)``.
            Distinct shells are deduplicated at centimetre precision.
        atmosphere_lut_context : GpuAtmosphereLutContext or None
            Atmosphere LUT used to query one-way absorption along each ψ
            slice.  Pass ``None`` to build a free-space cap matching a
            host run executed with atmosphere disabled.
        target_alt_km : float
            Ground candidate altitude passed to the atmosphere LUT.
            Matches the ``target_alt_km`` argument on the power kernel so
            the cap and the emitted PFD cannot disagree.
        beta_step_deg, beta_extra_margin_deg, psi_step_deg : float
            1-D (S.1528) grid parameters.  Defaults are chosen to resolve
            the narrowest S.1528 main lobe supported in production while
            keeping the transient GPU footprint under a few tens of MB
            per shell.
        m2101_beta_step_deg, m2101_alpha_step_deg, m2101_psi_step_deg, m2101_phi_step_deg : float
            2-D (M.2101) steering-grid and observation-sweep resolutions.
            Defaults trade startup time for LUT accuracy.

        Returns
        -------
        GpuPeakPfdLutContext
            Device-resident LUT keyed on ``(pattern_id, shell)``.  The
            returned context also carries ``d_shell_id_per_sat`` so the
            hot kernel can gather the right row without a host round trip.
        """
        self._ensure_owner_thread()
        self._ensure_open()
        _require_cupy()

        if atmosphere_lut_context is not None and atmosphere_lut_context.session is not self:
            raise ValueError("atmosphere_lut_context must belong to this session.")

        orbit_radii_host = np.asarray(
            sat_orbit_radius_m_per_sat, dtype=np.float64
        ).reshape(-1)
        if orbit_radii_host.size == 0:
            raise ValueError("sat_orbit_radius_m_per_sat must not be empty.")
        if not np.all(np.isfinite(orbit_radii_host)):
            raise ValueError("sat_orbit_radius_m_per_sat contains non-finite values.")

        # Round to centimetres to dedupe shells
        rounded_cm = np.rint(orbit_radii_host * 100.0).astype(np.int64)
        unique_cm, inverse = np.unique(rounded_cm, return_inverse=True)
        n_shells = int(unique_cm.size)
        shell_radii_m = unique_cm.astype(np.float64) / 100.0
        shell_id_per_sat_host = inverse.astype(np.int32)

        earth_radius_m = float(R_earth.to_value(u.m))
        pattern_id = id(pattern_context)
        apply_atmosphere = atmosphere_lut_context is not None
        pattern_eval_mode = str(_pattern_eval_mode)
        is_m2101_ctx = isinstance(pattern_context, GpuM2101PatternContext)
        is_asym_s1528_ctx = (
            isinstance(pattern_context, GpuS1528PatternContext)
            and bool(pattern_context.is_2d)
        )
        is_custom_2d_ctx = isinstance(pattern_context, GpuCustomPattern2DContext)
        # 2-D K(α, β) LUT is only needed for patterns whose angular
        # structure is fixed in the satellite body frame (M.2101 element
        # pattern). Asymmetric S.1528 *and* Custom-2D both attach the
        # asymmetry to the beam boresight — rotating α_i rotates the
        # aperture, so K is α-invariant and a 1-D K(β) suffices (built
        # with a 2-D observation sweep to catch the φ-dependent main
        # lobe max). See Stage-10 decision doc and
        # _build_peak_pfd_k_lut_custom2d_cp docstring.
        uses_2d_lut = is_m2101_ctx

        key = (
            self.device_id,
            self.compute_dtype.str,
            int(pattern_id),
            tuple(int(v) for v in unique_cm.tolist()),
            bool(apply_atmosphere),
            id(atmosphere_lut_context) if atmosphere_lut_context is not None else 0,
            float(target_alt_km),
            round(float(beta_step_deg), 9),
            round(float(beta_extra_margin_deg), 9),
            round(float(psi_step_deg), 9),
            pattern_eval_mode,
            bool(is_m2101_ctx),
            bool(is_asym_s1528_ctx),
            bool(is_custom_2d_ctx),
            round(float(m2101_beta_step_deg), 9),
            round(float(m2101_alpha_step_deg), 9),
            round(float(m2101_psi_step_deg), 9),
            round(float(m2101_phi_step_deg), 9),
        )
        cached = self._peak_pfd_lut_context_cache.get(key)
        if cached is not None:
            # Re-use device LUT but rebind the per-sat shell mapping in
            # case the caller passes a different (compatible) satellite
            # count — still covered by identical unique shells.
            with self._temporary_activation():
                cached_shell_ids = cached.d_shell_id_per_sat
                if cached_shell_ids is None or int(cached_shell_ids.size) != int(shell_id_per_sat_host.size):
                    cached.d_shell_id_per_sat = cp.asarray(shell_id_per_sat_host, dtype=cp.int32)
                else:
                    host_existing = cp.asnumpy(cached_shell_ids)
                    if not np.array_equal(host_existing, shell_id_per_sat_host):
                        cached.d_shell_id_per_sat = cp.asarray(shell_id_per_sat_host, dtype=cp.int32)
            self._touch()
            return cached

        k_rows: list[Any] = []
        psi_horizon_per_shell = np.empty((n_shells,), dtype=np.float64)
        beta_step_out = float(m2101_beta_step_deg if uses_2d_lut else beta_step_deg)
        beta_max_out = 0.0
        n_beta_out = 0
        alpha_step_out = 0.0
        alpha_min_out = 0.0
        n_alpha_out = 0
        with self._temporary_activation():
            for shell_idx, shell_r in enumerate(shell_radii_m.tolist()):
                if is_m2101_ctx:
                    (
                        k_cp,
                        beta_step_ret,
                        beta_max_ret,
                        n_beta_ret,
                        psi_horizon_deg,
                        alpha_step_ret,
                        alpha_min_ret,
                        n_alpha_ret,
                        _alpha_max_actual,
                    ) = _build_peak_pfd_k_lut_2d_cp(
                        pattern_context=pattern_context,
                        orbit_radius_m=float(shell_r),
                        earth_radius_m=earth_radius_m,
                        atmosphere_lut_context=atmosphere_lut_context,
                        target_alt_km=float(target_alt_km),
                        beta_step_deg=float(m2101_beta_step_deg),
                        alpha_step_deg=float(m2101_alpha_step_deg),
                        beta_extra_margin_deg=float(beta_extra_margin_deg),
                        psi_step_deg=float(m2101_psi_step_deg),
                        phi_step_deg=float(m2101_phi_step_deg),
                    )
                elif is_asym_s1528_ctx:
                    (
                        k_cp,
                        beta_step_ret,
                        beta_max_ret,
                        n_beta_ret,
                        psi_horizon_deg,
                    ) = _build_peak_pfd_k_lut_asym_s1528_cp(
                        pattern_context=pattern_context,
                        orbit_radius_m=float(shell_r),
                        earth_radius_m=earth_radius_m,
                        atmosphere_lut_context=atmosphere_lut_context,
                        target_alt_km=float(target_alt_km),
                        beta_step_deg=float(beta_step_deg),
                        beta_extra_margin_deg=float(beta_extra_margin_deg),
                        psi_step_deg=float(psi_step_deg),
                        phi_step_deg=float(m2101_phi_step_deg),
                    )
                    alpha_step_ret = 0.0
                    alpha_min_ret = 0.0
                    n_alpha_ret = 0
                elif is_custom_2d_ctx:
                    (
                        k_cp,
                        beta_step_ret,
                        beta_max_ret,
                        n_beta_ret,
                        psi_horizon_deg,
                    ) = _build_peak_pfd_k_lut_custom2d_cp(
                        pattern_context=pattern_context,
                        orbit_radius_m=float(shell_r),
                        earth_radius_m=earth_radius_m,
                        atmosphere_lut_context=atmosphere_lut_context,
                        target_alt_km=float(target_alt_km),
                        beta_step_deg=float(beta_step_deg),
                        beta_extra_margin_deg=float(beta_extra_margin_deg),
                        psi_step_deg=float(psi_step_deg),
                        phi_step_deg=float(m2101_phi_step_deg),
                    )
                    alpha_step_ret = 0.0
                    alpha_min_ret = 0.0
                    n_alpha_ret = 0
                else:
                    (
                        k_cp,
                        beta_step_ret,
                        beta_max_ret,
                        n_beta_ret,
                        psi_horizon_deg,
                    ) = _build_peak_pfd_k_lut_cp(
                        pattern_context=pattern_context,
                        orbit_radius_m=float(shell_r),
                        earth_radius_m=earth_radius_m,
                        atmosphere_lut_context=atmosphere_lut_context,
                        target_alt_km=float(target_alt_km),
                        beta_step_deg=float(beta_step_deg),
                        beta_extra_margin_deg=float(beta_extra_margin_deg),
                        psi_step_deg=float(psi_step_deg),
                    )
                    alpha_step_ret = 0.0
                    alpha_min_ret = 0.0
                    n_alpha_ret = 0
                psi_horizon_per_shell[shell_idx] = psi_horizon_deg
                if shell_idx == 0:
                    beta_step_out = float(beta_step_ret)
                    beta_max_out = float(beta_max_ret)
                    n_beta_out = int(n_beta_ret)
                    alpha_step_out = float(alpha_step_ret)
                    alpha_min_out = float(alpha_min_ret)
                    n_alpha_out = int(n_alpha_ret)
                else:
                    if int(n_beta_ret) != n_beta_out:
                        # Different shells produced different β grids — pad/trim
                        # to the common n_beta so we can stack into one tensor.
                        if uses_2d_lut:
                            if int(n_beta_ret) > n_beta_out:
                                k_cp = k_cp[:, :n_beta_out]
                            else:
                                pad = cp.tile(
                                    k_cp[:, -1:],
                                    (1, n_beta_out - int(n_beta_ret)),
                                )
                                k_cp = cp.concatenate([k_cp, pad], axis=1)
                        else:
                            if int(n_beta_ret) > n_beta_out:
                                k_cp = k_cp[:n_beta_out]
                            else:
                                pad = cp.full(
                                    (n_beta_out - int(n_beta_ret),),
                                    fill_value=float(k_cp[-1].get()),
                                    dtype=cp.float32,
                                )
                                k_cp = cp.concatenate([k_cp, pad], axis=0)
                    beta_max_out = max(beta_max_out, float(beta_max_ret))
                k_rows.append(k_cp)
            d_k_lut = cp.stack(k_rows, axis=0).astype(cp.float32, copy=False)
            d_shell_id_per_sat = cp.asarray(shell_id_per_sat_host, dtype=cp.int32)

        shell_keys_tuple = tuple(
            (int(pattern_id), int(v)) for v in unique_cm.tolist()
        )
        context = GpuPeakPfdLutContext(
            session=self,
            compute_dtype=self.compute_dtype,
            device_id=self.device_id,
            apply_atmosphere=apply_atmosphere,
            pattern_eval_mode=pattern_eval_mode,
            beta_step_deg=beta_step_out,
            beta_max_deg=beta_max_out,
            n_beta=n_beta_out,
            shell_keys=shell_keys_tuple,
            orbit_radius_m_per_shell=shell_radii_m.astype(np.float64, copy=False),
            psi_horizon_deg_per_shell=psi_horizon_per_shell.astype(np.float64, copy=False),
            observer_alt_km=float(target_alt_km),
            target_alt_km=float(target_alt_km),
            d_k_lut=d_k_lut,
            d_shell_id_per_sat=d_shell_id_per_sat,
            is_2d=bool(uses_2d_lut),
            alpha_step_deg=alpha_step_out,
            alpha_min_deg=alpha_min_out,
            n_alpha=n_alpha_out,
        )
        self._peak_pfd_lut_context_cache[key] = context
        self._touch()
        return context

    def prepare_spectrum_plan_context(
        self,
        *,
        reuse_factor: int,
        groups_per_cell: int,
        channel_bandwidth_mhz: float,
        service_band_start_mhz: float,
        service_band_stop_mhz: float,
        ras_band_start_mhz: float,
        ras_band_stop_mhz: float,
        power_policy: str,
        cell_reuse_slot_ids: Any,
        cell_leakage_factors: Any,
        cell_group_leakage_factors: Any,
        cell_group_valid_mask: Any,
        configured_group_counts_per_cell: Any,
        slot_edges_mhz: Any,
        mask_points_mhz: Any,
        tx_reference_frequencies_mhz: Any,
        ras_reference_frequencies_mhz: Any,
    ) -> GpuSpectrumPlanContext:
        """
        Prepare cached device-side reuse/leakage metadata.

        Parameters
        ----------
        reuse_factor, groups_per_cell : int
            Reuse-cluster size and number of occupied groups per cell.
        channel_bandwidth_mhz : float
            Channel width in MHz.
        service_band_start_mhz, service_band_stop_mhz : float
            Service-band edges in MHz.
        ras_band_start_mhz, ras_band_stop_mhz : float
            RAS receiver-band edges in MHz.
        power_policy : str
            Multi-group power policy descriptor.
        cell_reuse_slot_ids, cell_leakage_factors, cell_group_leakage_factors : Any
            ACTIVE-axis reuse-slot ids, full-cell leakage factors, and
            per-group leakage factors.
        cell_group_valid_mask, configured_group_counts_per_cell : Any
            ACTIVE-axis per-group validity mask and enabled-group counts used
            when the simulated service-channel subset is not rectangular across
            reuse slots.
        slot_edges_mhz, mask_points_mhz : Any
            Full-channel edge vector and mask breakpoint table in MHz.
        tx_reference_frequencies_mhz, ras_reference_frequencies_mhz : Any
            Reference-frequency sample vectors used for spectrum metadata.

        Returns
        -------
        GpuSpectrumPlanContext
            Cached device-resident spectrum context.
        """
        self._ensure_owner_thread()
        self._ensure_open()
        _require_cupy()

        reuse_factor_i = int(reuse_factor)
        if reuse_factor_i < 1:
            raise ValueError("reuse_factor must be >= 1.")
        groups_per_cell_i = int(groups_per_cell)
        if groups_per_cell_i < 1:
            raise ValueError("groups_per_cell must be >= 1.")
        slot_ids = np.asarray(cell_reuse_slot_ids, dtype=np.int32).reshape(-1)
        leakage = np.asarray(cell_leakage_factors, dtype=np.float32).reshape(-1)
        if slot_ids.shape != leakage.shape:
            raise ValueError(
                "cell_reuse_slot_ids and cell_leakage_factors must share the ACTIVE cell axis."
            )
        if slot_ids.size and (
            np.any(slot_ids < 0) or np.any(slot_ids >= np.int32(reuse_factor_i))
        ):
            raise ValueError(
                "cell_reuse_slot_ids must lie in [0, reuse_factor) for the ACTIVE cell axis."
            )
        if not np.all(np.isfinite(leakage)):
            raise ValueError("cell_leakage_factors must be finite.")
        if np.any(leakage < np.float32(0.0)):
            raise ValueError("cell_leakage_factors must be non-negative.")
        group_leakage = np.asarray(cell_group_leakage_factors, dtype=np.float32)
        if group_leakage.ndim != 2:
            raise ValueError("cell_group_leakage_factors must have shape (C, G).")
        if int(group_leakage.shape[0]) != int(slot_ids.size):
            raise ValueError(
                "cell_group_leakage_factors must align with the ACTIVE cell axis."
            )
        if int(group_leakage.shape[1]) != int(groups_per_cell_i):
            raise ValueError(
                "cell_group_leakage_factors group axis must match groups_per_cell."
            )
        if not np.all(np.isfinite(group_leakage)):
            raise ValueError("cell_group_leakage_factors must be finite.")
        if np.any(group_leakage < np.float32(0.0)):
            raise ValueError("cell_group_leakage_factors must be non-negative.")
        group_valid_mask = np.asarray(cell_group_valid_mask, dtype=bool)
        if group_valid_mask.shape != tuple(group_leakage.shape):
            raise ValueError(
                "cell_group_valid_mask must have the same shape as cell_group_leakage_factors."
            )
        configured_group_counts = np.asarray(
            configured_group_counts_per_cell,
            dtype=np.int32,
        ).reshape(-1)
        if int(configured_group_counts.size) != int(slot_ids.size):
            raise ValueError(
                "configured_group_counts_per_cell must align with the ACTIVE cell axis."
            )
        expected_group_counts = np.sum(group_valid_mask, axis=1, dtype=np.int32)
        if not np.array_equal(configured_group_counts, expected_group_counts):
            raise ValueError(
                "configured_group_counts_per_cell must equal the per-cell sum of "
                "cell_group_valid_mask."
            )
        slot_edges = np.asarray(slot_edges_mhz, dtype=np.float64).reshape(-1)
        if slot_edges.size < 2:
            raise ValueError("slot_edges_mhz must contain at least two entries.")
        if not np.all(np.isfinite(slot_edges)):
            raise ValueError("slot_edges_mhz must be finite.")
        if np.any(np.diff(slot_edges) <= 0.0):
            raise ValueError("slot_edges_mhz must be strictly increasing.")
        mask_points = np.asarray(mask_points_mhz, dtype=np.float64)
        if mask_points.ndim != 2 or mask_points.shape[1] != 2:
            raise ValueError("mask_points_mhz must have shape (N, 2).")
        if not np.all(np.isfinite(mask_points)):
            raise ValueError("mask_points_mhz must be finite.")
        tx_refs = np.asarray(tx_reference_frequencies_mhz, dtype=np.float64).reshape(-1)
        ras_refs = np.asarray(ras_reference_frequencies_mhz, dtype=np.float64).reshape(-1)
        if tx_refs.size < 1 or ras_refs.size < 1:
            raise ValueError("tx_reference_frequencies_mhz and ras_reference_frequencies_mhz must be non-empty.")
        if not np.all(np.isfinite(tx_refs)):
            raise ValueError("tx_reference_frequencies_mhz must be finite.")
        if not np.all(np.isfinite(ras_refs)):
            raise ValueError("ras_reference_frequencies_mhz must be finite.")

        key = (
            self.device_id,
            self.compute_dtype.str,
            int(reuse_factor_i),
            int(groups_per_cell_i),
            round(float(channel_bandwidth_mhz), 9),
            round(float(service_band_start_mhz), 9),
            round(float(service_band_stop_mhz), 9),
            round(float(ras_band_start_mhz), 9),
            round(float(ras_band_stop_mhz), 9),
            str(power_policy),
            hash(slot_ids.tobytes()),
            hash(leakage.tobytes()),
            hash(group_leakage.tobytes()),
            hash(group_valid_mask.tobytes()),
            hash(configured_group_counts.tobytes()),
            hash(slot_edges.tobytes()),
            hash(mask_points.tobytes()),
            hash(tx_refs.tobytes()),
            hash(ras_refs.tobytes()),
        )
        cached = self._spectrum_plan_context_cache.get(key)
        if cached is not None:
            self._touch()
            return cached

        with self._temporary_activation():
            context = GpuSpectrumPlanContext(
                session=self,
                compute_dtype=self.compute_dtype,
                device_id=self.device_id,
                reuse_factor=int(reuse_factor_i),
                groups_per_cell=int(groups_per_cell_i),
                channel_bandwidth_mhz=float(channel_bandwidth_mhz),
                service_band_start_mhz=float(service_band_start_mhz),
                service_band_stop_mhz=float(service_band_stop_mhz),
                ras_band_start_mhz=float(ras_band_start_mhz),
                ras_band_stop_mhz=float(ras_band_stop_mhz),
                power_policy=str(power_policy),
                slot_edges_mhz=np.asarray(slot_edges, dtype=np.float64),
                mask_points_mhz=np.asarray(mask_points, dtype=np.float64),
                tx_reference_frequencies_mhz=np.asarray(tx_refs, dtype=np.float64),
                ras_reference_frequencies_mhz=np.asarray(ras_refs, dtype=np.float64),
                cell_reuse_slot_ids=np.asarray(slot_ids, dtype=np.int32),
                cell_leakage_factors=np.asarray(leakage, dtype=np.float32),
                cell_group_leakage_factors=np.asarray(group_leakage, dtype=np.float32),
                cell_group_valid_mask=np.asarray(group_valid_mask, dtype=bool),
                configured_group_counts_per_cell=np.asarray(
                    configured_group_counts,
                    dtype=np.int32,
                ),
                d_slot_edges_mhz=_to_cupy_array(slot_edges, dtype=cp.float64),
                d_mask_points_mhz=_to_cupy_array(mask_points, dtype=cp.float64),
                d_tx_reference_frequencies_mhz=_to_cupy_array(tx_refs, dtype=cp.float64),
                d_ras_reference_frequencies_mhz=_to_cupy_array(ras_refs, dtype=cp.float64),
                d_cell_reuse_slot_ids=_to_cupy_array(slot_ids, dtype=cp.int32),
                d_cell_leakage_factors=_to_cupy_array(leakage, dtype=cp.float32),
                d_cell_group_leakage_factors=_to_cupy_array(group_leakage, dtype=cp.float32),
                d_cell_group_valid_mask=_to_cupy_array(group_valid_mask, dtype=cp.bool_),
                d_configured_group_counts_per_cell=_to_cupy_array(
                    configured_group_counts,
                    dtype=cp.int32,
                ),
            )
        self._spectrum_plan_context_cache[key] = context
        self._touch()
        return context

    def resolve_angle_sampler_sources(
        self,
        angle_sampler_context: GpuAngleSamplerContext,
        sat_azimuth_deg: Any,
        sat_elevation_deg: Any,
        sat_belt_id: Any,
        *,
        return_device: bool = True,
    ) -> dict[str, Any]:
        """
        Resolve the effective conditioned sampler source for each satellite row.

        Parameters
        ----------
        angle_sampler_context : GpuAngleSamplerContext
            Prepared conditional sampler context.
        sat_azimuth_deg, sat_elevation_deg, sat_belt_id : Any
            Observer-frame satellite azimuth, elevation, and belt-ID tensors
            with identical shapes. Numeric angles are interpreted as degrees.
        return_device : bool, optional
            If `True`, return CuPy arrays on the active GPU. Otherwise copy the
            results back to NumPy host arrays.

        Returns
        -------
        dict[str, Any]
            Dictionary containing `skycell_id`, `source_kind`, `source_id`,
            and `valid_mask`. Invalid rows use `source_kind=-1` and
            `source_id=-1`.
        """
        self._ensure_owner_thread()
        self._ensure_open()
        if angle_sampler_context.session is not self:
            raise ValueError("angle_sampler_context must belong to this session.")

        with self._temporary_activation():
            result = _resolve_sampler_sources_cp(
                angle_sampler_context,
                sat_azimuth_deg,
                sat_elevation_deg,
                sat_belt_id,
            )
            if return_device:
                self._touch()
                return result
            host_result = {key: copy_device_to_host(value) for key, value in result.items()}
        self._touch()
        return host_result

    def fill_conditioned_beams_streaming(
        self,
        angle_sampler_context: GpuAngleSamplerContext,
        source_kind: Any,
        source_id: Any,
        *,
        vis_mask_horizon: Any,
        is_co_sat: Any,
        alpha0_rad: Any,
        beta0_rad: Any,
        beta_max_rad_per_sat: Any,
        n_beams: int,
        cos_min_sep: float,
        seed: int,
        chunk_size: int = STREAM_CONDITIONED_CHUNK_SIZE,
        max_rounds: int = STREAM_CONDITIONED_MAX_ROUNDS,
        rescue_chunk_size: int = STREAM_CONDITIONED_RESCUE_CHUNK_SIZE,
        max_rescue_rounds: int = STREAM_CONDITIONED_MAX_RESCUE_ROUNDS,
        beam_placement_policy: str = STEP2_BEAM_PLACEMENT_FORCED_CO_RAS,
        ras_sat_azel: Any | None = None,
        orbit_radius_m_per_sat: Any | None = None,
        ras_exclusion_radius_km: float | None = None,
        target_alt_km: float = 0.0,
        return_device: bool = True,
    ) -> dict[str, Any]:
        """
        Fill EPFDflow beams by streaming conditioned candidate chunks on the GPU.

        Parameters
        ----------
        angle_sampler_context : GpuAngleSamplerContext
            Prepared conditioned sampler context.
        source_kind, source_id : Any
            Full-shape `(time, satellite)` conditioned source tensors,
            typically produced by :meth:`resolve_angle_sampler_sources`.
        vis_mask_horizon : Any
            Boolean visibility mask aligned with `source_kind`.
        is_co_sat : Any
            Boolean mask identifying the serving co-satellite rows.
        alpha0_rad, beta0_rad : Any
            Serving-link beam directions in radians for each `(time,
            satellite)` row.
        beta_max_rad_per_sat : Any
            One-dimensional maximum off-axis angle per satellite, in radians.
        n_beams : int
            Number of beams that must be assigned to each visible row.
        cos_min_sep : float
            Cosine of the minimum allowed beam-center separation.
        seed : int
            Deterministic seed for the streaming candidate draws.
        chunk_size, max_rounds, rescue_chunk_size, max_rescue_rounds : int, optional
            Streaming configuration for the normal and rescue draw rounds.
        beam_placement_policy : {"forced_co_ras", "exclude_ras_radius"}, optional
            Step-2 beam-placement policy. ``"forced_co_ras"`` preserves the
            existing forced CO beam to the RAS station. ``"exclude_ras_radius"``
            disables that forced beam and rejects candidate beams whose exact
            ground intercept lies inside the requested RAS exclusion radius.
        ras_sat_azel : Any or None, optional
            Exact RAS-station direction in the satellite frame, aligned over
            ``(T, S)``. Required only when
            ``beam_placement_policy="exclude_ras_radius"``.
        orbit_radius_m_per_sat : Any or None, optional
            One-dimensional orbital-radius array in metres aligned with the
            satellite axis. Required only when
            ``beam_placement_policy="exclude_ras_radius"``.
        ras_exclusion_radius_km : float or None, optional
            Forbidden ground-radius around the RAS station used only when
            ``beam_placement_policy="exclude_ras_radius"``.
        target_alt_km : float, optional
            Target-sphere altitude used for the exclusion-zone intercept
            geometry. The default ``0.0`` keeps the exclusion on the Earth
            surface.
        return_device : bool, optional
            If `True`, keep the beam tables on the GPU. Otherwise return host
            NumPy copies.

        Returns
        -------
        dict[str, Any]
            Assigned-beam dictionary containing `beam_idx`,
            `beam_alpha_rad`, `beam_beta_rad`, and `beam_valid`, plus scalar
            diagnostics `draws_attempted`, `rounds_used`, and
            `unfinished_row_count`.
        """
        self._ensure_owner_thread()
        self._ensure_open()
        if angle_sampler_context.session is not self:
            raise ValueError("angle_sampler_context must belong to this session.")

        with self._temporary_activation():
            result = _fill_conditioned_beams_streaming_cp(
                angle_sampler_context,
                source_kind,
                source_id,
                vis_mask_horizon=vis_mask_horizon,
                is_co_sat=is_co_sat,
                alpha0_rad=alpha0_rad,
                beta0_rad=beta0_rad,
                beta_max_rad_per_sat=beta_max_rad_per_sat,
                n_beams=n_beams,
                cos_min_sep=cos_min_sep,
                seed=seed,
                chunk_size=chunk_size,
                max_rounds=max_rounds,
                rescue_chunk_size=rescue_chunk_size,
                max_rescue_rounds=max_rescue_rounds,
                beam_placement_policy=beam_placement_policy,
                ras_sat_azel=ras_sat_azel,
                orbit_radius_m_per_sat=orbit_radius_m_per_sat,
                ras_exclusion_radius_km=ras_exclusion_radius_km,
                target_alt_km=target_alt_km,
            )
            if return_device:
                self._touch()
                return result
            host_result = {
                key: copy_device_to_host(value) if _is_cuda_array(value) or (_has_cupy() and isinstance(value, cp.ndarray)) else value
                for key, value in result.items()
            }
        self._touch()
        return host_result

    def make_conditioned_template_plan(
        self,
        source_kind: Any,
        source_id: Any,
        vis_mask_horizon: Any,
        beta_max_rad_per_sat: Any,
        *,
        mode: str | None = CONDITIONED_TEMPLATE_MODE_HYBRID,
        pool_size: int,
        template_size: int,
    ) -> GpuConditionedTemplatePlan:
        """
        Build the conditioned-template execution plan for an EPFDflow batch.

        Parameters
        ----------
        source_kind, source_id : Any
            Effective sampler source tensors, typically the outputs of
            :meth:`resolve_angle_sampler_sources`.
        vis_mask_horizon : Any
            Horizon-visibility mask aligned with the source tensors.
        beta_max_rad_per_sat : Any
            One-dimensional per-satellite maximum beta values in radians. The
            length must match the last axis of `source_kind`.
        mode : {"per_source", "per_row", "hybrid"} or None, optional
            Template-sharing policy. `None` is treated as `"hybrid"`.
        pool_size : int
            Number of candidate draws per template unit.
        template_size : int
            Maximum number of beams retained in each separated template.

        Returns
        -------
        GpuConditionedTemplatePlan
            Device-resident plan describing the active rows, unit mapping,
            selected sharing mode, and the per-unit maximum beta used during
            template construction.
        """
        self._ensure_owner_thread()
        self._ensure_open()

        with self._temporary_activation():
            plan = _make_conditioned_template_plan_cp(
                source_kind,
                source_id,
                vis_mask_horizon,
                beta_max_rad_per_sat,
                mode=CONDITIONED_TEMPLATE_MODE_HYBRID if mode is None else str(mode),
                pool_size=pool_size,
                template_size=template_size,
            )
        self._touch()
        return plan

