    def value_range_and_histogram(
        self,
        *,
        value_linear: Any,
        value_edges_dbw: np.ndarray | None,
        db_offset_db: float = 0.0,
    ) -> dict[str, Any]:
        """Fused range + histogram: one dB conversion shared by both.

        Returns a dict with ``range_db`` (tuple or None) and ``histogram``
        (host numpy int64 array or None).  When ``value_edges_dbw`` is
        ``None`` only the range is computed (the histogram requires edges).
        """
        with self._temporary_activation():
            value_cp = _to_cupy_array(value_linear, dtype=cp.float32)
            flat = value_cp.reshape(-1)
            # Fused: valid check + log10 + offset + masked sentinel in one kernel
            _k = _get_fused_db_minmax_kernel()
            dbw, dbw_for_min, dbw_for_max = _k(flat, cp.float32(float(db_offset_db)))
            # Single D2H sync for both min and max (stacked reduction)
            extrema = cp.array([cp.min(dbw_for_min), cp.max(dbw_for_max)])
            extrema_host = extrema.get()
            min_val, max_val = float(extrema_host[0]), float(extrema_host[1])
            if min_val >= 1e29:
                return {"range_db": None, "histogram": None}
            range_db = (min_val, max_val)
            if value_edges_dbw is None:
                return {"range_db": range_db, "histogram": None}
            # Histogram using the already-converted dB values
            edges_cp = cp.asarray(np.asarray(value_edges_dbw, dtype=np.float32))
            n_bins = int(edges_cp.size) - 1
            raw_bin_plus1 = cp.searchsorted(edges_cp, dbw, side="right")
            kept_bins, weights = _get_hist_bin_mask_kernel()(raw_bin_plus1, dbw, cp.int64(n_bins))
            hist = cp.asnumpy(
                cp.bincount(kept_bins, weights=weights, minlength=n_bins).astype(cp.int64)
            )
            return {"range_db": range_db, "histogram": hist}

