    @cuda.jit
    def _eligible_mask_kernel(
        sat_topo,
        sat_azel,
        sat_min_elev_deg,
        sat_beta_max_deg,
        use_cone_check,
        beta_tol_deg,
        eligible_out,
    ):
        idx = cuda.grid(1)
        T = sat_topo.shape[0]
        C = sat_topo.shape[1]
        S = sat_topo.shape[2]
        if idx >= T * C * S:
            return
        t = idx // (C * S)
        rem = idx - t * C * S
        c = rem // S
        s = rem - c * S
        elev = sat_topo[t, c, s, 1]
        visible = elev >= sat_min_elev_deg[s]
        if not visible:
            eligible_out[t, c, s] = False
            return
        if use_cone_check:
            theta = sat_azel[t, c, s, 1]
            beta = theta if theta >= 0.0 else -theta
            eligible_out[t, c, s] = beta <= (sat_beta_max_deg[s] + beta_tol_deg)
        else:
            eligible_out[t, c, s] = True


    @cuda.jit
    def _greedy_assign_sorted_candidates_boresight_kernel(
        segment_start,
        segment_end,
        candidate_cell,
        candidate_sat,
        candidate_alpha,
        candidate_beta,
        ras_azimuth,
        ras_elevation,
        sat_belt_id,
        sat_beta_max,
        boresight_full_mask,
        boresight_partial_mask,
        theta2_cell_mask,
        total_cells,
        n_links,
        n_beam,
        use_cone_check,
        write_payload,
        count_requested,
        has_link_geom,
        beta_tol_deg,
        cell_count_work,
        sat_count_work,
        eligible_count_work,
        assignments,
        cone_ok_out,
        sat_azimuth_out,
        sat_elevation_out,
        sat_alpha_out,
        sat_beta_out,
        sat_belt_out,
    ):
        t = cuda.blockIdx.x
        sky = cuda.blockIdx.y
        if t >= segment_start.shape[0] or sky >= boresight_full_mask.shape[1] or cuda.threadIdx.x != 0:
            return

        filled_cells = 0
        start = int(segment_start[t])
        stop = int(segment_end[t])
        for idx in range(start, stop):
            cell = int(candidate_cell[idx])
            sat = int(candidate_sat[idx])
            if boresight_full_mask[t, sky, sat]:
                continue
            if boresight_partial_mask[t, sky, sat] and theta2_cell_mask[cell]:
                continue
            slot = int(cell_count_work[t, sky, cell])
            if slot >= n_links:
                continue
            if int(sat_count_work[t, sky, sat]) >= n_beam:
                continue

            assignments[t, sky, cell, slot] = sat
            cell_count_work[t, sky, cell] = slot + 1
            sat_count_work[t, sky, sat] = sat_count_work[t, sky, sat] + 1
            if slot + 1 >= n_links:
                filled_cells += 1

            ok = True
            alpha_val = 0.0
            beta_val = 0.0
            if has_link_geom:
                alpha_val = candidate_alpha[idx]
                beta_val = candidate_beta[idx]
            if use_cone_check:
                ok = beta_val <= (sat_beta_max[sat] + beta_tol_deg)

            if write_payload:
                cone_ok_out[t, sky, cell, slot] = ok
                if ok:
                    sat_azimuth_out[t, sky, cell, slot] = ras_azimuth[t, sat]
                    sat_elevation_out[t, sky, cell, slot] = ras_elevation[t, sat]
                    sat_alpha_out[t, sky, cell, slot] = alpha_val
                    sat_beta_out[t, sky, cell, slot] = beta_val
                    sat_belt_out[t, sky, cell, slot] = sat_belt_id[sat]
            elif count_requested and use_cone_check:
                cone_ok_out[t, sky, cell, slot] = ok

            if count_requested:
                if use_cone_check:
                    if ok:
                        eligible_count_work[t, sky, sat] = eligible_count_work[t, sky, sat] + 1
                else:
                    eligible_count_work[t, sky, sat] = eligible_count_work[t, sky, sat] + 1

            if filled_cells >= total_cells:
                break


