def _c_contiguous_element_strides(shape: tuple[int, ...]) -> tuple[int, ...]:
    if not shape:
        return ()
    strides = [0] * len(shape)
    stride = 1
    for axis in range(len(shape) - 1, -1, -1):
        strides[axis] = stride
        stride *= max(int(shape[axis]), 1)
    return tuple(strides)


def _c_contiguous_byte_strides(shape: tuple[int, ...], itemsize: int) -> tuple[int, ...]:
    return tuple(stride * int(itemsize) for stride in _c_contiguous_element_strides(shape))


def _broadcast_element_strides(shape: tuple[int, ...], out_shape: tuple[int, ...]) -> np.ndarray:
    ndim = len(out_shape)
    padded_shape = (1,) * (ndim - len(shape)) + tuple(int(v) for v in shape)
    padded_strides = (0,) * (ndim - len(shape)) + _c_contiguous_element_strides(shape)
    out: list[int] = []
    for in_extent, out_extent, stride in zip(padded_shape, out_shape, padded_strides, strict=True):
        if in_extent == out_extent:
            out.append(int(stride))
        elif in_extent == 1:
            out.append(0)
        else:
            raise ValueError(
                f"input shape {shape!r} is not broadcastable to output shape {out_shape!r}."
            )
    return np.asarray(out, dtype=np.int64)


def _normalise_host_angular_output(
    values: np.ndarray,
    *,
    output_shape: tuple[int, ...],
    as_quantity: bool,
) -> Any:
    if output_shape:
        host = np.asarray(values).reshape(output_shape)
    else:
        host = np.asarray(values).reshape(()).item()
    if as_quantity:
        return host * u.deg
    return host


def _cpu_true_angular_distance_host(l1: Any, b1: Any, l2: Any, b2: Any) -> Any:
    return true_angular_distance(
        _to_host_degree_array(l1, dtype=np.float64) * u.deg,
        _to_host_degree_array(b1, dtype=np.float64) * u.deg,
        _to_host_degree_array(l2, dtype=np.float64) * u.deg,
        _to_host_degree_array(b2, dtype=np.float64) * u.deg,
    ).value


def _coerce_angular_device_operand(
    value: Any,
    *,
    session: GpuScepterSession,
    compute_dtype: np.dtype,
) -> tuple[Any, tuple[int, ...]]:
    if _is_cuda_array(value):
        raw = cuda.as_cuda_array(value)
        shape = tuple(int(v) for v in raw.shape)
        raw_dtype = np.dtype(raw.dtype)
        raw_strides = None if raw.strides is None else tuple(int(v) for v in raw.strides)
        is_c_contiguous = raw_strides is None or raw_strides == _c_contiguous_byte_strides(shape, raw_dtype.itemsize)
        if is_c_contiguous:
            try:
                flat = raw.reshape((raw.size,))
            except Exception:
                flat = None
            if flat is not None:
                if raw_dtype == compute_dtype:
                    return flat, shape
                casted = cuda.device_array(raw.size, dtype=compute_dtype)
                total = int(raw.size)
                _cast_vector_kernel[(total + 127) // 128, 128](flat, casted)
                cuda.synchronize()
                return casted, shape
        host = raw.copy_to_host()
    else:
        if hasattr(value, "to_value"):
            host = np.asarray(u.Quantity(value).to_value(u.deg))
        else:
            host = np.asarray(value)
    host_arr = np.ascontiguousarray(host, dtype=compute_dtype)
    return cuda.to_device(host_arr.reshape(-1)), tuple(int(v) for v in host_arr.shape)


def _true_angular_distance_gpu_impl(
    l1: Any,
    b1: Any,
    l2: Any,
    b2: Any,
    *,
    session: GpuScepterSession,
    return_device: bool,
    output_dtype: Any | None,
    as_quantity: bool,
) -> Any:
    if as_quantity and return_device:
        raise ValueError("as_quantity=True is only supported for host-return mode.")
    session._ensure_owner_thread()
    session._ensure_open()
    output_shape = _broadcast_shape_from_inputs(l1, b1, l2, b2)
    vector_shape = output_shape if output_shape else (1,)
    out_dtype = _normalise_output_dtype(output_dtype, default=session.compute_dtype)
    compute_dtype = session.compute_dtype
    with session._temporary_activation():
        d_l1, shape_l1 = _coerce_angular_device_operand(l1, session=session, compute_dtype=compute_dtype)
        d_b1, shape_b1 = _coerce_angular_device_operand(b1, session=session, compute_dtype=compute_dtype)
        d_l2, shape_l2 = _coerce_angular_device_operand(l2, session=session, compute_dtype=compute_dtype)
        d_b2, shape_b2 = _coerce_angular_device_operand(b2, session=session, compute_dtype=compute_dtype)
        d_l1_strides = cuda.to_device(_broadcast_element_strides(shape_l1, vector_shape))
        d_b1_strides = cuda.to_device(_broadcast_element_strides(shape_b1, vector_shape))
        d_l2_strides = cuda.to_device(_broadcast_element_strides(shape_l2, vector_shape))
        d_b2_strides = cuda.to_device(_broadcast_element_strides(shape_b2, vector_shape))
        d_out_shape = cuda.to_device(np.asarray(vector_shape, dtype=np.int64))
        out_flat = cuda.device_array(int(np.prod(vector_shape, dtype=np.int64)), dtype=out_dtype)
        block = 128
        grid = (out_flat.size + block - 1) // block
        _true_angular_distance_kernel[grid, block](
            d_l1,
            d_l1_strides,
            d_b1,
            d_b1_strides,
            d_l2,
            d_l2_strides,
            d_b2,
            d_b2_strides,
            d_out_shape,
            len(vector_shape),
            out_flat,
        )
        if return_device:
            session._touch()
            return out_flat.reshape(vector_shape)
        cuda.synchronize()
        host = out_flat.copy_to_host()
    session._touch()
    return _normalise_host_angular_output(host, output_shape=output_shape, as_quantity=as_quantity)


def _time_angular_backend(
    backend: str,
    l1: np.ndarray,
    b1: np.ndarray,
    l2: np.ndarray,
    b2: np.ndarray,
    *,
    session: GpuScepterSession,
    compute_dtype: np.dtype,
) -> float:
    start = time.perf_counter()
    if backend == _AUTO_BACKEND_CPU:
        _cpu_true_angular_distance_host(l1, b1, l2, b2)
    elif backend == _AUTO_BACKEND_GPU:
        _true_angular_distance_gpu_impl(
            l1.astype(compute_dtype, copy=False),
            b1.astype(compute_dtype, copy=False),
            l2.astype(compute_dtype, copy=False),
            b2.astype(compute_dtype, copy=False),
            session=session,
            return_device=False,
            output_dtype=compute_dtype,
            as_quantity=False,
        )
    else:
        raise ValueError(f"Unknown angular backend {backend!r}.")
    return time.perf_counter() - start


def _calibrate_angular_threshold_entry(
    *,
    session: GpuScepterSession,
    compute_dtype: np.dtype,
) -> dict[str, Any]:
    sizes = list(_ANGULAR_DISTANCE_CALIBRATION_SIZES)
    cpu_timings: list[float] = []
    gpu_timings: list[float] = []

    warm_n = int(sizes[0])
    warm_l = np.linspace(0.0, 359.5, warm_n, dtype=compute_dtype)
    warm_b = np.linspace(-70.0, 70.0, warm_n, dtype=compute_dtype)
    _true_angular_distance_gpu_impl(
        warm_l,
        warm_b,
        np.flip(warm_l),
        np.flip(warm_b),
        session=session,
        return_device=False,
        output_dtype=compute_dtype,
        as_quantity=False,
    )

    for size in sizes:
        l1 = np.linspace(0.0, 359.5, size, dtype=compute_dtype)
        b1 = np.linspace(-70.0, 70.0, size, dtype=compute_dtype)
        l2 = np.flip(l1)
        b2 = np.flip(b1)
        cpu_best = math.inf
        gpu_best = math.inf
        for _ in range(_ANGULAR_DISTANCE_CALIBRATION_REPEATS):
            cpu_best = min(cpu_best, _time_angular_backend(_AUTO_BACKEND_CPU, l1, b1, l2, b2, session=session, compute_dtype=compute_dtype))
            gpu_best = min(gpu_best, _time_angular_backend(_AUTO_BACKEND_GPU, l1, b1, l2, b2, session=session, compute_dtype=compute_dtype))
        cpu_timings.append(float(cpu_best))
        gpu_timings.append(float(gpu_best))

    threshold = int((1 << 62) - 1)
    for size, cpu_time, gpu_time in zip(sizes, cpu_timings, gpu_timings, strict=True):
        if gpu_time <= cpu_time:
            threshold = int(size)
            break

    return {
        "operation": "true_angular_distance",
        "threshold_elements": threshold,
        "sizes": sizes,
        "cpu_timings_s": cpu_timings,
        "gpu_timings_s": gpu_timings,
        "compute_dtype": np.dtype(compute_dtype).name,
        "calibrated_at_unix_s": time.time(),
    }


def _ensure_angular_threshold_entry(
    *,
    session: GpuScepterSession | None,
    compute_dtype: np.dtype,
    force: bool = False,
) -> dict[str, Any]:
    if not _has_cuda():
        raise RuntimeError("CUDA is not available.")
    temp_session: GpuScepterSession | None = None
    active_session = session
    if active_session is None:
        active_session = GpuScepterSession(
            device_id=_default_cuda_device_id(),
            compute_dtype=compute_dtype,
            watchdog_enabled=False,
        )
        temp_session = active_session
    elif active_session.compute_dtype != compute_dtype:
        active_session = GpuScepterSession(
            device_id=session.device_id,
            compute_dtype=compute_dtype,
            sat_frame=session.sat_frame,
            watchdog_enabled=False,
        )
        temp_session = active_session

    try:
        key = _angular_threshold_cache_key(
            device_id=active_session.device_id,
            compute_dtype=compute_dtype,
        )
        payload = _load_auto_threshold_cache()
        if not force and key in payload["entries"]:
            return payload["entries"][key]
        entry = _calibrate_angular_threshold_entry(
            session=active_session,
            compute_dtype=compute_dtype,
        )
        payload["entries"][key] = entry
        _save_auto_threshold_cache(payload)
        return entry
    finally:
        if temp_session is not None:
            temp_session.close(reset_device=False)


def calibrate_auto_thresholds(
    session: GpuScepterSession | None = None,
    *,
    force: bool = False,
) -> dict[str, Any]:
    """
    Calibrate host-side CPU/GPU auto-routing thresholds for angular distance.

    Parameters
    ----------
    session : GpuScepterSession or None, optional
        Existing session whose device and compute dtype should be used. When
        omitted, temporary sessions are created for both supported compute
        dtypes on the current/default CUDA device.
    force : bool, optional
        If `True`, ignore any cached thresholds and rerun the calibration.

    Returns
    -------
    dict[str, Any]
        Mapping from compute-dtype name to the cached or freshly calibrated
        threshold entry.
    """
    if not _has_cuda():
        return {}
    dtypes = [session.compute_dtype] if session is not None else [np.dtype(np.float64), np.dtype(np.float32)]
    out: dict[str, Any] = {}
    for compute_dtype in dtypes:
        entry = _ensure_angular_threshold_entry(
            session=session,
            compute_dtype=np.dtype(compute_dtype),
            force=force,
        )
        out[np.dtype(compute_dtype).name] = entry
    return out


def get_auto_thresholds() -> dict[str, Any]:
    """
    Return the cached GPU auto-routing thresholds.

    Returns
    -------
    dict[str, Any]
        Raw cache entry mapping keyed by machine/GPU/dtype fingerprint.
    """
    return _load_auto_threshold_cache()["entries"]


def true_angular_distance_gpu(
    l1: Any,
    b1: Any,
    l2: Any,
    b2: Any,
    *,
    session: GpuScepterSession | None = None,
    return_device: bool = False,
    output_dtype: Any | None = None,
    as_quantity: bool = False,
) -> Any:
    """
    Compute the true angular distance on the GPU.

    Parameters
    ----------
    l1, b1, l2, b2 : Any
        Longitudes and latitudes in degrees. Inputs may be scalars, NumPy
        arrays, CUDA arrays, or `astropy.units.Quantity`.
    session : GpuScepterSession or None, optional
        Existing session to reuse. Required for `return_device=True`.
    return_device : bool, optional
        If `True`, keep the result on the GPU and return a CUDA array.
    output_dtype : Any or None, optional
        Final output dtype. Defaults to the session `compute_dtype` or an
        inferred GPU compute dtype for temporary sessions.
    as_quantity : bool, optional
        If `True`, wrap host-return values as `Quantity` in degrees.

    Returns
    -------
    Any
        Raw degree arrays/scalars by default, `Quantity[deg]` when
        `as_quantity=True`, or a device-resident array when
        `return_device=True`.

    Raises
    ------
    ValueError
        If `return_device=True` is requested without an explicit session.
    """
    if return_device and session is None:
        raise ValueError(
            "return_device=True requires an explicit live GpuScepterSession."
        )
    if not _has_cuda():
        raise RuntimeError("CUDA is not available.")
    temp_session: GpuScepterSession | None = None
    active_session = session
    if active_session is None:
        active_session = GpuScepterSession(
            device_id=_default_cuda_device_id(),
            compute_dtype=_infer_angular_compute_dtype(
                (l1, b1, l2, b2),
                session=None,
                output_dtype=output_dtype,
            ),
            watchdog_enabled=False,
        )
        temp_session = active_session
    try:
        return _true_angular_distance_gpu_impl(
            l1,
            b1,
            l2,
            b2,
            session=active_session,
            return_device=return_device,
            output_dtype=output_dtype,
            as_quantity=as_quantity,
        )
    finally:
        if temp_session is not None:
            temp_session.close(reset_device=False)


def true_angular_distance_auto(
    l1: Any,
    b1: Any,
    l2: Any,
    b2: Any,
    *,
    session: GpuScepterSession | None = None,
    return_device: bool = False,
    output_dtype: Any | None = None,
    as_quantity: bool = False,
    force_backend: str | None = None,
) -> Any:
    """
    Compute the true angular distance using CPU or GPU as appropriate.

    Parameters
    ----------
    l1, b1, l2, b2 : Any
        Longitudes and latitudes in degrees. Inputs may be scalars, NumPy
        arrays, CUDA arrays, or `astropy.units.Quantity`.
    session : GpuScepterSession or None, optional
        Existing session to reuse. Required for `return_device=True`.
    return_device : bool, optional
        If `True`, keep the result on the GPU. This requires an explicit live
        session and forces the GPU path.
    output_dtype : Any or None, optional
        Final output dtype for the GPU path.
    as_quantity : bool, optional
        If `True`, wrap host-return values as `Quantity` in degrees.
    force_backend : {"cpu", "gpu"} or None, optional
        Explicitly force CPU or GPU execution. When `None`, host-side routing
        is decided from the cached calibration threshold.

    Returns
    -------
    Any
        Raw degree arrays/scalars by default, `Quantity[deg]` when
        `as_quantity=True`, or a device-resident CUDA array when
        `return_device=True`.
    """
    force_backend = _normalise_force_backend(force_backend)
    if return_device:
        if session is None:
            raise ValueError(
                "return_device=True requires an explicit live GpuScepterSession."
            )
        return true_angular_distance_gpu(
            l1,
            b1,
            l2,
            b2,
            session=session,
            return_device=True,
            output_dtype=output_dtype,
            as_quantity=as_quantity,
        )

    if force_backend == _AUTO_BACKEND_CPU:
        return _normalise_host_angular_output(
            np.asarray(_cpu_true_angular_distance_host(l1, b1, l2, b2)),
            output_shape=_broadcast_shape_from_inputs(l1, b1, l2, b2),
            as_quantity=as_quantity,
        )

    if force_backend == _AUTO_BACKEND_GPU or any(_is_cuda_array(value) for value in (l1, b1, l2, b2)):
        return true_angular_distance_gpu(
            l1,
            b1,
            l2,
            b2,
            session=session,
            return_device=False,
            output_dtype=output_dtype,
            as_quantity=as_quantity,
        )

    if not _has_cuda():
        return _normalise_host_angular_output(
            np.asarray(_cpu_true_angular_distance_host(l1, b1, l2, b2)),
            output_shape=_broadcast_shape_from_inputs(l1, b1, l2, b2),
            as_quantity=as_quantity,
        )

    compute_dtype = _infer_angular_compute_dtype(
        (l1, b1, l2, b2),
        session=session,
        output_dtype=output_dtype,
    )
    try:
        entry = _ensure_angular_threshold_entry(
            session=session,
            compute_dtype=compute_dtype,
            force=False,
        )
        threshold = int(entry["threshold_elements"])
    except Exception:
        threshold = (1 << 62) - 1

    elements = int(np.prod(_broadcast_shape_from_inputs(l1, b1, l2, b2), dtype=np.int64))
    if elements >= threshold:
        return true_angular_distance_gpu(
            l1,
            b1,
            l2,
            b2,
            session=session,
            return_device=False,
            output_dtype=output_dtype,
            as_quantity=as_quantity,
        )
    return _normalise_host_angular_output(
        np.asarray(_cpu_true_angular_distance_host(l1, b1, l2, b2)),
        output_shape=_broadcast_shape_from_inputs(l1, b1, l2, b2),
        as_quantity=as_quantity,
    )


def _broadcast_host_outputs(
    core_result: dict[str, Any],
    *,
    time_count: int,
    observer_count: int,
    sat_count: int,
    do_eci_pos: bool,
    do_eci_vel: bool,
    do_geo: bool,
    do_topo: bool,
    do_obs_pos: bool,
    do_sat_azel: bool,
    do_sat_rotmat: bool,
) -> dict[str, Any]:
    result: dict[str, Any] = {}
    if do_eci_pos and "eci_pos" in core_result:
        eci_pos = np.asarray(core_result["eci_pos"])
        result["eci_pos"] = np.broadcast_to(
            eci_pos[:, np.newaxis, :, :],
            (time_count, observer_count, sat_count, 3),
        ).copy()
    if do_eci_vel and "eci_vel" in core_result:
        eci_vel = np.asarray(core_result["eci_vel"])
        result["eci_vel"] = np.broadcast_to(
            eci_vel[:, np.newaxis, :, :],
            (time_count, observer_count, sat_count, 3),
        ).copy()
    if do_geo and "geo" in core_result:
        geo = np.asarray(core_result["geo"])
        result["geo"] = np.broadcast_to(
            geo[:, np.newaxis, :, :],
            (time_count, observer_count, sat_count, 3),
        ).copy()
    if do_topo and "topo" in core_result:
        result["topo"] = np.asarray(core_result["topo"])
    if do_obs_pos and "obs_pos" in core_result:
        obs_pos = np.asarray(core_result["obs_pos"])
        result["obs_pos"] = np.broadcast_to(
            obs_pos[:, :, np.newaxis, :],
            (time_count, observer_count, sat_count, 3),
        ).copy()
    if do_sat_azel and "sat_azel" in core_result:
        result["sat_azel"] = np.asarray(core_result["sat_azel"])
    if do_sat_rotmat and "sat_rotmat" in core_result:
        rot = np.asarray(core_result["sat_rotmat"])
        result["sat_rotmat"] = np.broadcast_to(
            rot[:, np.newaxis, :, :, :],
            (time_count, observer_count, sat_count, 3, 3),
        ).copy()
    if "memory_plan" in core_result:
        result["memory_plan"] = core_result["memory_plan"]
    return result


def propagate_many(
    mjds: Any,
    tles: Any,
    observers: Any | None = None,
    do_eci_pos: bool = True,
    do_eci_vel: bool = True,
    do_geo: bool = True,
    do_topo: bool = True,
    do_obs_pos: bool = False,
    do_sat_azel: bool = False,
    do_sat_rotmat: bool = False,
    sat_frame: str = "zxy",
    on_error: str = "raise",
    method: str = METHOD_DWARNER,
    *,
    session: GpuScepterSession | None = None,
    compute_dtype: Any | None = None,
    output_dtype: Any | None = None,
    return_device: bool = False,
    observer_context: GpuObserverContext | None = None,
    observer_slice: slice | None = None,
    eci_pos: Any | None = None,
    eci_vel: Any | None = None,
    device_id: int | None = None,
    gravity_model: str | None = None,
    ellipsoid_model: str | None = None,
    memory_policy: str = "adaptive",
    max_vram_fraction: float = 0.8,
) -> dict[str, Any]:
    """
    GPU-backed convenience wrapper compatible with `cysgp4.propagate_many`.

    Parameters
    ----------
    mjds : Any
        Scalar, 1-D, or broadcast-style modified Julian date input in days.
    tles : Any
        Either raw `cysgp4.PyTle` inputs or a prepared `GpuSatelliteContext`.
    observers : Any or None, optional
        Raw `cysgp4.PyObserver` inputs or a prepared `GpuObserverContext`.
        Ignored when `observer_context` is supplied.
    do_eci_pos, do_eci_vel, do_geo, do_topo, do_obs_pos, do_sat_azel, do_sat_rotmat : bool, optional
        Requested outputs. These positional-or-keyword arguments intentionally
        match the `cysgp4.propagate_many` surface and defaults.
    sat_frame : {"xyz", "zxy"}, optional
        Satellite frame convention. Defaults to ``"zxy"`` to match
        `cysgp4.propagate_many`.
    on_error : {"raise", "coerce_to_nan"}, optional
        Propagation error handling policy.
    method : {"vallado", "dwarner"}, optional
        Propagation method. Legacy aliases ``"vallado_gpu"`` and
        ``"dwarner_gpu"`` are accepted and normalised.
    session : GpuScepterSession or None, optional
        Existing session to reuse. Required when `return_device=True` or when
        device-resident `eci_pos` / `eci_vel` inputs are supplied.
    compute_dtype : Any or None, optional
        GPU compute dtype. Supported values are `float64` and `float32`.
    output_dtype : Any or None, optional
        Final output dtype. Supported values are `float64`, `float32`, and
        `float16`.
    return_device : bool, optional
        If `True`, return compact device-resident outputs and keep them on the
        GPU. This requires an explicit live `session`.
    observer_context : GpuObserverContext or None, optional
        Prepared observer context for chunked or repeated-loop usage.
    observer_slice : slice or None, optional
        Optional contiguous observer subset when using a prepared observer
        context.
    eci_pos, eci_vel : Any or None, optional
        Optional host or device ECI state inputs with shape ``(T, S, 3)``.
        When both are supplied, propagation is skipped and only geometry / view
        products are derived.
    device_id : int or None, optional
        CUDA device index used when a temporary session must be created.
    gravity_model : {"wgs72", "wgs84"} or None, optional
        Optional propagation gravity-model override. If omitted, the session
        default is used when a session is supplied, otherwise ``"wgs72"``.
    ellipsoid_model : {"wgs72", "wgs84"} or None, optional
        Optional observer/geodetic ellipsoid override. If omitted, the session
        default is used when a session is supplied, otherwise ``"wgs72"``.
    memory_policy : {"adaptive"}, optional
        Memory-planning policy.
    max_vram_fraction : float, optional
        Fraction of currently free VRAM made available to this request.

    Returns
    -------
    dict[str, Any]
        Host-return mode mirrors `cysgp4.propagate_many` broadcast semantics:

        - `eci_pos`, `eci_vel`, `geo`, `obs_pos`: ``(T, O, S, 3)``
        - `topo`: ``(T, O, S, 4)``
        - `sat_azel`: ``(T, O, S, 3)``
        - `sat_rotmat`: ``(T, O, S, 3, 3)``

        Device-return mode preserves the compact session shapes.

    Raises
    ------
    ValueError
        If prepared contexts conflict with explicitly supplied session, method,
        dtype, frame, or device settings, or if `return_device=True` is
        requested without an explicit live session.

    Notes
    -----
    The preferred performance path for repeated loops is to use
    :class:`GpuScepterSession` directly inside ``with session.activate():``.
    This wrapper keeps the original `cysgp4.propagate_many` call surface for
    host-return use and layers the GPU-resident/session behaviour behind
    optional keyword-only arguments. Mixed gravity/ellipsoid model choices are
    allowed and emit filterable warnings instead of raising.
    """
    if (eci_pos is None) ^ (eci_vel is None):
        raise ValueError("eci_pos and eci_vel must either both be provided or both be omitted.")

    requested_sat_frame = sat_frame
    requested_method = _normalise_method(method, default=METHOD_DWARNER)
    requested_compute_dtype = None if compute_dtype is None else _normalise_compute_dtype(compute_dtype)
    requested_device_id = 0 if device_id is None else int(device_id)
    requested_gravity_model = None if gravity_model is None else _normalise_earth_model(
        gravity_model,
        default=EARTH_MODEL_WGS72,
    )
    requested_ellipsoid_model = None if ellipsoid_model is None else _normalise_earth_model(
        ellipsoid_model,
        default=EARTH_MODEL_WGS72,
    )
    temp_session: GpuScepterSession | None = None

    if observer_context is None and isinstance(observers, GpuObserverContext):
        observer_context = observers

    if isinstance(tles, GpuSatelliteContext):
        sat_context = tles
        active_session = sat_context.session if session is None else session
        if active_session is not sat_context.session:
            raise ValueError("Prepared satellite contexts may only be used with their owning session.")
        effective_sat_frame = sat_context.sat_frame if requested_sat_frame == "zxy" else requested_sat_frame
        effective_method = sat_context.method if requested_method == METHOD_DWARNER else requested_method
        effective_compute_dtype = sat_context.compute_dtype if requested_compute_dtype is None else requested_compute_dtype
        effective_device_id = sat_context.device_id if device_id is None else requested_device_id
        _require_supported_geometry_flags(
            do_geo=do_geo,
            do_obs_pos=do_obs_pos,
            do_sat_rotmat=do_sat_rotmat,
            sat_frame=effective_sat_frame,
            on_error=on_error,
        )
        if effective_method != sat_context.method:
            raise ValueError("method conflicts with the prepared satellite context.")
        if np.dtype(effective_compute_dtype) != sat_context.compute_dtype:
            raise ValueError("compute_dtype conflicts with the prepared satellite context.")
        if effective_sat_frame != sat_context.sat_frame:
            raise ValueError("sat_frame conflicts with the prepared satellite context.")
        if effective_device_id != sat_context.device_id:
            raise ValueError("device_id conflicts with the prepared satellite context.")
        if requested_gravity_model is not None and requested_gravity_model != sat_context.gravity_model:
            _warn_context_model_override(
                kind="gravity_model",
                supplied_model=requested_gravity_model,
                context_model=sat_context.gravity_model,
            )
        method = effective_method
        sat_frame = effective_sat_frame
        compute_dtype = effective_compute_dtype
        device_id = effective_device_id
        gravity_model = sat_context.gravity_model
    else:
        active_session = session
        if active_session is None:
            if compute_dtype is None:
                compute_dtype = np.float64
            else:
                compute_dtype = requested_compute_dtype
            if device_id is None:
                device_id = 0
        else:
            compute_dtype = active_session.compute_dtype if compute_dtype is None else requested_compute_dtype
            device_id = active_session.device_id if device_id is None else requested_device_id
        method = requested_method
        sat_frame = requested_sat_frame
        _require_supported_geometry_flags(
            do_geo=do_geo,
            do_obs_pos=do_obs_pos,
            do_sat_rotmat=do_sat_rotmat,
            sat_frame=sat_frame,
            on_error=on_error,
        )
        if return_device and session is None:
            raise ValueError(
                "return_device=True requires an explicit live GpuScepterSession. "
                "Use session.propagate_many(...) or pass session=session."
            )
        if session is None and (
            _is_cuda_array(eci_pos) or _is_cuda_array(eci_vel)
        ):
            raise ValueError(
                "Device-resident eci_pos/eci_vel inputs require an explicit live "
                "GpuScepterSession."
            )
        if active_session is None:
            resolved_gravity_model = _normalise_earth_model(
                requested_gravity_model,
                default=EARTH_MODEL_WGS72,
            )
            resolved_ellipsoid_model = _normalise_earth_model(
                requested_ellipsoid_model,
                default=EARTH_MODEL_WGS72,
            )
            active_session = GpuScepterSession(
                device_id=device_id,
                compute_dtype=compute_dtype,
                sat_frame=sat_frame,
                gravity_model=resolved_gravity_model,
                ellipsoid_model=resolved_ellipsoid_model,
                watchdog_enabled=False,
            )
            temp_session = active_session
        else:
            if active_session.sat_frame != sat_frame:
                raise ValueError("sat_frame conflicts with the supplied session.")
            if active_session.compute_dtype != np.dtype(compute_dtype):
                raise ValueError("compute_dtype conflicts with the supplied session.")
            if active_session.device_id != int(device_id):
                raise ValueError("device_id conflicts with the supplied session.")
        resolved_gravity_model = _normalise_earth_model(
            requested_gravity_model,
            default=active_session.gravity_model,
        )
        resolved_ellipsoid_model = _normalise_earth_model(
            requested_ellipsoid_model,
            default=active_session.ellipsoid_model,
        )
        sat_context = None if eci_pos is not None else active_session.prepare_satellite_context(
            tles,
            method=method,
            gravity_model=resolved_gravity_model,
        )
        gravity_model = resolved_gravity_model
        ellipsoid_model = resolved_ellipsoid_model

    try:
        if observer_context is None:
            observer_context = active_session.prepare_observer_context(
                observers,
                ellipsoid_model=ellipsoid_model,
            )
        elif requested_ellipsoid_model is not None and requested_ellipsoid_model != observer_context.ellipsoid_model:
            _warn_context_model_override(
                kind="ellipsoid_model",
                supplied_model=requested_ellipsoid_model,
                context_model=observer_context.ellipsoid_model,
            )

        if eci_pos is not None:
            orbit_state = active_session.prepare_orbit_state(mjds, eci_pos, eci_vel)
            core_result = active_session.derive_from_eci(
                orbit_state,
                observer_context=observer_context,
                observer_slice=observer_slice,
                do_eci_pos=do_eci_pos,
                do_eci_vel=do_eci_vel,
                do_geo=do_geo,
                do_topo=do_topo,
                do_obs_pos=do_obs_pos,
                do_sat_azel=do_sat_azel,
                do_sat_rotmat=do_sat_rotmat,
                output_dtype=output_dtype,
                return_device=return_device,
            )
            sat_count = orbit_state.sat_count
        else:
            core_result = active_session.propagate_many(
                mjds,
                sat_context,
                observer_context=observer_context,
                observer_slice=observer_slice,
                do_eci_pos=do_eci_pos,
                do_eci_vel=do_eci_vel,
                do_geo=do_geo,
                do_topo=do_topo,
                do_obs_pos=do_obs_pos,
                do_sat_azel=do_sat_azel,
                do_sat_rotmat=do_sat_rotmat,
                output_dtype=output_dtype,
                return_device=return_device,
                on_error=on_error,
                memory_policy=memory_policy,
                max_vram_fraction=max_vram_fraction,
            )
            sat_count = sat_context.n_sats
        if return_device:
            return core_result
        time_count = _as_time_vector(mjds).size
        if observer_slice is None:
            observer_count = observer_context.n_observers
        else:
            _, observer_count = _normalise_observer_slice(observer_slice, observer_context.n_observers)
        return _broadcast_host_outputs(
            core_result,
            time_count=time_count,
            observer_count=observer_count,
            sat_count=sat_count,
            do_eci_pos=do_eci_pos,
            do_eci_vel=do_eci_vel,
            do_geo=do_geo,
            do_topo=do_topo,
            do_obs_pos=do_obs_pos,
            do_sat_azel=do_sat_azel,
            do_sat_rotmat=do_sat_rotmat,
        )
    finally:
        if temp_session is not None:
            temp_session.close(reset_device=False)


